INSERT INTO `about_us_content` (`id`, `section`, `content_key`, `content_value`, `content_type`, `display_order`, `is_active`, `synchronized_data`, `created_at`, `updated_at`) VALUES
('about-001', 'hero', 'title', 'About Bio Green Wax', 'text', 1, 1, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('about-002', 'hero', 'subtitle', 'Your trusted UK partner for premium edible oils and industrial waxes, delivering quality and sustainability worldwide.', 'text', 2, 1, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('about-003', 'story', 'title', 'Our Story', 'text', 1, 1, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('about-004', 'story', 'content', 'Bio Green Wax Ltd was incorporated in July 2024 with a clear vision: to become the UK\'s leading supplier of premium natural oils and industrial waxes. While we are a young company, our foundation is built on decades of combined industry experience from our leadership team.\n\nWe specialize in sourcing, processing, and distributing high-quality edible oils and industrial waxes to businesses across the UK and internationally. From food manufacturing to cosmetics, pharmaceuticals to industrial applications, our products serve a diverse range of industries with exacting standards.\n\nWhat truly sets us apart is our ability to supply RSPO SG (Segregated) certified palm oil and derivatives — a distinction that many established players in the industry have yet to achieve, as they remain reliant on MB (Mass Balance) certification. Our Segregated supply chain ensures that sustainably produced palm oil is kept physically separate throughout the entire process, offering our customers the highest level of traceability and sustainability assurance.\n\nWe are proud to supply Soy Products, Palm Products, and their derivatives that are fully compliant with EUDR (European Union Deforestation Regulation) standards, ensuring that our supply chains are deforestation-free and meet the latest European regulatory requirements.\n\nIn addition, we are able to supply biofuels feedstock products backed by ISCC-EU (International Sustainability and Carbon Certification) certifications, supporting the growing demand for sustainable and renewable energy solutions.\n\nOur commitment to quality, sustainability, and customer service sets us apart in the market. We believe in building long-term partnerships with our clients, understanding their unique requirements, and delivering solutions that exceed expectations.', 'textarea', 2, 1, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('about-005', 'mission', 'title', 'Our Mission', 'text', 1, 1, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('about-006', 'mission', 'content', 'To be the UK\'s most trusted supplier of quality oils and waxes, delivering exceptional products with outstanding service while maintaining our commitment to sustainability and ethical business practices.', 'textarea', 2, 1, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('about-007', 'director_message', 'title', 'A Message from Our Managing Director', 'text', 1, 1, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('about-008', 'director_message', 'content', 'Dear Valued Partners and Customers,\n\nThank you for taking the time to learn about Bio Green Wax Ltd. When I founded this company, I had a clear vision: to create a business that combines the highest quality products with exceptional customer service and a genuine commitment to sustainability.\n\nOur team brings decades of experience in the oils and waxes industry, and we have built relationships with trusted suppliers around the world. This enables us to offer you products that meet the most demanding quality standards while remaining competitively priced.\n\nWhat sets us apart is our personal approach. When you work with Bio Green Wax, you work directly with people who understand your industry and care about your success. We take the time to understand your specific requirements and deliver tailored solutions.\n\nI invite you to explore what we can offer your business. Whether you need edible oils for food manufacturing, specialty waxes for cosmetics, or industrial solutions for your operations, we are here to help.\n\nI look forward to the opportunity to serve you.', 'textarea', 2, 1, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('about-009', 'director_message', 'signature', 'Hantash Najam', 'text', 3, 1, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('about-010', 'director_message', 'signature_title', 'Managing Director, Bio Green Wax Ltd', 'text', 4, 1, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('about-011', 'company_info', 'company_number', '15814481', 'text', 1, 1, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('about-012', 'company_info', 'incorporated_date', '2 July 2024', 'text', 2, 1, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('about-013', 'company_info', 'registered_address', 'Bio Green Wax Ltd, 128 City Road, London, United Kingdom, EC1V 2NX', 'text', 3, 1, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('about-014', 'experience', 'title', 'Young Company, Experienced Leadership', 'text', 1, 1, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('about-015', 'experience', 'content', 'Although Bio Green Wax Ltd was founded in 2024, our leadership team brings over 25 years of combined experience in the oils and waxes industry. This expertise enables us to navigate complex supply chains, maintain rigorous quality standards, and deliver exceptional value to our customers.', 'textarea', 2, 1, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49');
INSERT INTO `about_us_content_ar` (`id`, `master_id`, `content_value`, `created_at`, `updated_at`) VALUES
(1, 'about-001', 'حول بيو جرين واكس', '2026-02-08 15:42:43', '2026-02-09 04:04:21'),
(2, 'about-002', 'شريكك الموثوق في المملكة المتحدة للزيوت الغذائية الفاخرة والشموع الصناعية، نوفر الجودة والاستدامة في جميع أنحاء العالم.', '2026-02-08 15:52:06', '2026-02-09 04:04:31'),
(3, 'about-003', 'قصتنا', '2026-02-08 15:53:21', '2026-02-09 04:04:42'),
(4, 'about-004', 'تم تسجيل شركة Bio Green Wax Ltd في يوليو 2024 برؤية واضحة: أن نصبح المزود الرائد في المملكة المتحدة للزيوت الطبيعية الممتازة وشرائح الشمع الصناعية. على الرغم من أننا شركة حديثة العهد، فإن أساسنا مبني على عقود من الخبرة المشتركة في الصناعة من قبل فريق قيادتنا.\n\nنحن متخصصون في مصدر، ومعالجة، وتوزيع الزيوت الصالحة للأكل عالية الجودة وشرائح الشمع الصناعية على الشركات في جميع أنحاء المملكة المتحدة وعلى المستوى الدولي. من تصنيع الأغذية إلى مستحضرات التجميل، الأدوية إلى التطبيقات الصناعية، تخدم منتجاتنا مجموعة متنوعة من الصناعات بمعايير دقيقة.\n\nما يميزنا حقًا هو قدرتنا على تزويد زيت النخيل ومنتجاته المعتمدة طبقًا لـ RSPO SG (Segregated) — وهو تميز لم يحققه العديد من اللاعبين الراسخين في الصناعة بعد، حيث يظلون معتمدين على شهادة MB (Mass Balance). تضمن سلسلة التوريد المنفصلة لدينا أن يتم الاحتفاظ بزيت النخيل المنتَج بشكل مستدام بشكل منفصل أثناء العملية بأكملها، مما يوفر لعملائنا أعلى مستوى من التتبع وضمان الاستدامة.\n\nنحن فخورون بتوريد منتجات الصويا، ومنتجات النخيل، ومشتقاتها، التي تتوافق تمامًا مع معايير EUDR (تنظيم الاتحاد الأوروبي بشأن إزالة الغابات)، مما يضمن أن سلاسل التوريد الخاصة بنا خالية من إزالة الغابات وتلتزم بأحدث اللوائح الأوروبية.\n\nبالإضافة إلى ذلك، يمكننا تزويد منتجات مواد التغذية للوقود الحيوي المدعومة بشهادات ISCC-EU (الشهادة الدولية للاستدامة والكربون)، دعمًا للطلب المتزايد على الحلول المستدامة والمتجددة للطاقة.\n\nالتزامنا بالجودة، والاستدامة، وخدمة العملاء يميزنا في السوق. نؤمن ببناء شراكات طويلة الأمد مع عملائنا، وفهم متطلباتهم الفريدة، وتقديم حلول تتجاوز التوقعات.', '2026-02-08 15:54:24', '2026-02-11 17:18:10'),
(5, 'about-005', 'مهمتنا', '2026-02-08 15:57:03', '2026-02-09 04:05:13'),
(6, 'about-006', 'أن نكون المورد الأكثر ثقة في المملكة المتحدة للزيوت والشموع ذات الجودة العالية، نوفر منتجات استثنائية مع خدمة متميزة مع الحفاظ على التزامنا بالاستدامة والممارسات التجارية الأخلاقية.', '2026-02-08 16:00:40', '2026-02-09 04:05:24'),
(7, 'about-007', 'رسالة من مديرنا العام', '2026-02-08 16:02:09', '2026-02-09 04:05:36'),
(8, 'about-008', 'أعزاءنا الشركاء والعملاء الكرام،\n\nشكرًا لكم على تخصيص الوقت للتعرف على شركة Bio Green Wax Ltd. عندما أسست هذه الشركة، كانت لدي رؤية واضحة: إنشاء عمل يجمع بين أعلى جودة للمنتجات وخدمة عملاء استثنائية والتزام حقيقي بالاستدامة.\n\nيتمتع فريقنا بخبرة تمتد لعدة عقود في صناعة الزيوت والشموع، وقد بنينا علاقات مع موردين موثوقين حول العالم. يتيح لنا ذلك أن نقدم لكم منتجات تلبي أعلى معايير الجودة مع الحفاظ على أسعار تنافسية.\n\nما يميزنا هو نهجنا الشخصي. عندما تتعامل مع Bio Green Wax، فإنك تتواصل مباشرة مع أشخاص يفهمون صناعتك ويهتمون بنجاحك. نحن نخصص الوقت لفهم متطلباتك المحددة ونقدم حلولاً مصممة خصيصًا لك.\n\nأدعوك لاستكشاف ما يمكننا تقديمه لعملك. سواء كنت بحاجة إلى زيوت صالحة للأكل لصناعة الأغذية، أو شموع خاصة لمستحضرات التجميل، أو حلول صناعية لعملياتك، نحن هنا للمساعدة.\n\nأتطلع لفرصة خدمتك.', '2026-02-08 16:24:22', '2026-02-09 04:24:03'),
(9, 'about-009', 'هانتاش نجم', '2026-02-08 16:49:04', '2026-02-09 04:05:47'),
(10, 'about-010', 'مدير عام، شركة بيو جرين واكس المحدودة', '2026-02-08 16:49:52', '2026-02-09 04:05:56'),
(11, 'about-011', '١٥٨١٤٤٨١', '2026-02-08 16:50:42', '2026-02-09 04:06:06'),
(12, 'about-012', '2 يوليو 2024', '2026-02-08 16:51:08', '2026-02-09 04:23:28'),
(13, 'about-013', '128 شارع المدينة، لندن، EC1V 2NX', '2026-02-08 16:51:47', '2026-02-09 04:23:39'),
(14, 'about-014', 'شركة يانغ، قيادة ذات خبرة', '2026-02-08 16:52:42', '2026-02-09 04:23:50'),
(15, 'about-015', 'على الرغم من تأسيس شركة Bio Green Wax Ltd في عام 2024، إلا أن فريق قيادتنا يمتلك أكثر من 25 عاماً من الخبرة المجمعة في صناعة الزيوت والشمع. تتيح لنا هذه الخبرة التنقل في سلاسل التوريد المعقدة، والحفاظ على معايير جودة صارمة، وتقديم قيمة استثنائية لعملائنا.', '2026-02-08 16:53:48', '2026-02-09 04:24:26');
INSERT INTO `about_us_content_de` (`id`, `master_id`, `content_value`, `created_at`, `updated_at`) VALUES
(1, 'about-001', 'Über Bio Green Wax', '2026-02-08 15:42:50', '2026-02-09 04:04:23'),
(2, 'about-002', 'Ihr vertrauenswürdiger UK-Partner für hochwertige essbare Öle und Industrie-Wachse, weltweit mit Qualität und Nachhaltigkeit.', '2026-02-08 15:52:20', '2026-02-09 04:04:33'),
(3, 'about-003', 'Unsere Geschichte', '2026-02-08 15:53:25', '2026-02-09 04:04:44'),
(4, 'about-004', 'Bio Green Wax Ltd wurde im Juli 2024 gegründet, mit einer klaren Vision: der führende Anbieter Großbritanniens für Premium-Naturöle und Industrie-Wachse zu werden. Obwohl wir ein junges Unternehmen sind, basiert unser Fundament auf jahrzehntelanger, branchenübergreifender Erfahrung unseres Führungsteams.\n\nWir sind spezialisiert auf die Beschaffung, Verarbeitung und den Vertrieb hochwertiger essbarer Öle und Industrie-Wachse an Unternehmen im gesamten Vereinigten Königreich und international. Vom Lebensmittelhersteller bis hin zu Kosmetika, von Pharma bis zu industriellen Anwendungen – unsere Produkte bedienen eine Vielzahl von Branchen mit anspruchsvollen Standards.\n\nWas uns wirklich unterscheidet, ist unsere Fähigkeit, RSPO SG (Segregated) zertifiziertes Palmöl und Derivate zu liefern — eine Eigenschaft, die viele etablierte Akteure in der Branche noch nicht erreicht haben, da sie weiterhin auf MB (Mass Balance) Zertifizierung angewiesen sind. Unsere segregierte Lieferkette stellt sicher, dass nachhaltig produziertes Palmöl während des gesamten Prozesses physisch getrennt bleibt, und bietet unseren Kunden das höchste Maß an Rückverfolgbarkeit und Nachhaltigkeitsgarantie.\n\nWir sind stolz darauf, Soja-Produkte, Palmprodukte und deren Derivate anzubieten, die vollständig mit den Standards der EUDR (European Union Deforestation Regulation) konform sind, sodass unsere Lieferketten entwaldungsfrei sind und den neuesten europäischen gesetzlichen Anforderungen entsprechen.\n\nZudem können wir Biokraftstoff-Rohstoffe liefern, die durch ISCC-EU (International Sustainability and Carbon Certification) Zertifikate unterstützt werden, um die wachsende Nachfrage nach nachhaltigen und erneuerbaren Energielösungen zu erfüllen.\n\nUnser Engagement für Qualität, Nachhaltigkeit und Kundenservice hebt uns vom Markt ab. Wir setzen auf den Aufbau langfristiger Partnerschaften mit unseren Kunden, verstehen ihre individuellen Anforderungen und liefern Lösungen, die die Erwartungen übertreffen.', '2026-02-08 15:54:57', '2026-02-11 17:18:17'),
(5, 'about-005', 'Unsere Mission', '2026-02-08 15:57:08', '2026-02-09 04:05:15'),
(6, 'about-006', 'Das Ziel ist es, der vertrauenswürdigste Lieferant für hochwertige Öle und Wachse im Vereinigten Königreich zu sein, indem wir außergewöhnliche Produkte mit exzellentem Service liefern und gleichzeitig unser Engagement für Nachhaltigkeit und ethische Geschäftspraktiken aufrechterhalten.', '2026-02-08 16:00:59', '2026-02-09 04:05:28'),
(7, 'about-007', 'Eine Nachricht unseres Geschäftsführers', '2026-02-08 16:02:20', '2026-02-09 04:05:38'),
(8, 'about-008', 'Sehr geehrte Partner und Kunden,\n\nvielen Dank, dass Sie sich die Zeit nehmen, mehr über Bio Green Wax Ltd. zu erfahren. Als ich dieses Unternehmen gründete, hatte ich eine klare Vision: ein Geschäft zu schaffen, das Produkte höchster Qualität mit außergewöhnlichem Kundenservice verbindet und sich auf echtes Engagement für Nachhaltigkeit stützt.\n\nUnser Team bringt jahrzehntelange Erfahrung in der Öl- und Wachswirtschaft mit, und wir haben Partnerschaften mit vertrauenswürdigen Lieferanten auf der ganzen Welt aufgebaut. Dies ermöglicht es uns, Ihnen Produkte anzubieten, die den anspruchsvollsten Qualitätsstandards entsprechen, dabei aber wettbewerbsfähig bleiben.\n\nWas uns unterscheidet, ist unser persönlicher Ansatz. Wenn Sie mit Bio Green Wax zusammenarbeiten, arbeiten Sie direkt mit Menschen, die Ihre Branche verstehen und sich um Ihren Erfolg kümmern. Wir nehmen uns die Zeit, Ihre spezifischen Anforderungen zu erfassen, und liefern maßgeschneiderte Lösungen.\n\nIch lade Sie ein, zu entdecken, was wir für Ihr Unternehmen anbieten können. Ob Sie essbare Öle für die Lebensmittelproduktion, Spezialwachse für Kosmetika oder industrielle Lösungen für Ihre Prozesse benötigen – wir sind für Sie da.\n\nIch freue mich auf die Gelegenheit, Sie bedienen zu dürfen.', '2026-02-08 16:25:14', '2026-02-09 04:24:07'),
(9, 'about-009', 'Hantash Najam', '2026-02-08 16:49:09', '2026-02-09 04:05:48'),
(10, 'about-010', 'Geschäftsführer, Bio Green Wax Ltd', '2026-02-08 16:50:00', '2026-02-09 04:05:58'),
(11, 'about-011', '15814481', '2026-02-08 16:50:46', '2026-02-09 04:06:08'),
(12, 'about-012', '2. Juli 2024', '2026-02-08 16:51:15', '2026-02-09 04:23:31'),
(13, 'about-013', '128 City Road, London, EC1V 2NX', '2026-02-08 16:51:56', '2026-02-09 04:23:41'),
(14, 'about-014', 'Young Company, Erfahrene Geschäftsführung', '2026-02-08 16:52:52', '2026-02-09 04:23:52'),
(15, 'about-015', 'Obwohl Bio Green Wax Ltd im Jahr 2024 gegründet wurde, bringt unser Führungsteam über 25 Jahre.combine Erfahrung in der Öl- und Wachsbranche mit. Dieses Fachwissen ermöglicht es uns, komplexe Lieferketten zu steuern, strenge Qualitätsstandards einzuhalten und unseren Kunden außergewöhnlichen Mehrwert zu bieten.', '2026-02-08 16:54:08', '2026-02-09 04:24:29');
INSERT INTO `about_us_content_es` (`id`, `master_id`, `content_value`, `created_at`, `updated_at`) VALUES
(1, 'about-001', 'Acerca de Bio Green Wax', '2026-02-08 15:42:39', '2026-02-09 04:04:20'),
(2, 'about-002', 'Tu socio de confianza en el Reino Unido para aceites comestibles premium y ceras industriales, entregando calidad y sostenibilidad en todo el mundo.', '2026-02-08 15:51:58', '2026-02-09 04:04:29'),
(3, 'about-003', 'Nuestra historia', '2026-02-08 15:53:17', '2026-02-09 04:04:41'),
(4, 'about-004', 'Bio Green Wax Ltd fue constituida en julio de 2024 con una visión clara: convertirse en el principal proveedor de Reino Unido de aceites naturales premium y ceras industriales. Aunque somos una empresa joven, nuestra base se ha construido sobre décadas de experiencia combinada en la industria por parte de nuestro equipo directivo.\n\nNos especializamos en la obtención, procesamiento y distribución de aceites comestibles de alta calidad y ceras industriales a negocios en todo el Reino Unido e internacionalmente. Desde la fabricación de alimentos hasta cosméticos, farmacéuticos y aplicaciones industriales, nuestros productos sirven a una amplia variedad de industrias con estándares rigurosos.\n\nLo que realmente nos distingue es nuestra capacidad para suministrar aceite de palma certificado RSPO SG (Segregado) y sus derivados — una distinción que muchos actores establecidos en la industria aún no han logrado, ya que siguen dependiendo de la certificación MB (Balance en Masa). Nuestra cadena de suministro Segregada garantiza que el aceite de palma producido de manera sostenible se mantenga físicamente separado durante todo el proceso, ofreciendo a nuestros clientes el máximo nivel de trazabilidad y garantía de sostenibilidad.\n\nEstamos orgullosos de suministrar productos de soja, productos de palma y sus derivados que cumplen completamente con las normativas EUDR (Reglamento de Deforestación de la Unión Europea), asegurando que nuestras cadenas de suministro no contribuyen a la deforestación y cumplen con los últimos requisitos regulatorios europeos.\n\nAdemás, podemos suministrar productos de materia prima para biocombustibles respaldados por certificaciones ISCC-EU (Certificación Internacional de Sostenibilidad y Carbono), apoyando la creciente demanda de soluciones energéticas sostenibles y renovables.\n\nNuestro compromiso con la calidad, la sostenibilidad y el servicio al cliente nos diferencia en el mercado. Creemos en construir asociaciones a largo plazo con nuestros clientes, comprendiendo sus requerimientos únicos y entregando soluciones que superen sus expectativas.', '2026-02-08 15:54:03', '2026-02-11 17:18:05'),
(5, 'about-005', 'Nuestra misión', '2026-02-08 15:57:00', '2026-02-09 04:05:12'),
(6, 'about-006', 'Ser el proveedor de confianza número uno del Reino Unido en aceites y ceras de calidad, ofreciendo productos excepcionales con un servicio sobresaliente mientras mantenemos nuestro compromiso con la sostenibilidad y las prácticas comerciales éticas.', '2026-02-08 16:00:29', '2026-02-09 04:05:22'),
(7, 'about-007', 'Un mensaje de nuestro director general', '2026-02-08 16:02:04', '2026-02-09 04:05:35'),
(8, 'about-008', 'Estimados Socios y Clientes Valiosos,\n\nGracias por tomarse el tiempo de conocer Bio Green Wax Ltd. Cuando fundé esta empresa, tenía una visión clara: crear un negocio que combine productos de la más alta calidad con un servicio al cliente excepcional y un compromiso genuino con la sostenibilidad.\n\nNuestro equipo aporta décadas de experiencia en la industria de aceites y ceras, y hemos establecido relaciones con proveedores de confianza en todo el mundo. Esto nos permite ofrecerle productos que cumplen con los estándares de calidad más exigentes, manteniendo precios competitivos.\n\nLo que nos diferencia es nuestro enfoque personalizado. Cuando trabaja con Bio Green Wax, lo hace directamente con personas que entienden su industria y se preocupan por su éxito. Nos tomamos el tiempo para entender sus requisitos específicos y ofrecer soluciones a medida.\n\nLe invito a explorar lo que podemos ofrecer a su negocio. Ya sea que necesite aceites comestibles para fabricación de alimentos, ceras especiales para cosmética o soluciones industriales para sus operaciones, estamos aquí para ayudarle.\n\nEspero con interés la oportunidad de atenderle.', '2026-02-08 16:24:00', '2026-02-09 04:23:59'),
(9, 'about-009', 'Hantash Najam', '2026-02-08 16:48:56', '2026-02-09 04:05:46'),
(10, 'about-010', 'Director General, Bio Green Wax Ltd', '2026-02-08 16:49:45', '2026-02-09 04:05:54'),
(11, 'about-011', '15814481', '2026-02-08 16:50:38', '2026-02-09 04:06:04'),
(12, 'about-012', '2 de julio de 2024', '2026-02-08 16:51:04', '2026-02-09 04:23:27'),
(13, 'about-013', '128 City Road, Londres, EC1V 2NX', '2026-02-08 16:51:40', '2026-02-09 04:23:38'),
(14, 'about-014', 'Young Company, Liderazgo Experimentado', '2026-02-08 16:52:36', '2026-02-09 04:23:49'),
(15, 'about-015', 'Aunque Bio Green Wax Ltd fue fundada en 2024, nuestro equipo de liderazgo cuenta con más de 25 años de experiencia combinada en la industria de los aceites y ceras. Esta experiencia nos permite navegar por cadenas de suministro complejas, mantener rigurosos estándares de calidad y ofrecer un valor excepcional a nuestros clientes.', '2026-02-08 16:53:37', '2026-02-09 04:24:24');
INSERT INTO `about_us_content_fr` (`id`, `master_id`, `content_value`, `created_at`, `updated_at`) VALUES
(1, 'about-001', 'À propos de Bio Green Wax', '2026-02-08 15:42:41', '2026-02-09 04:04:20'),
(2, 'about-002', 'Votre partenaire de confiance au Royaume-Uni pour des huiles comestibles premium et des cires industrielles, offrant qualité et durabilité dans le monde entier.', '2026-02-08 15:52:02', '2026-02-09 04:04:30'),
(3, 'about-003', 'Notre Histoire', '2026-02-08 15:53:19', '2026-02-09 04:04:42'),
(4, 'about-004', 'Bio Green Wax Ltd a été constituée en juillet 2024 avec une vision claire : devenir le principal fournisseur d\'huiles naturelles premium et de cires industrielles au Royaume-Uni. Bien que nous soyons une jeune entreprise, notre fondation repose sur des décennies d\'expérience combinée dans l\'industrie de notre équipe de direction.\n\nNous nous spécialisons dans l\'approvisionnement, le traitement et la distribution d\'huiles comestibles de haute qualité et de cires industrielles aux entreprises du Royaume-Uni et à l\'international. De la fabrication alimentaire à la cosmétique, de la pharmacie aux applications industrielles, nos produits répondent aux normes rigoureuses d\'une large gamme de secteurs.\n\nCe qui nous différencie vraiment, c\'est notre capacité à fournir de l\'huile de Palmiers certifiée RSPO SG (Segregated) et ses dérivés — une distinction que de nombreux acteurs établis du secteur n\'ont pas encore réussi à atteindre, car ils dépendent encore de la certification MB (Mass Balance). Notre chaîne d\'approvisionnement Segregated garantit que l\'huile de palme issue d\'une production durable reste physiquement séparée tout au long du processus, offrant à nos clients le plus haut niveau de traçabilité et d\'assurance en matière de durabilité.\n\nNous sommes fiers de fournir des produits de soja, des produits de palme et leurs dérivés qui sont entièrement conformes aux normes EUDR (European Union Deforestation Regulation), assurant que nos chaînes d\'approvisionnement sont sans déforestation et répondent aux dernières réglementations européennes.\n\nDe plus, nous sommes en mesure de fournir des matières premières pour biocarburants, soutenues par des certifications ISCC-EU (International Sustainability and Carbon Certification), répondant à la demande croissante de solutions énergétiques durables et renouvelables.\n\nNotre engagement envers la qualité, la durabilité et le service client nous distingue sur le marché. Nous croyons en la création de partenariats à long terme avec nos clients, en comprenant leurs besoins spécifiques et en fournissant des solutions qui dépassent leurs attentes.', '2026-02-08 15:54:15', '2026-02-11 17:18:07'),
(5, 'about-005', 'Notre mission', '2026-02-08 15:57:02', '2026-02-09 04:05:13'),
(6, 'about-006', 'Être le fournisseur de confiance numéro un au Royaume-Uni en huiles et cires de qualité, en proposant des produits exceptionnels avec un service remarquable tout en maintenant notre engagement envers la durabilité et les pratiques commerciales éthiques.', '2026-02-08 16:00:34', '2026-02-09 04:05:23'),
(7, 'about-007', 'Un message de notre Directeur Général', '2026-02-08 16:02:06', '2026-02-09 04:05:35'),
(8, 'about-008', 'Chers partenaires et clients appréciés,\n\nMerci de prendre le temps de découvrir Bio Green Wax Ltd. Lorsque j\'ai fondé cette entreprise, j\'avais une vision claire : créer une société qui allie des produits de la plus haute qualité à un service client exceptionnel et un engagement sincère envers la durabilité.\n\nNotre équipe possède des décennies d\'expérience dans l\'industrie des huiles et cires, et nous avons établi des relations avec des fournisseurs de confiance à travers le monde. Cela nous permet de vous offrir des produits qui répondent aux normes de qualité les plus exigeantes tout en restant compétitifs.\n\nCe qui nous distingue, c\'est notre approche personnelle. En travaillant avec Bio Green Wax, vous collaborez directement avec des personnes qui comprennent votre secteur et qui se soucient de votre succès. Nous prenons le temps de comprendre vos besoins spécifiques et proposons des solutions adaptées.\n\nJe vous invite à découvrir ce que nous pouvons offrir à votre entreprise. Que vous ayez besoin d\'huiles comestibles pour la fabrication alimentaire, de cires spécialisées pour la cosmétique ou de solutions industrielles pour vos opérations, nous sommes là pour vous aider.\n\nAu plaisir de pouvoir vous servir.', '2026-02-08 16:24:13', '2026-02-09 04:24:01'),
(9, 'about-009', 'Hantash Najam', '2026-02-08 16:48:57', '2026-02-09 04:05:46'),
(10, 'about-010', 'Directeur général, Bio Green Wax Ltd', '2026-02-08 16:49:48', '2026-02-09 04:05:55'),
(11, 'about-011', '15814481', '2026-02-08 16:50:39', '2026-02-09 04:06:05'),
(12, 'about-012', '2 juillet 2024', '2026-02-08 16:51:06', '2026-02-09 04:23:27'),
(13, 'about-013', '128 City Road, Londres, EC1V 2NX', '2026-02-08 16:51:43', '2026-02-09 04:23:38'),
(14, 'about-014', 'Jeune entreprise, direction expérimentée', '2026-02-08 16:52:39', '2026-02-09 04:23:50'),
(15, 'about-015', 'Bien que Bio Green Wax Ltd ait été fondée en 2024, notre équipe de direction cumule plus de 25 ans d\'expérience dans l\'industrie des huiles et des cires. Cette expertise nous permet de naviguer à travers des chaînes d\'approvisionnement complexes, de maintenir des normes de qualité strictes et de fournir une valeur exceptionnelle à nos clients.', '2026-02-08 16:53:41', '2026-02-09 04:24:25');
INSERT INTO `about_us_content_it` (`id`, `master_id`, `content_value`, `created_at`, `updated_at`) VALUES
(1, 'about-001', 'Informazioni su Bio Green Wax', '2026-02-08 15:51:46', '2026-02-09 04:04:27'),
(2, 'about-002', 'Il vostro partner di fiducia nel Regno Unito per oli vegetali di qualità superiore e cere industriali, offrendo eccellenza e sostenibilità in tutto il mondo.', '2026-02-08 15:53:06', '2026-02-09 04:04:39'),
(3, 'about-003', 'La Nostra Storia', '2026-02-08 15:53:39', '2026-02-09 04:04:48'),
(4, 'about-004', 'Bio Green Wax Ltd è stata costituita nel luglio 2024 con una visione chiara: diventare il principale fornitore nel Regno Unito di oli naturali di alta gamma e cere industriali. Pur essendo un\'azienda giovane, la nostra fortezza si basa su decenni di esperienza combinata nel settore della nostra squadra dirigenziale.\n\nSiamo specializzati nella ricerca, lavorazione e distribuzione di oli commestibili di alta qualità e cere industriali a aziende in tutto il Regno Unito e a livello internazionale. Dalla produzione alimentare ai cosmetici, dai prodotti farmaceutici alle applicazioni industriali, i nostri prodotti servono una vasta gamma di settori con standard rigorosi.\n\nCiò che ci distingue realmente è la nostra capacità di fornire olio di palma e derivati certificati RSPO SG (Segregato) — una distinzione che molti attori affermati del settore non hanno ancora raggiunto, poiché continuano a fare affidamento sulla certificazione MB (Mass Balance). La nostra catena di approvvigionamento Segregata garantisce che l\'olio di palma prodotto in modo sostenibile sia mantenuto fisicamente separato durante tutto il processo, offrendo ai nostri clienti il massimo livello di tracciabilità e garanzia di sostenibilità.\n\nSiamo orgogliosi di fornire prodotti a base di Soia, Prodotti di Palma e i loro derivati completamente conformi agli standard EUDR (Regolamento dell\'Unione Europea sulla deforestazione), assicurando che le nostre filiere siano prive di deforestazione e rispettino gli ultimi requisiti normativi europei.\n\nInoltre, siamo in grado di fornire prodotti per biocarburanti supportati da certificazioni ISCC-EU (International Sustainability and Carbon Certification), sostenendo la crescente domanda di soluzioni energetiche sostenibili e rinnovabili.\n\nIl nostro impegno per la qualità, la sostenibilità e il servizio clienti ci distingue nel mercato. Crediamo nella costruzione di partnership a lungo termine con i nostri clienti, comprendendo le loro esigenze uniche e offrendo soluzioni che superano le aspettative.', '2026-02-08 15:56:46', '2026-02-11 17:18:37'),
(5, 'about-005', 'La nostra missione', '2026-02-08 15:57:21', '2026-02-09 04:05:20'),
(6, 'about-006', 'Essere il fornitore di oli e cere di qualità più affidabile del Regno Unito, offrendo prodotti eccezionali con un servizio eccellente, mantenendo al contempo il nostro impegno per la sostenibilità e le pratiche commerciali etiche.', '2026-02-08 16:01:53', '2026-02-09 04:05:33'),
(7, 'about-007', 'Un messaggio del nostro Amministratore Delegato', '2026-02-08 16:02:45', '2026-02-09 04:05:44'),
(8, 'about-008', 'Cari Partners e Clienti Stimati,\n\nGrazie per aver dedicato del tempo a conoscere Bio Green Wax Ltd. Quando ho fondato questa azienda, avevo una visione chiara: creare un\'impresa che combinesse prodotti della più alta qualità con un servizio clienti eccezionale e un autentico impegno per la sostenibilità.\n\nIl nostro team porta decenni di esperienza nel settore degli oli e delle cere, e abbiamo costruito rapporti con fornitori affidabili in tutto il mondo. Ciò ci consente di offrirvi prodotti che rispettano i più elevati standard di qualità, mantenendo prezzi competitivi.\n\nCiò che ci distingue è il nostro approccio personale. Quando lavorate con Bio Green Wax, collaborate direttamente con persone che comprendono il vostro settore e si preoccupano del vostro successo. Dedichiamo tempo a capire le vostre esigenze specifiche e forniamo soluzioni su misura.\n\nVi invito a scoprire cosa possiamo offrire alla vostra attività. Che abbiate bisogno di oli commestibili per la produzione alimentare, cere specializzate per cosmetici o soluzioni industriali per le vostre operazioni, siamo qui per aiutare.\n\nNon vedo l\'ora di avere l\'opportunità di servirvi.', '2026-02-08 16:48:35', '2026-02-09 04:24:20'),
(9, 'about-009', 'Hantash Najam', '2026-02-08 16:49:36', '2026-02-09 04:05:52'),
(10, 'about-010', 'Amministratore Delegato, Bio Green Wax Ltd', '2026-02-08 16:50:27', '2026-02-09 04:06:02'),
(11, 'about-011', '15814481', '2026-02-08 16:50:59', '2026-02-09 04:06:11'),
(12, 'about-012', '2 luglio 2024', '2026-02-08 16:51:32', '2026-02-09 04:23:35'),
(13, 'about-013', '128 City Road, Londra, EC1V 2NX', '2026-02-08 16:52:23', '2026-02-09 04:23:46'),
(14, 'about-014', 'Young Company, Leadership Competente', '2026-02-08 16:53:22', '2026-02-09 04:23:55'),
(15, 'about-015', 'Sebbene Bio Green Wax Ltd sia stata fondata nel 2024, il nostro team di leadership vanta oltre 25 anni di esperienza complessiva nel settore degli oli e delle cere. Questa competenza ci permette di gestire catene di approvvigionamento complesse, mantenere rigorosi standard di qualità e offrire un valore eccezionale ai nostri clienti.', '2026-02-08 16:54:52', '2026-02-09 04:24:37');
INSERT INTO `about_us_content_ja` (`id`, `master_id`, `content_value`, `created_at`, `updated_at`) VALUES
(1, 'about-001', 'Bio Green Waxについて', '2026-02-08 15:42:53', '2026-02-09 04:04:23'),
(2, 'about-002', '高品質な食用油と工業用ワックスの信頼できる英国のパートナーとして、世界中に品質とサステナビリティをお届けします。', '2026-02-08 15:52:26', '2026-02-09 04:04:34'),
(3, 'about-003', '私たちの物語', '2026-02-08 15:53:27', '2026-02-09 04:04:44'),
(4, 'about-004', 'Bio Green Wax Ltdは、2024年7月に設立されました。私たちの明確なビジョンは、英国のプレミアム天然油と工業用ワックスの主要サプライヤーになることです。若い企業ではありますが、当社の礎は、リーダーシップチームの数十年にわたる業界経験に基づいています。\n\n私たちは、高品質な食用油と工業用ワックスの調達、加工、流通を専門とし、英国国内外の企業に供給しています。食品製造から化粧品、医薬品、産業用途まで、多様な業界の厳しい基準に応える製品を提供しています。\n\n私たちの真の強みは、多くの大手企業が未だ実現していないRSPO SG（Segregated）認証のパーム油とその派生製品を供給できることです。私たちのSegregatedサプライチェーンは、サステナブルに生産されたパーム油を全行程で物理的に分離し、顧客に最高レベルのトレーサビリティと持続可能性保証を提供します。\n\nまた、私たちは、EUDR（EU森林破壊規制）基準を完全に遵守した大豆製品、パーム製品、およびその派生品を提供しており、サプライチェーンが違法伐採のない状態で、最新の欧州規制要件を満たしていることを保証します。\n\nさらに、ISCC-EU（International Sustainability and Carbon Certification）認証付きのバイオ燃料原料も供給可能であり、持続可能で再生可能なエネルギーソリューションへの需要に応えています。\n\n私たちの品質、持続可能性、顧客サービスへの取り組みが、市場での差別化要素です。長期的なパートナーシップを築き、お客さまの独自のニーズを理解し、それを超えるソリューションを提供することを信条としています。', '2026-02-08 15:55:10', '2026-02-11 17:18:20'),
(5, 'about-005', '私たちの使命', '2026-02-08 15:57:10', '2026-02-09 04:05:16'),
(6, 'about-006', '品質の高いオイルやワックスの英国内で最も信頼されるサプライヤーとなり、卓越した製品と優れたサービスを提供するとともに、持続可能性と倫理的なビジネス慣行への取り組みを維持します。', '2026-02-08 16:01:09', '2026-02-09 04:05:28'),
(7, 'about-007', '私たちの代表取締役からのメッセージ', '2026-02-08 16:02:24', '2026-02-09 04:05:39'),
(8, 'about-008', '親愛なるパートナー様およびお客様、\n\nこのたびは、Bio Green Wax Ltd.についてご興味を持っていただき、誠にありがとうございます。私がこの会社を設立した際、明確なビジョンを持っていました。それは、最高品質の商品と卓越したカスタマーサービスを融合させ、持続可能性に真剣に取り組むビジネスを作り上げることです。\n\n私たちのチームは、オイルとワックス業界で何十年もの経験を積んでおり、世界各地の信頼できるサプライヤーとの関係を築いています。これにより、最も厳しい品質基準を満たしながらも競争力のある価格で商品を提供することが可能です。\n\n私たちの最大の特徴は、個人的なアプローチにあります。Bio Green Waxとお取引いただく際には、お客様の業界を理解し、成功を願う人々と直接やり取りを行います。お客様の具体的なニーズを理解し、最適なソリューションを提供するために時間をかけています。\n\n私たちが提供できるサービスについてぜひご検討ください。食品製造用の食用油、化粧品用の特殊ワックス、または業務用の産業ソリューションなど、どんなご要望にもお応えいたします。\n\nお客様にお役に立てる機会を心より楽しみにしています。', '2026-02-08 16:25:33', '2026-02-09 04:24:09'),
(9, 'about-009', 'ハンタッシュ・ナジャム', '2026-02-08 16:49:14', '2026-02-09 04:05:49'),
(10, 'about-010', 'バイオグリーンワックス株式会社 マネージングディレクター', '2026-02-08 16:50:06', '2026-02-09 04:05:59'),
(11, 'about-011', '15814481', '2026-02-08 16:50:48', '2026-02-09 04:06:08'),
(12, 'about-012', '2024年7月2日', '2026-02-08 16:51:17', '2026-02-09 04:23:31'),
(13, 'about-013', 'ロンドン市128通り、EC1V 2NX', '2026-02-08 16:52:01', '2026-02-09 04:23:41'),
(14, 'about-014', 'ヤングカンパニー、経験豊富なリーダーシップ', '2026-02-08 16:52:59', '2026-02-09 04:23:52'),
(15, 'about-015', 'Bio Green Wax Ltdは2024年に設立されましたが、私たちのリーダーシップチームは、オイルとワックス業界で合計25年以上の経験を持っています。この専門知識により、複雑なサプライチェーンを管理し、厳格な品質基準を維持し、お客様に卓越した価値を提供することが可能です。', '2026-02-08 16:54:14', '2026-02-09 04:24:30');
INSERT INTO `about_us_content_ko` (`id`, `master_id`, `content_value`, `created_at`, `updated_at`) VALUES
(1, 'about-001', 'Bio Green Wax에 대하여', '2026-02-08 15:51:43', '2026-02-09 04:04:26'),
(2, 'about-002', '전 세계에 품질과 지속 가능성을 제공하는 프리미엄 식용유 및 산업용 왁스의 신뢰받는 영국 파트너입니다.', '2026-02-08 15:52:56', '2026-02-09 04:04:38'),
(3, 'about-003', '우리의 이야기', '2026-02-08 15:53:35', '2026-02-09 04:04:47'),
(4, 'about-004', 'Bio Green Wax Ltd는 2024년 7월에 설립되었으며, 분명한 비전으로 시작했습니다: 영국 최고의 프리미엄 천연 오일과 산업용 왁스 공급업체가 되는 것. 비록 신생 기업이지만, 우리의 토대는 리더십 팀의 수십 년에 걸친 산업 경험에 기반을 두고 있습니다.\n\n우리는 고품질의 먹을 수 있는 오일과 산업용 왁스의 소싱, 가공, 유통을 전문으로 하며, 영국 내외의 기업에 공급하고 있습니다. 식품 제조부터 화장품, 제약 및 산업용 애플리케이션에 이르기까지, 우리의 제품은 높은 기준을 요구하는 다양한 산업군에 서비스를 제공합니다.\n\n우리를 차별화시키는 점은 많은 기존 업체들이 아직 달성하지 못한 RSPO SG(Segregated) 인증 팜오일과 파생품을 공급할 수 있다는 것입니다 — 대부분이 MB(Mass Balance) 인증에 의존하는 가운데, 우리의 Segregated 공급망은 지속가능하게 생산된 팜오일이 전체 과정에서 물리적으로 분리되어 유지됨을 보장하며, 고객에게 최고의 추적 가능성과 지속 가능성 보장을 제공합니다.\n\n또한, 우리는 EUDR(유럽 연합 산림파괴 방지 규정) 표준을 완벽히 준수하는 콩제품, 팜제품 및 그 파생품을 공급하며, 공급망이 산림파괴 없는 상태임을 보증하고 최신 유럽 규제 요구사항을 충족합니다.\n\n더불어, ISCC-EU(국제 지속가능성 및 탄소 인증) 인증이 뒷받침된 바이오연료 원료 공급도 가능하여, 지속 가능하고 재생 가능한 에너지 솔루션에 대한 증가하는 수요를 지원하고 있습니다.\n\n품질, 지속 가능성, 고객 서비스에 대한 우리의 헌신은 시장 내 차별화된 경쟁력을 만들어 냅니다. 우리는 고객과의 장기적 파트너십을 구축하는 것을 믿으며, 그들의 독특한 요구사항을 이해하고 기대를 뛰어넘는 솔루션을 제공하는 것에 최선을 다하고 있습니다.', '2026-02-08 15:56:17', '2026-02-11 17:18:31'),
(5, 'about-005', '우리의 사명', '2026-02-08 15:57:17', '2026-02-09 04:05:18'),
(6, 'about-006', '영국에서 가장 신뢰받는 고품질 오일과 왁스 공급업체가 되어 뛰어난 제품과 탁월한 서비스를 제공하며, 지속 가능성과 윤리적 비즈니스 관행에 대한 우리의 약속을 지켜나가는 것.', '2026-02-08 16:01:41', '2026-02-09 04:05:31'),
(7, 'about-007', '우리 경영이사님의 메시지', '2026-02-08 16:02:38', '2026-02-09 04:05:42'),
(8, 'about-008', '존경하는 파트너 및 고객님께,\n\nBio Green Wax Ltd.를 알아보는 시간을 내어 주셔서 감사합니다. 이 회사를 창립했을 때의 명확한 비전은 최고 품질의 제품과 뛰어난 고객 서비스, 그리고 진정한 지속 가능성에 대한 헌신을 결합하는 비즈니스를 만드는 것이었습니다.\n\n저희 팀은 오일과 왁스 산업에서 수십 년의 경험을 가지고 있으며, 신뢰할 수 있는 공급업체들과 전 세계적으로 관계를 구축해 왔습니다. 이를 통해 최고 수준의 품질 기준을 충족하면서도 경쟁력 있는 가격의 제품을 제공할 수 있습니다.\n\n저희를 차별화시키는 점은 바로 개인적인 접근 방식입니다. Bio Green Wax와 함께 일할 때는 업계에 대한 이해와 성공에 대한 열정을 가진 사람들과 직접 협력하게 됩니다. 고객님의 구체적인 요구 사항을 이해하고 맞춤 솔루션을 제공하는 데 최선을 다합니다.\n\n저희가 제공할 수 있는 서비스가 고객님의 비즈니스에 어떤 도움이 될 수 있을지 함께 알아보시기 바랍니다. 식품 제조를 위한 식용 오일, 화장품용 특수 왁스, 또는 귀하의 산업 운영에 필요한 산업 솔루션이 필요하신 경우 언제든 도와드리겠습니다.\n\n여러분께 서비스를 제공할 기회를 고대하겠습니다.', '2026-02-08 16:48:03', '2026-02-09 04:24:17'),
(9, 'about-009', '한타쉬 나자침', '2026-02-08 16:49:27', '2026-02-09 04:05:51'),
(10, 'about-010', '생명 그린 왁스 주식회사 이사', '2026-02-08 16:50:21', '2026-02-09 04:06:01'),
(11, 'about-011', '15814481', '2026-02-08 16:50:56', '2026-02-09 04:06:10'),
(12, 'about-012', '2024년 7월 2일', '2026-02-08 16:51:26', '2026-02-09 04:23:34'),
(13, 'about-013', '128 City Road, 런던, EC1V 2NX', '2026-02-08 16:52:15', '2026-02-09 04:23:45'),
(14, 'about-014', 'Young Company, Experienced Leadership', '2026-02-08 16:53:13', '2026-02-09 04:23:54'),
(15, 'about-015', 'Bio Green Wax Ltd는 2024년에 설립되었지만, 저희 리더십 팀은 오일과 왁스 산업에서 총 25년 이상 쌓아온 경험을 보유하고 있습니다. 이러한 전문성은 복잡한 공급망을 원활하게 관리하고 엄격한 품질 기준을 유지하며 고객에게 뛰어난 가치를 제공하는 데 큰 도움이 되고 있습니다.', '2026-02-08 16:54:42', '2026-02-09 04:24:34');
INSERT INTO `about_us_content_pl` (`id`, `master_id`, `content_value`, `created_at`, `updated_at`) VALUES
(1, 'about-001', 'O Bio Green Wax', '2026-02-08 15:51:48', '2026-02-09 04:04:28'),
(2, 'about-002', 'Twój zaufany partner w Wielkiej Brytanii w zakresie wysokiej jakości olejów jadalnych i wosków przemysłowych, dostarczający jakość i zrównoważony rozwój na całym świecie.', '2026-02-08 15:53:13', '2026-02-09 04:04:40'),
(3, 'about-003', 'Nasza historia', '2026-02-08 15:53:42', '2026-02-09 04:04:48'),
(4, 'about-004', 'Bio Green Wax Ltd zostało zarejestrowane w lipcu 2024 roku z jasno określoną wizją: stać się wiodącym dostawcą wysokiej jakości naturalnych olejów i wosków przemysłowych w Wielkiej Brytanii. Choć jesteśmy młodą firmą, nasze fundamenty opierają się na dziesięcioleciach wspólnego doświadczenia w branży naszego zespołu zarządzającego.\n\nSpecjalizujemy się w pozyskiwaniu, przetwarzaniu i dystrybucji wysokiej jakości olejów jadalnych oraz wosków przemysłowych dla przedsiębiorstw w całej Wielkiej Brytanii i na arenie międzynarodowej. Od produkcji spożywczej po kosmetyki, farmaceutyki i zastosowania przemysłowe — nasze produkty obsługują różnorodne branże, które stawiają wysokie wymagania.\n\nCo naprawdę nas wyróżnia, to nasza możliwość dostarczania oleju palmowego i jego pochodnych, certyfikowanych według standardu RSPO SG (Segregated) — oznaczenie, które wielu ugruntowanych graczy na rynku jeszcze nie osiągnęło, gdyż wciąż opiera się na certyfikacji MB (Mass Balance). Nasz łańcuch dostaw Segregated zapewnia, że zrównoważenie produkcja oleju palmowego jest utrzymywana w sposób fizycznie odseparowany na wszystkich etapach, oferując naszym klientom najwyższy poziom śledzenia pochodzenia i zapewnienia zrównoważonego rozwoju.\n\nJesteśmy dumni z dostarczania produktów sojowych, palmowych i ich pochodnych, które są w pełni zgodne z normami EUDR (European Union Deforestation Regulation), zapewniając, że nasze łańcuchy dostaw są wolne od wylesiania i spełniają najnowsze unijne wymogi regulacyjne.\n\nPonadto, możemy dostarczać surowce do biopaliw, wspierane certyfikatami ISCC-EU (International Sustainability and Carbon Certification), co odpowiada rosnącemu zapotrzebowaniu na zrównoważone i odnawialne źródła energii.\n\nNasze zaangażowanie w jakość, zrównoważony rozwój i obsługę klienta wyróżnia nas na rynku. Wierzymy w budowanie długoterminowych partnerstw z naszymi klientami, poznanie ich unikalnych potrzeb i dostarczanie rozwiązań, które przewyższają oczekiwania.', '2026-02-08 15:56:56', '2026-02-11 17:18:40'),
(5, 'about-005', 'Nasza Misja', '2026-02-08 16:00:21', '2026-02-09 04:05:20'),
(6, 'about-006', 'Być najbardziej zaufanym dostawcą wysokiej jakości olejów i wosków w Wielkiej Brytanii, dostarczając produkty wyjątkowej jakości i doskonałą obsługę, jednocześnie utrzymując zaangażowanie w zrównoważony rozwój i etyczne praktyki biznesowe.', '2026-02-08 16:01:58', '2026-02-09 04:05:33'),
(7, 'about-007', 'Wiadomość od naszego Dyrektora Zarządzającego', '2026-02-08 16:23:37', '2026-02-09 04:05:44'),
(8, 'about-008', 'Szanowni Partnerzy i Klienci,\n\nDziękujemy za poświęcenie czasu na poznanie firmy Bio Green Wax Ltd. Gdy zakładałem tę firmę, miałem jasno określoną wizję: stworzyć przedsiębiorstwo łączące produkty najwyższej jakości z doskonałą obsługą klienta i autentycznym zaangażowaniem w zrównoważony rozwój.\n\nNasz zespół posiada dziesięciolecia doświadczenia w branży olejów i wosków, a także wybudowaliśmy relacje z zaufanymi dostawcami na całym świecie. Dzięki temu możemy zaoferować produkty spełniające najbardziej wymagające standardy jakości, przy jednoczesnym zachowaniu konkurencyjnych cen.\n\nCo nas wyróżnia, to indywidualne podejście. Współpracując z Bio Green Wax, masz kontakt bezpośrednio z ludźmi, którzy rozumieją Twoją branżę i dbają o Twój sukces. Poświęcamy czas na poznanie Twoich szczególnych wymagań i dostarczamy rozwiązania szyte na miarę.\n\nZapraszam do zapoznania się z naszą ofertą dla Twojego biznesu. Niezależnie od tego, czy potrzebujesz olejów jadalnych do produkcji spożywczej, specjalistycznych wosków do kosmetyków, czy rozwiązań przemysłowych dla Twojej działalności, jesteśmy tu, aby pomóc.\n\nCzekam na możliwość, by móc służyć Państwu pomocą.', '2026-02-08 16:48:50', '2026-02-09 04:24:22'),
(9, 'about-009', 'Hantash Najam', '2026-02-08 16:49:38', '2026-02-09 04:05:53'),
(10, 'about-010', 'Dyrektor Zarządzający, Bio Green Wax Ltd', '2026-02-08 16:50:31', '2026-02-09 04:06:03'),
(11, 'about-011', '15814481', '2026-02-08 16:51:01', '2026-02-09 04:06:12'),
(12, 'about-012', '2 lipca 2024', '2026-02-08 16:51:33', '2026-02-09 04:23:36'),
(13, 'about-013', '128 City Road, Londyn, EC1V 2NX', '2026-02-08 16:52:28', '2026-02-09 04:23:47'),
(14, 'about-014', 'Młoda firma, doświadczone kierownictwo', '2026-02-08 16:53:25', '2026-02-09 04:23:56'),
(15, 'about-015', 'Chociaż Bio Green Wax Ltd zostało założone w 2024 roku, nasz zespół kierowniczy posiada ponad 25 lat łącznego doświadczenia w branży olejów i wosków. Ta wiedza pozwala nam na poruszanie się po złożonych łańcuchach dostaw, utrzymanie rygorystycznych standardów jakości oraz dostarczanie naszym klientom wyjątkowej wartości.', '2026-02-08 16:54:58', '2026-02-09 04:24:38');
INSERT INTO `about_us_content_pt` (`id`, `master_id`, `content_value`, `created_at`, `updated_at`) VALUES
(1, 'about-001', 'Sobre Bio Green Wax', '2026-02-08 15:42:46', '2026-02-09 04:04:22'),
(2, 'about-002', 'Seu parceiro confiável no Reino Unido para óleos comestíveis premium e ceras industriais, oferecendo qualidade e sustentabilidade em todo o mundo.', '2026-02-08 15:52:09', '2026-02-09 04:04:32'),
(3, 'about-003', 'Nossa História', '2026-02-08 15:53:22', '2026-02-09 04:04:43'),
(4, 'about-004', 'A Bio Green Wax Ltd foi fundada em julho de 2024 com uma visão clara: tornar-se o principal fornecedor de óleos naturais premium e ceras industriais no Reino Unido. Apesar de sermos uma empresa jovem, nossa base é construída em décadas de experiência combinada do setor por parte de nossa liderança.\n\nEspecializamo-nos em pesquisar, processar e distribuir óleos comestíveis de alta qualidade e ceras industriais para empresas em todo o Reino Unido e internacionalmente. Desde a fabricação de alimentos até cosméticos, farmacêuticos e aplicações industriais, nossos produtos atendem a uma ampla variedade de indústrias com padrões rigorosos.\n\nO que realmente nos diferencia é nossa capacidade de fornecer óleo de palma e derivados certificados RSPO SG (Segregated) — uma distinção que muitos players estabelecidos no setor ainda não conquistaram, uma vez que permanecem dependentes da certificação MB (Mass Balance). Nossa cadeia de suprimentos Segregated garante que o óleo de palma produzido de forma sustentável seja mantido fisicamente separado durante todo o processo, oferecendo aos nossos clientes o mais alto nível de rastreabilidade e garantia de sustentabilidade.\n\nTemos orgulho de fornecer Produtos de Soja, Produtos de Palma e seus derivados que estão totalmente em conformidade com os padrões EUDR (Regulamento da União Europeia sobre o Desmatamento), garantindo que nossas cadeias de suprimento sejam livres de desmatamento e atendam às últimas exigências regulatórias europeias.\n\nAlém disso, somos capazes de fornecer matérias-primas para biocombustíveis apoiadas pelas certificações ISCC-EU (International Sustainability and Carbon Certification), atendendo à crescente demanda por soluções energéticas sustentáveis e renováveis.\n\nNosso compromisso com qualidade, sustentabilidade e atendimento ao cliente nos diferencia no mercado. Acreditamos em construir parcerias de longo prazo com nossos clientes, entendendo suas necessidades específicas e entregando soluções que excedem expectativas.', '2026-02-08 15:54:38', '2026-02-11 17:18:12'),
(5, 'about-005', 'Nossa Missão', '2026-02-08 15:57:05', '2026-02-09 04:05:14'),
(6, 'about-006', 'Ser o fornecedor de óleos e ceras de maior confiança do Reino Unido, oferecendo produtos excepcionais com um serviço de excelência, ao mesmo tempo em que mantemos nosso compromisso com a sustentabilidade e práticas comerciais éticas.', '2026-02-08 16:00:46', '2026-02-09 04:05:26'),
(7, 'about-007', 'Uma mensagem do nosso Diretor Geral', '2026-02-08 16:02:12', '2026-02-09 04:05:37'),
(8, 'about-008', 'Prezado(a) Parceiro(a) e Cliente Valorizado(a),\n\nAgradecemos por dedicar seu tempo para conhecer a Bio Green Wax Ltd. Quando fundei esta empresa, tinha uma visão clara: criar um negócio que combine produtos da mais alta qualidade com um atendimento excepcional ao cliente e um compromisso genuíno com a sustentabilidade.\n\nNossa equipe traz décadas de experiência na indústria de óleos e cera, e estabelecemos relacionamento com fornecedores confiáveis ao redor do mundo. Isso nos permite oferecer produtos que atendem aos mais exigentes padrões de qualidade, mantendo preços competitivos.\n\nO que nos diferencia é nossa abordagem personalizada. Quando você trabalha com a Bio Green Wax, você trabalha diretamente com pessoas que entendem sua indústria e se importam com o seu sucesso. Reservamos tempo para entender suas necessidades específicas e oferecer soluções sob medida.\n\nConvido você a explorar o que podemos oferecer para o seu negócio. Se você precisa de óleos comestíveis para fabricação de alimentos, ceras especiais para cosméticos ou soluções industriais para suas operações, estamos aqui para ajudar.\n\nAnsioso para a oportunidade de servi-lo(a).', '2026-02-08 16:24:46', '2026-02-09 04:24:04'),
(9, 'about-009', 'Hantash Najam', '2026-02-08 16:49:05', '2026-02-09 04:05:47'),
(10, 'about-010', 'Diretor Geral, Bio Green Wax Ltd', '2026-02-08 16:49:56', '2026-02-09 04:05:56'),
(11, 'about-011', '15814481', '2026-02-08 16:50:44', '2026-02-09 04:06:06'),
(12, 'about-012', '2 de julho de 2024', '2026-02-08 16:51:11', '2026-02-09 04:23:28'),
(13, 'about-013', '128 City Road, Londres, EC1V 2NX', '2026-02-08 16:51:49', '2026-02-09 04:23:40'),
(14, 'about-014', 'Young Company, Liderança Experiente', '2026-02-08 16:52:45', '2026-02-09 04:23:51'),
(15, 'about-015', 'Embora a Bio Green Wax Ltd tenha sido fundada em 2024, nossa equipe de liderança possui mais de 25 anos de experiência combinada na indústria de óleos e ceras. Essa expertise nos permite navegar por cadeias de suprimentos complexas, manter rigorosos padrões de qualidade e oferecer um valor excepcional aos nossos clientes.', '2026-02-08 16:53:54', '2026-02-09 04:24:27');
INSERT INTO `about_us_content_ru` (`id`, `master_id`, `content_value`, `created_at`, `updated_at`) VALUES
(1, 'about-001', 'О Bio Green Wax', '2026-02-08 15:42:49', '2026-02-09 04:04:22'),
(2, 'about-002', 'Ваш надежный партнер из Великобритании по поставкам премиальных съедобных масел и промышленных восков, обеспечивающий качество и устойчивость по всему миру.', '2026-02-08 15:52:15', '2026-02-09 04:04:32'),
(3, 'about-003', 'Наша история', '2026-02-08 15:53:23', '2026-02-09 04:04:44'),
(4, 'about-004', 'Bio Green Wax Ltd была зарегистрирована в июле 2024 года с ясной целью: стать ведущим поставщиком премиальных натуральных масел и промышленных восков в Великобритании. Несмотря на молодость компании, наш фундамент основан на десятилетиях совокупного опыта нашей управленческой команды в отрасли.\n\nМы специализируемся на поиске, переработке и дистрибуции высококачественных пищевых масел и промышленных восков для предприятий по всей Великобритании и за границей. От производства продуктов питания до косметики, фармацевтики и промышленных применений — наши продукты обслуживают широкий спектр отраслей с высокими стандартами.\n\nЧто по-настоящему выделяет нас, — это наша способность поставлять сертифицированный RSPO SG (Segregated) пальмовый маслο и его производные — отличие, которого многие устоявшиеся игроки отрасли еще не достигли, оставаясь при этом зависимыми от сертификации MB (Mass Balance). Наша цепочка поставок Segregated гарантирует, что устойчиво произведенный пальмовый маслο остается физически раздельным на протяжении всего процесса, что обеспечивает наших клиентов высочайшим уровнем прослеживаемости и экологической ответственности.\n\nМы с гордостью поставляем Soy Products, Palm Products и их производные, полностью соответствующие стандартам EUDR (European Union Deforestation Regulation), что гарантирует отсутствие вырубки лесов в наших цепочках поставок и соблюдение последних европейских нормативных требований.\n\nКроме того, мы можем поставлять сырье для биотоплива, подтвержденное сертификатами ISCC-EU (International Sustainability and Carbon Certification), что поддерживает растущий спрос на устойчивые и возобновляемые источники энергии.\n\nНаше стремление к качеству, устойчивости и обслуживанию клиентов отличает нас на рынке. Мы верим в построение долгосрочных партнерств с нашими клиентами, понимание их уникальных требований и предоставление решений, которые превосходят ожидания.', '2026-02-08 15:54:48', '2026-02-11 17:18:15'),
(5, 'about-005', 'Наша миссия', '2026-02-08 15:57:06', '2026-02-09 04:05:15'),
(6, 'about-006', 'Стать самым надежным поставщиком качественных масел и восков в Великобритании, поставляя исключительную продукцию с превосходным обслуживанием, при этом сохраняя нашу приверженность устойчивому развитию и этичной бизнес-практике.', '2026-02-08 16:00:52', '2026-02-09 04:05:26'),
(7, 'about-007', 'Сообщение от нашего управляющего директора', '2026-02-08 16:02:15', '2026-02-09 04:05:38'),
(8, 'about-008', 'Уважаемые партнеры и клиенты,\n\nБлагодарим вас за то, что нашли время ознакомиться с компанией Bio Green Wax Ltd. Когда я основал эту компанию, у меня было четкое видение: создать бизнес, который объединяет продукты высочайшего качества, исключительный уровень обслуживания и искреннюю приверженность устойчивому развитию.\n\nНаша команда обладает десятилетиями опыта в сфере масел и восков, и мы наладили отношения с проверенными поставщиками по всему миру. Это позволяет нам предлагать вам продукцию, которая соответствует самым строгим стандартам качества при при этом оставаясь конкурентоспособной по цене.\n\nЧто выделяет нас, так это наш личный подход. Работая с Bio Green Wax, вы взаимодействуете напрямую с людьми, которые понимают вашу отрасль и заботятся о вашем успехе. Мы уделяем время тому, чтобы понять ваши конкретные требования и предложить индивидуальные решения.\n\nПриглашаю вас ознакомиться с тем, что мы можем предложить вашему бизнесу. Независимо от того, нужны ли вам съедобные масла для пищевой промышленности, специальные воски для косметики или промышленные решения для ваших операций, мы готовы помочь.\n\nС нетерпением жду возможности обслужить вас.', '2026-02-08 16:25:01', '2026-02-09 04:24:06'),
(9, 'about-009', 'Hantash Najam', '2026-02-08 16:49:08', '2026-02-09 04:05:48'),
(10, 'about-010', 'Генеральный директор, Bio Green Wax Ltd', '2026-02-08 16:49:58', '2026-02-09 04:05:57'),
(11, 'about-011', '15814481', '2026-02-08 16:50:45', '2026-02-09 04:06:07'),
(12, 'about-012', '2 июля 2024', '2026-02-08 16:51:13', '2026-02-09 04:23:30'),
(13, 'about-013', '128 City Road, Лондон, EC1V 2NX', '2026-02-08 16:51:52', '2026-02-09 04:23:40'),
(14, 'about-014', 'Молодая компания, опытное руководство', '2026-02-08 16:52:49', '2026-02-09 04:23:51'),
(15, 'about-015', 'Хотя компания Bio Green Wax Ltd была основана в 2024 году, наша команда руководителей обладает более чем 25-летним совокупным опытом в индустрии масел и восков. Этот опыт позволяет нам управлять сложными цепочками поставок, соблюдать строгие стандарты качества и предоставлять нашим клиентам исключительную ценность.', '2026-02-08 16:54:02', '2026-02-09 04:24:28');
INSERT INTO `about_us_content_sw` (`id`, `master_id`, `content_value`, `created_at`, `updated_at`) VALUES
(1, 'about-001', 'Kuhusu Bio Green Wax', '2026-02-08 15:42:55', '2026-02-09 04:04:24'),
(2, 'about-002', 'Mshirika wako wa kuaminika wa Uingereza kwa mafuta ya kuliwa ya ubora wa juu na wax za viwandani, ukileta ubora na uendelevu duniani kote.', '2026-02-08 15:52:37', '2026-02-09 04:04:34'),
(3, 'about-003', 'Hadithi yetu', '2026-02-08 15:53:29', '2026-02-09 04:04:45'),
(4, 'about-004', 'Bio Green Wax Ltd iliundwa mwezi Julai 2024 kwa maono wazi: kuwa wasambazaji mkuu wa mafuta asilia ya hali ya juu na wax ya viwandani nchini Uingereza. Ingawa sisi ni kampuni changa, msingi wetu umejengwa juu ya miongo kadhaa ya uzoefu wa pamoja wa sekta kutoka kwa timu yetu ya uongozi.\n\nTunabobea katika kupata, kusindika, na kusambaza mafuta ya chakula ya ubora wa hali ya juu na wax za viwandani kwa biashara kote Uingereza na kimataifa. Kuanzia utengenezaji wa vyakula hadi cosmetics, dawa, na matumizi ya viwandani, bidhaa zetu zinahudumia sekta mbalimbali kwa viwango vya hali ya juu kabisa.\n\nKinachotutofautisha kweli ni uwezo wetu wa kusambaza <i>RSPO SG (Segregated)</i> certified palm oil na bidhaa zake — tofauti ambayo wasambazaji wengi wa imani wanayo bado hawajafanikiwa, kwani bado wanajiwekea utegemezi wa <i>MB (Mass Balance)</i> certification. Mnyororo wetu wa usambazaji wa Segregated humakikisha kuwa mafuta ya mseto ya palm yanapatikana kwa kuviweka vimwe kwa mchakato wote, na kutoa wateja wetu kiwango cha juu zaidi cha ufuatiliaji na uhakika wa usalama wa mazingira.\n\nTuna fahari kusambaza <i>Soy Products</i>, <i>Palm Products</i>, na bidhaa zake zinazokubaliana kikamilifu na viwango vya <i>EUDR (European Union Deforestation Regulation)</i>, kuhakikisha kuwa mipango yetu ya usambazaji haina kuharibu misitu na inakidhi mahitaji ya sheria za Ulaya za hivi karibuni.\n\nAidha, tunaweza kusambaza bidhaa za malighafi za BIOFUELS zilizothibitishwa na ISCC-EU (International Sustainability and Carbon Certification), zikisaidia katika mahitaji yanayoongezeka kwa njia za nishati endelevu na zinazoweza kurejeshwa.\n\nJuhudi zetu kwa ubora, mazingira, na huduma kwa wateja zinatufanya tuwe tofauti katika soko. Tunaamini kujenga ushirikiano wa muda mrefu na wateja wetu, kuelewa mahitaji yao mahususi, na kuwatangazia suluhisho zinazovuka matarajio.', '2026-02-08 15:55:31', '2026-02-11 17:18:22'),
(5, 'about-005', 'Dhamira Yetu', '2026-02-08 15:57:12', '2026-02-09 04:05:16'),
(6, 'about-006', 'Kuwa msambazaji wa kuaminika zaidi wa mafuta na waxes bora nchini Uingereza, nikileta bidhaa za kipekee pamoja na huduma nzuri wakati wetu ukihakikisha kujali mazingira na maadili ya biashara.', '2026-02-08 16:01:18', '2026-02-09 04:05:29'),
(7, 'about-007', 'Ujumbe kutoka kwa Mkurugenzi Mkuu wetu', '2026-02-08 16:02:26', '2026-02-09 04:05:39'),
(8, 'about-008', 'Wapenzi Washirika Wathamani na Wateja,\n\nAsanteni kwa kuchukua muda kujifunza kuhusu Bio Green Wax Ltd. Nilipoanzisha kampuni hii, nilikuwa na maono wazi: kuunda biashara inayochanganya bidhaa za ubora wa juu na huduma bora kwa wateja na kujitolea kwa dhati kwa uchumi wa kabambe.\n\nTimu yetu inayo uzoefu wa miongo kadhaa katika sekta ya mafuta na wax, na tumejenga uhusiano na wasambazaji wanaoaminika duniani kote. Hii inatuwezesha kukupatia bidhaa zinazokidhi viwango vya ubora vya juu zaidi huku zikikubalika bei.\n\nKitu kinachotutofautisha ni mtazamo wetu wa kipekee. Unapofanya kazi na Bio Green Wax, unafanya kazi moja kwa moja na watu wanaoelewa tasnia yako na kujali mafanikio yako. Tunachukua muda kuelewa mahitaji yako maalum na kutoa suluhisho zilizobuniwa mahususi.\n\nNakualika uangalie yale tunaoweza kutoa kwa biashara yako. Ikiwa unahitaji mafuta ya chakula kwa utengenezaji wa vyakula, wax maalum kwa vipodozi, au suluhisho za viwanda kwa shughuli zako, tuko hapa kusaidia.\n\nNatarajia nafasi ya kukuhudumia.', '2026-02-08 16:25:51', '2026-02-09 04:24:11'),
(9, 'about-009', 'Hantash Najam', '2026-02-08 16:49:16', '2026-02-09 04:05:49'),
(10, 'about-010', 'Mkurugenzi Mtendaji, Bio Green Wax Ltd', '2026-02-08 16:50:08', '2026-02-09 04:05:59'),
(11, 'about-011', '15814481', '2026-02-08 16:50:49', '2026-02-09 04:06:09'),
(12, 'about-012', '2 Julai 2024', '2026-02-08 16:51:19', '2026-02-09 04:23:32'),
(13, 'about-013', '128 City Road, London, EC1V 2NX', '2026-02-08 16:52:04', '2026-02-09 04:23:42'),
(14, 'about-014', 'Kampuni Ndogo, Uongozi Unaébobea', '2026-02-08 16:53:04', '2026-02-09 04:23:53'),
(15, 'about-015', 'Ingawaje Bio Green Wax Ltd ilianzishwa mwaka wa 2024, timu yetu ya uongozi ina zaidi ya miaka 25 ya uzoefu wa pamoja katika sekta ya mafuta na wax. Uzoefu huu unatuwezesha kusafirisha minyororo tata ya usambazaji, kudumisha viwango vya ubora wa hali ya juu, na kutoa thamani ya kipekee kwa wateja wetu.', '2026-02-08 16:54:23', '2026-02-09 04:24:31');
INSERT INTO `about_us_content_th` (`id`, `master_id`, `content_value`, `created_at`, `updated_at`) VALUES
(1, 'about-001', 'เกี่ยวกับ Bio Green Wax', '2026-02-08 15:51:44', '2026-02-09 04:04:26'),
(2, 'about-002', 'พันธมิตรที่เชื่อถือได้จากสหราชอาณาจักรของคุณสำหรับน้ำมันบริโภคระดับพรีเมียมและขี้ผึ้งอุตสาหกรรม ส่งมอบคุณภาพและความยั่งยืนทั่วโลก', '2026-02-08 15:53:01', '2026-02-09 04:04:39'),
(3, 'about-003', 'เรื่องราวของเรา', '2026-02-08 15:53:36', '2026-02-09 04:04:47'),
(4, 'about-004', 'บริษัท Bio Green Wax Ltd ก่อตั้งขึ้นในเดือนกรกฎาคม 2024 ด้วยวิสัยทัศน์ที่ชัดเจน: เพื่อกลายเป็นผู้จัดหาน้ำมันธรรมชาติเบื้องต้นและเทียนอุตสาหกรรมชั้นนำของสหราชอาณาจักร ถึงแม้ว่าเราเป็นบริษัทที่เพิ่งก่อตั้ง แต่รากฐานของเราได้รับการสร้างขึ้นจากประสบการณ์ในอุตสาหกรรมรวมกันหลายทศวรรษของทีมผู้นำของเรา\n\nเรามีความเชี่ยวชาญในการหาแหล่งวัตถุดิบ การแปรรูป และการจัดจำหน่ายน้ำมันรับประทานและเทียนอุตสาหกรรมคุณภาพสูง ไปยังธุรกิจต่าง ๆ ทั่วสหราชอาณาจักรและต่างประเทศ ตั้งแต่การผลิตอาหาร ไปจนถึงเครื่องสำอาง ยารักษาโรค ไปจนถึงการใช้งานในอุตสาหกรรม ผลิตภัณฑ์ของเราให้บริการแก่หลากหลายอุตสาหกรรมด้วยมาตรฐานที่เข้มงวด\n\nสิ่งที่ทำให้เราแตกต่างอย่างแท้จริงคือความสามารถในการจัดจำหน่ายน้ำมันปาล์มและสารประกอบที่ได้รับการรับรอง RSPO SG (Segregated) — ซึ่งเป็นความแตกต่างที่ผู้เล่นในอุตสาหกรรมที่มีชื่อเสียงหลายรายยังไม่สามารถบรรลุได้ เนื่องจากพวกเขายังคงพึ่งพาการรับรอง MB (Mass Balance) เท่านั้น ห่วงโซ่อุปทานแบบ Segregated ของเรารับประกันว่าน้ำมันปาล์มที่ผลิตอย่างยั่งยืนจะถูกแยกออกอย่างชัดเจนตลอดทั้งกระบวนการ เพื่อมอบความสามารถในการติดตามและการรับรองความยั่งยืนสูงสุดแก่ลูกค้า\n\nเราเป็นผู้นำเสนอผลิตภัณฑ์จากถั่วเหลือง น้ำมันปาล์ม และสารประกอบต่าง ๆ ที่เป็นไปตามมาตรฐาน EUDR (European Union Deforestation Regulation) อย่างเต็มรูปแบบ เพื่อให้แน่ใจว่าห่วงโซ่อุปทานของเราเป็นไปโดยไม่ทำลายป่าไม้และสอดคล้องกับข้อกำหนดของกฎหมายยุโรปล่าสุด\n\nนอกจากนี้ เรายังสามารถจัดหาเสบียงเชื้อเพลิงชีวภาพที่ได้รับการรับรองโดย ISCC-EU (International Sustainability and Carbon Certification) เพื่อสนับสนุนความต้องการที่เพิ่มขึ้นสำหรับพลังงานที่ยั่งยืนและหมุนเวียน\n\nความมุ่งมั่นของเราต่อคุณภาพ ความยั่งยืน และการบริการลูกค้า ทำให้เราแตกต่างในตลาด เราเชื่อในการสร้างความสัมพันธ์ระยะยาวกับลูกค้า เข้าใจความต้องการเฉพาะของพวกเขา และมอบโซลูชันที่เกินความคาดหมาย', '2026-02-08 15:56:33', '2026-02-11 17:18:34'),
(5, 'about-005', 'พันธกิจของเรา', '2026-02-08 15:57:19', '2026-02-09 04:05:19'),
(6, 'about-006', 'เพื่อเป็นผู้จำหน่ายน้ำมันและข wax ที่น่าเชื่อถือที่สุดในสหราชอาณาจักร ส่งมอบผลิตภัณฑ์คุณภาพเยี่ยม พร้อมบริการที่ยอดเยี่ยม ในขณะเดียวกันก็รักษาความมุ่งมั่นด้านความยั่งยืนและแนวปฏิบัติทางธุรกิจที่มีจริยธรรม', '2026-02-08 16:01:48', '2026-02-09 04:05:32'),
(7, 'about-007', 'ข้อความจากผู้จัดการฝ่ายบริหารของเรา', '2026-02-08 16:02:40', '2026-02-09 04:05:43'),
(8, 'about-008', 'เรียน คู่ค้าและลูกค้าที่เคารพ,\n\nขอขอบคุณที่สละเวลาเรียนรู้เกี่ยวกับ Bio Green Wax Ltd. เมื่อผมก่อตั้งบริษัทนี้ขึ้นมาผมมีวิสัยทัศน์ชัดเจน: เพื่อสร้างธุรกิจที่ผสมผสานผลิตภัณฑ์คุณภาพสูงสุดเข้ากับการบริการลูกค้าที่ยอดเยี่ยมและความมุ่งมั่นอย่างแท้จริงต่อความยั่งยืน\n\nทีมของเรามีประสบการณ์ในอุตสาหกรรมออยล์และแว็กซ์มาหลายทศวรรษ และเราได้สร้างความสัมพันธ์กับซัพพลายเออร์ที่เชื่อถือได้ทั่วโลก ซึ่งช่วยให้เราสามารถนำเสนอผลิตภัณฑ์ที่มีมาตรฐานคุณภาพสูงสุดในขณะที่ยังสามารถรักษาราคาให้แข่งขันได้\n\nสิ่งที่ทำให้เราแตกต่างคือแนวทางส่วนตัวของเรา เมื่อคุณทำงานกับ Bio Green Wax คุณจะได้ทำงานโดยตรงกับผู้เชี่ยวชาญที่เข้าใจในอุตสาหกรรมของคุณและใส่ใจในความสำเร็จของคุณ เราใช้เวลาเพื่อเข้าใจความต้องการเฉพาะของคุณและนำเสนอโซลูชันที่ปรับแต่งให้ตรงใจ\n\nขอเชิญคุณสำรวจสิ่งที่เราสามารถนำเสนอให้กับธุรกิจของคุณ ไม่ว่าคุณจะต้องการน้ำมันรับประทานสำหรับการผลิตอาหาร, แว็กซ์เฉพาะทางสำหรับเครื่องสำอาง หรือโซลูชันทางอุตสาหกรรมสำหรับการดำเนินงานของคุณ เรายินดีที่จะช่วยเหลือ\n\nผมตั้งตารอโอกาสที่จะรับใช้คุณ', '2026-02-08 16:48:20', '2026-02-09 04:24:19'),
(9, 'about-009', 'ฮันตาช นาจาม', '2026-02-08 16:49:35', '2026-02-09 04:05:52'),
(10, 'about-010', 'กรรมการผู้จัดการ, Bio Green Wax Ltd', '2026-02-08 16:50:25', '2026-02-09 04:06:02'),
(11, 'about-011', '15814481', '2026-02-08 16:50:58', '2026-02-09 04:06:11'),
(12, 'about-012', '2 กรกฎาคม 2024', '2026-02-08 16:51:29', '2026-02-09 04:23:35'),
(13, 'about-013', '128 ถนนซิตี้, ลอนดอน, EC1V 2NX', '2026-02-08 16:52:20', '2026-02-09 04:23:46'),
(14, 'about-014', 'บริษัทหย่อง นักนำที่มีประสบการณ์', '2026-02-08 16:53:17', '2026-02-09 04:23:55'),
(15, 'about-015', 'แม้ว่าบริษัท Bio Green Wax Ltd ก่อตั้งขึ้นในปี 2024 ทีมผู้นำของเรามีประสบการณ์รวมกันมากกว่า 25 ปีในอุตสาหกรรมน้ำมันและข wax สารนี้ช่วยให้เราสามารถนำทางซับซ้อนซ่อนเงื่อนในห่วงโซ่อุปทาน รักษาระดับมาตรฐานคุณภาพที่เข้มงวด และมอบคุณค่าที่ยอดเยี่ยมให้แก่ลูกค้าของเรา', '2026-02-08 16:54:48', '2026-02-09 04:24:35');
INSERT INTO `about_us_content_tr` (`id`, `master_id`, `content_value`, `created_at`, `updated_at`) VALUES
(1, 'about-001', 'Bio Green Wax Hakkında', '2026-02-08 15:42:58', '2026-02-09 04:04:25'),
(2, 'about-002', 'İngiltere\'deki güvendiğiniz ortaklarınız olan, premium yenilebilir yağlar ve endüstriyel mumlar konusunda kalite ve sürdürülebilirliği dünya genelinde sunan partneriniz.', '2026-02-08 15:52:44', '2026-02-09 04:04:36'),
(3, 'about-003', 'Hikâyemiz', '2026-02-08 15:53:31', '2026-02-09 04:04:45'),
(4, 'about-004', 'Bio Green Wax Ltd, Temmuz 2024\'te kuruldu ve net bir vizyonla hareket ediyor: Birleşik Krallık\'ın en lider tedarikçisi olmak, premium doğal yağlar ve endüstriyel waxlar alanında. Henüz genç bir şirket olmamıza rağmen, kurucularımızın sektör deneyimlerinden oluşan onlarca yıllık bilgi birikimiyle sağlam bir temel üzerine inşa edilmiştir.\n\nBirçok sektör için yüksek kaliteli yenilebilir yağlar ve endüstriyel waxlar tedarikinde, işlemede ve dağıtımda uzmanız; Birleşik Krallık ve uluslararası çapta faaliyet gösteriyoruz. Gıda üretiminden kozmetiğe, ilaç sektöründen endüstriyel uygulamalara kadar, ürünlerimiz yüksek standartlara sahip çeşitli sektörlere hizmet vermektedir.\n\nGerçek farkımız, RSPO SG (Segregated) sertifikalı palmiye yağı ve türevlerini tedarik edebilme kabiliyetimizdir — bu, birçok köklü sektör oyuncusunun henüz ulaşamadığı bir başarıdır; çünkü onlar hâlâ MB (Mass Balance) sertifikasına bağımlıdır. Segregated tedarik zincirimiz, sürdürülebilir şekilde üretilmiş palmiye yağının tüm süreç boyunca fiziksel olarak ayrı tutulmasını sağlar, müşterilerimize en yüksek izlenebilirlik ve sürdürülebilirlik garantisini sunar.\n\nAyrıca, EUDR (European Union Deforestation Regulation) standartlarına tamamen uyumlu Soy Products, Palm Products ve türevlerini tedarik edebiliyoruz, böylece tedarik zincirlerimizin ormansızlaştırma işlemine karşı korunduğunu ve en güncel Avrupa düzenleyici gereklilikleri karşıladığını garanti ediyoruz.\n\nBunun yanı sıra, ISCC-EU (International Sustainability and Carbon Certification) sertifikalarıyla desteklenen biyoyakıt hammadde ürünleri de tedarik edebilme yeteneğine sahibiz; bu, sürdürülebilir ve yenilenebilir enerji çözümlerine olan artan talebi desteklemektedir.\n\nKalite, sürdürülebilirlik ve müşteri memnuniyetine olan bağlılığımız, sektörümüzde bizi öne çıkarıyor. Müşterilerimizle uzun vadeli ortaklıklar kurmaya, onların benzersiz ihtiyaçlarını anlamaya ve beklentilerin ötesinde çözümler sunmaya inanıyoruz.', '2026-02-08 15:55:45', '2026-02-11 17:18:25'),
(5, 'about-005', 'Görevimiz', '2026-02-08 15:57:14', '2026-02-09 04:05:17'),
(6, 'about-006', 'Birleşik Krallık\'ın en güvenilir kaliteli yağlar ve mumlar tedarikçisi olmak, üstün ürünler ve mükemmel hizmet sunmak, sürdürülebilirlik ve etik iş uygulamalarına olan bağlılığımızı koruyarak.', '2026-02-08 16:01:27', '2026-02-09 04:05:30'),
(7, 'about-007', 'Yönetim Kurulu Başkanımızdan Bir Mesaj', '2026-02-08 16:02:29', '2026-02-09 04:05:40'),
(8, 'about-008', 'Değerli İş Ortaklarımız ve Müşterilerimiz,\n\nBio Green Wax Ltd. hakkında bilgi edinmek için zaman ayırdığınız için teşekkür ederiz. Bu şirketi kurduğumda, yüksek kaliteli ürünleri üstün müşteri hizmetleriyle ve sürdürülebilirliğe gerçek anlamda bağlılıkla birleştiren bir işletme yaratma vizyonum vardı.\n\nEkibimiz, yağlar ve mumlar endüstrisinde onlarca yıllık tecrübeye sahiptir ve dünya çapında güvenilir tedarikçilerle ilişkiler kurduk. Bu da size en zorlu kalite standartlarını karşılayan ve rekabetçi fiyatlarla sunulabilecek ürünler almamıza imkan tanır.\n\nBizim bizi diğerlerinden ayıran özelliğimiz kişisel yaklaşımımızdır. Bio Green Wax ile çalıştığınızda, sektörünüzü anlayan ve başarınızla ilgilenen kişilerle doğrudan iletişim kurarsınız. Spesifik ihtiyaçlarınızı anlamak için zaman ayırıyor ve size özel çözümler sunuyoruz.\n\nİşiniz için neler sağlayabileceğimizi keşfetmeniz için sizi davet ediyorum. Gıda üretimi için yenilebilir yağlar, kozmetik için özel mumlar ya da operasyonlarınız için endüstriyel çözümler gerekse de, yardım etmeye hazırız.\n\nSize hizmet verme fırsatını dört gözle bekliyorum.', '2026-02-08 16:47:30', '2026-02-09 04:24:13'),
(9, 'about-009', 'Hantash Najam', '2026-02-08 16:49:17', '2026-02-09 04:05:50'),
(10, 'about-010', 'Yönetici Direktör, Bio Green Wax Ltd', '2026-02-08 16:50:12', '2026-02-09 04:06:00'),
(11, 'about-011', '15814481', '2026-02-08 16:50:51', '2026-02-09 04:06:09'),
(12, 'about-012', '2 Temmuz 2024', '2026-02-08 16:51:21', '2026-02-09 04:23:33'),
(13, 'about-013', '128 City Road, Londra, EC1V 2NX', '2026-02-08 16:52:06', '2026-02-09 04:23:43'),
(14, 'about-014', 'Genç Firma, Deneyimli Liderlik', '2026-02-08 16:53:07', '2026-02-09 04:23:53'),
(15, 'about-015', 'Bio Green Wax Ltd 2024 yılında kurulmuş olsa da, liderlik ekibimiz yağlar ve balmumu sektöründe toplam 25 yılı aşkın deneyime sahiptir. Bu uzmanlık, karmaşık tedarik zincirlerini yönetmemize, katı kalite standartlarını korumamıza ve müşterilerimize üstün değer sunmamıza olanak tanımaktadır.', '2026-02-08 16:54:30', '2026-02-09 04:24:32');
INSERT INTO `about_us_content_vi` (`id`, `master_id`, `content_value`, `created_at`, `updated_at`) VALUES
(1, 'about-001', 'Về Bio Green Wax', '2026-02-08 15:43:00', '2026-02-09 04:04:25'),
(2, 'about-002', 'Đối tác đáng tin cậy của UK của bạn về các loại dầu ăn cao cấp và sáp công nghiệp, mang lại chất lượng và tính bền vững toàn cầu.', '2026-02-08 15:52:51', '2026-02-09 04:04:37'),
(3, 'about-003', 'Câu chuyện của chúng tôi', '2026-02-08 15:53:33', '2026-02-09 04:04:46'),
(4, 'about-004', 'Bio Green Wax Ltd được thành lập vào tháng 7 năm 2024 với một tầm nhìn rõ ràng: trở thành nhà cung cấp hàng đầu của Vương quốc Anh về dầu tự nhiên cao cấp và sáp công nghiệp. Mặc dù chúng tôi còn trẻ, nhưng nền tảng của chúng tôi dựa trên nhiều thập kỷ kinh nghiệm chung của đội ngũ lãnh đạo trong ngành.\n\nChúng tôi chuyên về việc thu mua, xử lý và phân phối các loại dầu ăn và sáp công nghiệp chất lượng cao tới các doanh nghiệp trên toàn UK và quốc tế. Từ sản xuất thực phẩm đến mỹ phẩm, dược phẩm đến ứng dụng công nghiệp, các sản phẩm của chúng tôi phục vụ một loạt các ngành công nghiệp với tiêu chuẩn khắt khe.\n\nĐiều thực sự tạo nên sự khác biệt cho chúng tôi là khả năng cung cấp dầu cọ và các hợp chất của nó đạt chứng chỉ RSPO SG (Segregated) — một đặc điểm mà nhiều doanh nghiệp lớn trong ngành vẫn chưa đạt được, khi họ vẫn còn phụ thuộc vào chứng chỉ MB (Mass Balance). Chuỗi cung ứng Segregated của chúng tôi đảm bảo rằng dầu cọ được sản xuất bền vững được giữ riêng biệt trong suốt quá trình, mang lại cho khách hàng mức độ truy xuất nguồn gốc và cam kết bền vững cao nhất.\n\nChúng tôi tự hào cung cấp các sản phẩm đậu nành, sản phẩm cọ và các hợp chất của chúng phù hợp hoàn toàn với các tiêu chuẩn EUDR (Regulation về Phá rừng của Liên minh châu Âu), đảm bảo chuỗi cung ứng của chúng tôi không gây phá rừng và đáp ứng các yêu cầu pháp lý mới nhất của châu Âu.\n\nNgoài ra, chúng tôi còn có khả năng cung cấp nguyên liệu nhiên liệu sinh học được chứng nhận bởi ISCC-EU (Chứng nhận Bền vững và Lượng khí Cacbon Quốc tế), hỗ trợ nhu cầu ngày càng tăng về các giải pháp năng lượng bền vững và tái tạo.\n\nCam kết của chúng tôi đối với chất lượng, tính bền vững và dịch vụ khách hàng giúp chúng tôi nổi bật trên thị trường. Chúng tôi tin tưởng vào việc xây dựng các mối quan hệ đối tác lâu dài với khách hàng, hiểu rõ các yêu cầu riêng biệt của họ và cung cấp các giải pháp vượt mong đợi.', '2026-02-08 15:56:00', '2026-02-11 17:18:28'),
(5, 'about-005', 'Sứ Mệnh của Chúng Tôi', '2026-02-08 15:57:15', '2026-02-09 04:05:17'),
(6, 'about-006', 'Trở thành nhà cung cấp dầu và sáp được tin cậy nhất của Vương quốc Anh, cung cấp những sản phẩm chất lượng cao cùng dịch vụ tuyệt vời, đồng thời giữ vững cam kết về sự bền vững và các thực hành kinh doanh đạo đức.', '2026-02-08 16:01:32', '2026-02-09 04:05:30'),
(7, 'about-007', 'Thông điệp từ Giám đốc điều hành của chúng tôi', '2026-02-08 16:02:33', '2026-02-09 04:05:41'),
(8, 'about-008', 'Kính gửi Quý Đối tác và Khách hàng quý giá,\n\nCảm ơn Quý vị đã dành thời gian tìm hiểu về Công ty Bio Green Wax Ltd. Khi tôi thành lập công ty này, tôi đã có một tầm nhìn rõ ràng: xây dựng một doanh nghiệp kết hợp các sản phẩm chất lượng cao nhất với dịch vụ khách hàng xuất sắc và cam kết chân thành về phát triển bền vững.\n\nĐội ngũ của chúng tôi có nhiều thập kỷ kinh nghiệm trong ngành công nghiệp dầu và sáp, và chúng tôi đã xây dựng mối quan hệ với các nhà cung cấp đáng tin cậy trên toàn thế giới. Điều này giúp chúng tôi có thể cung cấp cho Quý vị những sản phẩm đáp ứng tiêu chuẩn chất lượng cao nhất trong khi vẫn giữ mức giá cạnh tranh.\n\nĐiều làm chúng tôi khác biệt chính là cách tiếp cận cá nhân. Khi làm việc với Bio Green Wax, Quý vị sẽ làm việc trực tiếp với những người hiểu rõ ngành của Quý vị và quan tâm đến sự thành công của Quý vị. Chúng tôi dành thời gian để hiểu rõ các yêu cầu cụ thể của Quý vị và cung cấp các giải pháp tùy chỉnh phù hợp.\n\nTôi mời Quý vị khám phá những gì chúng tôi có thể mang lại cho doanh nghiệp của Quý vị. Dù Quý vị cần dầu ăn cho sản xuất thực phẩm, sáp đặc biệt cho mỹ phẩm, hay các giải pháp công nghiệp cho hoạt động của mình, chúng tôi đều sẵn sàng hỗ trợ.\n\nTôi mong đợi có cơ hội phục vụ Quý vị.', '2026-02-08 16:47:47', '2026-02-09 04:24:15'),
(9, 'about-009', 'Hantash Najam', '2026-02-08 16:49:19', '2026-02-09 04:05:50'),
(10, 'about-010', 'Giám đốc điều hành, Công ty TNHH Bio Green Wax', '2026-02-08 16:50:15', '2026-02-09 04:06:00'),
(11, 'about-011', '15814481', '2026-02-08 16:50:52', '2026-02-09 04:06:10'),
(12, 'about-012', 'Ngày 2 tháng 7 năm 2024', '2026-02-08 16:51:23', '2026-02-09 04:23:33'),
(13, 'about-013', '128 City Road, London, EC1V 2NX', '2026-02-08 16:52:11', '2026-02-09 04:23:44'),
(14, 'about-014', 'Công ty Young, Lãnh đạo có nhiều kinh nghiệm', '2026-02-08 16:53:10', '2026-02-09 04:23:54'),
(15, 'about-015', 'Mặc dù Bio Green Wax Ltd được thành lập vào năm 2024, nhưng đội ngũ lãnh đạo của chúng tôi có hơn 25 năm kinh nghiệm tổng hợp trong ngành dầu và sáp. Kỹ năng này giúp chúng tôi điều hướng các chuỗi cung ứng phức tạp, duy trì tiêu chuẩn chất lượng nghiêm ngặt và mang lại giá trị vượt trội cho khách hàng của mình.', '2026-02-08 16:54:34', '2026-02-09 04:24:33');
INSERT INTO `about_us_content_zh` (`id`, `master_id`, `content_value`, `created_at`, `updated_at`) VALUES
(1, 'about-001', '关于 Bio Green Wax', '2026-02-08 15:42:37', '2026-02-09 04:04:19'),
(2, 'about-002', '您值得信赖的英国合作伙伴，提供优质食用油和工业蜡，推广全球的品质与可持续发展。', '2026-02-08 15:51:54', '2026-02-09 04:04:28'),
(3, 'about-003', '我们的故事', '2026-02-08 15:53:15', '2026-02-09 04:04:41'),
(4, 'about-004', 'Bio Green Wax Ltd于2024年7月成立，秉持着明确的愿景：成为英国领先的优质天然油和工业蜡供应商。虽然我们是一家年轻的公司，但我们的基础建立在领导团队数十年的行业经验之上。\n\n我们专注于为英国及国际客户提供高品质的食用油和工业蜡的采购、加工与分销。从食品制造到化妆品、医药再到工业应用，我们的产品满足各行业严格的标准。\n\n真正让我们与众不同的是，我们能够供应获得RSPO SG（Segregated）认证的棕榈油及其衍生品——这是许多行业成熟企业尚未实现的成就，因为它们仍依赖于MB（Mass Balance）认证。我们的Segregated供应链确保可持续生产的棕榈油在整个过程中始终保持实物分离，为客户提供最高水平的追溯性和可持续性保障。\n\n我们自豪地提供符合EUDR（欧洲联盟打击森林砍伐条例）标准的豆类产品、棕榈产品及其衍生品，确保我们的供应链无森林砍伐问题，并符合最新的欧洲法规要求。\n\n此外，我们还能提供获得ISCC-EU（国际可持续性与碳认证）认证的生物燃料原料，支持不断增长的可持续和可再生能源需求。\n\n我们对品质、可持续发展和客户服务的承诺，使我们在市场中独树一帜。我们相信与客户建立长期合作关系，理解他们的独特需求，提供超出预期的解决方案。', '2026-02-08 15:53:52', '2026-02-11 17:18:03'),
(5, 'about-005', '我们的使命', '2026-02-08 15:56:58', '2026-02-09 04:05:12'),
(6, 'about-006', '成为英国最值得信赖的优质油和蜡供应商，提供卓越的产品和一流的服务，同时坚持可持续发展和道德商业实践。', '2026-02-08 16:00:26', '2026-02-09 04:05:21'),
(7, 'about-007', '来自我们董事总经理的一则消息', '2026-02-08 16:02:00', '2026-02-09 04:05:34'),
(8, 'about-008', '尊敬的合作伙伴和客户，  \n\n感谢您抽出时间了解Bio Green Wax Ltd. 当我创立这家公司时， heart 有一个清晰的愿景：打造一个将最高品质产品与卓越客户服务以及对可持续发展的真诚承诺相结合的企业。  \n\n我们的团队拥有数十年的油料和蜡料行业经验，并且与全球可信赖的供应商建立了良好的合作关系。这使我们能够为您提供符合最高品质标准且具有竞争力的产品。  \n\n我们与众不同之处在于我们的个性化服务。当您与Bio Green Wax合作时，您直接与了解您行业、关心您成功的团队合作。我们会花时间了解您的具体需求，提供量身定制的解决方案。  \n\n我邀请您探索我们能为您的业务提供的服务。无论您需要食品制造用的食用油、化妆品用的特种蜡料，还是工业运营所需的解决方案，我们都愿意为您提供帮助。  \n\n期待有机会为您服务。', '2026-02-08 16:23:48', '2026-02-09 04:23:57'),
(9, 'about-009', '汉塔什·纳贾姆', '2026-02-08 16:48:54', '2026-02-09 04:05:45'),
(10, 'about-010', 'Bio Green Wax有限公司董事总经理', '2026-02-08 16:49:41', '2026-02-09 04:05:54'),
(11, 'about-011', '15814481', '2026-02-08 16:50:37', '2026-02-09 04:06:03'),
(12, 'about-012', '2024年7月2日', '2026-02-08 16:51:03', '2026-02-09 04:23:26'),
(13, 'about-013', '伦敦市路128号，邮编EC1V 2NX', '2026-02-08 16:51:37', '2026-02-09 04:23:37'),
(14, 'about-014', '年轻公司，经验丰富的领导团队', '2026-02-08 16:52:31', '2026-02-09 04:23:48'),
(15, 'about-015', '虽然 Bio Green Wax Ltd 成立于 2024 年，但我们的管理团队拥有超过 25 年的油类和蜡类行业的丰富经验。这一专业知识使我们能够应对复杂的供应链、保持严格的质量标准，并为客户提供卓越的价值。', '2026-02-08 16:53:31', '2026-02-09 04:24:23');
INSERT INTO `certifications` (`id`, `name`, `title`, `description`, `image_url`, `display_order`, `is_active`, `synchronized_data`, `created_at`) VALUES
('cert-001', 'ISO 9001', 'ISO 9001:2015 Quality Management', 'Our quality management system is certified to ISO 9001:2015 standards, ensuring consistent quality in all our products and services.', '', 2, 1, 1, '2026-02-05 21:03:49'),
('cert-002', 'RSPO', 'RSPO Certified Sustainable Palm Oil', 'We are committed to sourcing sustainable palm oil and are certified members of the Roundtable on Sustainable Palm Oil.', NULL, 2, 1, 1, '2026-02-05 21:03:49'),
('cert-003', 'Organic', 'Organic Certification', 'Select products are certified organic, meeting strict standards for natural and sustainable production.', NULL, 3, 1, 1, '2026-02-05 21:03:49');
INSERT INTO `certifications_ar` (`id`, `master_id`, `name`, `title`, `description`, `created_at`, `updated_at`) VALUES
(1, 'cert-001', 'أيزو 9001', 'إدارة الجودة وفقًا لـ ISO 9001:2015', 'نظام إدارة الجودة لدينا معتمد وفقًا لمعايير ISO 9001:2015، مما يضمن جودة متسقة في جميع منتجاتنا وخدماتنا.', '2026-02-06 05:01:10', '2026-02-11 18:17:19'),
(2, 'cert-002', 'RSPO', 'زيت النخيل المستدام المعتمد من RSPO', 'نحن ملتزمون بالحصول على زيت النخيل المستدام ونعتبر أعضاء معتمدين في منتدى زيت النخيل المستدام.', '2026-02-06 05:03:05', '2026-02-09 03:50:27'),
(3, 'cert-003', 'عضوي', 'الشهادة العضوية', 'المنتجات المختارة معتمدة عضوية، وتلبي معايير صارمة للإنتاج الطبيعي والمستدام.', '2026-02-06 05:05:25', '2026-02-09 03:50:58');
INSERT INTO `certifications_de` (`id`, `master_id`, `name`, `title`, `description`, `created_at`, `updated_at`) VALUES
(1, 'cert-001', 'ISO 9001', 'ISO 9001:2015 Qualitätssicherungsmanagement', 'Unser Qualitätsmanagementsystem ist nach den ISO 9001:2015 Standards zertifiziert, was eine gleichbleibende Qualität in allen unseren Produkten und Dienstleistungen gewährleistet.', '2026-02-06 05:01:31', '2026-02-11 18:17:27'),
(2, 'cert-002', 'RSPO', 'RSPO-zertifizierter nachhaltiger Palmöl', 'Wir verpflichten uns, nachhaltiges Palmöl zu beziehen, und sind zertifizierte Mitglieder der Roundtable on Sustainable Palm Oil.', '2026-02-06 05:03:40', '2026-02-09 03:50:32'),
(3, 'cert-003', 'Bio', 'Bio-Zertifizierung', 'Ausgewählte Produkte sind biologisch zertifiziert und erfüllen strenge Standards für eine natürliche und nachhaltige Produktion.', '2026-02-06 05:05:47', '2026-02-09 03:51:03');
INSERT INTO `certifications_es` (`id`, `master_id`, `name`, `title`, `description`, `created_at`, `updated_at`) VALUES
(1, 'cert-001', 'ISO 9001', 'Gestión de la Calidad ISO 9001:2015', 'Nuestro sistema de gestión de calidad está certificado según las normas ISO 9001:2015, garantizando una calidad constante en todos nuestros productos y servicios.', '2026-02-06 05:00:57', '2026-02-11 18:17:13'),
(2, 'cert-002', 'RSPO', 'Aceite de Palma Sostenible Certificado por la RSPO', 'Estamos comprometidos con la adquisición de aceite de palma sostenible y somos miembros certificados de la Mesa Redonda sobre Aceite de Palma Sostenible.', '2026-02-06 05:02:45', '2026-02-09 03:50:24'),
(3, 'cert-003', 'Orgánico', 'Certificación Orgánica', 'Los productos selectos están certificados como orgánicos, cumpliendo con estrictos estándares de producción natural y sostenible.', '2026-02-06 05:05:12', '2026-02-09 03:50:54');
INSERT INTO `certifications_fr` (`id`, `master_id`, `name`, `title`, `description`, `created_at`, `updated_at`) VALUES
(1, 'cert-001', 'ISO 9001', 'Gestion de la qualité ISO 9001:2015', 'Notre système de gestion de la qualité est certifié selon la norme ISO 9001:2015, garantissant une qualité constante dans tous nos produits et services.', '2026-02-06 05:01:02', '2026-02-11 18:17:16'),
(2, 'cert-002', 'RSPO', 'Huile de Palme Durable Certifiée RSPO', 'Nous nous engageons à approvisionner en huile de palme durable et sommes membres certifiés de la Roundtable on Sustainable Palm Oil.', '2026-02-06 05:02:52', '2026-02-09 03:50:25'),
(3, 'cert-003', 'Biologique', 'Certification biologique', 'Les produits sélectionnés sont certifiés biologiques, répondant à des normes strictes de production naturelle et durable.', '2026-02-06 05:05:19', '2026-02-09 03:50:56');
INSERT INTO `certifications_it` (`id`, `master_id`, `name`, `title`, `description`, `created_at`, `updated_at`) VALUES
(1, 'cert-001', 'ISO 9001', 'ISO 9001:2015 Gestione della qualità', 'Il nostro sistema di gestione della qualità è certificato secondo le norme ISO 9001:2015, garantendo una qualità costante in tutti i nostri prodotti e servizi.', '2026-02-06 05:02:21', '2026-02-11 18:17:44'),
(2, 'cert-002', 'RSPO', 'Olio di palma sostenibile certificato RSPO', 'Siamo impegnati nell\'approvvigionamento di olio di palma sostenibile e siamo membri certificati della Roundtable on Sustainable Palm Oil.', '2026-02-06 05:04:50', '2026-02-09 03:50:47'),
(3, 'cert-003', 'Biologico', 'Certificazione biologica', 'I prodotti Select sono certificati biologici, rispettando rigorosi standard per una produzione naturale e sostenibile.', '2026-02-06 05:06:43', '2026-02-09 03:51:14');
INSERT INTO `certifications_ja` (`id`, `master_id`, `name`, `title`, `description`, `created_at`, `updated_at`) VALUES
(1, 'cert-001', 'ISO 9001', 'ISO 9001:2015 品質マネジメント', '私たちの品質管理システムはISO 9001:2015規格の認証を受けており、すべての製品とサービスにおいて一定の品質を保証しています。', '2026-02-06 05:01:39', '2026-02-11 18:17:30'),
(2, 'cert-002', 'RSPO', 'RSPO認証済み持続可能なパーム油', '私たちは、持続可能なパーム油の調達にコミットしており、持続可能なパーム油協議会（Roundtable on Sustainable Palm Oil）の認証会員です。', '2026-02-06 05:03:51', '2026-02-09 03:50:34'),
(3, 'cert-003', 'オーガニック', '有機認証', '選択された製品は有機認証を受けており、自然で持続可能な生産に関する厳しい基準を満たしています。', '2026-02-06 05:05:54', '2026-02-09 03:51:05');
INSERT INTO `certifications_ko` (`id`, `master_id`, `name`, `title`, `description`, `created_at`, `updated_at`) VALUES
(1, 'cert-001', 'ISO 9001', 'ISO 9001:2015 품질경영', '저희 품질 관리 시스템은 ISO 9001:2015 표준 인증을 받았으며, 모든 제품과 서비스에서 일관된 품질을 보장합니다.', '2026-02-06 05:02:09', '2026-02-11 18:17:39'),
(2, 'cert-002', 'RSPO', 'RSPO 인증 지속 가능한 팜유', '우리는 지속 가능한 팜유를 조달하는 데 전념하고 있으며, 지속가능한 팜유를 위한 원탁회의(Roundtable on Sustainable Palm Oil, RSPO)의 인증 회원입니다.', '2026-02-06 05:04:35', '2026-02-09 03:50:42'),
(3, 'cert-003', '유기농', '유기농 인증', '선택된 제품들은 인증된 유기농으로, 자연적이고 지속 가능한 생산을 위한 엄격한 기준을 충족합니다.', '2026-02-06 05:06:28', '2026-02-09 03:51:11');
INSERT INTO `certifications_pl` (`id`, `master_id`, `name`, `title`, `description`, `created_at`, `updated_at`) VALUES
(1, 'cert-001', 'ISO 9001', 'ISO 9001:2015 Zarządzanie jakością', 'Nasz system zarządzania jakością jest certyfikowany zgodnie z normą ISO 9001:2015, zapewniającą stałą jakość wszystkich naszych produktów i usług.', '2026-02-06 05:02:27', '2026-02-11 18:17:46'),
(2, 'cert-002', 'RSPO', 'Certyfikowana Zrównoważona Olej Palmowy RSPO', 'Jesteśmy zobowiązani do pozyskiwania zrównoważonego oleju palmowego i jesteśmy certyfikowanymi członkami Rady Zrównoważonego Oleju Palmowego.', '2026-02-06 05:04:58', '2026-02-09 03:50:50'),
(3, 'cert-003', 'Organiczne', 'Certyfikacja ekologiczna', 'Wybrane produkty są certyfikowane jako organiczne, spełniając rygorystyczne standardy produkcji naturalnej i zrównoważonej.', '2026-02-06 05:06:52', '2026-02-09 03:51:16');
INSERT INTO `certifications_pt` (`id`, `master_id`, `name`, `title`, `description`, `created_at`, `updated_at`) VALUES
(1, 'cert-001', 'ISO 9001', 'ISO 9001:2015 Gerenciamento da Qualidade', 'Nosso sistema de gestão da qualidade é certificado de acordo com as normas ISO 9001:2015, garantindo uma qualidade consistente em todos os nossos produtos e serviços.', '2026-02-06 05:01:16', '2026-02-11 18:17:22'),
(2, 'cert-002', 'RSPO', 'Óleo de Palmiste Sustentável Certificado pela RSPO', 'Estamos comprometidos em adquirir óleo de dendê sustentável e somos membros certificados da Roundtable on Sustainable Palm Oil.', '2026-02-06 05:03:20', '2026-02-09 03:50:29'),
(3, 'cert-003', 'Orgânico', 'Certificação Orgânica', 'Seleção de produtos certificados orgânicos, atendendo a rigorosos padrões de produção natural e sustentável.', '2026-02-06 05:05:32', '2026-02-09 03:50:59');
INSERT INTO `certifications_ru` (`id`, `master_id`, `name`, `title`, `description`, `created_at`, `updated_at`) VALUES
(1, 'cert-001', 'ИСО 9001', 'Системы менеджмента качества ISO 9001:2015', 'Наша система менеджмента качества сертифицирована по стандарту ISO 9001:2015, что гарантирует стабильное качество всех наших продуктов и услуг.', '2026-02-06 05:01:25', '2026-02-11 18:17:25'),
(2, 'cert-002', 'RSPO', 'RSPO Сертифицированное экологически чистое пальмовое масло', 'Мы привержены использованию экологически устойчивого пальмового масла и являемся сертифицированными участниками Круглого стола по устойчивому пальмовому маслу.', '2026-02-06 05:03:32', '2026-02-09 03:50:30'),
(3, 'cert-003', 'Органический', 'Сертификация органической продукции', 'Выбранные продукты сертифицированы как органические, соответствуют строгим стандартам натурального и устойчивого производства.', '2026-02-06 05:05:39', '2026-02-09 03:51:01');
INSERT INTO `certifications_sw` (`id`, `master_id`, `name`, `title`, `description`, `created_at`, `updated_at`) VALUES
(1, 'cert-001', 'ISO 9001', 'ISO 9001:2015 Usimamizi wa Ubora', 'Mfumo wetu wa usimamizi wa ubora umeidhinishwa kwa viwango vya ISO 9001:2015, kuhakikisha ubora wa kila kitu katika bidhaa zetu na huduma zetu zote.', '2026-02-06 05:01:46', '2026-02-11 18:17:32'),
(2, 'cert-002', 'RSPO', 'Mafuta ya Nazi Endeleaji Yaliyothibitishwa na RSPO', 'Tumejitolea kupata mafuta ya nazi ya kisasa yanayostahiki na ni wanachama waliothibitishwa wa Roundtable on Sustainable Palm Oil.', '2026-02-06 05:04:05', '2026-02-09 03:50:35'),
(3, 'cert-003', 'Asilia', 'Uthibitishaji wa Kikaboni', 'Bidhaa zilizochaguliwa zimethibitishwa kuwa organic, zikitimiza viwango virefu vya uzalishaji wa asili na endelevu.', '2026-02-06 05:06:08', '2026-02-09 03:51:06');
INSERT INTO `certifications_th` (`id`, `master_id`, `name`, `title`, `description`, `created_at`, `updated_at`) VALUES
(1, 'cert-001', 'ISO 9001', 'ISO 9001:2015 การจัดการคุณภาพ', 'ระบบการ quản lýคุณภาพของเราได้รับการรับรองมาตรฐาน ISO 9001:2015 ซึ่งรับประกันคุณภาพที่สม่ำเสมอในสินค้าและบริการของเรา', '2026-02-06 05:02:16', '2026-02-11 18:17:42'),
(2, 'cert-002', 'RSPO', 'น้ำมันปาล์มที่ได้รับการรับรองจาก RSPO (Roundtable on Sustainable Palm Oil)', 'เรามุ่งมั่นที่จะจัดหาน้ำมันปาล์มที่ยั่งยืน และเป็นสมาชิกที่ได้รับการรับรองจากกลุ่มแนวทางในการผลิตน้ำมันปาล์มที่ยั่งยืน (Roundtable on Sustainable Palm Oil)', '2026-02-06 05:04:42', '2026-02-09 03:50:44'),
(3, 'cert-003', 'ออร์แกนิก', 'การรับรองแบบออร์แกนิก', 'ผลิตภัณฑ์ที่เลือกได้รับการรับรองว่าเป็นออร์แกนิก ผ่านมาตรฐานที่เข้มงวดสำหรับการผลิตที่เป็นธรรมชาติและยั่งยืน', '2026-02-06 05:06:35', '2026-02-09 03:51:13');
INSERT INTO `certifications_tr` (`id`, `master_id`, `name`, `title`, `description`, `created_at`, `updated_at`) VALUES
(1, 'cert-001', 'ISO 9001', 'ISO 9001:2015 Kalite Yönetimi', 'Kalite yönetim sistemimiz, ISO 9001:2015 standartlarına uygun olarak sertifikalandırılmıştır ve tüm ürünlerimiz ile hizmetlerimizde tutarlı kaliteyi sağlamaktadır.', '2026-02-06 05:01:52', '2026-02-11 18:17:35'),
(2, 'cert-002', 'RSPO', 'RSPO Sertifikalı Sürdürülebilir Palm Yağı', 'Sürdürülebilir palm yağı kaynağına bağlıyız ve Sürdürülebilir Palm Yağı Çerçevesi\'nde sertifikalı üyeyiz.', '2026-02-06 05:04:16', '2026-02-09 03:50:37'),
(3, 'cert-003', 'Organik', 'Organik Sertifikası', 'Seçili ürünler, doğal ve sürdürülebilir üretim için katı standartları karşılayan sertifikalı organik ürünlerdir.', '2026-02-06 05:06:14', '2026-02-09 03:51:08');
INSERT INTO `certifications_vi` (`id`, `master_id`, `name`, `title`, `description`, `created_at`, `updated_at`) VALUES
(1, 'cert-001', 'ISO 9001', 'Quản lý Chất lượng theo ISO 9001:2015', 'Hệ thống quản lý chất lượng của chúng tôi được chứng nhận theo tiêu chuẩn ISO 9001:2015, đảm bảo chất lượng nhất quán trong tất cả các sản phẩm và dịch vụ của chúng tôi.', '2026-02-06 05:02:00', '2026-02-11 18:17:37'),
(2, 'cert-002', 'RSPO', 'Dầu cọ bền vững được chứng nhận RSPO', 'Chúng tôi cam kết sử dụng dầu cọ bền vững và là thành viên được chứng nhận của Hội đồng Dầu cọ Bền vững (Roundtable on Sustainable Palm Oil).', '2026-02-06 05:04:23', '2026-02-09 03:50:40'),
(3, 'cert-003', 'Hữu cơ', 'Chứng nhận hữu cơ', 'Các sản phẩm được chọn lọc đạt chứng nhận hữu cơ, đáp ứng các tiêu chuẩn nghiêm ngặt về sản xuất tự nhiên và bền vững.', '2026-02-06 05:06:19', '2026-02-09 03:51:10');
INSERT INTO `certifications_zh` (`id`, `master_id`, `name`, `title`, `description`, `created_at`, `updated_at`) VALUES
(1, 'cert-001', 'ISO 9001', 'ISO 9001:2015 质量管理', '我们的质量管理体系已获得ISO 9001:2015标准认证，确保我们所有产品和服务的质量始终如一。', '2026-02-06 05:00:53', '2026-02-11 18:17:11'),
(2, 'cert-002', 'RSPO', 'RSPO认证的可持续棕榈油', '我们致力于采购可持续的棕榈油，并且是可持续棕榈油圆桌会议的认证会员。', '2026-02-06 05:02:36', '2026-02-09 03:50:22'),
(3, 'cert-003', '有机', '有机认证', '部分选购的产品获得了有机认证，符合天然与可持续生产的严格标准。', '2026-02-06 05:05:05', '2026-02-09 03:50:52');
INSERT INTO `contact_enquiries` (`id`, `name`, `email`, `phone`, `company`, `subject`, `message`, `is_read`, `created_at`) VALUES
('enq-001', 'David Chen', 'david.chen@candelux.com', '+44 20 1234 5678', 'Candelux Ltd', 'Bulk Order Enquiry - Soy Wax', 'We are a candle manufacturer looking to source soy wax in bulk. Could you please provide pricing for 5 tonnes monthly supply?', 1, '2026-02-05 21:03:49'),
('enq-002', 'Lisa Martinez', 'lisa@beautybrand.co.uk', '+44 20 2345 6789', 'Beauty Brand Co', 'Cosmetic Grade Beeswax', 'We are developing a new lip balm range and need cosmetic grade beeswax. What grades do you offer and what are the MOQs?', 1, '2026-02-05 21:03:49'),
('enq-003', 'Robert Taylor', 'r.taylor@industrialcoatings.com', '+44 161 345 6789', 'Industrial Coatings PLC', 'Paraffin Wax for Coatings', 'Looking for a reliable supplier of paraffin wax for our coating applications. Can we arrange a meeting to discuss requirements?', 1, '2026-02-05 21:03:49');
