INSERT INTO `directors` (`id`, `name`, `title`, `bio`, `linkedin_url`, `photo_url`, `display_order`, `is_active`, `synchronized_data`, `created_at`, `updated_at`) VALUES
('dir-001', 'Hantash Najam', 'Managing Director', 'Hantash Najam is the founder and Managing Director of Bio Green Wax Ltd. With extensive experience in international trade and commodity markets, he has built a network of trusted suppliers across Southeast Asia, Africa, and South America. Hantash is also a director of Bio Greenware Ltd, bringing a wealth of experience in sustainable product sourcing and distribution. His vision for Bio Green Wax is to create a company that prioritizes quality, sustainability, and customer partnerships.', 'https://www.linkedin.com/in/hantash-najam-025043218', NULL, 1, 1, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('dir-002', 'Umesh Gowda', 'Director', 'Umesh Gowda brings valuable expertise in operations and supply chain management to Bio Green Wax Ltd. His background in logistics and international trade helps ensure that our products are sourced efficiently and delivered reliably to customers across the UK and beyond. Umesh is dedicated to maintaining the highest standards of quality and service in all our operations.', 'https://www.linkedin.com/in/umesh-gowda', NULL, 2, 1, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49');
INSERT INTO `directors_ar` (`id`, `master_id`, `name`, `title`, `bio`, `created_at`, `updated_at`) VALUES
(1, 'dir-001', 'هانتاش نجم', 'المدير التنفيذي', 'هنتاش نجم هو مؤسس ومدير عام شركة Bio Green Wax Ltd. ومع خبرة واسعة في التجارة الدولية وأسواق السلع، قام ببناء شبكة من الموردين الموثوق بهم عبر جنوب شرق آسيا وأفريقيا وأمريكا الجنوبية. هنتاش هو أيضًا مدير في شركة Bio Greenware Ltd، ويجلب معه ثروة من الخبرة في مصادر المنتجات المستدامة وتوزيعها. رؤيته لشركة Bio Green Wax هي إنشاء شركة تركز على الجودة والاستدامة وشراكات العملاء.', '2026-02-08 15:23:59', '2026-02-09 03:52:24'),
(2, 'dir-002', 'أوميش جاودا', 'مدير', 'يوش جيودا يجلب خبرة قيمة في العمليات وإدارة سلسلة التوريد إلى شركة Bio Green Wax Ltd. تساعد خلفيته في اللوجستيات والتجارة الدولية على ضمان توفير منتجاتنا بكفاءة وتوصيلها بشكل موثوق للعملاء عبر المملكة المتحدة وخارجها. يوش ملتزم بالحفاظ على أعلى معايير الجودة والخدمة في جميع عملياتنا.', '2026-02-08 15:27:59', '2026-02-09 03:59:28');
INSERT INTO `directors_de` (`id`, `master_id`, `name`, `title`, `bio`, `created_at`, `updated_at`) VALUES
(1, 'dir-001', 'Hantash Najam', 'Geschäftsführer', 'Hantash Najam ist Gründer und Geschäftsführer der Bio Green Wax Ltd. Mit umfangreicher Erfahrung im internationalen Handel und Rohstoffmärkten hat er ein Netzwerk vertrauenswürdiger Lieferanten in Südostasien, Afrika und Südamerika aufgebaut. Hantash ist außerdem Director bei Bio Greenware Ltd und bringt eine Fülle von Erfahrung in nachhaltiger Beschaffung und Vertrieb von Produkten mit. Seine Vision für Bio Green Wax ist es, ein Unternehmen zu schaffen, das Qualität, Nachhaltigkeit und Kundenpartnerschaften in den Mittelpunkt stellt.', '2026-02-08 15:24:35', '2026-02-09 03:52:31'),
(2, 'dir-002', 'Umesh Gowda', 'Direktor', 'Umesh Gowda bringt wertvolle Fachkenntnisse in den Bereichen Betrieb und Lieferkettenmanagement bei Bio Green Wax Ltd. Sein Hintergrund in Logistik und internationalem Handel trägt dazu bei, dass unsere Produkte effizient beschafft und zuverlässig an Kunden in ganz Großbritannien und darüber hinaus geliefert werden. Umesh setzt sich dafür ein, die höchsten Standards in Qualität und Service in all unseren Abläufen zu wahren.', '2026-02-08 15:28:33', '2026-02-09 03:59:35');
INSERT INTO `directors_es` (`id`, `master_id`, `name`, `title`, `bio`, `created_at`, `updated_at`) VALUES
(1, 'dir-001', 'Hantash Najam', 'Director General', 'Hantash Najam es el fundador y Director General de Bio Green Wax Ltd. Con amplia experiencia en comercio internacional y mercados de productos básicos, ha construido una red de proveedores confiables en el sudeste asiático, África y Sudamérica. Hantash también es director de Bio Greenware Ltd, aportando una gran experiencia en el abastecimiento y distribución de productos sostenibles. Su visión para Bio Green Wax es crear una empresa que priorice la calidad, la sostenibilidad y las alianzas con los clientes.', '2026-02-08 15:23:28', '2026-02-09 03:52:19'),
(2, 'dir-002', 'Umesh Gowda', 'Director', 'Umesh Gowda aporta valiosa experiencia en operaciones y gestión de la cadena de suministro a Bio Green Wax Ltd. Su formación en logística y comercio internacional ayuda a garantizar que nuestros productos se obtengan de manera eficiente y se entreguen de manera confiable a los clientes en todo el Reino Unido y más allá. Umesh está comprometido a mantener los más altos estándares de calidad y servicio en todas nuestras operaciones.', '2026-02-08 15:27:29', '2026-02-09 03:59:24');
INSERT INTO `directors_fr` (`id`, `master_id`, `name`, `title`, `bio`, `created_at`, `updated_at`) VALUES
(1, 'dir-001', 'Hantash Najam', 'Directeur Général', 'Hantash Najam est le fondateur et Directeur Général de Bio Green Wax Ltd. Fort d\'une vaste expérience dans le commerce international et les marchés des matières premières, il a développé un réseau de fournisseurs de confiance à travers l\'Asie du Sud-Est, l\'Afrique et l\'Amérique du Sud. Hantash est également directeur de Bio Greenware Ltd, apportant une riche expérience en sourcing et distribution de produits durables. Sa vision pour Bio Green Wax est de créer une entreprise qui privilégie la qualité, la durabilité et les partenariats avec les clients.', '2026-02-08 15:23:40', '2026-02-09 03:52:21'),
(2, 'dir-002', 'Umesh Gowda', 'Directeur', 'Umesh Gowda apporte une expertise précieuse en gestion des opérations et de la chaîne d\'approvisionnement à Bio Green Wax Ltd. Son parcours dans la logistique et le commerce international contribue à garantir que nos produits soient sourcés efficacement et livrés de manière fiable aux clients du Royaume-Uni et au-delà. Umesh est dédié au maintien des standards les plus élevés en matière de qualité et de service dans toutes nos opérations.', '2026-02-08 15:27:38', '2026-02-09 03:59:26');
INSERT INTO `directors_it` (`id`, `master_id`, `name`, `title`, `bio`, `created_at`, `updated_at`) VALUES
(1, 'dir-001', 'Hantash Najam', 'Amministratore Delegato', 'Hantash Najam è il fondatore e Amministratore Delegato di Bio Green Wax Ltd. Con una vasta esperienza nel commercio internazionale e nei mercati delle materie prime, ha costruito una rete di fornitori affidabili in Southeast Asia, Africa e Sud America. Hantash è anche direttore di Bio Greenware Ltd, portando una grande esperienza nel sourcing e nella distribuzione di prodotti sostenibili. La sua visione per Bio Green Wax è creare un\'azienda che dia priorità alla qualità, alla sostenibilità e alle partnership con i clienti.', '2026-02-08 15:26:49', '2026-02-09 03:52:46'),
(2, 'dir-002', 'Umesh Gowda', 'Direttore', 'Umesh Gowda apporta preziose competenze in ambito operativo e di gestione della supply chain a Bio Green Wax Ltd. Il suo background in logistica e commercio internazionale assicura che i nostri prodotti siano approvvigionati in modo efficiente e consegnati con affidabilità ai clienti nel Regno Unito e oltre. Umesh è impegnato a mantenere i più alti standard di qualità e servizio in tutte le nostre operazioni.', '2026-02-08 15:30:03', '2026-02-09 03:59:50');
INSERT INTO `directors_ja` (`id`, `master_id`, `name`, `title`, `bio`, `created_at`, `updated_at`) VALUES
(1, 'dir-001', 'ハンタッシュ・ナジャム', '取締役社長', 'ハンタッシュ・ナジャムは、Bio Green Wax Ltdの創設者兼マネージングディレクターです。国際貿易とコモディティ市場での豊富な経験を持ち、東南アジア、アフリカ、南アメリカにわたる信頼できるサプライヤーのネットワークを築いています。ハンタッシュはまた、Bio Greenware Ltdの取締役でもあり、持続可能な製品調達と流通に関する豊かな経験を持っています。彼のBio Green Waxに対するビジョンは、品質・持続可能性・顧客とのパートナーシップを重視した企業を創ることです。', '2026-02-08 15:25:02', '2026-02-09 03:52:33'),
(2, 'dir-002', 'ウメッシュ・ゴーワダ', 'ディレクター', 'ウメシュ・ゴウダは、Bio Green Wax Ltd.において、運営およびサプライチェーンマネジメントの貴重な専門知識を提供しています。彼の物流と国際貿易の背景は、私たちの製品が効率的に調達され、英国やそれ以外の地域の顧客へ確実に配達されることを支えています。ウメシュは、すべての業務において最高水準の品質とサービスを維持することに専念しています。', '2026-02-08 15:28:48', '2026-02-09 03:59:37');
INSERT INTO `directors_ko` (`id`, `master_id`, `name`, `title`, `bio`, `created_at`, `updated_at`) VALUES
(1, 'dir-001', '한타쉬 나자엠', '전무 이사', '한타슈 나잠은 Bio Green Wax Ltd의 창립자이자 전무이사입니다. 국제 무역 및 원자재 시장에서의 폭넓은 경험을 바탕으로, 그는 동남아시아, 아프리카 및 남미 전역에 걸쳐 신뢰받는 공급업체 네트워크를 구축하였습니다. 한타슈는 또한 Bio Greenware Ltd의 이사로서, 지속 가능한 제품 조달 및 유통에 대한 풍부한 경험을 가지고 있습니다. 그의 Bio Green Wax에 대한 비전은 품질, 지속 가능성, 고객 파트너십을 최우선으로 하는 회사를 만드는 것입니다.', '2026-02-08 15:26:11', '2026-02-09 03:52:42'),
(2, 'dir-002', '우메시 고다', '감독', '우메시 고우다는 Bio Green Wax Ltd.에 운영 및 공급망 관리에 대한 귀중한 전문성을 제공합니다. 그의 물류 및 국제 무역 배경은 우리의 제품이 효율적으로 조달되고 영국 내외 고객에게 신뢰할 수 있게 배송되도록 돕습니다. 우메시는 우리의 모든 운영에서 최고의 품질과 서비스 표준을 유지하는 데 헌신하고 있습니다.', '2026-02-08 15:29:37', '2026-02-09 03:59:46');
INSERT INTO `directors_pl` (`id`, `master_id`, `name`, `title`, `bio`, `created_at`, `updated_at`) VALUES
(1, 'dir-001', 'Hantash Najam', 'Dyrektor Zarządzający', 'Hantash Najam jest założycielem i Dyrektorem Zarządzającym Bio Green Wax Ltd. Dzięki szerokiemu doświadczeniu w handlu międzynarodowym i rynkach surowców, zbudował sieć zaufanych dostawców w Azji Południowo-Wschodniej, Afryce i Ameryce Południowej. Hantash jest również dyrektorem w Bio Greenware Ltd, wnosi bogate doświadczenie w zakresie pozyskiwania i dystrybucji zrównoważonych produktów. Jego wizją dla Bio Green Wax jest stworzenie firmy, która stawia na jakość, zrównoważony rozwój i partnerstwo z klientami.', '2026-02-08 15:27:02', '2026-02-09 03:52:49'),
(2, 'dir-002', 'Umesh Gowda', 'Reżyser', 'Umesh Gowda wnosi cenne doświadczenie w zarządzaniu operacjami i łańcuchem dostaw do Bio Green Wax Ltd. Jego doświadczenie w logistyce i handlu międzynarodowym pomaga zapewnić, że nasze produkty są pozyskiwane efektywnie i dostarczane niezawodnie do klientów w całym Wielkiej Brytanii i poza nią. Umesh jest zaangażowany w utrzymanie najwyższych standardów jakości i obsługi we wszystkich naszych działaniach.', '2026-02-08 15:30:14', '2026-02-09 03:59:53');
INSERT INTO `directors_pt` (`id`, `master_id`, `name`, `title`, `bio`, `created_at`, `updated_at`) VALUES
(1, 'dir-001', 'Hantash Najam', 'Diretor Geral', 'Hantash Najam é o fundador e Diretor Executivo da Bio Green Wax Ltd. Com ampla experiência em comércio internacional e mercados de commodities, ele construiu uma rede de fornecedores confiáveis na Ásia, África e América do Sul. Hantash também é diretor da Bio Greenware Ltd, trazendo uma vasta experiência em sourcing e distribuição de produtos sustentáveis. Sua visão para a Bio Green Wax é criar uma empresa que priorize qualidade, sustentabilidade e parcerias com os clientes.', '2026-02-08 15:24:08', '2026-02-09 03:52:26'),
(2, 'dir-002', 'Umesh Gowda', 'Diretor', 'Umesh Gowda traz uma valiosa experiência em operações e gestão da cadeia de suprimentos para a Bio Green Wax Ltd. Sua formação em logística e comércio internacional ajuda a garantir que nossos produtos sejam obtidos de forma eficiente e entregues de maneira confiável aos clientes em todo o Reino Unido e além. Umesh está comprometido em manter os padrões mais elevados de qualidade e serviço em todas as nossas operações.', '2026-02-08 15:28:08', '2026-02-09 03:59:30');
INSERT INTO `directors_ru` (`id`, `master_id`, `name`, `title`, `bio`, `created_at`, `updated_at`) VALUES
(1, 'dir-001', 'Hantash Najam', 'Исполнительный директор', 'Ханташ Наджам — основатель и управляющий директор компании Bio Green Wax Ltd. Благодаря обширному опыту в области международной торговли и товарных рынков, он выстроил сеть надежных поставщиков в странах Юго-Восточной Азии, Африки и Южной Америки. Ханташ также является директором компании Bio Greenware Ltd, обладающей богатым опытом в области устойчивого поиска и распространения продукции. Его видение для Bio Green Wax — создать компанию, которая ориентируется на качество, устойчивость и партнерские отношения с клиентами.', '2026-02-08 15:24:23', '2026-02-09 03:52:29'),
(2, 'dir-002', 'Умеш Говда', 'Директор', 'Умеш Гауда приносит ценную экспертизу в области операций и управления цепочками поставок в Bio Green Wax Ltd. Его опыт в области логистики и международной торговли способствует тому, чтобы наши продукты закупались эффективно и доставлялись надежно клиентам по всему Великобритании и за её пределами. Умеш привержен поддержанию высочайших стандартов качества и сервиса во всех наших операциях.', '2026-02-08 15:28:21', '2026-02-09 03:59:33');
INSERT INTO `directors_sw` (`id`, `master_id`, `name`, `title`, `bio`, `created_at`, `updated_at`) VALUES
(1, 'dir-001', 'Hantash Najam', 'Mkurugenzi Mkuu', 'Hantash Najam ni mwanzilishi na Mkurugenzi Mkuu wa Bio Green Wax Ltd. Kwa uzoefu mkubwa katika biashara za kimataifa na masoko ya bidhaa, amejenga mtandao wa Wasambazaji wanaoaminika kote Asia Kusini-Mashariki, Afrika, na Amerika Kusini. Hantash pia ni mkurugenzi wa Bio Greenware Ltd, akileta uzoefu mwingi katika utafutaji na usambazaji wa bidhaa za kiustawi. Maono yake kwa Bio Green Wax ni kuunda kampuni inayoweka mbele ubora, uendelevu, na ushirikiano wa wateja.', '2026-02-08 15:25:12', '2026-02-09 03:52:35'),
(2, 'dir-002', 'Umesh Gowda', 'Mkurugenzi', 'Umesh Gowda analeta ujuzi wa kina katika usimamizi wa shughuli na mbinu za usambazaji kwa Bio Green Wax Ltd. Uzoefu wake katika usafirishaji na biashara za kimataifa unasaidia kuhakikisha kuwa bidhaa zetu zinapatikana kwa ufanisi na zinawafikia wateja kwa imani katika Uingereza na zaidi ya hapo. Umesh amejitolea kudumisha viwango vya juu vya ubora na huduma katika shughuli zetu zote.', '2026-02-08 15:28:58', '2026-02-09 03:59:39');
INSERT INTO `directors_th` (`id`, `master_id`, `name`, `title`, `bio`, `created_at`, `updated_at`) VALUES
(1, 'dir-001', 'Hantash Najam', 'ผู้จัดการฝ่ายบริหาร', 'Hantash Najam คือผู้ก่อตั้งและกรรมการผู้จัดการของ Bio Green Wax Ltd. ด้วยประสบการณ์อันลึกซึ้งในด้านการค้าระหว่างประเทศและตลาดสินค้าโภคภัณฑ์ เขาได้สร้างเครือข่ายซัพพลายเออร์ที่เชื่อถือได้ทั่วเอเชียตะวันออกเฉียงใต้ แอฟริกา และอเมริกาใต้ Hantash ยังเป็นกรรมการของ Bio Greenware Ltd ซึ่งนำเสนอประสบการณ์อันรุ่มรวยในด้านการจัดหาและจัดจำหน่ายผลิตภัณฑ์อย่างยั่งยืน วิสัยทัศน์ของเขาสำหรับ Bio Green Wax คือการสร้างบริษัทที่ให้ความสำคัญกับคุณภาพ ความยั่งยืน และความร่วมมือกับลูกค้า', '2026-02-08 15:26:33', '2026-02-09 03:52:44'),
(2, 'dir-002', 'อูเมช โวดา', 'ผู้กำกับ', 'อูเมช โ Gowda นำความเชี่ยวชาญอันมีค่าด้านการดำเนินงานและการจัดการซัพพลายเชนมาสู่ Bio Green Wax Ltd. พื้นฐานของเขาในด้านโลจิสติกส์และการค้าระหว่างประเทศช่วยให้มั่นใจได้ว่าสินค้าของเราได้รับการจัดหาอย่างมีประสิทธิภาพและส่งมอบอย่างน่าเชื่อถือให้กับลูกค้าทั้งในสหราชอาณาจักรและนอกเหนือจากนั้น อูเมชมุ่งมั่นที่จะรักษามาตรฐานสูงสุดด้านคุณภาพและการบริการในทุกการดำเนินงานของเรา', '2026-02-08 15:29:52', '2026-02-09 03:59:49');
INSERT INTO `directors_tr` (`id`, `master_id`, `name`, `title`, `bio`, `created_at`, `updated_at`) VALUES
(1, 'dir-001', 'Hantash Najam', 'Genel Müdür', 'Hantash Najam, Bio Green Wax Ltd.\'nin kurucusu ve Yönetim Kurulu Başkanıdır. Uluslararası ticaret ve emtia piyasalarında geniş deneyime sahip olan Hantash, Güneydoğu Asya, Afrika ve Güney Amerika genelinde güvenilir tedarikçilerden oluşan bir ağ kurmuştur. Ayrıca, Bio Greenware Ltd.\'nin direktörlüğünü yapan Hantash, sürdürülebilir ürün tedariki ve dağıtımı konularında zengin bir deneyime sahiptir. Bio Green Wax için vizyonu, kalite, sürdürülebilirlik ve müşteri ortaklıklarını ön planda tutan bir şirket yaratmaktır.', '2026-02-08 15:25:27', '2026-02-09 03:52:37'),
(2, 'dir-002', 'Umesh Gowda', 'Yönetmen', 'Umesh Gowda, Bio Green Wax Ltd.\'ye operasyonlar ve tedarik zinciri yönetimi konusunda değerli uzmanlık katmaktadır. Lojistik ve uluslararası ticaret geçmişi, ürünlerimizin verimli şekilde temin edilmesini ve İngiltere genelinde ve ötesinde müşterilere güvenilir şekilde ulaştırılmasını sağlamaya yardımcı olmaktadır. Umesh, tüm operasyonlarımızda en yüksek kalite ve hizmet standartlarını korumaya kendini adamıştır.', '2026-02-08 15:29:10', '2026-02-09 03:59:41');
INSERT INTO `directors_vi` (`id`, `master_id`, `name`, `title`, `bio`, `created_at`, `updated_at`) VALUES
(1, 'dir-001', 'Hantash Najam', 'Giám đốc Điều hành', 'Hantash Najam là nhà sáng lập và Giám đốc Điều hành của Bio Green Wax Ltd. Với kinh nghiệm dạn dày trong thương mại quốc tế và thị trường hàng hóa, ông đã xây dựng được một mạng lưới nhà cung cấp đáng tin cậy khắp Đông Nam Á, Châu Phi và Nam Mỹ. Hantash cũng là giám đốc của Bio Greenware Ltd, mang đến một kho tàng kinh nghiệm về sourcing và phân phối các sản phẩm bền vững. Tầm nhìn của ông đối với Bio Green Wax là tạo ra một công ty đặt chất lượng, tính bền vững và mối quan hệ khách hàng làm trọng tâm.', '2026-02-08 15:25:46', '2026-02-09 03:52:40'),
(2, 'dir-002', 'Umesh Gowda', 'Giám đốc', 'Umesh Gowda mang đến kiến thức quý giá về vận hành và quản lý chuỗi cung ứng cho Bio Green Wax Ltd. Nền tảng của anh ấy trong lĩnh vực logistics và thương mại quốc tế giúp đảm bảo các sản phẩm của chúng tôi được mua nguồn một cách hiệu quả và giao hàng đáng tin cậy đến khách hàng khắp Vương quốc Anh và hơn thế nữa. Umesh luôn cống hiến để duy trì các tiêu chuẩn cao nhất về chất lượng và dịch vụ trong tất cả các hoạt động của chúng tôi.', '2026-02-08 15:29:20', '2026-02-09 03:59:44');
INSERT INTO `directors_zh` (`id`, `master_id`, `name`, `title`, `bio`, `created_at`, `updated_at`) VALUES
(1, 'dir-001', '汉塔什·纳贾姆', '总经理', 'Hantash Najam 是 Bio Green Wax Ltd. 的创始人兼董事总经理。凭借在国际贸易和大宗商品市场方面的丰富经验，他在东南亚、非洲和南美建立了一个值得信赖的供应商网络。Hantash 还是 Bio Greenware Ltd. 的董事，在可持续产品采购和分销方面拥有丰富的经验。他对 Bio Green Wax 的愿景是打造一家以质量、可持续发展和客户合作为优先的公司。', '2026-02-08 15:23:17', '2026-02-09 03:52:16'),
(2, 'dir-002', '乌梅什·高达', '导演', 'Umesh Gowda为Bio Green Wax Ltd.带来了宝贵的运营与供应链管理专业知识。他在物流和国际贸易方面的背景有助于确保我们的产品高效采购，并可靠地交付给英国及其他地区的客户。Umesh致力于在所有业务中保持最高的质量和服务标准。', '2026-02-08 15:27:19', '2026-02-09 03:59:22');
