(3, 'slide-001', 'น้ำมันพืชคุณภาพสูงจาก Nature\'s Finest', 'น้ำมันถั่วเหลือง, ปาล์ม, คาวิซ, ดอกทานตะวัน, มะกอก และมะพร้าว พร้อมสำหรับ B2B ทั่วโลก', 'สำรวจน้ำมันของเรา', '2026-02-08 15:46:18', '2026-02-09 17:04:50'),
(4, 'slide-002', 'เทียนพ wax สำหรับทุกการใช้งาน', 'แว๊กซ์คุณภาพสูงสำหรับการทำเทียน เครื่องสำอาง และอื่นๆ', 'ดูช่วงสินค้า Wax', '2026-02-08 15:48:59', '2026-02-09 17:05:22'),
(5, 'slide-003', 'พันธมิตรที่เชื่อถือได้ของคุณสำหรับความต้องการด้านอุตสาหกรรม', 'หลายทศวรรษของความเชี่ยวชาญในน้ำมันธรรมชาติและขี้ผึ้งอุตสาหกรรม', 'เกี่ยวกับเรา', '2026-02-08 15:50:58', '2026-02-09 17:06:30');
INSERT INTO `hero_slides_tr` (`id`, `master_id`, `title`, `subtitle`, `cta_text`, `created_at`, `updated_at`) VALUES
(1, '29991d1d-087a-4b6e-be55-d74d0cc70cd8', 'RSPO SG (Segregated) ve MB (Mass Balance) Palm türevleri', 'Sürdürülebilir Palmiye Yağı İşleme: Meyveden Sertifikalı Ürünlere RSPO Segregated ve Mass Balance Modelleri altında', 'Ürünleri Görüntüle', '2026-02-09 17:04:13', '2026-02-09 17:04:13'),
(2, 'b1a3a562-6f7a-47b5-9481-c6e3dc3bd104', 'Çiftlikten Küresel Ticarete', 'Canlı Yonca, Soya, Ayçiçeği tarlaları ve RSPO sertifikalı Palm tarlaları tedarik zincirimizi besliyor.', 'Hakkımızda', '2026-02-09 17:05:49', '2026-02-09 17:05:49'),
(3, 'slide-001', 'Nature\'s Finest\'tan Premium yenilebilir yağlar', 'B2B dünyası için hazır olan Soy, Palm, Kanola, Ayçiçek, Zeytin ve Hindistan Cevizi yağları.', 'Hakkımızdaki Yağlarımızı Keşfedin', '2026-02-08 15:45:48', '2026-02-09 17:04:44'),
(4, 'slide-002', 'Her Uygulama İçin Endüstriyel Mumlar', 'Kaliteli performanslı mum yapımı, kozmetik ve daha fazlası için yüksek performanslı waxlar', 'Wax Aralığını Görüntüle', '2026-02-08 15:48:34', '2026-02-09 17:05:17'),
(5, 'slide-003', 'Endüstriyel İhtiyaçlarınız İçin Güvenilir Ortağınız', 'Doğal yağlar ve endüstriyel mumlar alanında onlarca yıllık uzmanlık', 'Hakkımızda', '2026-02-08 15:50:36', '2026-02-09 17:06:23');
INSERT INTO `hero_slides_vi` (`id`, `master_id`, `title`, `subtitle`, `cta_text`, `created_at`, `updated_at`) VALUES
(1, '29991d1d-087a-4b6e-be55-d74d0cc70cd8', 'Các sản phẩm phụ của dầu cọ RSPO SG (Phân loại riêng biệt) và MB (Cân bằng khối lượng)', 'Xử lý Dầu Cọ Bền vững: Từ Quả đến các Sản phẩm Từ chứng nhận theo các mô hình Ngăn xếp và Cân bằng Tổng hợp RSPO', 'Xem Sản Phẩm', '2026-02-09 17:04:16', '2026-02-09 17:04:16'),
(2, 'b1a3a562-6f7a-47b5-9481-c6e3dc3bd104', 'Từ Trang trại đến Thương mại Toàn cầu', 'Các cánh đồng Cải dầu, Đậu nành, Hoa hướng dương tươi sáng và đồn điền Cọ được chứng nhận RSPO đang cung cấp nguồn nguyên liệu cho chuỗi cung ứng của chúng tôi.', 'Về Chúng Tôi', '2026-02-09 17:05:51', '2026-02-09 17:05:51'),
(3, 'slide-001', 'Dầu ăn cao cấp từ những sản phẩm tốt nhất của Thiên nhiên', 'Dầu đậu nành, dầu cọ, dầu cải dầu, dầu hướng dương, dầu ô liu và dầu dừa sẵn sàng phục vụ B2B toàn cầu.', 'Khám phá các loại dầu của chúng tôi', '2026-02-08 15:45:58', '2026-02-09 17:04:46'),
(4, 'slide-002', 'Sáp công nghiệp cho mọi ứng dụng', 'Sáp chất lượng cao cho làm nến, mỹ phẩm và nhiều ứng dụng khác', 'Xem Khoảng Cách Sáp', '2026-02-08 15:48:42', '2026-02-09 17:05:19'),
(5, 'slide-003', 'Đối tác tin cậy của bạn cho các nhu cầu công nghiệp', 'Nhiều thập kỷ kinh nghiệm trong lĩnh vực dầu tự nhiên và sáp công nghiệp', 'Về chúng tôi', '2026-02-08 15:50:44', '2026-02-09 17:06:24');
INSERT INTO `hero_slides_zh` (`id`, `master_id`, `title`, `subtitle`, `cta_text`, `created_at`, `updated_at`) VALUES
(1, '29991d1d-087a-4b6e-be55-d74d0cc70cd8', 'RSPO SG（分离）和MB（质量平衡）棕榈衍生品', '可持续棕榈油加工：从果实到认证衍生品的RSPO分离和质量平衡模式', '查看产品', '2026-02-09 17:03:54', '2026-02-09 17:03:54'),
(2, 'b1a3a562-6f7a-47b5-9481-c6e3dc3bd104', '从农场到全球贸易', '充满生机的油菜、黄豆、向日葵田，以及获得RSPO认证的棕榈油种植园，为我们的供应链提供动力。', '关于我们', '2026-02-09 17:05:28', '2026-02-09 17:05:28'),
(3, 'slide-001', '来自大自然的最佳优质食用油', '大豆油、棕榈油、菜籽油、葵花籽油、橄榄油和椰子油，准备面向全球B2B市场。', '探索我们的油品', '2026-02-08 15:43:09', '2026-02-09 17:04:26'),
(4, 'slide-002', '适用于各种应用的工业蜡', '用于制造蜡烛、化妆品等的高性能蜡', '查看蜡范围', '2026-02-08 15:46:49', '2026-02-09 17:04:57'),
(5, 'slide-003', '您值得信赖的工业合作伙伴', '数十年的天然油和工业蜡专业知识', '关于我们', '2026-02-08 15:49:23', '2026-02-09 17:06:03');
INSERT INTO `job_applications` (`id`, `job_opening_id`, `full_name`, `email`, `phone`, `current_company`, `current_position`, `experience_years`, `linkedin_url`, `cover_letter`, `why_suitable`, `value_addition`, `cv_url`, `cv_filename`, `is_general_application`, `is_read`, `created_at`) VALUES
('app-001', 'job-001', 'James Wilson', 'james.wilson@email.com', '+44 7700 123456', 'ABC Chemicals Ltd', 'Senior Sales Executive', 7, 'https://linkedin.com/in/jameswilson', 'I am writing to express my strong interest in the Sales Manager position at Bio Green Wax Ltd.', 'My 7 years of experience in B2B chemical sales makes me an ideal candidate.', 'I can bring my extensive network of industry contacts and proven track record of exceeding sales targets.', NULL, NULL, 0, 0, '2026-02-05 21:03:49'),
('app-002', 'job-002', 'Sarah Thompson', 'sarah.t@email.com', '+44 7800 234567', 'Quality Labs UK', 'QC Analyst', 3, NULL, 'I am excited to apply for the Quality Control Technician role.', 'My chemistry degree and 3 years of QC experience have prepared me well.', 'I am ISO 9001 trained and have experience implementing quality improvement programs.', NULL, NULL, 0, 1, '2026-02-05 21:03:49'),
('app-003', 'job-003', 'Michael Brown', 'mbrown@email.com', '+44 7900 345678', NULL, NULL, 2, NULL, 'I would like to apply for the Warehouse Operative position.', 'I have previous warehouse experience and a valid forklift license.', 'I am reliable, hardworking, and enjoy being part of a team.', NULL, NULL, 0, 0, '2026-02-05 21:03:49'),
('app-004', NULL, 'Emily Roberts', 'emily.roberts@email.com', '+44 7600 456789', 'Self-employed', 'Freelance Writer', 5, 'https://linkedin.com/in/emilyroberts', 'I am submitting my CV for consideration for any suitable marketing or communications roles.', 'I have experience in content marketing for B2B companies.', 'My skills in SEO and content strategy could help grow your online presence.', NULL, NULL, 1, 0, '2026-02-05 21:03:49');
INSERT INTO `job_openings` (`id`, `title`, `department`, `location`, `type`, `employment_type`, `description`, `requirements`, `responsibilities`, `is_active`, `synchronized_data`, `display_order`, `created_at`) VALUES
('job-001', 'Sales Manager', 'Sales', 'London, UK', 'Full-time', 'Permanent', 'We are looking for an experienced Sales Manager to lead our UK sales team and drive business growth in the oils and waxes sector.', '[\"5+ years sales experience in B2B environment\", \"Experience in chemicals or commodities industry\", \"Strong negotiation and relationship-building skills\", \"Bachelor\'s degree in Business or related field\"]', 'Lead and manage the UK sales team, Develop and implement sales strategies, Build and maintain key client relationships, Meet quarterly and annual sales targets', 1, 1, 1, '2026-02-05 21:03:49'),
('job-002', 'Quality Control Technician', 'Operations', 'Manchester, UK', 'Full-time', 'Permanent', 'Join our quality team to ensure our products meet the highest standards of quality and compliance.', '[\"Degree in Chemistry or related field\", \"2+ years experience in QC laboratory\", \"Knowledge of GMP and ISO standards\", \"Attention to detail and analytical skills\"]', 'Perform quality testing on incoming materials and finished products, Maintain quality documentation and records, Implement and monitor quality control procedures', 1, 1, 2, '2026-02-05 21:03:49'),
('job-003', 'Warehouse Operative', 'Logistics', 'Birmingham, UK', 'Full-time', 'Permanent', 'We need a reliable Warehouse Operative to join our logistics team handling oils and wax products.', '[\"Previous warehouse experience preferred\", \"Forklift license advantageous\", \"Good physical fitness\", \"Ability to work in a team\"]', 'Pick and pack orders accurately, Receive and check incoming deliveries, Maintain clean and organized warehouse, Assist with stock counts', 1, 1, 3, '2026-02-05 21:03:49'),
('job-004', 'Marketing Coordinator', 'Marketing', 'Remote, UK', 'Part-time', 'Contract', 'Support our marketing team with digital campaigns and content creation for our growing business.', '[\"Experience with social media marketing\", \"Strong written communication skills\", \"Familiarity with B2B marketing\", \"Creative mindset\"]', 'Manage social media accounts, Create marketing content and collateral, Support trade show and event planning, Analyze marketing campaign performance', 1, 1, 4, '2026-02-05 21:03:49');
INSERT INTO `job_openings_ar` (`id`, `master_id`, `title`, `description`, `requirements`, `responsibilities`, `created_at`, `updated_at`) VALUES
(1, 'job-001', 'مدير المبيعات', 'نبحث عن مدير مبيعات ذو خبرة لقيادة فريق المبيعات في المملكة المتحدة ودفع نمو الأعمال في قطاع الزيوت والشموع.', '[\"خبرة تزيد عن 5 سنوات في المبيعات في بيئة B2B\", \"خبرة في صناعة الكيماويات أو السلع الأساسية\", \"مهارات تفاوض وبناء علاقات قوية\", \"درجة البكالوريوس في إدارة الأعمال أو مجال ذي صلة\"]', 'قيادة وإدارة فريق المبيعات في المملكة المتحدة، تطوير وتنفيذ استراتيجيات المبيعات، بناء والحفاظ على علاقات العملاء الرئيسية، تحقيق أهداف المبيعات الفصلية والسنوية', '2026-02-06 05:36:26', '2026-02-09 04:25:34'),
(2, 'job-002', 'فني مراقبة الجودة', 'انضم إلى فريق الجودة لدينا لضمان تلبية منتجاتنا لأعلى معايير الجودة والامتثال.', '[\"درجة في الكيمياء أو مجال ذو صلة\", \"خبرة تزيد عن سنتين في مختبر مراقبة الجودة\", \"معرفة بمعايير GMP و ISO\", \"الاهتمام بالتفاصيل والمهارات التحليلية\"]', 'إجراء اختبارات الجودة على المواد الواردة والمنتجات النهائية، الحفاظ على وثائق وسجلات الجودة، تنفيذ ورصد إجراءات مراقبة الجودة', '2026-02-06 05:42:21', '2026-02-09 04:26:25'),
(3, 'job-003', 'عامل مستودع', 'نحن بحاجة إلى عامل مخزن موثوق للانضمام إلى فريق اللوجستيات لدينا الذي يهتم بمنتجات الزيوت والشمع.', '[\"يفضل خبرة سابقة في المخزن\", \"رخصة الرافعة الشوكية ميزة إضافية\", \"لياقة بدنية جيدة\", \"القدرة على العمل ضمن فريق\"]', 'اختيار وتعبئة الطلبات بدقة، استلام وفحص الشحنات الواردة، الحفاظ على نظافة وتنظيم المستودع، المساعدة في جرد المخزون', '2026-02-08 15:08:54', '2026-02-09 04:27:14'),
(4, 'job-004', 'منسق التسويق', 'دعم فريق التسويق لدينا في الحملات الرقمية وإنشاء المحتوى لنمو أعمالنا المستمر.', '[\"الخبرة في التسويق عبر وسائل التواصل الاجتماعي\"، \"مهارات قوية في الكتابة والتواصل\"، \"الاطلاع على التسويق بين الشركات (B2B)\", \"ذهنية إبداعية\"]', 'إدارة حسابات وسائل التواصل الاجتماعي، إنشاء محتوى ومواد تسويقية، دعم تنظيم المعارض التجارية والفعاليات، تحليل أداء الحملات التسويقية', '2026-02-08 15:13:16', '2026-02-09 04:28:03');
INSERT INTO `job_openings_de` (`id`, `master_id`, `title`, `description`, `requirements`, `responsibilities`, `created_at`, `updated_at`) VALUES
(1, 'job-001', 'Vertriebsleiter', 'Wir suchen einen erfahrenen Vertriebsleiter, um unser Verkaufsteam im Vereinigten Königreich zu leiten und das Geschäftswachstum im Bereich Öle und Wachs voranzutreiben.', '[\"Mehr als 5 Jahre Verkaufserfahrung im B2B-Umfeld\", \"Erfahrung in der Chemie- oder Rohstoffbranche\", \"Starke Verhandlungs- und Beziehungsfähigkeiten\", \"Bachelor-Abschluss in Betriebswirtschaft oder einem verwandten Bereich\"]', 'Führen und leiten Sie das Vertriebsteam im Vereinigten Königreich, Entwickeln und implementieren Sie Vertriebsstrategien, Bauen Sie wichtige Kundenbeziehungen auf und pflegen Sie diese, Erreichen Sie vierteljährliche und jährliche Verkaufsziele.', '2026-02-06 05:37:46', '2026-02-09 04:25:45'),
(2, 'job-002', 'Qualitätskontrolleur/-techniker', 'Schließen Sie sich unserem Qualitätsteam an, um sicherzustellen, dass unsere Produkte die höchsten Standards in Qualität und Einhaltung erfüllen.', '[\"Abschluss in Chemie oder einem verwandten Bereich\", \"Mehrjährige Erfahrung im QC-Labor (>2 Jahre)\", \"Kenntnisse der GMP- und ISO-Standards\", \"Sorgfalt und analytische Fähigkeiten\"]', 'Führen Sie Qualitätsprüfungen an eingehenden Materialien und Fertigprodukten durch, pflegen Sie Qualitätsdokumentationen und Aufzeichnungen, implementieren und überwachen Sie Qualitätskontrollverfahren', '2026-02-06 05:43:21', '2026-02-09 04:26:35'),
(3, 'job-003', 'Lagerarbeiter', 'Wir benötigen einen zuverlässigen Lagerarbeiter, der unser Logistikteam bei der Abwicklung von Ölen und Wachsprodukten unterstützt.', '[\"Vorherige Lagererfahrung bevorzugt\", \"Gabelstaplerschein von Vorteil\", \"Gute körperliche Verfassung\", \"Teamfähigkeit\"]', 'Bestellen und kommissionieren Sie Bestellungen genau, Empfangen und überprüfen Sie eingehende Lieferungen, Halten Sie das Lager sauber und ordentlich, Unterstützen Sie bei Bestandszählungen', '2026-02-08 15:09:48', '2026-02-09 04:27:27'),
(4, 'job-004', 'Marketing Koordinator', 'Unterstützen Sie unser Marketing-Team bei digitalen Kampagnen und der Erstellung von Inhalten für unser wachsendes Unternehmen.', '[\"Erfahrung im Social-Media-Marketing\", \"Ausgezeichnete schriftliche Kommunikationsfähigkeiten\", \"Vertrautheit mit B2B-Marketing\", \"Kreative Denkweise\"]', 'Verwalten Sie Social-Media-Konten, erstellen Sie Marketinginhalte und -materialien, unterstützen Sie bei der Planung von Messen und Veranstaltungen, analysieren Sie die Leistung von Marketingkampagnen', '2026-02-08 15:14:07', '2026-02-09 04:28:12');
INSERT INTO `job_openings_es` (`id`, `master_id`, `title`, `description`, `requirements`, `responsibilities`, `created_at`, `updated_at`) VALUES
(1, 'job-001', 'Gerente de Ventas', 'Estamos buscando un Director de Ventas con experiencia para liderar nuestro equipo de ventas en Reino Unido y promover el crecimiento del negocio en el sector de los aceites y ceras.', '[\"Más de 5 años de experiencia en ventas en entorno B2B\", \"Experiencia en la industria de químicos o commodities\", \"Fuertes habilidades de negociación y de construcción de relaciones\", \"Licenciatura en Negocios o campo relacionado\"]', 'Liderar y gestionar el equipo de ventas en el Reino Unido, desarrollar e implementar estrategias de ventas, construir y mantener relaciones con clientes clave, alcanzar los objetivos de ventas trimestrales y anuales.', '2026-02-06 05:35:42', '2026-02-09 04:25:27'),
(2, 'job-002', 'Técnico de Control de Calidad', 'Únete a nuestro equipo de calidad para garantizar que nuestros productos cumplan con los más altos estándares de calidad y cumplimiento.', '[\"Licenciatura en Química o campo relacionado\", \"Más de 2 años de experiencia en laboratorio de control de calidad\", \"Conocimiento de las normas GMP e ISO\", \"Atención a los detalles y habilidades analíticas\"]', 'Realizar pruebas de calidad en materiales entrantes y productos terminados, mantener la documentación y registros de calidad, implementar y monitorear los procedimientos de control de calidad', '2026-02-06 05:41:41', '2026-02-09 04:26:20'),
(3, 'job-003', 'Operario de almacén', 'Necesitamos un Operador de Almacén confiable para unirse a nuestro equipo de logística encargado de productos de aceites y cera.', '[\"Se prefiere experiencia previa en almacén\", \"Se valorará licencia de carretilla elevadora\", \"Buena condición física\", \"Capacidad para trabajar en equipo\"]', 'Seleccionar y preparar pedidos con precisión, recibir y verificar entregas entrantes, mantener el almacén limpio y organizado, asistir con los conteos de inventario.', '2026-02-08 15:08:18', '2026-02-09 04:27:08'),
(4, 'job-004', 'Coordinador de Marketing', 'Apoya a nuestro equipo de marketing con campañas digitales y creación de contenido para nuestro negocio en crecimiento.', '[\"Experiencia en marketing en redes sociales\", \"Habilidades sólidas de comunicación escrita\", \"Familiaridad con el marketing B2B\", \"Mentalidad creativa\"]', 'Gestionar cuentas de redes sociales, Crear contenido y material de marketing, Apoyar la planificación de ferias comerciales y eventos, Analizar el rendimiento de campañas de marketing', '2026-02-08 15:12:49', '2026-02-09 04:27:57');
INSERT INTO `job_openings_fr` (`id`, `master_id`, `title`, `description`, `requirements`, `responsibilities`, `created_at`, `updated_at`) VALUES
(1, 'job-001', 'Responsable des Ventes', 'Nous recherchons un(e) manager des ventes expérimenté(e) pour diriger notre équipe de vente au Royaume-Uni et stimuler la croissance commerciale dans le secteur des huiles et cires.', '[\"Plus de 5 ans d\'expérience en vente dans un environnement B2B\", \"Expérience dans l\'industrie chimique ou des matières premières\", \"Solides compétences en négociation et en développement des relations\", \"Diplôme de licence en commerce ou dans un domaine connexe\"]', 'Diriger et gérer l\'équipe de vente au Royaume-Uni, développer et mettre en œuvre des stratégies de vente, établir et maintenir des relations avec les clients clés, atteindre les objectifs de vente trimestriels et annuels', '2026-02-06 05:36:07', '2026-02-09 04:25:30'),
(2, 'job-002', 'Technicien en Contrôle Qualité', 'Rejoignez notre équipe qualité pour garantir que nos produits répondent aux normes les plus élevées de qualité et de conformité.', '[\"Diplôme en chimie ou domaine connexe\", \"Plus de 2 ans d\'expérience en laboratoire de contrôle qualité\", \"Connaissance des normes GMP et ISO\", \"Souci du détail et compétences analytiques\"]', 'Effectuer des tests de qualité sur les matériaux entrants et les produits finis, Maintenir la documentation et les dossiers de qualité, Mettre en œuvre et suivre les procédures de contrôle qualité', '2026-02-06 05:42:04', '2026-02-09 04:26:22'),
(3, 'job-003', 'Opérateur d\'entrepôt', 'Nous avons besoin d\'un opérateur d\'entrepôt fiable pour rejoindre notre équipe logistique chargée de produits à base d\'huiles et de cires.', '[\"Expérience en entrepôt précédente appréciée\", \"Permis de chariot élévateur avantageux\", \"Bonne condition physique\", \"Capacité à travailler en équipe\"]', 'Préparer et emballer les commandes avec précision, réceptionner et vérifier les livraisons entrantes, maintenir un entrepôt propre et organisé, aider à l\'inventaire du stock', '2026-02-08 15:08:38', '2026-02-09 04:27:10'),
(4, 'job-004', 'Coordinateur(trice) Marketing', 'Soutenez notre équipe marketing avec des campagnes numériques et la création de contenu pour notre activité en pleine expansion.', '[\"Expérience en marketing sur les réseaux sociaux\", \"Excellentes compétences en communication écrite\", \"Connaissance du marketing B2B\", \"Esprit créatif\"]', 'Gérer les comptes de médias sociaux, Créer du contenu marketing et du matériel promotionnel, Soutenir la planification des salons professionnels et des événements, Analyser la performance des campagnes marketing', '2026-02-08 15:13:03', '2026-02-09 04:28:00');
INSERT INTO `job_openings_it` (`id`, `master_id`, `title`, `description`, `requirements`, `responsibilities`, `created_at`, `updated_at`) VALUES
(1, 'job-001', 'Direttore delle vendite', 'Siamo alla ricerca di un Sales Manager esperto per guidare il nostro team di vendita nel Regno Unito e stimolare la crescita del business nel settore degli oli e delle cere.', '[\"Oltre 5 anni di esperienza nelle vendite in ambiente B2B\", \"Esperienza nel settore chimico o delle commodities\", \"Spiccate capacità di negoziazione e di costruzione di rapporti\", \"Laurea in Economia o campo affine\"]', 'Guidare e gestire il team di vendita nel Regno Unito, sviluppare e attuare strategie di vendita, costruire e mantenere relazioni con clienti chiave, raggiungere gli obiettivi di vendita trimestrali e annuali', '2026-02-06 05:40:41', '2026-02-09 04:26:08'),
(2, 'job-002', 'Tecnico del Controllo Qualità', 'Unisciti al nostro team di qualità per garantire che i nostri prodotti rispettino i più alti standard di qualità e conformità.', '[\"Laurea in Chimica o in un campo correlato\", \"Oltre 2 anni di esperienza in laboratorio di CQ\", \"Conoscenza delle normative GMP e ISO\", \"Precisione e capacità analitiche\"]', 'Eseguire test di qualità sui materiali in ingresso e sui prodotti finiti, Mantenere la documentazione e i registri sulla qualità, Implementare e monitorare le procedure di controllo qualità', '2026-02-08 15:07:25', '2026-02-09 04:26:59'),
(3, 'job-003', 'Addetto al magazzino', 'Abbiamo bisogno di un Operatore di Magazzino affidabile per unirsi al nostro team di logistica che si occupa di oli e cere.', '[\"Esperienza precedente in magazzino preferita\", \"Patentino di carrello elevatore vantaggioso\", \"Buona forma fisica\", \"Capacità di lavorare in team\"]', 'Seleziona e imballa gli ordini con precisione, Ricevi e controlla le consegne in arrivo, Mantieni il magazzino pulito e ordinato, Assisti con le inventariamenti', '2026-02-08 15:12:01', '2026-02-09 04:27:50'),
(4, 'job-004', 'Coordinatore Marketing', 'Sostieni il nostro team di marketing con campagne digitali e creazione di contenuti per la nostra attività in crescita.', '[\"Anos di esperienza nel social media marketing\", \"Ottime capacità di comunicazione scritta\", \"Conoscenza del marketing B2B\", \"Mentalità creativa\"]', 'Gestisci account di social media, Crea contenuti e materiali di marketing, Supporta l\'organizzazione di fiere ed eventi, Analizza le prestazioni delle campagne di marketing', '2026-02-08 15:16:01', '2026-02-09 04:28:33');
INSERT INTO `job_openings_ja` (`id`, `master_id`, `title`, `description`, `requirements`, `responsibilities`, `created_at`, `updated_at`) VALUES
(1, 'job-001', '営業マネージャー', '私たちは、UKの営業チームをリードし、オイルやワックス分野での事業拡大を推進する経験豊富なセールスマネージャーを募集しています。', '[\"B2B環境での営業経験5年以上\", \"化学品またはコモディティ業界での経験\", \"高度な交渉力と人間関係構築スキル\", \"ビジネスまたは関連分野の学士号\"]', '英国の営業チームをリードおよび管理し、販売戦略を策定・実行し、主要顧客との関係を構築・維持し、四半期および年間の販売目標を達成する。', '2026-02-06 05:38:11', '2026-02-09 04:25:48'),
(2, 'job-002', '品質管理技術者', '私たちの品質チームに参加して、私たちの製品が最高の品質とコンプライアンス基準を満たすようにしましょう。', '[\"化学または関連分野の学位\", \"QCラボでの2年以上の経験\", \"GMPおよびISO基準の知識\", \"細部に注意を払い、分析スキルに優れる\"]', '入荷材料および完成品の品質検査を実施し、品質に関するドキュメントと記録を維持します。品質管理手順を実施・監視します。', '2026-02-06 05:43:40', '2026-02-09 04:26:39'),
(3, 'job-003', '倉庫作業員', '油やワックス製品を取り扱う物流チームに加わる信頼できる倉庫作業員が必要です。', '[\"以前の倉庫経験 優遇\", \"フォークリフト免許優遇\", \"良好な体力\", \"チームで働く能力\"]', '正確にピック＆パックを行う、入荷した納品物の受け取りと検品を行う、倉庫を清潔かつ整頓された状態に保つ、在庫数のカウントをサポートする', '2026-02-08 15:10:08', '2026-02-09 04:27:30'),
(4, 'job-004', 'マーケティングコーディネーター', '私たちの成長している事業のために、マーケティングチームのデジタルキャンペーンおよびコンテンツ制作をサポートしてください。', '「ソーシャルメディアマーケティングの経験」「優れた書面コミュニケーション能力」「B2Bマーケティングに関する知識」「創造的な思考」', 'ソーシャルメディアアカウントの管理、マーケティングコンテンツおよび資料の作成、展示会やイベントの企画サポート、マーケティングキャンペーンのパフォーマンス分析', '2026-02-08 15:14:26', '2026-02-09 04:28:14');
INSERT INTO `job_openings_ko` (`id`, `master_id`, `title`, `description`, `requirements`, `responsibilities`, `created_at`, `updated_at`) VALUES
(1, 'job-001', '영업 관리자', '우리는 영국 영업팀을 이끌 경험이 풍부한 영업 매니저를 찾고 있으며, 오일과 왁스 분야의 비즈니스 성장을 추진할 수 있는 분을 모집하고 있습니다.', '[\"B2B 환경에서 5년 이상 영업 경력\", \"화학 또는 상품 산업 경험\", \"강력한 협상 및 관계 구축 능력\", \"경영 또는 관련 분야 학사 학위\"]', 'UK 판매팀을 이끌고 관리하며, 판매 전략을 개발하고 실행한다. 주요 고객과의 관계를 구축하고 유지하며, 분기별 및 연간 판매 목표를 달성한다.', '2026-02-06 05:39:48', '2026-02-09 04:26:00'),
(2, 'job-002', '품질 관리 기술자', '우리의 품질 팀에 합류하여 우리의 제품이 최고의 품질과 규정 준수 기준을 충족하도록 하세요.', '[\"화학 또는 관련 분야 학위\", \"QC 실험실에서 2년 이상 경력\", \"GMP 및 ISO 표준 지식\", \"세심한 주의력과 분석 능력\"]', '들어오는 자재와 완제품에 대한 품질 테스트 수행, 품질 문서 및 기록 유지, 품질 관리 절차의 시행 및 모니터링', '2026-02-08 15:06:48', '2026-02-09 04:26:52'),
(3, 'job-003', '창고 작업원', '오일 및 왁스 제품을 취급하는 물류팀에 합류할 신뢰할 수 있는 창고 운영자를 찾고 있습니다.', '[\"이전 창고 경험 우대\", \"지게차 운전 면허증 소지자 우대\", \"좋은 체력\", \"팀으로 근무할 능력\"]', '주문을 정확하게 선택하고 포장하기, 배송물 수령 및 점검하기, 창고를 깨끗하게 정리하고 정돈하기, 재고 점검을 도와주기', '2026-02-08 15:11:27', '2026-02-09 04:27:44'),
(4, 'job-004', '마케팅 코디네이터', '성장하는 비즈니스를 위한 디지털 캠페인 및 콘텐츠 제작으로 우리 마케팅 팀을 지원하세요.', '[\"소셜 미디어 마케팅 경험\", \"강력한 서면 커뮤니케이션 능력\", \"B2B 마케팅에 대한 이해\", \"창의적인 사고방식\"]', '소셜 미디어 계정을 관리하고, 마케팅 콘텐츠 및 자료를 제작하며, 무역 박람회와 이벤트 기획을 지원하고, 마케팅 캠페인 성과를 분석합니다.', '2026-02-08 15:15:29', '2026-02-09 04:28:27');
INSERT INTO `job_openings_pl` (`id`, `master_id`, `title`, `description`, `requirements`, `responsibilities`, `created_at`, `updated_at`) VALUES
(1, 'job-001', 'Kierownik Sprzedaży', 'Poszukujemy doświadczonego Menadżera Sprzedaży, który poprowadzi nasz zespół sprzedaży w Wielkiej Brytanii i napędzi rozwój biznesu w sektorze olejów i wosków.', '[\"Ponad 5 lat doświadczenia w sprzedaży w środowisku B2B\", \"Doświadczenie w branży chemicznej lub towarowej\", \"Silne umiejętności negocjacyjne i budowania relacji\", \"Tytuł licencjata w dziedzinie biznesu lub pokrewnej\"]', 'Prowadź i zarządzaj zespołem sprzedaży w Wielkiej Brytanii, Opracowuj i wdrażaj strategie sprzedażowe, Buduj i utrzymuj kluczowe relacje z klientami, Realizuj cele sprzedażowe kwartalne i roczne', '2026-02-06 05:41:06', '2026-02-09 04:26:13'),
(2, 'job-002', 'Technik Kontroli Jakości', 'Dołącz do naszego zespołu ds. jakości, aby zapewnić, że nasze produkty spełniają najwyższe standardy jakości i zgodności.', '[\"Dyplom z chemii lub pokrewnego kierunku\", \"ponad 2-letnie doświadczenie w laboratorium kontroli jakości\", \"Znajomość standardów GMP i ISO\", \"Dbałość o szczegóły i umiejętności analityczne\"]', 'Przeprowadzać testy jakości na przychodzących materiałach i wyrobach gotowych, Dbać o dokumentację i rejestry jakości, Wprowadzać i nadzorować procedury kontroli jakości', '2026-02-08 15:07:45', '2026-02-09 04:27:02'),
(3, 'job-003', 'Pracownik magazynu', 'Potrzebujemy niezawodnego Magazyniera, który dołączy do naszego zespołu logistyki obsługującego produkty olejowe i woski.', '[\"Wymagane doświadczenie w magazynie\", \"Prawo jazdy na wózek widłowy będzie atutem\", \"Dobra kondycja fizyczna\", \"Umiejętność pracy zespołowej\"]', 'Wybierz i spakuj zamówienia zgodnie z zamówieniem, Przyjmuj i sprawdzaj przychodzące dostawy, Utrzymuj czystość i porządek w magazynie, Pomagaj przy inwentaryzacjach stanów magazynowych', '2026-02-08 15:12:16', '2026-02-09 04:27:53'),
(4, 'job-004', 'Koordynator ds. Marketingu', 'Wesprzyj nasz zespół marketingowy, realizując kampanie cyfrowe i tworząc treści dla rozwijającego się biznesu.', '[\"Doświadczenie w marketingu w mediach społecznościowych\", \"Silne umiejętności komunikacji pisemnej\", \"Znajomość marketingu B2B\", \"Kreatywne myślenie\"]', 'Zarządzaj kontami w mediach społecznościowych, Twórz materiały marketingowe i collateral, Wspieraj planowanie targów i wydarzeń, Analizuj wyniki kampanii marketingowych', '2026-02-08 15:16:16', '2026-02-09 04:28:35');
INSERT INTO `job_openings_pt` (`id`, `master_id`, `title`, `description`, `requirements`, `responsibilities`, `created_at`, `updated_at`) VALUES
(1, 'job-001', 'Gerente de Vendas', 'Estamos procurando um Gerente de Vendas experiente para liderar nossa equipe de vendas no Reino Unido e impulsionar o crescimento dos negócios no setor de óleos e ceras.', '[\"Mais de 5 anos de experiência em vendas em ambiente B2B\", \"Experiência na indústria de produtos químicos ou commodities\", \"Fortes habilidades de negociação e construção de relacionamentos\", \"Graduação em Administração de Empresas ou área relacionada\"]', 'Liderar e gerenciar a equipe de vendas do Reino Unido, Desenvolver e implementar estratégias de vendas, Construir e manter relacionamentos com clientes-chave, Alcançar metas de vendas trimestrais e anuais', '2026-02-06 05:36:47', '2026-02-09 04:25:37'),
(2, 'job-002', 'Técnico de Controle de Qualidade', 'Junte-se à nossa equipe de qualidade para garantir que nossos produtos atendam aos mais altos padrões de qualidade e conformidade.', '[\"Graduação em Química ou área relacionada\", \"Mais de 2 anos de experiência em laboratório de Controle de Qualidade\", \"Conhecimento das normas GMP e ISO\", \"Atenção aos detalhes e habilidades analíticas\"]', 'Realizar testes de qualidade em materiais recebidos e produtos acabados, Manter documentação e registros de qualidade, Implementar e monitorar procedimentos de controle de qualidade', '2026-02-06 05:42:40', '2026-02-09 04:26:28'),
(3, 'job-003', 'Operador de Armazém', 'Precisamos de um Operador de Armazém confiável para se juntar à nossa equipe de logística lidando com óleos e produtos à base de cera.', '[\"Experiência anterior em armazém desejável\", \"Carteira de motorista para forklift vantagem\", \"Boa condição física\", \"Capacidade de trabalhar em equipe\"]', 'Selecionar e embalar pedidos com precisão, receber e verificar entregas recebidas, manter o armazém limpo e organizado, ajudar com contagens de estoque', '2026-02-08 15:09:10', '2026-02-09 04:27:17'),
(4, 'job-004', 'Coordenador de Marketing', 'Apoie nossa equipe de marketing com campanhas digitais e criação de conteúdo para o nosso negócio em crescimento.', '[\"Experiência com marketing em redes sociais\", \"Fortes habilidades de comunicação escrita\", \"Familiaridade com marketing B2B\", \"Mentalidade criativa\"]', 'Gerencie contas de mídia social, crie conteúdo e materiais de marketing, apoie o planejamento de feiras e eventos, analise o desempenho das campanhas de marketing', '2026-02-08 15:13:30', '2026-02-09 04:28:06');
INSERT INTO `job_openings_ru` (`id`, `master_id`, `title`, `description`, `requirements`, `responsibilities`, `created_at`, `updated_at`) VALUES
(1, 'job-001', 'Менеджер по продажам', 'Мы ищем опытного менеджера по продажам, чтобы возглавить нашу команду продаж в Великобритании и стимулировать развитие бизнеса в секторе масел и восков.', '[\"Более 5 лет опыта продаж в сфере B2B\", \"Опыт работы в химической или сырьевой промышленности\", \"Развитые навыки переговоров и построения отношений\", \"Бакалавр в области бизнеса или смежной дисциплины\"]', 'Руководить и управлять командой продаж в Великобритании, разрабатывать и реализовывать стратегии продаж, выстраивать и поддерживать ключевые отношения с клиентами, достигать квартальных и годовых планов по продажам', '2026-02-06 05:37:08', '2026-02-09 04:25:42'),
(2, 'job-002', 'Техник по контролю качества', 'Присоединяйтесь к нашей команде по качеству, чтобы гарантировать соответствие наших продуктов самым высоким стандартам качества и соблюдения требований.', '[\"Степень в области химии или смежной области\", \"более 2 лет опыта работы в лаборатории контроля качества\", \"знание стандартов GMP и ISO\", \"внимание к деталям и аналитические навыки\"]', 'Проведение проверки качества входных материалов и готовой продукции, ведение документации и записей о качестве, внедрение и контроль процедур управления качеством', '2026-02-06 05:43:01', '2026-02-09 04:26:32'),
(3, 'job-003', 'Складской работник', 'Нам нужен надежный работник склада для присоединения к нашей команде логистики, занимающейся маслами и восковыми продуктами.', '[\"Предпочтительный опыт работы на складе\", \"Преимущество наличия лицензии на погрузчик\", \"Хорошая физическая подготовка\", \"Умение работать в команде\"]', 'Точно отбирать и упаковывать заказы, принимать и проверять входящие поставки, поддерживать чистоту и порядок на складе, помогать с подсчётом запасов', '2026-02-08 15:09:30', '2026-02-09 04:27:20'),
(4, 'job-004', 'Координатор по маркетингу', 'Поддерживайте нашу маркетинговую команду в реализации цифровых кампаний и создании контента для нашего растущего бизнеса.', '[\"Опыт работы в маркетинге в социальных сетях\", \"Отличные навыки письменной коммуникации\", \"Знание маркетинга B2B\", \"Креативное мышление\"]', 'Управление аккаунтами в социальных сетях, создание маркетингового контента и материалов, поддержка планирования выставок и мероприятий, анализ эффективности маркетинговых кампаний', '2026-02-08 15:13:48', '2026-02-09 04:28:09');
INSERT INTO `job_openings_sw` (`id`, `master_id`, `title`, `description`, `requirements`, `responsibilities`, `created_at`, `updated_at`) VALUES
(1, 'job-001', 'Meneja wa Mauzo', 'Tuna tafuta Meneja wa Mauzo mwenye uzoefu kuongoza timu yetu ya mauzo ya UK na kueneza ukuaji wa biashara katika sekta ya mafuta na wax.', '[\"Miaka zaidi ya 5 ya uzoefu wa uuzaji katika mazingira ya B2B\", \"Uzoefu katika sekta ya kemikali au bidhaa za msingi\", \"Ujuzi wa kuhakikisha makubaliano na ujenzi wa mahusiano imara\", \"Digrii ya shahada ya kwanza katika Biashara au uwanja unaoendana\"]', 'Kiongozi na simamia timu ya mauzo ya UK, Kukuza na kutekeleza mikakati ya mauzo, Jenga na dortia mahusiano muhimu na wateja, Kupata malengo ya mauzo ya robo mwaka na mwaka mzima', '2026-02-06 05:38:40', '2026-02-09 04:25:51'),
(2, 'job-002', 'Mtaalamu wa Udhibiti wa Ubora', 'Jiunge na timu yetu ya ubora ili kuhakikisha bidhaa zetu zinakidhi viwango vya juu vya ubora na ufanisi.', '[\" Shahada ya Kemia au uwanja unaohusiana\", \"Miaka 2+ ya uzoefu katika maabara ya QC\", \"Ujuzi wa viwango vya GMP na ISO\", \"Umakini kwa undani na ujuzi wa uchambuzi\"]', 'Fanya mtihani wa ubora kwa malighali yanayokuja na bidhaa zilizokamilika, Thibitisha nyaraka na rekodi za ubora, Tekeleza na kufuatilia taratibu za kudhibiti ubora', '2026-02-06 05:44:09', '2026-02-09 04:26:43'),
(3, 'job-003', 'Fanyakazi wa Ghala', 'Tunahitaji Mfanyakazi wa Ghala anayeaminika kujiunga na timu yetu ya usafirishaji inayoendesha mafuta na bidhaa za wax.', '[\"Uzoefu wa ghala wa awali unahitajika\", \"Leseni ya forklift ni faida\", \"Uzito mzuri wa mwili\", \"Uwezo wa kufanya kazi kwa timu\"]', 'Chagua na paka maagizo kwa usahihi, Pokea na angalia usafirishaji unaoingia, Dumisha ghala safi na imepangwa vizuri, Saidia na hesabu za mali inapatikana', '2026-02-08 15:10:35', '2026-02-09 04:27:35'),
(4, 'job-004', 'Mshauri wa Masoko', 'Saidia timu yetu ya uuzaji na kampeni za kidigitali pamoja na uundaji wa maudhui kwa ajili ya biashara yetu inayokua.', '[\"Uzoefu na masoko ya mitandao ya kijamii\", \"Ujuzi wenye nguvu wa kuwasiliana kwa maandishi\", \" Ufahamifu na masoko ya B2B\", \"Mtazamo wa ubunifu\"]', 'Simamia akaunti za mitandao ya kijamii, Tengeneza maudhui na nyenzo za masoko, Saidia kupanga maonyesho ya biashara na matukio, Chambua utendaji wa kampeni za masoko', '2026-02-08 15:14:43', '2026-02-09 04:28:18');
INSERT INTO `job_openings_th` (`id`, `master_id`, `title`, `description`, `requirements`, `responsibilities`, `created_at`, `updated_at`) VALUES
(1, 'job-001', 'ผู้จัดการฝ่ายขาย', 'เรากำลังมองหา Sales Manager ที่มีประสบการณ์เพื่อเป็นผู้นำทีมขายในสหราชอาณาจักรของเรา และขับเคลื่อนการเติบโตทางธุรกิจในกลุ่มผลิตภัณฑ์น้ำมันและแว็กซ์', '[\"มีประสบการณ์ด้านการขายกว่า 5 ปีในสภาพแวดล้อม B2B\", \"มีความรู้ด้านอุตสาหกรรมเคมีหรือสินค้าโภคภัณฑ์\", \"ทักษะการเจรจาต่อรองและสร้างความสัมพันธ์ที่แข็งแกร่ง\", \"วุฒิการศึกษาปริญญาตรีด้านธุรกิจหรือสาขาที่เกี่ยวข้อง\"]', 'นำและบริหารทีมขายในสหราชอาณาจักร พัฒนาและดำเนินกลยุทธ์การขาย สร้างและรักษาความสัมพันธ์กับลูกค้าหลัก ให้บรรลุเป้าหมายยอดขายรายไตรมาสและรายปี', '2026-02-06 05:40:11', '2026-02-09 04:26:05'),
(2, 'job-002', 'เจ้าหน้าที่ควบคุมคุณภาพ', 'เข้าร่วมทีมคุณภาพของเราเพื่อให้แน่ใจว่าผลิตภัณฑ์ของเราสอดคล้องกับมาตรฐานคุณภาพและความเป็นไปตามกฎระเบียบสูงสุด', '[\"ปริญญาทางเคมีหรือสาขาที่เกี่ยวข้อง\", \"มีประสบการณ์ด้านห้องปฏิบัติการควบคุมคุณภาพอย่างน้อย 2 ปี\", \"ความรู้เกี่ยวกับมาตรฐาน GMP และ ISO\", \"ความละเอียดรอบคอบและทักษะวิเคราะห์\"]', 'ดำเนินการทดสอบคุณภาพวัสดุที่เข้ามาและผลิตภัณฑ์สำเร็จรูป รวมทั้งรักษาเอกสารและบันทึกคุณภาพ ดำเนินการและตรวจสอบกระบวนการควบคุมคุณภาพ', '2026-02-08 15:07:08', '2026-02-09 04:26:56'),
(3, 'job-003', 'พนักงานคลังสินค้า', 'เราต้องการพนักงานคลังสินค้าที่เชื่อถือได้เพื่อร่วมทีมโลจิสติกส์ของเราในการจัดการผลิตภัณฑ์น้ำมันและข wax', '[\"มีประสบการณ์คลังสินค้าก่อนหน้านี้จะพิจารณาเป็นพิเศษ\", \"ใบอนุญาตรถโฟลค์ลิฟต์เป็นข้อได้เปรียบ\", \"ร่างกายแข็งแรงดี\", \"ความสามารถในการทำงานร่วมกับทีม\"]', 'เลือกและบรรจุคำสั่งซื้อให้ถูกต้อง, รับและตรวจสอบการจัดส่งสินค้าเข้า, รักษาคลังสินค้าให้สะอาดและเป็นระเบียบ, ช่วยในการนับสต็อก', '2026-02-08 15:11:44', '2026-02-09 04:27:46'),
(4, 'job-004', 'ผู้ประสานงานการตลาด', 'สนับสนุนทีมการตลาดของเราในการดำเนินแคมเปญดิจิทัลและการสร้างเนื้อหาเพื่อการเติบโตของธุรกิจของเรา', '[\"ประสบการณ์ด้านการตลาดผ่านโซเชียลมีเดีย\", \"ทักษะการเขียนที่แข็งแกร่ง\", \"คุ้นเคยกับการตลาด B2B\", \"แนวคิดสร้างสรรค์\"]', 'จัดการบัญชีโซเชียลมีเดีย, สร้างเนื้อหาและวัสดุการตลาด, สนับสนุนการวางแผนงานแสดงสินค้าและกิจกรรม, วิเคราะห์ผลการดำเนินแคมเปญการตลาด', '2026-02-08 15:15:48', '2026-02-09 04:28:30');
INSERT INTO `job_openings_tr` (`id`, `master_id`, `title`, `description`, `requirements`, `responsibilities`, `created_at`, `updated_at`) VALUES
(1, 'job-001', 'Satış Müdürü', 'Birleşik Krallık satış ekibimizi yönetecek ve yağlar ile mumlar sektöründe iş büyütmeyi sağlayacak deneyimli bir Satış Müdürü arıyoruz.', '[\"B2B ortamında 5+ yıl satış deneyimi\", \"Kimya veya emtia sektöründe deneyim\", \"Güçlü müzakere ve ilişki kurma becerileri\", \"İşletme veya ilgili alanda lisans derecesi\"]', 'İngiltere satış ekibini liderlik ve yönetmek, satış stratejileri geliştirmek ve uygulamak, önemli müşteri ilişkileri kurmak ve sürdürmek, üç aylık ve yıllık satış hedeflerini karşılamak', '2026-02-06 05:39:02', '2026-02-09 04:25:54'),
(2, 'job-002', 'Kalite Kontrol Teknisyeni', 'Kalite ekibimize katılarak ürünlerimizin en yüksek kalite ve uyum standartlarına uygun olmasını sağlayın.', '[\"Kimya veya ilgili alanlarda lisans derecesi\", \"Kalite kontrol laboratuvarında 2+ yıl deneyim\", \"GMP ve ISO standartları bilgisi\", \"Detaylara dikkat ve analitik beceriler\"]', 'Gelen malzemeler ve bitmiş ürünler üzerinde kalite testi yapın, kalite dokümantasyonu ve kayıtlarını tutun, kalite kontrol prosedürlerini uygulayın ve izleyin', '2026-02-06 05:44:31', '2026-02-09 04:26:45'),
(3, 'job-003', 'Depo Operatörü', 'Yağlar ve mum ürünleriyle çalışan lojistik ekibimize katılacak güvenilir bir Depo Operatörü gerekiyor.', '[\"Önceki depolama deneyimi tercih edilir\", \"Forklift ehliyeti avantaj sağlar\", \"İyi fiziksel kondisyon\", \"Takım içinde çalışma yeteneği\"]', 'Siparişleri doğru şekilde seçip paketleyin, gelen teslimatları alın ve kontrol edin, depoyu temiz ve düzenli tutun, stok sayımlarına yardımcı olun', '2026-02-08 15:10:54', '2026-02-09 04:27:38'),
(4, 'job-004', 'Pazarlama Koordinatörü', 'Büyüyen işletmemiz için dijital kampanyalar ve içerik oluşturmayla pazarlama ekibimize destek olun.', '[\"Sosyal medya pazarlama deneyimi\", \"Güçlü yazılı iletişim becerileri\", \"B2B pazarlama konusunda aşinalık\", \"Yaratıcı düşünce yapısı\"]', 'Sosyal medya hesaplarını yönetin, pazarlama içerikleri ve malzemeleri oluşturun, ticaret fuarı ve etkinlik planlamasına destek olun, pazarlama kampanyası performansını analiz edin', '2026-02-08 15:14:57', '2026-02-09 04:28:21');
INSERT INTO `job_openings_vi` (`id`, `master_id`, `title`, `description`, `requirements`, `responsibilities`, `created_at`, `updated_at`) VALUES
(1, 'job-001', 'Quản lý doanh số', 'Chúng tôi đang tìm kiếm một Quản lý Bán hàng có kinh nghiệm để lãnh đạo đội ngũ bán hàng tại Vương quốc Anh và thúc đẩy sự phát triển kinh doanh trong lĩnh vực dầu và sáp.', '[\"Hơn 5 năm kinh nghiệm bán hàng trong môi trường B2B\", \"Kinh nghiệm trong ngành công nghiệp hóa chất hoặc hàng hóa\", \"Kỹ năng đàm phán và xây dựng mối quan hệ vững chắc\", \"Bằng cử nhân Quản trị kinh doanh hoặc lĩnh vực liên quan\"]', 'Dẫn dắt và quản lý nhóm bán hàng tại Vương quốc Anh, Phát triển và thực hiện các chiến lược bán hàng, Xây dựng và duy trì các mối quan hệ khách hàng chính, Đạt các mục tiêu doanh số theo quý và hàng năm', '2026-02-06 05:39:27', '2026-02-09 04:25:57'),
(2, 'job-002', 'Kỹ thuật viên kiểm soát chất lượng', 'Tham gia đội ngũ chất lượng của chúng tôi để đảm bảo sản phẩm của chúng tôi đáp ứng các tiêu chuẩn cao nhất về chất lượng và sự tuân thủ.', '[\"Bằng Cử nhân Hóa học hoặc lĩnh vực liên quan\", \"Hơn 2 năm kinh nghiệm làm việc tại phòng thí nghiệm QC\", \"Hiểu biết về tiêu chuẩn GMP và ISO\", \"Chú ý đến từng chi tiết và kỹ năng phân tích\"]', 'Thực hiện kiểm tra chất lượng vật liệu đầu vào và thành phẩm, Duy trì hồ sơ và tài liệu về chất lượng, Thực hiện và giám sát các quy trình kiểm soát chất lượng', '2026-02-08 15:06:33', '2026-02-09 04:26:49'),
(3, 'job-003', 'Nhân viên kho', 'Chúng tôi cần một Nhân viên Kho hàng đáng tin cậy gia nhập đội ngũ logistics của chúng tôi để xử lý các sản phẩm dầu và sáp.', '[\"Ưu tiên có kinh nghiệm kho trước đó\", \"Có chứng chỉ vận hành xe nâng là lợi thế\", \"Sức khỏe tốt\", \"Khả năng làm việc nhóm\"]', 'Chọn và đóng gói đơn hàng chính xác, Nhận và kiểm tra các lô hàng nhập, Duy trì kho hàng sạch sẽ và ngăn nắp, Hỗ trợ kiểm kê kho hàng', '2026-02-08 15:11:09', '2026-02-09 04:27:41'),
(4, 'job-004', 'Điều phối viên Marketing', 'Hỗ trợ nhóm tiếp thị của chúng tôi trong các chiến dịch kỹ thuật số và tạo nội dung cho doanh nghiệp đang phát triển của chúng tôi.', '[\"Kinh nghiệm về marketing trên mạng xã hội\", \"Kỹ năng viết lách tốt\", \"Quen thuộc với marketing B2B\", \"Tư duy sáng tạo\"]', 'Quản lý các tài khoản mạng xã hội, Tạo nội dung và tài liệu marketing, Hỗ trợ lập kế hoạch hội chợ thương mại và sự kiện, Phân tích hiệu quả chiến dịch marketing', '2026-02-08 15:15:13', '2026-02-09 04:28:24');
INSERT INTO `job_openings_zh` (`id`, `master_id`, `title`, `description`, `requirements`, `responsibilities`, `created_at`, `updated_at`) VALUES
(1, 'job-001', '销售经理', '我们正在寻找一位具有丰富经验的销售经理，领导我们的英国销售团队，推动油品和蜡类行业的业务增长。', '[\"在B2B环境中具有5年以上销售经验\", \"化工或大宗商品行业经验\", \"优秀的谈判和关系建立能力\", \"商业或相关专业学士学位\"]', '领导并管理英国销售团队，制定并执行销售策略，建立并维护重要客户关系，达成季度和年度销售目标', '2026-02-06 05:35:18', '2026-02-09 04:25:23'),
(2, 'job-002', '质量控制技术员', '加入我们的质量团队，确保我们的产品达到最高的质量和合规标准。', '[化学或相关专业学士学位，2年以上QC实验室工作经验，熟悉GMP和ISO标准，注重细节与分析能力]', '对进货材料和成品进行质量检测，维护质量文件和记录，实施并监控质量控制程序', '2026-02-06 05:41:19', '2026-02-09 04:26:16'),
(3, 'job-003', '仓库操作员', '我们需要一名可靠的仓库操作员加入我们的物流团队，负责油类和蜡类产品的处理。', '[\"具有仓库经验者优先\", \"持叉车证者优先\", \"身体健康良好\", \"具备团队合作能力\"]', '准确挑选和打包订单，接收并检查到货，保持仓库整洁有序，协助盘点库存', '2026-02-08 15:08:00', '2026-02-09 04:27:05'),
(4, 'job-004', '市场营销协调员', '协助我们的营销团队进行数字营销活动和内容创作，以支持我们不断增长的业务。', '[\"社交媒体营销经验\", \"出色的书面沟通能力\", \"熟悉B2B营销\", \"富有创造力的思维\"]', '管理社交媒体账号，创建市场营销内容和宣传资料，支持展会和活动策划，分析市场推广活动的效果', '2026-02-08 15:12:34', '2026-02-09 04:27:55');
INSERT INTO `newsletter_subscribers` (`id`, `email`, `subscribed_at`, `ip_address`, `source`) VALUES
('57108f6e-ba31-4372-97af-76fa9f38a4cf', 'test@example.com', '2026-02-09 18:04:36', '127.0.0.1', 'website_footer'),
('e45772a4-59ce-4f68-be84-34f134c4dc65', 'test2@biogreenwax.com', '2026-02-09 18:04:42', '127.0.0.1', 'website_footer');
INSERT INTO `news_articles` (`id`, `title`, `slug`, `excerpt`, `content`, `image_url`, `is_published`, `synchronized_data`, `published_at`, `created_at`) VALUES
('news-001', 'Bio Green Wax Expands Product Range', 'bio-green-wax-expands-product-range', 'We are excited to announce the expansion of our natural oils and waxes product range.', 'Bio Green Wax Ltd is pleased to announce a significant expansion of our product portfolio. Following customer demand and market research, we have added several new natural oils and specialty waxes to our catalogue in 2026. These new products cater to the growing cosmetics and candle-making industries, offering superior quality and competitive pricing. Contact our sales team for more information about our expanded range.', NULL, 1, 1, '2026-02-11 17:55:44', '2026-02-05 21:03:49'),
('news-002', 'New RSPO Certification Achieved', 'new-rspo-certification-achieved', 'Bio Green Wax is proud to announce our RSPO Mass Balance certification for sustainable palm oil products.', 'We are delighted to announce that Bio Green Wax Ltd has achieved RSPO Mass Balance certification for our palm wax and palm oil products. This certification demonstrates our commitment to sustainable sourcing and responsible supply chain management. The Roundtable on Sustainable Palm Oil (RSPO) is the leading global certification scheme for sustainable palm oil. Our customers can now be confident that our palm-derived products meet the highest standards of sustainability.', NULL, 1, 1, '2026-01-29 21:03:49', '2026-02-05 21:03:49'),
('news-003', 'Trade Show Success at UK Candle Expo', 'trade-show-success-uk-candle-expo', 'Thank you to everyone who visited our stand at the UK Candle Expo 2026. It was great to meet so many candle makers!', 'The Bio Green Wax team had a fantastic time at the UK Candle Expo 2026 held in Birmingham last week. We showcased our complete range of candle waxes including our popular palm wax, soy wax, and paraffin wax products. It was wonderful to meet both existing customers and new faces in the candle making community. We received excellent feedback on our new crystallized palm wax range, which creates stunning visual effects in candles. If you missed us at the show, please get in touch to request samples.', NULL, 1, 1, '2026-01-22 21:03:49', '2026-02-05 21:03:49'),
('news-004', 'Introducing Our New Wax Blend Range', 'introducing-new-wax-blend-range', 'We are excited to launch our new range of custom wax blends designed for specific candle making applications.', 'After extensive research and development, Bio Green Wax is proud to introduce our new range of wax blends. These carefully formulated blends combine the best properties of different wax types to achieve optimal performance for specific applications. The new range includes blends optimized for container candles, pillar candles, and wax melts. Each blend has been tested extensively to ensure excellent scent throw, clean burning, and easy demoulding. Contact our sales team for samples and technical specifications.', NULL, 1, 1, '2026-01-15 21:03:49', '2026-02-05 21:03:49'),
('news-005', 'Sustainability Report 2025 Published', 'sustainability-report-2025', 'Our annual sustainability report highlights our progress towards carbon neutrality and sustainable sourcing goals.', 'Bio Green Wax Ltd has published our 2025 Sustainability Report, outlining our environmental initiatives and progress towards our 2030 sustainability goals. Key highlights include a 15% reduction in carbon emissions compared to 2024, 100% renewable electricity at our main warehouse, and increased sourcing of RSPO certified palm products. We remain committed to transparency and continuous improvement in our environmental performance. The full report is available on request from our customer service team.', NULL, 0, 1, NULL, '2026-02-05 21:03:49');
INSERT INTO `news_articles_ar` (`id`, `master_id`, `title`, `excerpt`, `content`, `created_at`, `updated_at`) VALUES
(1, 'news-001', 'شركة Bio Green Wax توسع مجموعة منتجاتها', 'نحن متحمسون للإعلان عن توسيع مجموعة منتجاتنا من الزيوت الطبيعية والشموع.', 'تتشرف شركة Bio Green Wax Ltd بالإعلان عن توسعة كبيرة لمحفظة منتجاتنا. استجابةً لطلبات العملاء وبحث السوق، أضفنا العديد من الزيوت الطبيعية والشموع الخاصة إلى كتالوجنا لعام 2026. تلبي هذه المنتجات الجديدة احتياجات صناعة مستحضرات التجميل وإنتاج الشموع المتزايدة، مع تقديم جودة فائقة وأسعار تنافسية. تواصل مع فريق المبيعات لدينا لمزيد من المعلومات حول تشكيلتنا الموسعة.', '2026-02-06 05:08:02', '2026-02-11 18:17:59'),
(2, 'news-002', 'تم الحصول على شهادة RSPO جديدة', 'تفتخر Bio Green Wax بالإعلان عن حصولها على شهادة RSPO Mass Balance لمنتجات زيت النخيل المستدامة.', 'يسعدنا أن نعلن أن شركة Bio Green Wax Ltd حصدت شهادة تعادل الكتلة لمجموعة RSPO لمنتجات شمع النخيل وزيت النخيل الخاصة بنا. تُظهر هذه الشهادة التزامنا بتوريد مستدام وإدارة سلسلة التوريد بمسؤولية. تُعد الجمعية المستديرة بشأن زيت النخيل المستدام (RSPO) البرنامج العالمي الرائد لشهادات زيت النخيل المستدام. يمكن لعملائنا الآن أن يكونوا واثقين من أن منتجاتنا المستخرجة من النخيل تلبي أعلى معايير الاستدامة.', '2026-02-06 05:13:07', '2026-02-09 04:29:44'),
(3, 'news-003', 'نجاح معرض التجارة في معرض الشموع البريطاني', 'شكرًا لكل من زار جناحنا في معرض الشموع في المملكة المتحدة 2026. كان من الرائع مقابلة العديد من صانعي الشموع!', 'قام فريق Bio Green Wax بوقت رائع في معرض الشموع في المملكة المتحدة 2026 الذي أقيم في برمنغهام الأسبوع الماضي. عرضنا مجموعتنا الكاملة من شمع الشموع بما في ذلك شمع النخيل الشائع، وشمع الصويا، وشمع البارافين. كان من الرائع لقاء العملاء الحاليين ووجوه جديدة في مجتمع صناعة الشموع. تلقينا تعليقات ممتازة على مجموعة شمع النخيل البلوري الجديدة، التي تخلق تأثيرات بصرية مذهلة في الشموع. إذا فاتك لقاؤنا في المعرض، يرجى التواصل معنا لطلب عينات.', '2026-02-06 05:19:11', '2026-02-09 04:30:20'),
(4, 'news-004', 'تقديم مجموعتنا الجديدة من مزيج الشموع', 'نحن متحمسون لإطلاق مجموعتنا الجديدة من خلطات الشموع المخصصة المصممة لتطبيقات صنع الشموع المحددة.', 'بعد بحث وتطوير موسعين، تفخر Bio Green Wax بتقديم مجموعتنا الجديدة من خلائط الشموع الشمعية. تجمع هذه الخلائط المصممة بعناية بين أفضل خصائص أنواع الشمع المختلفة لتحقيق الأداء الأمثل للاستخدامات المحددة. تتضمن المجموعة الجديدة خلائط محسّنة لشموع الحاويات، والشموع الأعمدة، وقطرات الشمع. لقد تم اختبار كل خلطة بشكل مكثف لضمان انتشار الرائحة بشكل ممتاز، واحتراق نظيف، وسهولة إخراج الشمع من القالب. تواصل مع فريق المبيعات لدينا للحصول على عينات والمواصفات التقنية.', '2026-02-06 05:24:54', '2026-02-09 04:30:59'),
(5, 'news-005', 'تم نشر تقرير الاستدامة لعام 2025', 'تسلط تقريرنا السنوي حول الاستدامة الضوء على تقدمنا نحو الحياد الكربوني وأهداف التوريد المستدام.', 'شركة Bio Green Wax المحدودة نشرت تقرير الاستدامة لعام 2025، موضحة مبادراتها البيئية وتقدمها نحو أهداف الاستدامة لعام 2030. تتضمن النقاط الرئيسية تقليل انبعاثات الكربون بنسبة 15% مقارنة بعام 2024، واستخدام الكهرباء المتجددة بنسبة 100% في مستودعنا الرئيسي، وزيادة مصادر منتجات نخيل شجرة زيت النخيل المعتمدة من RSPO. نلتزم بالشفافية والتحسين المستمر في أدائنا البيئي. التقرير الكامل متاح عند الطلب من فريق خدمة العملاء لدينا.', '2026-02-06 05:31:02', '2026-02-09 04:31:39');
INSERT INTO `news_articles_de` (`id`, `master_id`, `title`, `excerpt`, `content`, `created_at`, `updated_at`) VALUES
(1, 'news-001', 'Bio Green Wax erweitert sein Produktangebot', 'Wir freuen uns, die Erweiterung unserer Produktpalette an natürlichen Ölen und Wachsen bekannt zu geben.', 'Bio Green Wax Ltd freut sich, eine bedeutende Erweiterung unseres Produktportfolios bekannt zu geben. Im Zuge der Kundennachfrage und Marktanalyse haben wir im Jahr 2026 mehrere neue natürlichen Öle und Spezialwachse in unseren Katalog aufgenommen. Diese neuen Produkte richten sich an die wachsenden Kosmetik- und Kerzenherstellungsindustrien und bieten erstklassige Qualität zu wettbewerbsfähigen Preisen. Kontaktieren Sie unser Vertriebsteam für weitere Informationen über unser erweitertes Angebot.', '2026-02-06 05:08:53', '2026-02-11 18:18:08'),
(2, 'news-002', 'Neue RSPO-Zertifizierung erreicht', 'Bio Green Wax freut sich, unsere RSPO-Massenbilanz-Zertifizierung für nachhaltige Palmölprodukte bekannt zu geben.', 'Wir freuen uns, bekannt geben zu können, dass Bio Green Wax Ltd die RSPO-Mass Balance-Zertifizierung für unsere Palmenwachs- und Palmölprodukte erhalten hat. Diese Zertifizierung zeigt unser Engagement für nachhaltige Beschaffung und verantwortungsbewusstes Lieferkettenmanagement. Die Roundtable on Sustainable Palm Oil (RSPO) ist das weltweit führende Zertifizierungssystem für nachhaltiges Palmöl. Unsere Kunden können nun sicher sein, dass unsere palmabgeleiteten Produkte die höchsten Nachhaltigkeitsstandards erfüllen.', '2026-02-06 05:14:12', '2026-02-09 04:29:51'),
(3, 'news-003', 'Erfolg bei der Messe auf dem UK Candle Expo', 'Vielen Dank an alle, die unseren Stand auf der UK Candle Expo 2026 besucht haben. Es war großartig, so viele Kerzenhersteller kennenzulernen!', 'Das Bio Green Wax Team hatte eine großartige Zeit auf der UK Candle Expo 2026, die letzte Woche in Birmingham stattfand. Wir präsentierten unser gesamtes Sortiment an Kerzenwachsen, darunter unser beliebtes Palmenwachs, Sojawachs und Paraffinwachs. Es war wunderbar, sowohl bestehende Kunden als auch neue Gesichter in der Kerzenmanufaktur-Community kennenzulernen. Wir erhielten hervorragendes Feedback zu unserer neuen kristallisierten Palmenwachs-Reihe, die atemberaubende visuelle Effekte in Kerzen erzeugt. Wenn Sie uns auf der Messe verpasst haben, nehmen Sie bitte Kontakt auf, um Muster anzufordern.', '2026-02-06 05:20:14', '2026-02-09 04:30:28'),
(4, 'news-004', 'Einführung unserer neuen Wachsmischungslinie', 'Wir freuen uns, unsere neue Reihe maßgeschneiderter Wachsblends vorzustellen, die speziell für bestimmte Kerzenherstellungsanwendungen entwickelt wurden.', 'Nach umfangreicher Forschung und Entwicklung ist Bio Green Wax stolz darauf, unsere neue Produktlinie von Wachsmischungen vorzustellen. Diese sorgfältig formulierten Mischungen vereinen die besten Eigenschaften verschiedener Wachsarten, um eine optimale Leistung für spezifische Anwendungen zu erzielen. Die neue Reihe umfasst Mischungen, die für Containerkerzen, Säulenkerzen und Wachsziele optimiert sind. Jede Mischung wurde umfassend getestet, um eine ausgezeichnete Duftabstrahlung, sauberes Brennen und einfaches Entformen zu gewährleisten. Kontaktieren Sie unser Verkaufsteam für Muster und technische Spezifikationen.', '2026-02-06 05:26:04', '2026-02-09 04:31:07'),
(5, 'news-005', 'Veröffentlichung des Nachhaltigkeitsberichts 2025', 'Unser jährlicher Nachhaltigkeitsbericht hebt unsere Fortschritte bei der Erreichung von Kohlenstoffneutralität und nachhaltigen Beschaffungszielen hervor.', 'Bio Green Wax Ltd hat unseren Nachhaltigkeitsbericht 2025 veröffentlicht, in dem unsere Umweltinitiativen und der Fortschritt bei der Erreichung unserer Nachhaltigkeitsziele für 2030 dargestellt sind. Zu den wichtigsten Highlights gehören eine 15%ige Reduzierung der CO₂-Emissionen im Vergleich zu 2024, 100% erneuerbarer Strom in unserem Hauptlager und eine verstärkte Beschaffung von RSPO-zertifizierten Palmprodukten. Wir bleiben unserem Engagement für Transparenz und kontinuierliche Verbesserung unserer Umweltbilanz treu. Der vollständige Bericht ist auf Anfrage bei unserem Kundenservice-Team erhältlich.', '2026-02-06 05:32:03', '2026-02-09 04:31:46');
INSERT INTO `news_articles_es` (`id`, `master_id`, `title`, `excerpt`, `content`, `created_at`, `updated_at`) VALUES
(1, 'news-001', 'Bio Green Wax amplía su gama de productos', 'Estamos emocionados de anunciar la ampliación de nuestra gama de productos de aceites y ceras naturales.', 'Bio Green Wax Ltd se complace en anunciar una expansión significativa de nuestro portafolio de productos. Siguiendo la demanda de los clientes y la investigación de mercado, hemos añadido varios aceites naturales y ceras especiales a nuestro catálogo en 2026. Estos nuevos productos atienden a las crecientes industrias de cosméticos y fabricación de velas, ofreciendo calidad superior y precios competitivos. Contacte a nuestro equipo de ventas para obtener más información sobre nuestra gama ampliada.', '2026-02-06 05:07:23', '2026-02-11 18:17:52'),
(2, 'news-002', 'Nueva certificación RSPO lograda', 'Bio Green Wax se enorgullece en anunciar nuestra certificación RSPO de Balance en Masa para productos de aceite de palma sostenibles.', 'Estamos encantados de anunciar que Bio Green Wax Ltd ha obtenido la certificación RSPO Mass Balance para nuestros productos de cera de palma y aceite de palma. Esta certificación demuestra nuestro compromiso con una obtención sostenible y una gestión responsable de la cadena de suministro. La Mesa Redonda sobre Aceite de Palma Sostenible (RSPO) es el principal esquema de certificación global para el aceite de palma sostenible. Nuestros clientes pueden estar ahora seguros de que nuestros productos derivados de la palma cumplen con los más altos estándares de sostenibilidad.', '2026-02-06 05:12:19', '2026-02-09 04:29:39'),
(3, 'news-003', 'Éxito en ferias comerciales en UK Candle Expo', '¡Gracias a todos los que visitaron nuestro stand en la UK Candle Expo 2026. ¡Fue genial conocer a tantos fabricantes de velas!', 'El equipo de Bio Green Wax disfrutó muchísimo en la UK Candle Expo 2026 celebrada en Birmingham la semana pasada. Mostramos nuestra gama completa de ceras para velas, incluyendo nuestro popular cera de palma, cera de soja y cera de parafina. Fue maravilloso conocer tanto a clientes existentes como a nuevas caras en la comunidad de fabricación de velas. Recibimos excelentes comentarios sobre nuestra nueva gama de cera de palma cristalizada, que crea impresionantes efectos visuales en las velas. Si te perdiste nuestro stand en la feria, no dudes en ponerte en contacto con nosotros para solicitar muestras.', '2026-02-06 05:18:33', '2026-02-09 04:30:16'),
(4, 'news-004', 'Presentamos nuestra nueva gama de mezclas de cera', 'Estamos emocionados de lanzar nuestra nueva gama de mezclas de cera personalizadas diseñadas para aplicaciones específicas de fabricación de velas.', 'Después de una extensa investigación y desarrollo, Bio Green Wax se enorgullece en presentar nuestra nueva gama de mezclas de cera. Estas mezclas cuidadosamente formuladas combinan las mejores propiedades de diferentes tipos de cera para lograr un rendimiento óptimo en aplicaciones específicas. La nueva gama incluye mezclas optimizadas para velas en recipiente, velas de pilar y melts de cera. Cada mezcla ha sido sometida a pruebas exhaustivas para garantizar una excelente proyección de aroma, una combustión limpia y un desmoldeo fácil. Póngase en contacto con nuestro equipo de ventas para obtener muestras y especificaciones técnicas.', '2026-02-06 05:24:01', '2026-02-09 04:30:53'),
(5, 'news-005', 'Informe de Sostenibilidad 2025 Publicado', 'Nuestro informe anual de sostenibilidad destaca nuestro progreso hacia la neutralidad de carbono y los objetivos de abastecimiento sostenible.', 'Bio Green Wax Ltd ha publicado nuestro Informe de Sostenibilidad 2025, que detalla nuestras iniciativas medioambientales y los avances hacia nuestras metas de sostenibilidad para 2030. Los aspectos más destacados incluyen una reducción del 15% en las emisiones de carbono en comparación con 2024, electricidad 100% renovable en nuestro almacén principal y un aumento en la adquisición de productos de palma certificados por RSPO. Continuamos comprometidos con la transparencia y la mejora continua en nuestro desempeño ambiental. El informe completo está disponible a solicitud de nuestro equipo de atención al cliente.', '2026-02-06 05:30:19', '2026-02-09 04:31:34');
INSERT INTO `news_articles_fr` (`id`, `master_id`, `title`, `excerpt`, `content`, `created_at`, `updated_at`) VALUES
(1, 'news-001', 'Bio Green Wax Élargit sa Gamme de Produits', 'Nous sommes ravis d\'annoncer l\'élargissement de notre gamme de produits d\'huiles naturelles et de cires.', 'Bio Green Wax Ltd a le plaisir d\'annoncer une expansion majeure de notre portefeuille de produits. Suite à la demande des clients et à des études de marché, nous avons ajouté plusieurs nouvelles huiles naturelles et cires spéciales à notre catalogue en 2026. Ces nouveaux produits répondent aux industries croissantes des cosmétiques et de la fabrication de bougies, offrant une qualité supérieure et des prix compétitifs. Contactez notre équipe commerciale pour plus d\'informations sur notre gamme élargie.', '2026-02-06 05:07:33', '2026-02-11 18:17:55'),
(2, 'news-002', 'Certification RSPO nouvelle obtenue', 'Bio Green Wax est fier d\'annoncer notre certification RSPO Mass Balance pour des produits d\'huile de palme durables.', 'Nous sommes ravis d\'annoncer que Bio Green Wax Ltd a obtenu la certification RSPO Mass Balance pour nos produits en cire de palme et en huile de palme. Cette certification témoigne de notre engagement en faveur d\'une approvisionnement durable et d\'une gestion responsable de la chaîne d\'approvisionnement. La Roundtable on Sustainable Palm Oil (RSPO) est le principal référentiel mondial pour la certification de l\'huile de palme durable. Nos clients peuvent désormais être assurés que nos produits dérivés de la palme respectent les normes les plus strictes en matière de durabilité.', '2026-02-06 05:12:43', '2026-02-09 04:29:41'),
(3, 'news-003', 'Réussite lors du salon professionnel au UK Candle Expo', 'Merci à tous ceux qui ont visité notre stand lors du UK Candle Expo 2026. Ce fut un plaisir de rencontrer autant de fabricants de bougies !', 'L\'équipe Bio Green Wax a passé un moment fantastique lors de l\'UK Candle Expo 2026 qui s\'est tenu à Birmingham la semaine dernière. Nous avons présenté notre gamme complète de cires pour bougies, y compris notre populaire cire de palme, cire de soja et cire de paraffine. Ce fut un plaisir de rencontrer à la fois nos clients fidèles et de nouvelles personnes dans la communauté de la fabrication de bougies. Nous avons reçu d\'excellents retours concernant notre nouvelle gamme de cire de palme cristallisée, qui crée des effets visuels spectaculaires dans les bougies. Si vous nous avez manqué lors du salon, n\'hésitez pas à nous contacter pour demander des échantillons.', '2026-02-06 05:18:51', '2026-02-09 04:30:18'),
(4, 'news-004', 'Présentation de notre nouvelle gamme de mélanges de cires', 'Nous sommes ravis de lancer notre nouvelle gamme de mélanges de cires personnalisés conçus pour des applications spécifiques de fabrication de bougies.', 'Après de vastes recherches et développements, Bio Green Wax a le plaisir de présenter sa nouvelle gamme de mélanges de cires. Ces mélanges soigneusement formulés combinent les meilleures propriétés de différents types de cire pour atteindre des performances optimales pour des applications spécifiques. La nouvelle gamme comprend des mélanges optimisés pour bougies en verre, bougies de type pillar, et cires à faire fondre. Chaque mélange a été testé de manière approfondie pour garantir une excellente diffusion du parfum, une combustion propre et un démoulage facile. Contactez notre équipe commerciale pour des échantillons et des spécifications techniques.', '2026-02-06 05:24:26', '2026-02-09 04:30:56'),
(5, 'news-005', 'Rapport sur la durabilité 2025 publié', 'Notre rapport annuel sur la durabilité met en lumière nos progrès vers la neutralité carbone et nos objectifs d\'approvisionnement durable.', 'Bio Green Wax Ltd a publié notre Rapport de Durabilité 2025, décrivant nos initiatives environnementales et nos progrès vers nos objectifs de durabilité pour 2030. Parmi les points clés, une réduction de 15 % des émissions de carbone par rapport à 2024, 100 % d\'électricité renouvelable dans notre entrepôt principal, et une augmentation de l\'approvisionnement en produits de palme certifiés RSPO. Nous restons engagés en faveur de la transparence et de l\'amélioration continue de notre performance environnementale. Le rapport complet est disponible sur demande auprès de notre service client.', '2026-02-06 05:30:43', '2026-02-09 04:31:36');
INSERT INTO `news_articles_it` (`id`, `master_id`, `title`, `excerpt`, `content`, `created_at`, `updated_at`) VALUES
(1, 'news-001', 'Bio Green Wax amplia la gamma di prodotti', 'Siamo entusiasti di annunciare l’espansione della nostra gamma di oli naturali e cere.', 'Bio Green Wax Ltd è lieta di annunciare una significativa espansione del nostro portafoglio prodotti. In seguito alla domanda dei clienti e alle ricerche di mercato, nel 2026 abbiamo aggiunto diversi nuovi oli naturali e cere speciali al nostro catalogo. Questi nuovi prodotti soddisfano le esigenze crescenti delle industrie cosmetiche e della produzione di candele, offrendo qualità superiore e prezzi competitivi. Contatta il nostro team commerciale per ulteriori informazioni sulla nostra gamma ampliata.', '2026-02-06 05:11:27', '2026-02-11 18:18:31'),
(2, 'news-002', 'Nuova Certificazione RSPO Raggiunta', 'Bio Green Wax è orgogliosa di annunciare la nostra certificazione RSPO Mass Balance per prodotti di olio di palma sostenibile.', 'Siamo lieti di annunciare che Bio Green Wax Ltd ha ottenuto la certificazione RSPO Mass Balance per i nostri prodotti a base di cera di palma e olio di palma. Questa certificazione dimostra il nostro impegno per un sourcing sostenibile e una gestione responsabile della catena di approvvigionamento. La Roundtable on Sustainable Palm Oil (RSPO) è il principale schema di certificazione globale per l\'olio di palma sostenibile. I nostri clienti possono ora essere certi che i nostri prodotti derivati dalla palma rispettano i più alti standard di sostenibilità.', '2026-02-06 05:17:15', '2026-02-09 04:30:08'),
(3, 'news-003', 'Successo alla fiera al UK Candle Expo', 'Grazie a tutti coloro che sono passati al nostro stand al UK Candle Expo 2026. È stato fantastico conoscere così tanti produttori di candele!', 'Il team di Bio Green Wax ha trascorso un periodo fantastico al UK Candle Expo 2026, tenutosi a Birmingham la settimana scorsa. Abbiamo presentato la nostra gamma completa di cere per candele, tra cui i nostri popolari cera di palma, cera di soia e cera di paraffina. È stato meraviglioso incontrare sia clienti già affermati sia nuove persone nella comunità degli artigiani delle candele. Abbiamo ricevuto feedback eccellenti sulla nostra nuova linea di cera di palma cristallizzata, che crea effetti visivi sorprendenti nelle candele. Se non sei riuscito a trovarci alla fiera, contattaci pure per richiedere dei campioni.', '2026-02-06 05:22:55', '2026-02-09 04:30:46'),
(4, 'news-004', 'Presentiamo la nostra nuova gamma di miscele di cera', 'Siamo entusiasti di lanciare la nostra nuova gamma di miscele di cera personalizzate, progettate per applicazioni specifiche nella produzione di candele.', 'Dopo approfondite ricerche e sviluppo, Bio Green Wax è orgogliosa di presentare la nostra nuova gamma di miscele di cere. Queste miscele accuratamente formulate combinano le migliori proprietà di diversi tipi di cere per garantire prestazioni ottimali per applicazioni specifiche. La nuova gamma include miscele ottimizzate per candele in vasca, candele a colonna e cera per melt. Ogni miscela è stata sottoposta a test approfonditi per garantire un\'eccellente diffusione della fragranza, una combustione pulita e una facile estrazione dallo stampo. Contatta il nostro team commerciale per campioni e schede tecniche.', '2026-02-06 05:29:10', '2026-02-09 04:31:26'),
(5, 'news-005', 'Rapporto sulla Sostenibilità 2025 pubblicato', 'Il nostro rapporto annuale sulla sostenibilità evidenzia i nostri progressi verso gli obiettivi di neutralità carbonica e approvvigionamento sostenibile.', 'Bio Green Wax Ltd ha pubblicato il nostro Rapporto sulla Sostenibilità 2025, che illustra le nostre iniziative ambientali e i progressi verso i obiettivi di sostenibilità del 2030. I punti salienti includono una riduzione del 15% delle emissioni di carbonio rispetto al 2024, il 100% di energia elettrica rinnovabile nel nostro magazzino principale e un aumento dell\'approvvigionamento di prodotti di palma certificati RSPO. Rimaniamo impegnati alla trasparenza e al miglioramento continuo delle nostre performance ambientali. Il rapporto completo è disponibile su richiesta dal nostro team di assistenza clienti.', '2026-02-06 05:34:34', '2026-02-09 04:32:05');
INSERT INTO `news_articles_ja` (`id`, `master_id`, `title`, `excerpt`, `content`, `created_at`, `updated_at`) VALUES
(1, 'news-001', 'バイオグリーンワックスが商品ラインナップを拡大', '私たちは、自然オイルとワックスの製品ラインナップの拡大をお知らせできることを嬉しく思います。', 'Bio Green Wax Ltdは、商品ラインナップの大幅な拡充を喜んでお知らせいたします。お客様のご要望と市場調査に基づき、2026年にいくつかの新しい天然オイルと特殊ワックスをカタログに追加しました。これらの新製品は、成長著しい化粧品およびキャンドル製造業界に対応し、優れた品質と競争力のある価格を提供します。拡大したラインナップについての詳細は、弊社の営業チームまでお問い合わせください。', '2026-02-06 05:09:18', '2026-02-11 18:18:11'),
(2, 'news-002', '新しいRSPO認証を取得しました', 'Bio Green Waxは、持続可能なパーム油製品のためのRSPOマスバランス認証取得を誇りに思います。', '私たちは、Bio Green Wax Ltdがパームワックスおよびパーム油製品でRSPOマスマBalance認証を取得したことをお知らせできることを大変嬉しく思います。この認証は、持続可能な調達と責任あるサプライチェーン管理へのコミットメントを示しています。持続可能なパーム油に関する円卓会議（RSPO）は、持続可能なパーム油の世界的な認証スキームのリーダーです。お客様は、私たちのパーム由来製品が最高水準のサステナビリティ基準を満たしていると安心してお選びいただけます。', '2026-02-06 05:14:38', '2026-02-09 04:29:53'),
(3, 'news-003', 'UKキャンドルエキスポでのトレードショー成功', 'UKキャンドルエキスポ2026で当ブースにお越しくださった皆さま、ありがとうございました。たくさんのキャンドルメーカーの方々にお会いできて、とても楽しかったです！', 'Bio Green Waxチームは、先週バーミンガムで開催されたUK Candle Expo 2026で素晴らしい時間を過ごしました。私たちは、人気のパームワックス、ソイワックス、パラフィンワックス製品を含む、全ラインナップのキャンドルワックスを紹介しました。既存のお客様や新たなキャンドル製作コミュニティの皆さまとお会いできたことは素晴らしい経験でした。特に、新しい結晶化パームワックスのシリーズについては、キャンドルに驚くべき視覚効果を生み出すと好評を博しました。もし展示会でお会いできなかった方がいらっしゃいましたら、サンプルのリクエストについてお気軽にご連絡ください。', '2026-02-06 05:20:36', '2026-02-09 04:30:31'),
(4, 'news-004', '新しいワックスブレンドシリーズのご紹介', '私たちは、特定のキャンドル作りの用途に合わせて設計された新しいカスタムワックスブレンドのラインナップを発表できることにわくわくしています。', '長年の研究開発を経て、Bio Green Waxは新しいワックスブレンドのラインナップを誇らしげにご紹介します。これらの丁寧に調合されたブレンドは、異なるワックスタイプの優れた特性を組み合わせて、特定の用途に最適な性能を実現します。新ラインナップには、コンテナキャンドル、ピラーキャンドル、ワックスメルト用に最適化されたブレンドが含まれています。各ブレンドは、優れた香りの広がり、クリーンな燃焼、そして取り外しやすさを確実にするために徹底的にテストされています。サンプルや技術仕様については、弊社の営業チームまでお問い合わせください。', '2026-02-06 05:26:33', '2026-02-09 04:31:10'),
(5, 'news-005', 'サステナビリティレポート2025を公開しました', '私たちの年間サステナビリティレポートは、カーボンニュートラルと持続可能な調達目標に向けた進展を強調しています。', 'Bio Green Wax Ltdは、2025年サステナビリティレポートを発表しました。これには、私たちの環境への取り組みと、2030年のサステナビリティ目標に向けた進捗状況が記載されています。主なハイライトは、2024年と比較して炭素排出量を15％削減したこと、主要倉庫での電力100％再生可能エネルギーの使用、そしてRSPO認証のパーム製品の調達拡大です。私たちは透明性を重視し、環境パフォーマンスの継続的な改善に引き続き努めてまいります。全文は、カスタマーサービスチームにご連絡いただくことでご請求いただけます。', '2026-02-06 05:32:30', '2026-02-09 04:31:49');
INSERT INTO `news_articles_ko` (`id`, `master_id`, `title`, `excerpt`, `content`, `created_at`, `updated_at`) VALUES
(1, 'news-001', '바이오 그린 왁스, 제품군 확대', '우리는 자연유 및 왁스 제품군의 확장을 발표하게 되어 매우 기쁩니다.', 'Bio Green Wax Ltd는 제품 포트폴리오의 대대적 확장을 기쁘게 발표합니다. 고객의 수요와 시장 조사에 따라 2026년에 여러 가지 새로운 천연 오일과 전문 왁스를 저희 카탈로그에 추가하였습니다. 이 신제품들은 성장하는 화장품 및 캔들 제작 산업을 타겟으로 하여 우수한 품질과 경쟁력 있는 가격을 제공합니다. 저희 확장된 제품군에 대한 자세한 정보를 원하시면 영업팀에 문의해 주시기 바랍니다.', '2026-02-06 05:10:51', '2026-02-11 18:18:23'),
(2, 'news-002', '새로운 RSPO 인증 획득', 'Bio Green Wax는 지속 가능한 팜유 제품에 대해 RSPO Mass Balance 인증을 받았음을 자랑스럽게 발표합니다.', 'Bio Green Wax Ltd가 우리의 팜 왁스와 팜 오일 제품에 대해 RSPO Mass Balance 인증을 획득했다는 소식을 기쁘게 전합니다. 이 인증은 지속 가능한 원료 조달과 책임 있는 공급망 관리에 대한 우리의 의지를 보여줍니다. 지속 가능한 팜유에 관한 원탁회의(RSPO)는 전 세계에서 가장 선도적인 지속 가능 팜유 인증 제도입니다. 이제 우리의 고객들은 당사의 팜 유래 제품이 최고 수준의 지속 가능성 기준을 충족한다는 것을 안심하고 신뢰하실 수 있습니다.', '2026-02-06 05:16:31', '2026-02-09 04:30:03'),
(3, 'news-003', 'UK Candle Expo에서의 무역 박람회 성공', 'UK Candle Expo 2026에서 저희 부스를 방문해 주신 모든 분들께 감사드립니다. 많은 캔들 제작자 분들과 만나게 되어 정말 좋았습니다!', 'Bio Green Wax 팀은 지난주 버밍햄에서 열린 UK Candle Expo 2026에서 정말 즐거운 시간을 보냈습니다. 저희는 인기 있는 팜 왁스, 소이 왁스, 파라핀 왁스를 포함한 전체 캔들 왁스 제품군을 선보였습니다. 기존 고객과 새로운 캔들 제작 커뮤니티의 분들을 만날 수 있어 매우 뜻깊은 시간이었습니다. 특히 새롭게 선보인 크리스털라이즈드 팜 왁스 제품이 캔들에 놀라운 시각 효과를 만들어내는 것에 대해 아주 긍정적인 피드백을 받았습니다. 저희를 행사장에서 만나지 못하셨다면, 언제든지 샘플 요청을 위해 연락 주세요.', '2026-02-06 05:22:06', '2026-02-09 04:30:41'),
(4, 'news-004', '우리의 새로운 왁스 블렌드 라인업을 소개합니다', '우리는 특정 양초 제작 애플리케이션을 위해 설계된 맞춤형 왁스 블렌드 신제품 라인을 출시하게 되어 기대됩니다.', '오랜 연구 개발 끝에, Bio Green Wax는 새로운 왁스 블렌드 라인을 자랑스럽게 선보입니다. 이 정성스럽게 조제된 블렌드들은 다양한 왁스 종류의 최고의 특성을 결합하여 특정 용도에 맞는 최적의 성능을 발휘할 수 있도록 제작되었습니다. 새 라인에는 용기 초, 기둥 초, 왁스 멜트에 최적화된 블렌드가 포함되어 있습니다. 각 블렌드는 뛰어난 향기 전달력, 깨끗한 연소, 그리고 쉽게 분리되는 덤프를 보장하기 위해 광범위하게 테스트되었습니다. 샘플 및 기술 사양에 관해서는 저희 영업팀에 문의하시기 바랍니다.', '2026-02-06 05:28:19', '2026-02-09 04:31:22'),
(5, 'news-005', '2025 지속 가능성 보고서 발행', '우리의 연례 지속 가능성 보고서는 탄소 중립 및 지속 가능한 조달 목표를 향한 우리의 발전 상황을 강조합니다.', 'Bio Green Wax Ltd는 2025년 지속 가능성 보고서를 공개했으며, 이 보고서에서는 우리의 환경 이니셔티브와 2030년 지속 가능성 목표를 향한 진척 상황을 자세히 설명하고 있습니다. 주요 하이라이트는 2024년 대비 탄소 배출량이 15% 감소한 것, 주 창고에서 100% 재생 가능 전력을 사용하고 있는 것, 그리고 RSPO 인증 팜 제품의 구매를 늘린 것을 포함합니다. 우리는 투명성과 지속적인 환경 성과 향상에 대한 약속을 계속 지켜나가고 있습니다. 전체 보고서는 고객 서비스팀에 요청하시면 제공해 드립니다.', '2026-02-06 05:34:02', '2026-02-09 04:31:59');
INSERT INTO `news_articles_pl` (`id`, `master_id`, `title`, `excerpt`, `content`, `created_at`, `updated_at`) VALUES
(1, 'news-001', 'Bio Green Wax Rozszerza swoją gamę produktów', 'Z niecierpliwością ogłaszamy rozszerzenie naszej gamy produktów naturalnych olejów i wosków.', 'Bio Green Wax Ltd z przyjemnością ogłasza znaczące rozszerzenie naszego portfolio produktów. W odpowiedzi na zapotrzebowanie klientów oraz badania rynkowe, w 2026 roku dodaliśmy do naszego katalogu kilka nowych naturalnych olejów i wosków specjalistycznych. Te nowe produkty odpowiadają rosnącemu zapotrzebowaniu przemysłów kosmetycznych i produkcji świec, oferując wysoką jakość i konkurencyjne ceny. Skontaktuj się z naszym zespołem sprzedaży, aby uzyskać więcej informacji o naszej poszerzonej ofercie.', '2026-02-06 05:11:46', '2026-02-11 18:18:34'),
(2, 'news-002', 'Nowe certyfikaty RSPO osiągnięte', 'Bio Green Wax z dumą ogłasza posiadanie certyfikatu RSPO Mass Balance dla produktów zrównoważonego oleju palmowego.', 'Z radością informujemy, że Bio Green Wax Ltd uzyskała certyfikat RSPO Mass Balance dla naszych produktów z wosku palmowego i oleju palmowego. Certyfikat ten potwierdza nasze zobowiązanie do zrównoważonego sourcingu i odpowiedzialnego zarządzania łańcuchem dostaw. Rada Zrównoważonego Oleju Palmowego (RSPO) jest wiodącym globalnym systemem certyfikacji dla zrównoważonego oleju palmowego. Nasi klienci mogą teraz być pewni, że nasze produkty pochodzące z palmy spełniają najwyższe standardy zrównoważonego rozwoju.', '2026-02-06 05:17:38', '2026-02-09 04:30:11'),
(3, 'news-003', 'Sukces na targach na UK Candle Expo', 'Dziękujemy wszystkim, którzy odwiedzili nasze stoisko na UK Candle Expo 2026. To było wspaniałe spotkać tylu producentów świec!', 'Zespół Bio Green Wax świetnie bawił się na UK Candle Expo 2026, które odbyło się w Birmingham w zeszłym tygodniu. Zaprezentowaliśmy nasz pełny asortyment wosków do świec, w tym nasze popularne woski palmowe, sojowe i parafinowe. To było wspaniałe spotkać zarówno obecnych klientów, jak i nowe twarze w społeczności miłośników tworzenia świec. Otrzymaliśmy świetne opinie na temat naszej nowej, krystalizowanej serii wosków palmowych, która tworzy oszałamiające efekty wizualne w świecach. Jeśli nie udało się wam nas odwiedzić na targach, prosimy o kontakt, aby zamówić próbki.', '2026-02-06 05:23:18', '2026-02-09 04:30:49'),
(4, 'news-004', 'Przedstawiamy naszą nową linię mieszanek wosków', 'Z niecierpliwością wprowadzamy naszą nową gamę niestandardowych mieszanek wosków przeznaczonych do konkretnych zastosowań w produkcji świec.', 'Po długotrwałych badaniach i rozwoju, Bio Green Wax z dumą prezentuje naszą nową gamę mieszanek woskowych. Te starannie opracowane mieszanki łączą najlepsze cechy różnych rodzajów wosku, aby osiągnąć optymalną wydajność w określonych zastosowaniach. Nowa gama obejmuje mieszanki zoptymalizowane do świec w słoikach, świec stożkowych oraz wosków do topienia. Każda mieszanka była poddana intensywnym testom, aby zapewnić doskonały rozproszenie zapachu, czyste spalanie oraz łatwe wyjmowanie zeformowanej świecy. Skontaktuj się z naszym zespołem sprzedaży w celu uzyskania próbek i specyfikacji technicznych.', '2026-02-06 05:29:39', '2026-02-09 04:31:29'),
(5, 'news-005', 'Raport zrównoważonego rozwoju 2025 opublikowany', 'Nasz coroczny raport dotyczący zrównoważonego rozwoju podkreśla nasze postępy w dążeniu do neutralności węglowej i celów zrównoważonych źródeł zaopatrzenia.', 'Bio Green Wax Ltd opublikowało nasz Raport Zrównoważonego Rozwoju na 2025 rok, który przedstawia nasze inicjatywy środowiskowe oraz postępy w realizacji celów zrównoważonego rozwoju na 2030 rok. Kluczowe punkty obejmują 15% redukcję emisji dwutlenku węgla w porównaniu z 2024 rokiem, 100% odnawialnej energii elektrycznej w naszym głównym magazynie oraz zwiększenie pozyskiwania produktów palmowych certyfikowanych przez RSPO. Pozostajemy zaangażowani w transparentność i ciągłe doskonalenie naszego wpływu na środowisko. Pełny raport jest dostępny na życzenie od naszego zespołu obsługi klienta.', '2026-02-06 05:35:00', '2026-02-09 04:32:08');
INSERT INTO `news_articles_pt` (`id`, `master_id`, `title`, `excerpt`, `content`, `created_at`, `updated_at`) VALUES
(1, 'news-001', 'Bio Green Wax Expande sua Linha de Produtos', 'Estamos entusiasmados em anunciar a ampliação da nossa linha de óleos naturais e ceras.', 'A Bio Green Wax Ltd tem o prazer de anunciar uma expansão significativa do nosso portfólio de produtos. Após a demanda dos clientes e pesquisas de mercado, adicionamos várias novas óleos naturais e ceras especiais ao nosso catálogo em 2026. Estes novos produtos atendem às indústrias de cosméticos e velas em crescimento, oferecendo qualidade superior e preços competitivos. Entre em contato com nossa equipe de vendas para mais informações sobre nossa linha ampliada.', '2026-02-06 05:08:21', '2026-02-11 18:18:01'),
(2, 'news-002', 'Nova Certificação RSPO Conquistada', 'A Bio Green Wax tem orgulho de anunciar nossa certificação RSPO Mass Balance para produtos de óleo de palma sustentável.', 'Temos o prazer de anunciar que a Bio Green Wax Ltd obteve a certificação RSPO Mass Balance para nossos produtos de cera de palma e óleo de palma. Essa certificação demonstra nosso compromisso com a obtenção sustentável e a gestão responsável da cadeia de suprimentos. A Mesa-redonda de Óleo de Palma Sustentável (RSPO) é o principal esquema de certificação global para óleo de palma sustentável. Nossos clientes agora podem confiar que nossos produtos derivados de palma atendem aos mais altos padrões de sustentabilidade.', '2026-02-06 05:13:29', '2026-02-09 04:29:46'),
(3, 'news-003', 'Sucesso na Feira de Comércio na Expo de Velas do Reino Unido', 'Obrigado a todos que visitaram nosso estande na UK Candle Expo 2026. Foi ótimo conhecer tantos fabricantes de velas!', 'A equipe da Bio Green Wax teve um momento incrível na UK Candle Expo 2026 realizada em Birmingham na semana passada. Mostrámos nossa linha completa de ceras para velas, incluindo nossos populares produtos de cera de palma, cera de soja e cera de parafina. Foi maravilhoso conhecer tanto clientes já existentes quanto novos talentos na comunidade de fabricação de velas. Recebemos feedbacks excelentes sobre nossa nova linha de cera de palma cristalizada, que cria efeitos visuais impressionantes nas velas. Se você perdeu nossa participação no evento, entre em contato conosco para solicitar amostras.', '2026-02-06 05:19:39', '2026-02-09 04:30:23'),
(4, 'news-004', 'Apresentando nossa nova linha de Blend de Ceras', 'Estamos animados em lançar nossa nova linha de combinações de cera personalizadas, desenvolvidas para aplicações específicas na fabricação de velas.', 'Após extensa pesquisa e desenvolvimento, a Bio Green Wax tem orgulho de apresentar nossa nova linha de misturas de cera. Essas misturas cuidadosamente formuladas combinam as melhores propriedades de diferentes tipos de cera para alcançar o desempenho ideal para aplicações específicas. A nova linha inclui misturas otimizadas para velas de recipiente, velas de coluna e melts de cera. Cada mistura foi testada de forma abrangente para garantir ótima difusão do aroma, queima limpa e desmoldagem fácil. Entre em contato com nossa equipe de vendas para amostras e especificações técnicas.', '2026-02-06 05:25:18', '2026-02-09 04:31:02'),
(5, 'news-005', 'Relatório de Sustentabilidade 2025 Publicado', 'Nosso relatório anual de sustentabilidade destaca nosso progresso em direção à neutralidade de carbono e às metas de aquisição sustentável.', 'A Bio Green Wax Ltd publicou o nosso Relatório de Sustentabilidade de 2025, destacando nossas iniciativas ambientais e o progresso em direção às nossas metas de sustentabilidade para 2030. Os principais destaques incluem uma redução de 15% nas emissões de carbono em comparação com 2024, 100% de eletricidade renovável em nosso depósito principal e aumento na origem de produtos de palma certificados pela RSPO. Permanecemos comprometidos com a transparência e a melhoria contínua em nosso desempenho ambiental. O relatório completo está disponível mediante solicitação à nossa equipe de atendimento ao cliente.', '2026-02-06 05:31:25', '2026-02-09 04:31:42');
INSERT INTO `news_articles_ru` (`id`, `master_id`, `title`, `excerpt`, `content`, `created_at`, `updated_at`) VALUES
(1, 'news-001', 'Bio Green Wax расширяет ассортимент продукции', 'Мы рады сообщить о расширении нашего ассортимента натуральных масел и восков.', 'Компания Bio Green Wax Ltd с удовольствием объявляет о значительном расширении нашего ассортимента продукции. В ответ на потребности клиентов и результаты маркетинговых исследований, в 2026 году мы добавили в наш каталог несколько новых натуральных масел и специальных восков. Эти новые продукты предназначены для растущих индустрий косметики и изготовления свечей, предлагая превосходное качество и конкурентоспособные цены. Свяжитесь с нашей командой продаж для получения дополнительной информации о расширенном ассортименте.', '2026-02-06 05:08:37', '2026-02-11 18:18:05'),
(2, 'news-002', 'Достигнута новая сертификация RSPO', 'Bio Green Wax гордится тем, что получил сертификат RSPO Mass Balance на продукцию из устойчивого пальмового масла.', 'Мы рады сообщить, что Bio Green Wax Ltd получила сертификат RSPO Mass Balance на нашу пальмовую воск и пальмовое масло. Этот сертификат подтверждает нашу приверженность устойчивому снабжению и ответственному управлению цепочками поставок. Рабочий круг по устойчивому маслу из пальм (RSPO) — это ведущая мировая схема сертификации устойчивого пальмового масла. Наши клиенты теперь могут быть уверены, что наши продукты на основе пальм обладают высочайшими стандартами экологической ответственности.', '2026-02-06 05:13:46', '2026-02-09 04:29:48'),
(3, 'news-003', 'Успех на торговой выставке на UK Candle Expo', 'Благодарим всех, кто посетил наш стенд на UK Candle Expo 2026. Было приятно познакомиться с таким количеством производителей свечей!', 'Команда Bio Green Wax прекрасно провела время на UK Candle Expo 2026, которая прошла на прошлой неделе в Бирмингеме. Мы продемонстрировали весь наш ассортимент candle wax, включая популярные продукты из пальмового воска, соевого воска и парафиновый воск. Было замечательно встретить как существующих клиентов, так и новых участников сообщества производителей свечей. Мы получили отличные отзывы о нашей новой серии кристализированного пальмового воска, которая создает потрясающие визуальные эффекты в свечах. Если вы пропустили нас на выставке, пожалуйста, свяжитесь с нами, чтобы запросить образцы.', '2026-02-06 05:19:52', '2026-02-09 04:30:25'),
(4, 'news-004', 'Представляем нашу новую линейку восковых смесей', 'Мы с радостью представляем нашу новую линейку индивидуальных восковых смесей, разработанных для конкретных целей при изготовлении свечей.', 'После обширных исследований и разработок компания Bio Green Wax с гордостью представляет новую линейку восковых смесей. Эти тщательно разработанные смеси объединяют лучшие свойства различных видов воска для достижения оптимальной производительности в конкретных сферах применения. Новая линейка включает смеси, оптимизированные для изготовления контейнерных свечей, столбиковых свечей и восковых расплавов. Каждая смесь прошла многочисленные тесты для обеспечения отличного распространения аромата, чистого горения и легкого извлечения из форм. Свяжитесь с нашей командой продаж для получения образцов и технических характеристик.', '2026-02-06 05:25:42', '2026-02-09 04:31:04'),
(5, 'news-005', 'Опубликован Отчет по устойчивому развитию 2025', 'Наш годовой отчет по устойчивому развитию подчеркивает наш прогресс в достижении целей по углеродной нейтральности и устойчивому приобретению ресурсов.', 'Bio Green Wax Ltd опубликовала наш отчет о устойчивом развитии за 2025 год, в котором представлены наши экологические инициативы и прогресс в достижении целей устойчивого развития к 2030 году. Основные моменты включают сокращение выбросов углерода на 15% по сравнению с 2024 годом, использование 100% возобновляемой электроэнергии на нашем основном складе и увеличение закупок продукции из пальмовых масел, сертифицированных RSPO. Мы остаемся приверженными прозрачности и постоянному улучшению нашего экологического показателя. Полный отчет доступен по запросу у нашей службы поддержки клиентов.', '2026-02-06 05:31:43', '2026-02-09 04:31:44');
INSERT INTO `news_articles_sw` (`id`, `master_id`, `title`, `excerpt`, `content`, `created_at`, `updated_at`) VALUES
(1, 'news-001', 'Bio Green Wax Yanafungua Mahitaji Mapya ya Bidhaa', 'Tuna furahi kutangazha upanuzi wa mseto wa mafuta ya asili na waxes yetu.', 'Bio Green Wax Ltd inafurahi kutangaza upanuzi mkubwa wa orodha yetu ya bidhaa. Kufuatia mahitaji ya wateja na utafiti wa soko, tumeongeza mafuta mapya ya asili na wax maalum kwenye katalogi yetu mwaka wa 2026. Bidhaa hizi mpya zinatoa huduma kwa sekta zinazokua za urembo na utengenezaji wa mishumaa, zikitoa ubora bora na bei za ushindani. Wasiliana na timu yetu ya mauzo kwa habari zaidi kuhusu mseto wetu uliopanuliwa.', '2026-02-06 05:09:48', '2026-02-11 18:18:14'),
(2, 'news-002', 'Uthibitisho Mpya wa RSPO Umepatikana', 'Bio Green Wax inajivunia kutangaza uthibitisho wetu wa RSPO Mass Balance kwa bidhaa za mafuta ya nazi ambazo ni endelevu.', 'Tuna furaha kutangaza kuwa Bio Green Wax Ltd imepata vyeti vya RSPO Mass Balance kwa bidhaa zetu za nta ya palm and mafuta ya palm. Vyeti hivi vinaonyesha kujitolea kwetu kwa usambazaji endelevu na usimamizi wa mnyororo wa usambazaji wa kuwajibika. The Roundtable on Sustainable Palm Oil (RSPO) ni mpango wa vyeti wa kimataifa unaoongoza kwa usambazaji wa mafuta ya palm yanayostahili. Wateja wetu sasa wanaweza kuwa na uhakika kuwa bidhaa zetu zinazotokana na palm zinakidhi kiwango cha juu zaidi cha uendelevu.', '2026-02-06 05:15:18', '2026-02-09 04:29:56'),
(3, 'news-003', 'Mafanikio ya Maonyesho ya Biashara katika UK Candle Expo', 'Asante kwa kila mtu aliye tembelea banda letu kwenye UK Candle Expo 2026. Ilikuwa furaha kukutana na wengie wa watengenezaji wa mishumaa!', 'Tim Bio Green Wax alifurahia sana kwenye UK Candle Expo 2026 iliyofanyika Birmingham wiki iliyopita. Tulionyesha anuwai yetu kamili ya wax za mishumaa ikiwa ni pamoja na wax yetu maarufu ya palm wax, soy wax, na paraffin wax. Ilikuwa jambo zuri kukutana na wateja wa zamani na nyuso mpya katika jamii ya kutengeneza mishumaa. Tulipata maoni mazuri kuhusu anuwai yetu mpya ya crystallized palm wax, ambayo huunda athari za kuangalia za kuvutia kwenye mishumaa. Ikiwa umekosa kujua kuhusu sisi kwenye maonyesho, tafadhali wasiliana nasi ili kuomba sampuli.', '2026-02-06 05:20:58', '2026-02-09 04:30:33'),
(4, 'news-004', 'Tunawasilisha Mfululizo Wetu Mpya wa Mchanganyiko wa ParAff', 'Tunafurahi kutangaza aina mpya ya mchanganyiko wa wax iliyobinafsishwa iliyoundwa kwa matumizi maalum ya kutengeneza mishumaa.', 'Baada ya utafiti na maendeleo makubwa, Bio Green Wax inajivunia kuwasilisha mlolongo wetu mpya wa mchanganyiko wa nta. Mchanganyiko huu ulioundwa kwa makini huvunja sifa bora za aina tofauti za nta ili kufanikisha utendaji bora kwa matumizi maalum. Mfululizo mpya unajumuisha mchanganyiko ulioboreshwa kwa mishumaa ya chupa, mishumaa ya nguzo, na wax melts. Kila mchanganyiko umethibitishwa kwa kina ili kuhakikisha utoaji mzuri wa harufu, kuwaka safi, na urahisi wa kutoa kutoka kwenye mold. Wasiliana na timu yetu ya mauzo kwa sampuli na maelezo ya kiufundi.', '2026-02-06 05:27:10', '2026-02-09 04:31:13'),
(5, 'news-005', 'Ripoti ya Uendelevu 2025 Imachapishwa', 'Ripoti letu la mwaka kuhusu uendelevu linaonyesha maendeleo yetu kuelekea kuwa na kaboni sifuri na malengo ya ununuzi wa kudumu.', 'Bio Green Wax Ltd imachapisha Mipango Yetu ya Uendelevu 2025, inayotaja mipango yetu ya mazingira na maendeleo kuelekea malengo yetu ya uendelevu ya 2030. Mambo muhimu yanajumuisha kupunguka kwa 15% kwa utoaji wa kaboni ikilinganishwa na mwaka wa 2024, umeme safi wa 100% wa nishati mbadala kwenye ghala letu kuu, na kuongezeka kwa usambazaji wa bidhaa za michungwa zilizothibitishwa na RSPO. Tunaendelea kuonyesha uwazi na kuboresha mara kwa mara utendaji wetu wa mazingira. Ripoti kamili inapatikana kwa ombi kutoka kwa timu yetu ya huduma kwa wateja.', '2026-02-06 05:32:58', '2026-02-09 04:31:51');
INSERT INTO `news_articles_th` (`id`, `master_id`, `title`, `excerpt`, `content`, `created_at`, `updated_at`) VALUES
(1, 'news-001', 'Bio Green Wax ขยายช่วงผลิตภัณฑ์', 'เราตื่นเต้นที่จะประกาศการขยายช่วงผลิตภัณฑ์น้ำมันจากธรรมชาติและแว็กซ์ของเรา', 'Bio Green Wax Ltd มีความยินดีที่จะประกาศความขยายตัวอย่างมากในกลุ่มสินค้าของเรา ตามความต้องการของลูกค้าและการวิจัยตลาด เรายินดีที่จะนำเข้า <strong>น้ำมันธรรมชาติ</strong> และ <strong>แว็กซ์พิเศษ</strong> ใหม่หลายรายการสู่แคตตาล็อกในปี 2026 สินค้าใหม่นี้รองรับอุตสาหกรรมเครื่องสำอางและเทียนไขที่เติบโตขึ้นอย่างต่อเนื่อง พร้อมคุณภาพที่ยอดเยี่ยมและราคาที่แข่งขันได้ ติดต่อทีมขายของเราเพื่อข้อมูลเพิ่มเติมเกี่ยวกับกลุ่มสินค้าที่ขยายตัวของเรา', '2026-02-06 05:11:09', '2026-02-11 18:18:27'),
(2, 'news-002', 'ได้รับการรับรอง RSPO ใหม่เรียบร้อยแล้ว', 'Bio Green Wax ภูมิใจที่จะแจ้งให้ทราบว่าเราได้รับรองมาตรฐาน RSPO Mass Balance สำหรับผลิตภัณฑ์น้ำมันปาล์มที่ยั่งยืน', 'เรามีความยินดีที่จะประกาศว่า Bio Green Wax Ltd ได้รับการรับรอง RSPO Mass Balance สำหรับผลิตภัณฑ์ขี้ผึ้งปาล์มและน้ำมันปาล์มของเรา การรับรองนี้แสดงให้เห็นถึงความมุ่งมั่นของเราในการจัดหาที่ยั่งยืนและการบริหารจัดการห่วงโซ่อุปทานอย่างรับผิดชอบ กลุ่มสนทนาเรื่องน้ำมันปาล์ยั่งยืน (RSPO) เป็นโครงการรับรองระดับโลกชั้นนำสำหรับน้ำมันปาล์มที่ยั่งยืน ลูกค้าของเราจึงสามารถมั่นใจได้ว่าผลิตภัณฑ์ที่ได้จากปาล์มของเราเป็นไปตามมาตรฐานความยั่งยืนสูงสุด', '2026-02-06 05:16:57', '2026-02-09 04:30:06'),
(3, 'news-003', 'ความสำเร็จในงานแสดงสินค้าที่ UK Candle Expo', 'ขอขอบคุณทุกคนที่แวะเยี่ยมชมบูธของเราในงาน UK Candle Expo 2026 ยินดีที่ได้พบกับนักทำเทียนหลายท่าน!', 'ทีม Bio Green Wax มีช่วงเวลาที่ยอดเยี่ยมที่งาน UK Candle Expo 2026 ซึ่งจัดขึ้นที่เบอร์มิงแฮมเมื่อสัปดาห์ที่ผ่านมา เราได้แสดงสินค้าเทียนต่างๆ ของเราอย่างครบถ้วน รวมถึงเทียนปาล์มเทียนซอย และเทียนพาราฟิน ซึ่งเป็นที่นิยม การได้พบปะทั้งลูกค้าเก่าและหน้าใหม่ในชุมชนการทำเทียนเป็นเรื่องน่าประทับใจมาก เรายินดีที่ได้รับคำติชมดีเยี่ยมเกี่ยวกับกลุ่มเทียนปาล์มคริสตัลใหม่ของเรา ซึ่งสร้างเอฟเฟกต์ภาพที่น่าทึ่งในเทียน หากคุณพลาดโอกาสเจอเราที่งาน กรุณาติดต่อเพื่อขอรับตัวอย่างได้เลย', '2026-02-06 05:22:31', '2026-02-09 04:30:44'),
(4, 'news-004', 'แนะนำกลุ่มผลิตภัณฑ์เทียนผสมใหม่ของเรา', 'เราตื่นเต้นที่จะเปิดตัวชุดผสมเทียนชนิดใหม่ของเรา ซึ่งออกแบบมาเพื่อการใช้งานในการทำเทียนโดยเฉพาะ', 'หลังจากการวิจัยและพัฒนาที่กว้างขวาง Bio Green Wax ภูมิใจนำเสนอผลิตภัณฑ์ใหม่ในกลุ่มของผสมเทียนขี้ผึ้ง กลุ่มผสมที่ได้รับการคัดสรรอย่างพิถีพิถันนี้รวมคุณสมบัติที่ดีที่สุดของชนิดเทียนขี้ผึ้งต่างๆ เพื่อให้ได้ประสิทธิภาพสูงสุดสำหรับการใช้งานเฉพาะด้าน กลุ่มผลิตภัณฑ์ใหม่รวมถึงผสมที่ปรับให้เหมาะสำหรับเทียนใส่กล่อง เทียนเสา และเทียนละลายแต่ละสูตรได้รับการทดสอบอย่างเข้มงวดเพื่อให้แน่ใจว่ามีการปล่อยกลิ่นที่ดี การเผาไหม้ที่สะอาด และการถอดแบบง่าย ติดต่อทีมขายของเราเพื่อขอรับตัวอย่างและข้อมูลทางเทคนิค', '2026-02-06 05:28:46', '2026-02-09 04:31:24'),
(5, 'news-005', 'รายงานความยั่งยืน 2025 เผยแพร่แล้ว', 'รายงานความยั่งยืนประจำปีของเราชี้ให้เห็นความคืบหน้าของเราในการบรรลุเป้าหมายความเป็นกลางทางคาร์บอนและการจัดหาอย่างยั่งยืน', 'Bio Green Wax Ltd ได้เผยแพร่รายงานความยั่งยืนปี 2025 ของเรา ซึ่งสรุ่นโครงการและความก้าวหน้าทางสิ่งแวดล้อมของเราในการบรรลุเป้าหมายความยั่งยืนปี 2030 จุดเด่นสำคัญได้แก่ การลดการปล่อยก๊าซคาร์บอนลง 15% เมื่อเทียบกับปี 2024, พลังงานไฟฟ้าทั้งหมดมาจากแหล่งหมุนเวียน 100% ที่คลังสินค้าหลักของเรา, และการเพิ่มการจัดหาผลิตภัณฑ์ปาล์มที่ได้รับการรับรองจาก RSPO เรายังคงมุ่งมั่นในความโปร่งใสและการปรับปรุงด้านสิ่งแวดล้อมอย่างต่อเนื่อง รายงานฉบับเต็มสามารถขอรับได้จากฝ่ายบริการลูกค้าของเรา', '2026-02-06 05:34:19', '2026-02-09 04:32:03');
INSERT INTO `news_articles_tr` (`id`, `master_id`, `title`, `excerpt`, `content`, `created_at`, `updated_at`) VALUES
(1, 'news-001', 'Bio Green Wax Ürün Yelpazesini Genişletiyor', 'Doğal yağlar ve mumlar ürün yelpazemizi genişletmenin heyecanını yaşıyoruz.', 'Bio Green Wax Ltd, ürün portföyümüzde önemli bir genişleme duyurmaktan memnuniyet duyar. Müşteri talebi ve piyasa araştırmaları doğrultusunda, 2026 yılında kataloğumuza birkaç yeni doğal yağ ve özel muma ekledik. Bu yeni ürünler, büyüyen kozmetik ve mum yapımı sektörlerine hitap ederek üstün kalite ve rekabetçi fiyatlar sunmaktadır. Genişletilmiş ürün yelpazemiz hakkında daha fazla bilgi almak için satış ekibimizle iletişime geçiniz.', '2026-02-06 05:10:12', '2026-02-11 18:18:17'),
(2, 'news-002', 'Yeni RSPO Sertifikası Başarıyla Alındı', 'Bio Green Wax, sürdürülebilir palm yağı ürünleri için RSPO Mass Balance sertifikasını almış olmaktan gurur duyuyor.', 'Bio Green Wax Ltd olarak, palm mumlarımız ve palm yağı ürünlerimiz için RSPO Mass Balance sertifikası almış olmaktan büyük mutluluk duyuyoruz. Bu sertifika, sürdürülebilir tedarik ve sorumlu tedarik zinciri yönetimine olan bağlılığımızı göstermektedir. Sürdürülebilir Palm Yağı Çalışma Grubu (RSPO), sürdürülebilir palm yağı için dünya çapında önde gelen sertifika programıdır. Müşterilerimiz artık palm bazlı ürünlerimizin en yüksek sürdürülebilirlik standartlarına uygun olduğunu güvenle bilebilirler.', '2026-02-06 05:15:49', '2026-02-09 04:29:58'),
(3, 'news-003', 'İngiltere Mum Fuarı\'nda Ticaret Gösterisi Başarısı', 'UK Candle Expo 2026\'da standımızı ziyaret eden herkese teşekkür ederiz. Bu kadar çok mum yapımcısıyla tanışmak harikaydı!', 'Bio Green Wax ekibi, geçen hafta Birmingham\'da düzenlenen UK Candle Expo 2026\'da harika vakit geçirdi. Popüler palm wax, soya wax ve paraffin wax ürünlerimizi içeren tam serimizi sergiledik. Hem mevcut müşterilerimizle hem de mum yapım topluluğundaki yeni yüzlerle tanışmak çok güzel oldu. Yeni kristalleştirilmiş palm wax serimiz hakkında mükemmel geri dönüşler aldık; bu ürünler mumlarda göz alıcı görsel efektler yaratıyor. Bizi fuarda kaçırdıysanız, lütfen numune talebinde bulunmak için bizimle iletişime geçin.', '2026-02-06 05:21:21', '2026-02-09 04:30:36'),
(4, 'news-004', 'Yeni Mum Karışımı Serimizi Tanıtıyoruz', 'Özel mum yapım uygulamaları için tasarlanmış yeni özel balmumu karışımlarımızı tanıtmaktan heyecan duyuyoruz.', 'Kapsamlı araştırma ve geliştirme çalışmalarının ardından, Bio Green Wax yeni wax karışımlarımızı gururla tanıtmaktadır. Bu özenle formüle edilmiş karışımlar, farklı wax türlerinin en iyi özelliklerini bir araya getirerek belirli uygulamalar için en uygun performansı sağlar. Yeni seri, kap mühürleri, fitilli mumlar ve wax meltler için optimize edilmiş karışımları içermektedir. Her bir karışım, mükemmel koku yayılımı, temiz yanma ve kolay kalıbından çıkarma sağlamak amacıyla kapsamlı testlerden geçmiştir. Numune ve teknik özellikler için satış ekibimizle iletişime geçiniz.', '2026-02-06 05:27:40', '2026-02-09 04:31:16'),
(5, 'news-005', 'Sürdürülebilirlik Raporu 2025 Yayınlandı', 'Yıllık sürdürülebilirlik raporumuz, karbon nötrlüğü ve sürdürülebilir tedarik hedeflerimize doğru ilerlememizi vurgulamaktadır.', 'Bio Green Wax Ltd, 2025 Sürdürülebilirlik Raporu\'nu yayımladı ve çevresel girişimlerimizi ile 2030 sürdürülebilirlik hedeflerimize doğru ilerlememizi özetledi. Başlıca önemli noktalar arasında, 2024\'e kıyasla karbon emisyonlarında %15 azalma, ana depomuzda %100 yenilenebilir elektrik kullanımı ve RSPO sertifikalı palm ürünlerin tedarikinde artış bulunmaktadır. Şeffaflık ve çevresel performansımızda sürekli iyileştirmeye bağlılığımız devam ediyor. Tam rapora, müşteri hizmetleri ekibimizden talep edilerek ulaşabilirsiniz.', '2026-02-06 05:33:17', '2026-02-09 04:31:54');
INSERT INTO `news_articles_vi` (`id`, `master_id`, `title`, `excerpt`, `content`, `created_at`, `updated_at`) VALUES
(1, 'news-001', 'Bio Green Wax Mở Rộng Dòng Sản Phẩm', 'Chúng tôi vô cùng phấn khích thông báo về việc mở rộng dòng sản phẩm dầu tự nhiên và sáp của chúng tôi.', 'Bio Green Wax Ltd vui mừng thông báo về việc mở rộng đáng kể danh mục sản phẩm của chúng tôi. Dựa trên nhu cầu của khách hàng và nghiên cứu thị trường, chúng tôi đã bổ sung một số loại dầu tự nhiên và sáp đặc biệt mới vào danh mục trong năm 2026. Những sản phẩm mới này phục vụ cho ngành mỹ phẩm và làm nến ngày càng phát triển, cung cấp chất lượng vượt trội và giá cả cạnh tranh. Liên hệ với đội ngũ bán hàng của chúng tôi để biết thêm thông tin về phạm vi sản phẩm mở rộng.', '2026-02-06 05:10:32', '2026-02-11 18:18:20'),
(2, 'news-002', 'Chứng nhận RSPO mới đã được cấp', 'Bio Green Wax tự hào thông báo chứng nhận RSPO Mass Balance cho các sản phẩm dầu cọ bền vững của chúng tôi.', 'Chúng tôi vui mừng thông báo rằng Bio Green Wax Ltd đã đạt chứng nhận RSPO Mass Balance cho các sản phẩm sáp cọ và dầu cọ của mình. Chứng nhận này thể hiện cam kết của chúng tôi về nguồn cung ứng bền vững và quản lý chuỗi cung ứng có trách nhiệm. Hội đồng về Dầu cọ Bền vững (RSPO) là hệ thống chứng nhận hàng đầu toàn cầu dành cho dầu cọ bền vững. Khách hàng của chúng tôi giờ đây có thể yên tâm rằng các sản phẩm từ cọ của chúng tôi đáp ứng các tiêu chuẩn cao nhất về tính bền vững.', '2026-02-06 05:16:11', '2026-02-09 04:30:00'),
(3, 'news-003', 'Thành công tại Triển lãm Sự kiện Thương mại UK Candle Expo', 'Cảm ơn tất cả mọi người đã ghé thăm gian hàng của chúng tôi tại UK Candle Expo 2026. Thật tuyệt vời khi được gặp gỡ nhiều nhà làm nến!', 'Nhóm Bio Green Wax đã có một khoảng thời gian tuyệt vời tại UK Candle Expo 2026 diễn ra ở Birmingham vào tuần trước. Chúng tôi giới thiệu toàn bộ các dòng sáp nến của mình bao gồm sáp dừa phổ biến, sáp đậu nành và sáp paraffin. Thật tuyệt vời khi được gặp gỡ cả khách hàng hiện tại lẫn những gương mặt mới trong cộng đồng làm nến. Chúng tôi nhận được phản hồi tích cực về dòng sáp dừa crystallized mới của mình, giúp tạo ra những hiệu ứng thị giác gây ấn tượng trong nến. Nếu bạn bỏ lỡ chúng tôi tại triển lãm, vui lòng liên hệ để yêu cầu mẫu thử.', '2026-02-06 05:21:39', '2026-02-09 04:30:38'),
(4, 'news-004', 'Giới thiệu dòng sản phẩm Hỗn hợp sáp mới của chúng tôi', 'Chúng tôi rất háo hức giới thiệu dòng sản phẩm mới của chúng tôi - các hỗn hợp sáp tùy chỉnh được thiết kế dành riêng cho các ứng dụng làm nến khác nhau.', 'Sau nhiều nghiên cứu và phát triển, Bio Green Wax tự hào giới thiệu dòng sản phẩm hỗn hợp sáp mới của chúng tôi. Các hỗn hợp được phối chế cẩn thận này kết hợp các đặc tính tốt nhất của các loại sáp khác nhau để đạt hiệu suất tối ưu cho các ứng dụng cụ thể. Dòng sản phẩm mới này bao gồm các hỗn hợp tối ưu hóa cho nến đựng, nến cột và nến sáp nóng chảy. Mỗi hỗn hợp đã được thử nghiệm kỹ lưỡng để đảm bảo khả năng tỏa hương tốt, cháy sạch và dễ dàng tháo khuôn. Liên hệ với đội ngũ bán hàng của chúng tôi để lấy mẫu và thông số kỹ thuật.', '2026-02-06 05:27:59', '2026-02-09 04:31:19'),
(5, 'news-005', 'Báo cáo Bền vững 2025 đã được phát hành', 'Báo cáo bền vững hàng năm của chúng tôi nhấn mạnh tiến trình hướng tới trung hòa carbon và các mục tiêu cung ứng bền vững.', 'Bio Green Wax Ltd đã công bố Báo cáo Bền vững năm 2025 của chúng tôi, trình bày các sáng kiến môi trường và tiến trình đạt được hướng tới các mục tiêu bền vững năm 2030. Những điểm nổi bật chính gồm giảm 15% lượng phát thải carbon so với năm 2024, 100% điện năng tái tạo tại kho chính của chúng tôi, và tăng cường nguồn cung các sản phẩm từ dầu cọ được chứng nhận RSPO. Chúng tôi vẫn cam kết minh bạch và không ngừng cải thiện hiệu quả môi trường của mình. Toàn bộ báo cáo có sẵn theo yêu cầu từ đội ngũ dịch vụ khách hàng của chúng tôi.', '2026-02-06 05:33:41', '2026-02-09 04:31:57');
INSERT INTO `news_articles_zh` (`id`, `master_id`, `title`, `excerpt`, `content`, `created_at`, `updated_at`) VALUES
(1, 'news-001', 'Bio Green Wax 扩展产品系列', '我们很高兴宣布我们的天然油脂和蜡类产品系列将不断扩展。', 'Bio Green Wax Ltd 很高兴宣布我们产品线的重大扩展。根据客户需求和市场调研，我们在2026年新增了多种天然油和特色蜡到我们的目录中。 这些新产品满足日益增长的化妆品和蜡烛制造行业的需求，提供优质的品质和具有竞争力的价格。有关我们扩展产品范围的更多信息，请联系销售团队。', '2026-02-06 05:07:06', '2026-02-11 18:17:49'),
(2, 'news-002', '获得新的RSPO认证', 'Bio Green Wax 自豪地宣布我们获得了RSPO大众平衡认证，以生产可持续的棕榈油产品。', '我们很高兴宣布，Bio Green Wax Ltd 已获得RSPO质量平衡认证，用于我们的棕榈蜡和棕榈油产品。这项认证彰显了我们对可持续采购和负责任供应链管理的承诺。可持续棕榈油圆桌会议（RSPO）是全球领先的可持续棕榈油认证体系。我们的客户现在可以放心，我们的棕榈提取产品符合最高的可持续性标准。', '2026-02-06 05:12:05', '2026-02-09 04:29:36'),
(3, 'news-003', '在英国蜡烛博览会取得交易会成功', '感谢所有到访我们在英国蜡烛博览会2026展台的朋友们。很高兴能与如此多的蜡烛制造商相见！', 'Bio Green Wax团队上周在伯明翰举行的英国蜡烛博览会2026期间收获满满。我们展示了全系列的蜡烛蜡产品，包括受到欢迎的棕榈蜡、豆蜡和石蜡产品。很高兴与现有客户以及新认识的蜡烛制造社区成员们见面。我们收到了关于新款结晶棕榈蜡系列的极佳反馈，该系列在蜡烛中创造出令人惊艳的视觉效果。如果您错过了我们的展会，欢迎与我们联系索取样品。', '2026-02-06 05:18:08', '2026-02-09 04:30:13'),
(4, 'news-004', '介绍我们的新蜡混合系列', '我们很高兴推出我们为特定蜡烛制作应用而设计的全新定制蜡混合系列。', '经过大量的研究与开发，Bio Green Wax自豪地推出我们的新系列蜡混合物。这些精心配制的混合物结合了不同蜡类型的最佳特性，以实现特定应用的最佳性能。新系列包括为容器蜡烛、柱状蜡烛和蜡片优化的混合物。每一种混合物都经过 extensive 测试，确保出香效果优良、燃烧清洁、易于脱模。请联系我们的销售团队索取样品和技术规格。', '2026-02-06 05:23:41', '2026-02-09 04:30:51'),
(5, 'news-005', '《2025年可持续发展报告》已发布', '我们的年度可持续发展报告突出了我们在实现碳中和和可持续采购目标方面的进展。', 'Bio Green Wax Ltd 已公布我们的2025年可持续发展报告，概述了我们的环保举措及实现2030年可持续发展目标的进展。主要亮点包括与2024年相比碳排放减少15%，我们主要仓库使用100%的可再生电力，以及增加RSPO认证棕榈产品的采购。我们将继续致力于透明度和持续改善环境表现。如需查阅完整报告，请联系客户服务团队索取。', '2026-02-06 05:29:55', '2026-02-09 04:31:31');
