INSERT INTO `products` (`id`, `slug`, `name`, `description`, `full_description`, `category`, `category_label`, `categories`, `image_url`, `specifications`, `applications`, `packaging`, `is_active`, `is_featured`, `display_order`, `priority_order`, `synchronized_data`, `created_at`) VALUES
('bdf424df-f9b0-4a79-84d6-f6ed1eb1e84f', 'palm-olein', 'Palm Olein', 'Palm olein is the liquid fraction of refined palm oil, prized as a stable frying and cooking oil that delivers neutral taste, long fry life, and crisp texture for snacks, fast‑food, and household applications.\n', 'Palm olein is produced by fractionating refined, bleached, and deodorized (RBD) palm oil to obtain a clear liquid rich in oleic and palmitic acids, giving a balanced fatty‑acid profile with naturally good oxidative stability. Its high smoke point, resistance to oxidation and polymer formation, and low tendency to form off‑flavours allow repeated frying cycles with reduced oil breakdown, less foaming, and extended shelf life of finished products.\n​\nIn food applications, palm olein is widely used as a deep‑frying medium for snacks, potato chips, fried chicken, instant noodles, and pre‑fried frozen foods, as well as a general‑purpose household cooking oil in many tropical markets. It also serves as a base oil in blends with soybean, sunflower, or other vegetable oils to achieve tailored nutritional and functional profiles, and is used in margarines, bakery fats, and foodservice frying systems where stable performance and clean flavor are critical.', 'edible-oils', 'Edible Oils', '[\"edible-oils\",\"oleochemicals\"]', '/uploads/products/palm-olein.jpg', '[]', '[\"margarines\",\"frying\",\"cooking\"]', '[]', 1, 1, 32, 1, 0, '2026-02-11 09:25:25'),
('prod-beeswax', 'beeswax', 'Beeswax', 'Pure natural beeswax for cosmetics and candle making', 'Pure natural beeswax sourced from ethical beekeepers. Perfect for cosmetics, candle making, and food applications. Available in various grades.', 'plant-based-waxes', 'Plant-Based Waxes', '[\"plant-based-waxes\"]', '/uploads/products/beeswax.jpg', '[]', '[\"Cosmetics & Pharma\",\"Candles\",\"Food grade coating\"]', '[]', 1, 1, 6, 2, 0, '2026-02-05 21:03:49'),
('prod-bw101-palm-wax', 'bw101-palm-wax', 'Palm Wax', 'Premium 100% palm wax with creamy yellow color, ideal for candle making. RSPO SG (Segregated) / MB (Mass balance) certified.', 'Premium 100% Palm Wax, available with RSPO Segregated (SG) / RSPO Mass Balance (MB), or EUDR certification for full sustainability and compliance. Custom grades tailored for candle production feature varied melting points, perfect for crafting premium jar candles, moulding, and versatile candle wax blends. Its beautiful creamy yellow color ensures stunning results with clean, efficient burning.', 'plant-based-waxes', 'Plant-Based Waxes', '[\"plant-based-waxes\",\"industrial-waxes\",\"oleochemicals\"]', '/uploads/products/bw101-palm-wax.jpg', '[{\"label\":\"Melting Point\",\"value\":\"52-54\"},{\"label\":\"Melting Point\",\"value\":\"50-52\"},{\"label\":\"Melting Point\",\"value\":\"48-50\"},{\"label\":\"Melting point \",\"value\":\"46-48\"},{\"label\":\"Melting point\",\"value\":\"42-44\"}]', '[\"Food coating\",\"Candle making\",\"Jar candles making\"]', '[\"20 kg Cartons\",\"10 kg Cartons\",\"50 Lbs Cartons\"]', 1, 1, 8, 2, 0, '2026-02-05 21:03:49'),
('prod-bw105-palm-wax', 'palm-shortenings-lmp', 'Palm Shortenings(Low melting point)', 'Palm Shortening is a semi-solid, non-hydrogenated fat derived from fractionated palm oil, offering superior stability and neutral flavor.', 'Palm Shortening is a semi-solid, non-hydrogenated fat derived from fractionated palm oil, offering superior stability and neutral flavor.\nPerfect for bakery applications—creates flaky pastries, tender cakes, and crispy fried foods with high smoke point.\nCost-effective, oxidation-resistant alternative to butter or lard in industrial baking.', 'plant-based-waxes', 'Plant-Based Waxes', '[\"plant-based-waxes\",\"edible-oils\"]', '/uploads/products/palm-shortenings-lmp.jpg', '[{\"label\":\"Melting point\",\"value\":\"40-42\"},{\"label\":\"Melting point\",\"value\":\"42-44\"}]', '[\"Food industry\",\"Jar candle making\",\"Vanaspathi making\",\"Vegetable Ghee\",\"Margarine production\"]', '[\"20 kg cartons\"]', 1, 0, 9, 10, 1, '2026-02-05 21:03:49'),
('prod-bw10510-blended-wax', 'palm-paraffin-blended-wax-jarcandles', 'Palm-Paraffin blended wax for jar candles', 'Ready-to-use Low MP Jar Candle Blend: Palm-Paraffin-Microcrystalline with Polyboost™, Vybar®, UV stabilizers—just add color & fragrance for superior glass adhesion and maximum throw.', 'Bio Green Wax\'s Low Melting Point Jar Candle Blend (48-50°C) and (50-52°C)—Palm-Paraffin-Microcrystalline formulation optimized for glass containers. Ready-to-use: add only color & fragrance. Features Polyboost/Vybar for opacity/adhesion, UV stabilizers/antioxidants for shelf life, plus fragrance retention agents delivering exceptional hot/cold throw, crease-free burn, and superior jar retention for premium container candles.', 'wax-blends', 'Wax Blends', '[\"wax-blends\",\"industrial-waxes\"]', '/uploads/products/palm-paraffin-blended-wax-jarcandles.jpg', '[]', '[\"Jar candles production\",\"scented candles\"]', '[\"20 kg cartons\"]', 1, 0, 18, 10, 1, '2026-02-05 21:03:49'),
('prod-bw10555-blended-wax', 'soy-blend-vegan-wax', 'Soy-Based Vegan Wax Blend', 'Ready-to-use 95% Soy Vegan Blend from Bio Green Wax—pure plant-based for Jar (48-52°C) & Pillar (56-62°C) candles. Just add color & fragrance.', 'Bio Green Wax\'s 95% Soy Wax Vegan Blend (5% plant additives) delivers clean-burning, natural performance for glass jars and freestanding pillars. Available in low melting point (48-52°C) for containers and high melting point (56-62°C) for pillars. Ready-to-use: simply add your color and fragrance for exceptional throw and smooth finish.', 'wax-blends', 'Wax Blends', '[\"wax-blends\",\"industrial-waxes\"]', '/uploads/products/soy-blend-vegan-wax.jpg', '[]', '[\"Jar candles\",\"Pillar Candles\"]', '[]', 1, 0, 20, 10, 1, '2026-02-05 21:03:49'),
('prod-bw10610-blended-wax', 'palm-paraffin-blended-wax-pillar', 'Palm-Paraffin- blended wax for Pillar Candles', 'Ready-to-use High MP Pillar Candle Blends (56-58°C & 58-60°C): Palm-Paraffin-Microcrystalline with Polyboost™, Vybar®, UV stabilizers—just add color & fragrance for superior pillar performance.', 'Bio Green wax\'s High Melting Point Pillar Candle Blends (56-58°C & 58-60°C)—Palm-Paraffin-Microcrystalline formulations engineered for freestanding pillar candles. Ready-to-use: add only color & fragrance. Optimized with Polyboost/Vybar for mold release & opacity, UV stabilizers/antioxidants for extended shelf life, plus fragrance retention agents delivering exceptional hot/cold throw, perfect pillar shape retention, and clean-burning performance.', 'wax-blends', 'Wax Blends', '[\"wax-blends\",\"industrial-waxes\"]', '/uploads/products/palm-paraffin-blended-wax-pillar.jpg', '[]', '[\"Pillar candles\"]', '[\"20 kg cartons\",\"25 kg bags\"]', 1, 0, 19, 10, 1, '2026-02-05 21:03:49'),
('prod-bw10655-blended-wax', 'soy-beeswax-blend', 'Soy-Beeswax-Paraffin Wax Blend', 'Ready-to-use Soy-Beeswax-Paraffin Blend from Bio Green Wax—ultimate fragrance throw for Jar (48-52°C) & Pillar (56-62°C) candles. Just add scent & color.', 'Bio Green Wax\'s Soy-Beeswax-Paraffin Blend combines natural soy smoothness, beeswax stability, and paraffin\'s scent power for unmatched fragrance performance. Low melting point (48-52°C) excels in glass containers; high melting point (56-62°C) perfect for pillars. Ready-to-use formulation—just add fragrance and color for superior hot/cold throw and flawless candle finish.', 'wax-blends', 'Wax Blends', '[\"wax-blends\",\"industrial-waxes\"]', '/uploads/products/soy-beeswax-blend.jpg', '[]', '[\"jar candles\",\"pillar candles\"]', '[]', 1, 0, 21, 10, 1, '2026-02-05 21:03:49'),
('prod-bw8307-blended-wax', 'coconut-rapeseed-blend', 'Coconut-Rapeseed Wax Blend', 'Ready-to-use Coconut-Rapeseed Blend from Bio Green Wax—creamy natural performance for Jar (48-52°C) & Pillar (56-62°C) candles. Add color & fragrance only.', 'Bio Green Wax\'s Coconut-Rapeseed Blend combines coconut wax\'s creamy texture and rapeseed wax\'s smooth burn for exceptional natural candle performance. Low melting point (48-52°C) optimized for container candles; high melting point (56-62°C) for pillar candles. Completely ready-to-use—add only your choice of color and fragrance for professional, clean-burning results.', 'wax-blends', 'Wax Blends', '[\"wax-blends\",\"industrial-waxes\"]', '/uploads/products/coconut-rapeseed-blend.jpg', '[]', '[\"jar candle\",\"pillar candle\"]', '[]', 1, 0, 22, 10, 1, '2026-02-05 21:03:49'),
('prod-carnauba-wax', 'carnauba-wax', 'Carnauba Wax', 'Premium Brazilian carnauba wax for polishes and coatings', 'Premium Brazilian carnauba wax, known as the \"queen of waxes\". Ideal for car polish, cosmetics, and food coatings. Highest natural melting point.', 'plant-based-waxes', 'Plant-Based Waxes', '[\"plant-based-waxes\"]', '/uploads/products/carnauba-wax.jpg', '[]', '[]', '[]', 1, 0, 7, 2, 1, '2026-02-05 21:03:49'),
('prod-castor-oil', 'castor-oil', 'Castor Oil', 'Premium cold-pressed castor oil derived from Ricinus communis seeds, widely used in pharmaceuticals, cosmetics, and industrial applications.', 'Bio Green Wax supplies high-quality castor oil, a versatile vegetable oil obtained by pressing the seeds of the castor bean plant (Ricinus communis). Known for its unique chemical composition rich in ricinoleic acid (approximately 85–90%), castor oil exhibits exceptional viscosity, lubricity, and moisturising properties that make it invaluable across a wide range of industries.\n\nOur castor oil is carefully sourced and processed to meet the highest standards of purity and consistency. It is available in both cold-pressed (virgin) and refined grades, suitable for pharmaceutical, cosmetic, and industrial applications. The oil\'s remarkable stability and solubility in alcohol distinguish it from other vegetable oils, making it a preferred ingredient in formulations requiring superior performance.\n\nCastor oil is naturally biodegradable and derived from renewable resources, aligning with Bio Green Wax\'s commitment to sustainable and environmentally responsible sourcing.', 'oleochemicals', 'Oleochemicals', '[\"oleochemicals\"]', '/uploads/products/castor-oil.jpg', '[\"Ricinoleic Acid Content: 85\\u201390%\",\"Iodine Value: 82\\u201390\",\"Saponification Value: 176\\u2013187\",\"Acid Value: \\u2264 2.0 mg KOH\\/g\",\"Moisture: \\u2264 0.5%\",\"Colour (Gardner): \\u2264 3\",\"Specific Gravity (25\\u00b0C): 0.957\\u20130.968\",\"Viscosity (25\\u00b0C): 650\\u2013700 cP\",\"Grade: Cold-Pressed \\/ Refined (BSS\\/FSG)\"]', '[\"Pharmaceuticals & nutraceuticals\",\"Cosmetics & personal care (skin, hair, lip products)\",\"Industrial lubricants & greases\",\"Coatings, paints & varnishes\",\"Biodiesel & biopolymers\",\"Soap & detergent manufacturing\",\"Textile finishing & dyeing\",\"Food-grade applications & flavouring\"]', '[\"190 kg steel drums\",\"Flexitanks (22 MT)\"]', 1, 1, 7, 2, 0, '2026-02-11 10:14:05'),
('prod-coconut-oil', 'coconut-oil', 'Coconut Oil', 'Virgin and refined coconut oil for food and cosmetic applications', 'Premium virgin and refined coconut oil suitable for cooking, baking, and cosmetic applications. Available in various grades to meet your specific requirements.', 'edible-oils', 'Edible Oils', '[\"edible-oils\"]', '/uploads/products/coconut-oil.jpeg', '[]', '[]', '[]', 1, 1, 2, 1, 0, '2026-02-05 21:03:49'),
('prod-coconut-wax', 'coconut-wax', 'Coconut Wax', 'Coconut wax is a natural wax derived from coconut oil, prized for clean burning candles and eco-friendly applications.', 'Coconut wax is a natural wax derived from the oil of coconuts, known for its clean and slow burn in candle making. It is often considered a sustainable alternative to other waxes. Coconut wax is prized for its eco-friendly characteristics and ability to hold fragrance well. It is derived from a natural and renewable resource, providing clean and slow burning in candles for a longer-lasting and more efficient performance.', 'oleochemicals', 'Oleochemicals', '[\"oleochemicals\",\"plant-based-waxes\"]', '/uploads/products/coconut-wax.jpg', '[]', '[]', '[]', 1, 1, 48, 2, 0, '2026-02-09 04:40:19'),
('prod-fr5456-paraffin-wax', 'sr-paraffin-wax', 'Semi Refined Paraffin Wax (50-68°C)', 'Bio Green Wax Semi Refined Paraffin (50-68°C)—cost-effective 1-5% oil content for candles, rubber, textiles, and high-volume industrial applications.', 'Bio Green Wax\'s Semi Refined Paraffin Waxes (50-68°C) offer economical performance with controlled oil content (1-5%) for flexible hardness. Standard grades: 52/54°C (candles), 56/58°C (pillars), 60/62°C (industrial). Perfect for cost-sensitive candle production, rubber processing aids, textile finishing, and bulk packaging coatings where balanced performance and price matter most.', 'industrial-waxes', 'Industrial Waxes', '[\"industrial-waxes\"]', '/uploads/products/sr-paraffin-wax.jpg', '[]', '[]', '[]', 1, 0, 26, 10, 1, '2026-02-05 21:03:49'),
('prod-glycerine', 'glycerine', 'Glycerine', 'Glycerine is a colorless, odorless, viscous liquid used extensively in pharmaceuticals, cosmetics, and food industries.', 'Glycerine, also known as glycerol or glycerin, is a colorless, odorless, and viscous liquid with a sweet taste. It is a clear, syrupy liquid that is typically colorless, although it can have a slightly yellowish tinge. Glycerine has a high viscosity, meaning it flows slowly and is relatively thick. It has a syrup-like consistency, which contributes to its ability to retain moisture. Glycerine finds extensive use in pharmaceuticals, cosmetics, food processing, and various industrial applications.', 'oleochemicals', 'Oleochemicals', '[\"oleochemicals\"]', '/uploads/products/glycerine.jpg', '[]', '[]', '[]', 1, 0, 42, 4, 1, '2026-02-09 04:40:19'),
('prod-hydrogenated-castor-oil', 'hydrogenated-castor-oil', 'Hydrogenated Castor Oil', 'Hydrogenated castor oil is a solid waxy derivative of castor oil, used in cosmetics, pharmaceuticals, and industrial applications.', 'Hydrogenated castor oil, also known as castor wax or castor wax flake, is a derivative of castor oil that undergoes a hydrogenation process. This involves the addition of hydrogen to the castor oil molecules, resulting in a solid, waxy substance. It is employed in cosmetic and personal care products like lipsticks, creams, and lotions as an emollient to provide smoothness and moisture to the skin. It also acts as a binding agent in cosmetic formulations, helping ingredients stick together and adhere to the skin.', 'oleochemicals', 'Oleochemicals', '[\"oleochemicals\",\"plant-based-waxes\"]', '/uploads/products/hydrogenated-castor-oil.jpg', '[]', '[]', '[]', 1, 1, 52, 2, 0, '2026-02-09 04:40:19'),
('prod-microcrystalline-wax', 'microcrystalline-wax', 'Microcrystalline Wax', 'Flexible microcrystalline wax for cosmetics and adhesives', 'Flexible microcrystalline wax ideal for cosmetics, hot-melt adhesives, and specialty coatings. Superior flexibility and binding properties.', 'industrial-waxes', 'Industrial Waxes', '[\"industrial-waxes\"]', '/uploads/products/microcrystalline-wax.jpg', '[]', '[]', '[]', 1, 1, 24, 10, 1, '2026-02-05 21:03:49'),
('prod-olive-oil', 'olive-oil', 'Olive Oil', 'Premium quality pure olive oil, cold-pressed from select Mediterranean olives for culinary, cosmetic, and industrial applications.', 'Our premium pure olive oil is cold-pressed from carefully selected Mediterranean olives, delivering exceptional quality and rich flavour. Widely used in food preparation, cosmetics, pharmaceuticals, and personal care products, olive oil is prized for its health benefits, antioxidant properties, and versatile applications. Bio Green Wax sources olive oil that meets stringent international quality standards, ensuring consistent purity and performance across all applications.', 'edible-oils', 'Edible Oils', '[\"edible-oils\",\"oleochemicals\"]', '/images/products/olive-oil.jpg', '[]', '[\"Cooking and food preparation\",\"Salad dressings and marinades\",\"Cosmetics and personal care\",\"Pharmaceutical formulations\",\"Soap and candle making\",\"Industrial lubricants\"]', '[\"Flexitanks\",\"ISO tanks\",\"Drums (190 kg)\",\"IBC (1000 L)\",\"Jerrycans (20 L)\"]', 1, 1, 6, 1, 1, '2026-02-10 09:54:48'),
('prod-palm-kernel-oil', 'palm-kernel-oil', 'Palm Kernel Oil', 'Palm kernel oil is derived from the kernel of the oil palm fruit, used in food products, cosmetics, and industrial applications.', 'Palm kernel oil is derived from the kernel of the oil palm fruit and has distinct physical properties. It is typically a light yellow to white solid at room temperature, but melts into a clear, yellowish liquid when heated. The melting point ranges from 23 to 28 degrees Celsius (73 to 82 degrees Fahrenheit). Palm kernel oil is rich in lauric acid and is widely used in food manufacturing, cosmetics, and soap production.', 'oleochemicals', 'Oleochemicals', '[\"oleochemicals\",\"edible-oils\"]', '/uploads/products/palm-kernel-oil.jpg', '[]', '[]', '[]', 1, 0, 41, 1, 1, '2026-02-09 04:40:19'),
('prod-palm-kernel-olein', 'palm-kernel-olein', 'Palm Kernel Olein', 'Premium refined palm kernel olein, the liquid fraction obtained from fractionation of palm kernel oil, valued for its excellent clarity, low cloud point, and versatile use in food, personal care, and oleochemical industries.', 'Bio Green Wax supplies high-quality palm kernel olein (PKOo), the liquid fraction produced through the controlled fractionation of refined palm kernel oil. When palm kernel oil is cooled under precise conditions, it separates into a solid fraction (palm kernel stearin) and a liquid fraction (palm kernel olein). The resulting olein is a clear, light-coloured oil with a low melting point and excellent pourability.\n\nPalm kernel olein is rich in lauric acid (C12) and capric/caprylic medium-chain fatty acids, giving it outstanding clarity, rapid absorption, and a light, non-greasy feel. These characteristics make it highly desirable in the food industry as a cooking oil, frying medium, and ingredient in non-dairy creamers, ice cream, and filled milk formulations.\n\nIn the personal care and cosmetics sector, palm kernel olein is widely used as a base oil in lotions, creams, shampoos, and liquid soaps due to its excellent emollient properties and skin compatibility. It also serves as a key feedstock in oleochemical production, yielding fatty acids, methyl esters, and surfactants used in detergents and cleaning products.\n\nBio Green Wax sources its palm kernel olein from RSPO-certified supply chains, ensuring full traceability and alignment with sustainable palm oil commitments. The product is available in refined, bleached, and deodorised (RBD) form, meeting stringent international quality standards.', 'edible-oils', 'Edible Oils', '[\"edible-oils\",\"oleochemicals\"]', '/images/products/palm-kernel-olein.jpeg', '[\"Lauric Acid (C12): 40\\u201348%\",\"Capric Acid (C10): 3\\u20135%\",\"Caprylic Acid (C8): 3\\u20134%\",\"Myristic Acid (C14): 14\\u201317%\",\"Oleic Acid (C18:1): 12\\u201318%\",\"Iodine Value: 20\\u201328\",\"Saponification Value: 230\\u2013250\",\"Cloud Point: 8\\u201312\\u00b0C\",\"Free Fatty Acid (as Lauric): \\u2264 0.1%\",\"Moisture & Impurities: \\u2264 0.1%\",\"Colour (Lovibond 5\\u00bc\\\" cell): \\u2264 3R\",\"Grade: RBD (Refined, Bleached, Deodorised)\"]', '[\"Cooking oil & frying medium\",\"Non-dairy creamers & filled milk\",\"Ice cream & frozen desserts\",\"Cosmetics & personal care (lotions, creams, shampoos)\",\"Liquid soap & detergent manufacturing\",\"Fatty acid & methyl ester production\",\"Surfactant & emulsifier formulation\",\"Oleochemical feedstock\"]', '[\"190 kg steel drums\",\"Flexitanks (20\\u201322 MT)\",\"ISO tank containers\",\"1000 L IBC totes\",\"Bulk tanker loads\"]', 1, 1, 9, 1, 0, '2026-02-11 16:07:28'),
('prod-palm-kernel-stearin', 'palm-kernel-stearin', 'Palm Kernel Stearin', 'High-quality palm kernel stearin, the solid fraction obtained from the fractionation of palm kernel oil, prized for its sharp melting profile and excellent hardness in confectionery, cosmetics, and oleochemical applications.', 'Bio Green Wax supplies premium-grade palm kernel stearin (PKS), the higher-melting solid fraction produced through the controlled fractionation of refined palm kernel oil. During fractionation, palm kernel oil is separated into two components: palm kernel olein (the liquid fraction) and palm kernel stearin (the solid fraction). The resulting stearin is a white to off-white fat with a characteristically sharp melting point and firm texture.\n\nPalm kernel stearin is rich in lauric acid (C12) and myristic acid (C14), giving it excellent hardness, rapid crystallisation, and a clean melt profile. These properties make it an ideal ingredient for cocoa butter substitutes (CBS), compound chocolate coatings, confectionery fillings, and specialty fats where a snap and gloss finish are required.\n\nBeyond food applications, palm kernel stearin serves as a valuable feedstock in the oleochemical industry for the production of fatty acids, fatty alcohols, soap noodles, and surfactants. In personal care and cosmetics, it contributes body and structure to creams, lotions, and solid formulations.\n\nBio Green Wax sources its palm kernel stearin from RSPO-certified supply chains, ensuring full traceability and compliance with sustainable palm oil commitments. The product is available in refined, bleached, and deodorised (RBD) form, meeting international quality standards for food-grade and technical-grade use.', 'oleochemicals', 'Oleochemicals', '[\"oleochemicals\",\"plant-based-waxes\"]', '/images/products/palm-kernel-stearin.jpeg', '[\"Lauric Acid (C12): 46\\u201352%\",\"Myristic Acid (C14): 15\\u201318%\",\"Palmitic Acid (C16): 7\\u201310%\",\"Oleic Acid (C18:1): 5\\u20138%\",\"Iodine Value: 5\\u20139\",\"Saponification Value: 240\\u2013255\",\"Melting Point: 30\\u201334\\u00b0C\",\"Free Fatty Acid (as Lauric): \\u2264 0.1%\",\"Moisture & Impurities: \\u2264 0.1%\",\"Colour (Lovibond 5\\u00bc\\\" cell): \\u2264 3R\",\"Grade: RBD (Refined, Bleached, Deodorised)\"]', '[\"Cocoa butter substitutes (CBS) & compound chocolate\",\"Confectionery coatings & fillings\",\"Specialty fats & non-dairy creamer\",\"Soap noodles & laundry bar production\",\"Fatty acid & fatty alcohol manufacturing\",\"Cosmetics & personal care formulations\",\"Candle making & wax blends\",\"Surfactant & detergent production\"]', '[\"190 kg steel drums\",\"25 kg carton boxes\",\"Flexitanks (20\\u201322 MT)\"]', 1, 0, 8, 2, 1, '2026-02-11 16:03:48'),
('prod-palm-oil', 'palm-oil', 'Palm Oil', 'Sustainably sourced palm oil and palm derivatives with RSPO SG(segregated) / MB(Mass Balance) Grade', 'RSPO SG(segregated) / MB(Mass balance) Grades available, Sustainably sourced palm oil and palm derivatives for food manufacturing, soap and detergent production. ', 'edible-oils', 'Edible Oils', '[\"edible-oils\",\"oleochemicals\"]', '/uploads/products/palm-oil.jpeg', '[]', '[\"RSPO SG\",\"RSPO MB\"]', '[]', 1, 1, 3, 1, 0, '2026-02-05 21:03:49'),
('prod-palm-shortenings', 'palm-shortenings', 'Palm Shortenings(high melting point)', 'High‑melting palm shortenings (46–52 °C) are specialty bakery and frying fats made from fractionated palm oil, designed to give strong structure, clean flavor, and excellent heat stability in demanding industrial applications.', 'High‑melting point palm shortenings in the 46–52 °C range are formulated from palm stearin and mid‑fractions to deliver high solid‑fat content, firm texture, and a stable crystal network at ambient and elevated temperatures. This higher melting range provides superior heat resistance, oxidative stability, and reduced oiling‑out, making them well suited for tropical climates and high‑temperature processing lines.\n​\n\nIn bakery applications, these shortenings give good aeration, lamination, and snap, supporting flaky pie crusts, puff pastries, cream crackers, cookies, and biscuits while maintaining shape and bite even in warm conditions. They are also used as robust frying and dough fats, and as animal‑fat replacers in meat products, where their firm structure, emulsion stability, and zero‑trans, non‑hydrogenated profile help achieve consistent texture, clean flavor release, and label‑friendly formulations.', 'oleochemicals', 'Oleochemicals', '[\"oleochemicals\",\"edible-oils\",\"plant-based-waxes\"]', '/uploads/products/palm-shortenings.jpg', '[]', '[]', '[]', 1, 0, 44, 2, 1, '2026-02-09 04:40:19'),
('prod-palm-stearic-acid', 'palm-stearic-acid', 'Palm Stearic Acid', 'Palm stearic acid is a saturated fatty acid derived from palm oil, used in cosmetics, candles, and rubber manufacturing.', 'Palm stearic acid is a type of fatty acid derived from palm oil, obtained through the process of separating and crystallizing the fatty acids. It is a saturated fatty acid known for its stability and solid form at room temperature. Palm stearic acid has a waxy appearance ranging from white to slightly yellow. It has a melting point typically between 55-70 degrees Celsius (131-158 degrees Fahrenheit), which allows it to be easily incorporated into various formulations for cosmetics, candles, and rubber products.', 'oleochemicals', 'Oleochemicals', '[\"oleochemicals\",\"plant-based-waxes\"]', '/uploads/products/palm-stearic-acid.jpg', '[]', '[]', '[]', 1, 1, 45, 4, 0, '2026-02-09 04:40:19'),
('prod-palm-stearin', 'palm-stearin', 'Palm Stearin', 'Palm stearin is the solid fraction of palm oil, commonly used in food manufacturing, candle production, and soap making.\nOur Palm Stearin is RSPO SG (Segregated) / MB (Mass balance) grade certified.', 'Palm stearin is a solid fraction of palm oil obtained through the fractionation process, known for its high saturated fatty acid content. It is a solid fat at room temperature with a creamy white to pale yellow color and a smooth, waxy texture. Palm stearin has a higher melting point compared to palm oil. It is commonly used in the food industry for stabilizing fats, producing margarine, and in the production of candles and soap.\nOur Palm Stearin is RSPO SG (Segregated) / MB (Mass balance) grade certified.', 'oleochemicals', 'Oleochemicals', '[\"oleochemicals\",\"edible-oils\",\"plant-based-waxes\"]', '/uploads/products/palm-stearin.jpg', '[]', '[\"RSPO SG \\/ RSPO MB\"]', '[]', 1, 0, 43, 2, 0, '2026-02-09 04:40:19'),
('prod-paraffin-wax', 'paraffin-wax', 'Fully Refined Paraffin Wax (50-68°C)', 'Bio Green Wax Fully Refined Paraffin (50-68°C)—food/pharma grade, <0.5% oil, superior hardness. Perfect for candles, cosmetics, packaging, and precision industrial applications.', 'Bio Green Wax\'s Fully Refined Paraffin Waxes (50-68°C melting points) feature ultra-low oil content (<0.5%), exceptional hardness, and neutral odor/color. Available in candle grades (52/54°C, 56/58°C), container grades (50/52°C), and high-melt pillar grades (64/66°C). Ideal for premium candles, cosmetics, food packaging coatings, and precision molding requiring maximum purity and performance consistency.', 'industrial-waxes', 'Industrial Waxes', '[\"industrial-waxes\"]', '/uploads/products/paraffin-wax.jpg', '[]', '[]', '[]', 1, 0, 23, 10, 1, '2026-02-05 21:03:49'),
('prod-pf56-synthetic-wax', 'fischer-tropsch-ft-wax', 'Fischer-Tropsch (FT) wax', 'Fischer‑Tropsch (FT) wax is a high‑purity synthetic paraffin wax produced from syngas, offering high melting point, low viscosity, and excellent hardness for demanding applications in plastics, coatings, inks, adhesives, and bitumen modification', 'FT wax is generated via the Fischer‑Tropsch synthesis, yielding a water‑white, ultra‑clean wax with a narrow carbon‑chain distribution, very low oil content, and outstanding thermal stability. It combines a high softening point with low melt viscosity and strong hardness, giving superior scratch resistance, gloss control, matting effects, and lubrication in many formulations.\n\nIn plastics and PVC/CPVC processing, FT wax acts as an efficient internal and external lubricant and processing aid, reducing melt viscosity, improving flow, and enhancing mold release and dimensional stability. It is widely used in hot‑melt and pressure‑sensitive adhesives, printing inks, and industrial coatings to increase hardness, abrasion and scratch resistance, block resistance, and anti‑settling while stabilizing viscosity. Additional key applications include bitumen and asphalt modification, masterbatch and polymer compounding, rubber processing, polishes, textiles, and even cosmetic formulations, where FT wax delivers controlled crystallinity, improved wear and wrinkle resistance, and a smooth sensory feel.', 'industrial-waxes', 'Industrial Waxes', '[\"industrial-waxes\"]', '/uploads/products/fischer-tropsch-ft-wax.jpg', '[]', '[]', '[]', 1, 0, 29, 10, 1, '2026-02-05 21:03:49'),
('prod-pfad', 'palm-fatty-acid-distillate-pfad', 'PFAD (Palm Fatty Acid Distillate)', 'PFAD is a byproduct of palm oil refining, used in soap manufacturing, animal feed, and biofuel production.', 'Palm Fatty Acid Distillate (PFAD) is a byproduct of the palm oil refining process. It is obtained through the distillation of crude palm oil to remove impurities and achieve a higher level of purity. PFAD is a brownish-yellow liquid with a characteristic odor. It contains a mixture of saturated and unsaturated fatty acids, with the predominant fatty acids being lauric acid, myristic acid, and palmitic acid. PFAD is used in soap manufacturing, animal feed, and biofuel production.', 'oleochemicals', 'Oleochemicals', '[\"oleochemicals\"]', '/uploads/products/palm-fatty-acid-distillate-pfad.jpg', '[]', '[]', '[]', 1, 0, 46, 3, 1, '2026-02-09 04:40:19'),
('prod-pkfad', 'palm-kernel-fatty-acid-distillate-pkfad', 'Palm Kernel Fatty Acid Distillate (PKFAD)', 'PKFAD is a byproduct of palm kernel oil refining, rich in lauric acid, used in soap and oleochemical industries.', 'Palm Kernel Fatty Acid Distillate (PKFAD) is a byproduct obtained during the refining of palm kernel oil. It is rich in fatty acids, including lauric acid, making it valuable for certain industrial applications. PKFAD is utilized in various industrial applications, including soap manufacturing, biofuel production, and as a raw material in the oleochemical industry.', 'oleochemicals', 'Oleochemicals', '[\"oleochemicals\"]', '/uploads/products/palm-kernel-fatty-acid-distillate-pkfad.jpg', '[]', '[]', '[]', 1, 0, 47, 3, 0, '2026-02-09 04:40:19'),
('prod-polyethylene-wax', 'polyethylene-wax', 'Polyethylene Wax (PE wax)', 'is a low‑molecular‑weight polyethylene used as a high‑performance lubricant and processing aid in plastics, coatings, inks, and adhesives, improving flow, surface slip, and scratch resistance.', 'Polyethylene wax is a finely divided, high‑melting synthetic wax with low viscosity, excellent thermal stability, and strong compatibility with common polymers such as PVC, PE, PP, and EVA. It provides internal and external lubrication, reduces melt viscosity and friction, enhances mold release, and delivers a smooth, glossy, and scratch‑resistant surface.\n​\n\nKey applications include plastics and masterbatch processing, where PE wax improves extrusion and injection molding efficiency, prevents die build‑up, and improves dispersion of pigments and fillers. It is also used in hot‑melt and pressure‑sensitive adhesives, inks, and powder coatings to control melt viscosity, boost cohesion and toughness, and optimize open and setting times. Additional uses span bitumen and road‑marking paints, wood‑plastic composites, rubber compounding, cable compounds, and formulated wax products such as polishes and crayons, where it raises softening point, hardness, and water resistance.', 'industrial-waxes', 'Industrial Waxes', '[\"industrial-waxes\"]', '/uploads/products/polyethylene-wax.jpg', '[]', '[\"plastics manufacturing\",\"Lubricant\",\"Processing Aid\",\"Mold Release Agent\",\"Dispersant\",\"Surface Enhancement\"]', '[]', 1, 0, 25, 10, 1, '2026-02-05 21:03:49'),
('prod-rapeseed-oil', 'rapeseed-oil', 'Rapeseed Oil', 'Cold-pressed and refined rapeseed oil from UK farms', 'Cold-pressed and refined rapeseed oil sourced from UK farms. Ideal for cooking, roasting, and salad dressings. Low in saturated fat and high in omega-3.', 'edible-oils', 'Edible Oils', '[\"edible-oils\"]', '/uploads/products/rapeseed-oil.jpeg', '[]', '[]', '[]', 1, 1, 5, 1, 0, '2026-02-05 21:03:49'),
('prod-rapeseed-wax', 'rapeseed-wax', 'Rapeseed Wax', 'Rapeseed wax is a natural vegetable wax used as an eco-friendly alternative in candle making and cosmetics.', 'Rapeseed wax is a natural vegetable wax derived from the oil of the rapeseed plant, commonly used as an eco-friendly alternative to traditional paraffin wax in candle making and other applications. It offers a clean and slow burn, as well as good fragrance retention. Rapeseed wax is frequently used in candle production and in the formulation of natural cosmetics such as lip balms, lotions, and creams, providing moisturizing properties.', 'oleochemicals', 'Oleochemicals', '[\"oleochemicals\",\"plant-based-waxes\"]', '/uploads/products/rapeseed-wax.jpg', '[]', '[]', '[]', 1, 0, 51, 2, 1, '2026-02-09 04:40:19'),
('prod-soap-noodles', 'soap-noodles', 'Soap Noodles', 'Soap noodles are primary raw materials for soap manufacturing, produced by saponification of vegetable oils and fats.', 'Soap noodles, also known as soap granules, are one of the primary raw materials used in the manufacturing of soap. They are produced by processing vegetable oils and fats with sodium hydroxide (lye) through saponification. Soap noodles are typically solid white or off-white chunks or beads with a mild and neutral aroma. They are free from impurities and contain a high concentration of fatty acids that contribute to their cleansing and emulsifying properties.', 'oleochemicals', 'Oleochemicals', '[\"oleochemicals\"]', '/uploads/products/soap-noodles.jpg', '[]', '[\"Soap making\"]', '[]', 1, 0, 49, 3, 1, '2026-02-09 04:40:19'),
('prod-soy-wax', 'soy-wax', 'Soy Wax', 'Soy wax is a renewable vegetable wax made from soybean oil, popular for eco-friendly candle making.', 'Soy wax is a type of vegetable wax derived from soybean oil. It is a popular alternative to traditional paraffin wax, which is derived from petroleum. Soy wax is considered a renewable, biodegradable, and eco-friendly option for candle making. It is created by hydrogenating soybean oil, transforming it into a solid form suitable for candles. It typically comes in the form of flakes, which are easy to measure and melt.', 'oleochemicals', 'Oleochemicals', '[\"oleochemicals\",\"plant-based-waxes\"]', '/uploads/products/soy-wax.jpg', '[]', '[\"Candle making\",\"cosmetics\"]', '[\"20 kg Cartons\"]', 1, 1, 50, 2, 0, '2026-02-09 04:40:19'),
('prod-soybean-oil', 'soybean-oil', 'Soya Bean Oil', 'High-quality soya bean oil for industrial and culinary use', 'Soybean oil is a versatile vegetable oil extracted from soybeans, widely used for frying, baking, and salad dressings due to its neutral flavor and high smoke point.\nIt is rich in polyunsaturated fats, including omega‑3 and omega‑6 fatty acids, and provides vitamin K and vitamin E.\nIt is perfect for deep frying, margarine production, and industrial food applications. Refined and deodorized to premium standards.', 'edible-oils', 'Edible Oils', '[\"edible-oils\"]', '/uploads/products/soybean-oil.jpg', '[]', '[]', '[]', 1, 0, 4, 1, 0, '2026-02-05 21:03:49'),
('prod-sunflower-oil', 'sunflower-oil', 'Sunflower Oil', 'Premium refined sunflower oil for cooking and food processing', 'Our premium refined sunflower oil is perfect for cooking, frying, and food processing applications. Sourced from quality sunflower seeds and refined to the highest standards.', 'edible-oils', 'Edible Oils', '[\"edible-oils\"]', '/uploads/products/sunflower-oil.jpeg', '[]', '[]', '[]', 1, 1, 1, 1, 1, '2026-02-05 21:03:49');
INSERT INTO `products_ar` (`id`, `master_id`, `name`, `description`, `full_description`, `created_at`, `updated_at`) VALUES
(1, 'bdf424df-f9b0-4a79-84d6-f6ed1eb1e84f', 'زيت النخيل الأولين', 'مزيج الزيتون المكرر هو الجزء السائل من زيت النخيل المكرر، ويُعتبر زيت قلي وطهي مستقر يحقق طعمًا محايدًا، عمر قلي طويل، وملمس مقرمش للوجبات الخفيفة، والوجبات السريعة، والتطبيقات المنزلية.', 'زيت النخيل المملح مستخلص من خلال تجزئة زيت النخيل المكرر والمبيض والمزيل الروائح (RBD) للحصول على سائل شفاف غني بالأحماض أوليك و بالميتات، مما يمنحه ملفًا غذائيًا متوازنًا من الأحماض الدهنية مع استقرار أكس diep هوائي طبيعي وجيد. نظرًا لنقطة دخانه العالية، ومقاومته للأكسدة وتكوين البوليمرات، وانخفاض ميله لتكوين نكهات غريبة، فإنه يسمح بتكرار عمليات القلي مع تقليل تدهور الزيت، وتقليل الفوران، وإطالة عمر الأرفف للمنتجات النهائية.\n\nفي التطبيقات الغذائية، يُستخدم زيت النخيل المملح على نطاق واسع كوسيط للقلي العميق للوجبات الخفيفة، ورقائق البطاطس، والدجاج المقلي، والنودلز الفورية، والأطعمة المجمدة المقلية مسبقًا، بالإضافة إلى زيت الطهي المنزلي متعدد الاستخدامات في العديد من الأسواق الاستوائية. كما يُستخدم كزيت أساسي في الخلطات مع فول الصويا أو عباد الشمس أو زيوت نباتية أخرى لتحقيق ملفات غذائية ووظيفية مخصصة، ويُستخدم في المارجرين، ودهون المخابز، وأنظمة القلي في خدمات الطعام حيث الأداء المستقر والنكهة النظيفة ضروريان.', '2026-02-11 17:15:01', '2026-02-11 17:15:01'),
(2, 'prod-beeswax', 'شمع العسل', 'شمع النحل الطبيعي النقي لمستحضرات التجميل وصناعة الشموع', 'شمع العسل الطبيعي النقي المستخلص من سماسرة الخلايا النحل الأخلاقيين. مثالي لمستحضرات التجميل، صناعة الشموع، وتطبيقات الطعام. متوفر بدرجات متنوعة.', '2026-02-05 21:56:57', '2026-02-11 17:29:42'),
(3, 'prod-bw101-palm-wax', 'شمع النخيل', 'شمع نخيل فاخرة بنسبة 100% بلون أصفر كريمي، مثالي لصناعة الشموع. معتمد من قبل RSPO SG (فصل الأسهم) / MB (توازن الكتلة).', 'شمع نخيل فائق الجودة بنسبة 100% بلون أصفر كريمي جميل. حاصل على شهادة RSPO MB للاستدامة. مثالي لصناعة الشموع، والتشكيل، والشموع الحاوية.', '2026-02-05 22:04:09', '2026-02-11 17:45:19'),
(4, 'prod-bw105-palm-wax', 'زيوت النخيل المجرّدة (ذات نقطة انصهار منخفضة)', 'زيت النخيل المشتق من زيت النخيل المكرر هو دهون شبه صلبة غير مهدرجة، يوفر استقراراً أعلى ونكهة محايدة.', 'زيت النخيل المهدرج جزئيًا هو دهون شبه صلبة غير مهدرجة مشتقة من زيت النخيل المفرّق، ويوفر استقرارًا فائقًا ونكهة محايدة.\nمثالي للاستخدام في المخابز—يُكوّن معجنات هشة، وكعك طري، وأطعمة مقلية مقرمشة ذات نقطة دخان عالية.\nبديل اقتصادي ومقاوم للأكسدة للزبدة أو السمن في الخبز الصناعي.', '2026-02-05 22:08:22', '2026-02-11 17:30:58'),
(5, 'prod-bw10510-blended-wax', 'شمع مزيج من الجمال وبارافين للشموع الزجاجية', 'مزيج شمعة الجرة منخفضة نقطة الانصهار جاهز للاستخدام: زيت النخيل ـ بارافين ـ ميكروكرystalline مع Polyboost™، Vybar®، مثبتات الأشعة فوق البنفسجية — فقط أضف اللون والرائحة لتحقيق التصاق ممتاز بالزجاج وإلقاء مثالي.', 'خلطة شموع الجرار ذات نقطة انصهار منخفضة من Bio Green Wax (48-50°C) و(50-52°C)—تركيبة من الزيت النخيل، البرافين، والكريستالات الدقيقة، محسنة للتعبئة في الحاويات الزجاجية. جاهزة للاستخدام: أضف اللون والعطر فقط. تأتي مع مركبات Polyboost/Vybar لزيادة الشفافية والالتصاق، مع مثبتات الأشعة فوق البنفسجية / مضادات الأكسدة لتمديد عمر الرف، بالإضافة إلى عوامل حفظ العطر التي تقدم أداءً استثنائيًا في الإطلاق عند الحرارة والبرودة، حرق بدون طيات، واحتجاز ممتاز للجرار للحفاظ على جودة الشموع داخل الحاويات الفاخرة.', '2026-02-06 03:35:41', '2026-02-11 17:37:04'),
(6, 'prod-bw10555-blended-wax', 'مزيج شمع نباتي قائم على الصويا', 'مزيج الصويا النباتي الجاهز للاستخدام بنسبة 95% من Bio Green Wax—مكون من نباتات نقية لشموع الJar (48-52°C) والPillar (56-62°C). فقط أضف اللون والعطر.', 'برمية بيوب جرين وكس، خليط الصويا النباتي بنسبة 95٪ (ويحتوي على 5٪ إضافات نباتية)، يوفر أداءً طبيعيًا ونظيفًا للحرق للأوعية الزجاجية والأعمدة المستقلة. متوفر بدرجة انصهار منخفضة (48-52°C) للمحافظ ودرجة انصهار عالية (56-62°C) للأعمدة. جاهز للاستخدام: ببساطة أضف لونك وعطرك للحصول على نتائج استثنائية وتشبث ناعم.', '2026-02-06 03:43:05', '2026-02-11 17:31:46'),
(7, 'prod-bw10610-blended-wax', 'شمع مزيج من البالم-البارافين لشموع الأعمدة', 'عبوات الشموع العمودية عالية الجودة جاهزة للاستخدام (56-58°C و 58-60°C): مزيج من زبدة النخيل، البارافين، الميكروكريستالين مع Polyboost™، Vybar®، المثبّتات فوق البنفسجية—فقط أضف اللون والعطر لتحقيق أداء متفوق للشموع العمودية.', 'خليط شموع الأعمدة Bio Green wax ذات درجة انصهار عالية (56-58°C و58-60°C)—تركيبات من Palm-Paraffin-Microcrystalline مصممة خصيصًا لشموع الأعمدة المستقلة. جاهزة للاستخدام: أضف فقط اللون والعطر. مُحسنة باستخدام Polyboost/Vybar لتحقيق سهولة فك القالب وشفافية، ومواد مثبتة للأشعة فوق البنفسجية/مضادات الأكسدة لتمديد فترة الصلاحية، بالإضافة إلى عوامل احتفاظ بالعطر لضمان أداء فائق في الانبعاث الحار/البارد، والحفاظ على شكل العمود المثالي، وأداء احتراق نظيف.', '2026-02-06 03:39:19', '2026-02-11 17:37:54'),
(8, 'prod-bw10655-blended-wax', 'مزيج من شمع الصويا وشمع البارافين', 'مزيج جاهز للاستخدام من الصويا وشمع العسل وشمع البارافين من Bio Green Wax—أفضل قدر على إطلاق العطر للشموع الزجاجية (48-52°C) والشموع العمودية (56-62°C). فقط أضف العطر واللون.', 'يمزج مزيج Bio Green Wax من الصويا وشمع العسل والبارافين بين نعومة الصويا الطبيعية، واستقرار شمع العسل، وقوة رائحة البارافين لأداء عطر لا مثيل له. نقطة الانصهار المنخفضة (48-52°C) تتفوق في الحاويات الزجاجية؛ أما نقطة الانصهار العالية (56-62°C) فهي مثالية للشموع الأسطوانية. تركيبة جاهزة للاستخدام — فقط أضف العطر واللون للحصول على أداء ممتاز في الإشعال الساخن والبارد وإنهاء شمعة مثالي.', '2026-02-06 03:46:42', '2026-02-11 17:32:36'),
(9, 'prod-bw8307-blended-wax', 'مزيج شمع جوز الهند ودوار الشمس', 'مزيج جوز الهند والكانولا الجاهز للاستخدام من Bio Green Wax—أداء طبيعي كريمي لشموع الجرة (48-52°C) وعمود الشمعة (56-62°C). أضف اللون والعطر فقط.', 'مزيج جوز الهند وعباد شمس Bio Green Wax يجمع بين قوام شمع جوز الهند الكريمي وحرق عباد الشمس الناعم لتحقيق أداء استثنائي للشموع الطبيعية. نقطة انصهار منخفضة (48-52°C) محسنة لشموع الحاويات؛ ونقطة انصهار عالية (56-62°C) لشموع الأعمدة. جاهز تمامًا للاستخدام — أضف فقط لونك وعطرك المفضلين للحصول على نتائج محترفة ونقية في الاحتراق.', '2026-02-06 03:50:25', '2026-02-11 17:33:26'),
(10, 'prod-carnauba-wax', 'شمع الكارناوبا', 'شمع الكارنوبا البرازيلي الفاخر للتلميع والطلاءات', 'شمع كارنوبا البرازيلي الممتاز، المعروف باسم \"ملكة الشموع\". مثالي لتلميع السيارات، ومستحضرات التجميل، وطلاءات الطعام. أعلى نقطة إذابة طبيعية.', '2026-02-05 22:00:03', '2026-02-11 17:30:18'),
(11, 'prod-castor-oil', 'زيت الخروع', 'زيت الخروع البارد المعصور عالي الجودة المستخلص من بذور Ricinus communis، يُستخدم على نطاق واسع في الصناعات الدوائية والتجميلية والتطبيقات الصناعية.', 'تورد شركة Bio Green Wax زيت الخروع عالي الجودة، وهو زيت نباتي متعدد الاستخدامات يتم الحصول عليه عن طريق عصر بذور نبات الخروع (Ricinus communis). ويشتهر بتكوينه الكيميائي الفريد الغني بحمض الر任يميكوليك (حوالي 85–90%)، حيث يظهر زيت الخروع خصائص استثنائية من حيث اللزوجة، والانزلاق، والمرطبات التي تجعله لا يُقدر بثمن عبر مجموعة واسعة من الصناعات.\n\nيتم اختيار ومعالجة زيت الخروع الخاص بنا بعناية ليتوافق مع أعلى معايير النقاء والاتساق. ويتوفر في درجات غير مطهرة (الخام) ومكررة، مناسبة للتطبيقات الصيدلانية والتجميلية والصناعية. وتتميز ثباتية الزيت وقابليته للذوبان في الكحول عن غيره من الزيوت النباتية، مما يجعله مكونًا مفضلًا في التركيبات التي تتطلب أداءً فائقًا.\n\nكما أن زيت الخروع طبيعي قابل للتحلل البيولوجي ومستمد من موارد متجددة، مما يتماشى مع التزام شركة Bio Green Wax بالتصنيع المستدام والمسؤول بيئيًا.', '2026-02-11 17:16:02', '2026-02-11 17:16:02'),
(12, 'prod-coconut-oil', 'زيت جوز الهند', 'زيت جوز الهند النقي والمكرر للاستخدامات الغذائية والتجميلية', 'زيت جوز الهند الممتاز البكر والمكرر المناسب للطهي والخَبْز والتطبيقات التجميلة. متوفر بأنواع مختلفة لتلبية متطلباتك الخاصة.', '2026-02-05 21:49:53', '2026-02-11 17:16:51'),
(13, 'prod-coconut-wax', 'شمع جوز الهند', 'شمع جوز الهند هو شمع طبيعي يُستخرج من زيت جوز الهند، يُقدر لاستخدامه في صنع الشموع النظيفة والصديقة للبيئة.', 'شمع جوز الهند هو شمع طبيعي مشتق من زيت جوز الهند، المعروف بحرقه النظيف والبطيء في صناعة الشموع. غالبًا ما يُعتبر بديلاً مستدامًا للشمعات الأخرى. يُقدر شمع جوز الهند لخصائصه الصديقة للبيئة وقدرته على الاحتفاظ بالعطر بشكل جيد. ويشتق من مصدر طبيعي ومتجدد، مما يوفر حرقًا نظيفًا وبطيئًا في الشموع لأداء يدوم لفترة أطول وأكثر كفاءة.', '2026-02-11 17:25:39', '2026-02-11 17:25:39'),
(14, 'prod-fr5456-paraffin-wax', 'شمع البارافين شبه المكرر (50-68°C)', 'شمع Bio Green Wax شبه مكرر البارافين (50-68°C) — تكلفة فعالة تحتوي على نسبة زيت من 1-5% للاستخدام في الشموع، والمطاط، والمنسوجات، والتطبيقات الصناعية ذات الحجم الكبير.', 'شموع Bio Green Wax ذات الشمع شبه المكرر (50-68°C) تقدم أداءً اقتصاديًا مع محتوى زيت محكّم (1-5%) لصلابة مرنة. الأنواع القياسية: 52/54°C (للحُليّ)، 56/58°C (للعُمدان)، 60/62°C (صناعي). مثالية لإنتاج الشموع ذات التكلفة المنخفضة، مساعدات معالجة المطاط، تشطيب النسيج، وطلاءات التعبئة والتغليف بالجملة حيث يكون الأداء المتوازن والسعر أهم ما يُميزها.', '2026-02-06 04:04:44', '2026-02-11 17:23:30'),
(15, 'prod-glycerine', 'الجلسرين', 'الجلسرين مادة سائلة لزجة عديمة اللون والرائحة وتستخدم على نطاق واسع في الصناعات الصيدلانية والتجميلية و الصناعات الغذائية.', 'الجليسرين، والمعروف أيضًا بالجليسرول أو الجليسرين، هو سائل عديم اللون والرائحة ذات لزوجة عالية وطعم حلو. هو سائل شفاف وشرابي يتسم عادة بلونه الشفاف، على الرغم من أنه قد يكون له مسحة صفراء خفيفة. الجليسرين يمتلك لزوجة عالية، مما يعني أنه يتدفق ببطء ويكون سميكًا نسبيًا. له قوام يشبه الشراب، الأمر الذي يساهم في قدرته على احتجاز الرطوبة. يُستخدم الجليسرين بشكل واسع في الأدوية ومستحضرات التجميل ومعالجة الأغذية والعديد من التطبيقات الصناعية.', '2026-02-11 17:19:31', '2026-02-11 17:19:31'),
(16, 'prod-hydrogenated-castor-oil', 'زيت الخروع المهدرج', 'زيت الخروع المهدرج هو مركب شمعي صلب مشتق من زيت الخروع، يُستخدم في مستحضرات التجميل والأدوية والتطبيقات الصناعية.', 'زيوت الخروع المهدرجة، المعروفة أيضًا بشمع الخروع أو رقائق شمع الخروع، هي مشتق من زيت الخروع يمر بعملية هدرجة. تتضمن هذه العملية إضافة الهيدروجين إلى جزيئات زيت الخروع، مما يؤدي إلى مادة صلبة وشمعية. وتُستخدم في المنتجات التجميلية والعناية الشخصية مثل أحمر الشفاه والكريمات والمستحضرات كملين لمنح البشرة النعومة والرطوبة. كما تعمل كعامل ربط في التركيبات التجميلية، مما يساعد المكونات على الالتصاق ببعضها والالتصاق بالبشرة.', '2026-02-11 17:24:55', '2026-02-11 17:24:55'),
(17, 'prod-microcrystalline-wax', 'شمع ميكروكريستالي', 'شمع ميكركرستالين مرن للمنتجات التجميلية والمواد اللاصقة', 'شمع ميكروكريستالي مرن مثالي لمستحضرات التجميل، واللاصق القابل للذوبان بالحرارة، والطلاءات الخاصة. مرونة وخصائص التلاصق فائقة.', '2026-02-06 03:57:19', '2026-02-11 17:22:51'),
(18, 'prod-olive-oil', 'زيت الزيتون', 'زيت زيتون نقي عالي الجودة، مضغوط على البارد من زيتون البحر الأبيض المتوسط المختار للاستخدامات الطهوية والتجميلية والصناعية.', 'زيت الزيتون النقي المميز لدينا يُضغط على الباردة من زيتون البحر الأبيض المتوسط المختار بعناية، ليقدم جودة استثنائية ونكهة غنية. يُستخدم على نطاق واسع في تحضير الطعام، ومستحضرات التجميل، والصناعات الدوائية، ومنتجات العناية الشخصية، ويُعتبر زيت الزيتون ذو قيمة عالية لفوائده الصحية، وخصائصه المضادة للأكسدة، وتنوع تطبيقاته. تقوم شركة Bio Green Wax بتوريد زيت الزيتون الذي يلتزم بمعايير الجودة الدولية الصارمة، لضمان نقاوة وأداء ثابتين في جميع الاستخدامات.', '2026-02-11 17:41:33', '2026-02-11 17:41:33'),
(19, 'prod-palm-kernel-oil', 'زيت نواة النخيل', 'يتم استخراج زيت نواة النخيل من لب ثمرة نخيل الزيت، ويستخدم في المنتجات الغذائية ومستحضرات التجميل والتطبيقات الصناعية.', 'زيت نواة النخيل مشتق من نواة ثمرة نخيل الزيت وله خصائص فيزيائية مميزة. عادةً ما يكون صلبًا لونه أصفر فاتح إلى أبيض في درجة حرارة الغرفة، لكنه يذوب ليصبح سائلاً واضحًا ومائلًا إلى الصفرة عند التسخين. تتراوح نقطة انصهاره من 23 إلى 28 درجة مئوية (73 إلى 82 درجة فهرنهايت). يُعد زيت نواة النخيل غنيًا بحمض اللوريك ويُستخدم على نطاق واسع في صناعة الأغذية، ومستحضرات التجميل، وصناعة الصابون.', '2026-02-11 17:21:24', '2026-02-11 17:21:24'),
(20, 'prod-palm-kernel-olein', 'زيت نخيل الكاولا', 'زيت النخيل المكرر premium، الجزء السائل الناتج من تقطير زيت نواة النخيل، يُقدر لصفائه العالي، ودرجته المنخفضة في نقطه الغيم، واستخداماته المتعددة في الصناعات الغذائية، والعناية الشخصية، والكيميائية الدهنية.', 'يوفر Bio Green Wax زيت النخيل المشتق من نخيل الزيت (PKOo) عالي الجودة، وهو الجزء السائل الناتج عن التكرير الانتقائي لزيت النخيل المعالج. عندما يُبرّد زيت النخيل تحت ظروف دقيقة، ينفصل إلى جزء صلب (الستيرين النخيل) وجزء سائل (زيت النخيل المليل). يكون الزيت الناتج واضحًا وبلون فاتح ويتميز بنقطة انصهار منخفضة وخصائص تصب جيدة.\n\nيتميز زيت النخيل المليل بغناه بحمض اللوريك (C12) والأحماض الدهنية من السلسلة الوسطى مثل حمض الكابريليك والكابريك، مما يمنحه وضوحًا استثنائيًا وامتصاصًا سريعًا وملمسًا خفيفًا غير دهني. تجعل هذه الخصائص منه خيارًا مرغوبًا في صناعة الأغذية كزيت للطهي، وسط للقلي، ومكونًا في الكريمرات غير الألبانية، والآيس كريم، وصيغ الحليب المحشو.\n\nوفي قطاع العناية الشخصية ومستحضرات التجميل، يُستخدم زيت النخيل المليل على نطاق واسع كزيت قاعدة في اللوشنات والكريمات والشامبو والصوابين السائلة نظرًا لخصائصه الممتازة كمطري وتوافقه مع البشرة. كما أنه يعد مادة خام رئيسية في إنتاج الوليهاكيميائيات، التي تنتج الأحماض الدهنية، والإسترات الميثيلية، والمواد الفاعلة السطحية المستخدمة في المنظفات ومنتجات التنظيف.\n\nيعتمد Bio Green Wax في الحصول على زيت النخيل المليل من سلاسل التوريد المعتمدة من RSPO، مما يضمن إمكانية التتبع الكامل والتوافق مع الالتزامات الخاصة بالزيت النجيـل المستدام. يتوفر المنتج في صورة معالَجة، مُبيّضة، ومخلوطة برائحة (RBD)، تلبية لمعايير الجودة الدولية الصارمة.', '2026-02-11 17:46:03', '2026-02-11 17:46:03'),
(21, 'prod-palm-kernel-stearin', 'ستيرين نواة النخيل', 'ستيران نواة النخيل عالي الجودة، الجزء الصلب الذي يُستخرج من تقطير زيت نواة النخيل، يُقدر لقوامه الذي يذوب بسرعة وصلابته الممتازة في صناعة الحلوى والمستحضرات التجميلية والتطبيقات اليوسيكيميائية.', 'يوو غرين وكس يوفر ستيرين نوى النخيل عالي الجودة (PKS)، وهو الجزء الصلب ذو نقطة الانصهار العالية الناتج عن التحديد والتحليل المنضبط لزيت نواة النخيل المكرر. خلال عملية التحديد، ينفصل زيت نواة النخيل إلى مكونين: أولين نواة النخيل (الجزء السائل) وستيرين نواة النخيل (الجزء الصلب). يكون الستيرين الناتج دهناً أبيض إلى مائل إلى الأبيض يتميز بنقطة انصهار حادة وملمس صلب.\n\nستيرين نواة النخيل غني بحمض اللوريك (C12) وحمض الميرистيك (C14)، مما يمنحه صلابة ممتازة وتبلور سريع ونقطة انصهار نظيفة. تجعل هذه الخصائص منه مكونًا مثاليًا للمستبدلات زبدة الكاكاو (CBS)، وغلافات الشوكولاتة المركبة، وحشوات الحلويات، والدهون الخاصة التي تتطلب لمسة وبياض لامع.\n\nوع beyond التطبيقات الغذائية، يُستخدم ستيرين نواة النخيل كمادة خام قيمة في صناعة الoleو كيميائية لإنتاج الأحماض الدهنية، والكحولات الدهنية، وشعيرات الصابون، والمركبات السطحية.وفي المستحضرات الشخصية ومستحضرات التجميل، يساهم في إعطاء الجسم والهيكلية للكريمات، واللوشنات، والصيغة الصلبة.\n\nتقوم شركة Bio Green Wax بتوريد ستيرين نواة النخيل من سلاسل إمداد معتمدة من RSPO، مما يضمن تتبع المنتج بالكامل والامتثال لالتزامات زيت النخيل المستدام. يتوفر المنتج في شكل مكرر، ومبيض، ومزيل للروائح (RBD)، ويلبي المعايير الدولية للجودة للاستخدام الغذائي والتقني.', '2026-02-11 17:20:25', '2026-02-11 17:20:25'),
(22, 'prod-palm-oil', 'زيت النخيل', 'زيت النخيل المستدام ومشتقاته', 'زيت النخيل المستخرج بشكل مستدام ومشتقاته لتصنيع الأغذية، وإنتاج الصابون والمنظفات. تتوفر خيارات معتمدة من RSPO.', '2026-02-05 21:50:40', '2026-02-11 17:28:26'),
(23, 'prod-palm-shortenings', 'زبدة النخيل (نقطة انصهار عالية)', 'زيوت النخيل ذات نقطة انصهار عالية (46–52 °م) هي زيوت مخصصة للمخابز والقلي مصنوعة من زيت النخيل المكرر، مصممة لإعطاء هيكل قوي، ونكهة نقية، واستقرار ممتاز في التحمل الحراري في التطبيقات الصناعية الصعبة.', 'السمنات النسيجية ذات نقطة الانصهار العالية التي تتراوح بين 46 و52 درجة مئوية، مصنوعة من ستيرين النخيل والكسور الوسيطة لتوفير محتوى عالي من الدهون الصلبة، وملمس متماسك، وشبكة بلورية مستقرة في درجات الحرارة المحيطة ودرجات الحرارة المرتفعة. توفر هذه النطاقات الأعلى للذوبان مقاومة فائقة للحرارة، واستقرارًا أكسديًا، وتقليل حدوث الزيت، مما يجعلها مناسبة تمامًا للمناخات الاستوائية وخطوط المعالجة ذات درجات الحرارة العالية.\n\nفي تطبيقات المخابز، تمنح هذه السمنات تهوية جيدة، وطبقات مرنة، وطية مكسرة، تدعم قشور الفطائر الهشة، والمعجنات المنتفخة، والبسكويت والكراكرز والكعك والبيتي فور، مع الحفاظ على الشكل والملمس حتى في الظروف الدافئة. كما تُستخدم أيضًا كدهون مقلاة متينة ودهون للعجائن، وكبدائل لدهون الحيوانات في منتجات اللحوم، حيث يسهم تركيبها الصلب، واستقرار المستحلبات، وخصائصها غير الحلقيّة، غير المحوّلة، في تحقيق قوام ثابت، وإطلاق نكهة نظيفة، وتركيبات ملصقات صديقة.', '2026-02-11 17:27:34', '2026-02-11 17:27:34'),
(24, 'prod-palm-stearic-acid', 'حمض الستيارك النخلي', 'حمض الستيارك البمالي هو حمض دهني مشبع مستخلص من زيت النخيل، يُستخدم في مستحضرات التجميل، والشموع، وتصنيع المطاط.', 'حمض الستيارك من النخيل هو نوع من الأحماض الدهنية المستخلصة من زيت النخيل، ويتم الحصول عليه من خلال عملية فصل وتبلور الأحماض الدهنية. وهو حمض دهني مشبع معروف باستقراره وشكله الصلب في درجة الحرارة العادية. يمتلك حمض الستيارك من النخيل مظهرًا شمعيًا يتراوح بين الأبيض والأصفر الفاتح. وله نقطة انصهار تتراوح عادة بين 55-70 درجة مئوية (131-158 درجة فهرنهايت)، مما يسهل دمجه في مختلف التركيبات الخاصة بمستحضرات التجميل، والشموع، ومنتجات المطاط.', '2026-02-11 17:39:22', '2026-02-11 17:39:22'),
(25, 'prod-palm-stearin', 'ستيارين النخيل', 'ستيرين النخيل هو الجزء الصلب من زيت النخيل، ويستخدم بشكل شائع في تصنيع الأغذية، وإنتاج الشموع، وصناعة الصابون.', 'ستيارين النخيل هو الجزء الصلب من زيت النخيل الذي يُستخرج من خلال عملية التكرير، وهو معروف بمحتواه العالي من الأحماض الدهنية المشبعة. وهو دهون صلبة في درجة حرارة الغرفة بلون أبيض كريمي إلى أصفر باهت وملمس ناعم ودهني. لدى ستيارين النخيل نقطة ذوبان أعلى مقارنة بزيت النخيل. يُستخدم بشكل شائع في صناعة الأغذية لتحقيق استقرار الدهون، وإنتاج المارجرين، وفي صناعة الشموع والصابون.', '2026-02-11 17:38:40', '2026-02-11 17:38:40'),
(26, 'prod-paraffin-wax', 'شمع البرافين المكرر بالكامل (50-68°C)', 'شمع Bio Green Wax المكرر بالكامل من البارافين (50-68°C) - درجة جودة غذائية/صناعية، <0.5% زيت، صلابة متفوقة. مثالي للشموع، والمستحضرات التجميلية، والتعبئة، والتطبيقات الصناعية الدقيقة.', 'شمع البارافين المكرر بالكامل من Bio Green Wax (نقطة انصهاره بين 50-68°C) يتميز بمحتوى زيوت منخفض جدًا (<0.5%)، وصلابة استثنائية، ورائحة ولون حياديين. يتوفر بأصناف الشموع (52/54°C و56/58°C)، وأصناف الحاويات (50/52°C)، وأصناف الأعمدة ذات نقطة انصهار عالية (64/66°C). مثالي للشموع الفاخرة، ومستحضرات التجميل، وطبقات تغليف التغليف الغذائي، وقياسات الصب الدقيقة التي تتطلب أعلى درجات النقاء وتوافق الأداء.', '2026-02-06 03:54:13', '2026-02-11 17:43:16'),
(27, 'prod-pf56-synthetic-wax', 'شمع فشر-تروبسش (FT)', 'شمع Fischer‑Tropsch (FT) هو شمع بارافيين اصطناعي عالي النقاء يُنتج من غاز الإيثان، ويتميز بنقطة انصهار عالية، لزوجة منخفضة، وصلابة ممتازة لتلبية الطلبات الصعبة في مجالات البلاستيك والطلاءات والأحبار واللاصق وتعديل القار', 'شمع FT يُنتج عبر عملية تخليق Fischer‑Tropsch، ويُنتج شمعًا شفافًا أبيض الماء، عالي النقاء، ذو توزيع ضيق لسلسلة الكربون، ومحتوى زيوت منخفض جدًا، واستقرار حراري ممتاز. يجمع بين نقطة انصهار عالية مع لزوجة انصهار منخفضة وصلابة قوية، مما يوفر مقاومة خدوش متفوقة، وتحكمًا في اللمعان، وتأثيرات مطفأة، وتزييت في العديد من التركيبات.\n\nفي معالجة البلاستيك وPVC/CPVC، يعمل شمع FT كواحد من مواد التزليق الداخلية والخارجية الفعالة، وساعد في عملية المعالجة، حيث يقلل من لزوجة الذوبان، ويحسن التدفق، ويساعد في إطلاق القالب واستقرار الأبعاد. يُستخدم على نطاق واسع في مواد اللصق الساخنة واللاصقات الحساسة للضغط، والأحبار الطباعية، والطلاءات الصناعية لزيادة الصلابة، ومقاومة التآكل والخدوش، ومقاومة الالتصاق، ومقاومة الترسيب مع استقرار اللزوجة. تشمل التطبيقات الرئيسية الإضافية تعديل البيتومين والإسفلت، وخلط الـmasterbatch والبوليمر، ومعالجة المطاط، والمواد اللامعة، والمنسوجات، وحتى التركيبات التجميلية، حيث يوفر شمع FT التبلُور المتحكم فيه، وتحسين مقاومة التآكل والتجاعيد، وإحساس ناعم وسلس.', '2026-02-06 04:15:57', '2026-02-11 17:44:09'),
(28, 'prod-pfad', 'PFAD (مقطر حمض دهني من نخيل البلح)', 'PFAD هو منتج ثانوي من تكرير زيت النخيل، يُستخدم في صناعة الصابون، وتغذية الحيوانات، وإنتاج الوقود الحيوي.', 'مُقطر الأحماض الدهنية من النخيل (PFAD) هو ناتج ثانوي من عملية تكرير زيت النخيل. يُحصل عليه من خلال تقطير زيت النخيل الخام لإزالة الشوائب وتحقيق مستوى أعلى من النقاء. يُعد PFAD سائلًا بني اللون مائلًا إلى الأصفر وله رائحة مميزة. يحتوي على مزيج من الأحماض الدهنية المشبعة وغير المشبعة، مع أن الأحماض الدهنية السائدة هي حمض اللوريك، وحمض الميرستيك، وحمض البالمتيك. يُستخدم PFAD في صناعة الصابون، وتغذية الحيوانات، وإنتاج الوقود الحيوي.', '2026-02-11 17:26:23', '2026-02-11 17:26:23'),
(29, 'prod-pkfad', 'مُكرر الأحماض الدهنية لزيت نواة النخيل (PKFAD)', 'PKFAD هو ناتج ثانوي من تكرير زيت نخيل التمر، غني بحمض اللوريك، ويستخدم في صناعات الصابون والكيماويات الدهنية.', 'مُركز حمض دهني النواة النخيل (PKFAD) هو منتج ثانوي يُستَخرج خلال تكرير زيت نواة النخيل. وهو غني بالأحماض الدهنية، بما في ذلك حمض اللوريك، مما يجعله ذا قيمة للتطبيقات الصناعية المحددة. يُستخدم PKFAD في العديد من التطبيقات الصناعية، بما في ذلك صناعة الصابون، وإنتاج الوقود الحيوي، وكمادة خام في صناعة الأوليوكيميائيات.', '2026-02-11 17:40:07', '2026-02-11 17:40:07'),
(30, 'prod-polyethylene-wax', 'شمع polyethlene (شمع PE)', 'البولي إيثيلين منخفض الوزن الجزيئي يُستخدم كمزلق عالي الأداء ومساعد في المعالجة في مجالات البلاستيك والطلاءات والأحبار والمواد اللاصقة، حيث يُحسن التدفق، وانزلاق السطح، ومقاومة الخدوش.', 'شمع البولي إيثيلين هو شمع اصطناعي دقيق التوزيع ذو نقطة انصهار عالية، ويتميز ب لزوجة منخفضة، واستقرار حراري ممتاز، وتوافق قوي مع البوليمرات الشائعة مثل PVC، PE، PP، و EVA. يوفر تزييتًا داخليًا وخارجيًا، يقلل من لزوجة الذوبان والاحتكاك، يعزز إطلاق القالب، ويمنح سطحًا أملسًا ولامعًا ومقاومًا للخدوش.\n​\n\nتشمل التطبيقات الرئيسية معالَجة البلاستيك والماستر باتش، حيث يُحسن شمع PE من كفاءة البثق والتشكيل بالحقن، ويمنع تراكم القالب، ويحسن توزيع الأصباغ والمملءات. كما يُستخدم في اللواصق الساخنة الذوبان واللواصق الحساسة للضغط، والأحبار، وطبقات الطلاء البودرة للتحكم في لزوجة الذوبان، وزيادة الترابط والمتانة، وتحسين أوقات الفتح والتثبيت. وتشتمل الاستخدامات الإضافية على القار ودهانات تحديد الطرق، والمواد المركبة من الخشب والبلاستيك، وخلطات المطاط، ومركبات الكابلات، ومنتجات الشمع المصاغة مثل الملمعات والألوان الشمعية، حيث يرفع نقطة الانصهار، والصلابة، ومقاومة الماء.', '2026-02-06 04:00:58', '2026-02-11 17:42:22'),
(31, 'prod-rapeseed-oil', 'زيت بذرة الكتان', 'زيت دوار الشمس المضغوط على البارد والمنقّى من مزارع المملكة المتحدة', 'زيت بذرة الكانولا المضغوط على البارد والمكرر من مزارع المملكة المتحدة. مثالي للطهي، والتحميص، وصلصات السلطة. منخفض في الدهون المشبعة وغني بأوميغا-3.', '2026-02-05 21:53:42', '2026-02-11 17:34:08'),
(32, 'prod-rapeseed-wax', 'شمع بذرة الكتان', 'شمع بذور الكنوك هو شمع نباتي طبيعي يُستخدم كبديل صديق للبيئة في صناعة الشموع ومستحضرات التجميل.', 'شمع بذرة اللفت هو شمع نباتي طبيعي مستخلص من زيت نبات اللفت، يُستخدم عادة كبديل صديق للبيئة لشمع البارافين التقليدي في صناعة الشموع وتطبيقات أخرى. فهو يوفر حرقًا نظيفًا وبطيئًا، بالإضافة إلى احتفاظ جيد بالعطر. يُستخدم شمع بذرة اللفت بشكل متكرر في إنتاج الشموع وفي تركيب المستحضرات الطبيعية مثل بلسم الشفاه، اللوشنات، والكريمات، حيث يمنح خصائصمرطبة.', '2026-02-11 17:24:15', '2026-02-11 17:24:15'),
(33, 'prod-soap-noodles', 'نودلز الصابون', 'شعيرات الصابون هي المواد الخام الأساسية لصناعة الصابون، وتُنتج من خلال صابون الأحماض الدهنية النباتية والزيوت.', 'شعيرات الصابون، المعروفة أيضًا بحبيبات الصابون، هي أحد المواد الخام الرئيسية المستخدمة في تصنيع الصابون. يتم إنتاجها عن طريق معالجة الزيوت والدهون النباتية مع هيدروكسيد الصوديوم (اللي) من خلال عملية التصبن. عادةً ما تكون شعيرات الصابون عبارة عن قطع أو خرز بيضاء أو ذات لون أملس، برائحة خفيفة ومحايدة. وخالية من الشوائب وتحتوي على تركيز عالي من الأحماض الدهنية التي تسهم في خصائصها في التنظيف والاستحلاب.', '2026-02-11 17:40:50', '2026-02-11 17:40:50'),
(34, 'prod-soy-wax', 'شمع الصويا', 'شمع الصويا هو شمع نباتي متجدد مصنوع من زيت الصويا، ويُعد شهيرًا في صناعة الشموع الصديقة للبيئة.', 'شمع الصويا هو نوع من الشموع النباتية المستمدة من زيت فول الصويا. يعتبر خيارًا شائعًا بديلًا لشمع البارافين التقليدي، الذي يتم استخراجه من النفط الخام. يُعتبر شمع الصويا خيارًا متجددًا وقابلًا للتحلل البيولوجي وبيئيًا لصناعة الشموع. يتم تصنيعه عن طريق هيدرة زيت فول الصويا، مما يحوله إلى شكل صلب مناسب للشموع. عادةً ما يأتي على شكل رقائق، والتي يسهل قياسها وذوبانها.', '2026-02-11 17:17:29', '2026-02-11 17:17:29'),
(35, 'prod-soybean-oil', 'زيت فول الصويا', 'زيت فول الصويا عالي الجودة للاستخدامات الصناعية والطهوية', 'زيت الصويا هو زيت نباتي متعدد الاستخدامات يُستخرج من فول الصويا، ويُستخدم على نطاق واسع في القلي والخبز وتتبيلات السلطات نظرًا لنكهته المحايدة ونقطة دُخان عالية.\nويُعد غنيًا بالدهون غير المشبعة المتعددة، بما في ذلك أحماض أوميغا‑3 وأوميغا‑6 الدهنية، ويوفر فيتامين ك وفيتامين هـ.\nوهو مثالي للقلي العميق، وإنتاج المارجرين، والتطبيقات الصناعية للأطعمة. مُكرر ومُزيل للروائح وفقًا لمعايير عالية الجودة.', '2026-02-05 21:50:40', '2026-02-11 17:29:06'),
(36, 'prod-sunflower-oil', 'زيت عباد الشمس', 'زيت عباد الشمس المكرر عالي الجودة للطهي ومعالجة الطعام', 'زيت دوار الشمس الممتاز المكرر لدينا مثالي للطهي والقلي وتطبيقات معالجة الطعام. مستخلص من بذور دوار الشمس عالية الجودة ومكرر بأعلى المعايير.', '2026-02-05 21:42:39', '2026-02-11 17:22:11');
INSERT INTO `products_de` (`id`, `master_id`, `name`, `description`, `full_description`, `created_at`, `updated_at`) VALUES
(1, 'bdf424df-f9b0-4a79-84d6-f6ed1eb1e84f', 'Palm Olein', 'Palmolenin ist die flüssige Fraktion des raffinierten Palmenöls, geschätzt als stabile Frittier- und Kochöl, das einen neutralen Geschmack, eine lange Bratdauer und eine knusprige Textur für Snacks, Fast Food und Anwendungen im Haushalt bietet.', 'Palm Olein wird durch Fraktionierung von raffiniertem, gebleichtem und deodoriertem (RBD) Palmöl hergestellt, um ein klares, flüssiges Produkt zu erhalten, das reich an Ölsäure und Palmitinsäure ist. Es bietet ein ausgewogenes Fettsäureprofil mit natürlicher guter Oxidationsstabilität. Sein hoher Rauchpunkt, seine Resistance gegen Oxidation und Polymerbildung sowie seine geringe Neigung, Off‑Geschmäcker zu entwickeln, ermöglichen wiederholte Frittierzyklen mit reduzierter Ölverschlechterung, weniger Schaumbildung und längerer Haltbarkeit der Endprodukte.\n​\nIn der Lebensmittelanwendung wird Palm Olein häufig als Frittiermedium für Snacks, Kartoffelchips, Hühnchen, Instant-Nudeln und vorfrittierte Tiefkühlprodukte eingesetzt, sowie als Allzweck- Kochöl im Haushalt in vielen tropischen Märkten. Es dient auch als Basisöl in Mischungen mit Sojaöl, Sonnenblumenöl oder anderen pflanzlichen Ölen, um maßgeschneiderte ernährungsphysiologische und funktionale Profile zu erzielen. Außerdem wird es in Margarinen, Backfett und Frittier systemen im Foodservice verwendet, bei denen stabile Leistung und reines Aroma entscheidend sind.', '2026-02-11 17:15:13', '2026-02-11 17:15:13'),
(2, 'prod-beeswax', 'Bienenwachs', 'Reines natürlicher Bienenwachs für Kosmetik und Kerzenherstellung', 'Reine natürliche Bienenwachsquelle von nachhaltigen Imkern. Perfekt für Kosmetik, Kerzenherstellung und Lebensmittelanwendungen. In verschiedenen Qualitätsstufen erhältlich.', '2026-02-05 21:57:24', '2026-02-11 17:29:48'),
(3, 'prod-bw101-palm-wax', 'Palmwachs', 'Premium 100% Palmenwachs mit cremig gelber Farbe, ideal für die Kerzenherstellung. RSPO SG (Segregated) / MB (Mass balance) zertifiziert.', 'Premium 100% Palmenwachs mit einer schönen cremiggelben Farbe. RSPO MB zertifiziert für Nachhaltigkeit. Ideal für die Kerzenherstellung, Gießen und Containerkerzen.', '2026-02-05 22:04:52', '2026-02-11 17:45:26'),
(4, 'prod-bw105-palm-wax', 'Palmfette (niedriger Schmelzpunkt)', 'Palm Shortening ist ein halbfestes, nicht-hydrierendes Fett, das aus fraktioniertem Palmöl gewonnen wird und eine überlegene Stabilität sowie einen neutralen Geschmack bietet.', 'Palm Shortening ist ein halbfestes, nicht-hydrogeniertes Fett, das aus fraktioniertem Palmöl gewonnen wird und eine hervorragende Stabilität sowie neutralen Geschmack bietet.  \nPerfekt für Bäckerei-Anwendungen – sorgt für blättrige Gebäck, zarte Kuchen und knusprige frittierte Speisen mit hohem Rauchpunkt.  \nKostenersparnis, oxidationsresistente Alternative zu Butter oder Schmalz im industriellen Bäckereihandwerk.', '2026-02-06 02:26:23', '2026-02-11 17:31:08'),
(5, 'prod-bw10510-blended-wax', 'Palm-Paraffin-Gemischwachs für Glas-Teelichter', 'Fertige Low MP Jar Candle Blend: Palm-Paraffin-Microcrystalline mit Polyboost™, Vybar® und UV-Stabilisatoren—einfach Farbe und Duft hinzufügen für eine hervorragende Glashaftung und maximale Duftentfaltung.', 'Bio Green Wax\'s Low Melting Point Jar Candle Blend (48-50°C) und (50-52°C) — Palm-Paraffin-Microcrystalline-Formulierung, optimiert für Glasbehälter. Fertig zur Verwendung: nur Farb- und Duftstoffe hinzufügen. Enthält Polyboost/Vybar für Opazität/Haftung, UV-Stabilisatoren/Antioxidantien für die Haltbarkeit, sowie Duftstoffretentionsmittel, die außergewöhnlichen Hot-/Cold-Throw, knitterfreien Brand und ausgezeichnete Haltbarkeit im Glas für Premium-Containerkerzen gewährleisten.', '2026-02-06 03:36:27', '2026-02-11 17:37:14'),
(6, 'prod-bw10555-blended-wax', 'Soja-basierte vegane Wachsmischung', 'Fertiger 95% Soja-Vegan-Mischung von Bio Green Wax—rein pflanzlich für Kerzen im Glas (48-52 °C) & Säulenkerzen (56-62 °C). Einfach Farbe & Duft hinzufügen.', 'Bio Green Wax\'s 95% Sojawachs-Veganmischung (5% Pflanzenzusätze) bietet sauberes Brennverhalten und natürliche Performance für Gläser und freistehende Säulen. Erhältlich in niedrig schmelzender Variante (48-52°C) für Behälter und hoch schmelzender Variante (56-62°C) für Säulen. Fertig zur Verwendung: Fügen Sie einfach Ihre Farbe und Ihren Duft hinzu für eine hervorragende Duftwirkung und ein glattes Finish.', '2026-02-06 03:43:54', '2026-02-11 17:31:55'),
(7, 'prod-bw10610-blended-wax', 'Palm-Paraffin-Gemischwachs für Säulenzünder', 'Fertig zum Gebrauch Hoch-MP-Säulenkerzenmischungen (56-58 °C & 58-60 °C): Palm-Paraffin-Mikrokristall with Polyboost™, Vybar®, UV-Stabilisatoren—einfach Farbe & Duft hinzufügen für überlegene Säulenleistung.', 'Bio Green Wax\'s High Melting Point Pillar Candle Blends (56-58°C & 58-60°C)—Palm-Paraffin-Mikrokristalline-Formulierungen, die für freistehende Säulendochte entwickelt wurden. Fertig zur Verwendung: Nur noch Farbe & Duft hinzufügen. Mit Polyboost/Vybar für den Gießformenablösungs- und Opazitätseffekt optimiert, UV-Stabilisatoren/Antioxidantien für eine verlängerte Haltbarkeit, sowie Duftretentionsmittel, die eine außergewöhnliche Hitze- und Kältespannung, eine perfekte Säulenformbeständigkeit und ein sauberes Brennen gewährleisten.', '2026-02-06 03:40:03', '2026-02-11 17:38:03'),
(8, 'prod-bw10655-blended-wax', 'Soy- Bienenwachs- Paraffinwachs-Mischung', 'Fertige Soja-Bienenwachs-Paraffin-Mischung von Bio Green Wax—ultativ für Duftabgabe bei Glas (48-52 °C) & Säulenkerzen (56-62 °C). Einfach Duft und Farbe hinzufügen.', 'Bio Green Wax\'s Soja-Bienenwachs-Paraffin-Gemisch vereint die natürliche Sanftheit von Soja, die Stabilität von Bienenwachs und die Duftkraft von Paraffin für eine unvergleichliche Duftleistung. Der niedrige Schmelzpunkt (48-52°C) eignet sich hervorragend für Glasbehälter; der hohe Schmelzpunkt (56-62°C) ist perfekt für Säulen. Bereits fertige Formulierung – einfach Duftstoff und Farbe hinzufügen für eine überlegene Wärme- und Kaltduftabgabe sowie ein makelloses Kerzenausblenden.', '2026-02-06 03:47:21', '2026-02-11 17:32:47'),
(9, 'prod-bw8307-blended-wax', 'Kokos-Öl-Rapswachs-Mischung', 'Fertig verwendbare Kokos-Rapsmischung von Bio Green Wax—cremige natürliche Leistung für Glasgefäßkerzen (48-52°C) & Säulenkernkerzen (56-62°C). Nur Farbe & Duft hinzufügen.', 'Bio Green Wax\'s Coconut-Rapeseed Blend kombiniert die cremige Textur von Kokoswachs und das gleichmäßige Abbrennen von Rapswachs für eine außergewöhnliche natürliche Kerzenleistung. Niedriger Schmelzpunkt (48-52°C), optimiert für Teelichter; hoher Schmelzpunkt (56-62°C) für Säulenkerzen. Völlig einsatzbereit—nur Ihre Wahl von Farbe und Duft hinzufügen für professionelle, sauber brennende Ergebnisse.', '2026-02-06 03:51:15', '2026-02-11 17:33:34'),
(10, 'prod-carnauba-wax', 'Carnaubawachs', 'Premium-Brazilianische Carnaubawachs für Polituren und Beschichtungen', 'Premium brasilianisches Carnaubawachs, bekannt als die „Königin der Wachse“. Ideal für Autopolitur, Kosmetika und Lebensmittelbeschichtungen. Höchster natürlicher Schmelzpunkt.', '2026-02-05 22:00:49', '2026-02-11 17:30:25'),
(11, 'prod-castor-oil', 'Rizinusöl', 'Premium kaltgepresstes Rizinusöl, gewonnen aus den Samen von Ricinus communis, das vielfältig in Pharma, Kosmetik und industriellen Anwendungen eingesetzt wird.', 'Bio Green Wax liefert hochwertiges Rizinusöl, ein vielseitiges pflanzliches Öl, das durch Pressung der Samen der Rizinusbaumpflanze (Ricinus communis) gewonnen wird. Bekannt für seine einzigartige chemische Zusammensetzung, die reich an Ricinolsäure (etwa 85–90 %) ist, weist Rizinusöl außergewöhnliche Viskositäts-, Schmier- und Feuchtigkeitsbindereigenschaften auf, die es in einer Vielzahl von Branchen unentbehrlich machen.\n\nUnser Rizinusöl wird sorgfältig beschafft und verarbeitet, um höchste Reinheits- und Qualitätsstandards zu erfüllen. Es ist sowohl in kaltgepresster (Virgin) als auch in raffinierten Qualitäten erhältlich und eignet sich für pharmazeutische, kosmetische und industrielle Anwendungen. Die bemerkenswerte Stabilität des Öls und seine Löslichkeit in Alkohol unterscheiden es von anderen pflanzlichen Ölen und machen es zu einer bevorzugten Zutat in Formulierungen, die herausragende Leistung erfordern.\n\nRizinusöl ist auf natürliche Weise biologisch abbaubar und stammt aus erneuerbaren Ressourcen, was das Engagement von Bio Green Wax für nachhaltige und umweltverantwortliche Beschaffung unterstreicht.', '2026-02-11 17:16:12', '2026-02-11 17:16:12'),
(12, 'prod-coconut-oil', 'Kokosöl', 'Virgin und raffiniertes Kokosöl für Lebensmittel- und Kosmetik-Anwendungen', 'Premium, virgines und raffiniertes Kokosöl, geeignet zum Kochen, Backen und für kosmetische Anwendungen. Erhältlich in verschiedenen Qualitäten, um Ihren spezifischen Anforderungen gerecht zu werden.', '2026-02-05 21:50:26', '2026-02-11 17:16:58'),
(13, 'prod-coconut-wax', 'Kokoswachs', 'Kokoswachs ist ein natürliches Wachs, das aus Kokosöl gewonnen wird und sich durch sauberes Brennen und umweltfreundliche Anwendungen auszeichnet.', 'Kokoswachs ist ein natürliches Wachs, das aus dem Öl von Kokosnüssen gewonnen wird und für einen sauberen und langsamen Brennverlauf bei der Kerzenherstellung bekannt ist. Es wird oft als nachhaltige Alternative zu anderen Wachsen angesehen. Kokoswachs wird wegen seiner umweltfreundlichen Eigenschaften und seiner Fähigkeit, Duftstoffe gut zu halten, geschätzt. Es stammt aus einer natürlichen und erneuerbaren Ressource, sorgt für einen sauberen und langsamen Brennvorgang in Kerzen und bietet eine längere und effizientere Brenndauer.', '2026-02-11 17:25:46', '2026-02-11 17:25:46'),
(14, 'prod-fr5456-paraffin-wax', 'Halbraffiniertes Paraffinwachs (50-68°C)', 'Bio Green Wax Semi Refined Paraffin (50-68°C)—kostengünstiger Paraffin mit 1-5 % Ölgehalt für Kerzen, Gummi, Textilien und hochvolumige Industrieanwendungen.', 'Bio Green Wax\'s semi-raffinierten Paraffinwachse (50-68°C) bieten wirtschaftliche Leistung mit kontrolliertem Ölgehalt (1-5%) für flexible Härte. Standardqualitäten: 52/54°C (Kerzen), 56/58°C (Säulen), 60/62°C (industriell). Perfekt für kostenbewusste Kerzenproduktion, Gummi-Verarbeitungszusätze, Textil-Finish und Schüttgutverpackungsbeschichtungen, bei denen ausgewogene Leistung und Preis im Vordergrund stehen.', '2026-02-06 04:05:28', '2026-02-11 17:23:39'),
(15, 'prod-glycerine', 'Glyzerin', 'Glycerin ist eine farblose, geruchslose, viskose Flüssigkeit, die in der Pharma-, Kosmetik- und Lebensmittelindustrie extensively eingesetzt wird.', 'Glycerin, auch bekannt als Glycerol oder Glycerin, ist eine farblose, geruchlose und viskose Flüssigkeit mit süßlichem Geschmack. Es handelt sich um eine klare, sirupartige Flüssigkeit, die in der Regel farb- kaum gelblich gefärbt ist. Glycerin weist eine hohe Viskosität auf, was bedeutet, dass es langsam fließt und relativ zäh ist. Es hat eine zähflüssige Konsistenz, die dazu beiträgt, Feuchtigkeit zu speichern. Glycerin wird umfangreich in Pharmazeutika, Kosmetika, der Lebensmittelverarbeitung und in verschiedenen industriellen Anwendungen eingesetzt.', '2026-02-11 17:19:41', '2026-02-11 17:19:41'),
(16, 'prod-hydrogenated-castor-oil', 'Hydrogenisiertes Rizinusöl', 'Hydrogeniertes Rizinusöl ist ein fester, wachshafter Derivat von Rizinusöl, das in Kosmetika, Arzneimitteln und industriellen Anwendungen verwendet wird.', 'Hydrierte Rizinusöl, auch bekannt als Rizinwax oder Rizinwax-Flake, ist ein Derivat von Rizinusöl, das einem Hydrogenierungsprozess unterzogen wurde. Dabei wird Wasserstoff zu den Rizinusölmolekülen hinzugefügt, was zu einer festen, waxartigen Substanz führt. Es wird in Kosmetik- und Pflegeprodukten wie Lippenstiften, Cremes und Lotionen als Emolliens verwendet, um die Haut geschmeidig und mit Feuchtigkeit zu versorgen. Zudem wirkt es als Bindemittel in kosmetischen Formulierungen, hilft dabei, die Inhaltsstoffe zusammenzuhalten und auf der Haut haften zu bleiben.', '2026-02-11 17:25:05', '2026-02-11 17:25:05'),
(17, 'prod-microcrystalline-wax', 'Mikrokristalline Wachs', 'Flexibler mikrokrystalliner Wachs für Kosmetika und Klebstoffe', 'Flexible mikrokristalline Wachse ideal für Kosmetika, Heißschmelzklebstoffe und Spezialbeschichtungen. Überlegene Flexibilität und Haftvermögen.', '2026-02-06 03:58:07', '2026-02-11 17:22:59'),
(18, 'prod-olive-oil', 'Olivenöl', 'Premium-Qualität reines Olivenöl, kaltgepresst aus ausgewählten Mediterranen Oliven, geeignet für kulinarische, kosmetische und industrielle Anwendungen.', 'Unser hochwertiges natives Olivenöl extra wird kaltgepresst aus sorgfältig ausgewählten mediterranen Oliven und bietet außergewöhnliche Qualität und intensiven Geschmack. Olivenöl wird vielfältig in der Lebensmittelzubereitung, Kosmetik, Pharmazie und Pflegeprodukte verwendet und ist wegen seiner gesundheitlichen Vorteile, antioxidativen Eigenschaften und vielseitigen Einsatzmöglichkeiten geschätzt. Bio Green Wax bezieht Olivenöl, das strenge internationale Qualitätsstandards erfüllt, um eine gleichbleibende Reinheit und Leistungsfähigkeit in allen Anwendungen zu gewährleisten.', '2026-02-11 17:41:42', '2026-02-11 17:41:42'),
(19, 'prod-palm-kernel-oil', 'Palmkernelöl', 'Palmkernöl wird aus dem Kern der Ölpalmenfrucht gewonnen und in Lebensmitteln, Kosmetika und industriellen Anwendungen verwendet.', 'Palmöl aus Palmkern ist ein Produkt, das aus dem Kern der Ölpalmenfrucht gewonnen wird und spezifische physikalische Eigenschaften aufweist. Es ist in der Regel bei Raumtemperatur eine hellgelbe bis weiße Feststoffmasse, schmilzt jedoch bei Erwärmung zu einer klaren, gelblichen Flüssigkeit. Der Schmelzpunkt liegt zwischen 23 und 28 Grad Celsius (73 bis 82 Grad Fahrenheit). Palmöl aus Palmkernen ist reich an Laurinsäure und wird häufig in der Lebensmittelherstellung, Kosmetik sowie Seifenproduktion verwendet.', '2026-02-11 17:21:33', '2026-02-11 17:21:33'),
(20, 'prod-palm-kernel-olein', 'Palmketten-Öline', 'Premium raffiniertes Palmkerneöl-olein, die flüssige Fraktion, die aus der Fraktionierung von Palmkerneöl gewonnen wird, geschätzt für ihre hervorragende Klarheit, niedrigen Wolkepunkt und vielseitige Verwendung in der Lebensmittel-, Körperpflege- und Oleochemieindustrie.', 'Bio Green Wax liefert hochqualitative Palmkernelöl-olein (PKOo), die flüssige Fraktion, die durch die kontrollierte Fraktionierung von raffiniertem Palmkernelöl gewonnen wird. Wenn Palmkernelöl unter präzisen Bedingungen gekühlt wird, trennt es sich in eine Feststofffraktion (Palmkernelstearin) und eine Flüssigfraktion (Palmkernelolein). Das resultierende Olein ist ein klares, hell gefärbtes Öl mit niedrigem Schmelzpunkt und ausgezeichneter Fließfähigkeit.\n\nPalmkernelolein ist reich an Mandylsäure (C12) sowie mittelkettigen Caprinsäure/Caprylsäure, was ihm eine herausragende Klarheit, schnelle Absorption und ein leichtes, nicht fettendes Gefühl verleiht. Diese Eigenschaften machen es in der Lebensmittelindustrie äußerst begehrt als Speiseöl, Bratmedium sowie als Bestandteil in nicht-milchhaltigen Cremes, Eiscreme und gefüllten Milchprodukten.\n\nIm Bereich der Körperpflege und Kosmetik wird Palmkernelolein aufgrund seiner hervorragenden emollierenden Eigenschaften und Hautverträglichkeit vielfältig als Basisöl in Lotionen, Cremes, Shampoos und Flüssigseifen eingesetzt. Es dient außerdem als wichtiger Rohstoff in der Oleochemieproduktion, aus der Fettsäuren, Methylester und Tenside gewonnen werden, die in Reinigungsmitteln und Putzmitteln Verwendung finden.\n\nBio Green Wax bezieht sein Palmkernelolein aus RSPO-zertifizierten Lieferketten, die vollständige Rückverfolgbarkeit und die Einhaltung nachhaltiger Palmöl-Engagements gewährleisten. Das Produkt ist in raffiniert, gebleicht und deodoriert (RBD) erhältlich und erfüllt strenge internationale Qualitätsstandards.', '2026-02-11 17:46:15', '2026-02-11 17:46:15'),
(21, 'prod-palm-kernel-stearin', 'Palmkern-Stearin', 'Hochwertiges Palmkernel-Stearin, die feste Fraktion, die aus der Fraktionierung von Palmöl gewonnen wird, geschätzt aufgrund seines ausgeprägten Schmelzprofils und hervorragender Härte in Süßwaren-, Kosmetik- und Oleochemieanwendungen.', 'Bio Green Wax liefert hochwertige Palmkerne Stearin (PKS), die feste Fraktion mit höheren Schmelzpunkten, die durch die kontrollierte Fraktionierung von raffiniertem Palmöl gewonnen wird. Während der Fraktionierung wird Palmöl in zwei Komponenten getrennt: Palmkerne Olein (die flüssige Fraktion) und Palmkerne Stearin (die feste Fraktion). Das resultierende Stearin ist ein weißer bis elfenbeinfarbener Fettstoff mit einem charakteristisch scharfen Schmelzpunkt und fester Textur.\n\nPalmkerne Stearin ist reich an Laurinsäure (C12) und Myristinsäure (C14), was ihm hervorragende Härte, schnelle Kristallisation und ein klares Schmelzverhalten verleiht. Diese Eigenschaften machen es zu einer idealen Zutat für Kakaobutter-Substitute (CBS), Duftschokoladenüberzüge, Füllungen für Süßwaren und Spezialfette, bei denen ein knackiges Finish und Glanz gefragt sind.\n\nNeben Anwendungen in der Lebensmittelindustrie dient Palmkerne Stearin auch als wertvoller Rohstoff in der Oleochemie für die Herstellung von Fettsäuren, Fetalkoholen, Seifen-Nudeln und Tensiden. In der Körperpflege und Kosmetik trägt es zu Körper und Struktur in Cremes, Lotionen und festen Formulierungen bei.\n\nBio Green Wax bezieht sein Palmkerne Stearin aus RSPO-zertifizierten Lieferketten, die vollständige Rückverfolgbarkeit und die Einhaltung nachhaltiger Palmölengagements gewährleisten. Das Produkt ist in raffiniert, gebleicht und deodorisiert (RBD) erhältlich und erfüllt internationale Qualitätsstandards für Lebensmittel- und technische Verwendung.', '2026-02-11 17:20:37', '2026-02-11 17:20:37'),
(22, 'prod-palm-oil', 'Palmöl', 'Nachhaltig bezogene Palmkernöl und Palmderivate', 'Nachhaltig gewonnene Palmöl und Palmölderivate für die Lebensmittelherstellung, Seifen- und Waschmittelproduktion. RSPO-zertifizierte Optionen verfügbar.', '2026-02-05 21:50:40', '2026-02-11 17:28:34'),
(23, 'prod-palm-shortenings', 'Palm Shortenings (hoher Schmelzpunkt)', 'Hochschmelzende Palmfette (46–52 °C) sind Spezialbäckerei- und Frittierfette, die aus fraktioniertem Palmöl hergestellt werden. Sie sind darauf ausgelegt, eine stabile Struktur, einen reinen Geschmack und eine ausgezeichnete Hitzestabilität in anspruchsvollen industriellen Anwendungen zu gewährleisten.', 'Hochschmelzende Palmfetters im Bereich von 46–52 °C werden aus Palmfettstearin und Mittelfraktionen hergestellt, um einen hohen Feststoffgehalt, eine feste Textur und ein stabiles Kristallgitter bei Raumtemperatur und erhöhten Temperaturen zu gewährleisten. Dieser höhere Schmelzbereich bietet überlegene Hitzebeständigkeit, oxidative Stabilität und eine reduzierte Öläusströmmung, was sie ideal für tropische Klimazonen und Hochtemperatur-Verarbeitungsanlagen macht.\n\n​\n\nIn Backanwendungen sorgen diese Fette für gute Aeration, Laminierung und Bruchfestigkeit und unterstützen mürbe Teigkrusten, Blätterteig, Cracker, Kekse und Biscuit, während sie ihre Form und Biss auch bei warmen Bedingungen beibehalten. Sie werden auch als robuste Frittier- und Teigfette sowie als Tierfett-Alternativen in Fleischprodukten eingesetzt, wobei ihre feste Struktur, Emulsionsstabilität und das zero‑trans, nicht gehärtete Profil helfen, eine gleichmäßige Textur, einen sauberen Geschmack und eine etikettenfreundliche Formulierung zu erreichen.', '2026-02-11 17:27:45', '2026-02-11 17:27:45'),
(24, 'prod-palm-stearic-acid', 'Palm-Stearinsäure', 'Palmiste Stearinsäure ist eine gesättigte Fettsäure, die aus Palmöl gewonnen wird und in Kosmetika, Kerzen und der Gummiherstellung verwendet wird.', 'Palm-Stearinsäure ist eine Art Fettsäure, die aus Palmöl gewonnen wird und durch den Prozess der Trennung und Kristallisation der Fettsäuren hergestellt wird. Es handelt sich um eine gesättigte Fettsäure, die für ihre Stabilität und ihre feste Form bei Raumtemperatur bekannt ist. Palm-Stearinsäure hat ein waxartiges Erscheinungsbild, das von Weiß bis leicht gelblich reicht. Sie hat einen Schmelzpunkt, der typischerweise zwischen 55-70 Grad Celsius (131-158 Grad Fahrenheit) liegt, was ihre einfache Einbindung in verschiedene Formulierungen für Kosmetika, Kerzen und Gummi-Produkte ermöglicht.', '2026-02-11 17:39:31', '2026-02-11 17:39:31'),
(25, 'prod-palm-stearin', 'Palm Stearin', 'Palmestearin ist die feste Fraktion des Palmöls, die häufig in der Lebensmittelherstellung, Kerzenproduktion und Seifenherstellung verwendet wird.', 'Palmstearin ist eine Festphase des Palmöls, die durch das Fraktionierungsverfahren gewonnen wird und bekannt ist für ihren hohen Gehalt an gesättigten Fettsäuren. Es ist ein festes Fett bei Raumtemperatur mit einer cremig weißen bis blassgelben Farbe und einer glatten, wachsartigen Textur. Palmstearin hat einen höheren Schmelzpunkt im Vergleich zu Palmöl. Es wird häufig in der Lebensmittelindustrie zur Stabilisierung von Fetten, zur Herstellung von Margarine sowie in der Produktion von Kerzen und Seifen verwendet.', '2026-02-11 17:38:49', '2026-02-11 17:38:49'),
(26, 'prod-paraffin-wax', 'Vollständig raffiniertes Paraffinwachs (50-68°C)', 'Bio Green Wax Vollraffinierter Paraffin (50-68°C)—Lebensmittel-/Pharmaqualität, <0,5% Öl, überlegene Härte. Perfekt für Kerzen, Kosmetik, Verpackungen und präzise industrielle Anwendungen.', 'Bio Green Wax\'s vollständig raffinate Paraffinwachs (Schmelzpunkte 50-68°C) zeichnen sich durch extrem niedrigen Ölgehalt (<0,5 %), außergewöhnliche Härte und neutralen Geruch sowie Farbe aus. Erhältlich in Kerzenqualität (52/54°C, 56/58°C), Containerqualität (50/52°C) und Hochschmelzsäulequalitäten (64/66°C). Ideal für Premiumkerzen, Kosmetika, Lebensmittelverpackungsbeschichtungen und Präzisionsformen, die maximale Reinheit und gleichbleibende Leistung erfordern.', '2026-02-06 03:54:40', '2026-02-11 17:43:25'),
(27, 'prod-pf56-synthetic-wax', 'Fischer-Tropsch (FT) Wachs', 'Fischer‑Tropsch (FT) Wachs ist ein hochwertiges synthetisches Paraffinwachs, das aus Synthesegas hergestellt wird. Es zeichnet sich durch hohe Schmelzpunkte, geringe Viskosität und ausgeprägte Härte aus und eignet sich für anspruchsvolle Anwendungen in Kunststoffen, Beschichtungen, Tinten, Klebstoffen und Bitumenmodifikation.', 'FT-Wachs wird durch die Fischer-Tropsch-Synthese hergestellt und ergibt einen wasserweißen, superreinen Wachs mit einer engen Carbon-Kettenverteilung, sehr niedrigem Ölgehalt und ausgezeichneter thermischer Stabilität. Es vereint einen hohen Softening Point mit niedriger Schmelzviskosität und hoher Härte, was zu einem überlegenen Kratzschutz, Glanzkontrolle, Mattierungseffekten und Schmierung in vielen Formulierungen führt.\n\nIn der Kunststoff- und PVC/CPVC-Verarbeitung wirkt FT-Wachs als effizientes internes und externes Schmiermittel sowie Verarbeitungshilfe, reduziert die Schmelzviskosität, verbessert den Fluss und fördert den Mold Release sowie die Dimensionsstabilität. Es wird häufig in Heißschmelzklebstoffen, druckempfindlichen Klebstoffen, Druckfarben und Industrielackierungen eingesetzt, um die Härte, Abrieb- und Kratzfestigkeit, Blockwiderstand und Anti-Absetz-Eigenschaften zu erhöhen und gleichzeitig die Viskosität zu stabilisieren. Weitere wichtige Anwendungen sind die Modifikation von Bitumen und Asphalt, Masterbatch- und Polymerkompoundierung, Gummi-Verarbeitung, Polituren, Textilien und sogar kosmetische Formulierungen, bei denen FT-Wachs kontrollierte Kristallinität, verbesserte Verschleiß- und Faltenresistenz sowie ein glattes sensorisches Hautgefühl bietet.', '2026-02-06 04:16:38', '2026-02-11 17:44:19'),
(28, 'prod-pfad', 'PFAD (Palmfett-Ölsäuredistillat)', 'PFAD ist ein Nebenprodukt der Palmölraffination und wird in der Seifenherstellung, in der Tierfütterung sowie bei der Produktion von Biokraftstoffen verwendet.', 'Palm-Fettsäuredistillat (PFAD) ist ein Nebenprodukt des Palmöl-Refineringsprozesses. Es wird durch Destillation von Rohpalmenöl gewonnen, um Verunreinigungen zu entfernen und einen höheren Reinheitsgrad zu erreichen. PFAD ist eine bräunlich-gelbe Flüssigkeit mit charakteristischem Geruch. Es enthält eine Mischung aus gesättigten und ungesättigten Fettsäuren, wobei die vorherrschenden Fettsäuren Laurinsäure, Myristinsäure und Palmitinsäure sind. PFAD wird in der Seifenherstellung, in der Tierfutterproduktion und bei der Herstellung von Biokraftstoffen eingesetzt.', '2026-02-11 17:26:34', '2026-02-11 17:26:34'),
(29, 'prod-pkfad', 'Palm-Kernfettfettsäuredestillat (PKFAD)', 'PKFAD ist ein Nebenprodukt der Raffination von Palmkernölfett, reich an Laurinsäure und in der Seifen- sowie der Oleochemieindustrie vielfältig eingesetzt.', 'Palm Kernel Fatty Acid Distillate (PKFAD) ist ein Nebenprodukt, das bei der Raffinierung von Palmkernelöl entsteht. Es ist reich an Fettsäuren, einschließlich Laurinsäure, was es für bestimmte industrielle Anwendungen wertvoll macht. PKFAD wird in verschiedenen industriellen Anwendungen eingesetzt, darunter Seifenherstellung, Biokraftstoffproduktion und als Rohstoff in der Oleochemieindustrie.', '2026-02-11 17:40:15', '2026-02-11 17:40:15'),
(30, 'prod-polyethylene-wax', 'Polyethylenwachs (PE-Wachs)', 'ist ein Polyethylen mit niedrigem Molekulargewicht, das als Hochleistungs-Schmiermittel und Verarbeitungshilfe in Kunststoffen, Beschichtungen, Tinten und Klebstoffen eingesetzt wird, um Fließfähigkeit, Oberflächenrutschfähigkeit und Kratzfestigkeit zu verbessern.', 'Polyethylenwachs ist ein fein verteiltes, hoch schmelzendes synthetisches Wachs mit niedriger Viskosität, ausgezeichneter thermischer Stabilität und starker Kompatibilität mit gängigen Polymeren wie PVC, PE, PP und EVA. Es sorgt für Innen- und Außenlubrikation, reduziert die Schmelzviskosität und Reibung, verbessert den Formtastersatz und liefert eine glatte, glänzende und kratzfeste Oberfläche.\n​\n\nWichtige Anwendungsbereiche sind die Verarbeitung von Kunststoffen und Masterbatch, wobei PE-Wachs die Extrusions- und Spritzgießeffizienz verbessert, die Einlaufbildung im Werkzeug verhindert und die Dispersion von Pigmenten und Füllstoffen optimiert. Es wird auch in Schmelzklebstoffen und druckempfindlichen Klebstoffen, Tinten sowie Pulverlacken eingesetzt, um die Schmelzviskosität zu steuern, die Kohäsion und Zähigkeit zu erhöhen und die Offen- und Aushärtezeiten zu optimieren. Weitere Verwendungszwecke umfassen Bitumen und Straßenmarkierungsfarben, Holz-Kunststoff-Verbundwerkstoffe, Gummi-Compoundierungen, Kabelmischungen sowie formulierte Wachssorten wie Polituren und Wachsmalstifte, wobei es den Schmelzpunkt, die Härte und die Wasserresistenz erhöht.', '2026-02-06 04:01:33', '2026-02-11 17:42:32'),
(31, 'prod-rapeseed-oil', 'Rapsöl', 'Kaltgepresstes und raffiniertes Rapsöl von britischen Feldern', 'Kaltgepresstes und raffiniertes Rapsöl aus UK-Bauernhöfen. Ideal zum Kochen, Rösten und für Salatdressings. Wenig gesättigte Fettsäuren und reich an Omega-3.', '2026-02-05 21:54:22', '2026-02-11 17:34:15'),
(32, 'prod-rapeseed-wax', 'Rapswachs', 'Rapswachs ist ein natürliches pflanzliches Wachs, das als umweltfreundliche Alternative in der Kerzenherstellung und Kosmetik verwendet wird.', 'Rapswachs ist ein natürliches pflanzliches Wachs, das aus dem Öl der Raps-Pflanze gewonnen wird. Es wird häufig als umweltfreundliche Alternative zu herkömmlichem Paraffinwachs beim Kerzenmachen und in anderen Anwendungen verwendet. Es bietet eine saubere und langanhaltende Brenndauer sowie eine gute Duftaufnahme. Rapswachs wird häufig in der Kerzenherstellung und bei der Entwicklung von Naturkosmetik wie Lippenbalsamen, Lotionen und Cremes eingesetzt, wobei es feuchtigkeitsspendende Eigenschaften bietet.', '2026-02-11 17:24:22', '2026-02-11 17:24:22'),
(33, 'prod-soap-noodles', 'Seifen-Nudeln', 'Seifenstränge sind die primären Rohstoffe für die Seifenherstellung, die durch Verseifung von pflanzlichen Ölen und Fetten entstehen.', 'Seifen-Nudeln, auch bekannt als Seifen-Granulate, sind eine der wichtigsten Rohstoffe bei der Herstellung von Seife. Sie werden durch die Verarbeitung von pflanzlichen Ölen und Fetten mit Natriumhydroxid (Lauge) mittels Verseifung hergestellt. Seifen-Nudeln sind typischerweise feste weiße oder elfenbeinfarbene Stücke oder Perlen mit einem milden und neutralen Aroma. Sie sind frei von Verunreinigungen und enthalten eine hohe Konzentration an Fettsäuren, die zu ihren reinigenden und emulgierenden Eigenschaften beitragen.', '2026-02-11 17:40:59', '2026-02-11 17:40:59'),
(34, 'prod-soy-wax', 'Sojawachs', 'Sojawachs ist ein erneuerbares pflanzliches Wachs, das aus Sojabohnenöl hergestellt wird und sich großer Beliebtheit bei umweltfreundlicher Kerzenherstellung erfreut.', 'Sojawachs ist eine Art pflanzliches Wachs, das aus Sojaöl gewonnen wird. Es ist eine beliebte Alternative zu herkömmlichem Paraffinwachs, das aus Erdöl hergestellt wird. Sojawachs gilt als erneuerbare, biologisch abbaubare und umweltfreundliche Option für die Kerzenherstellung. Es wird durch Hydrierung von Sojaöl hergestellt, wobei es in eine feste Form umgewandelt wird, die sich gut für Kerzen eignet. Es liegt meist in Form von Flocken vor, die leicht zu messen und zu schmelzen sind.', '2026-02-11 17:17:37', '2026-02-11 17:17:37'),
(35, 'prod-soybean-oil', 'Sojaöl', 'Hochwertiges Sojabohnenöl für industrielle und kulinarische Zwecke', 'Sojaöl ist ein vielseitiges pflanzliches Öl, das aus Sojabohnen gewonnen wird und aufgrund seines neutralen Geschmacks und seines hohen Rauchpunkts häufig zum Braten, Backen und für Salatdressings verwendet wird.  \nEs ist reich an mehrfach ungesättigten Fettsäuren, darunter Omega‑3- und Omega‑6-Fettsäuren, und liefert Vitamin K sowie Vitamin E.  \nEs eignet sich perfekt zum Frittieren, für die Margarinenherstellung und industrielle Lebensmittelanwendungen. Gereingt und deodoriert nach Premiumstandards.', '2026-02-05 21:50:40', '2026-02-11 17:29:14'),
(36, 'prod-sunflower-oil', 'Sonnenblumenöl', 'Premium raffiniertes Sonnenblumenöl zum Kochen und in der Lebensmittelverarbeitung', 'Unser hochwertiges raffiniertes Sonnenblumenöl ist perfekt zum Kochen, Braten und in der Lebensmittelverarbeitung. Es stammt aus hochwertigen Sonnenblumensamen und wird nach den höchsten Standards veredelt.', '2026-02-05 21:43:12', '2026-02-11 17:22:19');
INSERT INTO `products_es` (`id`, `master_id`, `name`, `description`, `full_description`, `created_at`, `updated_at`) VALUES
(1, 'bdf424df-f9b0-4a79-84d6-f6ed1eb1e84f', 'Palm Oleín', 'El palm oleín es la fracción líquida del aceite de palma refinado, valorada como un aceite de fritura y cocina estable que ofrece un sabor neutro, una larga vida en frituras y una textura crujiente para aperitivos, comida rápida y aplicaciones domésticas.', 'El palm olein se produce mediante la fraccionación del aceite de palma refinado, blanqueado y desodorizado (RBD) para obtener un líquido transparente rico en ácidos oleico y palmítico, proporcionando un perfil equilibrado de ácidos grasos con una buena estabilidad oxidativa natural. Su alto punto de humo, resistencia a la oxidación y a la formación de polímeros, y su baja tendencia a desarrollar sabores indeseados permiten ciclos de fritura repetidos con una menor descomposición del aceite, menos formación de espuma y una vida útil prolongada de los productos terminados.\n\nEn aplicaciones alimentarias, el palm olein se utiliza ampliamente como medio de fritura profunda para aperitivos, patatas fritas, pollo frito, fideos instantáneos y alimentos congelados pre-fritos, así como un aceite de uso general en la cocina doméstica en muchos mercados tropicales. También sirve como aceite base en mezclas con soja, girasol u otros aceites vegetales para lograr perfiles nutricionales y funcionales adaptados, y se emplea en margarinas, grasas para panadería y sistemas de fritura en servicios de comida, donde un rendimiento estable y un sabor limpio son cruciales.', '2026-02-11 17:14:54', '2026-02-11 17:14:54'),
(2, 'prod-beeswax', 'Cera de abejas', 'Cera de abejas pura y natural para cosméticos y fabricación de velas', 'Cera de abejas pura y natural, obtenida de apicultores éticos. Perfecta para cosméticos, fabricación de velas y aplicaciones alimentarias. Disponible en varias calidades.', '2026-02-05 21:56:38', '2026-02-11 17:29:38'),
(3, 'prod-bw101-palm-wax', 'Cera de Palma', 'Cera de palma Premium 100% de color amarillo cremoso, ideal para la fabricación de velas. Certificada por RSPO SG (Segregada) / MB (Balance en masa).', 'Cera de palma premium al 100% con un hermoso color amarillo cremoso. Certificada por RSPO MB por su sostenibilidad. Ideal para hacer velas, moldear y velas en envase.', '2026-02-05 22:03:38', '2026-02-11 17:45:13'),
(4, 'prod-bw105-palm-wax', 'Aceites de palma para repostería (punto de fusión bajo)', 'La grasa de palma enpomada es una grasa semisólida, no hidrogenada, derivada del aceite de palma fraccionado, que ofrece una estabilidad superior y un sabor neutro.', 'Palm Shortening es una grasa semi-sólida, no hidrogenada, derivada del aceite de palma fraccionado, que ofrece una estabilidad superior y un sabor neutro.\nIdeal para aplicaciones en panadería: crea hojaldres crujientes, pasteles tiernos y alimentos fritos crujientes con un punto de humo alto.\nAlternativa rentable y resistente a la oxidación al mantequilla o la manteca en la panadería industrial.', '2026-02-05 22:07:58', '2026-02-11 17:30:51'),
(5, 'prod-bw10510-blended-wax', 'Cera mezclada de Palm-Parafina para velas en frascos', 'Mezcla de velas en tarro de Bajo MP lista para usar: Palm-Parafina-Microcristalino con Polyboost™, Vybar®, estabilizadores UV—solo agrega color y fragancia para una mejor adherencia en vidrio y un rendimiento máximo.', 'Mezcla para vela en tarro de Bio Green Wax con punto de fusión bajo (48-50°C) y (50-52°C): formulación de Palm-Parafina-Microcristalina optimizada para recipientes de cristal. Lista para usar: solo añadir color y fragancia. Incluye Polyboost/Vybar para opacidad/adhesión, estabilizadores UV/antioxidantes para la vida en estantería, además de agentes conservantes de fragancia que ofrecen una excepcional disipación de fragancia en caliente y en frío, combustión sin pliegues y una retención superior en el tarro para velas de contenedor premium.', '2026-02-06 03:35:12', '2026-02-11 17:36:57'),
(6, 'prod-bw10555-blended-wax', 'Mezcla de Cera Vegana a Base de Cera de Soja', 'Mezcla vegana lista para usar al 95% de soja de Bio Green Wax—puramente a base de plantas para velas en tarro (48-52°C) y en velaínder (56-62°C). Solo agrega color y fragancia.', 'La mezcla vegana de cera de soja al 95% de Bio Green Wax (5% de aditivos vegetales) ofrece un rendimiento natural y de combustión limpia para frascos de vidrio y pilares independientes. Disponible en punto de fusión bajo (48-52°C) para envases y en punto de fusión alto (56-62°C) para pilares. Listo para usar: simplemente añada su color y fragancia para una excelente proyección y un acabado suave.', '2026-02-06 03:42:37', '2026-02-11 17:31:40'),
(7, 'prod-bw10610-blended-wax', 'Cera de parafina y palma mezclada para velas de pilar', 'Mezclas de velas de columna de alto punto de fusión listas para usar (56-58 °C y 58-60 °C): Palm-Parafina-Microcristalina con Polyboost™, Vybar®, estabilizadores UV—solo añade color y fragancia para un rendimiento superior de las columnas.', 'Las mezclas para velas de pilar de Bio Green wax con Punto de Fusión Alto (56-58°C y 58-60°C)—formulaciones de Palm-Paraffin-Microcrystalline diseñadas para velas de pilar independientes. Lista para usar: solo añada color y fragancia. Optimizadas con Polyboost/Vybar para facilitar la separación del molde y la opacidad, estabilizadores UV/antioxidantes para una mayor vida útil, además de agentes retenedores de fragancia que proporcionan una excelente difusión en caliente y en frío, retención de la forma perfecta de la vela y un rendimiento de combustión limpio.', '2026-02-06 03:38:51', '2026-02-11 17:37:47'),
(8, 'prod-bw10655-blended-wax', 'Mezcla de cera de abeja y cera de parafina', 'Mezcla lista para usar de soja, cera de abeja y parafina de Bio Green Wax—la mejor difusión de fragancia para velas en tarro (48-52°C) y en columna (56-62°C). Solo agrega aroma y color.', 'La mezcla de Bio Green Wax de soja, cera de abeja y parafina combina la suavidad natural de la soja, la estabilidad de la cera de abeja y la potencia aromática de la parafina para un rendimiento de fragancia insuperable. Su bajo punto de fusión (48-52°C) es ideal para envases de vidrio; el alto punto de fusión (56-62°C) es perfecto para pilares. Formulación lista para usar: solo agrega fragancia y color para una excelente difusión en caliente y en frío, y un acabado impecable en la vela.', '2026-02-06 03:46:20', '2026-02-11 17:32:29'),
(9, 'prod-bw8307-blended-wax', 'Mezcla de cera de coco y colza', 'Mezcla lista de Coco-Rapeseed de Bio Green Wax—rendimiento natural y cremoso para velas en Tarro (48-52°C) y Vela Pilar (56-62°C). Solo agrega color y fragancia.', 'La Mezcla de Coco-Rapeseed de Bio Green Wax combina la textura cremosa del cera de coco y la combustión suave de la cera de colza para un rendimiento excepcional en velas naturales. Punto de fusión bajo (48-52°C) optimizado para velas en vaso; punto de fusión alto (56-62°C) para velas de pilar. Completamente lista para usar—solo añada el color y la fragancia de su elección para obtener resultados profesionales y de combustión limpia.', '2026-02-06 03:49:54', '2026-02-11 17:33:20'),
(10, 'prod-carnauba-wax', 'Cera de Carnauba', 'Cera de carnauba brasileña premium para pulimentos y recubrimientos', 'Cera de carnauba brasileña premium, conocida como la \"reina de las ceras\". Ideal para pulido de autos, cosméticos y recubrimientos alimentarios. Máxima temperatura de fusión natural.', '2026-02-05 21:59:32', '2026-02-11 17:30:13'),
(11, 'prod-castor-oil', 'Aceite de Ricino', 'Aceite de ricino prensado en frío de primera calidad, obtenido de las semillas de Ricinus communis, ampliamente utilizado en farmacéutica, cosmética y aplicaciones industriales.', 'Bio Green Wax suministra aceite de ricino de alta calidad, un aceite vegetal versátil obtenido mediante el prensado de las semillas de la planta Ricinus communis (alfabega). Conocido por su composición química única, rica en ácido ricino (aproximadamente 85–90%), el aceite de ricino presenta propiedades excepcionales de viscosidad, lubricidad y humectación que lo hacen invaluable en una amplia gama de industrias.\n\nNuestro aceite de ricino se obtiene y procesa cuidadosamente para cumplir con los más altos estándares de pureza y consistencia. Está disponible en grados de prensado en frío (virgen) y refinado, adecuados para aplicaciones farmacéuticas, cosméticas e industriales. La notable estabilidad y solubilidad del aceite en alcohol lo distinguen de otros aceites vegetales, convirtiéndolo en un ingrediente preferido en formulaciones que requieren un rendimiento superior.\n\nEl aceite de ricino es biodegradables de forma natural y se obtiene de recursos renovables, en línea con el compromiso de Bio Green Wax con una adquisición sostenible y responsable con el medio ambiente.', '2026-02-11 17:15:56', '2026-02-11 17:15:56'),
(12, 'prod-coconut-oil', 'Aceite de Coco', 'Aceite de coco virgen y refinado para aplicaciones alimentarias y cosméticas', 'Aceite de coco virgen y refinado de alta calidad, adecuado para cocinar, hornear y aplicaciones cosméticas. Disponible en varias categorías para satisfacer sus requerimientos específicos.', '2026-02-05 21:49:32', '2026-02-11 17:16:47'),
(13, 'prod-coconut-wax', 'Vela de cera de coco', 'La cera de coco es una cera natural derivada del aceite de coco, valorada por sus velas de combustión limpia y aplicaciones ecológicas.', 'La cera de coco es una cera natural derivada del aceite de coco, conocida por su combustión limpia y lenta en la fabricación de velas. A menudo se considera una alternativa sostenible a otras ceras. La cera de coco es valorada por sus características ecológicas y su capacidad para retener bien las fragancias. Se obtiene de un recurso natural y renovable, lo que permite una combustión limpia y lenta en las velas para un rendimiento más duradero y eficiente.', '2026-02-11 17:25:34', '2026-02-11 17:25:34'),
(14, 'prod-fr5456-paraffin-wax', 'Cera de parafina semirrefinada (50-68°C)', 'Bio Green Wax Parafina Semirefinada (50-68°C): contenido de aceite económico del 1-5% para velas, caucho, textiles y aplicaciones industriales de alto volumen.', 'Las ceras de parafina semirrefinadas de Bio Green Wax (50-68°C) ofrecen un rendimiento económico con un contenido de aceite controlado (1-5%) para una dureza flexible. Los grados estándar: 52/54°C (velas), 56/58°C (columnas), 60/62°C (industrial). Perfectas para la producción de velas de sensibilidad a costos, ayudantes para el procesado de caucho, acabados textiles y recubrimientos para embalaje a granel donde el rendimiento equilibrado y el precio son lo más importante.', '2026-02-06 04:04:09', '2026-02-11 17:23:24'),
(15, 'prod-glycerine', 'Glicerina', 'La glicerina es un líquido viscoso, incoloro e insípido que se utiliza ampliamente en las industrias farmacéutica, cosmética y alimentaria.', 'Glicerina, también conocida como glicerol o glicérido, es un líquido incoloro, inodoro y viscoso con un sabor dulce. Es un líquido claro y azucarado que generalmente es incoloro, aunque puede tener un tinte ligeramente amarillento. La glicerina tiene una alta viscosidad, lo que significa que fluye lentamente y es relativamente espesa. Tiene una consistencia similar a la de un jarabe, lo que contribuye a su capacidad para retener la humedad. La glicerina se utiliza ampliamente en farmacéutica, cosmética, procesamiento de alimentos y diversas aplicaciones industriales.', '2026-02-11 17:19:26', '2026-02-11 17:19:26'),
(16, 'prod-hydrogenated-castor-oil', 'Aceite de ricino hidrogenado', 'El aceite de ricino hidrogenado es un derivado sólido y ceroso del aceite de ricino, utilizado en cosméticos, productos farmacéuticos y aplicaciones industriales.', 'Aceite de ricino hidrogenado, también conocido como cera de ricino o copo de cera de ricino, es un derivado del aceite de ricino que pasa por un proceso de hidrogenación. Esto implica la adición de hidrógeno a las moléculas de aceite de ricino, resultando en una sustancia sólida y cerosa. Se utiliza en productos cosméticos y de cuidado personal como lápices labiales, cremas y lociones, como emoliente para proporcionar suavidad y humedad a la piel. También actúa como un agente vinculante en las formulaciones cosméticas, ayudando a que los ingredientes se adhieran entre sí y a la piel.', '2026-02-11 17:24:50', '2026-02-11 17:24:50'),
(17, 'prod-microcrystalline-wax', 'Cera microcristalina', 'Cera microcristalina flexible para cosméticos y adhesivos', 'Cera microcristalina flexible ideal para cosméticos, adhesivos termofusibles y recubrimientos especializados. Propiedades superiores de flexibilidad y adhesión.', '2026-02-06 03:56:55', '2026-02-11 17:22:46'),
(18, 'prod-olive-oil', 'Aceite de Oliva', 'Aceite de oliva virgen de calidad premium, extraído en frío de olives mediterráneas seleccionadas para aplicaciones culinarias, cosméticas e industriales.', 'Nuestro aceite de oliva virgen extra de primera calidad es prensado en frío a partir de aceitunas mediterráneas cuidadosamente seleccionadas, ofreciendo una calidad excepcional y un sabor intenso. Utilizado ampliamente en la preparación de alimentos, cosméticos, productos farmacéuticos y cuidado personal, el aceite de oliva es valorado por sus beneficios para la salud, propiedades antioxidantes y aplicaciones versátiles. Bio Green Wax obtiene aceite de oliva que cumple con estrictos estándares internacionales de calidad, garantizando una pureza y un rendimiento consistentes en todas sus aplicaciones.', '2026-02-11 17:41:28', '2026-02-11 17:41:28'),
(19, 'prod-palm-kernel-oil', 'Aceite de cártamo', 'El aceite de kernel de palma se obtiene del núcleo de la fruta de la palma aceitera, y se utiliza en productos alimenticios, cosméticos y aplicaciones industriales.', 'El aceite de salvado de palma se obtiene del núcleo de la fruta de la palma aceitera y posee propiedades físicas distintas. Generalmente, es un sólido de color amarillo claro a blanco a temperatura ambiente, pero se funde en un líquido transparente de tonalidad amarilla cuando se calienta. El punto de fusión oscila entre 23 y 28 grados Celsius (73 a 82 grados Fahrenheit). El aceite de salvado de palma es rico en ácido láurico y se usa ampliamente en la fabricación de alimentos, cosméticos y en la producción de jabones.', '2026-02-11 17:21:18', '2026-02-11 17:21:18'),
(20, 'prod-palm-kernel-olein', 'Oleín de salvado de palma', 'Olein de hydroala de maní refinado premium, la fracción líquida obtenida de la fraccionación del aceite de maní, valorada por su excelente claridad, bajo punto de nubosidad y su uso versátil en industrias de alimentos, cuidado personal y oleoquímicas.', 'Bio Green Wax suministra oleín de palmiste de alta calidad (PKOo), la fracción líquida producida mediante la fraccionación controlada del aceite de palmiste refinado. Cuando el aceite de palmiste se enfría bajo condiciones precisas, se separa en una fracción sólida (palmiste de palmiste) y una fracción líquida (oleín de palmiste). El oleín resultante es un aceite transparente, de color claro, con un punto de fusión bajo y una excelente capacidad de vertido.\n\nEl oleín de palmiste es rico en ácido láurico (C12) y ácidos grasos de cadena media, como el caprílico y el caproico, lo que le confiere una claridad excepcional, rápida absorción y una sensación ligera y no grasa. Estas características lo hacen muy apreciado en la industria alimentaria como aceite de cocina, medio de fritura e ingrediente en cremas no lácteas, helados y formulaciones de leche rellena.\n\nEn el sector de cuidado personal y cosmética, el oleín de palmiste se utiliza ampliamente como aceite base en lociones, cremas, champús y jabones líquidos debido a sus excelentes propiedades emolientes y compatibilidad con la piel. También sirve como materia prima clave en la producción de oleoquímicos, generando ácidos grasos, ésteres metílicos y tensioactivos utilizados en detergentes y productos de limpieza.\n\nBio Green Wax obtiene su oleín de palmiste de cadenas de suministro certificadas por RSPO, lo que garantiza total trazabilidad y alineación con los compromisos de sostenibilidad del aceite de palma. El producto está disponible en forma refinada, blanqueada y deodorada (RBD), cumpliendo con estrictas normas internacionales de calidad.', '2026-02-11 17:45:54', '2026-02-11 17:45:54'),
(21, 'prod-palm-kernel-stearin', 'Estearina de almendra de palma', 'Estearina de palmiste de alta calidad, la fracción sólida obtenida de la fraccionación del aceite de palmiste, valorada por su perfil de fusión rápido y su excelente dureza en aplicaciones de confitería, cosmética y oleoquímica.', 'Bio Green Wax suministra estearina de salvado de palmiste de grado premium (PKS), la fracción sólida de mayor punto de fusión producida mediante la fraccionación controlada del aceite de palmiste refinado. Durante la fraccionación, el aceite de palmiste se separa en dos componentes: oleína de palmiste (la fracción líquida) y estearina de palmiste (la fracción sólida). La estearina resultante es una grasa de color blanco a grisáceo con un punto de fusión notablemente agudo y una textura firme. \n\nLa estearina de palmiste es rica en ácido láurico (C12) y ácido mirístico (C14), lo que le confiere una excelente dureza, rápida cristalización y un perfil de fusión limpio. Estas propiedades la hacen un ingrediente ideal para sustitutos de manteca de cacao (CBS), recubrimientos de chocolate compuesto, rellenos de confitería y grasas especiales donde se requiere un acabado de “crack” y brillo.\n\nMás allá de las aplicaciones alimentarias, la estearina de palmiste sirve como materia prima valiosa en la industria oleoquímica para la producción de ácidos grasos, alcoholes grasos, noodles de jabón y tensioactivos. En productos de cuidado personal y cosméticos, contribuye cuerpo y estructura a cremas, lociones y formulaciones sólidas. \n\nBio Green Wax obtiene su estearina de palmiste de cadenas de suministro certificadas por RSPO, asegurando trazabilidad total y cumplimiento con los compromisos de sostenibilidad del aceite de palma. El producto está disponible en forma refinada, blanqueada y deodorada (RBD), cumpliendo con los estándares internacionales de calidad para uso alimentario y técnico.', '2026-02-11 17:20:15', '2026-02-11 17:20:15'),
(22, 'prod-palm-oil', 'Aceite de palma', 'Aceite de palma y derivados de palma de origen sostenible', 'Aceite de palma y derivados de palma obtenidos de manera sostenible para la fabricación de alimentos, producción de jabón y detergentes. Opciones certificadas por RSPO disponibles.', '2026-02-05 21:50:40', '2026-02-11 17:28:21'),
(23, 'prod-palm-shortenings', 'Margarinas de palma (punto de fusión alto)', 'Las mantecas de palma de alto punto de fusión (46–52 °C) son grasas especiales para panadería y frituras, elaboradas a partir de aceite de palma fraccionado, diseñadas para proporcionar una estructura sólida, sabor limpio y una excelente estabilidad al calor en aplicaciones industriales exigentes.', 'Las grasas de palma de punto de fusión alto en el rango de 46–52 °C se elaboran a partir de palmiste y fracciones medias para ofrecer un alto contenido de grasa sólida, una textura firme y una red cristalina estable a temperaturas ambientes y elevadas. Este rango de fusión más alto proporciona una resistencia al calor superior, estabilidad antioxidante y reducción del oling-out, lo que las hace ideales para climas tropicales y líneas de procesamiento a altas temperaturas.\n​\n\nEn aplicaciones de panadería, estas grasas ofrecen una buena aireación, laminación y tensión, soportando masas quebradas, hojaldres, crackers, galletas y bizcochos, manteniendo la forma y la textura incluso en condiciones cálidas. También se utilizan como grasas de fritura robustas y grasas para masa, y como sustitutos de grasa animal en productos cárnicos, donde su estructura firme, estabilidad de emulsión y perfil sin trans ni hidrogenados ayudan a lograr una textura consistente, una liberación de sabor limpia y formulaciones amigables para la etiqueta.', '2026-02-11 17:27:27', '2026-02-11 17:27:27'),
(24, 'prod-palm-stearic-acid', 'Ácido Palmítico', 'El ácido palmítico es un ácido graso saturado derivado del aceite de palma, utilizado en cosméticos, velas y fabricación de caucho.', 'El ácido esteárico de palma es un tipo de ácido graso derivado del aceite de palma, obtenido a través del proceso de separación y cristalización de los ácidos grasos. Es un ácido graso saturado conocido por su estabilidad y forma sólida a temperatura ambiente. El ácido esteárico de palma tiene una apariencia cerosa que varía de blanco a ligeramente amarillo. Tiene un punto de fusión que típicamente oscila entre 55-70 grados Celsius (131-158 grados Fahrenheit), lo que permite su incorporación fácil en diversas formulaciones para cosméticos, velas y productos de caucho.', '2026-02-11 17:39:16', '2026-02-11 17:39:16'),
(25, 'prod-palm-stearin', 'Palm Stearin', 'La palmiste es la fracción sólida del aceite de palma, comúnmente utilizada en la fabricación de alimentos, producción de velas y fabricación de jabón.', 'La stearina de palma es una fracción sólida del aceite de palma obtenida mediante el proceso de fraccionamiento, conocida por su alto contenido en ácidos grasos saturados. Es una grasa sólida a temperatura ambiente, de color blanco cremosa a amarillo pálido y con una textura suave y cerosa. La stearina de palma tiene un punto de fusión más alto en comparación con el aceite de palma. Se usa comúnmente en la industria alimentaria para estabilizar grasas, producir margarina y en la fabricación de velas y jabón.', '2026-02-11 17:38:34', '2026-02-11 17:38:34'),
(26, 'prod-paraffin-wax', 'Cera de parafina completamente refinada (50-68°C)', 'Bio Green Wax Parafina totalmente refinada (50-68°C)—grado alimentario/farmacéutico, <0.5% de aceite, dureza superior. Perfecto para velas, cosméticos, embalaje y aplicaciones industriales de precisión.', 'Las ceras de parafina totalmente refinadas de Bio Green Wax (puntos de fusión de 50-68°C) presentan un contenido de aceite ultrabajo (<0,5%), dureza excepcional y olor/color neutro. Disponibles en grados para velas (52/54°C, 56/58°C), grados para envases (50/52°C) y grados para pilares de alta fusión (64/66°C). Ideales para velas premium, cosméticos, recubrimientos para envases de alimentos y moldeo de precisión que requieren la máxima pureza y consistencia en el rendimiento.', '2026-02-06 03:53:55', '2026-02-11 17:43:10'),
(27, 'prod-pf56-synthetic-wax', 'Wax Fischer-Tropsch (FT)', 'Cera Fischer‑Tropsch (FT) es una cera de paralina sintética de alta pureza, producida a partir de gas de síntesis (syngas), que ofrece un alto punto de fusión, baja viscosidad y una dureza excelente para aplicaciones exigentes en plásticos, recubrimientos, tintas, adhesivos y modificación de betún', 'La cera FT se produce mediante la síntesis de Fischer‑Tropsch, obteniendo una cera de color blanco agua, ultralimpia, con una distribución de cadenas de carbono estrecha, contenido de aceite muy bajo y una estabilidad térmica excepcional. Combina un alto punto de ablandamiento con baja viscosidad de fusión y gran dureza, ofreciendo una resistencia superior a los arañazos, control del brillo, efectos mate y lubricación en muchas formulaciones.\n\nEn el procesamiento de plásticos y PVC/CPVC, la cera FT funciona como un lubricante interno y externo eficiente y un aditivo de procesamiento, reduciendo la viscosidad de la fusión, mejorando el flujo y facilitando el desmoldeo y la estabilidad dimensional. Se utiliza ampliamente en adhesivos de fusión en caliente y sensibles a la presión, tintas de impresión y recubrimientos industriales para incrementar la dureza, la resistencia al desgaste y a los arañazos, la resistencia al bloqueo y la anti-precipitación, al tiempo que estabiliza la viscosidad. Las aplicaciones clave adicionales incluyen la modificación de betún y asfalto, la producción de masterbatches y la copolimerización, el procesamiento de caucho, pulimentos, textiles e incluso formulaciones cosméticas, donde la cera FT ofrece cristalización controlada, mayor resistencia al desgaste y a las arrugas, y una sensación sensorial suave.', '2026-02-06 04:15:28', '2026-02-11 17:44:00'),
(28, 'prod-pfad', 'PFAD (Destilado de Ácido Graso de Palma)', 'PFAD es un subproducto del refinado de aceite de palma, utilizado en la fabricación de jabón, alimentación animal y producción de biocombustibles.', 'El Destilado de Ácido Grasos de Palma (PFAD) es un subproducto del proceso de refinado del aceite de palma. Se obtiene mediante la destilación del aceite de palma crudo para eliminar impurezas y alcanzar un nivel más alto de pureza. El PFAD es un líquido de color amarillo-amarillento con un olor característico. Contiene una mezcla de ácidos grasos saturados e insaturados, siendo los ácidos grasos predominantes el ácido láurico, el ácido mirístico y el ácido palmítico. El PFAD se utiliza en la fabricación de jabón, en la alimentación animal y en la producción de biocombustibles.', '2026-02-11 17:26:17', '2026-02-11 17:26:17'),
(29, 'prod-pkfad', 'Destilado de Ácidos Grasos de Cáscara de Palma (PKFAD)', 'PKFAD es un subproducto del refinado del aceite de palm kernel, rico en ácido láurico, utilizado en las industrias de jabón y oleoquímica.', 'El Destilado de Ácido Grasos de Núcleo de Palma (PKFAD) es un subproducto obtenido durante el refinamiento del aceite de núcleo de palma. Es rico en ácidos grasos, incluyendo ácido láurico, lo que lo hace valioso para ciertas aplicaciones industriales. El PKFAD se emplea en diversas aplicaciones industriales, como la fabricación de jabón, producción de biocombustible y como materia prima en la industria oleoquímica.', '2026-02-11 17:40:01', '2026-02-11 17:40:01'),
(30, 'prod-polyethylene-wax', 'Cera de polietileno (cera de PE)', 'es un polietileno de bajo peso molecular utilizado como lubricante de alto rendimiento y aditivo para procesamiento en plásticos, recubrimientos, tintas y adhesivos, mejorando el flujo, el deslizamiento superficial y la resistencia a los arañazos.', 'La cera de polietileno es una cera sintética finamente dividida, de alta fusión, con baja viscosidad, excelente estabilidad térmica y fuerte compatibilidad con polímeros comunes como PVC, PE, PP y EVA. Proporciona lubricación interna y externa, reduce la viscosidad y la fricción del fundido, mejora el desmoldeo y ofrece una superficie lisa, brillante y resistente a los arañazos.\n​\n\nLas aplicaciones clave incluyen el procesamiento de plásticos y masterbatch, donde la cera de PE mejora la eficiencia en la extrusión y moldeo por inyección, previene la acumulación en la matriz y mejora la dispersión de pigmentos y rellenos. También se utiliza en adhesivos termofusibles y sensibles a la presión, tintas y recubrimientos en polvo para controlar la viscosidad del fundido, aumentar la cohesión y resistencia, y optimizar los tiempos de apertura y fraguado. Usos adicionales abarcan betún y pinturas de señalización vial, compuestos de madera y plástico, mezclas de caucho, compuestos de cables y productos formulados de cera como pulimentos y ceras, donde incrementa el punto de ablandamiento, la dureza y la resistencia al agua.', '2026-02-06 04:00:33', '2026-02-11 17:42:15'),
(31, 'prod-rapeseed-oil', 'Aceite de colza', 'Aceite de colza prensado en frío y refinado de granjas del Reino Unido', 'Aceite de colza prensado en frío y refinado procedente de granjas del Reino Unido. Ideal para cocinar, asar y aderezar ensaladas. Bajo en grasas saturadas y rico en omega-3.', '2026-02-05 21:53:18', '2026-02-11 17:34:04'),
(32, 'prod-rapeseed-wax', 'Cera de colza', 'La cera de colza es una cera vegetal natural utilizada como alternativa ecológica en la fabricación de velas y cosméticos.', 'La cera de colza es una cera vegetal natural derivada del aceite de la planta de colza, comúnmente utilizada como una alternativa ecológica a la cera de parafina tradicional en la fabricación de velas y otras aplicaciones. Ofrece una combustión limpia y lenta, así como una buena retención de fragancia. La cera de colza se utiliza con frecuencia en la producción de velas y en la formulación de cosméticos naturales como bálsamos labiales, lociones y cremas, proporcionando propiedades hidratantes.', '2026-02-11 17:24:08', '2026-02-11 17:24:08'),
(33, 'prod-soap-noodles', 'Fideos de jabón', 'Los fideos de jabón son materias primas primarias para la fabricación de jabón, producidos por saponificación de aceites y grasas vegetales.', 'Los fideos de jabón, también conocidos como gránulos de jabón, son una de las materias primas principales utilizadas en la fabricación de jabón. Se producen mediante el procesamiento de aceites y grasas vegetales con hidróxido de sodio (lejía) a través de la saponificación. Los fideos de jabón son generalmente trozos o cuentas sólidas de color blanco o marfil, con un aroma suave y neutral. Están libres de impurezas y contienen una alta concentración de ácidos grasos que contribuyen a sus propiedades de limpieza y emulsificación.', '2026-02-11 17:40:44', '2026-02-11 17:40:44'),
(34, 'prod-soy-wax', 'Soja Wax', 'La cera de soja es una cera vegetal renovable hecha a partir de aceite de soja, popular para la fabricación de velas ecológicas.', 'La cera de soja es un tipo de cera vegetal derivada del aceite de soja. Es una alternativa popular a la cera de parafina tradicional, que proviene del petróleo. La cera de soja se considera una opción renovable, biodegradable y ecológica para la fabricación de velas. Se obtiene mediante la hidrogenación del aceite de soja, transformándolo en una forma sólida adecuada para velas. Generalmente, se presenta en forma de copos, que son fáciles de medir y derretir.', '2026-02-11 17:17:23', '2026-02-11 17:17:23'),
(35, 'prod-soybean-oil', 'Aceite de soja', 'Aceite de soja de alta calidad para uso industrial y culinario', 'El aceite de soja es un aceite vegetal versátil extraído de la soja, ampliamente utilizado para freír, hornear y aderezar ensaladas debido a su sabor neutro y su alto punto de humo.\nEs rico en grasas poliinsaturadas, incluyendo ácidos grasos omega‑3 y omega‑6, y proporciona vitamina K y vitamina E.\nEs perfecto para la fritura profunda, producción de margarina y aplicaciones alimentarias industriales. Refinado y desodorizado según estándares premium.', '2026-02-05 21:50:40', '2026-02-11 17:28:59'),
(36, 'prod-sunflower-oil', 'Aceite de girasol', 'Aceite de girasol refinado premium para cocinar y procesar alimentos', 'Nuestro aceite de girasol refinado premium es perfecto para cocinar, freír y aplicaciones de procesamiento de alimentos. Obtenido de semillas de girasol de calidad y refinado según los estándares más altos.', '2026-02-05 21:42:18', '2026-02-11 17:22:05');
INSERT INTO `products_fr` (`id`, `master_id`, `name`, `description`, `full_description`, `created_at`, `updated_at`) VALUES
(1, 'bdf424df-f9b0-4a79-84d6-f6ed1eb1e84f', 'Palme Olein', 'L\'oléine de palme est la fraction liquide de l\'huile de palme raffinée, appréciée comme huile de friture et de cuisson stable, offrant un goût neutre, une longue durée de friture et une texture croustillante pour les snacks, la restauration rapide et les applications domestiques.', 'L\'huile olein de palme est produite par fractionnement de l\'huile de palme raffinée, blanchie et désodorisée (RBD) afin d\'obtenir un liquide clair riche en acides oléique et palmitique, offrant un profil équilibré en acides gras avec une stabilité oxydative naturellement bonne. Son point de fumée élevé, sa résistance à l\'oxydation et à la formation de polymères, ainsi que sa faible tendance à développer des saveurs désagréables, permettent des cycles de friture répétés avec une dégradation de l\'huile réduite, moins de formation de mousse et une durée de conservation prolongée des produits finis.\n\nDans les applications alimentaires, l\'huile olein de palme est largement utilisée comme moyen de friture en profondeur pour les snacks, chips, poulet frit, nouilles instantanées et aliments surgelés déjà frits, ainsi que comme huile de cuisson ménagère polyvalente dans de nombreux marchés tropicaux. Elle sert également d\'huile de base dans des mélanges avec du soja, du tournesol ou d\'autres huiles végétales pour obtenir des profils nutritionnels et fonctionnels adaptés, et est utilisée dans la margarine, les graisses de boulangerie et les systèmes de friture en restauration où la performance stable et la saveur neutre sont essentielles.', '2026-02-11 17:14:57', '2026-02-11 17:14:57'),
(2, 'prod-beeswax', 'Cire d\'abeille', 'Cire d\'abeille pure naturelle pour la cosmétique et la fabrication de bougies', 'Cire d\'abeille 100% naturelle issue d\'apiculteurs éthiques. Parfaite pour la fabrication de cosmétiques, de bougies et d\'applications alimentaires. Disponible en différentes qualités.', '2026-02-05 21:56:48', '2026-02-11 17:29:40'),
(3, 'prod-bw101-palm-wax', 'Cire de palmier', 'Cire de palme Premium à 100 % avec une couleur jaune crémeuse, idéale pour la fabrication de bougies. Certifiée RSPO SG (Segregated) / MB (Mass balance).', 'Cire de palm 100 % de qualité premium avec une jolie couleur jaune crémeux. Certifiée RSPO MB pour la durabilité. Idéale pour la fabrication de bougies, le moulage et les bougies en contenant.', '2026-02-05 22:03:54', '2026-02-11 17:45:15'),
(4, 'prod-bw105-palm-wax', 'Palme Shortenings (Point de fusion faible)', 'Graisse de palme solide est une graisse semi-solide, non hydrogénée, dérivée d\'huile de palme fractionnée, offrant une stabilité supérieure et une saveur neutre.', 'Palm Shortening est une graisse semi-solide, non hydrogénée, dérivée de l\'huile de palme fractionnée, offrant une stabilité supérieure et une saveur neutre.  \nParfait pour les applications de boulangerie — il crée des pâtisseries feuilletées, des gâteaux tendres et des aliments frits croustillants avec un point de fumée élevé.  \nUne alternative économique et résistante à l\'oxydation au beurre ou au lard dans la pâtisserie industrielle.', '2026-02-05 22:08:11', '2026-02-11 17:30:54'),
(5, 'prod-bw10510-blended-wax', 'Cire mélangée à la paraffine Palm-Paraffin pour bougies en pot', 'Mélange de bougie en jarre à faible point de fusion prêt à l\'emploi : Palm-Paraffin-Microcrystalline avec Polyboost™, Vybar®, stabilisateurs UV — il ne suffit que d\'ajouter de la couleur et du parfum pour une adhérence supérieure au verre et une diffusion maximale.', 'Mélange de bougie en jarre à point de fusion faible de Bio Green Wax (48-50°C) et (50-52°C)—formulation Palm-Paraffin-Microcristallin optimisée pour contenants en verre. Prêt à l\'emploi : il suffit d\'ajouter de la couleur et du parfum. Inclut Polyboost/Vybar pour l\'opacité/l\'adhérence, stabilisants UV/antioxydants pour la durée de conservation, ainsi que des agents de fixation du parfum offrant une excellente diffusion à chaud et à froid, une combustion sans plis, et une meilleure rétention dans le pot pour des bougies en conteneur haut de gamme.', '2026-02-06 03:35:30', '2026-02-11 17:37:01'),
(6, 'prod-bw10555-blended-wax', 'Mélange de cire végétalienne à base de soja', 'Mélange végétalien prêt à l\'emploi à 95 % de soja de Bio Green Wax — entièrement à base de plantes, conçu pour bougies en Jar (48-52°C) & Pillar (56-62°C). Ajoutez simplement couleur et parfum.', 'Le mélange vegan Bio Green Wax, composé à 95 % de cire de soja (avec 5 % d\'additifs végétaux), offre une combustion propre et une performance naturelle pour les bocaux en verre et les piliers autonomes. Disponible en point de fusion bas (48-52°C) pour les contenants et en point de fusion élevé (56-62°C) pour les piliers. Prêt à l\'emploi : il suffit d\'ajouter votre couleur et votre fragrance pour une diffusion exceptionnelle et une finition lisse.', '2026-02-06 03:42:52', '2026-02-11 17:31:43'),
(7, 'prod-bw10610-blended-wax', 'Cire mélangée paraffine-palmier pour bougies en colonne', 'Cierges de colonne haute température prêtes à l\'emploi (56-58°C & 58-60°C) : mélange de palme-paraffine-microcristalline avec Polyboost™, Vybar®, stabilisateurs UV — il ne vous reste qu\'à ajouter de la couleur et du parfum pour une performance supérieure de votre candle pillar.', 'Les mélanges de bougies en colonne à point de fusion élevé Bio Green wax (56-58°C & 58-60°C) — formulations Palm-Paraffin-Microcristallin conçues pour des bougies en colonne indépendantes. Prêts à l\'emploi : il suffit d\'ajouter la couleur et le parfum. Optimisés avec Polyboost/Vybar pour le démoulage et l\'opacité, des stabilisateurs UV/antioxydants pour une durée de conservation prolongée, ainsi que des agents de retention du parfum, offrant une diffusion exceptionnelle à chaud et à froid, une excellente tenue de la forme en colonne, et une combustion propre.', '2026-02-06 03:39:05', '2026-02-11 17:37:51'),
(8, 'prod-bw10655-blended-wax', 'Mélange de cire d\'abeille, paraffine et paraffine', 'Mélange prêt à l\'emploi de soja, cire d\'abeille et paraffine de Bio Green Wax—ressort de parfum ultime pour bougies en verre (48-52 °C) et en colonne (56-62 °C). Il suffit d\'ajouter du parfum et de la couleur.', 'Le mélange Bio Green Wax à base de soja, cire d\'abeille et paraffine allie la douceur naturelle du soja, la stabilité de la cire d\'abeille et la puissance parfumée de la paraffine pour une performance fragrance inégalée. Son point de fusion bas (48-52°C) convient parfaitement aux contenants en verre ; son point de fusion élevé (56-62°C) est idéal pour les piliers. Formulation prête à l\'emploi — il suffit d\'ajouter parfum et colorant pour une diffusion chaude/froide supérieure et une finition de bougie impeccable.', '2026-02-06 03:46:31', '2026-02-11 17:32:32'),
(9, 'prod-bw8307-blended-wax', 'Mélange de cire de noix de coco et de colza', 'Mélange prêt à l\'emploi de Coconut-Rapeseed de Bio Green Wax—performance naturelle crémeuse pour bougies en Jar (48-52°C) et en Pillar (56-62°C). Ajoutez seulement la couleur et le parfum.', 'Le mélange de cire Bio Green Wax à base de noix de coco et de colza combine la texture crémeuse de la cire de noix de coco et la combustion douce de la cire de colza pour des performances exceptionnelles de bougie naturelle. Point de fusion bas (48-52°C) optimisé pour les bougies en conteneur ; point de fusion élevé (56-62°C) pour les bougies à tige. Entièrement prêt à l’emploi — il suffit d’ajouter la couleur et le parfum de votre choix pour des résultats professionnels et propres à brûler.', '2026-02-06 03:50:11', '2026-02-11 17:33:23'),
(10, 'prod-carnauba-wax', 'Cire de Carnauba', 'Cire de carnauba brésilienne premium pour polishes et revêtements', 'Cire de carnauba brésilienne de qualité supérieure, connue sous le nom de « reine des cires ». Idéale pour la polissage de voitures, la cosmétique et les revêtements alimentaires. Point de fusion naturel le plus élevé.', '2026-02-05 21:59:49', '2026-02-11 17:30:16'),
(11, 'prod-castor-oil', 'Huile de ricin', 'Huile de ricin pressée à froid de qualité premium, extraite des graines de Ricinus communis, largement utilisée dans les produits pharmaceutiques, les cosmétiques et les applications industrielles.', 'Bio Green Wax fournit de l\'huile de ricin de haute qualité, une huile végétale polyvalente obtenue par pressing des graines de la plante Ricin commun (Ricinus communis). Connue pour sa composition chimique unique, riche en acide ricinoléique (environ 85–90 %), l\'huile de ricin présente une viscosité, une lubrification et des propriétés hydratantes exceptionnelles qui la rendent indispensable dans une large gamme d\'industries.\n\nNotre huile de ricin est soigneusement sélectionnée et transformée pour répondre aux normes les plus strictes de pureté et de constance. Elle est disponible en pressée à froid (vierge) et en grades raffinés, adaptées aux applications pharmaceutiques, cosmétiques et industrielles. La stabilité remarquable de l\'huile et sa solubilité dans l\'alcool la distinguent des autres huiles végétales, en faisant un ingrédient privilégié dans les formulations nécessitant des performances supérieures.\n\nL\'huile de ricin est naturellement biodégradable et issue de ressources renouvelables, s\'inscrivant dans l\'engagement de Bio Green Wax en faveur d\'une approvisionnement durable et responsable sur le plan environnemental.', '2026-02-11 17:15:59', '2026-02-11 17:15:59'),
(12, 'prod-coconut-oil', 'Huile de noix de coco', 'Huile de noix de coco vierge et raffinée pour les applications alimentaires et cosmétiques', 'Huile de noix de coco vierge et raffinée de qualité premium, adaptée à la cuisson, à la pâtisserie et aux applications cosmétiques. Disponible en différentes qualités pour répondre à vos besoins spécifiques.', '2026-02-05 21:49:44', '2026-02-11 17:16:49'),
(13, 'prod-coconut-wax', 'Cire de noix de coco', 'La cire de noix de coco est une cire naturelle obtenue à partir de l\'huile de noix de coco, prisée pour ses bougies à combustion propre et ses applications respectueuses de l\'environnement.', 'La cire de noix de coco est une cire naturelle dérivée de l\'huile de noix de coco, reconnue pour sa combustion propre et lente dans la fabrication de bougies. Elle est souvent considérée comme une alternative durable à d\'autres cires. La cire de noix de coco est appréciée pour ses caractéristiques écologiques et sa capacité à bien retenir le parfum. Elle provient d\'une ressource naturelle et renouvelable, offrant une combustion propre et lente pour des bougies plus durables et plus performantes.', '2026-02-11 17:25:36', '2026-02-11 17:25:36'),
(14, 'prod-fr5456-paraffin-wax', 'Cire de paraffine semi- raffinée (50-68°C)', 'Bio Green Wax Paraffine Semi-Raffinée (50-68°C)—coût-efficace avec 1-5 % de teneur en huile, pour bougies, caoutchouc, textiles et applications industrielles à gros volume.', 'Les paraffines semi-refinées de Bio Green Wax (50-68°C) offrent une performance économique avec une teneur en huile contrôlée (1-5%) pour une dureté flexible. Les grades standards : 52/54°C (bougies), 56/58°C (colonnes), 60/62°C (industriel). Parfaites pour la fabrication de bougies à budget modéré, les agents de traitement du caoutchouc, le finissage textile et les revêtements d\'emballage en vrac où l\'équilibre entre performance et prix est essentiel.', '2026-02-06 04:04:26', '2026-02-11 17:23:27'),
(15, 'prod-glycerine', 'Glycérine', 'La glycérine est un liquide incolore, inodore et visqueux, largement utilisé dans l\'industrie pharmaceutique, la cosmétique et l\'alimentation.', 'La glycérine, également connue sous le nom de glycérol ou glycerine, est un liquide incolore, inodore et visqueux, au goût sucré. C\'est un liquide clair et sirupeux, généralement incolore, bien qu\'il puisse avoir une teinte légèrement jaunâtre. La glycérine possède une viscosité élevée, ce qui signifie qu\'elle s\'écoule lentement et est relativement épaisse. Elle a une consistance semblable à celle du sirop, ce qui contribue à sa capacité à retenir l\'humidité. La glycérine trouve une utilisation extensive dans les domaines pharmaceutique, cosmétique, de la transformation alimentaire et dans diverses applications industrielles.', '2026-02-11 17:19:28', '2026-02-11 17:19:28'),
(16, 'prod-hydrogenated-castor-oil', 'Huile de Ricin Hydrogénée', 'L\'huile de ricin hydrogénée est un dérivé solide cireux de l\'huile de ricin, utilisé dans les cosmétiques, les produits pharmaceutiques et les applications industrielles.', 'L\'huile de ricin hydrogénée, également connue sous le nom de cire de ricin ou flocons de cire de ricin, est un dérivé de l\'huile de ricin qui subit un processus d\'hydrogénation. Cela implique l\'ajout d\'hydrogène aux molécules d\'huile de ricin, ce qui donne une substance solide et cireuse. Elle est utilisée dans des produits cosmétiques et de soin personnel comme les rouges à lèvres, crèmes et lotions, en tant qu\'émollient pour apporter douceur et hydratation à la peau. Elle agit également comme agent liant dans les formulations cosmétiques, aidant les ingrédients à se fixer ensemble et à adhérer à la peau.', '2026-02-11 17:24:53', '2026-02-11 17:24:53'),
(17, 'prod-microcrystalline-wax', 'Cire microcristalline', 'Cire microcristalline flexible pour cosmétiques et adhésifs', 'Cire microcristalline flexible idéale pour les cosmétiques, les adhésifs thermofusibles et les revêtements spéciaux. Flexibilité supérieure et propriétés de liaison exceptionnelles.', '2026-02-06 03:57:05', '2026-02-11 17:22:48'),
(18, 'prod-olive-oil', 'Huile d\'olive', 'Huile d\'olive pure de qualité premium, extraite à froid d\'olives méditerranéennes sélectionnées pour des applications culinaires, cosmétiques et industrielles.', 'Notre huile d\'olive pure de qualité supérieure est obtenue par pression à froid à partir d\'olives méditerranéennes soigneusement sélectionnées, garantissant une qualité exceptionnelle et une saveur riche. Utilisée largement dans la préparation de repas, les cosmétiques, les produits pharmaceutiques et les soins personnels, l\'huile d\'olive est prisée pour ses bienfaits pour la santé, ses propriétés antioxydantes et ses applications polyvalentes. Bio Green Wax source une huile d\'olive qui respecte des normes internationales de qualité strictes, assurant une pureté et des performances constantes dans toutes ses utilisations.', '2026-02-11 17:41:31', '2026-02-11 17:41:31'),
(19, 'prod-palm-kernel-oil', 'Huile de son de palme', 'L\'huile de noyau de palmier à huile est extraite du noyau du fruit du palmier à huile, et elle est utilisée dans les produits alimentaires, les cosmétiques et les applications industrielles.', 'L\'huile de noyau de palmiste est dérivée du noyau du fruit du palmier à huile et possède des propriétés physiques distinctes. Elle est généralement solide de couleur jaune clair à blanche à température ambiante, mais fond pour devenir un liquide clair, jaunâtre lorsqu\'elle est chauffée. Son point de fusion varie de 23 à 28 degrés Celsius (73 à 82 degrés Fahrenheit). L\'huile de noyau de palmiste est riche en acide laurique et est largement utilisée dans la fabrication alimentaire, la cosmétique et la production de savon.', '2026-02-11 17:21:21', '2026-02-11 17:21:21'),
(20, 'prod-palm-kernel-olein', 'Palme Kernel Oléine', 'Palme raffinée premium oleïne d\'amande de palmiste, la fraction liquide obtenue par fractionnement de l\'huile de palmiste, appréciée pour sa clarté exceptionnelle, son point de nuage faible et son utilisation polyvalente dans les industries alimentaires, des produits de soin personnel et de l\'oléochimie.', 'Bio Green Wax fournit de l\'oléine de pépin de palmiste de haute qualité (PKOo), la fraction liquide produite par lafractionnement contrôlé de l\'huile de pépin de palmiste raffinée. Lorsque l\'huile de pépin de palmiste est refroidie dans des conditions précises, elle se sépare en une fraction solide (palmiste de pépin de palmiste) et une fraction liquide (oléine de pépin de palmiste). L\'oléine résultante est une huile claire, de couleur pâle, avec un point de fusion faible et une excellente fluidité.\n\nL\'oléine de pépin de palmiste est riche en acide laurique (C12) et en acides gras à chaîne moyenne caprique/caprylique, lui conférant une grande clarté, une absorption rapide et une sensation légère et non-grasse. Ces caractéristiques en font un ingrédient très recherché dans l\'industrie alimentaire en tant qu\'huile de cuisson, médium de friture, et composant dans les crèmes non laitières, glaces et formulations de lait écrémé.\n\nDans le secteur des soins personnels et de la cosmétique, l\'oléine de pépin de palmiste est largement utilisée comme huile de base dans les lotions, crèmes, shampoings et savons liquides en raison de ses excellentes propriétés émollientes et de sa compatibilité avec la peau. Elle sert également de matière première clé dans la production d\'oléochimie, produisant des acides gras, des esters méthyliques et des tensioactifs utilisés dans les détergents et produits de nettoyage.\n\nBio Green Wax source son oléine de pépin de palmiste auprès de chaînes d\'approvisionnement certifiées RSPO, garantissant une traçabilité totale et une conformité aux engagements en matière d\'huile de palme durable. Le produit est disponible sous forme raffinée, décolorée et désodorisée (RBD), conforme à des normes de qualité internationales strictes.', '2026-02-11 17:45:58', '2026-02-11 17:45:58'),
(21, 'prod-palm-kernel-stearin', 'Stéarine de noyau de palmier', 'Stéarine de noyau de palmier de haute qualité, la fraction solide obtenue par fractionnement de l\'huile de noyau de palmier, appréciée pour son profil de fonte précis et sa dureté exceptionnelle dans les applications confiserie, cosmétique et oléochimique.', 'Bio Green Wax fournit du stéarine de pépin de palmier de qualité supérieure (PKS), la fraction solide à point de fusion plus élevé produite par la fractionation contrôlée de l\'huile de pépin de palmier raffinée. Lors de la fractionation, l\'huile de pépin de palmier est séparée en deux composants : l\'oléine de pépin de palmier (la fraction liquide) et la stéarine de pépin de palmier (la fraction solide). La stéarine ainsi obtenue est une graisse allant du blanc au beige, avec un point de fusion caractéristiquement élevé et une texture ferme.\n\nLa stéarine de pépin de palmier est riche en acide laurique (C12) et en acide myristique (C14), ce qui lui confère une excellente dureté, une cristallisation rapide et un profil de fusion net. Ces propriétés en font un ingrédient idéal pour les substituts de beurre de cacao (CBS), les enrobages de chocolat à compound, les garnitures de confiserie et les graisses de spécialité nécessitant un fini à cassant et brillant.\n\nAu-delà des applications alimentaires, la stéarine de pépin de palmier sert de matière première précieuse dans l\'industrie oléochimique pour la production d\'acides gras, d\'alcools gras, de nouilles de savon et de tensioactifs. Dans les soins personnels et la cosmétique, elle contribue au corps et à la structure des crèmes, laits, et formulations solides.\n\nBio Green Wax sourcing sa stéarine de pépin de palmier auprès de filières certifiées RSPO, garantissant une traçabilité complète et le respect des engagements en matière d\'huile de palme durable. Le produit est disponible sous forme raffinée, blanchi et déodorisée (RBD), répondant aux normes internationales de qualité pour un usage alimentaire et technique.', '2026-02-11 17:20:19', '2026-02-11 17:20:19'),
(22, 'prod-palm-oil', 'Huile de palme', 'Huile de palme et dérivés de palme issus de sources durables', 'Huiles de palme et dérivés de palmier issus de sources durables pour la fabrication alimentaire, la production de savon et de détergents. Options certifiées RSPO disponibles.', '2026-02-05 21:50:40', '2026-02-11 17:28:23'),
(23, 'prod-palm-shortenings', 'Graisses Palm (point de fusion élevé)', 'Les shortening de palm à point de fusion élevé (46–52 °C) sont des graisses de pâtisserie et de friture spécialisées, élaborées à partir d\'huile de palme fractionnée, conçues pour offrir une structure solide, une saveur propre et une excellente stabilité à la chaleur dans des applications industrielles exigeantes.', 'Les shortenings à point de fusion élevé dans la gamme de 46 à 52 °C sont formulés à partir de palm stearin et de fractions moyennes pour offrir une teneur élevée en matières grasses solides, une texture ferme et un réseau cristallin stable à température ambiante et à des températures plus élevées. Cette gamme de fusion plus élevée offre une résistance thermique supérieure, une stabilité oxydative et une réduction de l\'oiling‑out, ce qui les rend particulièrement adaptés aux climats tropicaux et aux lignes de traitement à haute température.\n​\n\nDans les applications boulangères, ces shortenings assurent une bonne aération, lamination et croquant, soutenant des croûtes de tartes feuilletées, des pâtisseries feuilletées, des crackers à la crème, des biscuits et des biscuits, tout en conservant leur forme et leur texture en conditions chaudes. Ils sont également utilisés comme matières grasses robustes pour la friture et la pâte, ainsi que comme substituts de la graisse animale dans les produits carnés, où leur structure ferme, leur stabilité d’émulsion et leur profil sans trans, non hydrogéné, contribuent à obtenir une texture cohérente, une libération de saveur propre et des formulations respectueuses de l’étiquetage.', '2026-02-11 17:27:30', '2026-02-11 17:27:30'),
(24, 'prod-palm-stearic-acid', 'Acide stéarique de palm', 'L\'acide stéarique de palme est un acide gras saturé dérivé de l\'huile de palme, utilisé en cosmétique, dans la fabrication de bougies et de caoutchouc.', 'L\'acide stéarique de palme est un type d\'acide gras dérivé de l\'huile de palme, obtenu par séparation et cristallisation des acides gras. C\'est un acide gras saturé connu pour sa stabilité et sa forme solide à température ambiante. L\'acide stéarique de palme a une apparence cireuse allant du blanc au jaune légèrement tacheté. Il a un point de fusion généralement compris entre 55 et 70 degrés Celsius (131-158 degrés Fahrenheit), ce qui lui permet de s\'incorporer facilement dans diverses formulations pour la cosmétique, les bougies et les produits en caoutchouc.', '2026-02-11 17:39:20', '2026-02-11 17:39:20'),
(25, 'prod-palm-stearin', 'Stéarine de palme', 'Le palm stearin est la fraction solide de l\'huile de palme, couramment utilisée dans la fabrication alimentaire, la production de bougies et la savonnerie.', 'Le palmiste est une fraction solide d\'huile de palme obtenue par procédé de fractionnement, reconnu pour sa teneur élevée en acides gras saturés. C\'est une graisse solide à température ambiante, de couleur crème à jaune pâle, avec une texture lisse et cireuse. Le palmiste a un point de fusion plus élevé que l\'huile de palme. Il est couramment utilisé dans l\'industrie alimentaire pour stabiliser les graisses, produire de la margarine, ainsi que dans la fabrication de bougies et de savon.', '2026-02-11 17:38:37', '2026-02-11 17:38:37'),
(26, 'prod-paraffin-wax', 'Cire de paraffine entièrement raffinée (50-68°C)', 'Bio Green Wax Paraffine entièrement raffinée (50-68°C) — qualité alimentaire/pharmaceutique, <0,5 % d\'huile, dureté supérieure. Parfait pour les bougies, les cosmétiques, l\'emballage et les applications industrielles de précision.', 'Les cires paraffine entièrement raffinées de Bio Green Wax (points de fusion de 50-68°C) présentent une teneur en huile ultra-faible (<0,5%), une dureté exceptionnelle et une odeur/couleur neutres. Disponibles en grades pour bougies (52/54°C, 56/58°C), en grades pour contenants (50/52°C), et en grades pour piliers à haute fusion (64/66°C). Idéales pour les bougies premium, les cosmétiques, les revêtements pour emballages alimentaires et le moulage de précision nécessitant une pureté maximale et une cohérence de performance.', '2026-02-06 03:54:04', '2026-02-11 17:43:13'),
(27, 'prod-pf56-synthetic-wax', 'Cire Fischer-Tropsch (FT)', 'La cire de Fischer‑Tropsch (FT) est une cire paraffinée synthétique de haute pureté produite à partir de syngaz, offrant un point de fusion élevé, une faible viscosité et une excellente dureté pour des applications exigeantes dans les plastiques, les revêtements, les encres, les adhésifs et la modification du bitume', 'La cire FT est produite via la synthèse Fischer‑Tropsch, ce qui donne une cire blanc lait, ultra-propre, avec une distribution étroite de chaînes de carbone, une teneur en huile très faible et une stabilité thermique exceptionnelle. Elle combine un point de fusion élevé avec une faible viscosité de fusion et une dureté forte, offrant une résistance aux griffures supérieure, un contrôle du gloss, des effets de matification et une lubrification dans de nombreuses formulations.\n\nDans la transformation des plastiques et du PVC/CPVC, la cire FT agit comme un lubrifiant interne et externe efficace ainsi qu’un aide au traitement, en réduisant la viscosité du melt, en améliorant l’écoulement, et en favorisant le démoulage et la stabilité dimensionnelle. Elle est largement utilisée dans les adhésifs thermofusibles et sensibles à la pression, les encres d’imprimerie et les coatings industriels pour augmenter la dureté, la résistance à l’abrasion et aux rayures, la résistance à la blocage, et la stabilité contre l settling tout en stabilisant la viscosité. Parmi ses applications clés figurent également la modification de bitume et d’asphalte, la fabrication de masterbatches et la compounding de polymères, la transformation du caoutchouc, les polish, les textiles, et même les formulations cosmétiques, où la cire FT offre une cristallinité contrôlée, une résistance améliorée à l’usure et aux plis, ainsi qu’une sensation douce au toucher.', '2026-02-06 04:15:41', '2026-02-11 17:44:05'),
(28, 'prod-pfad', 'PFAD (Palm Fatty Acid Distillate)', 'PFAD est un sous-produit de la raffinage d\'huile de palme, utilisé dans la fabrication de savons, l\'alimentation animale et la production de biocarburants.', 'Distillat d\'acides gras de palmier (PFAD) est un sous-produit du processus de raffinage de l\'huile de palme. Il est obtenu par distillation de l\'huile de palme brute afin d\'éliminer les impuretés et d\'atteindre un niveau de pureté supérieur. Le PFAD est un liquide de couleur brun jaunâtre, avec une odeur caractéristique. Il contient un mélange d\'acides gras saturés et insaturés, les acides gras prédominants étant l\'acide laurique, l\'acide myristique et l\'acide palmitique. Le PFAD est utilisé dans la fabrication de savon, l\'alimentation animale et la production de biocarburant.', '2026-02-11 17:26:21', '2026-02-11 17:26:21'),
(29, 'prod-pkfad', 'Distillat d\'acides gras de palm kernel (PKFAD)', 'PKFAD est un sous-produit de la raffinage de l\'huile de pépin de palmiste, riche en acide laurique, utilisé dans les industries de la lessive et des oléochimiques.', 'Distillat d\'acides gras de noix de palme (PKFAD) est un sous-produit obtenu lors du raffinage de l\'huile de noix de palme. Il est riche en acides gras, notamment en acide laurique, ce qui le rend précieux pour certaines applications industrielles. Le PKFAD est utilisé dans diverses applications industrielles, notamment la fabrication de savon, la production de biocarburants, et comme matière première dans l\'industrie oléochimique.', '2026-02-11 17:40:04', '2026-02-11 17:40:04'),
(30, 'prod-polyethylene-wax', 'Cire de polyéthylène (cire PE)', 'est un polyéthylène à faible poids moléculaire utilisé comme lubrifiant haute performance et agent de traitement dans les plastiques, revêtements, encres et adhésifs, améliorant la fluidité, le glissement de surface et la résistance aux rayures.', 'Les cires de polyethylene sont des cires synthétiques finement divisées, à point de fusion élevé, avec une faible viscosité, une excellente stabilité thermique et une forte compatibilité avec les polymères courants tels que le PVC, le PE, le PP et l\'EVA. Elles offrent une lubrification interne et externe, réduisent la viscosité de fusion et la friction, améliorent le dévaillage des moules, et procurent une surface lisse, brillante et résistante aux rayures.\n​\n\nLes applications clés incluent le traitement des plastiques et des masterbatches, où la cire de PE améliore l\'efficacité de l\'extrusion et du moulage par injection, empêche l\'accumulation dans les matrices, et favorise une meilleure dispersion des pigments et des charges. Elle est également utilisée dans les adhésifs thermofusibles et sensibles à la pression, les encres, et les revêtements en poudre pour contrôler la viscosité de fusion, augmenter la cohésion et la résistance, ainsi qu\'optimiser les temps d\'ouverture et de fixation. D\'autres usages concernent le bitume et les peintures de marquage routier, les composites bois-plastique, la compound de caoutchouc, les composés de câbles, et les produits à base de cire formulés tels que les polishes et les crayons, où elle augmente le point de ramollissement, la dureté et la résistance à l\'eau.', '2026-02-06 04:00:45', '2026-02-11 17:42:18'),
(31, 'prod-rapeseed-oil', 'Huile de colza', 'Huile de colza pressée à froid et raffinée provenant des fermes du Royaume-Uni', 'Huile de colza pressée à froid et raffinée provenant de fermes du Royaume-Uni. Idéale pour la cuisson, la torréfaction et les vinaigrettes. Faible en acides gras saturés et riche en oméga-3.', '2026-02-05 21:53:31', '2026-02-11 17:34:06'),
(32, 'prod-rapeseed-wax', 'Cire de colza', 'La cire de colza est une cire végétale naturelle utilisée comme alternative écologique dans la fabrication de bougies et les cosmétiques.', 'La cire de colza est une cire végétale naturelle dérivée de l\'huile de la plante de colza, souvent utilisée comme alternative écologique à la cire de paraffine traditionnelle dans la fabrication de bougies et d\'autres applications. Elle offre une combustion propre et lente, ainsi qu\'une bonne rétention des fragrances. La cire de colza est fréquemment utilisée dans la production de bougies et dans la formulation de cosmétiques naturels tels que les baumes à lèvres, les lotions et les crèmes, apportant des propriétés hydratantes.', '2026-02-11 17:24:11', '2026-02-11 17:24:11'),
(33, 'prod-soap-noodles', 'NOUILLES DE SAVON', 'Les nouilles de savon sont des matières premières primaires pour la fabrication du savon, produites par saponification des huiles et graisses végétales.', 'Les filaments de savon, également appelés granules de savon, constituent l\'une des matières premières principales utilisées dans la fabrication du savon. Ils sont produits en traitant des huiles et graisses végétales avec de l\'hydroxyde de sodium (lessive) par saponification. Les filaments de savon sont généralement des morceaux ou des perles solides de couleur blanche ou cassie, avec un arôme doux et neutre. Ils sont exempts d\'impuretés et contiennent une concentration élevée d\'acides gras qui contribuent à leurs propriétés nettoyantes et émulsifiantes.', '2026-02-11 17:40:47', '2026-02-11 17:40:47'),
(34, 'prod-soy-wax', 'Cire de soja', 'La cire de soja est une cire végétale renouvelable composée d\'huile de soja, populaire pour la fabrication de bougies écologiques.', 'La cire de soja est un type de cire végétale dérivée de l\'huile de soja. C\'est une alternative populaire à la cire de paraffine traditionnelle, qui est issue du pétrole. La cire de soja est considérée comme une option renouvelable, biodégradable et respectueuse de l\'environnement pour la fabrication de bougies. Elle est obtenue en hydrogénant l\'huile de soja, la transformant en une forme solide adaptée à la fabrication de bougies. Elle se présente généralement sous forme de flocons, faciles à mesurer et à faire fondre.', '2026-02-11 17:17:26', '2026-02-11 17:17:26'),
(35, 'prod-soybean-oil', 'Huile de soja', 'Huile de soja de haute qualité pour usage industriel et culinaire', 'L\'huile de soja est une huile végétale polyvalente extraite des graines de soja, largement utilisée pour la friture, la cuisson au four et les vinaigrettes en raison de sa saveur neutre et de son point de fumée élevé.\nElle est riche en acides gras polyinsaturés, notamment en oméga‑3 et oméga‑6, et fournit de la vitamine K et de la vitamine E.\nElle est idéale pour la friture profonde, la fabrication de margarine et les applications alimentaires industrielles. Raffinée et désodorisée selon des normes premium.', '2026-02-05 21:50:40', '2026-02-11 17:29:03'),
(36, 'prod-sunflower-oil', 'Huile de tournesol', 'Huile de tournesol raffinée de qualité premium pour la cuisson et la transformation alimentaire', 'Notre huile de tournesol raffinée de qualité supérieure est parfaite pour la cuisson, la friture et les applications de transformation alimentaire. Provenant de graines de tournesol de qualité et raffinée selon les normes les plus strictes.', '2026-02-05 21:42:27', '2026-02-11 17:22:07');
INSERT INTO `products_it` (`id`, `master_id`, `name`, `description`, `full_description`, `created_at`, `updated_at`) VALUES
(1, 'bdf424df-f9b0-4a79-84d6-f6ed1eb1e84f', 'Palm Olein', 'La palm oleina è la frazione liquida dell\'olio di palma raffinato, apprezzata come olio stabile per friggere e cucinare che offre un gusto neutro, una lunga durata nella frittura e una consistenza croccante per snack, fast‑food e applicazioni domestiche.', 'Il olein di palma viene prodotto mediante frazionamento dell\'olio di palma raffinato, decolorato e deodorato (RBD) per ottenere un liquido limpido ricco di acidi oleico e palmitico, offrendo un profilo di acidi grassi equilibrato con una buona stabilità ossidativa naturale. Il suo alto punto di fumo, la resistenza all\'ossidazione e alla formazione di polimeri, e la bassa tendenza a sviluppare odori sgradevoli, permettono cicli di frittura ripetuti con una ridotta degradazione dell\'olio, meno formazione di schiuma e una vita più lunga dei prodotti finiti.\n\nNelle applicazioni alimentari, l\'olein di palma è ampiamente utilizzato come mezzo di frittura profonda per snack, patatine, pollo fritto, pasta istantanea e alimenti surgelati precotti, così come come olio da cucina di uso generale nei mercati tropicali. Serve anche come olio di base in miscele con soia, girasole o altri oli vegetali per ottenere profili nutrizionali e funzionali su misura, ed è impiegato in margarine, cereali da forno e sistemi di frittura professionale dove è fondamentale una performance stabile e un sapore pulito.', '2026-02-11 17:15:41', '2026-02-11 17:15:41'),
(2, 'prod-beeswax', 'Cera d\'api', 'Cera d\'api pura e naturale per cosmetici e produzione di candele', 'Cera d\'api pura e naturale proveniente da apicoltori etici. Perfetta per cosmetici, candlemaking e applicazioni alimentari. Disponibile in diverse qualità.', '2026-02-11 17:30:05', '2026-02-11 17:30:05'),
(3, 'prod-bw101-palm-wax', 'Cera di Palma', 'Cera di palma premium al 100% di colore giallo-crema, ideale per la produzione di candele. Certificata RSPO SG (Segregated) / MB (Mass balance).', 'Cera di palma Premium al 100% con un bellissimo colore giallo crema. Certificata RSPO MB per la sostenibilità. Ideale per la produzione di candele, stampaggi e candele in contenitore.', '2026-02-11 17:45:44', '2026-02-11 17:45:44'),
(4, 'prod-bw105-palm-wax', 'Oliature di palma (punto di fusione basso)', 'Palm Shortening è un grasso semi-solido, non idrogenato, derivato da olio di palma frazionato, che offre una stabilità superiore e un sapore neutro.', 'Palm Shortening è un grasso semisolido, non idrogenato, derivato dall\'olio di palma frazionato, che offre una stabilità superiore e un sapore neutro.  \nPerfetto per applicazioni da forno—crea pasticcini sfogliati, torte morbide e cibi fritti croccanti con un punto di fumo elevato.  \nAlternativa economica e resistente all’ossidazione a burro o strutto nella panificazione industriale.', '2026-02-11 17:31:31', '2026-02-11 17:31:31'),
(5, 'prod-bw10510-blended-wax', 'Cera a base di paraffina e paraffina palmare per candele in barattolo', 'Miscela di candele in barattolo Low MP pronta all\'uso: Palm-Paraffin-Microcrystalline con Polyboost™, Vybar®, stabilizzatori UV—basta aggiungere colore e fragranza per un\'adesione superiore al vetro e una diffusione massima.', 'La miscela di cera in barattolo con punto di fusione basso Bio Green Wax (48-50°C) e (50-52°C)— formulazione a base di Palm-Paraffin-Microcristallino ottimizzata per contenitori in vetro. Pronta all\'uso: basta aggiungere colore e fragranza. Include Polyboost/Vybar per opacità e adesione, stabilizzatori UV/antiossidanti per la durata, oltre a agenti per la ritenzione della fragranza che garantiscono una straordinaria diffusione di calore/freddo, una combustione senza grinze e una superiore ritenzione nel barattolo per candele di alta qualità in contenitori premium.', '2026-02-11 17:37:38', '2026-02-11 17:37:38'),
(6, 'prod-bw10555-blended-wax', 'Miscela di cere vegane a base di soia', 'Miscela vegana al 95% di soia pronta all\'uso da Bio Green Wax—puramente a base vegetale per candele in <Jar> (48-52°C) e <Pillar> (56-62°C). Basta aggiungere colore e fragranza.', 'La miscela vegana Bio Green Wax al 95% di cera di soia (5% di additivi vegetali) garantisce prestazioni naturali e brucia pulito, ideale per contenitori di vetro e candelabri autoportanti. Disponibile con punto di fusione basso (48-52°C) per contenitori e con punto di fusione alto (56-62°C) per candelabri. Pronta all\'uso: basta aggiungere il colore e la fragranza per un\'ottima diffusione e una finitura liscia.', '2026-02-11 17:32:19', '2026-02-11 17:32:19'),
(7, 'prod-bw10610-blended-wax', 'Cera a miscela di paraffina e palmà per candele a colonna', 'Candele a colonna High MP pronte all\'uso (56-58°C e 58-60°C): miscela di palm-paraffina-microcristallina con Polyboost™, Vybar®, stabilizzatori UV—aggiungi solo colore e profumo per prestazioni superiori della candela a colonna.', 'Bio Green wax\'s High Melting Point Pillar Candle Blends (56-58°C e 58-60°C)—Formulazioni Palm-Paraffin-Microcrystalline appositamente studiate per candele colonne autofusanti. Pronte all\'uso: basta aggiungere colore e profumo. Ottimizzate con Polyboost/Vybar per facilitare il distacco dagli stampi e per l\'opacità, stabilizzatori UV/antiossidanti per una durata più lunga, oltre ad agenti di trattenimento della fragranza che garantiscono un\'eccezionale propagazione in hot e cold, mantenimento perfetto della forma della candela e una combustione pulita.', '2026-02-11 17:38:25', '2026-02-11 17:38:25'),
(8, 'prod-bw10655-blended-wax', 'Miscela di Soia, Cera d\'Api e Cera Paraffina', 'Miscelatore pronto all\'uso di Bio Green Wax a base di soia, cera d\'api e paraffina—massima propagazione della fragranza per candele in contenitore (48-52°C) e a colonna (56-62°C). Basta aggiungere profumo e colore.', 'La miscela di Bio Green Wax a base di Soia, Cera d\'Api e Paraffina unisce la morbidezza naturale della soia, la stabilità della cera d\'api e la forza del profumo della paraffina per prestazioni olfattive senza pari. Il punto di fusione basso (48-52°C) è ideale per contenitori in vetro; quello alto (56-62°C) perfetto per candele a colonna. Formula pronta all\'uso—basta aggiungere fragranza e colore per una diffusione superiore a caldo e a freddo e una finitura perfetta della candela.', '2026-02-11 17:33:10', '2026-02-11 17:33:10'),
(9, 'prod-bw8307-blended-wax', 'Miscela di cera di cocco e di colza', 'Miscela pronta di Coconut-Rapeseed di Bio Green Wax—performance naturale cremosa per candele in Vaso (48-52°C) e Torre (56-62°C). Aggiungi solo colore e profumo.', 'La miscela di Bio Green Wax di Coconut-Rapeseed combina la consistenza cremosa della cera di cocco e la combustione uniforme della cera di colza per prestazioni eccezionali delle candele naturali. Punto di fusione basso (48-52°C) ottimizzato per candele in contenitore; punto di fusione alto (56-62°C) per candele a colonna. Completamente pronta all\'uso—basta aggiungere il proprio colore e profumo preferiti per risultati professionali e puliti durante la combustione.', '2026-02-11 17:33:57', '2026-02-11 17:33:57'),
(10, 'prod-carnauba-wax', 'Cera di Carnauba', 'Cera di carnauba brasiliana premium per lucidature e rivestimenti', 'Cera di carnauba brasiliana di qualità premium, conosciuta come la \"regina delle cere\". Ideale per la lucidatura delle automobili, cosmetici e rivestimenti alimentari. Punto di fusione naturale più alto.', '2026-02-11 17:30:43', '2026-02-11 17:30:43'),
(11, 'prod-castor-oil', 'Olio di ricino', 'Olio di ricino spremuto a freddo di alta qualità derivato dai semi di Ricinus communis, ampiamente utilizzato in prodotti farmaceutici, cosmetici e applicazioni industriali.', 'Bio Green Wax fornisce olio di ricino di alta qualità, un versatile olio vegetale ottenuto mediante spremitura dei semi della pianta Ricinus communis (pianta del ricino). Nota per la sua composizione chimica unica ricca di acido ricinoleico (circa l\'85-90%), l\'olio di ricino presenta eccezionali proprietà di viscosità, lubrificazione e idratazione che ne rendono inestimabile l\'uso in una vasta gamma di settori.\n\nIl nostro olio di ricino è accuratamente selezionato e lavorato per rispettare i più elevati standard di purezza e uniformità. È disponibile in gradi sia a spremitura a freddo (vergine) sia raffinati, adatti per applicazioni farmaceutiche, cosmetiche e industriali. La straordinaria stabilità e solubilità dell\'olio in alcool lo distinguono dagli altri oli vegetali, rendendolo un ingrediente preferenziale nelle formulazioni che richiedono prestazioni superiori.\n\nL\'olio di ricino è naturalmente biodegradabile e derivato da risorse rinnovabili, in linea con l\'impegno di Bio Green Wax per un approvvigionamento sostenibile e rispettoso dell\'ambiente.', '2026-02-11 17:16:38', '2026-02-11 17:16:38'),
(12, 'prod-coconut-oil', 'Olio di Cocco', 'Olio di cocco vergine e raffinato per applicazioni alimentari e cosmetiche', 'Olio di cocco premium vergine e raffinato, adatto per uso in cucina, panificazione e applicazioni cosmetiche. Disponibile in diverse qualità per soddisfare le tue esigenze specifiche.', '2026-02-09 02:59:36', '2026-02-11 17:17:15'),
(13, 'prod-coconut-wax', 'Cera di cocco', 'La cera di cocco è una cera naturale derivata dall\'olio di cocco, apprezzata per candele che bruciano in modo pulito e applicazioni ecologiche.', 'La cera di cocco è una cera naturale derivata dall\'olio di cocco, nota per la sua combustione pulita e lenta nella creazione di candele. Spesso è considerata un\'alternativa sostenibile ad altre cere. La cera di cocco è apprezzata per le sue caratteristiche eco-friendly e per la capacità di trattenere bene la fragranza. Deriva da una risorsa naturale e rinnovabile, offrendo una combustione pulita e lenta nelle candele per una durata più lunga e prestazioni più efficienti.', '2026-02-11 17:26:08', '2026-02-11 17:26:08'),
(14, 'prod-fr5456-paraffin-wax', 'Cera di paraffina semi raffinata (50-68°C)', 'Bio Green Wax Paraffina Semi Raffinata (50-68°C)—contenuto di olio economico del 1-5% per candele, gomma, tessuti e applicazioni industriali ad alto volume.', 'Le Cere Bolle Semi Rivestite di Bio Green Wax (50-68°C) offrono prestazioni economiche con un contenuto di olio controllato (1-5%) per una durezza flessibile. Grade standard: 52/54°C (candele), 56/58°C (pilastri), 60/62°C (industriale). Ideali per la produzione di candele a costi contenuti, ausili per la lavorazione del caucciù, finissaggi tessili e rivestimenti per imballaggi all\'ingrosso, dove è importante un equilibrio tra performance e prezzo.', '2026-02-11 17:24:01', '2026-02-11 17:24:01'),
(15, 'prod-glycerine', 'Glicerina', 'La glicerina è un liquido incolore, inodore e viscoso, ampiamente utilizzato nelle industrie farmaceutiche, cosmetiche e alimentari.', 'Glicerina, anche nota come glicerolo o glicero, è un liquido incolore, inodore e viscoso con un sapore dolce. È un liquido trasparente, sciropposo, solitamente incolore, anche se può avere una leggera tonalità gialla. La glicerina ha una viscosità elevata, il che significa che scorre lentamente ed è relativamente densa. Ha una consistenza simile a quella dello sciroppo, che contribuisce alla sua capacità di mantenere l’umidità. La glicerina trova un ampio impiego nel settore farmaceutico, cosmetico, nell’industria alimentare e in varie applicazioni industriali.', '2026-02-11 17:20:03', '2026-02-11 17:20:03'),
(16, 'prod-hydrogenated-castor-oil', 'Olio di Ricino Idrogenato', 'L\'olio di ricino idrogenato è un derivato solido ceroso dell\'olio di ricino, utilizzato in cosmetici, prodotti farmaceutici e applicazioni industriali.', 'Olio di ricino idrogenato, noto anche come cera di ricino o scaglie di cera di ricino, è un derivato dell\'olio di ricino che subisce un processo di idrogenazione. Questo comporta l\'aggiunta di idrogeno alle molecole di olio di ricino, risultando in una sostanza solida e cerosa. Viene impiegato in prodotti cosmetici e per la cura personale come rossetti, creme e lozioni, come emolliente per offrire morbidezza e umidità alla pelle. Agisce anche come agente legante nelle formulazioni cosmetiche, aiutando gli ingredienti a stickarsi tra loro e ad aderire alla pelle.', '2026-02-11 17:25:26', '2026-02-11 17:25:26'),
(17, 'prod-microcrystalline-wax', 'Cera microcristallina', 'Cera microcristallina flessibile per cosmetici e adesivi', 'Cera microcristallina flessibile ideale per cosmetici, adesivi a caldo e rivestimenti speciali. Superiore flessibilità e proprietà di adesione.', '2026-02-11 17:23:17', '2026-02-11 17:23:17'),
(18, 'prod-olive-oil', 'Olio d\'oliva', 'Olio extravergine di oliva di qualità premium, spremuto a freddo da olive mediterranee selezionate per applicazioni culinarie, cosmetiche e industriali.', 'Il nostro olio extravergine di oliva di alta qualità è ottenuto a freddo da olive mediterranee selezionate con cura, garantendo un livello eccezionale di qualità e un sapore ricco. Ampiamente utilizzato in preparazioni alimentari, cosmetici, prodotti farmaceutici e per l\'igiene personale, l\'olio di oliva è apprezzato per i suoi benefici per la salute, le proprietà antiossidanti e le applicazioni versatili. Bio Green Wax fornisce olio d\'oliva che rispetta rigorosi standard internazionali di qualità, assicurando purezza e prestazioni costanti in tutte le applicazioni.', '2026-02-11 17:42:05', '2026-02-11 17:42:05'),
(19, 'prod-palm-kernel-oil', 'Olio di Nucleo di Palma', 'L\'olio di kernel di palma si ottiene dal nocciolo del frutto della palma da olio, utilizzato in prodotti alimentari, cosmetici e applicazioni industriali.', 'L\'olio di kernel di palmo deriva dal seme del frutto della palma da olio e possiede proprietà fisiche distinte. È generalmente un solido di colore dal giallo chiaro al bianco a temperatura ambiente, ma si scioglie in un liquido trasparente e giallo tendente al miele quando riscaldato. Il punto di fusione varia da 23 a 28 gradi Celsius (73 a 82 gradi Fahrenheit). L\'olio di kernel di palmo è ricco di acido laurico ed è ampiamente utilizzato nella produzione alimentare, cosmetici e nella produzione di saponi.', '2026-02-11 17:21:56', '2026-02-11 17:21:56'),
(20, 'prod-palm-kernel-olein', 'Oleina di nocciolo di palma', 'OLEINA DI PINOLI DI PALMA raffinata PREMIUM, la frazione liquida ottenuta dalla frazionatura dell\'olio di noce di palma, apprezzata per la sua eccezionale trasparenza, il basso punto di nuvola e l\'uso versatile negli settori alimentare, cura della persona e oleochimico.', 'Bio Green Wax rifornisce palm kerneloleina (PKOo) di alta qualità, la frazione liquida prodotta attraverso la frazionatura controllata dell\'olio di palma kernel raffinato. Quando l\'olio di palma kernel viene raffreddato sotto condizioni precise, si separa in una frazione solida (palm kernel stearin) e una frazione liquida (palm kernel olein). La oleina risultante è un olio limpido, di colore leggero, con un punto di fusione basso e una straordinaria fluidità.\n\nLa palm kernel olein è ricca di acido laurico (C12) e di acidi grassi a catena media capric/caprilico, donandole un\'eccellente trasparenza, rapida assimilazione e una sensazione leggera e non untuosa. Queste caratteristiche la rendono molto apprezzata nel settore alimentare come olio da cucina, medium per frittura e ingrediente in cremine non lattiero-casearie, gelati e formulazioni di latte ripieno.\n\nNel settore della cura personale e cosmetica, la palm kernel olein è ampiamente utilizzata come olio di base in lozioni, creme, shampoo e saponette liquide grazie alle sue eccellenti proprietà emollienti e compatibilità con la pelle. Serve anche come materia prima chiave nella produzione oleochimica, producendo acidi grassi, esteri metilici e tensioattivi utilizzati in detergenti e prodotti per la pulizia.\n\nBio Green Wax rifornisce la sua palm kernel olein da catene di approvvigionamento certificate RSPO, garantendo piena tracciabilità e coerenza con gli impegni per un’olio di palma sostenibile. Il prodotto è disponibile in forma raffinata, sbiancata e deodorata (RBD), soddisfacendo alti standard di qualità internazionali.', '2026-02-11 17:46:46', '2026-02-11 17:46:46'),
(21, 'prod-palm-kernel-stearin', 'Stearina di nocciolo di palma', 'Stearina di nocciolo di palma di alta qualità, la frazione solida ottenuta dalla frazionatura dell\'olio di cocco di palma, apprezzata per il suo profilo di fusione rapido e l\'eccellente durezza in applicazioni di confetteria, cosmetici e oleochimiche.', 'Bio Green Wax fornisce stearin di nocciolo di palma di qualità premium (PKS), la frazione solida a punto di fusione più alto prodotta attraverso la frazionatura controllata dell\'olio di nocciolo di palma raffinato. Durante la frazionatura, l\'olio di nocciolo di palma viene separato in due componenti: oleina di nocciolo di palma (la frazione liquida) e stearin di nocciolo di palma (la frazione solida). Lo stearin risultante è un grasso da bianco a bianco sporco, caratterizzato da un punto di fusione acuto e una consistenza compatta.\n\nLo stearin di nocciolo di palma è ricco di acido laurico (C12) e acido miristico (C14), il che gli conferisce un\'ottima durezza, rapida cristallizzazione e un profilo di fusione pulito. Queste proprietà lo rendono un ingrediente ideale per sostituti del burro di cacao (CBS), rivestimenti di cioccolato composito, ripieni di confetteria e lipidi speciali, dove sono richiesti un effetto croccante e una finitura brillante.\n\nOltre alle applicazioni alimentari, lo stearin di nocciolo di palma rappresenta una preziosa materia prima nell\'industria oleochimica per la produzione di acidi grassi, alcoli grassi, noodles di sapone e tensioattivi. Nel settore cura della persona e cosmetici, contribuisce a conferire corpo e struttura a creme, lozioni e formulazioni solide.\n\nBio Green Wax proviene da catene di approvvigionamento certificata RSPO, garantendo piena tracciabilità e conformità agli impegni di sostenibilità dell’olio di palma. Il prodotto è disponibile in versione raffinata, bleached e deodorised (RBD), soddisfacendo gli standard di qualità internazionali per uso alimentare e tecnico.', '2026-02-11 17:21:08', '2026-02-11 17:21:08'),
(22, 'prod-palm-oil', 'Olio di Palma', 'Olio di palma e derivati della palma provenienti da fonti sostenibili', 'Olio di palma e derivati del palma provenienti da fonti sostenibili per la produzione alimentare, la produzione di saponi e detersivi. Opzioni certificate RSPO disponibili.', '2026-02-09 03:17:37', '2026-02-11 17:28:51'),
(23, 'prod-palm-shortenings', 'Mangimi di palma (punti di fusione elevati)', 'Grassi di palma ad alta temperatura di melting (46–52 °C) sono grassi speciali per pasticceria e frittura realizzati con olio di palma frazionato, progettati per offrire una struttura forte, un sapore neutro e una straordinaria stabilità al calore in applicazioni industriali impegnative.', 'Riduzioni di pasta di palma con punto di fusione elevato nella gamma dei 46–52 °C sono formulate con palm stearin e mid-fractions per offrire un alto contenuto di grasso solido, una consistenza compatta e una rete cristallina stabile a temperature ambientali e elevate. Questa gamma di fusione più alta garantisce una resistenza superiore al calore, stabilità ossidativa e una riduzione del fuoriuscita di olio, rendendole ideali per climi tropicali e linee di produzione ad alte temperature.\n​\n\nNelle applicazioni da forno, queste riduzioni garantiscono una buona aerazione, laminazione e fragilità, supportando crostate sfogliate, pasta choux, cracker alla crema, biscotti e cookies, mantenendo forma e consistenza anche in condizioni calde. Sono inoltre utilizzate come grassi robusti per frittura e impasti, e come sostituti di grassi animali in prodotti a base di carne, dove la loro struttura rigida, stabilità dell\'emulsione e profilo zero-trans, non idrogenato aiutano a ottenere una consistenza costante, una liberazione di sapore pulita e formulazioni che rispettano l’etichetta.', '2026-02-11 17:28:13', '2026-02-11 17:28:13'),
(24, 'prod-palm-stearic-acid', 'Acido stearico palmaceo', 'L\'acido stearico di palma è un acido grasso saturo derivato dall\'olio di palma, utilizzato in cosmetici, candele e nella produzione di rubber.', 'L\'acido stearico di palma è un tipo di acido grasso derivato dall\'olio di palma, ottenuto attraverso il processo di separazione e cristallizzazione degli acidi grassi. È un acido grasso saturo noto per la sua stabilità e la forma solida a temperatura ambiente. L\'acido stearico di palma ha un aspetto ceroso che varia dal bianco al leggermente giallo. Ha un punto di fusione tipicamente tra 55 e 70 gradi Celsius (131-158 gradi Fahrenheit), il che ne permette una facile integrazione in diverse formulazioni per cosmetici, candele e prodotti in gomma.', '2026-02-11 17:39:52', '2026-02-11 17:39:52'),
(25, 'prod-palm-stearin', 'Stearina di palma', 'Il palm stearin è la frazione solida dell\'olio di palma, comunemente utilizzata nella produzione alimentare, nella fabbricazione di candele e nella produzione di sapone.', 'Il palm stearin è una frazione solida dell\'olio di palma ottenuta attraverso il processo di frazionamento, noto per il suo elevato contenuto di acidi grassi saturi. È un grasso solido a temperatura ambiente, di colore bianco crema a giallo pallido e con una consistenza liscia e cerosa. Il palm stearin ha un punto di fusione più alto rispetto all\'olio di palma. È comunemente utilizzato nell\'industria alimentare per stabilizzare i grassi, produrre margarine e nella produzione di candele e saponi.', '2026-02-11 17:39:09', '2026-02-11 17:39:09'),
(26, 'prod-paraffin-wax', 'Cera di paraffina totalmente raffinata (50-68°C)', 'Bio Green Wax Paraffina interamente raffinata (50-68°C)—grado alimentare/farmaceutico, <0,5% di olio, durezza superiore. Ideale per candele, cosmetici, imballaggi e applicazioni industriali di precisione.', 'Le cere di Paraffina completamente raffinata di Bio Green Wax (con punti di fusione tra 50 e 68°C) presentano un contenuto di olio ultra-basso (<0,5%), eccezionale durezza e odore/colore neutri. Disponibili in gradi per candele (52/54°C, 56/58°C), per contenitori (50/52°C) e in gradi ad alta fusione per colate (64/66°C). Ideali per candele di alta qualità, cosmetici, rivestimenti per imballaggi alimentari e Stampi di precisione che richiedono purezza massima e una costanza di prestazioni elevata.', '2026-02-11 17:43:49', '2026-02-11 17:43:49'),
(27, 'prod-pf56-synthetic-wax', 'Cera Fischer-Tropsch (FT)', 'Cera Fischer–Tropsch (FT) è una cera paraffinica sintetica di alta purezza prodotta dal syngas, che offre un alto punto di fusione, bassa viscosità e eccellente durezza per applicazioni esigenti in plastica, rivestimenti, inchiostri, adesivi e modifica del bitume', 'La cera FT è prodotta tramite la sintesi Fischer‑Tropsch, dando origine a una cera bianca acqua, ultra‑pura, con una distribuzione di catene di carbonio stretta, un contenuto di olio molto basso e un\'eccezionale stabilità termica. Combina un alto punto di indurimento con una bassa viscosità di fusione e una forte durezza, offrendo una resistenza superiore ai graffi, controllo del gloss, effetti opacizzanti e lubrificazione in molte formulazioni.\n\nNella lavorazione di plastiche e PVC/CPVC, la cera FT funge da lubrificante interno ed esterno efficace e da ausilio alla lavorazione, riducendo la viscosità di fusione, migliorando il flusso e aumentando il rilascio dallo stampo e la stabilità dimensionale. È ampiamente utilizzata in adesivi a fusione a caldo e sensibili alla pressione, inchiostri da stampa e rivestimenti industriali per aumentare la durezza, la resistenza all\'abrasione e ai graffi, la resistenza al bloccaggio e l\'anti-settling, stabilizzando allo stesso tempo la viscosità. Altre applicazioni chiave includono la modificazione di asfaltature e bitumi, il masterbatch e la compounding di polimeri, la lavorazione di elastomeri, cere, tessuti e persino formulazioni cosmetiche, dove la cera FT garantisce una cristallinità controllata, una migliore resistenza all\'usura e alle rughe, e una sensazione liscia al tatto.', '2026-02-11 17:44:51', '2026-02-11 17:44:51'),
(28, 'prod-pfad', 'PFAD (Distillato di Acidi Grassi di Palma)', 'PFAD è un sottoprodotto della raffinazione dell\'olio di palma, utilizzato nella produzione di saponi, mangimi per animali e biocarburanti.', 'Il Distillato di Acidi Grassi di Palma (PFAD) è un sottoprodotto del processo di raffinazione dell\'olio di palma. Si ottiene tramite la distillazione dell\'olio di palma grezzo per rimuovere le impurità e raggiungere un livello di purezza più elevato. Il PFAD è un liquido di colore giallo-bruno con un odore caratteristico. Contiene una miscela di acidi grassi saturi e insaturi, con gli acidi grassi predominanti che sono acido laurico, acido miristico e acido palmitico. Il PFAD viene utilizzato nella produzione di saponi, nei mangimi per animali e nella produzione di biocarburanti.', '2026-02-11 17:26:56', '2026-02-11 17:26:56'),
(29, 'prod-pkfad', 'Distillato di acidi grassi di nocciolo di palma (PKFAD)', 'PKFAD è un sottoprodotto della raffinazione dell\'olio di noce di palma, ricco di acido laurico, utilizzato nelle industrie del sapone e oleochemiche.', 'Distillato di Acidi Grassi del Cocco di Palma (PKFAD) è un sottoprodotto ottenuto durante il raffinamento dell\'olio di noce di palma. È ricco di acidi grassi, tra cui l\'acido laurico, rendendolo prezioso per alcune applicazioni industriali. Il PKFAD viene utilizzato in diverse applicazioni industriali, tra cui la produzione di saponi, la produzione di biocarburanti e come materia prima nell\'industria oleochimica.', '2026-02-11 17:40:34', '2026-02-11 17:40:34'),
(30, 'prod-polyethylene-wax', 'Cera di polietilene (cera PE)', 'è un polietilene a basso peso molecolare usato come lubrificante ad alte prestazioni e aiuto alla lavorazione in materie plastiche, rivestimenti, inchiostri e adesivi, migliorando la fluidità, la scarica superficiale e la resistenza ai graffi.', 'La cera di polietilene è una cera sintetica finemente dispersa, con un punto di fusione elevato, bassa viscosità, eccellente stabilità termica e forte compatibilità con i polimeri comuni come PVC, PE, PP e EVA. Essa fornisce lubrificazione interna ed esterna, riduce la viscosità del fusione e l\'attrito, migliora il rilascio dagli stampi e conferisce una superficie liscia, lucida e resistente ai graffi.\n​\n\nLe principali applicazioni includono la lavorazione di plastica e masterbatch, dove la cera di PE migliora l\'efficienza di estrusione e stampaggio a iniezione, previene l\'accumulo nelle calanderie e favorisce la dispersione di pigmenti e riempitivi. Viene inoltre impiegata in adesivi hot-melt e a pressione sensibile, inchiostri e rivestimenti in polvere per controllare la viscosità di fusione, aumentare la coesione e la durezza, e ottimizzare i tempi di apertura e di setting. Ulteriori utilizzi includono bitume e vernici per la segnaletica stradale, compositi legno-plastica, compound di gomma, prodotti di rivestimento per cavi e cere formulate come lucidanti e pastelli, dove innalza il punto di punteggiatura, la durezza e la resistenza all\'acqua.', '2026-02-11 17:43:01', '2026-02-11 17:43:01'),
(31, 'prod-rapeseed-oil', 'Olio di colza', 'Olio di colza spremuto a freddo e raffinato proveniente da aziende agricole del Regno Unito', 'Olio di colza spremuto a freddo e raffinato proveniente da aziende agricole del Regno Unito. Ideale per cucinare, arrostire e condire insalate. Ricco di omega-3 e povero di grassi saturi.', '2026-02-11 17:34:33', '2026-02-11 17:34:33'),
(32, 'prod-rapeseed-wax', 'Cera di colza', 'La cera di colza è una cera vegetale naturale utilizzata come alternativa ecologica nella produzione di candele e cosmetici.', 'La cera di colza è una cera vegetale naturale derivata dall\'olio della pianta di colza, comunemente usata come alternativa ecologica alla cera di paraffina tradizionale nella produzione di candele e in altre applicazioni. Offre una combustione pulita e lenta, oltre a un buon mantenimento della fragranza. La cera di colza è frequentemente impiegata nella produzione di candele e nella formulazione di cosmetici naturali come balsami per le labbra, lozioni e creme, offrendo proprietà idratanti.', '2026-02-11 17:24:42', '2026-02-11 17:24:42'),
(33, 'prod-soap-noodles', 'Noodle di sapone', 'Le noodles di sapone sono materie prime primarie per la produzione di sapone, ottenute tramite saponificazione di oli e grassi vegetali.', 'Fili di sapone, anche conosciuti come granuli di sapone, sono una delle materie prime principali utilizzate nella produzione di sapone. Vengono prodotti processando oli e grassi vegetali con idrossido di sodio (soda caustica) tramite saponificazione. I fili di sapone sono generalmente blocchi o perle di colore bianco solido o avorio, con un aroma delicato e neutro. Sono privi di impurità e contengono una concentrazione elevata di acidi grassi che contribuiscono alle loro proprietà detergenti ed emulsionanti.', '2026-02-11 17:41:20', '2026-02-11 17:41:20'),
(34, 'prod-soy-wax', 'Cera di soia', 'Cera di soia è una cera vegetale rinnovabile ottenuta dall\'olio di soia, popolare per la realizzazione di candele eco-sostenibili.', 'La cera di soia è un tipo di cera vegetale derivata dall\'olio di soia. È un\'alternativa popolare alla tradizionale cera di paraffina, che proviene dal petrolio. La cera di soia è considerata un\'opzione rinnovabile, biodegradabile ed eco-compatibile per la produzione di candele. Si ottiene attraverso l\'idrogenazione dell\'olio di soia, trasformandolo in una forma solida adatta alle candele. Di solito si presenta sotto forma di scaglie, facili da misurare e sciogliere.', '2026-02-11 17:17:58', '2026-02-11 17:17:58'),
(35, 'prod-soybean-oil', 'Olio di semi di soia', 'Olio di soia di alta qualità per uso industriale e culinario', 'L\'olio di soia è un versatile olio vegetale estratto dai semi di soja, ampiamente utilizzato per friggere, cucinare al forno e condire insalate grazie al suo sapore neutro e al suo alto punto di fumo.  \nÈ ricco di grassi polinsaturi, tra cui acidi grassi omega‑3 e omega‑6, e fornisce vitamina K e vitamina E.  \nÈ perfetto per la frittura profonda, la produzione di margarina e applicazioni alimentari industriali. Rifinito e deodorato secondo standard di alta qualità.', '2026-02-11 17:29:31', '2026-02-11 17:29:31'),
(36, 'prod-sunflower-oil', 'Olio di semi di girasole', 'Olio di girasole raffinato premium per cucina e trasformazione alimentare', 'Il nostro olio di semi di girasole raffinato premium è perfetto per la cottura, la frittura e le applicazioni di trasformazione alimentare. Prodotto da semi di girasole di qualità e raffinato secondo i più alti standard.', '2026-02-09 03:22:39', '2026-02-11 17:22:38');
INSERT INTO `products_ja` (`id`, `master_id`, `name`, `description`, `full_description`, `created_at`, `updated_at`) VALUES
(1, 'bdf424df-f9b0-4a79-84d6-f6ed1eb1e84f', 'パームオレイン', 'パームオレインは、精製パーム油の液体分画であり、味が中性的で長持ちする揚げ油・料理油として高く評価されています。スナック、ファストフード、家庭用の用途において、安定した油性とサクサクとした食感を提供します。', 'パームオレインは、精製・漂白・脱臭（RBD）したパーム油を分別し、透明な液体を得ることで製造されます。この液体はオレイン酸とパルミチン酸に富み、自然に優れた酸化安定性を持つバランスのとれた脂肪酸組成を示しています。その高い煙点、酸化やポリマー形成に対する耐性、低臭化傾向により、繰り返しの揚げ物調理が可能で、油の劣化や泡立ちを抑え、完成品の賞味期限を延ばすことができます。\n\n食品用途では、パームオレインはスナック、ポテトチップス、フライドチキン、即席麺、冷凍揚げ食品の揚げ油として広く使用されているほか、多くの熱帯地域の家庭用料理油としても一般的です。また、ダイズ油、ヒマワリ油などの植物油とブレンドした基油として、栄養や機能性の調整を目的とした用途にも利用されています。マーガリンやベーカリー用脂肪、フライヤーなどのフードサービス用途でも、安定した性能とクリーンな風味を求められる場面で重宝されています。', '2026-02-11 17:15:17', '2026-02-11 17:15:17'),
(2, 'prod-beeswax', 'ミツロウ', '化粧品やキャンドル作りのための純粋な天然蜜蠟', '倫理的な養蜂家から仕入れた純天然の蜜蝋。化粧品、ロウソク作り、食品用途に最適です。さまざまな等級でご提供しています。', '2026-02-05 21:57:34', '2026-02-11 17:29:51'),
(3, 'prod-bw101-palm-wax', 'パームワックス', 'プレミアム100％パームワックス、クリーミーな黄色で、キャンドル制作に理想的です。RSPO SG（セグリゲーテッド）/MB（マスマーケティング）認証取得。', 'プレミアム100%パームワックスは、美しいクリーミーな黄色をしています。RSPO MB認証を取得しており、持続可能性を証明しています。キャンドル作り、成形、コンテナキャンドルに最適です。', '2026-02-05 22:05:07', '2026-02-11 17:45:29'),
(4, 'prod-bw105-palm-wax', 'パームショートニング（低融点）', 'パームショートニングは、部分固化されたパーム油から得られる半固体の非水素化脂肪であり、優れた安定性とニュートラルな風味を備えています。', 'パームショートニングは、部分的に岩せきされたパーム油から得られる半固体の非水素化脂肪で、優れた安定性と中立的な風味を提供します。\nベーカリー用途に最適で、サクサクしたペストリー、しっとりとしたケーキ、カリッとした揚げ物などを、高い煙点で作るのに適しています。\n工業用ベーキングにおいて、バターやラードのコスト効率の良い酸化耐性のある代替品です。', '2026-02-06 02:26:35', '2026-02-11 17:31:11'),
(5, 'prod-bw10510-blended-wax', 'ジャーキャンドル用パームパラフィン混合ワックス', 'すぐに使える低MPジャーキャンドルブレンド：パームパラフィン、マイクロクリスタル、Polyboost™、Vybar®、UV安定剤を配合—色と香りを加えるだけで優れたガラスへの密着性と最大の香り拡散を実現。', 'Bio Green Waxの低融点ジャーキャンドルブレンド（48-50°C）および（50-52°C）—パルム・パラフィン・マイクロクリスタリン配合のガラス容器向け最適化フォーミュレーション。すぐに使える状態で、色と香りを追加するだけです。Polyboost／Vybarによる不透明性／付着性向上、UV安定剤／酸化防止剤による保存性、さらに香り保持剤を備え、優れたホット／コールドスロー、ひび割れのない燃焼、そしてプレミアム容器キャンドル向けの優れたジャー保持性を実現します。', '2026-02-06 03:36:39', '2026-02-11 17:37:17'),
(6, 'prod-bw10555-blended-wax', 'ソイベースのビーガンワックスブレンド', 'Bio Green Waxの使い切りタイプの95％ソイヴィーガンブレンド—ジャー（48-52°C）とパイラー（56-62°C）キャンドル用の純植物由来。色と香りを加えるだけ。', 'Bio Green Waxの95%大豆ワックスヴィーガンブレンド（植物添加物5%）は、ガラスジャーやスタンドアロンのピラーキャンドルにおいて、クリーンな燃焼とナチュラルなパフォーマンスを提供します。容器用の低融点（48-52°C）とピラー用の高融点（56-62°C）の2種類があります。使用準備完了：お好みの色と香りを加えるだけで、優れた香りの広がりとなめらかな仕上がりが得られます。', '2026-02-06 03:44:10', '2026-02-11 17:31:58'),
(7, 'prod-bw10610-blended-wax', 'パームパラフィン混合キャンドル用ワックス', '即使用可能な高MPピラーキャンドルブレンド（56-58°Cおよび58-60°C）：パームパラフィン-ミクロクリスタル with Polyboost™、Vybar®、UV安定剤—色と香りを加えるだけで優れたピラー性能を発揮します。', 'Bio Green waxのHigh Melting Point Pillar Candle Blends（56-58°C＆58-60°C）—パーム・パラフィン・マイクロクリスタル配合の独立型ピラーキャンドル用設計。すぐに使える：色と香りを加えるだけで完成。Polyboost／Vybarを使用して型離れと不透明度を最適化し、UV安定剤／抗酸化剤で長期保存性を向上、さらに香り保持剤により優れたホット／コールドスロー、完璧なピラー形状保持、クリーンな燃焼性能を実現。', '2026-02-06 03:40:14', '2026-02-11 17:38:05'),
(8, 'prod-bw10655-blended-wax', 'ソイ・ビーズワックス・パラフィンワックスブレンド', 'Bio Green Waxの使い切り済みの大豆ワックス・蜜蝋・パラフィンのブレンド—ジャー（48-52°C）＆ピラー（56-62°C）キャンドル用の最高のフレグランス投与。香料とカラーを加えるだけ。', 'Bio Green Waxのソイ・ビーズワックス・パラフィンブレンドは、自然なソイの滑らかさ、ビーズワックスの安定性、そしてパラフィンの香りの持続力を兼ね備えた、比類のない香りのパフォーマンスを実現します。低融点（48-52°C）はガラス容器に最適で、高融点（56-62°C）はピラーキャンドルに最適です。すぐに使用できるフォーミュレーションで、香料とカラーを加えるだけで、優れたホット＆コールドスローローと完璧なキャンドル仕上げを実現します。', '2026-02-06 03:47:35', '2026-02-11 17:32:50'),
(9, 'prod-bw8307-blended-wax', 'ココナッツ・菜種油ブレンドワックス', 'Bio Green Waxのすぐに使えるココナッツ・菜種ブレンド—ジャー（48-52°C）およびパイラー（56-62°C）キャンドルのためのクリーミーでナチュラルなパフォーマンス。色と香りを追加するだけです。', 'Bio Green Waxのココナッツと菜種のブレンドは、ココナッツワックスのクリーミーな質感と菜種ワックスの滑らかな燃焼を組み合わせ、優れた自然派キャンドルの性能を実現します。溶解点は低めの（48-52°C）でコンテナキャンドルに最適化されており、ピラーキャンドルには高めの（56-62°C）を採用。完全に使う準備が整っており、カラーや芳香剤を加えるだけで、プロフェッショナルでクリーンな燃焼結果を得られます。', '2026-02-06 03:51:25', '2026-02-11 17:33:38'),
(10, 'prod-carnauba-wax', 'カルナウバワックス', 'ポリッシュやコーティングに最適なプレミアムブラジル産カーネウバワックス', 'プレミアムブラジルカーナバワックスは、「ワックスの女王」として知られています。車のポリッシュ、化粧品、食品コーティングに理想的です。天然成分中最高の融点を持ちます。', '2026-02-05 22:01:05', '2026-02-11 17:30:28'),
(11, 'prod-castor-oil', 'ヒマシ油', '医薬品、化粧品、工業用途に広く使用されている、ヒマシ種子から抽出されたプレミアムコールドプレッシャー製キャスターオイル。', 'Bio Green Waxは、高品質のヒマシ油を提供しています。ヒマシ油は、ヒマシの種子（Ricinnus communis）の種子を圧搾して得られる多用途の植物油です。その独特の化学組成はリシノレイン酸（約85〜90％）に富み、優れた粘度、潤滑性、保湿性を持ち、多くの産業分野で重要な役割を果たしています。\n\n私たちのヒマシ油は、純度と一貫性を最優先に厳選して調達・加工しています。コールドプレス（ヴァージン）と精製品の両方のグレードを取り扱っており、医薬品、化粧品、工業用途に適しています。油の優れた安定性とアルコールへの溶解性の高さは、他の植物油と一線を画し、優れた性能を求める配合に最適です。\n\nヒマシ油は自然分解性を持ち、再生可能な資源から作られています。これは、Bio Green Waxの持続可能で環境に配慮した調達への取り組みと一致しています。', '2026-02-11 17:16:16', '2026-02-11 17:16:16'),
(12, 'prod-coconut-oil', 'ココナッツオイル', '食品および化粧品用途のバージンおよび精製ココナッツオイル', '調理、製菓、化粧品用途に適したプレミアムバージンココナッツオイルと精製ココナッツオイル。さまざまな等級でご用意し、あなたのニーズにお応えします。', '2026-02-05 21:50:37', '2026-02-11 17:17:01'),
(13, 'prod-coconut-wax', 'ココナッツワックス', 'ココナッツワックスはココナッツ油から抽出された天然のワックスで、クリーンに燃えるキャンドルやエコフレンドリーな用途に高く評価されています。', 'ココナッツワックスは、ココナッツの油から抽出される天然のワックスで、キャンドル作りにおいてクリーンでじっくり燃える特性で知られています。多くの場合、他のワックスの持続可能な代替品と考えられています。ココナッツワックスは、その環境に優しい特性とフレグランスをよく保持する能力で高く評価されています。自然で再生可能な資源から得られ、長時間にわたりクリーンにゆっくり燃えるため、より長持ちで効率的な性能を実現します。', '2026-02-11 17:25:50', '2026-02-11 17:25:50'),
(14, 'prod-fr5456-paraffin-wax', '半精製パラフィンワックス（50-68°C）', 'Bio Green Wax セミリファインドパラフィン（50-68°C）—キャンドル、ゴム、繊維、及び大量生産の産業用途に適したコスト効果の高い1〜5％の油分含有量。', 'Bio Green Waxのセミリファインドパラフィンワックス（50-68°C）は、油分含有量（1-5％）を制御し、経済的な性能を提供します。柔軟な硬さを実現します。標準グレード：52/54°C（キャンドル用）、56/58°C（ピラー用）、60/62°C（工業用）。コストに敏感なキャンドル製造、ゴム加工補助剤、テキスタイル仕上げ、バルク梱包コーティングなど、バランスの取れた性能と価格が重要な用途に最適です。', '2026-02-06 04:05:46', '2026-02-11 17:23:43'),
(15, 'prod-glycerine', 'グリセリン', 'グリセリンは、無色で無臭の粘性液体であり、医薬品、化粧品、食品産業で広く使用されています。', 'グリセリンは、グリセロールやグリセリンとしても知られ、無色・無臭で粘性のある液体で、甘い味がします。透明でシロップ状の液体であり、一般的には無色ですが、わずかに黄色味を帯びることもあります。グリセリンは高い粘度を持ち、ゆっくりと流れ、比較的粘りがあるのが特徴です。そのシロップのような粘性は、湿気を保持する能力に寄与しています。グリセリンは、医薬品、化粧品、食品加工、さまざまな工業用途で広く使用されています。', '2026-02-11 17:19:44', '2026-02-11 17:19:44'),
(16, 'prod-hydrogenated-castor-oil', '水素添加精製ヒマシ油', '水添ヒマシ油は、ヒマシ油の固体のワックス状誘導体であり、化粧品、医薬品、工業用途に使用されています。', '水添ヒマシ油（キャスター wax またはキャスター waxflake とも呼ばれる）は、ヒマシ油を水素化した派生物であり、水素化工程を経て得られる固体のワックス状物質です。これはヒマシ油の分子に水素を付加することで生成されます。化粧品やパーソナルケア用品（リップスティック、クリーム、ローションなど）では、肌に滑らかさと潤いを与えるエモリエントとして使用されます。また、化粧品の配合剤としても作用し、成分同士を結びつけ、肌にしっかりと密着させる効果があります。', '2026-02-11 17:25:08', '2026-02-11 17:25:08'),
(17, 'prod-microcrystalline-wax', 'マイクロクリスタリンワックス', '化粧品および接着剤用の柔軟な微結晶ワックス', '化粧品、ホットメルト接着剤、特殊コーティングに理想的な柔軟なミクロクリスタルワックス。優れた柔軟性と粘着性を持ちます。', '2026-02-06 03:58:23', '2026-02-11 17:23:01'),
(18, 'prod-olive-oil', 'オリーブオイル', '高品質純粋オリーブオイル、選び抜かれた地中海産オリーブからコールドプレスで抽出し、料理、化粧品、工業用途に適します。', '当社のプレミアムピュアオリーブオイルは、厳選された地中海産のオリーブをコールドプレスして抽出しており、卓越した品質と豊かな風味をお届けします。食品の調理、化粧品、医薬品、セルフケア製品など幅広く使用されており、オリーブオイルはその健康効果、抗酸化作用、多用途な用途で高く評価されています。Bio Green Waxは、厳格な国際的品質基準を満たすオリーブオイルを調達し、すべての用途において一貫した純度と性能を保証します。', '2026-02-11 17:41:45', '2026-02-11 17:41:45'),
(19, 'prod-palm-kernel-oil', 'パーム核油', 'パーム核油は、ヤシの実の核から抽出され、食品、化粧品、工業用途に利用されています。', 'パーム核油は、ヤシの実の核から抽出される油で、独特の物理的特性を持ちます。常温では淡い黄色から白色の固体ですが、加熱すると透明な黄色がかった液体に変わります。融点は23度から28度 Celsius（73度から82度 Fahrenheit）の範囲です。パーム核油はラウリン酸を豊富に含み、食品製造、化粧品、石鹸の製造などに広く使用されています。', '2026-02-11 17:21:36', '2026-02-11 17:21:36'),
(20, 'prod-palm-kernel-olein', 'パーム核オレイン', 'プレミアム高精製パーム核油オレインは、パーム核油の分留により得られる液状成分であり、その優れた透明度、低クラウドポイント、多用途な用途から、食品、パーソナルケア、オレオケミカル産業で高く評価されています。', 'Bio Green Waxは、高品質なパーム核オレイン（PKOo）を供給します。これは、精製されたパーム核油の制御された分別によって生産される液体成分です。パーム核油を正確な条件下で冷却すると、固体部分（パーム核ステアリン）と液体部分（パーム核オレイン）に分離します。得られるオレインは、透明で薄い色をした油で、融点が低く、優れた流動性を持っています。\n\nパーム核オレインは、ラウリン酸（C12）やカプリル／カプリン酸などの中鎖脂肪酸が豊富で、そのために抜群の透明度、迅速な吸収性、軽くてベタつかない感触を備えています。これらの特徴により、食用油や揚げ油、非乳製品のクリーマー、アイスクリーム、乳脂肪入り製品の原料として、食品業界で高く評価されています。\n\nパーソナルケア・化粧品分野では、パーム核オレインは、ローション、クリーム、シャンプー、液体石鹸の基油として広く使用されており、その優れたエモリエント効果と肌親和性によって支持されています。また、脂肪酸、メチルエステル、界面活性剤などのオレオケミカル原料の主要な原料としても機能し、洗剤やクリーニング製品に利用されています。\n\nBio Green Waxは、RSPO認証済みのサプライチェーンからパーム核オレインを調達し、完全なトレーサビリティと持続可能なパーム油のコミットメントに沿った供給を保証します。本製品は、リファインド、漂白、脱臭（RBD）された形態で入手可能であり、厳しい国際品質基準を満たしています。', '2026-02-11 17:46:19', '2026-02-11 17:46:19'),
(21, 'prod-palm-kernel-stearin', 'パーム核ステアリンプラン', '高品質なパーム核ステアリンは、パーム核油の分別抽出によって得られる固体部分であり、そのシャープな融点と優れた硬度から、菓子、化粧品、およびオレオケミカル用途で高く評価されています。', 'Bio Green Waxは、精製パーム核油の制御された分別によって生成される高融点の固体成分であるプレミアムグレードのパーム核ステアリン（PKS）を供給します。分別の過程で、パーム核油はパーム核オレイン（液体成分）とパーム核ステアリン（固体成分）の2つに分離されます。その結果得られるステアリンは、特徴的なシャープな融点としっかりとした質感を持つ白色から淡い色調の脂肪です。\n\nパーム核ステアリンは、ラウリン酸（C12）とミリスチン酸（C14）が豊富に含まれており、優れた硬さ、急速な結晶化、クリーンな融解特性を備えています。これらの特性により、ココアバター代用品（CBS）、複合チョコレートコーティング、菓子のフィリング、そしてパリッとした仕上がりと光沢を必要とする特殊脂肪の成型に理想的な成分となっています。\n\n食品用途以外にも、パーム核ステアリンはオレオケミカル産業において脂肪酸、脂肪アルコール、ソープヌードル、界面活性剤の生産において貴重な原料として使用されています。パーソナルケアや化粧品の分野では、クリームやローション、固形製品にボディと構造を付与します。\n\nBio Green Waxは、RSPO認証のサプライチェーンからパーム核ステアリンを調達し、完全なトレーサビリティと持続可能なパーム油の約束を確保しています。同製品は精製・漂白・脱臭（RBD）処理済みで、食品および技術用途における国際的な品質基準を満たしています。', '2026-02-11 17:20:41', '2026-02-11 17:20:41'),
(22, 'prod-palm-oil', 'パーム油', '持続可能な調達のパーム油およびパーム誘導体', '食品製造、石鹸・洗剤製造向けのサステナブルに調達されたパーム油およびパーム由来製品。RSPO認証のオプションもご利用いただけます。', '2026-02-05 21:50:40', '2026-02-11 17:28:36'),
(23, 'prod-palm-shortenings', 'パームショートニング（高融点）', '高融点のパームショートニング（46～52°C）は、分別されたパーム油から作られる特殊なベーカリーおよび揚げ油であり、強い構造を保ち、爽やかな風味を与え、要求の厳しい工業用途において優れた耐熱性を発揮します。', '高融点パームショートニング（46–52°C範囲）は、パームステアリンと中間フラクションから成り、室温および高温で高い固形脂肪含有量、しっかりとした食感、安定した結晶網を実現します。このより高い融解範囲は、優れた耐熱性、酸化安定性を提供し、油の酸化や脂肪の析出を抑えるため、熱帯地域や高温加工ラインに適しています。\n\n​\n\n製パン用途では、これらのショートニングは良好な発酵性、ラミネーション性、パリッとした食感をもたらし、サクサクのパイ生地、パフペストリー、クリームクラッカー、クッキー、ビスケットの形状や食感を温暖な環境でも維持します。また、耐久性のある揚げ油や生地脂肪、肉製品における動物性脂肪の代替品としても使用され、しっかりとした構造、乳化安定性、トランスゼロ・非水素化の特性により、一貫した食感、すっきりとした風味の放出、ラベル表示に優しい製品設計を可能にします。', '2026-02-11 17:27:50', '2026-02-11 17:27:50'),
(24, 'prod-palm-stearic-acid', 'パームステアリン酸', 'パルミチン酸は、ヤシ油から抽出される飽和脂肪酸であり、化粧品、ろうそく、ゴムの製造に使用されています。', 'パームステアリン酸は、パーム油から抽出された脂肪酸の一種で、脂肪酸を分離し結晶化させるプロセスで得られます。これは飽和脂肪酸であり、常温での安定性と固形状態が特徴です。パームステアリン酸は、白色からやや黄みを帯びたろう状の外観を持ちます。融点は通常55～70度 Celsius（131～158度 Fahrenheit）の範囲で、さまざまな化粧品、キャンドル、ゴム製品の配合に容易に組み込むことができます。', '2026-02-11 17:39:34', '2026-02-11 17:39:34'),
(25, 'prod-palm-stearin', 'パームスチアリン', 'パームステアリンはパーム油の固体部分であり、食品製造、キャンドル製造、石鹸作りに一般的に使用されています。', 'パームステアリンは、分別工程によって抽出されるパーム油の固体部分であり、高い飽和脂肪酸含有量で知られています。常温で固体の脂肪であり、クリーミーな白色から淡黄色を帯びた色合いと、滑らかでワックスのような質感があります。パームステアリンは、パーム油に比べて融点が高いです。食品業界では、脂肪の安定化、マーガリンの製造、キャンドルや石鹸の製造に一般的に使用されています。', '2026-02-11 17:38:51', '2026-02-11 17:38:51'),
(26, 'prod-paraffin-wax', '完全精製パラフィンワックス (50-68°C)', 'Bio Green Wax 完全精製パラフィン（50-68°C）—食品/医薬品等級、油分<0.5%、優れた硬度。キャンドル、化粧品、パッケージング、精密工業用途に最適です。', 'Bio Green Waxの完全精製パラフィンワックス（融点50～68°C）は、超低油分（<0.5%）、優れた硬さ、中性の香りと色を特徴としています。キャンドルグレード（52/54°C、56/58°C）、容器グレード（50/52°C）、高融点ピラーグレード（64/66°C）で利用可能です。高純度と性能の一貫性が求められるプレミアムキャンドル、化粧品、食品包装コーティング、精密成形に最適です。', '2026-02-06 03:54:49', '2026-02-11 17:43:29'),
(27, 'prod-pf56-synthetic-wax', 'フィッシャー・トロプシュ（FT）ワックス', 'フィッシャー‐トロプシュ（FT）ワックスは、合成ガス（シンガス）から製造される高純度の合成パラフィンワックスであり、高い融点、低粘度、優れた硬度を備えており、プラスチック、コーティング、インク、接着剤、アスファルト改質などの demanding applications に適しています', 'FTワックスは、フィッシャー・トロプシュ合成によって生成され、水白色で超純粋なワックスを供給します。炭素鎖の分布が狭く、油分含有量が非常に低く、卓越した熱安定性を持っています。これにより、高い限界粘度と低い融解粘度、強い硬度を兼ね備え、優れた傷防止性、光沢コントロール、マット効果、潤滑特性を多くの配合において実現します。\n\nプラスチックやPVC/CPVCの加工において、FTワックスは効率的な内部および外部絶縁剤や加工助剤として作用し、溶融粘度を低減し、流動性を改善し、金型離型性と寸法安定性を向上させます。ホットメルト接着剤や感圧接着剤、印刷インキ、工業用コーティングなどで広く使用されており、硬度、耐摩耗性・傷抵抗性、ブロック抵抗性、防錆性を高めるとともに、粘度の安定化も行います。その他の主要な用途には、アスファルトやタールの改質、マスターバッチやポリマーコンパウンド、ゴム加工、ポリッシュ、繊維製品、さらには化粧品配合にも使用されており、FTワックスは結晶性の制御、耐摩耗性としわ抵抗性の向上、滑らかな感触を提供します。', '2026-02-06 04:16:56', '2026-02-11 17:44:24'),
(28, 'prod-pfad', 'PFAD（パーム脂肪酸 distillate）', 'PFADはパーム油精製の副産物であり、石鹸製造、動物飼料、バイオ燃料の製造に使用されます。', 'パーム脂肪酸精留物（PFAD）は、パーム油精製過程の副産物です。原料のパーム油を蒸留して不純物を除去し、より純度の高いものにすることで得られます。PFADは茶褐色から黄褐色の液体で、特徴的な香りがあります。飽和脂肪酸と不飽和脂肪酸の混合物であり、主要な脂肪酸はラウリン酸、ミリスチン酸、パルミチン酸です。PFADは石鹸製造、家畜飼料、バイオ燃料の生産に使用されています。', '2026-02-11 17:26:37', '2026-02-11 17:26:37'),
(29, 'prod-pkfad', 'パーム核脂肪酸蒸留物（PKFAD）', 'PKFADはパーム核油精製の副産物であり、ラウリン酸が豊富で、石鹸やオレオケミカル産業で使用されています。', 'パーム核脂肪酸蒸留物（PKFAD）は、パーム核油の精製過程で得られる副産物です。ラウリン酸を含む脂肪酸が豊富であり、特定の工業用途において価値があります。PKFADは、石鹸製造、バイオ燃料生産、オレオケミカル産業の原料など、さまざまな工業用途に利用されています。', '2026-02-11 17:40:17', '2026-02-11 17:40:17'),
(30, 'prod-polyethylene-wax', 'ポリエチレンワックス（PEワックス）', '低分子量ポリエチレンは、高性能な潤滑剤および加工助剤としてプラスチック、コーティング、インキ、接着剤に使用され、流動性、表面滑り性、引っかき傷耐性を向上させます。', 'ポリエチレンワックスは、微細な粒子の高融点合成ワックスであり、粘度が低く、優れた熱安定性を持ち、PVC、PE、PP、EVAなどの一般的なポリマーと高い互換性があります。内部および外部の潤滑剤として機能し、融点粘度や摩擦を低減し、金型の離型性を向上させ、滑らかで光沢のある、傷に強い表面を提供します。\n​\n\n主な用途には、プラスチックやマスターバッチの加工が含まれます。ここでPEワックスは、押出や射出成形の効率を改善し、ダイの堆積を防ぎ、顔料や充填材の分散を向上させます。また、ホットメルト接着剤や圧力感応型接着剤、インク、粉体コーティングにも使用され、融点粘度を制御し、結合性や耐久性を高め、開放時間や硬化時間を最適化します。さらに、瀝青や道路標示塗料、木材プラスチック複合材、ゴム配合、ケーブル用コンパウンド、ポリッシュやクレヨンなどの配合ワックス製品にも利用され、軟化点、硬度、防水性を向上させます。', '2026-02-06 04:01:43', '2026-02-11 17:42:35'),
(31, 'prod-rapeseed-oil', '菜種油', '英国の農場で採れたコールドプレスおよび精製された菜種油', 'イギリスの農場から仕入れたコールドプレスおよび精製された菜種油。調理、ロースト、サラダドレッシングに理想的です。飽和脂肪酸が少なく、オメガ-3が豊富です。', '2026-02-05 21:54:39', '2026-02-11 17:34:18'),
(32, 'prod-rapeseed-wax', 'ナノサフラワーワックス', '菜種油脂は、キャンドルや化粧品のエコフレンドリーな代替品として使用される天然の植物性ワックスです。', '菜種 wax は、菜種植物の油から抽出された天然植物性のワックスで、キャンドル作りやその他の用途において伝統的なパラフィンワックスの環境に優しい代替品として一般的に使用されています。クリーンでゆっくり燃える特性と、香りの保持性も優れています。菜種 wax は、キャンドルの製造やリップバーム、ローション、クリームなどの天然化粧品の調合に頻繁に使用され、保湿作用も提供します。', '2026-02-11 17:24:25', '2026-02-11 17:24:25'),
(33, 'prod-soap-noodles', 'ソープヌードル', 'ソープヌードルは、石鹸製造の原料の基本素材であり、植物油脂の皂化によって生産されます。', 'ソープヌードル（ソープグラニュールとも呼ばれる）は、石鹸の製造に使用される主要な原料のひとつです。植物油や脂肪を水酸化ナトリウム（苛性ソーダ）と反応させて鹸化させることで生産されます。ソープヌードルは、通常、白または薄色の固形の塊やビーズ状で、穏やかで中立的な香りを持っています。不純物がなく、洗浄・乳化特性に寄与する脂肪酸が豊富に含まれています。', '2026-02-11 17:41:02', '2026-02-11 17:41:02'),
(34, 'prod-soy-wax', 'ソイワックス', 'ソイワックスは、大豆油から作られる再生可能な植物性ワックスで、環境に優しいキャンドル作りに人気があります。', '大豆ワックスは、大豆油から抽出される植物性ワックスの一種です。従来の石油由来のパラフィンワックスの代替品として人気があります。大豆ワックスは、再生可能で生分解性があり、環境に優しいキャンドル素材とされています。大豆油を水素添加することで作られ、キャンドルに適した固形に変化させています。通常はフレーク状で販売されており、計量や溶かしやすさに優れています。', '2026-02-11 17:17:40', '2026-02-11 17:17:40'),
(35, 'prod-soybean-oil', '大豆油', '工業および料理用の高品質大豆油', '大豆油は、大豆から抽出される多用途な植物油であり、その中性の風味と高い煙点から、揚げ物、焼き菓子、サラダドレッシングに広く使用されています。  \nオメガ‑３やオメガ‑６脂肪酸を含む多価不飽和脂肪が豊富で、ビタミンKとビタミンEも供給します。  \n揚げ物、マーガリンの製造、産業用食品に最適です。精製・脱臭されて高品質の基準を満たしています。', '2026-02-05 21:50:40', '2026-02-11 17:29:16'),
(36, 'prod-sunflower-oil', 'ひまわり油', '料理および食品加工用のプレミアムリファインドひまわり油', '私たちのプレミアム精製ひまわり油は、調理、揚げ物、食品加工に最適です。高品質なひまわりの種から供給され、最高基準に精製されています。', '2026-02-05 21:43:22', '2026-02-11 17:22:22');
INSERT INTO `products_ko` (`id`, `master_id`, `name`, `description`, `full_description`, `created_at`, `updated_at`) VALUES
(1, 'bdf424df-f9b0-4a79-84d6-f6ed1eb1e84f', '팜 올린', '팜 올린은 정제된 팜오일의 액체 성분으로, 중화된 맛과 긴 튀김 수명, 바삭한 식감을 제공하는 안정적인 튀김 및 조리용 오일로 평가받으며, 간식, 패스트푸드, 가정용 제품에 적합합니다.', '팜 올레인(Palm olein)은 정제, 표백, 탈취(RBD)된 팜유를 분별하여 투명한 액체 상태로 만든 것으로, 올레산과 팔미트산이 풍부하게 함유되어 있어 자연스럽게 우수한 산화 안정성을 갖춘 균형 잡힌 지방산 프로필을 제공합니다. 높은 발연점, 산화 및 고분자 형성에 대한 저항성, 냄새 변질 가능성이 낮아 반복적인 튀김 과정에서도 기름의 분해가 줄어들고, 거품이 적게 생기며, 완성품의 유통기한이 연장됩니다.\n\n식품 용도에서, 팜 올레인은 스낵, 감자칩, 프라이드 치킨, 즉석 라면, 냉동 프라이드 식품 등의 딥 프라이용 매체로 널리 사용되며, 많은 열대 지역에서는 일반 가정용 조리유로도 활용됩니다. 또한, 콩기름, 해바라기유 또는 기타 채소유와 혼합하여 맞춤형 영양 및 기능적 프로필을 구현하는 베이스 오일로도 사용되며, 마가린, 제과용 유지, 식품 서비스용 튀김 시스템 등에서도 안정적인 성능과 깨끗한 맛을 유지하는 데 필수적입니다.', '2026-02-11 17:15:33', '2026-02-11 17:15:33'),
(2, 'prod-beeswax', '밀랍', '화장품 및 양초 제작용 순천연 밀랍', '윤리적인 양봉가로부터 공급받은 순수 천연 밀랍입니다. 화장품, 양초 제작, 식품 용도에 적합하며 다양한 등급으로 제공됩니다.', '2026-02-11 17:30:00', '2026-02-11 17:30:00'),
(3, 'prod-bw101-palm-wax', '파름 왁스', '고급 100% 팜 왁스, 크리미한 노란색으로 양초 제작에 이상적입니다. RSPO SG (Segregated) / MB (Mass balance) 인증 항목입니다.', '프리미엄 100% 야자 왁스는 아름다운 크리미 옐로우 색상을 자랑합니다. 환경 지속 가능성을 위해 RSPO MB 인증을 받았습니다. 양초 제작, 몰딩, 컨테이너 양초에 이상적입니다.', '2026-02-11 17:45:39', '2026-02-11 17:45:39'),
(4, 'prod-bw105-palm-wax', '팔름 쇼트닝(저녹는점)', 'Palm Shortening은 분별된 팜 오일에서 얻어지는 반고체, 비하이드로제네이티드 지방으로, 뛰어난 안정성과 중립적인 맛을 제공합니다.', 'Palm Shortening은 부분 경화되지 않은 반고체 형태의 지방으로, 팜유를 분획하여 얻으며 뛰어난 안정성과 중립적인 풍미를 제공합니다.\n베이커리 용도에 이상적이며, 크러스트가 바삭한 페이스트리, 부드러운 케이크, 높은 발연점의 바삭한 튀김 요리를 만들어 냅니다.\n산화 저항성이 높은 경제적인 버터 또는 라드 대체재로, 산업 제빵에 적합합니다.', '2026-02-11 17:31:24', '2026-02-11 17:31:24'),
(5, 'prod-bw10510-blended-wax', '병용 캔들용 팔름-파라핀 블렌드왁스', '사용 준비 완료된 Low MP 병 캔들 블렌드: 팜-파라핀-미크로크리스탈린과 Polyboost™, Vybar®, UV 안정제를 포함—색상과 향을 추가하기만 하면 뛰어난 유리 부착력과 최대 연기가 가능합니다.', 'Bio Green Wax의 저녹는점 병 Candle Blend (48-50°C) 및 (50-52°C)—유리 용기에 최적화된 Palm-Paraffin-Microcrystalline 조성. 사용 준비 완료: 색상과 향료만 추가하세요. Polyboost/Vybar를 활용한 불투명도/접착력 강화, UV 안정제/항산화제를 통한 저장 수명 연장, 그리고 향료 유지제와 함께 뛰어난 온/냉서 Throws, 주름 없는 연소, 우수한 병 유지력으로 프리미엄 용기 캔들에 적합합니다.', '2026-02-11 17:37:30', '2026-02-11 17:37:30'),
(6, 'prod-bw10555-blended-wax', '대두 기반 비건 왁스 블렌드', 'Bio Green Wax의 Ready-to-use 95% Soy Vegan Blend—Jar(48-52°C) 및 Pillar(56-62°C) 캔들용 순수 식물성 제품. 색상과 향만 더하면 완성됩니다.', 'Bio Green Wax의 95% Soy Wax Vegan Blend(식물 첨가제 5%)는 유리 용기와 독립형 기둥용으로 깨끗하게 타오르는 자연스러운 성능을 제공합니다. 용기용 저융점(48-52°C)과 기둥용 고융점(56-62°C)으로 제공됩니다. 바로 사용 가능하며, 색상과 향을 추가하기만 하면 뛰어난 향발산과 부드러운 마감 처리를 즐기실 수 있습니다.', '2026-02-11 17:32:13', '2026-02-11 17:32:13'),
(7, 'prod-bw10610-blended-wax', '기둥초용 팜-파라핀 혼합 왁스', '즉시 사용 가능한 고MP 기둥초 블렌드 (56-58°C & 58-60°C): Palm-Paraffin-Microcrystalline와 Polyboost™, Vybar®, UV 안정제—색상과 향만 추가하면 우수한 기둥초 성능을 발휘합니다.', 'Bio Green wax의 High Melting Point Pillar Candle Blends (56-58°C & 58-60°C)—독립형 필라 candle에 맞게 설계된 Palm-Paraffin-Microcrystalline 조성물. 바로 사용 가능: 컬러와 향료만 첨가하세요. Polyboost/Vybar로 몰드 방출과 불투명도 향상, UV 안정제/항산화제로 유통기한 연장, 향 유지제 포함으로 뛰어난 온/냉 불꽃, 완벽한 필라 형태 유지, 깔끔한 연소 성능을 제공합니다.', '2026-02-11 17:38:18', '2026-02-11 17:38:18'),
(8, 'prod-bw10655-blended-wax', 'soy-밀랍-파라핀 왁스 블렌드', 'Bio Green Wax의 즉시 사용 가능한 소이-비즈왁스-파라핀 블렌드— Jar(48-52°C)와 Pillar(56-62°C) 캔들의 향기 발산을 극대화합니다. 향과 색을 더하기만 하면 됩니다.', 'Bio Green Wax의 Soy-Beeswax-Paraffin 블렌드는 자연스러운 소이의 부드러움, 밀랍의 안정성, 그리고 파라핀의 향기 강도를 결합하여 비할 데 없는 향기 연출력을 자랑합니다. 낮은 용융점(48-52°C)은 유리 용기에서 뛰어난 성능을 발휘하며, 높은 용융점(56-62°C)은 필러에 이상적입니다. 바로 사용 가능한 포뮬러로, 향료와 색소만 추가하면 뛰어난 온도별(온/냉) 분사력과 결점 없는 캔들 마감이 가능합니다.', '2026-02-11 17:33:03', '2026-02-11 17:33:03'),
(9, 'prod-bw8307-blended-wax', '코코넛-유채왁스 블렌드', 'Bio Green Wax의 즉시 사용 가능한 코코넛-유채씨 블렌드—Jar(48-52°C) 및 Pillar(56-62°C) 양초용 크리미한 자연 성능. 색상과 향만 추가하세요.', 'Bio Green Wax의 Coconut-Rapeseed Blend는 코코넛 왁스의 크리미한 질감과 유채왁스의 부드러운 연소를 결합하여 뛰어난 자연 테이프 성능을 자랑합니다. 낮은 녹는점(48-52°C)은 용기 캔들에 최적화되어 있으며, 높은 녹는점(56-62°C)은 필러 캔들에 적합합니다. 완전히 사용 준비가 되어 있어, 색상과 향기만 선택하여 넣기만 하면 전문적이고 깨끗하게 타는 결과를 얻을 수 있습니다.', '2026-02-11 17:33:52', '2026-02-11 17:33:52'),
(10, 'prod-carnauba-wax', '카르나우바 왁스', '폴리시 및 코팅용 프리미엄 브라질 카르나우바 왁스', '프리미엄 브라질 카나우바 왁스, 흔히 \"왁스의 여왕\"으로 알려져 있습니다. 차량 광택, 화장품, 식품 코팅에 이상적입니다. 가장 높은 자연 녹는점이 특징입니다.', '2026-02-11 17:30:38', '2026-02-11 17:30:38'),
(11, 'prod-castor-oil', '피마자유', '프리미엄 냉압 착색 캐스터 오일은 리시누스 커뮤니스 씨앗에서 추출되며, 의약품, 화장품 및 산업용으로 널리 사용됩니다.', 'Bio Green Wax는 고품질의 피마자유를 공급합니다. 피마자유는 피마자 식물(Ricinus communis)의 씨를 압착하여 얻는 다양한 용도의 채소유입니다. 리시놀레산(약 85~90%)이 풍부한 독특한 화학 조성으로 알려진 이 오일은 뛰어난 점도, 윤활성, 보습 특성을 가지고 있어 다양한 산업 분야에서 매우 귀중하게 여겨집니다.\n\n저희 피마자유는 엄격한 원료 선정과 가공 과정을 거쳐 순도와 일관성을 최상의 수준으로 유지하고 있습니다. 냉압 (버진) 및 정제 등급으로 제공되며, 제약, 화장품, 산업용으로 사용할 수 있습니다. 이 오일은 뛰어난 안정성 및 알코올에 대한 용해도를 가지고 있어, 다른 식물성 오일과 차별화되며, 우수한 성능이 요구되는 제형에 이상적입니다.\n\n피마자유는 자연적으로 생분해 가능하며 재생 가능 자원에서 유래되어, Bio Green Wax의 지속 가능하고 환경 책임 있는 공급 원칙과 일치합니다.', '2026-02-11 17:16:31', '2026-02-11 17:16:31'),
(12, 'prod-coconut-oil', '코코넛 오일', '음식 및 화장품용 버진 및 정제 코코넛 오일', '요리, 베이킹 및 화장품 용도로 적합한 프리미엄 버진 및 정제된 코코넛 오일입니다. 다양한 등급으로 제공되어 귀하의 특정 요구에 부응합니다.', '2026-02-09 02:59:11', '2026-02-11 17:17:11'),
(13, 'prod-coconut-wax', '코코넛 왁스', '코코넛 왁스는 코코넛 오일에서 추출한 천연 왁스로, 깨끗하게 태우는 양초와 친환경적인 용도로 높이 평가됩니다.', '코코넛 왁스는 코코넛 오일에서 추출된 천연 왁스로, 양초 제작에서 깨끗하고 천천히 타는 특성으로 잘 알려져 있습니다. 이는 종종 다른 왁스의 지속 가능한 대안으로 여겨집니다. 코코넛 왁스는 친환경적인 특성과 향기를 잘 유지하는 능력으로 높이 평가됩니다. 자연스럽고 재생 가능한 자원에서 얻어지며, 더 오래 지속되고 효율적인 연소를 위해 깨끗하게 타는 양초를 만들어줍니다.', '2026-02-11 17:26:03', '2026-02-11 17:26:03'),
(14, 'prod-fr5456-paraffin-wax', '반정제 파라핀 왁스 (50-68°C)', 'Bio Green Wax 세미 정제 파라핀 (50-68°C)—양초, 고무, 섬유 및 대량 산업용 응용에 적합한 1-5% 오일 함유로 비용 효율적인 제품입니다.', 'Bio Green Wax의 Semi Refined Paraffin Waxes (50-68°C)는 유연한 경도를 위해 조절된 오일 함량(1-5%)으로 경제적인 성능을 제공합니다. 표준 등급: 52/54°C (양초용), 56/58°C (기둥용), 60/62°C (산업용). 비용 민감한 양초 제작, 고무 가공 보조제, 섬유 마감, 대량 포장 코팅 등에 이상적이며, 균형잡힌 성능과 가격이 가장 중요한 경우에 적합합니다.', '2026-02-11 17:23:56', '2026-02-11 17:23:56'),
(15, 'prod-glycerine', '글리세린', '글리세린은 무색, 무취의 점성 액체로, 의약품, 화장품, 식품 산업에서 널리 사용됩니다.', '글리세린(또는 글리세롤, 글리세린)은 무색, 무취의 점성 액체로 달콤한 맛이 있습니다. 일반적으로 무색의 시럽 같은 액체이며, 약간 노란빛이 도는 경우도 있습니다. 글리세린은 높은 점성으로 인해 천천히 흘러가며 비교적 두꺼운 성질을 가지고 있습니다. 시럽과 같은 농도를 지니고 있어 수분을 유지하는 데 뛰어나며, 제약, 화장품, 식품 가공, 다양한 산업 분야에서 광범위하게 사용됩니다.', '2026-02-11 17:19:57', '2026-02-11 17:19:57'),
(16, 'prod-hydrogenated-castor-oil', '수소화 피마자유', '수소화 피마자유는 피마자유의 고체 왁스성 유도체로, 화장품, 의약품 및 산업용으로 사용됩니다.', '수소화 피마자유(캐스터 왁스 또는 캐스터 왁스 플레이크라고도 함)는 피마자유에서 유래된 화합물로, 수소화 과정을 거쳐 생성됩니다. 이 과정은 피마자유 분자에 수소를 첨가하는 것으로, 고체의 왁스 같은 물질로 변하게 됩니다. 이 성분은 립스틱, 크림, 로션 등 화장품 및 개인 케어 제품에 피부에 부드러움과 수분을 제공하는 유연제로 사용됩니다. 또한 화장품 제조 시 결합제로서 역할을 하여 성분들이 서로 잘 붙고 피부에 잘 밀착되도록 돕습니다.', '2026-02-11 17:25:20', '2026-02-11 17:25:20'),
(17, 'prod-microcrystalline-wax', '미세결정 왁스', '화장품 및 접착제용 유연성 미세결정 왁스', '화장품, 핫멜트 접착제 및 특수 코팅에 이상적인 유연한 미세결정 왁스. 뛰어난 유연성과 접착력을 자랑합니다.', '2026-02-11 17:23:10', '2026-02-11 17:23:10'),
(18, 'prod-olive-oil', '올리브 오일', '프리미엄 품질의 순수 올리브유로, 지중해산 엄선된 올리브를 냉압착하여 요리, 화장품, 산업용으로 사용됩니다.', '저희 프리미엄 순수 올리브 오일은 엄선된 지중해산 올리브를 차가운 압착 방식으로 추출하여 뛰어난 품질과 풍부한 풍미를 자랑합니다. 식품 조리, 화장품, 의약품, 개인 케어 제품 등 다양한 분야에 널리 사용되며, 건강에 유익한 성분, 항산화 특성, 그리고 다목적 활용성으로 높이 평가받고 있습니다. Bio Green Wax는 엄격한 국제 품질 기준에 부합하는 올리브 오일만을 공급하여 모든 용도에서 안정적인 순도와 성능을 보장합니다.', '2026-02-11 17:41:59', '2026-02-11 17:41:59'),
(19, 'prod-palm-kernel-oil', '팜 커널 오일', '팜 kernel 오일은 야자 열매의 씨앗에서 추출되며, 식품, 화장품, 산업용 제품에 사용됩니다.', '팜커널 오일은 야자나무 열매의 핵심에서 추출되며, 뚜렷한 물리적 특성을 가지고 있습니다. 일반적으로 실온에서는 연한 노란색에서 흰색의 고체 상태를 띠며, 가열 시 맑은 노란빛 액체로 녹아내립니다. 녹는점은 23도에서 28도(73도에서 82도 화씨) 사이입니다. 팜커널 오일은 라우르산이 풍부하며, 식품 제조, 화장품, 비누 생산에 널리 사용됩니다.', '2026-02-11 17:21:49', '2026-02-11 17:21:49'),
(20, 'prod-palm-kernel-olein', '야자핵경유', '프리미엄 정제된 팜커널 오레인, 팜커널 오일을 분별하여 얻은 액체 부분으로서 뛰어난 투명도, 낮은 구름점, 식품, 퍼스널 케어 및 올레오케미컬 산업에서의 다용도 사용으로 가치가 높습니다.', 'Bio Green Wax는 정제된 팜커널 오일의 제어된 분별 공정을 통해 생산되는 액체 성분인 고품질 팜커널 올레인(PKOo)을 공급합니다. 팜커널 오일이 정밀한 조건 하에서 냉각되면 고체성분(팜커널 스테아린)과 액체성분(팜커널 올레인)으로 분리됩니다. 이렇게 얻어진 올레인은 맑고 밝은 색상의 낮은 융점과 뛰어난 유동성을 가진 투명한 기름입니다.\n\n팜커널 올레인은 라우릭산(C12)과 카프릴/카프릭 중쇄지방산이 풍부하여 뛰어난 투명도, 빠른 흡수력, 그리고 가볍고 끈적이지 않는 피부감촉을 제공합니다. 이러한 특징으로 인해 식품 산업에서는 조리용 오일, 튀김매체, 무유제품 크림, 아이스크림, 충진유 제품의 원료로 매우 인기가 높습니다.\n\n개인 케어 및 화장품 분야에서는 로션, 크림, 샴푸, 액체 비누의 기본 오일로 널리 사용되며, 뛰어난 피부연화 특성과 피부적합성으로 알려져 있습니다. 또한, 오일화학 제품의 주요 원료로서 지방산, 메틸 에스터, 계면활성제 등을 생산하는 데 사용되어 세제와 세정제의 원료로 활용됩니다.\n\nBio Green Wax는 RSPO 인증 공급망에서 팜커널 올레인을 공급하며, 전체 공급망의 투명성과 지속 가능한 팜유 공약에 부합됩니다. 본 제품은 정제, 표백, 탈취(RBD)된 형태로 제공되며, 엄격한 국제 품질 기준을 충족합니다.', '2026-02-11 17:46:36', '2026-02-11 17:46:36'),
(21, 'prod-palm-kernel-stearin', '팜 커널 스테아린', '고품질 팜커널 스테아린은 팜커널 오일의 분별 과정에서 얻어진 고체 부분으로, 선명한 녹는 점과 뛰어난 경도를 자랑하여 제과, 화장품, 올레오화학 제품에 널리 사용됩니다.', 'Bio Green Wax는 정제 팜커널유의 제어된 분별 과정을 통해 생산되는 고융점 고체 성분인 프리미엄 등급 팜 커널 스테아린(PKS)을 공급합니다. 분별 과정에서 팜커널유는 두 가지 성분으로 분리되며, 이는 팜커널 올레인(액체 성분)과 팜커널 스테아린(고체 성분)입니다. 이렇게 생성된 스테아린은 특유의 날카로운 융점과 단단한 질감을 가진 백색 또는 오프 화이트 계열의 지방입니다.\n\n팜커널 스테아린은 C12인 래우릭산과 C14인 미리스틱산이 풍부하여 우수한 경도, 빠른 결정화, 깨끗한 용융 특성을 갖추고 있습니다. 이러한 특성은 코코아버터 대체제(CBS), 합성초콜릿 코팅재, 제과 충전재, 그리고 크랙과 광택이 요구되는 특수 지방류에 이상적입니다.\n\n식품 이외의 용도에서도, 팜커널 스테아린은 지방산, 지방알코올, 비누누들, 계면활성제 생산을 위한 올레오케미컬 산업에서 중요한 원료로 사용됩니다. 또한 퍼스널 케어 및 화장품 분야에서는 크림, 로션, 고형 제형의 바디와 구조를 제공하는 역할을 합니다.\n\nBio Green Wax는 RSPO 인증 공급망에서 팜커널 스테아린을 조달하여, 완전한 추적 가능성과 지속가능한 팜오일 이행을 보장합니다. 이 제품은 정제, 표백, 탈취(RBD) 형태로 제공되며, 식품용 및 기술용 국제 품질기준을 충족합니다.', '2026-02-11 17:20:58', '2026-02-11 17:20:58'),
(22, 'prod-palm-oil', '팜 오일', '지속 가능한 방식으로 조달된 야자유와 야자유 유도체', '지속 가능하게 공급된 팜유 및 팜 유래 제품은 식품 제조, 비누 및 세제 생산에 사용됩니다. RSPO 인증 옵션도 제공됩니다.', '2026-02-09 03:17:10', '2026-02-11 17:28:45'),
(23, 'prod-palm-shortenings', '팜쇼트닝(고융점)', '고융점 팜 슈레딩(46–52 °C)은 정제된 팜유를 분별하여 만든 전문 베이커리 및 튀김용 지방으로, 강한 구조를 제공하고 깔끔한 맛과 뛰어난 내열 안정성을 갖추어 산업 현장에서 까다로운 요구에 적합하게 설계되었습니다.', '46–52 °C 범위의 고융점 팜 쇼트닝은 팜스테인과 미분획으로 만들어져 높은 고형 지방 함량, 단단한 질감, 안정된 결정망을 실내 및 고온 환경에서도 유지하도록 설계되었습니다. 이 높은 융점 범위는 뛰어난 내열성, 산화 안정성, 그리고 오일리 현상의 감소를 제공하여 열대 기후와 고온 가공 라인에 적합합니다.\n​\n\n제과 응용 분야에서는 이 쇼트닝이 우수한 기포화, 층 쌓기, 그리고 탁월한 부서짐을 제공하여 바삭한 파이 크러스트, 퍼프 페이스트리, 크림 크래커, 쿠키, 비스킷 등을 지지하며, 따뜻한 조건에서도 모양과 식감을 유지합니다. 또한 강인한 튀김용 및 반죽용 지방으로 사용되며, 육류 제품에서 동물성 지방 대체제 역할도 합니다. 이 제품들의 단단한 구조, 유화 안정성, 그리고 트랜스-제로, 비수소화 성분 특성은 일관된 식감, 깔끔한 풍미 발산, 그리고 라벨 친화적인 성분 구성에 도움을 줍니다.', '2026-02-11 17:28:05', '2026-02-11 17:28:05'),
(24, 'prod-palm-stearic-acid', '팜 스테아릭 애시드', '팜 스테아릭 산은 팜유에서 추출된 포화 지방산으로, 화장품, 양초, 고무 제조에 사용됩니다.', '팜스테아르산은 팜오일에서 추출된 지방산의 일종으로, 지방산을 분리하고 결정화하는 과정을 통해 얻어집니다. 이는 안정성과 상온에서 고체 상태를 유지하는 포화 지방산으로 알려져 있으며, 왁스 같은 흰색에서 약간 노란색을 띠는 외관을 가지고 있습니다. 팜스테아르산의 녹는점은 일반적으로 55-70도 섭씨(131-158도 화씨) 사이로, 화장품, 양초, 고무 제품 등 다양한 제형에 쉽게 통합할 수 있습니다.', '2026-02-11 17:39:45', '2026-02-11 17:39:45'),
(25, 'prod-palm-stearin', '팜 스테아린', 'Palm stearin은 팜유의 고체 부분으로, 일반적으로 식품 제조, 양초 제작, 비누 제조에 사용됩니다.', '팜 스테아린은 분별 과정을 통해 얻어진 팜유의 고체 부분으로, 높은 포화 지방산 함량으로 알려져 있습니다. 실온에서 고체 상태를 유지하며, 크림색이거나 연한 노란색을 띠고 부드럽고 왁스 같은 질감을 가지고 있습니다. 팜 스테아린은 팜유보다 녹는점이 높습니다. 식품 산업에서는 지방 안정화, 마가린 생산, 양초와 비누 제조에 일반적으로 사용됩니다.', '2026-02-11 17:39:03', '2026-02-11 17:39:03'),
(26, 'prod-paraffin-wax', '완전히 정제된 파라핀 왁스 (50-68°C)', 'Bio Green Wax 완전 정제 파라핀 (50-68°C)—식품/제약 등급, 유류 함유량 <0.5%, 탁월한 경도. 양초, 화장품, 포장, 정밀 산업용 애플리케이션에 적합합니다.', 'Bio Green Wax의 완전 정제 파라핀 왁스(녹는점 50-68°C)는 초저유지(<0.5%), 뛰어난 경도, 그리고 중성 냄새/색상을 특징으로 합니다. 촛불용 등급(52/54°C, 56/58°C), 용기용 등급(50/52°C), 고녹임 기둥용 등급(64/66°C)으로 제공됩니다. 프리미엄 촛불, 화장품, 식품 포장 코팅, 정밀 성형 등 최대 순도와 성능 일관성을 요구하는 제품에 이상적입니다.', '2026-02-11 17:43:43', '2026-02-11 17:43:43'),
(27, 'prod-pf56-synthetic-wax', '피셔-트롭스치 (FT) 왁스', '피셔‑트로프쉬 (FT) 왁스는 합성 가스(syngas)에서 생산되는 고순도 인조 파라핀 왁스로, 높은 녹는점, 낮은 점도, 뛰어난 경도를 갖추어 플라스틱, 코팅제, 잉크, 접착제, 아스팔트 개질 등의 까다로운 용도에 적합합니다.', 'FT 왁스는 Fischer‑Tropsch 합성을 통해 생성되며, 맑고 순백색의 초순수 왁스를 만들어 냅니다. 이 왁스는 좁은 탄소 사슬 분포, 매우 낮은 유분 함량, 뛰어난 열 안정성을 갖추고 있습니다. 높은 연화점과 낮은 용융 점도, 강한 경도를 결합하여 많은 제형에서 탁월한 긁힘 저항, 광택 조절, 무광 효과 및 윤활성을 제공합니다.\n\n플라스틱 및 PVC/CPVC 가공 시, FT 왁스는 내부 및 외부 윤활제와 가공 보조제로서 작용하여 용융 점도를 낮추고, 유동성을 개선하며, 금형 분리 및 치수 안정을 향상시킵니다. 또한 열용융 접착제와 압력 감응 접착제, 인쇄 잉크, 산업용 코팅제 등에 널리 사용되어 단단함, 마모 및 긁힘 저항, 블록 저항, 침전 방지 효과를 높이면서 점도 안정화에 기여합니다. 중요한 응용 분야로는 아스팔트 및 아스팔트 개질, 마스터배치 및 폴리머 혼합, 고무 가공, 광택제, 섬유, 그리고 화장품 제형이 있으며, FT 왁스는 결정성 조절, 마모 및 주름 저항 개선, 부드러운 촉각을 제공합니다.', '2026-02-11 17:44:43', '2026-02-11 17:44:43'),
(28, 'prod-pfad', 'PFAD (Palm Fatty Acid Distillate)', 'PFAD는 팜 오일 정제의 부산물로, 비누 제조, 동물 사료, 바이오연료 생산에 사용됩니다.', '팜 지방산 증류물 (PFAD)은 야자유 정제 과정의 부산물입니다. 원유 야자유를 증류하여 불순물을 제거하고 더 높은 순도를 달성하는 과정에서 얻어집니다. PFAD는 특유의 냄새를 가진 갈색빛 노란색 액체입니다. 포화 지방산과 불포화 지방산이 혼합되어 있으며, 주요 지방산은 라우르산, 미리스틴산, 팔미트산입니다. PFAD는 비누 제조, 동물 사료, 바이오디젤 생산에 사용됩니다.', '2026-02-11 17:26:48', '2026-02-11 17:26:48'),
(29, 'prod-pkfad', '야자핵유지방산증류물 (PKFAD)', 'PKFAD는 야자핵유 정제 과정에서 부산물로 생성되며, 라우릭산이 풍부하여 비누 및 올레오화학 산업에 사용됩니다.', 'Palm Kernel Fatty Acid Distillate (PKFAD)는 야자유 정제 과정에서 얻어지는 부산물입니다. 이 제품은 라우릭산을 포함한 다수의 지방산이 풍부하여 특정 산업용도에 가치가 있습니다. PKFAD는 비누 제조, 바이오연료 생산, 그리고 올레오화학 산업의 원료 등 다양한 산업 분야에 사용됩니다.', '2026-02-11 17:40:28', '2026-02-11 17:40:28'),
(30, 'prod-polyethylene-wax', '폴리에틸렌 왁스 (PE 왁스)', '저분자량 폴리에틸렌은 플라스틱, 코팅제, 잉크, 접착제에서 고성능 윤활제 및 가공 보조제로 사용되며, 유동성, 표면 미끄러짐, 흠집 저항을 향상시킵니다.', '폴리에틸렌 왁스는 미세 분쇄된 고융점의 합성 왁스로, 점도가 낮고 열 안정성이 뛰어나며 PVC, PE, PP, EVA와 같은 일반 폴리머와의 우수한 상용성을 자랑합니다. 내부 및 외부 윤활제 역할을 하며, 용융점 점도와 마찰을 감소시키고 금형탈출을 용이하게 하며, 매끄럽고 광택이 나는 긁힘 방지 표면을 제공합니다.\n​\n\n주요 용도는 플라스틱 및 마스터배치 가공으로, PE 왁스는 압출 및 사출 성형 효율을 높이고 다이 퇴적물 방지, 그리고 안료와 충전제의 분산을 개선합니다. 또한, 핫멜트 및 압력 감응 접착제, 잉크, 분체 코팅 등에 사용되어 용융점 점도를 조절하고, 결속력과 인성을 강화하며, 개시 및 경화 시간을 최적화합니다. 추가적으로 아스팔트 및 도로 표지용 페인트, 목질‑플라스틱 복합재, 고무 컴파운드, 케이블 컴파운드, 광택제 및 크레용과 같은 제형 왁스 제품에 사용되어 연화점, 경도, 방수성을 높입니다.', '2026-02-11 17:42:53', '2026-02-11 17:42:53'),
(31, 'prod-rapeseed-oil', '유채유', '영국 농장에서 생산된 냉압착 및 정제된 카놀라유', '영국 농장에서 생산된 냉압착 및 정제된 카놀라유. 요리, 구이, 샐러드 드레싱에 이상적입니다. 포화지방이 적고 오메가-3가 풍부합니다.', '2026-02-11 17:34:28', '2026-02-11 17:34:28'),
(32, 'prod-rapeseed-wax', '유채왁스', '유채왁스는 양초 제작과 화장품에 친환경적인 대안으로 사용되는 천연 식물성 왁스입니다.', '유채 왁스는 유채 식물의 기름에서 추출된 천연 식물성 왁스로, 전통적인 파라핀 왁스의 환경 친화적인 대안으로 촛불 제작 및 기타 용도에 일반적으로 사용됩니다. 깨끗하고 느리게 타며, 향기 유지력이 뛰어납니다. 유채 왁스는 촛불 생산뿐만 아니라 립 밤, 로션, 크림 등 천연 화장품의 조합에도 자주 사용되며, 보습 기능을 제공합니다.', '2026-02-11 17:24:36', '2026-02-11 17:24:36'),
(33, 'prod-soap-noodles', '비누 국수', '솝 누들은 비누 제조의 주 원료로, 식물성 기름과 지방의 비누화 과정을 통해 생산됩니다.', '비누 국수(Soap noodles), 또는 비누 과립(soap granules)라고도 하는 이 원료는 비누 제조에 사용되는 주요 원료 중 하나입니다. 식물성 기름과 지방을 수산화나트륨(가성소다, lye)과 반응시켜 비누화하는 과정인 비누화(saponification)를 통해 생산됩니다. 비누 국수는 일반적으로 연한 흰색 또는 미색의 덩어리 또는 구슬 형태로, 부드럽고 중성적인 향기를 가지고 있습니다. 불순물이 없으며, 세정력과 유화 특성을 높이는 지방산이 풍부하게 함유되어 있습니다.', '2026-02-11 17:41:14', '2026-02-11 17:41:14'),
(34, 'prod-soy-wax', '소이 왁스', '소이 왁스는 대두유로 만든 재생 가능한 식물성 왁스로, 환경 친화적인 캔들 제작에 인기 있습니다.', '소이 왁스는 대두유에서 추출된 식물성 왁스의 일종입니다. 이것은 석유에서 유래된 전통적인 파라핀 왁스의 인기 있는 대체품입니다. 소이 왁스는 재생 가능하고 생분해 가능하며 친환경적인 촛불 용품 선택으로 여겨집니다. 이는 대두유를 수소화하여 만들어지며, 촛불에 적합한 고체 형태로 변환됩니다. 일반적으로는 측정하기 쉽고 녹이기 편한 조각(플레이크) 형태로 제공됩니다.', '2026-02-11 17:17:52', '2026-02-11 17:17:52'),
(35, 'prod-soybean-oil', '대두유', '산업용 및 요리용 고품질 대두유', '대두유는 콩에서 추출한 다목적 식물성 기름으로, 중성적인 맛과 높은 연기점 덕분에 튀김, 베이킹, 샐러드 드레싱에 широко 사용됩니다.  \n이 기름은 오메가‑3와 오메가‑6 지방산을 포함한 다중불포화지방이 풍부하며, 비타민 K와 비타민 E를 제공합니다.  \n깊은 튀김, 마가린 생산, 산업용 식품에 적합합니다. 정제 및 탈취 과정을 거쳐 프리미엄 기준으로 제조됩니다.', '2026-02-11 17:29:26', '2026-02-11 17:29:26'),
(36, 'prod-sunflower-oil', '해바라기유', '요리 및 식품 가공용 프리미엄 정제 해바라기유', '우리의 프리미엄 정제 해바라기유는 조리, 튀김, 식품 가공에 적합합니다. 양질의 해바라기씨에서 공급되었으며, 최고 수준으로 정제되었습니다.', '2026-02-09 03:22:15', '2026-02-11 17:22:33');
INSERT INTO `products_pl` (`id`, `master_id`, `name`, `description`, `full_description`, `created_at`, `updated_at`) VALUES
(1, 'bdf424df-f9b0-4a79-84d6-f6ed1eb1e84f', 'Olej palmowy rafinowany', 'Oleina palmowa to płynna frakcja rafinowanego oleju palmowego, ceniona jako stabilny olej do smażenia i gotowania, który zapewnia neutralny smak, długą trwałość podczas smażenia oraz chrupiącą teksturę dla przekąsek, fast foodów i zastosowań domowych.', 'Palm olein jest produkowany poprzez frakcjonowanie rafinowanego, wybielonego i deodorowanego (RBD) oleju palmowego, aby uzyskać klarowny płyn bogaty w kwasy oleinowy i palmitynowy, zapewniający zrównoważony profil kwasów tłuszczowych z naturalnie dobrą stabilnością oksydacyjną. Jego wysoka temperatura dymienia, odporność na utlenianie i tworzenie się polimerów oraz niska skłonność do tworzenia nieprzyjemnych smaków umożliwiają wielokrotne smażenie z mniejszym rozkładem oleju, mniej pienienia i wydłużonym okresem przydatności końcowych produktów.\n​\nW zastosowaniach spożywczych palm olein jest powszechnie używany jako medium do głębokiego smażenia przekąsek, czipsów ziemniaczanych, kurczaka smażonego, instant noodle i mrożenek wcześniej smażonych, a także jako uniwersalny olej kuchenny w wielu rynkach tropikalnych. Służy również jako olej bazowy w mieszankach z sojowym, słonecznikowym lub innymi olejami roślinnymi, aby uzyskać dostosowane profile odżywcze i funkcjonalne, a także jest stosowany w margarynach, tłuszczach piekarniczych i systemach smażenia w gastronomii, gdzie kluczowa jest stabilna wydajność i czysty smak.', '2026-02-11 17:15:45', '2026-02-11 17:15:45'),
(2, 'prod-beeswax', 'Wosk pszczeli', 'Czysty naturalny wosk pszczeli do kosmetyków i produkcji świec', 'Czysty naturalny wosk pszczeli pochodzący od etycznych pszczelarzy. Idealny do produkcji kosmetyków, świec oraz zastosowań spożywczych. Dostępny w różnych klasach jakościowych.', '2026-02-11 17:30:08', '2026-02-11 17:30:08'),
(3, 'prod-bw101-palm-wax', 'Wosk Palmowy', 'Premium 100% wosk palmowy o kremowo-żółtym kolorze, idealny do produkcji świec. Certyfikowany przez RSPO SG (Segregated) / MB (Mass balance).', 'Premiumowa, 100% wosk palmowy o pięknym, kremowo-żółtym kolorze. Certyfikat RSPO MB potwierdzający zrównoważony rozwój. Idealny do produkcji świec, odlewów i świec w słoikach.', '2026-02-11 17:45:46', '2026-02-11 17:45:46'),
(4, 'prod-bw105-palm-wax', 'Palmowe tłuszcze do smarowania (o niskiej temperaturze topnienia)', 'Palm Shortening to półstała, nienasycona tłuszczowa substancja pochodząca z frakcjonowanego oleju palmowego, zapewniająca wyjątkową stabilność i neutralny smak.', 'Palm Shortening to półstała, nieuwodorniona tłuszcz pochodzący z frakcjonowanego oleju palmowego, zapewniający doskonałą stabilność i neutralny smak.\nIdealny do zastosowań piekarniczych — tworzy kruche ciasta, delikatne ciasta i chrupiące potrawy smażone na głębokim tłuszczu, charakteryzujące się wysokim punktem dymienia.\nEkonomiczna, odporna na utlenianie alternatywa dla masła lub smalcu w przemysłowym pieczeniu.', '2026-02-11 17:31:33', '2026-02-11 17:31:33'),
(5, 'prod-bw10510-blended-wax', 'Miękka woskowa mieszanka palmowo-parafynowa do świec słoikowych', 'Gotowa do użycia mieszanka świecy jar Low MP: palmowo-parafinowa-mikrokrystaliczna z Polyboost™, Vybar®, stabilizatorami UV—wystarczy dodać kolor i zapach dla lepszej przyczepności do szkła i maksymalnego efektu.', 'Bio Green Wax\'s Low Melting Point Jar Candle Blend (48-50°C) i (50-52°C)—formuła Palm-Paraffin-Microcrystalline zoptymalizowana dla pojemników szklanych. Gotowa do użycia: wystarczy dodać barwnik i zapach. Zawiera Polyboost/Vybar dla nieprzezroczystości/przyczepności, stabilizatory UV/antyoksydanty dla trwałości, oraz środki zatrzymujące zapach, zapewniające wyjątkowe przenikanie ciepła/zimna, brak zagnieceń podczas palenia i lepszą przyczepność do pojemnika, co czyni ją idealnym rozwiązaniem dla wysokiej jakości świec w szkle.', '2026-02-11 17:37:41', '2026-02-11 17:37:41'),
(6, 'prod-bw10555-blended-wax', 'Wegetyczna mieszanina wosku na bazie soi', 'Gotowa do użycia 95% wegańska mieszanka sojowa Bio Green Wax — czysto roślinna, przeznaczona do świec w słoiku (48-52°C) i na słupki (56-62°C). Wystarczy dodać barwnik i zapach.', 'Bio Green Wax\'s 95% Soy Wax Vegan Blend (5% dodatków roślinnych) zapewnia czyste, naturalne spalanie dla słoików szklanych i wolnostojących słupków. Dostępny w wersji o niskiej temperaturze topnienia (48-52°C) dla pojemników oraz wysokiej temperaturze topnienia (56-62°C) dla słupków. Gotowy do użycia: wystarczy dodać swój kolor i zapach, aby uzyskać wyjątkową projekcję i gładkie wykończenie.', '2026-02-11 17:32:22', '2026-02-11 17:32:22'),
(7, 'prod-bw10610-blended-wax', 'Wosk mieszany Palm-Parafina do świec stołowych', 'Gotowe do użycia mieszanki świec pillar High MP (56-58°C i 58-60°C): palmowo-parafinizowe-mikrokrystaliczne z Polyboost™, Vybar®, stabilizatorami UV—wystarczy dodać barwnik i perfum, aby uzyskać doskonałe właściwości świec pillar.', 'Bio Green wax\'s High Melting Point Pillar Candle Blends (56-58°C i 58-60°C)—Formulacje Palm-Parafina-Mikrokrystaliczne zaprojektowane do samodzielnych świec stożkowych. Gotowe do użycia: wystarczy dodać kolor i zapach. Optymalizowane z Polyboost/Vybar dla łatwego wydobycia z formy i nieprzepuszczalności, stabilizatory UV/antyoksydanty dla przedłużonej trwałości, a także środki zatrzymujące zapach zapewniające doskonały rozkład ciepła/zimna, utrzymanie kształtu świecy i czyste spalanie.', '2026-02-11 17:38:28', '2026-02-11 17:38:28'),
(8, 'prod-bw10655-blended-wax', 'Mieszanka sojowego wosku, wosku pszczelego i parafinowego', 'Gotowa mieszanka soi, wosku pszczelego i parafiny od Bio Green Wax — najlepszy rozprysk zapachu dla świec w słoiku (48-52°C) oraz świec kandelabrów (56-62°C). Wystarczy dodać aromat i barwnik.', 'Bio Green Wax\'s Soy-Beeswax-Paraffin Blend łączy naturalną gładkość soi, stabilność wosku pszczelego i siłę zapachu parafiny, zapewniając niezrównaną wydajność zapachu. Niska temperatura topnienia (48-52°C) doskonale sprawdza się w szklanych naczyniach; wysoka temperatura topnienia (56-62°C) idealna do słupków. Gotowa do użycia formuła — wystarczy dodać zapach i barwnik, aby uzyskać doskonały efekt rozpylenia ciepłego/zimnego oraz perfekcyjne wykończenie świecy.', '2026-02-11 17:33:13', '2026-02-11 17:33:13'),
(9, 'prod-bw8307-blended-wax', 'Mieszanka wosków kokosowo-rzepakowych', 'Gotowa do użycia mieszanka kokosowo-rapeseedowa od Bio Green Wax — kremowa, naturalna wydajność dla świec słoikowych (48-52°C) i słupkowych (56-62°C). Dodaj tylko barwnik i zapach.', 'Bio Green Wax\'s Coconut-Rapeseed Blend łączy kremową teksturę wosku kokosowego z gładkim paleniem wosku rzepakowego, zapewniając wyjątkową naturalną wydajność świec. Niska temperatura topnienia (48-52°C) zoptymalizowana dla świec w pojemnikach; wysoka temperatura topnienia (56-62°C) dla świec filarowych. Całkowicie gotowe do użycia — wystarczy dodać wybrany przez siebie kolor i aromat, aby uzyskać profesjonalne, czyste spalanie.', '2026-02-11 17:34:00', '2026-02-11 17:34:00'),
(10, 'prod-carnauba-wax', 'Wosk Carnauba', 'Premiumowa brazylijska wosk karnauba do polerek i powłok', 'Premierowy wosk z brazylijskiej carnauby, znany jako \"królowa wosków\". Idealny do polerowania samochodów, kosmetyków oraz powłok spożywczych. Najwyższy naturalny punkt topnienia.', '2026-02-11 17:30:46', '2026-02-11 17:30:46'),
(11, 'prod-castor-oil', 'Olej rycynowy', 'Premiumowa olej rycynowy tłoczony na zimno z nasion Ricinus communis, szeroko stosowany w przemyśle farmaceutycznym, kosmetycznym i przemysłowym.', 'Bio Green Wax dostarcza wysokiej jakości olej rycynowy, uniwersalny olej roślinny pozyskiwany przez tłoczenie nasion rośliny rokitnika pospolitego (Ricinus communis). Znany ze swojej unikalnej chemicznej kompozycji bogatej w kwas rycynolowy (około 85–90%), olej rycynowy wykazuje wyjątkową lepkość, ślizg i właściwości nawilżające, które czynią go nieocenionym w szerokim zakresie branż.\n\nNasz olej rycynowy jest starannie pozyskiwany i przetwarzany, aby spełniać najwyższe standardy czystości i jednolitości. Dostępny jest zarówno w wersji tłoczonej na zimno (surowej), jak i rafinowanej, odpowiedniej do zastosowań farmaceutycznych, kosmetycznych i przemysłowych. Wyjątkowa stabilność oleju i jego rozpuszczalność w alkoholu odróżniają go od innych olejów roślinnych, co czyni go preferowanym składnikiem w formulacjach wymagających wysokiej wydajności.\n\nOlej rycynowy jest naturalnie biodegradowalny i pochodzi ze źródeł odnawialnych, co jest zgodne z zobowiązaniem Bio Green Wax do zrównoważonego i ekologicznego pozyskiwania surowców.', '2026-02-11 17:16:42', '2026-02-11 17:16:42'),
(12, 'prod-coconut-oil', 'Olejek kokosowy', 'Wegański i oczyszczony olej kokosowy do zastosowań spożywczych i kosmetycznych', 'Premium virgin i rafinowany olej kokosowy odpowiedni do gotowania, pieczenia oraz zastosowań kosmetycznych. Dostępny w różnych klasach, aby sprostać Twoim szczególnym potrzebom.', '2026-02-09 02:59:53', '2026-02-11 17:17:18'),
(13, 'prod-coconut-wax', 'Wosk kokosowy', 'Wosk kokosowy to naturalny wosk pozyskiwany z oleju kokosowego, ceniony za czyste spalanie w świecach oraz ekologiczne zastosowania.', 'Wosk kokosowy to naturalny wosk pozyskiwany z oleju kokosowego, znany z czystego i wolnego od dymu spalania w produkcji świec. Często jest uważany za zrównoważoną alternatywę dla innych wosków. Wosk kokosowy cieszy się uznaniem ze względu na swoje ekologiczne właściwości oraz zdolność do dobrze utrzymania zapachu. Jest pozyskiwany z naturalnego i odnawialnego surowca, zapewniając czyste i wolne od dymu spalanie świec, co przekłada się na dłuższą żywotność i bardziej efektywną wydajność.', '2026-02-11 17:26:11', '2026-02-11 17:26:11'),
(14, 'prod-fr5456-paraffin-wax', 'Półrafinowany wosk parafinowy (50-68°C)', 'Bio Green Wax Semi Refined Paraffin (50-68°C)—opłacalna zawartość oleju 1-5% do świec, gumy, tekstyliów oraz zastosowań przemysłowych o dużym wolumenie.', 'Bio Green Wax\'s Semi Refined Paraffin Waxes (50-68°C) zapewniają ekonomiczną wydajność z kontrolowaną zawartością oleju (1-5%) dla elastycznej twardości. Standardowe gatunki: 52/54°C (świece), 56/58°C (fakty i kolumny), 60/62°C (przemysłowe). Idealne do produkcji świec o niskim koszcie, środków do przetwarzania gumy, wykończenia tekstyliów oraz powłok do pakowania hurtowego, gdzie najważniejsze jest zrównoważenie wydajności i ceny.', '2026-02-11 17:24:04', '2026-02-11 17:24:04'),
(15, 'prod-glycerine', 'Gliceryna', 'Glicerina jest bezbarwną, bezwonną, lepką substancją używaną szeroko w przemyśle farmaceutycznym, kosmetycznym i spożywczym.', 'Gliceryna, znana również jako glicerol lub gliceryna, jest bezbarwną, bezwonną i lepką cieczą o słodkim smaku. Jest klarowną, syropowatą substancją, która zazwyczaj jest bezbarwna, choć może mieć lekko żółtawy odcień. Gliceryna charakteryzuje się wysoką lepkością, co oznacza, że płynie wolno i jest stosunkowo gęsta. Ma konsystencję przypominającą syrop, co przyczynia się do jej zdolności do zatrzymywania wilgoci. Gliceryna znajduje szerokie zastosowanie w farmaceutyce, kosmetyce, przemyśle spożywczym oraz w różnych zastosowaniach przemysłowych.', '2026-02-11 17:20:07', '2026-02-11 17:20:07'),
(16, 'prod-hydrogenated-castor-oil', 'Uleczalina rycynowa uwodorniona', 'Wosk rycynowy utwardzony jest stałym, woskowatym pochodnym oleju rycynowego, stosowanym w kosmetykach, farmaceutykach i zastosowaniach przemysłowych.', 'Uwodniony olej rycynowy, znany również jako wosk rycynowy lub płatek wosku rycynowego, jest pochodną oleju rycynowego, poddawaną procesowi uwodornienia. Polega on na dodaniu wodoru do cząsteczek oleju rycynowego, co skutkuje powstaniem stałej, woskowej substancji. Stosowany jest w produktach kosmetycznych i pielęgnacyjnych, takich jak szminki, kremy i balsamy, jako emolient zapewniający skórze gładkość i nawilżenie. Działa również jako środek wiążący w formulacjach kosmetycznych, pomagając składnikom trzymać się razem i przylegać do skóry.', '2026-02-11 17:25:28', '2026-02-11 17:25:28'),
(17, 'prod-microcrystalline-wax', 'Wosk mikrokrystaliczny', 'Elastyczny wosk mikrokrystaliczny do kosmetyków i klejów', 'Elastyczny wosk mikrokrystaliczny idealny do kosmetyków, klejów na gorąco oraz specjalistycznych powłok. Wyjątkowa elastyczność i właściwości wiążące.', '2026-02-11 17:23:20', '2026-02-11 17:23:20'),
(18, 'prod-olive-oil', 'Oliwa z oliwek', 'Najwyższej jakości czysty olej z oliwek tłoczony na zimno z wyselekcjonowanych oliwek śródziemnomorskich do zastosowań kulinarnych, kosmetycznych i przemysłowych.', 'Nasze wysokiej jakości czyste oliwne oleje extra virgin tłoczone na zimno z starannie wyselekcjonowanych oliwek z regionu Morza Śródziemnego, zapewniają wyjątkową jakość i bogaty smak. Powszechnie stosowany w przygotowaniu żywności, kosmetykach, produktach farmaceutycznych oraz artykułach do pielęgnacji osobistej, oliwa z oliwek jest ceniona za swoje korzyści zdrowotne, właściwości antyoksydacyjne oraz wszechstronne zastosowania. Bio Green Wax pozyskuje oliwę z oliwek spełniającą surowe międzynarodowe normy jakości, gwarantującą stałą czystość i skuteczność we wszystkich zastosowaniach.', '2026-02-11 17:42:09', '2026-02-11 17:42:09'),
(19, 'prod-palm-kernel-oil', 'Olej palmowy z orzeszków palmowych', 'Olej palmowy jest pozyskiwany z nasiona owocu palmy olejowej, używany w produktach spożywczych, kosmetykach i zastosowaniach przemysłowych.', 'Olej z pestek palmowych jest pozyskiwany z kernerka owocu palmy olejowej i ma charakterystyczne właściwości fizyczne. Zazwyczaj jest to jasnożółty do białego stały tłuszcz w temperaturze pokojowej, ale podczas podgrzewania rozpuszcza się w przezroczystą, żółtawą ciecz. Punkt topnienia mieści się w zakresie od 23 do 28 stopni Celsjusza (73 do 82 stopni Fahrenheita). Olej z pestek palmowych jest bogaty w kwas laurynowy i jest szeroko stosowany w produkcji żywności, kosmetyków oraz w produkcji mydeł.', '2026-02-11 17:22:00', '2026-02-11 17:22:00'),
(20, 'prod-palm-kernel-olein', 'Olein z łuski palmy', 'Premiumowa rafinowana oleina z orzechów palmowych, płynna frakcja uzyskana z frakcjonowania oleju palmowego, ceniona za doskonałą klarowność, niską punkt zmętnienia oraz wszechstronne zastosowanie w przemyśle spożywczym, kosmetycznym i oleochemicznym.', 'Bio Green Wax dostarcza wysokiej jakości palm kernel olein (PKOo), ciekłą frakcję uzyskiwaną w wyniku kontrolowanej frakcjonowania oczyszczonego oleju z orzecha palmowego. Gdy olej z orzecha palmowego jest chłodzony w precyzyjnych warunkach, rozdziela się na frakcję stałą (palm kernel stearin) oraz frakcję ciekłą (palm kernel olein). Uzyskany olein jest klarownym, jasnoznamespacewym olejem o niskiej temperaturze topnienia i doskonałej zdolności wylewania.\n\nPalm kernel olein jest bogaty w kwas laurynowy (C12) oraz średniołańcuchowe kwasy tłuszczowe kaprylowe i kaprynowe, co nadaje mu znakomitą przejrzystość, szybkie wchłanianie i lekkie, nielepiące się uczucie. Te właściwości czynią go bardzo pożądanym w przemyśle spożywczym jako olej do gotowania, medium do smażenia oraz składnik w nie-mlecznych kremach, lodach i preparatach mlecznych z nadzieniem.\n\nW sektorze kosmetyków i produktów do pielęgnacji skóry palm kernel olein jest szeroko wykorzystywany jako olej bazowy w lotionach, kremach, szamponach oraz mydłach w płynie ze względu na swoje doskonałe właściwości emolientowe i zgodność ze skórą. Służy także jako kluczowy surowiec w produkcji oleochemikaliów, z których powstają kwasy tłuszczowe, estry metylowe oraz surfaktanty używane w detergentach i produktach do czyszczenia.\n\nBio Green Wax pozyskuje palm kernel olein z łańcuchów dostaw certyfikowanych przez RSPO, zapewniając pełną identyfikowalność i zgodę z zobowiązaniami dotyczącymi zrównoważonego rozwoju oleju palmowego. Produkt dostępny jest w formie oczyszczonej, wybielonej i deodorized (RBD), spełniając surowe międzynarodowe normy jakości.', '2026-02-11 17:46:50', '2026-02-11 17:46:50'),
(21, 'prod-palm-kernel-stearin', 'Stearyna z orzecha palmowego', 'Staran wysokiej jakości z palmowych orzechów, stała frakcja uzyskiwana z frakcjonowania oleju palmowego, ceniona za ostre właściwości topnienia i doskonałą twardość w zastosowaniach cukierniczych, kosmetycznych oraz oleochemicznych.', 'Bio Green Wax dostarcza wysokiej jakości palmowe stearyna orzechowa (PKS), stałą frakcję o wyższej temperaturze topnienia, powstającą w wyniku kontrolowanej frakcjonacji rafinowanego oleju palmowego orzechowego. Podczas frakcjonowania olej palmowy orzechowy jest rozdzielany na dwie składowe: oleinę palmową orzechową (frakcję ciekłą) oraz stearynę palmową orzechową (frakcję stałą). Powstała stearyna to biały lub lekko kremowy tłuszcz o charakterystycznie ostrym punkcie topnienia i zwartej teksturze.\n\nStearyna palmowa orzechowa jest bogata w kwas laurynowy (C12) i kwas mirystynowy (C14), co zapewnia jej doskonałą twardość, szybkie krystalizowanie oraz czysty profil topnienia. Te właściwości czynią ją idealnym składnikiem do substytutów masła kakaowego (CBS), powłok czekoladowych, nadzień cukierniczych oraz tłuszczów specjalistycznych, gdzie wymagana jest chrupkość i lśniąca powierzchnia.\n\nPoza zastosowaniami spożywczymi, stearyna palmowa orzechowa służy jako cenny surowiec w branży oleochemicznej do produkcji kwasów tłuszczowych, alkoholi tłuszczowych, cienkich pastylkowych mydeł oraz surfaktantów. W branży kosmetycznej i dermokosmetycznej przyczynia się do nadania kremom, balsamom i formulacjom stałym odpowiedniej struktury i ciała.\n\nBio Green Wax pozyskuje swoją stearynę palmową orzechową z łańcuchów dostaw certyfikowanych przez RSPO, zapewniając pełną śledzoność i zgodność z zobowiązaniami dotyczącymi zrównoważonego rozwoju oleju palmowego. Produkt jest dostępny w formie rafinowanej, wybielonej i deodorized (RBD), spełniając międzynarodowe normy jakościowe dla zastosowań spożywczych i technicznych.', '2026-02-11 17:21:13', '2026-02-11 17:21:13'),
(22, 'prod-palm-oil', 'Olej palmowy', 'Sustainable pozyskiwana olej palmowy i jego pochodne', 'Oleje palmowe i pochodne pochodzące z zrównoważonych źródeł do produkcji żywności, produkcji mydła i detergentów. dostępne opcje certyfikowane przez RSPO.', '2026-02-09 03:17:47', '2026-02-11 17:28:53'),
(23, 'prod-palm-shortenings', 'Palm Shortenings (wysoka temperatura topnienia)', 'Wysokotopliwa palmowa margaryna (46–52 °C) to specjalistyczne tłuszcze do wypieków i smażenia wykonane z frakcjonowanego oleju palmowego, zaprojektowane tak, aby zapewnić mocną strukturę, czysty smak oraz doskonałą stabilność termiczną w wymagających zastosowaniach przemysłowych.', 'Zagęszczacze palmowe o wysokiej temperaturze topnienia w zakresie 46–52 °C są produkowane z palm stearyny i frakcji środkowych, aby zapewnić wysoką zawartość stałego tłuszczu, zwartą konsystencję i stabilną sieć kryształów w warunkach pokojowych i wysokich temperaturach. Ten wyższy zakres topnienia zapewnia lepszą odporność na ciepło, stabilność oksydacyjną oraz mniejsze wyciekanie oleju, co czyni je szczególnie odpowiednimi do klimatów tropikalnych i linii technologicznych o wysokiej temperaturze.\n\nW zastosowaniach piekarniczych te zagęszczacze zapewniają dobrą napowietrzalność, laminację i chrupkość, wspierając kruche spody ciast, ciasta ptysiowe, herbatniki, ciastka i biszkopty, zachowując kształt i teksturę nawet w ciepłych warunkach. Są również używane jako wytrzymałe tłuszcze do smażenia i do wyrabiania ciast, a także jako zamienniki tłuszczu zwierzęcego w wyrobach mięsnych, gdzie ich solidna struktura, stabilność emulsji oraz profil bez trans tłuszczów i niehydrogenowanych składników pomagają osiągnąć jednolitą teksturę, czysty smak i formuły przyjazne dla etykiet.', '2026-02-11 17:28:17', '2026-02-11 17:28:17'),
(24, 'prod-palm-stearic-acid', 'Palmitowy kwas stearynowy', 'Kwas stearynowy palmowy jest nasyconym kwasem tłuszczowym pozyskiwanym z oleju palmowego, stosowanym w kosmetykach, świecach oraz produkcji gumy.', 'Kwas strowy z palm jest rodzajem nasyconego kwasu tłuszczowego pochodzącego z oleju palmowego, uzyskiwanego poprzez proces oddzielania i krystalizacji kwasów tłuszczowych. Jest to kwas tłuszczowy nasycony, znany ze swojej stabilności i stałej formy w temperaturze pokojowej. Kwas strowy z palm ma wygląd woskowy, od białego do lekko żółtawego. Ma punkt topnienia zwykle między 55 a 70 stopni Celsjusza (131-158 stopni Fahrenheita), co pozwala na łatwe włączenie go do różnych formulacji kosmetycznych, świec i produktów z gumy.', '2026-02-11 17:39:55', '2026-02-11 17:39:55'),
(25, 'prod-palm-stearin', 'Palm Stearin', 'Palm stearin to stała frakcja oleju palmowego, powszechnie używana w produkcji żywności, wytwarzaniu świec i produkcji mydeł.', 'Stearyna palmowa jest stałą frakcją oleju palmowego uzyskiwaną w procesie frakcjonowania, znaną z wysokiej zawartości nasyconych kwasów tłuszczowych. Jest tłuszczem stałym w temperaturze pokojowej o kremowo-białym do jasnożółtego kolorze i gładkiej, woskowej teksturze. Stearyna palmowa ma wyższą temperaturę topnienia w porównaniu z olejem palmowym. Jest powszechnie wykorzystywana w przemyśle spożywczym do stabilizacji tłuszczów, produkcji margaryny oraz w produkcji świec i mydła.', '2026-02-11 17:39:12', '2026-02-11 17:39:12'),
(26, 'prod-paraffin-wax', 'W pełni rafinowany wosk parafinowy (50-68°C)', 'Bio Green Wax W pełni rafinowany parafina (50-68°C)—klasa spożywcza/farmaceutyczna, zawartość oleju <0,5%, wyższa twardość. Idealna do produkcji świec, kosmetyków, opakowań oraz precyzyjnych zastosowań przemysłowych.', 'Woski parafinowe Bio Green Wax Fully Refined (o temperaturze topnienia 50-68°C) charakteryzują się ultra-niską zawartością oleju (<0,5%), wyjątkową twardością oraz neutralnym zapachem i kolorem. Dostępne w klasach do produkcji świec (52/54°C, 56/58°C), do zastosowań w pojemnikach (50/52°C) oraz w wysokotopliwych klasach do formowania kolumnowego (64/66°C). Idealne do produkcji ekskluzywnych świec, kosmetyków, powłok do pakowania żywności oraz precyzyjnego odlewania, które wymagają maksymalnej czystości i jednolitych parametrów wydajności.', '2026-02-11 17:43:53', '2026-02-11 17:43:53'),
(27, 'prod-pf56-synthetic-wax', 'Wosk Fischer-Tropsch (FT)', 'Wosk Fischer‑Tropsch (FT) to wysokiej czystości syntetyczny wosk parafinowy wytwarzany z gazu syntezowego, charakteryzujący się wysoką temperaturą topnienia, niską lepkością oraz doskonała twardością, idealny do wymagających zastosowań w branży tworzyw sztucznych, powłok, farb, klejów oraz modyfikacji asfaltów.', 'Wosk FT jest produkowany metodą syntezy Fischera‑Tropscha, co skutkuje wodnistą, ultra‑czystą woskiem o wąskim rozkładzie łańcuchów węglowych, bardzo niskiej zawartości oleju i doskonałej stabilności termicznej. Łączy wysoką temperaturę mięknięcia z niską lepkością topnienia i dużą twardością, zapewniając wyjątkową odporność na zarysowania, kontrolę połysku, efekty matowienia oraz smarowność w wielu formulacjach.\n\nW przetwórstwie tworzyw sztucznych oraz PVC/CPVC, wosk FT pełni rolę efektywnego wewnętrznego i zewnętrznego środka smarnego oraz środka pomocniczego w obróbce, obniża lepkość topienia, poprawia płynność oraz zwiększa łatwość wyjmowania z formy i stabilność wymiarową. Jest szeroko stosowany w klejach na gorąco i klejach reagujących na nacisk, tuszach drukarskich oraz powłokach przemysłowych, aby zwiększyć twardość, odporność na ścieranie i zarysowania, odporność na zbijanie się i osadzanie, a także stabilizować lepkość. Dodatkowe kluczowe zastosowania obejmują modyfikację bitumenu i asfaltu, masterbatch, kompozycje polimerowe, obróbkę gumy, polerki, tekstylia, a nawet formulacje kosmetyczne, gdzie wosk FT zapewnia kontrolowaną krystaliczność, poprawę odporności na ścieranie i zmarszczki oraz gładkie odczucie sensoryczne.', '2026-02-11 17:44:55', '2026-02-11 17:44:55'),
(28, 'prod-pfad', 'PFAD (Palm Fatty Acid Distillate)', 'PFAD jest produktem ubocznym rafinacji oleju palmowego, używanym w produkcji mydeł, paszy dla zwierząt oraz wytwarzaniu biopaliw.', 'Distillat kwasów tłuszczowych palmy (PFAD) jest produktem ubocznym procesu rafinacji oleju palmowego. Uzyskuje się go poprzez destylację surowego oleju palmowego w celu usunięcia zanieczyszczeń i osiągnięcia wyższego poziomu czystości. PFAD to brązowawo-żółta ciecz o charakterystycznym zapachu. Zawiera mieszaninę kwasów tłuszczowych nasyconych i nienasyconych, przy czym dominującymi kwasami tłuszczowymi są kwas laurynowy, kwas mirrorski i kwas palmitynowy. PFAD znajduje zastosowanie w produkcji mydła, paszach dla zwierząt oraz w produkcji biopaliw.', '2026-02-11 17:26:59', '2026-02-11 17:26:59'),
(29, 'prod-pkfad', 'Odpadowy destylat kwasów tłuszczowych z orzeszków palmowych (PKFAD)', 'PKFAD jest produktem ubocznym rafinacji oleju palmowego z pestek, bogatym w kwas laurynowy, stosowanym w przemyśle mydlarskim i oleochemicznym.', 'Odwarstwie kwasów tłuszczowych z orzecha palmowego (PKFAD) to produkt uboczny uzyskiwany podczas rafinacji oleju z orzecha palmowego. Jest bogaty w kwasy tłuszczowe, w tym kwas laurynowy, co czyni go cennym dla niektórych zastosowań przemysłowych. PKFAD znajduje zastosowanie w różnych gałęziach przemysłu, w tym w produkcji mydeł, wytwarzaniu biopaliw oraz jako surowiec w branży oleochemicznej.', '2026-02-11 17:40:37', '2026-02-11 17:40:37'),
(30, 'prod-polyethylene-wax', 'Wosk polietylenowy (wosk PE)', 'jest polietylenem o niskiej masie cząsteczkowej stosowanym jako wysokowydajny środek smarny i środek ułatwiający przetwarzanie w plastiku, powłokach, tuszach i klejach, poprawiającym przepływ, poślizg powierzchni oraz odporność na zarysowania.', 'Wosk polietylenowy to drobnoziarnisty, wysokotopliwy wosk syntetyczny o niskiej lepkości, doskonałej stabilności termicznej i silnej kompatybilności z typowymi polimerami takimi jak PVC, PE, PP oraz EVA. Zapewnia wewnętrzne i zewnętrzne smarowanie, obniża lepkość topnienia i tarcie, poprawia wypuszczanie z formy oraz nadaje powierzchni gładki, błyszczący i odporne na zarysowania wykończenie.\n​\nKluczowe zastosowania obejmują przetwórstwo tworzyw sztucznych i masterbatchy, gdzie wosk PE poprawia wydajność ekstruzji i wtrysku, zapobiega osadzaniu się na matrycy oraz poprawia rozproszenie pigmentów i wypełniaczy. Jest także wykorzystywany w gorączkliwych i termokurczliwych klejach, tuszach, powłokach proszkowych, aby kontrolować lepkość topnienia, zwiększać spójność i wytrzymałość oraz optymalizować czas otwarcia i utwardzania. Dodatkowe zastosowania obejmują bituminy i farby do oznakowania dróg, kompozyty z drewna i plastiku, mieszanki gumowe, kompozycje kabli i produkty woskowe formulowane, takie jak polerki i kredki, gdzie podnosi temperaturę mięknienia, twardość i odporność na wodę.', '2026-02-11 17:43:05', '2026-02-11 17:43:05'),
(31, 'prod-rapeseed-oil', 'Olej rzepakowy', 'Olej rzepakowy tłoczony na zimno i rafinowany z angielskich gospodarstw', 'Olej rzepakowy tłoczony na zimno i rafinowany, pochodzi z farm w Wielkiej Brytanii. Idealny do gotowania, pieczenia i sosów sałatkowych. Niski poziom tłuszczów nasyconych i bogaty w omega-3.', '2026-02-11 17:34:36', '2026-02-11 17:34:36'),
(32, 'prod-rapeseed-wax', 'Wosk rzepakowy', 'Wosk rzepakowy to naturalny, roślinny wosk stosowany jako ekologiczna alternatywa w produkcji świec i kosmetyków.', 'Wosk rzepakowy jest naturalnym wegańskim woskiem pochodzącym z oleju rzepaku, powszechnie wykorzystywanym jako ekologiczna alternatywa dla tradycyjnego wosku parafinowego w produkcji świec oraz innych zastosowaniach. Zapewnia czyste i powolne spalanie oraz dobre zatrzymanie aromatu. Wosk rzepakowy jest często używany w produkcji świec oraz w formulacjach naturalnych kosmetyków takich jak balsamy do ust, lotions i kremy, zapewniając właściwości nawilżające.', '2026-02-11 17:24:45', '2026-02-11 17:24:45'),
(33, 'prod-soap-noodles', 'Kostki mydlane', 'Noodle mydlane są podstawowymi surowcami do produkcji mydła, powstającymi w wyniku saponifikacji olejów i tłuszczów roślinnych.', 'Nudle mydlane, znane również jako granule mydlane, są jednym z podstawowych surowców używanych w produkcji mydła. Powstają poprzez przetwarzanie olejów roślinnych i tłuszczów z sodą kaustyczną (wodorotlenkiem sodu) w procesie saponifikacji. Nudle mydlane to zazwyczaj stałe, białe lub lekko kremowe kawałki lub koraliki o łagodnym i neutralnym aromacie. Są wolne od zanieczyszczeń i zawierają wysokie stężenie kwasów tłuszczowych, które przyczyniają się do ich właściwości oczyszczających i emulgujących.', '2026-02-11 17:41:22', '2026-02-11 17:41:22'),
(34, 'prod-soy-wax', 'Wosk sojowy', 'Wosk sojowy to odnawialny wosk roślinny wykonany z oleju sojowego, popularny w ekologicznej produkcji świec.', 'Wosk sojowy jest rodzajem wosku roślinnego pozyskiwanego z oleju sojowego. Jest popularną alternatywą dla tradycyjnego wosku parafinowego, który pochodzi z ropy naftowej. Wosk sojowy jest uważany za odnawialną, biodegradowalną i przyjazną dla środowiska opcję do produkcji świec. Powstaje poprzez uwodornienie oleju sojowego, co przekształca go w stan stały odpowiedni do formowania świec. Zazwyczaj występuje w formie płatków, które są łatwe do odmierzania i topienia.', '2026-02-11 17:18:01', '2026-02-11 17:18:01'),
(35, 'prod-soybean-oil', 'Olej sojowy', 'Wysokiej jakości olej sojowy do zastosowań przemysłowych i kulinarnych', 'Olej sojowy to wszechstronny olej roślinny pozyskiwany z soja, szeroko stosowany do smażenia, pieczenia i dressingu do sałatek ze względu na swój neutralny smak i wysoką temperaturę dymienia. \nJest bogaty w tłuszcze wielonienasycone, w tym kwasy tłuszczowe omega‑3 i omega‑6, oraz dostarcza witaminę K i witaminę E. \nIdealnie nadaje się do głębokiego smażenia, produkcji margaryny oraz zastosowań przemysłowych w przemyśle spożywczym. Oczyszczony i ododorowany zgodnie z wysokimi standardami.', '2026-02-11 17:29:34', '2026-02-11 17:29:34'),
(36, 'prod-sunflower-oil', 'Olej słonecznikowy', 'Premium rafinowany olej słonecznikowy do gotowania i przetwórstwa spożywczego', 'Nasza wysokiej jakości rafinowana olej słonecznikowy jest idealny do gotowania, smażenia i zastosowań w przetwórstwie spożywczym. Pochodzi z wysokiej jakości nasion słonecznika i jest rafinowany zgodnie z najwyższymi standardami.', '2026-02-09 03:22:53', '2026-02-11 17:22:41');
INSERT INTO `products_pt` (`id`, `master_id`, `name`, `description`, `full_description`, `created_at`, `updated_at`) VALUES
(1, 'bdf424df-f9b0-4a79-84d6-f6ed1eb1e84f', 'Palm Olein', 'Palm olein é a fração líquida do óleo de palma refinado, valorizada como um óleo de fritura e cozimento estável que oferece sabor neutro, longa durabilidade na fritura e textura crocante para lanches, fast-food e aplicações domésticas.', 'Palm olein é produzido por fracionamento do óleo de palma refinado, branqueado e deodorizado (RBD), obtendo-se um líquido claro rico em ácidos oléico e palmítico, proporcionando um perfil de ácidos graxos equilibrado com uma estabilidade oxidativa naturalmente boa. Seu ponto de fumaça elevado, resistência à oxidação e formação de polímeros, além de baixa tendência a formar sabores indesejados, permitem ciclos de fritura repetidos com menor quebra do óleo, menos formação de espuma e maior vida útil dos produtos finais.\n​\nNa alimentação, o palm olein é amplamente utilizado como meio de fritura profunda para salgadinhos, batatas chips, frango frito, macarrão instantâneo e alimentos congelados pré-fritos, além de ser um óleo de cozinha de uso geral em muitos mercados tropicais. Ele também serve como óleo base em misturas com soja, girassol ou outros óleos vegetais para alcançar perfis nutricionais e funcionais ajustados, sendo utilizado em margarinas, gorduras de panificação e sistemas de fritura em serviços de alimentos onde desempenho estável e sabor limpo são essenciais.', '2026-02-11 17:15:05', '2026-02-11 17:15:05'),
(2, 'prod-beeswax', 'Cera de abelha', 'Cera de abelha pura e natural para cosméticos e fabricação de velas', 'Cera de abelha pura e natural, proveniente de apicultores éticos. Perfeita para cosméticos, produção de velas e aplicações alimentares. Disponível em vários graus.', '2026-02-05 21:57:07', '2026-02-11 17:29:44'),
(3, 'prod-bw101-palm-wax', 'Cera de Palme', 'Cera de palma premium 100% com cor amarela cremosa, ideal para fabricação de velas. Certificada pelo RSPO SG (Segregada) / MB (Balanço de massa).', 'Cera de palma premium 100% com uma bela cor amarela cremosa. Certificada pelo RSPO MB para sustentabilidade. Ideal para fabricação de velas, moldagem e velas em recipientes.', '2026-02-05 22:04:24', '2026-02-11 17:45:21'),
(4, 'prod-bw105-palm-wax', 'Óleos de palma (ponto de fusão baixo)', 'Palm Shortening é uma gordura semi-sólida, não hidrogenada, derivada do óleo de palma fracionado, proporcionando maior estabilidade e sabor neutro.', 'Palm Shortening é uma gordura semi-sólida, não hidrogenada, derivada do óleo de palma fracionado, oferecendo maior estabilidade e sabor neutro.  \nIdeal para aplicações em padarias—cria massas folhadas, bolos macios e alimentos fritos crocantes com ponto de fumaça alto.  \nAlternativa econômica e resistente à oxidação ao manteiga ou gordura de porco na panificação industrial.', '2026-02-05 22:08:34', '2026-02-11 17:31:01'),
(5, 'prod-bw10510-blended-wax', 'Cera de parafina misturada com palm para velas de vidro', 'Mistura de vela de pote Low MP pronta para uso: Palm-Parafina-Microcristalina com Polyboost™, Vybar®, estabilizadores UV—basta adicionar cor e fragrância para uma adesão superior ao vidro e maior alcance de aroma.', 'Mistura de vela em frasco Bio Green Wax com ponto de fusão baixo (48-50°C) e (50-52°C)—fórmula Palm-Parafina-Microcristalina otimizada para recipientes de vidro. Pronta para usar: adicione apenas cor e fragrância. Possui Polyboost/Vybar para opacidade/adesão, estabilizadores UV/antioxidantes para maior durabilidade, além de agentes de retenção de fragrância que oferecem excelente projeção quente/fria, queima sem vincos e retenção superior no recipiente, ideal para velas de vidro premium.', '2026-02-06 03:35:56', '2026-02-11 17:37:07'),
(6, 'prod-bw10555-blended-wax', 'Mistura de Cera Vegana à Base de Soja', 'Mistura vegana de soja pronta para uso com 95% do Bio Green Wax—, pura à base de plantas para velas de pote (48-52°C) e de pilar (56-62°C). Basta adicionar cor e fragrância.', 'A mistura vegana Bio Green Wax, composta por 95% de cera de soja (com 5% de aditivos vegetais), oferece um desempenho limpo e natural para potes de vidro e pilares autônomos. Disponível na temperatura de fusão baixa (48-52°C) para recipientes e na temperatura de fusão alta (56-62°C) para pilares. Pronta para uso: basta adicionar sua cor e fragrância para uma ótima dispersão e acabamento suave.', '2026-02-06 03:43:17', '2026-02-11 17:31:49'),
(7, 'prod-bw10610-blended-wax', 'Cera de mistura de parafina pomar com cera para velas de pilar', 'Velas de Pilar Prontas para Uso com Alto Ponto de Fusão (56-58°C e 58-60°C): Palm-Parafina-Microcristalina com Polyboost™, Vybar®, estabilizadores UV—basta adicionar cor e fragrância para desempenho superior de pilar.', 'Misturas de vela de vela de Pilar com Ponto de Fusão Elevado da Bio Green wax (56-58°C e 58-60°C)—Formulações de Palm-Parafina-Microcristalina desenvolvidas para velas de pilar autônomas. Prontas para uso: adicione apenas cor e fragrância. Otimizadas com Polyboost/Vybar para liberação do molde e opacidade, estabilizadores UV/antioxidantes para maior durabilidade, além de agentes de retenção de fragrância que proporcionam uma queima excepcional, tanto quente quanto fria, preservando a forma da vela e desempenho de queima limpa.', '2026-02-06 03:39:33', '2026-02-11 17:37:57'),
(8, 'prod-bw10655-blended-wax', 'Mistura de cera de abelha, parafina e cera de soja', 'Mistura pronta de soja, cera de abelha e parafina da Bio Green Wax—o aroma mais intenso para velas de vidro (48-52°C) e de coluna (56-62°C). Basta adicionar aroma e cor.', 'A mistura de cera de soja, cera de abelha e parafina da Bio Green Wax combina a suavidade natural da soja, a estabilidade da cera de abelha e o poder aromático da parafina para um desempenho de fragrância incomparável. O ponto de fusão baixo (48-52°C) é excelente para vidros; o ponto de fusão alto (56-62°C) é perfeito para pilares. Formulação pronta para uso — basta adicionar fragrância e cor para obter uma performance superior de dispersão térmica e acabamento impecável na vela.', '2026-02-06 03:46:54', '2026-02-11 17:32:39'),
(9, 'prod-bw8307-blended-wax', 'Mistura de Cera de Coco e Rapsodía', 'Mistura pronta de Coco-Aveia da Bio Green Wax—performance natural cremosa para velas em Vaso (48-52°C) e em Coluna (56-62°C). Adicione apenas cor e fragrância.', 'A mistura de Coco-Canola da Bio Green Wax combina a textura cremosa da cera de coco com a queima suave da cera de canola para um desempenho excepcional de vela natural. Ponto de fusão baixo (48-52°C) otimizado para velas em recipiente; ponto de fusão alto (56-62°C) para velas de coluna. Completamente pronta para uso — basta adicionar sua cor e fragrância preferidas para resultados profissionais e de queima limpa.', '2026-02-06 03:50:42', '2026-02-11 17:33:29'),
(10, 'prod-carnauba-wax', 'Cera de Carnaúba', 'Cera de carnaúba brasileira premium para polimentos e revestimentos', 'Cera de carnaúba brasileira premium, conhecida como a \"rainha das ceras\". Ideal para polimento de automóveis, cosméticos e revestimentos alimentícios. Maior ponto de fusão natural.', '2026-02-05 22:00:17', '2026-02-11 17:30:21'),
(11, 'prod-castor-oil', 'Óleo de Rícino', 'Óleo de rícino prensado a frio de alta qualidade, derivado das sementes de Ricinus communis, amplamente utilizado em produtos farmacêuticos, cosméticos e aplicações industriais.', 'A Bio Green Wax fornece óleo de rícino de alta qualidade, um óleo vegetal versátil obtido pela prensagem das sementes da planta de rícino (Ricinus communis). Conhecido por sua composição química única, rica em ácido ricinoleico (aproximadamente 85–90%), o óleo de rícino apresenta propriedades excepcionais de viscosidade, lubricidade e hidratação que o tornam indispensável em uma ampla variedade de indústrias.\n\nNosso óleo de rícino é cuidadosamente obtido e processado para atender aos mais altos padrões de pureza e consistência. Está disponível em graus prensados a frio (virgens) e refinados, adequados para aplicações farmacêuticas, cosméticas e industriais. A estabilidade notável do óleo e sua solubilidade em álcool o distinguem de outros óleos vegetais, tornando-se um ingrediente preferencial em formulações que exigem desempenho superior.\n\nO óleo de rícino é naturalmente biodegradável e derivado de recursos renováveis, alinhando-se ao compromisso da Bio Green Wax com uma obtenção sustentável e ambientalmente responsável.', '2026-02-11 17:16:05', '2026-02-11 17:16:05'),
(12, 'prod-coconut-oil', 'Óleo de Coco', 'Óleo de coco virgem e refinado para aplicações alimentícias e cosméticas', 'Óleo de coco virgem e refinado premium, adequado para culinária, panificação e aplicações cosméticas. Disponível em várias categorias para atender às suas necessidades específicas.', '2026-02-05 21:50:02', '2026-02-11 17:16:53'),
(13, 'prod-coconut-wax', 'Cera de Coco', 'Cera de coco é uma cera natural derivada do óleo de coco, valorizada por suas velas de queima limpa e aplicações ecológicas.', 'A cera de coco é uma cera natural derivada do óleo de cocos, conhecida por sua queima limpa e lenta na fabricação de velas. Ela é frequentemente considerada uma alternativa sustentável a outras ceras. A cera de coco é valorizada por suas características ecológicas e pela capacidade de reter bem a fragrância. Derivada de uma fonte natural e renovável, oferece uma queima limpa e lenta em velas, garantindo uma performance mais duradoura e eficiente.', '2026-02-11 17:25:42', '2026-02-11 17:25:42'),
(14, 'prod-fr5456-paraffin-wax', 'Cera de Paraffina Semi Refinada (50-68°C)', 'Bio Green Wax Parafina Semi Refinada (50-68°C)—conteúdo de óleo econômico de 1-5% para velas, borracha, têxteis e aplicações industriais de alto volume.', 'As Paraffinas Semi Refinadas Bio Green Wax (50-68°C) oferecem desempenho econômico com teor de óleo controlado (1-5%) para uma dureza flexível. Graus padrão: 52/54°C (velas), 56/58°C (colunas), 60/62°C (industrial). Perfeitas para produção de velas de baixo custo, auxiliares de processamento de borracha, acabamento têxtil e revestimentos de embalagens em grande volume, onde o equilíbrio entre desempenho e preço é fundamental.', '2026-02-06 04:05:00', '2026-02-11 17:23:33'),
(15, 'prod-glycerine', 'Glicerina', 'Glicerina é um líquido viscoso, incolor e inodoro, amplamente utilizado nas indústrias farmacêutica, de cosméticos e de alimentos.', 'Glicerina, também conhecida como glicerol ou glicerina, é um líquido incolor, inodoro e viscoso, com um sabor adocicado. É um líquido transparente, semelhante a um xarope, que normalmente é incolor, embora possa apresentar uma tonalidade amarelada. A glicerina possui alta viscosidade, ou seja, ela flui lentamente e é relativamente espessa. Tem uma consistência semelhante à de xarope, o que contribui para sua capacidade de reter umidade. A glicerina encontra uso extensivo em produtos farmacêuticos, cosméticos, processamento de alimentos e diversas aplicações industriais.', '2026-02-11 17:19:34', '2026-02-11 17:19:34'),
(16, 'prod-hydrogenated-castor-oil', 'Óleo de Mamona Hidrogenado', 'Óleo de rícino hidrogenado é um derivado sólido em forma de cera do óleo de rícino, utilizado em cosméticos, produtos farmacêuticos e aplicações industriais.', 'Óleo de ricino hydrogenado, também conhecido como cera de ricino ou flocos de cera de ricino, é um derivado do óleo de ricino que passa por um processo de hidrogenação. Isso envolve a adição de hidrogênio às moléculas de óleo de ricino, resultando em uma substância sólida e cerosa. Ele é utilizado em produtos cosméticos e de cuidados pessoais, como batons, cremes e loções, como emoliente para proporcionar suavidade e umidade à pele. Também atua como agente ligante nas formulações cosméticas, ajudando os ingredientes a se manterem unidos e a aderirem à pele.', '2026-02-11 17:24:58', '2026-02-11 17:24:58'),
(17, 'prod-microcrystalline-wax', 'Cera microcristalina', 'Cera microcristalina flexível para cosméticos e adesivos', 'Cera microcristalina flexível ideal para cosméticos, adesivos de fusão a quente e tintas especiais. Propriedades superiores de flexibilidade e adesão.', '2026-02-06 03:57:32', '2026-02-11 17:22:53'),
(18, 'prod-olive-oil', 'Azeite de Oliva', 'Azeite de oliva puro de alta qualidade, extraído a frio de azeitonas selecionadas do Mediterrâneo, para aplicações culinárias, cosméticas e industriais.', 'Nosso azeite de oliva puro premium é cold-pressed a partir de azeitonas mediterrâneas cuidadosamente selecionadas, proporcionando qualidade excepcional e sabor rico. Ampliamente usado na preparação de alimentos, cosméticos, produtos farmacêuticos e cuidados pessoais, o azeite de oliva é valorizado por seus benefícios à saúde, propriedades antioxidantes e aplicações versáteis. A Bio Green Wax fornece azeite de oliva que atende a rigorosos padrões internacionais de qualidade, garantindo pureza e desempenho consistentes em todas as aplicações.', '2026-02-11 17:41:36', '2026-02-11 17:41:36'),
(19, 'prod-palm-kernel-oil', 'Óleo de Amêndoa de Dendê', 'Óleo de palmiste é derivado do núcleo do fruto da palma de óleo, utilizado em produtos alimentícios, cosméticos e aplicações industriais.', 'Óleo de baba de cacau é derivado do caroço do fruto da palmeira de óleo e possui propriedades físicas distintas. Geralmente é um sólido de cor amarelo claro a branco em temperatura ambiente, mas derrete formando um líquido transparente de tonalidade amarelada quando aquecido. O ponto de fusão varia de 23 a 28 graus Celsius (73 a 82 graus Fahrenheit). O óleo de baba de cacau é rico em ácido láurico e é amplamente utilizado na fabricação de alimentos, cosméticos e produtos de sabão.', '2026-02-11 17:21:26', '2026-02-11 17:21:26'),
(20, 'prod-palm-kernel-olein', 'Óleos de Palmiste (Palm Kernel Olein)', 'Oleína de côco refinada premium, a fração líquida obtida a partir da fração do óleo de palma, valorizada por sua excelente transparência, baixo ponto de turbidez e uso versátil nas indústrias de alimentos, cuidados pessoais e oleoquímicas.', 'A Bio Green Wax fornece oleína de baba de caracol de alta qualidade (PKOo), a fração líquida produzida por meio da fracionação controlada do óleo de baba de caracol refinado. Quando o óleo de baba de caracol é resfriado sob condições precisas, ele se divide em uma fração sólida (palmiste de baba de caracol) e uma fração líquida (oleína de baba de caracol). A oleína resultante é um óleo claro, de cor clara, com baixo ponto de fusão e excelente fluidez.\n\nA oleína de baba de caracol é rica em ácido láurico (C12) e ácidos graxos de cadeia média, como caprílico e cáprico, conferindo-lhe uma transparência excepcional, rápida absorção e uma sensação leve e não gordurosa. Essas características tornam-na altamente desejável na indústria alimentícia como óleo de cozinha, meio de fritura e ingrediente em cremes não lácteos, sorvetes e formulações de leite enriquecido.\n\nNo setor de cuidados pessoais e cosméticos, a oleína de baba de caracol é amplamente utilizada como óleo base em loções, cremes, xampus e sabonetes líquidos devido às suas excelentes propriedades emolientes e compatibilidade com a pele. Ela também serve como matéria-prima principal na produção de oleoquímicos, fornecendo ácidos graxos, ésteres metílicos e surfactantes utilizados em detergentes e produtos de limpeza.\n\nA Bio Green Wax obtém sua oleína de baba de caracol de cadeias de suprimento certificadas pelo RSPO, garantindo rastreabilidade completa e alinhamento com compromissos de sustentabilidade do óleo de palma. O produto está disponível nas versões refinada, branqueada e deodorada (RBD), atendendo a rigorosos padrões internacionais de qualidade.', '2026-02-11 17:46:07', '2026-02-11 17:46:07'),
(21, 'prod-palm-kernel-stearin', 'Palm Kernel Stearin', 'Estearina de amêndoa de dendê de alta qualidade, a fração sólida obtida a partir da fractionação do óleo de amêndoa de dendê, valorizada por seu perfil de fusão preciso e excelente dureza em aplicações de confeitaria, cosméticos e oleoquímicos.', 'A Bio Green Wax fornece estearina de caroço de palma de qualidade premium (PKS), a fração sólida de ponto de fusão mais alto produzida através da fracionação controlada do óleo de caroço de palma refinado. Durante a fracionação, o óleo de caroço de palma é separado em dois componentes: oleína de caroço de palma (a fração líquida) e estearina de caroço de palma (a fração sólida). A estearina resultante é uma gordura de coloração branca a bege, com um ponto de fusão caracteristicamente agudo e textura firme.\n\nA estearina de caroço de palma é rica em ácido láurico (C12) e ácido palmítico (C14), conferindo-lhe excelente rigidez, rápida cristalização e um perfil de fusão limpo. Essas propriedades a tornam um ingrediente ideal para substitutos do manteiga de cacau (CBS), revestimentos de chocolate composto, recheios de confeitaria e gorduras especiais, onde um acabamento com estalido e brilho é desejado.\n\nAlém de aplicações alimentares, a estearina de caroço de palma serve como uma matéria-prima valiosa na indústria oleoquímica para a produção de ácidos graxos, álcoois graxos, noodles de sabão e surfactantes. Em cuidados pessoais e cosméticos, ela contribui com corpo e estrutura para cremes, loções e formulações sólidas.\n\nA Bio Green Wax obtém sua estearina de caroço de palma de cadeias de fornecimento certificadas pelo RSPO, garantindo rastreabilidade total e conformidade com os compromissos de sustentabilidade do óleo de palma. O produto está disponível na forma refinada, branqueada e deodorada (RBD), atendendo aos padrões internacionais de qualidade para uso alimentício e técnico.', '2026-02-11 17:20:29', '2026-02-11 17:20:29'),
(22, 'prod-palm-oil', 'Óleo de Palma', 'Óleo de palma e derivados de palma de fonte sustentável', 'Óleo de palma e derivados de palma de origem sustentável para fabricação de alimentos, produção de sabonetes e detergentes. Opções certificadas pela RSPO disponíveis.', '2026-02-05 21:50:40', '2026-02-11 17:28:29'),
(23, 'prod-palm-shortenings', 'Margarinas de palma (ponto de fusão elevado)', 'Sabores de palma de fusão rápida (46–52 °C) são gorduras especiais para panificação e fritura feitas de óleo de palma fracionado, projetadas para oferecer estrutura robusta, sabor limpo e excelente estabilidade ao calor em aplicações industriais exigentes.', 'Gorduras de palma com ponto de fusão alto, na faixa de 46 a 52 °C, são formuladas a partir de palmiste e frações médias para proporcionar alto teor de gordura sólida, textura firme e uma rede cristalina estável em temperaturas ambientes e elevadas. Essa faixa de fusão mais elevada oferece resistência térmica superior, estabilidade oxidativa e redução do óleo escorrendo, tornando-as ideais para climas tropicais e linhas de processamento em altas temperaturas.\n​\n\nEm aplicações de panificação, essas gorduras proporcionam boa aeração, laminação e crocância, sustentando crostas de tortas folhadas, massas folhadas, crackers de creme, biscoitos e bolachas, enquanto mantêm a forma e a mastigabilidade mesmo em condições quentes. Também são utilizadas como gorduras resistentes para fritura e massas, e como substitutos de gordura animal em produtos cárneos, onde sua estrutura firme, estabilidade de emulsão e perfil zero trans, não H₂, ajudam a alcançar uma textura consistente, liberação de sabor limpa e formulações com rótulo amigável.', '2026-02-11 17:27:38', '2026-02-11 17:27:38'),
(24, 'prod-palm-stearic-acid', 'Ácido palmítico', 'Ácido esteárico de palma é um ácido graxo saturado derivado do óleo de palma, utilizado em cosméticos, velas e na fabricação de borracha.', 'Ácido esteárico de palma é um tipo de ácido graxo derivado do óleo de palma, obtido através do processo de separação e cristallização dos ácidos graxos. É um ácido graxo saturado conhecido por sua estabilidade e forma sólida em temperatura ambiente. O ácido esteárico de palma apresenta uma aparência cerosa que varia do branco ao levemente amarelo. Possui um ponto de fusão geralmente entre 55-70 graus Celsius (131-158 graus Fahrenheit), o que permite sua fácil incorporação em diversas formulações para cosméticos, velas e produtos de borracha.', '2026-02-11 17:39:25', '2026-02-11 17:39:25'),
(25, 'prod-palm-stearin', 'Estearina de Palma', 'Palm stearin é a fração sólida do óleo de palma, comumente usado na fabricação de alimentos, produção de velas e confecção de sabão.', 'Palma stearina é uma fração sólida de óleo de palma obtida pelo processo de fracionamento, conhecida pelo seu alto teor de ácidos graxos saturados. É uma gordura sólida à temperatura ambiente, com cor que varia de branco cremoso a amarelo pálido e textura suave e cerosa. A palma stearina possui um ponto de fusão mais alto em comparação com o óleo de palma. É comumente utilizada na indústria alimentícia para estabilizar gorduras, produzir margarina e na fabricação de velas e sabonetes.', '2026-02-11 17:38:42', '2026-02-11 17:38:42'),
(26, 'prod-paraffin-wax', 'Cera de Paraftena Totalmente Refinada (50-68°C)', 'Bio Green Wax Paraftina Totalmente Refinada (50-68°C)—classe alimentícia/farmacêutica, <0,5% de óleo, dureza superior. Perfeita para velas, cosméticos, embalagens e aplicações industriais de precisão.', 'As Paraffinas Totalmente Refinadas da Bio Green Wax (pontos de fusão entre 50-68°C) apresentam teor de óleo ultra baixo (<0,5%), dureza excepcional e odor/cor neutros. Disponíveis em graus para velas (52/54°C, 56/58°C), graus para recipientes (50/52°C) e graus para pilares de fusão alta (64/66°C). Ideais para velas premium, cosméticos, revestimentos para embalagens alimentícias e moldagem de precisão, que exigem máxima pureza e consistência no desempenho.', '2026-02-06 03:54:22', '2026-02-11 17:43:19'),
(27, 'prod-pf56-synthetic-wax', 'Cera Fischer-Tropsch (FT)', 'A cera Fischer‑Tropsch (FT) é uma cera sintética de parafina de alta pureza produzida a partir de syngas, oferecendo alto ponto de fusão, baixa viscosidade e excelente dureza para aplicações exigentes em plásticos, revestimentos, tintas, adesivos e modificação de asfalto', 'Cera FT é produzida por meio da síntese Fischer‑Tropsch, resultando em uma cera ultra limpa, de cor branca água, com uma distribuição de cadeias de carbono estreita, teor de óleo muito baixo e estabilidade térmica excepcional. Ela combina um alto ponto de amolecimento com baixa viscosidade de fusão e grande dureza, proporcionando resistência superior a riscos, controle de brilho, efeitos de matização e lubrificação em muitas formulações.\n\nNa fabricação de plásticos e processamento de PVC/CPVC, a cera FT atua como um lubrificante interno e externo eficiente, além de auxiliar no processamento, reduzindo a viscosidade do fusão, melhorando o fluxo, e aprimorando a liberação do molde e a estabilidade dimensional. É amplamente utilizada em adesivos de fusão a quente e adesivos sensíveis à pressão, tintas de impressão e revestimentos industriais para aumentar a dureza, resistência ao desgaste e riscos, resistência ao bloqueio e anti-precipitação, além de estabilizar a viscosidade. Outras aplicações-chave incluem modificação de asfalto e betume, concentração em masterbatch e compostos de polímeros, processamento de borracha, polidores, têxteis e até formulações cosméticas, onde a cera FT proporciona cristalização controlada, maior resistência ao desgaste e às rugas, além de uma sensação sensorial suave.', '2026-02-06 04:16:06', '2026-02-11 17:44:12'),
(28, 'prod-pfad', 'PFAD (Distilado de Ácidos Graxos de Palma)', 'PFAD é um subproduto do refino de óleo de palma, utilizado na fabricação de sabonetes, alimentação animal e produção de biocombustíveis.', 'Distilado de Ácido Gorduroso de Palma (PFAD) é um subproduto do processo de refino do óleo de palma. Ele é obtido por destilação do óleo de palma cru para remover impurezas e alcançar um nível mais elevado de pureza. O PFAD é um líquido de cor amarelo-acastanhada, com um odor característico. Ele contém uma mistura de ácidos graxos saturados e insaturados, sendo os ácidos graxos predominantes o ácido láurico, o ácido mirístico e o ácido palmítico. O PFAD é utilizado na fabricação de sabonetes, na alimentação animal e na produção de biocombustíveis.', '2026-02-11 17:26:27', '2026-02-11 17:26:27'),
(29, 'prod-pkfad', 'Destilado de Ácidos Graxos de Endurecimento do Gema de Palm (PKFAD)', 'PKFAD é um subproduto do refino do óleo de mamona, rico em ácido láurico, utilizado nas indústrias de sabão e oleoquímica.', 'Distilado de Ácidos Graxos de Fats de Caju (PKFAD) é um subproduto obtido durante a refinação do óleo de caju. É rico em ácidos graxos, incluindo ácido láurico, tornando-o valioso para certas aplicações industriais. O PKFAD é utilizado em várias aplicações industriais, incluindo fabricação de sabonetes, produção de biocombustíveis e como matéria-prima na indústria oleoquímica.', '2026-02-11 17:40:09', '2026-02-11 17:40:09'),
(30, 'prod-polyethylene-wax', 'Cera de Polietileno (cera PE)', 'é um polietileno de baixo peso molecular utilizado como um lubrificante de alto desempenho e auxiliar de processamento em plásticos, revestimentos, tintas e adesivos, melhorando o fluxo, o deslizamento superficial e a resistência a riscos.', 'Cera de polyethylene é uma cera sintética finamente divided, de alto ponto de fusão, com baixa viscosidade, excelente estabilidade térmica e forte compatibilidade com polímeros comuns como PVC, PE, PP e EVA. Ela oferece lubrificação interna e externa, reduz a viscosidade de fusão e o atrito, melhora a liberação do molde e proporciona uma superfície lisa, brilhante e resistente a riscos.\n\nAplicações principais incluem processamento de plásticos e masterbatch, onde a cera de PE melhora a eficiência da extrusão e moldagem por injeção, evita o acúmulo na matriz e melhora a dispersão de pigmentos e cargas. Também é utilizada em adesivos hot-melt e sensíveis à pressão, tintas e revestimentos em pó para controlar a viscosidade de fusão, aumentar a coesão e resistência, além de otimizar os tempos de abertura e de endurecimento. Outras utilizações abrangem betume e tintas para marcação viária, compósitos de madeira e plástico, compostos de borracha, compostos de cabos e produtos de cera formulados, como polidores e giz de cera, onde ela eleva o ponto de amolecimento, a dureza e a resistência à água.', '2026-02-06 04:01:08', '2026-02-11 17:42:25'),
(31, 'prod-rapeseed-oil', 'Óleo de canola', 'Óleo decanolado e refinado de canola de fazendas do Reino Unido', 'Óleo de canola prensado a frio e refinado, proveniente de fazendas no Reino Unido. Ideal para cozinhar, assar e molhos para salada. Baixo em gordura saturada e rico em ômega-3.', '2026-02-05 21:53:53', '2026-02-11 17:34:10'),
(32, 'prod-rapeseed-wax', 'Cera de colza', 'A cera de soja é uma cera vegetal natural utilizada como uma alternativa ecológica na fabricação de velas e cosméticos.', 'Cera de colza é uma cera vegetal natural derivada do óleo da planta de canola, comumente usada como uma alternativa ecológica à cera de parafina tradicional na fabricação de velas e outras aplicações. Ela oferece uma queima limpa e lenta, além de retenção de fragrância adequada. A cera de colza é frequentemente utilizada na produção de velas e na formulação de cosméticos naturais, como bálsamos labiais, loções e cremes, proporcionando propriedades hidratantes.', '2026-02-11 17:24:17', '2026-02-11 17:24:17'),
(33, 'prod-soap-noodles', 'Noodles de Sabão', 'Fios de sabão são matérias-primas primárias para a fabricação de sabonetes, produzidos por saponificação de óleos e gorduras vegetais.', 'Noodles de sabão, também conhecidos como grânulos de sabão, são uma das matérias-primas principais utilizadas na fabricação de sabão. São produzidos através do processamento de óleos e gorduras vegetais com hidróxido de sódio (dizer) por meio da saponificação. Os noodles de sabão geralmente são pedaços ou contas sólidas de cor branca ou bege com um aroma suave e neutro. Estão livres de impurezas e contêm uma alta concentração de ácidos graxos que contribuem para suas propriedades de limpeza e emulsificação.', '2026-02-11 17:40:53', '2026-02-11 17:40:53'),
(34, 'prod-soy-wax', 'Ceras de soja', 'A cera de soja é uma cera vegetal renovável feita a partir do óleo de soja, popular na fabricação de velas ecológicas.', 'A cera de soja é um tipo de cera vegetal derivada do óleo de soja. É uma alternativa popular à cera de parafina tradicional, que é derivada do petróleo. A cera de soja é considerada uma opção renovável, biodegradável e ecologicamente correta para a fabricação de velas. Ela é criada mediante a hidrogenação do óleo de soja, transformando-o em uma forma sólida adequada para velas. Geralmente, apresenta-se na forma de Flocos, que são fáceis de medir e derreter.', '2026-02-11 17:17:32', '2026-02-11 17:17:32'),
(35, 'prod-soybean-oil', 'Óleo de Soja', 'Óleo de soja de alta qualidade para uso industrial e culinário', 'Óleo de soja é um óleo vegetal versátil extraído de soja, amplamente utilizado para frituras, assados e molhos para salada devido ao seu sabor neutro e alto ponto de fumaça.\nÉ rico em gorduras poli-insaturadas, incluindo ácidos graxos ômega‑3 e ômega‑6, e fornece vitamina K e vitamina E.\nÉ ideal para fritura profunda, produção de margarina e aplicações industriais na alimentação. Refinado e desodorizado segundo padrões premium.', '2026-02-05 21:50:40', '2026-02-11 17:29:08'),
(36, 'prod-sunflower-oil', 'Óleo de Girassol', 'Óleo de girassol refinado premium para cozimento e processamento de alimentos', 'Nosso óleo de girassol refinado premium é perfeito para cozinhar, fritar e aplicações de processamento de alimentos. Proveniente de sementes de girassol de qualidade e refinado para os mais altos padrões.', '2026-02-05 21:42:49', '2026-02-11 17:22:14');
INSERT INTO `products_ru` (`id`, `master_id`, `name`, `description`, `full_description`, `created_at`, `updated_at`) VALUES
(1, 'bdf424df-f9b0-4a79-84d6-f6ed1eb1e84f', 'Пальмовое масло Олейн', 'Пальмовое олеин — это жидкая фракция рафинированного пальмового масла, ценится как стабильное масло для жарки и приготовления пищи, которое обеспечивает нейтральный вкус, длительный срок жарки и хрустящую текстуру для закусок, фаст-фуда и бытовых нужд.', 'Пальмовое масло-олейцер produced by фракционирование рафинированного, отбеленного и дезодорированного (РВД) пальмового масла для получения прозрачной жидкости, богатой олеиновой и пальмитиновой кислотами, обеспечивающей сбалансированный профиль жирных кислот с естественной хорошей окислительной стойкостью. Его высокая точка дымления, устойчивость к окислению и полимеризации, а также низкая склонность к образованию посторонних запахов позволяют использовать повторные циклы жарки с меньшим распадом масла, меньшим образованием пены и увеличенным сроком хранения готовых продуктов.\n​\nВ пищевых целях пальмовое масло-олейцер широко используется в качестве среды для глубокого жарения закусок, картофельных чипсов, жареной курицы, быстрого приготовления лапши и полуфабрикатов, а также в качестве универсального кулинарного масла для домашних нужд во многих тропических регионах. Оно также служит базовым маслом в смесях с соевым, подсолнечным или другими растительными маслами для достижения определенных нутриционных и функциональных характеристик, а также используется в маргаринах, маслах для хлебопекарной промышленности и системах жарки для общественного питания, где важна стабильная работа и чистый вкус.', '2026-02-11 17:15:10', '2026-02-11 17:15:10'),
(2, 'prod-beeswax', 'Пчелиный воск', 'Натуральный пчелиный воск для косметики и изготовления свечей', 'Чистый натуральный пчелиный воск, полученный у этичных пчеловодов. Идеально подходит для косметики, изготовления свечей и кулинарных целей. Доступен в различных сортах.', '2026-02-05 21:57:15', '2026-02-11 17:29:46'),
(3, 'prod-bw101-palm-wax', 'Пальмовый воск', 'Премиальный 100% пальмовый воск с кремовым жёлтым оттенком, идеально подходит для изготовления свечей. Сертифицирован по стандартам RSPO SG (Segregated) / MB (Mass balance).', 'Премиальный 100% пальмовый воск с красивым кремово-жёлтым оттенком. Сертифицирован по стандарту RSPO MB для устойчивого развития. Идеально подходит для изготовления свечей, литья и свечей в контейнерах.', '2026-02-05 22:04:37', '2026-02-11 17:45:23'),
(4, 'prod-bw105-palm-wax', 'Пальмовые спреды (низкая точка плавления)', 'Пальмовое топирамидное масло — это полутвёрдое, не гидрогенизированное жирное вещество, полученное методом фракционной очистки пальмового масла, обладающее высокой устойчивостью и нейтральным вкусом.', 'Пальмовый shortening — это полутвердый, нерафинированный жир, полученный из фракционированного пальмового масла, обладающий высокой стабильностью и нейтральным вкусом.  \nИдеально подходит для хлебопекарных изделий — создаёт слоистые сдобные изделия, нежные торты и хрустящую жареную еду с высокой точкой дымления.  \nЭкономичный и устойчивый к окислению заменитель масла или сала в промышленной выпечке.', '2026-02-06 02:26:05', '2026-02-11 17:31:05'),
(5, 'prod-bw10510-blended-wax', 'Смесь парафина и парафиновый воск для стеклянных свечей', 'Готовая к использованию низкометановая смесь для свечей в банке: Palm-Paraffin-Microcrystalline с Polyboost™, Vybar®, УФ-стабилизаторы — просто добавьте краситель и аромат для отличной адгезии к стеклу и максимального распространения аромата.', 'Смесь для свечей в стеклянных банках Bio Green Wax с низкой температурой плавления (48-50°C) и (50-52°C) — формула на основе пальмового парафина и микрокристаллического парафина, оптимизированная для использования в стеклянных контейнерах. Готова к использованию: добавьте только краситель и ароматизатор. Включает Polyboost/Vybar для однородности и адгезии, UV-стабилизаторы/антиоксиданты для продления срока хранения, а также агенты для удержания аромата, обеспечивающие выдающийся горячий и холодный отлив, равномерное горение без заломов и превосходную фиксацию в банке для премиальных контейнерных свечей.', '2026-02-06 03:36:11', '2026-02-11 17:37:11'),
(6, 'prod-bw10555-blended-wax', 'Веганская смесь воска на основе сои', 'Готовая к использованию 95% соевая веганская смесь от Bio Green Wax — полностью растительного происхождения, предназначена для свечей в банке (48-52°C) и столбчатых свечей (56-62°C). Просто добавьте краситель и аромат.', 'Би Грин Вакс, веганская смесь из 95% соевого воска (5% растительных добавок), обеспечивает чистое горение и натуральную отдачу для стеклянных банок и самостоятельных колонн. Доступен с низкой точкой плавления (48-52°C) для контейнеров и высокой точкой плавления (56-62°C) для колонн. Готов к использованию: просто добавьте свой цвет и аромат для отличного распространения и гладкой отделки.', '2026-02-06 03:43:36', '2026-02-11 17:31:52'),
(7, 'prod-bw10610-blended-wax', 'Смесь парафина и пальмового парафина для столбчатых свечей', 'Готовые к использованию смеси для высокомаганитудных свечных колонн (56-58°C и 58-60°C): пальмово-парафиновая-микро-кристаллическая с Polyboost™, Vybar®, UV-стабилизаторами — просто добавьте цвет и аромат для превосходной работы свечных колонн.', 'Био Грин wax\'s High Melting Point Pillar Candle Blends (56-58°C и 58-60°C)—формулы на основе пальмового парафина и микрокристаллического парафина, разработанные специально для самостоятельных столбчатых свечей. Готовы к использованию: добавьте только краситель и ароматизатор. Оптимизированы с Polyboost/Vybar для легкого извлечения из формы и высокой непрозрачности, стабилизаторами/антиоксидантами UV для увеличения срока хранения, а также агентами для сохранения аромата, обеспечивающими превосходный раскал и холодный бросок, превосходное сохранение формы столбчатой свечи и чистое горение.', '2026-02-06 03:39:47', '2026-02-11 17:38:00'),
(8, 'prod-bw10655-blended-wax', 'Смесь соевого воска, пчелиного воска и парафинового воска', 'Готовая смесь соевого воска, пчелиного воска и парафина от Bio Green Wax — идеальный ароматораспылитель для свечей в банке (48-52°C) и столбиком (56-62°C). Просто добавьте аромат и краситель.', 'Смесь Bio Green Wax из соевого, пчелиного воска и парафина сочетает в себе естественную гладкость сои, стабильность пчелиного воска и мощность аромата парафина для непревзойденной эффективности запаха. Низкая точка плавления (48-52°C) идеально подходит для стеклянных емкостей; высокая точка плавления (56-62°C) отлично подходит для свечных колонн. Готовая к использованию формула — просто добавьте ароматизатор и краситель для превосходного горячего и холодного распространения запаха и безупречной отделки свечи.', '2026-02-06 03:47:07', '2026-02-11 17:32:42'),
(9, 'prod-bw8307-blended-wax', 'Смесь кокосового и рапсового воска', 'Готовая смесь кокоса и рапса от Bio Green Wax — кремовая натуральная основа для свечей в банке (от 48 до 52°C) и в колонне (от 56 до 62°C). Добавляйте только цвет и аромат.', 'Смесь Bio Green Wax с кокосовым и рапсовым воском сочетает в себе кремовую текстуру кокосового воска и ровное горение рапсового воска для исключительной натуральной свечи. Низкая температура плавления (48-52°C), оптимизированная для свечей в контейнерах; высокая температура плавления (56-62°C) — для столбиковых свечей. Полностью готова к использованию — добавьте только выбранный вами цвет и аромат для профессионального, чистого горения.', '2026-02-06 03:50:57', '2026-02-11 17:33:31'),
(10, 'prod-carnauba-wax', 'Пчелиный воск', 'Премиальный бразильский воск карнауба для полировок и покрытий', 'Премиальный бразильский карнаубский воск, известный как \"королева восков\". Идеален для полировки автомобилей, косметики и пищевых покрытий. Самая высокая природная температура плавления.', '2026-02-05 22:00:35', '2026-02-11 17:30:23'),
(11, 'prod-castor-oil', 'Касторовое масло', 'Премиальное холодного отжима касторовое масло, полученное из семян Ricinus communis, широко используемое в фармацевтике, косметике и промышленности.', 'Bio Green Wax поставляет высококачественное касторовое масло — универсальное растительное масло, полученное путём отжима семян растения клещевины (Ricinus communis). Известное своей уникальной химической структурой, насыщенной рицинолевой кислотой (примерно 85–90%), касторовое масло обладает исключительной вязкостью, смазочными и увлажняющими свойствами, что делает его незаменимым в самых различных отраслях.\n\nНаше касторовое масло тщательно отбирается и перерабатывается в соответствии с высочайшими стандартами чистоты и однородности. Оно доступно в холодном отжиме (необработанное) и рафинированных grade, подходящих для фармацевтической, косметической и промышленной сферы. Выдающаяся стабильность масла и его растворимость в спирте выделяют его среди других растительных масел, делая предпочитаемым ингредиентом в формулах, требующих высокого качества.\n\nКасторовое масло является природно биоразлагаемым продуктом, полученным из возобновляемых ресурсов, что соответствует обязательствам Bio Green Wax по экологически ответственному и устойчивому сырьевому обеспечению.', '2026-02-11 17:16:09', '2026-02-11 17:16:09'),
(12, 'prod-coconut-oil', 'Кокосовое масло', 'Веганское и рафинированное кокосовое масло для пищевых и косметических целей', 'Пременное сырье и рафинированное кокосовое масло, подходящее для кулинарии, выпечки и косметических применений. Доступно в различных grades, чтобы удовлетворить ваши конкретные требования.', '2026-02-05 21:50:14', '2026-02-11 17:16:55'),
(13, 'prod-coconut-wax', 'Кокосовый воск', 'Кокосовый воск — это натуральный воск, полученный из кокосового масла, ценится за чистое горение свечей и экологичные применения.', 'Кокосовый воск — это натуральный воск, получаемый из масла кокосов, известный своей чистой и медленной горелкой при изготовлении свечей. Его часто рассматривают как экологичную альтернативу другим видам воска. Кокосовый воск ценится за свои экологичные свойства и хорошую способность удерживать аромат. Он получен из природного и возобновляемого ресурса, обеспечивая чистое и медленное горение свечей, что способствует более длительному сроку службы и более эффективной работе.', '2026-02-11 17:25:44', '2026-02-11 17:25:44'),
(14, 'prod-fr5456-paraffin-wax', 'Полусырой парафиновый воск (50-68°C)', 'Bio Green Wax Полурафинированный парафин (50-68°C) — экономичный с содержанием масла 1-5% для свечей, резины, тканей и промышленных масштабов.', 'Парфирные воски Bio Green Wax полутеребоделённой очистки (50-68°C) обеспечивают экономичную работу с контролируемым содержанием масел (1-5%) для гибкой твердости. Стандартные grades: 52/54°C (свечи), 56/58°C (столбики), 60/62°C (промышленное применение). Идеально подходят для производства доступных свечей, добавок для обработки резины, отделки тканей и покрытий для тарообых материалов, где важны баланс между производительностью и ценой.', '2026-02-06 04:05:14', '2026-02-11 17:23:36'),
(15, 'prod-glycerine', 'Глицерин', 'Глицерин — бесцветная, без запаха, вязкая жидкость, широко используемая в фармацевтической, косметической и пищевой промышленности.', 'Глицерин, также известный как глицерол или глицерин, — бесцветная, без запаха и вязкая жидкость с сладким вкусом. Это прозрачная, сиропообразная жидкость, обычно бесцветная, хотя может иметь слегка желтоватый оттенок. Глицерин обладает высокой вязкостью, что означает, что он течет медленно и относительно густой. У него консистенция, похожая на сироп, что способствует его способности удерживать влагу. Глицерин широко используется в фармацевтике, косметике, пищевой промышленности и в различных промышленных сферах.', '2026-02-11 17:19:38', '2026-02-11 17:19:38'),
(16, 'prod-hydrogenated-castor-oil', 'Гидрогенизированное касторовое масло', 'Гидрогенизированное касторовое масло — это твердый воскообразный производный продукт касторового масла, используемый в косметике, фармацевтике и промышленности.', 'Гидрированный касторовый масло, также известное как касторовый воск или касторовый воск в виде хлопьев, является производным касторового масла, прошедшим процесс гидрогенизации. Это включает добавление водорода к молекулам касторового масла, в результате чего получается твердая, воскоподобная субстанция. Он применяется в косметических и средств личной гигиены, таких как помады, кремы и лосьоны, в качестве эмолента для придания коже гладкости и увлажнения. Также он выступает в качестве связующего агента в косметических составах, помогая ингредиентам сцепляться и прилипать к коже.', '2026-02-11 17:25:02', '2026-02-11 17:25:02'),
(17, 'prod-microcrystalline-wax', 'Микрокристаллический воск', 'Микрокристаллическая воск гибкой консистенции для косметики и клеев', 'Гибкий микрокристаллический воск, идеально подходящий для косметики, горячего плавления клеев и специальных покрытий. Отличная гибкость и адгезионные свойства.', '2026-02-06 03:57:50', '2026-02-11 17:22:56'),
(18, 'prod-olive-oil', 'Оливковое масло', 'Премиальное качество чистого оливкового масла, холодного отжима из отборных средиземноморских оливок для кулинарных, косметических и промышленных применений.', 'Наш премиальный чистый оливковый масло холодного отжима из sorgfältig отобранных средиземноморских оливок, обеспечивающее исключительное качество и насыщенный вкус. Широко используется в приготовлении пищи, косметике, фармацевтике и средствах для личной гигиены, оливковое масло ценится за свои полезные свойства, антиоксиданты и разнообразие применений. Bio Green Wax поставляет оливковое масло, которое соответствует строгим международным стандартам качества, обеспечивая постоянную чистоту и эффективность во всех сферах применения.', '2026-02-11 17:41:39', '2026-02-11 17:41:39'),
(19, 'prod-palm-kernel-oil', 'Пальмовое ядромасло', 'Пальмовое масло получают из ядра плода масличной пальмы, оно используется в пищевых продуктах, косметике и промышленных сферах.', 'Масло пальмовых орехов получают из ядра плода масличной пальмы и обладает характерными физическими свойствами. Оно обычно представляет собой светло-желтый или белый твердый материал при комнатной температуре, но при нагревании превращается в прозрачную, желтоватую жидкость. Точка плавления колеблется от 23 до 28 градусов Цельсия (73 до 82 градусов Фаренгейта). Масло пальмовых орехов богато лауриновой кислотой и широко используется в производстве продуктов питания, косметики и мыловарении.', '2026-02-11 17:21:30', '2026-02-11 17:21:30'),
(20, 'prod-palm-kernel-olein', 'Пальмовое масло стерни', 'Премиум-очищенный пальмовый кернельолейн, жидкая фракция, полученная в результате фракционирования пальмового кернельного масла, ценится за свою отличную прозрачность, низкую температуру помутнения и универсальное применение в пищевой, косметической и олеохимической промышленности.', 'Bio Green Wax поставляет высококачественный пальмовое масло олеин (PKOo), жидкую фракцию, производимую посредством контролируемой фракционировки рафинированного пальмового масла. При охлаждении пальмового масла под точными условиями оно разделяется на твердую фракцию (пальмостьерин) и жидкую фракцию (пальмовое масло олеин). В результате получается прозрачное, светлое масло с низкой точкой плавления и отличной текучестью.\n\nПальмовое масло олеин богато лауриновой кислотой (C12) и каприловой/каприновой маслами средней цепи, что придает ему исключительную прозрачность, быструю усвояемость и легкое, не жирное ощущение. Эти характеристики делают его особенно востребованным в пищевой промышленности в качестве кулинарного масла, жарочного средства и компонента в несырных сливках, мороженом и молочных смесях с наполнителями.\n\nВ секторе личной гигиены и косметики пальмовое масло олеин широко используется в качестве базового масла в lotions, кремах, шампунях и жидких мылах благодаря своим отличным смягчающим свойствам и совместимости с кожей. Оно также служит важным сырьем для производства олеохимикатов, из которых получают жирные кислоты, метилэстеры и поверхностно-активные вещества, используемые в моющих средствах и чистящих продуктах.\n\nBio Green Wax закупает пальмовое масло олеин у поставщиков, сертифицированных по RSPO, что обеспечивает полную прослеживаемость и соответствие целям устойчивого развития пальмового масла. Продукт представлен в рафинированной, отбеленной и ароматизированной (RBD) форме, соответствующей строгим международным стандартам качества.', '2026-02-11 17:46:11', '2026-02-11 17:46:11'),
(21, 'prod-palm-kernel-stearin', 'Пальмоядровый стеарин', 'Высококачественный пальмовый кэролинстирин, твердое вещество, полученное в результате фракционирования пальмового орехового масла, ценится за свой острый профиль плавления и отличную твердость в кондитерских, косметических и олеохимических применениях.', 'Bio Green Wax поставляет высококачественный пальмовое масло–стерины (PKS), твердая фракция с более высокой точкой плавления, получаемая через контролируемую фракционную обработку рафинированного пальмового масла. В процессе фракционирования пальмовое масло разделяется на две составляющие: пальмоядровый олеин (жидкая фракция) и пальмоядровый стерин (твердая фракция). В результате получается стерин — белый или слегка желтоватый жир с характерной острой точкой плавления и твердой текстурой.\n\nПальмоядровый стерин богат лауриновой кислотой (C12) и миристиновой кислотой (C14), что дает ему отличную твердость, быстрое кристаллизование и чистый профиль плавления. Эти свойства делают его идеальным ингредиентом для заменителей какао-масла (CBS), компаундных шоколадных покрытий, кондитерских наполнителей и специальных жиров, где необходимы хруст и блестящая поверхность.\n\nПомимо пищевого применения, пальмоядровый стерин служит ценным сырьем в олеохимической промышленности для производства жирных кислот, жирных спиртов, мылодельных нитей и моющих средствами. В личной гигиене и косметике он придает телу и структуре кремам, лосьонам и твердым formulations.\n\nBio Green Wax получает пальмоядровый стерин из цепочек поставок, сертифицированных RSPO, что обеспечивает полную прослеживаемость и соблюдение обязательств по устойчивому развитию масличных культур. Продукт выпускается в рафинированной, отбеленной и дезодорированной (RBD) форме, отвечающей международным стандартам качества для пищевого и технического использования.', '2026-02-11 17:20:33', '2026-02-11 17:20:33'),
(22, 'prod-palm-oil', 'Пальмовое масло', 'Производство пальмового масла и его производных с устойчивых источников', 'Эко-ответственно поставленное пальмовое масло и продукты его переработки для производства продуктов питания, мыла и моющих средств. Доступны сертифицированные варианты RSPO.', '2026-02-05 21:50:40', '2026-02-11 17:28:32'),
(23, 'prod-palm-shortenings', 'Пальмовое жироподобное масло (с высоким температурой плавления)', 'Высокотопленые пальмовые жиры-слоночки (46–52 °C) являются специализированными кондитерскими и жареными жирами, изготовленными из фракционированного пальмового масла, предназначенными для обеспечения прочной структуры, чистого вкуса и отличной термостойкости в сложных промышленных применениях.', 'Пальмовые шортенинги с высокой температурой плавления в диапазоне 46–52 °C изготавливаются из пальмовых стиринов и средних фракций, обеспечивая высокий содержание твердых веществ, плотную текстуру и稳定ную кристаллическую сеть при комнатной и повышенной температуре. Этот более высокий диапазон плавления обеспечивает превосходную теплоустойчивость, окислительную стабильность и снижение проявлений «oil-out», что делает их особенно подходящими для тропических климатов и линий переработки при высокой температуре.\n\nВ хлебопекарных ремеслах эти шортенинги обеспечивают хорошую аэрацию, ламинацию и хруст, поддерживая слоеные корочки пирогов, слоеное тесто, сливочные крекеры, печенье и бисквиты, даже при теплых условиях сохраняя форму и приятную консистенцию. Они также используются в качестве надежных жиров для жарки и замеса теста, а также в качестве заменителей животного жира в мясных изделиях, где их жесткая структура, стабильность эмульсий и профиль без трансизомеров, безгидрогенизированный, помогают достигнуть постоянной текстуры, чистого вкусового раскрытия и формирования этикеток,-friendly.', '2026-02-11 17:27:42', '2026-02-11 17:27:42'),
(24, 'prod-palm-stearic-acid', 'Пальмитиновая кислота', 'Пальмовая стеариновая кислота — это насыщенная жирная кислота, получаемая из пальмового масла, используемая в косметике, свечах и производстве резины.', 'Пальмовая стеариновая кислота — это тип жирной кислоты, полученной из пальмового масла путём разделения и кристаллизации жирных кислот. Это насыщенная жирная кислота, известная своей стабильностью и твёрдой формой при комнатной температуре. Пальмовая стеариновая кислота имеет воскоподобную поверхность, варьирующуюся от белого до слегка желтоватого оттенка. Ее температура плавления обычно колеблется между 55-70 градусами Цельсия (131-158 градусами по Фаренгейту), что позволяет легко включать её в различные формулы для косметики, свечей и резиновых изделий.', '2026-02-11 17:39:28', '2026-02-11 17:39:28'),
(25, 'prod-palm-stearin', 'Пальмовое стеариновое масло', 'Пальмовое стеариновое масло — это твердая фракция пальмового масла, широко используемая в производстве продуктов питания, свечей и мыловарении.', 'Пальмовая сераина — это твердое фракционное соединение пальмового масла, полученное в процессе фракционирования, известное высоким содержанием насыщенных жирных кислот. Она представляет собой твердый жир при комнатной температуре, с кремово-белым или бледно-желтым цветом и гладкой, воскоподобной текстурой. У пальмовой сераины более высокая температура плавления по сравнению с пальмовым маслом. Обычно она используется в пищевой промышленности для стабилизации жиров, производства маргаринов и в изготовлении свечей и мыла.', '2026-02-11 17:38:46', '2026-02-11 17:38:46'),
(26, 'prod-paraffin-wax', 'Полностью рафинированный парафиновый воск (50-68°C)', 'Bio Green Wax полностью очищенный парафин (50-68°C)—продукт питания/фармацевтического класса, содержание масел менее 0,5%, превосходная твердость. Идеально подходит для свечей, косметики, упаковки и точных промышленных применений.', 'Тканые парафиновые воски Bio Green Wax с полностью рафинированной структурой (температура плавления 50-68°C) характеризуются ультранизким содержанием масла (<0,5%), исключительной твердостью и нейтральным запахом/цветом. Доступны в свечных сортаментах (52/54°C, 56/58°C), контейнерных сортах (50/52°C) и высокотемпературных колонковых сортаментах (64/66°C). Идеальны для премиальных свечей, косметики, покрытий для пищевой упаковки и точечного формования, требующих максимальной чистоты и постоянства характеристик.', '2026-02-06 03:54:32', '2026-02-11 17:43:22'),
(27, 'prod-pf56-synthetic-wax', 'Воск Фишера-Тропша (FT)', 'Воск Фишер‑Тропш (FT) — это высокочистый синтетический парафин, производимый из синтез-газа, обладающий высокой точкой плавления, низкой вязкостью и отличной твердостью, что делает его пригодным для требовательных применений в пластиках, покрытиях, красках, клеях и модификации битума.', 'Восковая продукция FT создается методом синтеза Фишера-Тропша, в результате которого получается водянисто-белый, ультрачистый воск с узким распределением по цепям углерода, очень низким содержанием масел и выдающейся термической стабильностью. Он сочетает в себе высокий температуру размягчения с низкой вязкостью расплава и высокой твердостью, что обеспечивает превосходную стойкость к царапинам, контроль блеска, матирующие эффекты и смазочные свойства во многих композициях.\n\nВ обработке пластмасс и PVC/CPVC воск FT выступает в качестве эффективного внутреннего и внешнего смазочного и helper-агента, уменьшает вязкость расплава, улучшает текучесть, а также повышает высвобождение из формы и стабильность размеров. Он широко используется в горячих клеях и клеях с чувствительностью к давлению, красках для печати и промышленных покрытий для повышения твердости, устойчивости к истиранию и царапинам, блокирующих свойств и предотвращения оседания, одновременно стабилизируя вязкость. Дополнительные ключевые применения включают модификацию битума и асфальта, мастербячи и компаунды полимеров, переработку резины, полироли, текстиль и даже косметические формулы, где FT-воск обеспечивает контролируемую кристалличность, улучшенную износостойкость и устойчивость к морщинам, а также гладкое тактильное ощущение.', '2026-02-06 04:16:22', '2026-02-11 17:44:16'),
(28, 'prod-pfad', 'PFAD (Дестиллят пальмовый жирных кислот)', 'PFAD — побочный продукт переработки пальмового масла, используемый в производстве мыла, кормов для животных и био топлива.', 'Дистиллят пальмовых жирных кислот (PFAD) — побочный продукт процесса рафинирования пальмового масла. Он получается путём дистилляции сырого пальмового масла для удаления примесей и достижения более высокой степени чистоты. PFAD — это жидкость коричневато-жёлтого цвета с характерным запахом. Он содержит смесь насыщенных и ненасыщенных жирных кислот, при этом преобладают лауриновая, миристиновая и пальмитиновая кислоты. PFAD используется в производстве мыла, кормов для животных и биоэтанола.', '2026-02-11 17:26:31', '2026-02-11 17:26:31'),
(29, 'prod-pkfad', 'Дистиллят жирных кислот пальмового ядра (PKFAD)', 'PKFAD является побочным продуктом рафинирования пальмового ядра, богатым лауриновой кислотой, используемой в мыловаренной и олейтинговой промышленности.', 'Дистиллят пальмовых косточек жирных кислот (PKFAD) — это побочный продукт, получаемый в процессе рафинирования пальмового ядра. Он богат жирными кислотами, включая мноюрацную кислоту, что делает его ценным для определённых промышленных применений. PKFAD применяется в различных отраслях промышленности, включая производство мыла, биоэтанола и в качестве сырья в олеохимической индустрии.', '2026-02-11 17:40:12', '2026-02-11 17:40:12'),
(30, 'prod-polyethylene-wax', 'Полиэтиленовая воск (PE-воск)', 'N kannst производит низкомолекулярный полиэтилен, используемый как высокоэффективная смазка и добавка для обработки в пластмассах, покрытиях, красках и клеях, улучшая текучесть, скользкость поверхности и устойчивость к царапинам.', 'Полиэтиленовая воск — это тонко раздробленный, высокотемпературный синтетический воск с низкой вязкостью, отличной термической стабильностью и высокой совместимостью с распространёнными полимерами, такими как PVC, PE, PP и EVA. Он обеспечивает внутреннее и внешнее смачивание, снижает вязкость расплава и трение, улучшает высвобождение из формы и создает гладкую, глянцевую и устойчивую к царапинам поверхность.\n​\n\nОсновные области применения включают обработку пластиков и мастикажа, где PE-воск повышает эффективность экструзии и литья под давлением, предотвращает накопление на формах и улучшает дисперсию пигментов и наполнителей. Он также используется в горячих расплавах и клеях с чувствительной к давлению адгезией, чернилах и порошковых покрытых материалах для регулировки вязкости расплава, повышения сцепляемости и прочности, а также для оптимизации времени открывания и застывания. Дополнительное применение охватывает битум и дорожные краски, древесно-пластиковые композиты, rubber-композиты, кабельные составы и формульные wax-продукты, такие как полироли и карандаши, где он повышает температуру размягчения, твердость и водопрочность.', '2026-02-06 04:01:24', '2026-02-11 17:42:29'),
(31, 'prod-rapeseed-oil', 'Рапсовое масло', 'Холодного отжима и рафинированное рапсовое масло с фермерских хозяйств Великобритании', 'Холодного отжима и рафинированное рапсовое масло, полученное с фермерских хозяйств Великобритании. Идеально подходит для приготовления пищи, запекания и заправки салатов. Низкое содержание насыщенных жиров и богатое омега-3.', '2026-02-05 21:54:09', '2026-02-11 17:34:12'),
(32, 'prod-rapeseed-wax', 'Масло рапсовых семян', 'Рапсовое воск — это натуральный растительный воск, используемый в качестве экологически чистой альтернативы при производстве свечей и косметики.', 'Воск из масличной редьки — это натуральный растительный воск, получаемый из масла растения масличной редьки, широко используемый как экологичная альтернатива традиционному парафиновому воску в изготовлении свечей и других сферах. Он обеспечивает чистое и медленное горение, а также хорошую удержание аромата. Воск из масличной редьки часто применяется в производстве свечей и в составлении натуральной косметики, такой как бальзамы для губ, лосьоны и кремы, обладая увлажняющими свойствами.', '2026-02-11 17:24:19', '2026-02-11 17:24:19'),
(33, 'prod-soap-noodles', 'Мыловаренная паста', 'Мылообразующие нити — это первичные исходные материалы для производства мыла, получаемые путем слабоонования растительных масел и жиров.', 'Мыльная стружка, также известная как мыльные гранулы, является одним из основных сырьевых материалов, используемых в производстве мыла. Она производится путём обработки растительных масел и жиров с помощью гидроксида натрия (щёлочи) посредством салипономизации. Мыльная стружка обычно представляет собой твёрдые белые или бежевые куски или шарики с мягким и нейтральным ароматом. Она не содержит примесей и обладает высокой концентрацией жирных кислот, что способствует её очищающим и эмульгирующим свойствам.', '2026-02-11 17:40:56', '2026-02-11 17:40:56'),
(34, 'prod-soy-wax', 'Соевый воск', 'Соевый воск — это возобновляемый растительный воск, произведённый из соевого масла, популярный для экологически чистого изготовления свечей.', 'Соевый воск — это вид растительного воска, получаемого из соевого масла. Он является популярной альтернативой традиционному парафинному воску, который получают из нефти. Соевый воск считается возобновляемым, биоразлагаемым и экологически чистым выбором для изготовления свечей. Его получают путем гидрогенизации соевого масла, преобразуя его в твердую форму, пригодную для свечей. Обычно он выпускается в виде хлопьев, которые легко измерять и расплавлять.', '2026-02-11 17:17:34', '2026-02-11 17:17:34'),
(35, 'prod-soybean-oil', 'Соевое масло', 'Высококачественное соевое масло для промышленного и кулинарного использования', 'Соевое масло — универсальное растительное масло, получаемое из soybeans, широко используемое для жарки, выпечки и заправки салатов благодаря своему нейтральному вкусу и высокой точке дымления.  \nОно богато полиненасыщенными жирами, включая омега‑3 и омега‑6 жирные кислоты, а также содержит витамин K и витамин E.  \nИдеально подходит для глубокой жарки, производства маргарина и промышленных продуктов питания. Очищено и дезодорировано до высокого стандарта.', '2026-02-05 21:50:40', '2026-02-11 17:29:11'),
(36, 'prod-sunflower-oil', 'Подсолнечное масло', 'Преминое рафинированное подсолнечное масло для приготовления пищи и переработки продуктов питания', 'Наш премиальный рафинированный подсолнечное масло идеально подходит для приготовления, жарки и обработки продуктов питания. Происходит из качественных подсолнечных семян и рафинируется по самым высоким стандартам.', '2026-02-05 21:43:01', '2026-02-11 17:22:16');
INSERT INTO `products_sw` (`id`, `master_id`, `name`, `description`, `full_description`, `created_at`, `updated_at`) VALUES
(1, 'bdf424df-f9b0-4a79-84d6-f6ed1eb1e84f', 'Palm Olein', 'Palm olein ni sehemu ya kioevu ya mafuta ya palmi yaliyosemwa, inayotambuliwa kama mafuta thabiti ya kukaanga na kupikia ambayo hutoa ladha isiyo na ladha maalum, maisha marefu ya kukaanga, na muundo mkavu kwa vyakula vya vitafunwa, vyakula vya haraka, na matumizi ya nyumbani.', 'Palm olein hutengenezwa kwa kugawanya mafuta ya mbao yaliyochakatwa, yaliyopauka, na yaliyotulizwa (RBD) ili kupata kioevu safi chenye utajiri wa asidi ya oleiki na palmitic, na kutoa mkusanyiko wa asidi tata wa mafuta yenye utulivu mzuri wa kioevu kwa asili. Kuepuka kwake kwa kiwango cha juu cha moshi, upinzani dhidi ya oksidi na uundaji wa polymers, pamoja na kutokuwa na mwelekeo mdogo wa kuunda harufu mbaya, kunaruhusu mizunguko ya kukaanga mara kwa mara kwa mafuta yanayodumu kwa muda mrefu bila kupasuka, kupungua kwa povu, na kuongeza muda wa kukaa kwa bidhaa zilizomalizika.\n​\nKatika matumizi ya chakula, palm olein hutumika sana kama kati ya kukaanga kwa vyakula vya vitafunwa, chipsi za viazi, kuku waliokaangwa, sahani za kukaanga za haraka, na vyakula vya baridi vilivyowekwa tayari, pamoja na mafuta ya nyumbani kwa matumizi ya jumla katika masoko mengi ya kitropiki. Pia hutumika kama mafuta ya msingi katika mchanganyiko na soya, alizeti, au mafuta mengine ya mboga ili kufanikisha mifumo ya lishe na kazi zilizobinafsishwa, na hutumika katika margarine, mafuta ya mkate, na mifumo ya kukaanga ya huduma za chakula ambapo utendaji thabiti na ladha safi ni muhimu.', '2026-02-11 17:15:21', '2026-02-11 17:15:21'),
(2, 'prod-beeswax', 'Nguvu za nta', 'Parafua safi ya nyuki kwa ajili ya urembo na utengenezaji wa mishumaa', 'Ngeu safi asilia kutoka kwa wawindaji nyuki wa maadili. Inafaa kwa matumizi ya vipodozi, utengenezaji wa mishumaa, na matumizi ya chakula. Inapatikana kwa viwango mbalimbali.', '2026-02-05 21:58:01', '2026-02-11 17:29:53'),
(3, 'prod-bw101-palm-wax', 'Kiazi cha Waluti', 'Wax ya palm 100% ya Premium yenye rangi ya manjano yenye mantiki, inayofaa kwa kutengeneza mishumaa. Imetambulika na RSPO SG (Segregated) / MB (Mass balance).', 'Wax ya mviringo wa 100% ya palm wenye rangi nzuri ya manjano ya creme. Imetibitishwa na RSPO MB kwa ajili ya uendelevu. Inafaa sana kwa utengenezaji wa mishumaa, kuunda mifumo, na mishumaa ya chupa.', '2026-02-05 22:05:36', '2026-02-11 17:45:31'),
(4, 'prod-bw105-palm-wax', 'Palm Shortening (Mchakato wa Kupoa wa Chini)', 'Palm Shortening ni mafuta semi-imara, yasiyo na hydrogenate yanayotokana na mafuta ya mbegu za mwani yaliyogawanyika, yanayotoa uimara bora na ladha isiyo na ladha maalum.', 'Palm Shortening ni mafuta yaliyo semi-solid, yasiyo na hydrogenated yanayotokana na palm oil iliyogawanyika, na kutoa utulivu bora na ladha ya asili. \nInafaa kwa matumizi ya bidhaa za bakery—huunda maziwa ya keki yaliyonyooka, mifupa laini, na vyakula vya kukaanga vilivyokoroma na kiwango cha juu cha kuteketeza moshi. \nMbadala wa bei nafuu, usioharibika na oksidi kwa siagi au ladi kwenye pagani za viwanda.', '2026-02-06 02:27:03', '2026-02-11 17:31:15'),
(5, 'prod-bw10510-blended-wax', 'Kiazi cha parafini cha mchanganyiko wa Palm-Paraffin kwa mishumaa ya chupa', 'Mchanganyiko wa Kandarasi ya Mashumari ya Low MP iliyotayarishwa tayari: Palm-Paraffin-Microcrystalline na Polyboost™, Vybar®, stabilizers za UV—ongeza tu rangi na manukato kwa kuambatana bora na kioo na upeo mkubwa wa utoaji.', 'Mchanganyiko wa taa ya kioo ya Bio Green Wax Low Melting Point Jar Candle (48-50°C) na (50-52°C)—Mfumo wa Palm-Paraffin-Microcrystalline ulioboreshwa kwa ajili ya vyombo vya glasi. Tayari kutumika: ongeza tu rangi na harufu. Inajumuisha Polyboost/Vybar kwa ulinzi wa utando/ushikaji, viambato vya UV stabilizers/antioxidants kwa muda wa kuhifadhi, pamoja na wakala wa kuhifadhi harufu ambao huwapa uwezo wa kutupa jua kali na baridi, kuchoma bila mikunjo, na usikimaji bora wa jar kwa ajili ya mishumaa ya makontena ya hali ya juu.', '2026-02-06 03:37:04', '2026-02-11 17:37:21'),
(6, 'prod-bw10555-blended-wax', 'Mchanganyiko wa Takatifu wa Wax ya Vegan inayotokana na Soja', 'Mchanganyiko wa Vegan wa Soy 95% wa Ready-to-use kutoka Bio Green Wax—bakiwa kabisa na asili ya mimea kwa mishumaa ya Jar (48-52°C) na Pillar (56-62°C). Ongeza rangi na harufu tu.', 'Bio Green Wax\'s 95% Soy Wax Vegan Blend (5% mchanganyiko wa mimea) unatoa mwanga safi, wa asili kwa chupa za glasi na misingi inayojitegemea. Inapatikana kwa kiwango cha kiwango cha chini cha kuyeyuka (48-52°C) kwa chujio na kiwango cha juu cha kuyeyuka (56-62°C) kwa misingi. Tayari kwa matumizi: ongeza tu rangi na harufu yako kwa fasaha ya kipekee na mwisho laini.', '2026-02-06 03:44:36', '2026-02-11 17:32:01'),
(7, 'prod-bw10610-blended-wax', 'Paraafin ya palm na mchanganyiko wa nta wa mishumaa ya Pillar', 'Mchanganyiko wa Mishi wa Kila Mara wa Msingi wa High MP wa tayari kutumika (56-58°C & 58-60°C): Palm-Paraffin-Microcrystalline na Polyboost™, Vybar®, stabilizers za UV—onlyosha rangi na harufu kwa utendaji bora wa mshipa wa msingi.', 'Bio Green wax\'s High Melting Point Pillar Candle Blends (56-58°C & 58-60°C)—Mchanganyiko wa mafuta ya palm-Paraffin-Microcrystalline uliobuniwa kwa ajili ya mishumaa ya nguzo inayojitegemea. Imeandaliwa tayari kwa matumizi: ongeza tu rangi na harufu. Imeboreshwa kwa Polyboost/Vybar kwa ajili ya kuachilia mold na ufanisi wa opacity, viungio vya UV stabilizers/antioxidants kwa ajili ya kuongeza muda wa matumizi, pamoja na wapataji wa kubeba harufu ambao hutoa uzalishaji wa moto/baridi wa kipekee, kuhifadhi umbo kamilifu la mishumaa ya nguzo, na utendaji wa kuchoma safi.', '2026-02-06 03:40:42', '2026-02-11 17:38:08'),
(8, 'prod-bw10655-blended-wax', 'Mchanganyiko wa Soy-Beeswax na Paraffin Wax', 'Mchanganyiko wa Soy-Beeswax-Paraffin wa tayari kwa matumizi kutoka Bio Green Wax—kukata harufu kali kabisa kwa mishumaa ya Jar (48-52°C) na Pillar (56-62°C). Kutoa harufu na rangi tu.', 'Bio Green Wax\'s Soy-Beeswax-Paraffin Blend huunganisha ufanisi wa asili wa soja, uimara wa asali, na uwezo wa harufu wa paraffin kwa utendakazi usio na kifani wa harufu. Kielelezo cha kiwango kidogo cha kuyeyuka (48-52°C) kinatenda vyema kwenye vyombo vya vioo; kiwango kikubwa cha kuyeyuka (56-62°C) kinafaa kwa mipheru. Muundo wa tayari kutumia—ongeza tu harufu na rangi kwa ufanisi wa moto/baridi na kumaliza taa bila kasoro.', '2026-02-06 03:48:05', '2026-02-11 17:32:53'),
(9, 'prod-bw8307-blended-wax', 'Mchanganyiko wa Parafufa wa Kokos na Mafuta ya Lecithin', 'Mchanganyiko wa Mafutanyakula ya Kokos na Mafuta ya Mzeituni uliotengenezwa tayari kutoka Bio Green Wax—utendaji wa asili wenye cramu kwa mishumaa ya Jar (48-52°C) na Pillar (56-62°C). Ongeza rangi na harufu pekee.', 'Bio Green Wax\'s Coconut-Rapeseed Blend inachanganya muundo wa mafuta ya nazi na ule wa mafuta ya rapeseed kwa kuwasha kwa mwezi asilia kwa muonekano bora wa taa za asili. Kiwango cha chini cha kuteketeza (48-52°C) kilichoboreshwa kwa taa za chupa; kiwango cha juu cha kuteketeza (56-62°C) kwa taa za nguzo. Imekwisha kamilika, tayari kutumia—ongeza tu rangi na harufu unazozipenda kwa matokeo ya kitaalamu na safi yanayowaka.', '2026-02-06 03:51:55', '2026-02-11 17:33:42'),
(10, 'prod-carnauba-wax', 'Sugatula ya Carnauba', 'Wax ya kutumia wa Brazil ya premium Carnauba kwa polishi na shinikizo', 'Wax ya premium ya Brazilian carnauba, inayojulikana kama \"malkia wa waxes\". Inafaa kwa kusafisha magari, vipodozi, na zinazofunga vyakula. Kiwango cha juu cha halijoto ya kuyeyuka ya asili.', '2026-02-05 22:01:23', '2026-02-11 17:30:30'),
(11, 'prod-castor-oil', 'Mafuta ya Castor', 'Mafuta ya nazi ya cold-pressed ya kiwango cha juu yanayotokana na mbegu za Ricinus communis, yanayotumika sana katika uwanja wa agharama, vipodozi, na matumizi ya viwandani.', 'Bio Green Wax inatoa mafuta ya mazao ya kastori ya ubora wa juu, mafuta ya mboga yenye matumizi mengi yanapatikana kwa kubonyeza mbegu za mmea wa kastori bean (Ricinus communis). Inajulikana kwa muundo wake wa kipekee wa kemikali uliojaa asidi ya ricinoleic (takriban 85–90%), mafuta ya kastori yanaonyesha wiani wa kipekee, uwezo wa kusugua, na mali ya unyonyaji ambayo yanayufanya kuwa muhimu sana kwenye sekta mbalimbali.\n\nMafuta yetu ya kastori yanapatikana kwa uangalifu na kuchakatwa ili kukidhi viwango vya juu zaidi vya usafi na mwaka. Inapatikana kwa hali ya cold-pressed (virgin) na refined, inayostahili kwa matumizi ya dawa, urembo, na viwandani. Utulivu wa ajabu wa mafuta haya na uwezo wake wa kuchanganyika na pombe yanamtofautisha na mafuta mengine ya mboga, na kumfanya kipengele kinachopendelewa katika taarifa zinazohitaji utendaji wa juu.\n\nMafuta ya kastori ni asili yanayoweza kuharibika na yanatoka kwa rasilimali zinazoweza kurejeshwa, yanayolingana na dhamira ya Bio Green Wax ya upatikanaji wa mazingira kwa njia endelevu na zinazowajibika kwa mazingira.', '2026-02-11 17:16:20', '2026-02-11 17:16:20'),
(12, 'prod-coconut-oil', 'Mafutaya Nazi', 'Mafuta ya parachichi yasiyobadilishwa na yaliyosafishwa kwa matumizi ya chakula na ajili ya urembo', 'Supuzi ya nazi safi na iliyochakatwa kwa ubora wa hali ya juu inayofaa kwa kupikia, kuoka, na matumizi ya kosmetiki. Inapatikana kwa viwango mbalimbali ili kukidhi mahitaji yako maalum.', '2026-02-05 21:50:40', '2026-02-11 17:17:04'),
(13, 'prod-coconut-wax', 'Paraffini ya Nazi', 'Sili ya nazi ni mafuta asili yanayotoka kwenye mafuta ya nazi, yanayothaminiwa kwa mishumaa safi inayowaka na matumizi rafiki kwa mazingira.', 'Sukari ya nazi ni wax ya asili inayotokana na mafuta ya nazi, maarufu kwa kuchoma safi na polepole katika utengenezaji wa mishumaa. Mara nyingi huzingatiwa kama njia endelevu ya kuchukua nafasi ya wax nyingine. Sukari ya nazi imenunuliwa kwa sifa zake za kirafiki kwa mazingira na uwezo wake wa kushikilia harufu vizuri. Inatokana na rasilimali asili na zinazoweza kurejeshwa, ikitoa kuchoma safi na polepole katika mishumaa kwa kipindi chenye muddadili na ufanisi zaidi.', '2026-02-11 17:25:53', '2026-02-11 17:25:53'),
(14, 'prod-fr5456-paraffin-wax', 'Pochini la Paraffini Isiyo Kamili (50-68°C)', 'Bio Green Wax Paraffini Semi Refined (50-68°C)—gharama nafuu, mafuta ya 1-5% kwa mishumaa, mpira, nguo na matumizi ya viwandani yenye mtiririko mkubwa.', 'Bio Green Wax\'s Semi Refined Paraffin Waxes (50-68°C) yanatoa utendaji wa kujenga bei nafuu yenye kiasi kinachodhibitiwa cha mafuta (1-5%) kwa usakinishaji unaobadilika. Viwango vya Kawaida: 52/54°C ( mishumaa), 56/58°C (nguzo), 60/62°C (viwanda). Inafaa kamili kwa uzalishaji wa mishumaa unaohitaji bajeti, msaada wa usindikaji wa mpira, kumalizia kwa ngozi, na coating za ujazo wa makopo ambapo utendaji wa usawa na bei vinathaminiwa zaidi.', '2026-02-06 04:06:10', '2026-02-11 17:23:46'),
(15, 'prod-glycerine', 'Glycerini', 'Glycerine ni kioevu kisicho na rangi, kisicho na harufu, chenye wingi wa unyevunyevu kinachotumika sana katika sekta za dawa, urembo, na chakula.', 'Glycerine, pia inajulikana kama glycerol au glycerin, ni kioevu kisicho na rangi, kisicho na harufu, na chenye unyevunyevu mkubwa chenye ladha tamu. Ni kioevu cha uwazi, kinachoshikana kama syrupi, ambacho kwa kawaida hakina rangi, ingawa kinaweza kuwa na tinge nyekundu kidogo. Glycerine ina unyevunyevu mkubwa, yaani inatiririka polepole na ni nyembamba kwa kiasi kikubwa. Ina muundo wa kama syrupi, ambao huchangia uwezo wake wa kubeba unyevu. Glycerine inatumika sana katika sekta za vidonge, vipodozi, usindikaji wa vyakula, na matumizi tofauti ya viwandani.', '2026-02-11 17:19:48', '2026-02-11 17:19:48'),
(16, 'prod-hydrogenated-castor-oil', 'Mafuta ya Castor yaliyohifadhiwa na Hydrogen', 'Mafuta ya mafuta ya karite yaliyo hydrogenated ni kiwali chenye umbo wa jiwe la kung\'aa kinachotoka kwa mafuta ya karite, kinatumika katika vipodozi, dawa, na matumizi ya viwanda.', 'Mafuta ya minazi yaliyo hydrogenated, yanajulikana pia kama wax ya minazi au flakes za wax ya minazi, ni bidhaa ya toholdwa kutoka kwa mafuta ya minazi ambayo yanapitia mchakato wa hydrogenation. Hii inahusisha kuongeza hydrogen kwenye molekuli za mafuta ya minazi, na kusababisha nyongeza ya kinyesi kigumu, kilichojumuika kama wax. Inatumika katika bidhaa za urembo na usafi wa binafsi kama lipsticks, krimu, na lotions kama emollient ili kutoa laini na unyevu kwa ngozi. Pia hufanya kama kiunganishi katika mchanganyiko wa vipodozi, kusaidia viungo kushikamana pamoja na kusalia kwenye ngozi.', '2026-02-11 17:25:12', '2026-02-11 17:25:12'),
(17, 'prod-microcrystalline-wax', 'Sabuni ya Microcrystalline', 'Parafini ya microcrystalline inayobadilika kwa urahisi kwa ajili ya vipodozi na mafuta ya kunamakia', 'Asali ya microcrystalline inayobadilika kwa urahisi, bora kwa vipodozi, makanda ya kuyeyusha kwa joto, na coatings maalum. Kubadilika kwake kwa kipekee na sifa nzuri za kujifunga.', '2026-02-06 03:58:46', '2026-02-11 17:23:04'),
(18, 'prod-olive-oil', 'Mafuta ya Zaituni', 'Ngozi ya ubora wa juu mafuta ya mzeituni safi, yaliyojikunja kwa baridi kutoka kwa mzeituni bora ya Mediterranean kwa matumizi ya upishi, urembo, na viwandani.', 'Supu ya mafuta ya kamili ya zeituni safi ya Premium ya Bio Green Wax imetengenezwa kwa shinikizo la baridi kutoka kwa mawezi ya Mediterranean yaliyochaguliwa kwa makini, na kuhakikisha ubora wa kipekee na ladha tajiri. Imethumika sana katika maandalizi ya vyakula, vipodozi, dawa, na bidhaa za urembo binafsi, mafuta ya zeituni yanathaminiwa kwa faida zake kiafya, mali za antioksidanti, na matumizi mbalimbali. Bio Green Wax inapata mafuta ya zeituni yanayokidhi viwango mkali vya ubora wa kimataifa, kuhakikisha usafi wa kudumu na utendaji mzuri katika matumizi yote.', '2026-02-11 17:41:49', '2026-02-11 17:41:49'),
(19, 'prod-palm-kernel-oil', 'Mafuta ya Mafuta ya Mafuta ya Mafuta', 'Mafuta ya kernel ya kinoo cha mpira wa mikoko yanatokana na kernel ya tunda la mkaa wa mafuta, yanatumika katika bidhaa za chakula, vipodozi, na matumizi ya viwandani.', 'Mafuta ya kernel ya mti wa mikoko hupatikana kutoka kwenye kernel ya tunda la mti wa mikoko na yana sifa za kiwili za kipekee. Kwa kawaida ni rangi nyepesi ya manjano hadi nyeupe kuwa ukilinganisha na joto la chumba, lakini huinyea na kuwa mchochovyo wa rangi ya manjano wazi wakati yanapozimwa. Kiwango cha kuyeyuka kinatofautiana kati ya nyuzi joto 23 hadi 28 darandi Celsius (73 hadi 82 nyuzi Fahrenheit). Mafuta ya kernel ya mti wa mikoko ni tajiri katika asidi laurik na yanatumika sana katika utengenezaji wa vyakula, vipodozi, na utengenezaji wa sabuni.', '2026-02-11 17:21:40', '2026-02-11 17:21:40'),
(20, 'prod-palm-kernel-olein', 'Olein ya Korodani la Miti', 'Oleini ya kinifu ya mafuta ya shina la mpera iliyochemshwa vizuri, sehemu ya kioevu inayopatikana kutoka kwa kugawanyika kwa mafuta ya shina la mpera, inayothaminiwa kwa uwazi wake bora, kiwango cha mvua cha chini, na matumizi ya kisekta katika sekta za chakula, huduma binafsi, na viwanda vya oleokemikali.', 'Bio Green Wax inatoa palm kernel olein (PKOo) wa ubora wa juu, sehemu ya kioevu inayozalishwa kupitia ugawaji wa kudhibitiwa wa mafuta ya kernel ya mzeituni wa palamu yaliyochakatwa. Wakati mafuta ya kernel ya palamu yanahooa chini ya masharti maalum, huzitenga kuwa sehemu ngumu (palm kernel stearin) na sehemu ya kioevu (palm kernel olein). Olein inayopatikana ni mafuta safi, rangi nyepesi, yenye pointi ya kuyeyuka ya chini na rahisi kumimina.\n\nPalm kernel olein ni tajiri katika asidi lauric (C12) na midadi ya mafuta ya kati ya capric/caprylic, yanayoiwezesha kuwa na mwonekano safi, kupenya kwa haraka, na hisia nyepesi isiyokuwa na mafuta mengi. Sifa hizi hufanya iwe ya kusudi sana katika tasnia ya vyakula kama mafuta ya kupikia, kati ya kukaanga, na kiungo katika cream zisizo na maziwa, barafu, na mchanganyiko wa maziwa yaliyojaa.\n\nKatika sekta ya huduma za kibinafsi na cosmetiki, palm kernel olein inatumika sana kama mafuta msingi katika lotions, creams, shampoos, na sabuni za mto, kutokana na mali zake nzuri za kuleta unyevu na ufanisi kwa ngozi. Pia, inatumikia kama nyenzo muhimu katika utengenezaji wa oleochemicals, ikitoa asidi za mafuta, methyl esters, na surfactants zinazotumika katika sabuni na bidhaa za kusafisha.\n\nBio Green Wax inapata palm kernel olein kutoka kwa minara ya usambazaji iliyoidhinishwa na RSPO, kuhakikisha uwazi kamili na uendeshaji sambamba na ahadi za mafuta ya palamu endelevu. Bidhaa inapatikana kwa fomu ya refined, bleached, na deodorised (RBD), ikikidhi viwango vigumu vya ubora vya kimataifa.', '2026-02-11 17:46:24', '2026-02-11 17:46:24'),
(21, 'prod-palm-kernel-stearin', 'Palm Kernel Stearin', 'Stearin ya ubora wa juu ya mafuta ya mbegu za nazi, sehemu imara inayopatikana kutokana na kugawanywa kwa mafuta ya nazi, inayothaminiwa kwa mchanganyiko wake wa kuyeyuka haraka na ugumu mzuri katika maelekezo ya kutengeneza pipi, vipodozi, na matumizi ya oleochemicals.', 'Bio Green Wax hutoa stearin ya kokwa ya kori (PKS) ya daraja la juu, sehemu ya fuwele imara inayotengenezwa kwa urefushaji wa kudhibitiwa wa mafuta ya kori safi. Wakati wa urefushaji, mafuta ya kori huogezwa kuwa sehemu mbili: oleini ya kori (sehemu ya kioevu) na stearin ya kori (sehemu ya fuwele). Stearin inayotengenezwa ni mafuta meupe hadi nyeupe machoni na tabia ya kuingia kwenye kuzama kwa haraka na muundo imara.\n\nStearin ya kori ni tajiri katika asidi lauric (C12) na asidi myristic (C14), inayoifanya kuwa na ugumu mzuri, kuundwa kwa kiolo mbishi kwa haraka, na mfungo safi wa kuyeyuka. Sifa hizi hunifanya kuwa kiungo bora kwa mbadala wa siagi ya kakao (CBS), mashine za kofia za chokoleti za mseto, vilivyojazwa tamu, na mafuta maalum yanapohitaji muundo wa kukwaruza na kukoroma.\n\nZaidi ya matumizi ya chakula, stearin ya kori hutumika kama malighafi muhimu katika sekta ya oleokemia kwa utengenezaji wa asidi za mafuta, pombe za mafuta, ndoo za sabuni, na surfactants. Katika huduma za kibinafsi na urembo, huchangia mwili na muundo kwa kremu, lotions, na fomula za fuwele.\n\nBio Green Wax inapata stearin ya kori kutoka kwa mnyororo wa usambazaji wa RSPO-certified, kuhakikisha ufuatiliaji kamili na ufanisi wa ahadi za mafuta ya kori endelevu. Bidhaa hii inapatikana kwa hali ya kusafishwa, kubadilishwa rangi, na kuepukwa harufu (RBD), ikitimize viwango vya ubora vya kimataifa kwa matumizi ya chakula na ya kiteknolojia.', '2026-02-11 17:20:45', '2026-02-11 17:20:45'),
(22, 'prod-palm-oil', 'Mafuta ya Mao {/*Note: If \"Palm Oil\" is a specific product or term, the translation is \"Mafuta ya Mao\" in Swahili. If \"Palm Oil\" refers to the actual oil derived from palm trees, then \"Mafuta ya Miti ya Mikoko\" could also be used, but \"Mafuta ya Mao\" is the most common.*/}', 'Mafuta ya nazi yenye asili endelevu na dista zake', 'Mafuta ya nazi yaliyochaguliwa kwa njia endelevu na majimaji ya nazi kwa ajili ya utengenezaji wa chakula, uzalishaji wa sabuni na sabuni za kufulia. Chaguo zilizothibitishwa na RSPO zinapatikana.', '2026-02-05 21:50:40', '2026-02-11 17:28:39'),
(23, 'prod-palm-shortenings', 'Palm Shortenings (kiwango cha kuyeyuka cha juu)', 'Mafuta ya kupunguza mafuta ya mikoko yenye kuyeyuka kwa joto la juu (46–52 °C) ni mafuta maalum ya machakula na kukaanga yanayotengenezwa kutoka kwa mafuta ya mikoko yaliyogawanyika, yaliyoundwa kutoa muundo imara, harufu safi, na ustahimilivu bora wa joto katika matumizi makali ya viwandani.', 'Majani ya mafuta ya kupikia ya palm yenye harufu ya kuyeyuka kwa kiwango cha 46–52 °C yanatengenezwa kutoka palm stearin na mid‑fractions ili kutoa kiwango cha juu cha mafuta thabiti, muundo imara, na mtandao wa kristali thabiti kwenye hali ya hewa ya kawaida na juu. Kiwango hiki cha kuyeyuka kwa juu huleta upinzani bora wa joto, utulivu wa oksidi, na kupunguza mafuta kujinawa, na kufanya zifae kwa hali ya joto ya kitropiki na viunzi vya usindikaji vya joto kali.\n​\n\nKatika matumizi ya mikate, majani haya ya mafuta huwapa hewa nzuri, uchanganyaji wa tabaka, na kukunja, kusaidia uundaji wa mizizi ya mali, pastry za puff, crackers za cream, biskuti, na kuoka huku yakihifadhi umbo na msisimko hata katika hali ya joto. Pia zinatumika kama mafuta kwa kukaanga yenye nguvu, mafuta ya dough, na kama mbadala wa mafuta ya wanyama kwenye bidhaa za nyama, ambapo muundo wao thabiti, utulivu wa emulsion, na profile isiyo na trans, isiyohydrogenated, husaidia kufanikisha muundo wa kila mara, kuachilia harufu safi, na michanganyiko yenye lebo rafiki.', '2026-02-11 17:27:54', '2026-02-11 17:27:54'),
(24, 'prod-palm-stearic-acid', 'Asidi ya Stearik ya Kidole', 'Asidi ya stearik ya mfano wa palm isetaha mafuta yenye usira kutoka kwa mafuta ya palm, inayotumika katika vipodozi, mishumaa, na utengenezaji wa mpira.', 'Asidi ya palm stearic ni aina ya asidi ya mafuta inayotokana na mafuta ya mtende, inayopatikana kwa njia ya kutenganisha na kuunda kativu vya mafuta. Ni asidi ya mafuta iliyosafishwa inayojulikana kwa uimara wake na umbo thabiti wakati wa joto la chumba. Asidi ya palm stearic ina muonekano wa waxy unaoanzia kwenye mweupe hadi njano kidogo. Ina kiashirio cha kuyeyuka kati ya digrii 55-70 Celsius (131-158 Fahrenheit), ambacho kinampa uwezo wa kuingizwa kwa urahisi kwenye viraka mbalimbali vya mapambo, mishumaa, na bidhaa za mpira.', '2026-02-11 17:39:37', '2026-02-11 17:39:37'),
(25, 'prod-palm-stearin', 'Palm Stearin', 'Palm stearin ni sehemu thabiti ya mafuta ya nazi, inayotumika sana katika utengenezaji wa vyakula, uzalishaji wa mishumaa, na kutengeneza sabuni.', 'Palm stearin ni sehemu imara ya mafuta ya leo yanayopatikana kupitia mchakato wa kugawanya, inajulikana kwa kiwango chake kikubwa cha asidi ya mafuta yaliyojaa. Ni mafuta imara yanapokewa na joto la chumbani yana rangi nyeupe ya kremu hadi manjano hafifu na muundo laini, wa wax. Palm stearin ina point ya kuyeyuka ya juu ikilinganishwa na mafuta ya leo. Inatumiwa sana katika tasnia ya vyakula kwa ajili ya kusimamia mafuta, kutengeneza margarine, na katika uzalishaji wa mishumaa na sabuni.', '2026-02-11 17:38:54', '2026-02-11 17:38:54'),
(26, 'prod-paraffin-wax', 'Peti la Paraffin lililomalizika kikamilifu (50-68°C)', 'Bio Green Wax Paraffin Iliyotengenezwa Kikamilifu (50-68°C)—daraja la chakula/pharma, mafuta <0.5%, ugumu bora. Kamili kwa mishumaa, cosmetics, ufungaji, na matumizi maalum ya viwandani.', 'Bio Green Wax\'s Fully Refined Paraffin Waxes (50-68°C melting points) zina sifa za mafuta ya chini sana (<0.5%), ugumu wa kipekee, na harufu/rangi ya neutral. Zinapatikana katika daraja za mishumaa (52/54°C, 56/58°C), daraja za chupa (50/52°C), na daraja za ubao wa high-melt (64/66°C). Yanafaa kwa mishumaa ya hali ya juu, vipodozi, kingo za kufunga chakula, na molding ya usahihi inayohitaji usafi wa hali ya juu na ufanisi wa hali ya juu.', '2026-02-06 03:55:16', '2026-02-11 17:43:32'),
(27, 'prod-pf56-synthetic-wax', 'Kondoo wa Fischer-Tropsch (FT)', 'Paraffini ya Fischer‑Tropsch (FT) ni waxi wa synthetic wa kiwango cha juu cha usafi unaozalishwa kutoka kwa syngas, ukitoa kiwango cha juu cha kuyeyuka, mchanganyiko mdogo wa viscousity, na ugumu mzuri kwa matumizi yanayohitaji katika plastiki, rangi za kinga, ink, mafuta ya kuchukua maisha, na marekebisho ya bitumen', 'FT wax hutengenezwa kupitia synthesis ya Fischer‑Tropsch, ikitoa wax nyeupe ya maji, safi sana ikiwa na usambazaji wa mlolongo wa kaboni wa pingu, pia ina kiwango cha chini sana cha mafuta, na utulivu bora wa joto. Inachanganya kiwango cha juu cha kupanda kwa joto pamoja na ugumu mdogo wa kuyeyuka na ugumu mkubwa, kinachotoa upinzani wa kiwango cha juu wa kubomoka, udhibiti wa mng\'aro, athari za kupaka matte, na lubrication katika manyanaga tofauti.\n\nKatika utengenezaji wa plastiki na PVC/CPVC, FT wax hutumika kama lubricant bora wa ndani na wa nje na msaada wa usindikaji, kupunguza viscosity ya kuyeyuka, kuboresha mtiririko, na kuongeza uhuru wa mold na utulivu wa vipimo. Inatumika sana katika clingi za hot-melt na za msukumo wa shinikizo, ink za uchapishaji, na rangi za viwandani ili kuongeza ugumu, upinzani wa kuondoa na kubomoka, upinzani wa kuzuia kuchomeka, na kupinga kusababisha, huku ikidumisha viscosity. Matumizi muhimu zaidi ni pamoja na mabadiliko ya bitumen na barabara ya asf alter, masterbatch na mchanganyiko wa polima, usindikaji wa mpira, polish, nguo, na hata vianzio vya mapambo, ambapo FT wax huleta crystallinity iliyodhibitiwa, kuboresha upinzani wa kuvaa na kupoinyana, na hisia laini ya kugusa.', '2026-02-06 04:17:22', '2026-02-11 17:44:29'),
(28, 'prod-pfad', 'PFAD (Palm Fatty Acid Distillate)', 'PFAD ni bidhaa ndogo ya usafishaji wa mafuta ya nazi, inayotumika katika utengenezaji wa sabuni, chakula cha wanyama, na uzalishaji wa biofuel.', 'Palm Fatty Acid Distillate (PFAD) ni bidhaa inayopatikana kama sehemu ya mchakato wa kusafisha mafuta ya m[palme. Inapata kwa kupitia distillation ya mafuta mbichi ya m[palme ili kuondoa mivunjiko na kufikia kiwango cha hali ya juu cha usafi. PFAD ni kioevu cha rangi ya manjano na kahawia chenye harufu maalum. Kina mchanganyiko wa asidi za mafuta zilizosawiana na zisizo sawa, kwa kuwa asidi za mafuta zinazotawala ni lauric acid, myristic acid, na palmitic acid. PFAD inatumika katika utengenezaji wa sabuni, kulisha wanyama, na utengenezaji wa biofuel.', '2026-02-11 17:26:39', '2026-02-11 17:26:39'),
(29, 'prod-pkfad', 'Distilati ya Asidi ya Mafuta ya Mafuta ya Kokosho (PKFAD)', 'PKFAD ni bidhaa inayotokana na kusafisha mafuta ya-kilaini ya nazi, inayotajwa kwa utajiri wa asidi lauric, inayotumika katika viwanda vya sabuni na oleokemikali.', 'Palm Kernel Fatty Acid Distillate (PKFAD) ni kiambato kinachopatikana wakati wa kusafisha mafuta ya karanji. Kina utajiri wa mafuta ya mafuta, ikiwa ni pamoja na lauric acid, na kufanya kuwa na thamani kwa matumizi fulani ya viwanda. PKFAD hutumika katika matumizi mbalimbali ya viwanda, ikiwa ni pamoja na utengenezaji wa sabuni, uzalishaji wa biofuel, na kama malighafi katika sekta ya oleochemicals.', '2026-02-11 17:40:20', '2026-02-11 17:40:20'),
(30, 'prod-polyethylene-wax', 'Wax ya Polyethylene (PE wax)', 'ni polyethylene ya molekuli yenye uzito wa chini inayotumika kama mafuta ya kiwango cha juu na msaada wa uchakataji katika plastiki, mipako, vinywaji, na vinyunyizi, kuboresha mtiririko, kupunguza msuguano wa uso, na kuzuia mikwaruzo.', 'Wax polyethylene ni wax synthetic wa kinyesi kilichogawanyika vizuri, chenye kiwango cha kuyeyuka cha juu, na viskositi kidogo, uimara mkubwa wa halijoto, na ufanisi mkubwa na polima za kawaida kama PVC, PE, PP, na EVA. Inatoa mafuta ndani na nje, inapunguza viskositi ya kuyeyuka na kusugua, huongeza uhuru wa mold, na kutoa uso laini, wenye mng’aro, na wa kuzuia mikunjo.\n​\n\nMaombi muhimu ni pamoja na usindikaji wa plastiki na masterbatch, ambapo PE wax huimarisha ufanisi wa extrusion na molding ya sindano, huzuia kujikusanya kwa die, na huimarisha usambazaji wa vionjo na filler. Pia inatumika katika waya wa kuyeyuka kwa joto na mastiha za mshikaji zinazohisi shinikizo, ink na poda za kubandika ili kudhibiti viskositi ya kuyeyuka, kuimarisha umoja na uimara, na kuboresha nyakati za kufungua na kusimama. Matumizi mengine yanahusisha bitumen na rangi za alama za barabara, mchanganyiko wa mbao na plastiki, mchanganyiko wa tairidi, mchanganyiko wa waya waendidaji, na bidhaa zilizoweko za wax kama vile polishing na crayons, ambapo huongeza kiwango cha kuyeyuka, ugumu, na upinzani wa maji.', '2026-02-06 04:02:03', '2026-02-11 17:42:39'),
(31, 'prod-rapeseed-oil', 'Mafuta ya Mafuta ya Rapeseed', 'Mafuta ya alizeti yaliyoshinikwa baridi na kuandaliwa kutoka kwa mashamba ya Uingereza', 'Mafuta ya alizeti yaliyowekwa kwa baridi na kuponywa kutoka kwa shamba za UK. Inafaa kwa kupika, kukaanga, na kuandaa saladi. Ina mafuta finyu yaliyozidi wanga na omega-3 kwa wingi.', '2026-02-05 21:55:00', '2026-02-11 17:34:20'),
(32, 'prod-rapeseed-wax', 'Paraffini ya Mafuta ya Rapeseed', 'Karatasi ya mafuta ya rapeseed ni mafuta ya mimea ya asili inayotumika kama mbadala wa kiridhikali katika utengenezaji wa mishumaa na vipodozi.', 'SihA ya alizeti ni wax asili wa mboga unaotokana na mafuta ya mmea wa alizeti, mara nyingi hutumika kama mbadala wa kirika wa mazingira kwa ajili ya kutengeneza mishumaa na matumizi mengine. Inatoa muwasho safi na wa polepole, pamoja na uwezo mzuri wa kubeba harufu. SihA ya alizeti mara nyingi hutumika katika utengenezaji wa mishumaa na katika uundaji wa vipodozi vya asili kama vile lip balm, lotion, na krimu, vinavyotoa mali ya kuimarisha unyevu.', '2026-02-11 17:24:28', '2026-02-11 17:24:28'),
(33, 'prod-soap-noodles', 'Noodle za Sabuni', 'Noodle za sabuni ni malighali msingi kwa ajili ya kutengeneza sabuni, zinazozalishwa kwa saponification ya mafuta na mafuta ya mimea.', 'Noodles za sabuni, zinazojulikana pia kama granules za sabuni, ni mojawapo ya nyenzo za msingi zinazotumiwa katika utengenezaji wa sabuni. Huzalishwa kwa kusindika mafuta ya mboga na mafuta kwa kutumia kiasa ya sodium hydroxide (lye) kupitia mchakato wa saponification. Noodles za sabuni kwa kawaida ni vipande au mavuno meupe au meusi ya rangi ya nyepesi au ya rangi ya kawaida wenye harufu nyepesi na ya wastani. Haziwezi kuwa na uchafu wowote na zina kiwango kikubwa cha asidi za mafuta zinazochangia kazi zao za kusafisha na kueneza.', '2026-02-11 17:41:06', '2026-02-11 17:41:06'),
(34, 'prod-soy-wax', 'Mafuta ya Shaba', 'Soy wax ni waxi wa mboga unaoweza kurejeshwa upya kutoka katika mafuta ya soya, maarufu kwa utengenezaji wa mishumaa rafiki wa mazingira.', 'Soy wax ni aina ya mafuta ya mboga inayotokana na mafuta ya soya. Ni chaguo maarufu kwa ajili ya mbadala wa paraffin wax ya jadi, ambayo inatokana na mafuta ya petroli. Soy wax inachukuliwa kuwa chaguo lisiloweza kuisha, linaloibika kwa urahisi na rafiki kwa mazingira kwa ajili ya kutengeneza mishumaa. Inatengenezwa kwa kuhydrogenate mafuta ya soya, kuibadilisha kuwa umbo thabiti linalofaa kwa mishumaa. Mara nyingi inakuja kwa umbo la flakes, ambalo ni rahisi kupimia na kuyeyusha.', '2026-02-11 17:17:43', '2026-02-11 17:17:43'),
(35, 'prod-soybean-oil', 'Mafuta ya kunde la soya', 'Mafuta bora ya soya bean kwa matumizi ya viwandani na jikoni', 'Mafuta ya soya ni mafuta ya mboga ya matumizi mbalimbali yanayopatikana kutoka kwa maharagwe ya soya, yanayotumika sana kwa kukaanga, kuoka, na mapishi ya saladi kutokana na ladha yake isiyo na rangi na kiwango chake cha juu cha wakati wa kukaanga. \nNi tajiri kwa mafuta yenye miondoko mingi, ikiwa ni pamoja na asidi ya mafuta omega‑3 na omega‑6, na hutoa vitamin K na vitamin E. \nNi kamilifu kwa kukaanga kwa kina, uzalishaji wa margarine, na matumizi ya viwanda vya vyakula. Imekuwa ikiwa imesafishwa na kupuliziwa ili kufikia viwango vya juu vya ubora.', '2026-02-05 21:50:40', '2026-02-11 17:29:19'),
(36, 'prod-sunflower-oil', 'Sii mafuta ya alizeti', 'Mafuta ya alizeti yaliyotengenezwa kwa ubora wa juu kwa kupikia na usindikaji wa chakula', 'Mafuta yetu ya alizeti ya kupendelewa mafuta ya juu ni kamilifu kwa Kupikia, kukaanga, na matumizi ya usindikaji wa vyakula. Yametoka kwa mbegu za alizeti za ubora wa hali ya juu na yamechapwa kwa viwango vya juu kabisa.', '2026-02-05 21:43:33', '2026-02-11 17:22:25');
INSERT INTO `products_th` (`id`, `master_id`, `name`, `description`, `full_description`, `created_at`, `updated_at`) VALUES
(1, 'bdf424df-f9b0-4a79-84d6-f6ed1eb1e84f', 'ปาล์มออยล์นีล', 'Palm olein คือ เศษเหลวของน้ำมันปาล์มที่ผ่านการกลั่น ซึ่งได้รับความนิยมในฐานะน้ำมันทอดและปรุงอาหารที่เสถียร ให้รสชาติเป็นกลาง มีอายุการทอดยาวนาน และให้เนื้อสัมผัสกรุบกรอบสำหรับของกินเล่น อาหารจานด่วน และการใช้งานในครัวเรือน', 'Palm olein ผลิตโดยการแยกชั้นน้ำมันปาล์มที่ผ่านการกลั่น ขาว และดีโอโดเรไลซ์ (RBD) เพื่อให้ได้ของเหลวใสที่อุดมไปด้วยกรดโอเลิกและกรดปาล์มิติ ซึ่งให้สมดุลของกรดไขมันพร้อมความเสถียรทางออกซิเดชันตามธรรมชาติ คุณสมบัติที่จุดควันสูง ทนต่อการออกซิเดชันและการเกิดพอลิเมอร์ รวมถึงแนวโน้มต่ำในการเกิดรสชาติไม่พึงประสงค์ ช่วยให้สามารถทอดซ้ำได้หลายรอบ พร้อมลดการสลายตัวของน้ำมัน ฟองน้อยลง และยืดอายุการเก็บรักษาของผลิตภัณฑ์สำเร็จรูป\n\nในการใช้งานด้านอาหาร Palm olein ถูกใช้กันอย่างแพร่หลายเป็นน้ำมันสำหรับการทอดลึก เช่น อาหารว่าง มันฝรั่งทอด ไก่ทอด บะหมี่กึ่งสำเร็จรูป และอาหารแช่แข็งทอดล่วงหน้า รวมถึงเป็นน้ำมันประกอบชั้นในครัวเรือนทั่วไปในตลาดเขตร้อนจำนวนมาก นอกจากนี้ ยังใช้เป็นน้ำมันฐานในส่วนผสมกับน้ำมันถั่วเหลือง น้ำมันดอกทานตะวัน หรือ น้ำมันพืชอื่น ๆ เพื่อให้ได้โปรไฟล์ด้านโภชนาการและฟังก์ชันเฉพาะบุคคล และยังใช้ในมาร์การีน ไขมันเบเกอรี่ และระบบทอดในงานบริการอาหาร ซึ่งความเสถียรและรสชาติที่สะอาดถือเป็นสิ่งสำคัญ', '2026-02-11 17:15:38', '2026-02-11 17:15:38'),
(2, 'prod-beeswax', 'ขี้ผึ้ง', 'น้ำผึ้งธรรมชาติบริสุทธิ์สำหรับเครื่องสำอางและการทำเทียน', 'เทียนผึ้งธรรมชาติบริสุทธิ์จากผู้เลี้ยงผึ้งที่มีจริยธรรม เหมาะสำหรับเครื่องสำอาง การทำเทียน และการใช้งานด้านอาหาร มีให้เลือกหลายเกรด', '2026-02-11 17:30:03', '2026-02-11 17:30:03'),
(3, 'prod-bw101-palm-wax', 'เทียนพิมพ์', 'เทียนพิมพ์ Premium 100% จากขี้ผึ้งปาล์ม มีสีเหลืองครีม เหมาะสำหรับการทำเทียน รับรองมาตรฐาน RSPO SG (Segregated) / MB (Mass balance)', 'ขี้ผึ้งปาล์มพรีเมียม 100% มีสีเหลืองครีมที่สวยงาม ได้รับการรับรอง RSPO MB เพื่อความยั่งยืน เหมาะสำหรับการทำเทียน การหล่อ และเทียนในภาชนะ', '2026-02-11 17:45:42', '2026-02-11 17:45:42'),
(4, 'prod-bw105-palm-wax', 'น้ำมันปาล์มเคลือบ (จุดหลอมเหลวต่ำ)', 'Palm Shortening คือไขมันชนิดกึ่งแข็งที่ไม่ผ่านการไฮโดรจี้น ซึ่งได้จากน้ำมันปาล์มที่ผ่านการแยกชั้น ให้ความเสถียรภาพที่โดดเด่นและรสชาติที่เป็นกลาง', 'Palm Shortening คือไขมันกึ่งของแข็งที่ไม่ผ่านการไฮโดรจ์เนทีด มาจากน้ำมันปาล์มที่ผ่านการแยกส่วน ให้ความเสถียรภาพที่เหนือกว่าและรสชาติที่เป็นกลาง\nเหมาะสำหรับการทำเบเกอรี่—สร้างขนมปังแป้งกรอบ เค้กที่นุ่มและอาหารทอดกรอบที่มีจุดเกิดควันสูง\nเป็นทางเลือกที่คุ้มค่าและทนต่อการออกซิเดชันเมื่อเทียบกับเนยหรือตับในงานอบแบบอุตสาหกรรม', '2026-02-11 17:31:28', '2026-02-11 17:31:28'),
(5, 'prod-bw10510-blended-wax', 'เทียนผสมพาล์ม-พาราฟินสำหรับเทียนใส่ขวด', 'ส่วนผสมเทียนในแก้วพร้อมใช้ Low MP: Palm-Paraffin-Microcrystalline พร้อม Polyboost™, Vybar®, ตัวกันยูวี—เพียงเติมสีและน้ำหอมเพื่อการยึดเกาะกับแก้วที่ยอดเยี่ยมและการปล่อยแสงสูงสุด', 'Biogreen Wax\'s Low Melting Point Jar Candle Blend (48-50°C) และ (50-52°C)—สูตร Palm-Paraffin-Microcrystalline ที่ได้รับการปรับแต่งให้เหมาะสมสำหรับภาชนะแก้ว พร้อมใช้งาน: เพียงเติมสีและกลิ่นหอมเท่านั้น คุณสมบัติของ Polyboost/Vybar เพื่อความทึบแสงและการเกาะติด, ตัวตรึงแสง UV/stabilizer/สารต้านอนุมูลอิสระ เพื่อความคงทนในระยะยาว รวมถึงสารคงกลิ่นหอมที่มอบพลังการปล่อยแสงร้อน/เย็นที่ยอดเยี่ยม การเผาไหม้โดยไม่มีรอยร้าว และการเก็บรักษาในภาชนะที่ยอดเยี่ยมสำหรับเทียนในภาชนะคุณภาพสูง', '2026-02-11 17:37:35', '2026-02-11 17:37:35'),
(6, 'prod-bw10555-blended-wax', 'ส่วนผสมเทียนวีแกนที่ทำจากถั่วเหลือง', 'เบลนด์เวแกน 95% ซอยพร้อมใช้จาก Bio Green Wax — สารสกัดจากพืชบริสุทธิ์ สำหรับเทียน Jar (48-52°C) และเทียน Pillar (56-62°C) เพียงเพิ่มสีและกลิ่นเท่านั้น', 'Bio Green Wax\'s 95% Soy Wax Vegan Blend (5% อาหารเสริมจากพืช) ให้การเผาที่สะอาดและเป็นธรรมชาติสำหรับภาชนะแก้วและเสาหลักอิสระ มีให้เลือกในจุดหลอมเหลวต่ำ (48-52°C) สำหรับภาชนะ และจุดหลอมเหลวสูง (56-62°C) สำหรับเสาหลัก พร้อมใช้งาน: เพียงแค่เติมสีและกลิ่นเพื่อความกระจัดกระจายที่ยอดเยี่ยมและผิวเรียบเนียน', '2026-02-11 17:32:16', '2026-02-11 17:32:16'),
(7, 'prod-bw10610-blended-wax', 'เทียนผสมพาล์ม-พาราฟินสำหรับเทียนเสา', 'เทียนเสาทรงพลังพร้อมใช้งานแบบ High MP Blends (56-58°C & 58-60°C): ปาล์ม-พาราฟิน-ไมโครคริสตัลไลน์ ผสม Polyboost™, Vybar®, ตัวทำให้คงทนต่อรังสี UV—เพียงแค่เติมสีและกลิ่น เพื่อประสิทธิภาพสูงสุดของเทียนเสา', 'Bio Green wax\'s High Melting Point Pillar Candle Blends (56-58°C & 58-60°C)—สูตรพาราฟินปาล์มไมโครคริสตัลสำหรับเทียนแท่งตั้งเองที่ออกแบบมาเป็นพิเศษสำหรับเทียนแท่งตั้งเอง พร้อมใช้งาน: เพียงเติมสีและน้ำหอม ปรับปรุงด้วย Polyboost/Vybar เพื่อการปล่อยตัวจากแม่พิมพ์และความทึบแสง, สาร stabilizer/สารต้านอนุมูลอิสระ UV เพื่อยืดอายุการเก็บรักษา, รวมถึงสารคงความหอมที่ให้การปล่อยกลิ่นร้อน/เย็นยอดเยี่ยม รูปทรงเทียนแท่งที่คงรูปทรงดีและการเผาไหม้ที่สะอาด', '2026-02-11 17:38:22', '2026-02-11 17:38:22'),
(8, 'prod-bw10655-blended-wax', 'ส่วนผสมของ Soy-Beeswax-Paraffin Wax', 'ส่วนผสมสำเร็จรูปจาก Bio Green Wax ประกอบด้วยถั่วเหลือง, ขี้ผึ้งผสมเทียนผง Paraffin—ให้กลิ่นหอมที่สุดสำหรับเทียน jar (48-52°C) และเทียน pillar (56-62°C) แค่เติมกลิ่นและสี', 'Bio Green Wax\'s Soy-Beeswax-Paraffin Blend ผสมผสานความเรียบเนียนตามธรรมชาติของถั่วเหลือง ความมั่นคงของขี้ผึ้งผึ้ง และพลังกลิ่นของพาราฟิน เพื่อประสิทธิภาพกลิ่นหอมหาที่ไม่เป็นรองใคร จุดหลอมเหลวต่ำ (48-52°C) เหมาะสำหรับภาชนะแก้ว; จุดหลอมเหลวสูง (56-62°C) เหมาะสำหรับเทียนแท่ง สูตรพร้อมใช้งาน—แค่เติมกลิ่นและสี เพื่อการปล่อยกลิ่นที่ยอดเยี่ยมทั้งร้อนและเย็น และการเสร็จสิ้นของเทียนที่ไม่มีตำหนิ', '2026-02-11 17:33:06', '2026-02-11 17:33:06'),
(9, 'prod-bw8307-blended-wax', 'การผสมเทียนจากน้ำมันมะพร้าวและน้ำมันเรพซีด', 'บลนด์มะพร้าว-คาโนลาจาก Bio Green Wax พร้อมใช้งาน—เนื้อครีมธรรมชาติเกรดสูงสำหรับเทียน Jar (48-52°C) & Pillar (56-62°C) เติมสีและกลิ่นเท่านั้น', 'Bio Green Wax\'s Coconut-Rapeseed Blend ผสมผสานเนื้อสัมผัสครีมมี่ของเทียนกะทิและการเผาไหม้เรียบง่ายของเทียนราพีส์เพื่อประสิทธิภาพของเทียนธรรมชาติที่ยอดเยี่ยม จุดหลอมเหลวต่ำ (48-52°C) เหมาะสำหรับเทียนบรรจุภัณฑ์; จุดหลอมเหลวสูง (56-62°C) สำหรับเทียนเสาสามารถนำออกไปใช้ได้เต็มที่—เพียงเพิ่มสีสันและกลิ่นหอมตามที่คุณเลือกเพื่อผลลัพธ์การเผาที่เป็นมืออาชีพและสะอาด', '2026-02-11 17:33:55', '2026-02-11 17:33:55'),
(10, 'prod-carnauba-wax', 'ขี้ผึ้งคาร์นูบา', 'ขี้ผึ้งคาร์นัวบาบารายางรถยนต์พรีเมียมจากบราซิลสำหรับเคลือบเงาและเคลือบผิว', 'ขี้ผึ้งคาร์นัวาบราซิลพรีเมียม ซึ่งรู้จักกันในชื่อ \"ราชินีแห่งขี้ผึ้ง\" เหมาะสำหรับการขัดรถ เครื่องสำอาง และเคลือบอาหาร จุดหลอมละลายตามธรรมชาติสูงที่สุด', '2026-02-11 17:30:41', '2026-02-11 17:30:41'),
(11, 'prod-castor-oil', 'น้ำมันโจโจบา', 'น้ำมันละหุ่งสกัดเย็นพรีเมียมที่ได้จากเมล็ด Ricinus communis ซึ่งใช้กันอย่างแพร่หลายในอุตสาหกรรมยา เครื่องสำอาง และการใช้งานในอุตสาหกรรม', 'Bio Green Wax จัดหา น้ำมันละหุ่งคุณภาพสูง ซึ่งเป็นน้ำมันพืชที่มีความหลากหลาย ได้จากการสกัดเมล็ดของต้นต้นละหุ่ง (Ricinus communis) ซึ่งเป็นที่รู้จักกันดีในด้านองค์ประกอบทางเคมีเฉพาะตัวที่อุดมไปด้วยกรดริซินโอลีอิค (ประมาณ 85–90%) น้ำมันละหุ่งมีความหนืด เงียบและให้ความชุ่มชื้นที่โดดเด่น ซึ่งทำให้มันเป็นวัตถุดิบที่มีคุณค่าในอุตสาหกรรมหลากหลายสาย\n\nน้ำมันละหุ่งของเราได้รับการคัดสรรและผ่านกระบวนการอย่างพิถีพิถัน เพื่อให้ได้มาตรฐานความบริสุทธิ์และความคงที่ในระดับสูง ทั้งในรุ่น Cold-Pressed (Virgin) และรุ่นฟอกขาว เหมาะสำหรับการใช้งานในด้านยา อาหาร เครื่องสำอาง และอุตสาหกรรม น้ำมันนี้มีความเสถียรและสามารถละลายในแอลกอฮอล์ได้ดี ซึ่งเป็นลักษณะที่แตกต่างจากน้ำมันพืชอื่น ๆ ทำให้เป็นส่วนประกอบที่นิยมใช้ในสูตรที่ต้องการประสิทธิภาพที่ยอดเยี่ยม\n\nน้ำมันละหุ่งเป็นสารที่สามารถย่อยสลายตามธรรมชาติได้เอง และมาจากทรัพยากรที่สามารถนำกลับมาใช้ใหม่ได้ ซึ่งสอดคล้องกับความมุ่งมั่นของ Bio Green Wax ในการคัดสรรวัตถุดิบที่ยั่งยืนและเป็นมิตรกับสิ่งแวดล้อม', '2026-02-11 17:16:34', '2026-02-11 17:16:34'),
(12, 'prod-coconut-oil', 'น้ำมันมะพร้าว', 'น้ำมันมะพร้าวบริสุทธิ์และผ่านการกลั่นสำหรับการใช้งานทางอาหารและเครื่องสำอาง', 'น้ำมันมะพร้าวบริสุทธิ์และผ่านการกลั่นคุณภาพสูง เหมาะสำหรับการทำอาหาร การอบ และการใช้งานในเครื่องสำอาง มีให้เลือกหลายเกรดเพื่อความตรงกับความต้องการของคุณ', '2026-02-09 02:59:24', '2026-02-11 17:17:13'),
(13, 'prod-coconut-wax', 'เทียนไขจากมะพร้าว', 'เทียนไขมะพร้าวเป็นเทียนไขธรรมชาติที่ได้จากน้ำมันมะพร้าว ซึ่งเป็นที่นิยมสำหรับการเผาไหม้ที่สะอาดและใช้งานที่เป็นมิตรกับสิ่งแวดล้อม', 'เทียนไขจากมะพร้าวคือเทียนไขธรรมชาติที่ได้จากน้ำมันมะพร้าว ซึ่งเป็นที่รู้จักกันในเรื่องการเผาไหม้อย่างสะอาดและช้าระหว่างการทำเทียน เทียนไขจากมะพร้าวมักถูกพิจารณาว่าเป็นทางเลือกที่ยั่งยืนสำหรับเทียนไขชนิดอื่นๆ เทียนไขจากมะพร้าวได้รับความนิยมในด้านคุณสมบัติเป็นมิตรต่อสิ่งแวดล้อมและความสามารถในการเก็บกลิ่นได้ดี เป็นทรัพยากรธรรมชาติและสามารถต่ออายุได้ ซึ่งให้การเผาไหม้อย่างสะอาดและช้ากว่าเดิม ทำให้เทียนมีอายุการใช้งานนานขึ้นและมีประสิทธิภาพมากขึ้น', '2026-02-11 17:26:06', '2026-02-11 17:26:06'),
(14, 'prod-fr5456-paraffin-wax', 'วาสลีนซึมเข้าเงานำเข้าหนักเบา (50-68°C)', 'Bio Green Wax Paraffin กึ่งบริสุทธิ์ (50-68°C)—ต้นทุนคุ้มค่า มีปริมาณน้ำมัน 1-5% สำหรับเทียนพิมพ์ ยาง สิ่งทอ และการใช้งานในอุตสาหกรรมที่มีปริมาณมาก', 'เทียนพาราฟิน Semi Refined จาก Bio Green Wax (50-68°C) ให้ประสิทธิภาพที่คุ้มค่า พร้อมควบคุมปริมาณน้ำมัน (1-5%) สำหรับความแข็งที่ยืดหยุ่น ได้มาตรฐานเกรด: 52/54°C (เทียน), 56/58°C (เสาเทียน), 60/62°C (อุตสาหกรรม) เหมาะสำหรับการผลิตเทียนที่ต้องการความคุ้มค่า การช่วยในการประมวลผลยาง การปรับแต่งสิ่งทอ และเคลือบบรรจุภัณฑ์จำนวนมาก ที่ซึ่งสมดุลระหว่างประสิทธิภาพและราคาเป็นสิ่งสำคัญที่สุด', '2026-02-11 17:23:59', '2026-02-11 17:23:59'),
(15, 'prod-glycerine', 'กลีเซอรีน', 'กลีเซอรีนเป็นของเหลวใส ไม่มีสี ไม่มีกลิ่น มีความข้นหนืด ซึ่งใช้กันอย่างแพร่หลายในอุตสาหกรรมยา เครื่องสำอาง และอาหาร', 'กลีเซอรีน หรือที่รู้จักกันในชื่อกลีเซอริล หรือกลีเซอรีน เป็นของเหลวใส ไม่มีสี ไม่มีกลิ่น และมีลักษณะข้นเหนียว รสหวาน เป็นของเหลวใสคล้ายไซรัป ซึ่งโดยทั่วไปจะไม่มีสี แต่บางครั้งอาจมีประกายเหลืองเล็กน้อย กลีเซอรีนมีความหนืดสูง ซึ่งหมายความว่ามันไหลช้าและมีความหนา ค่วามเหนียวคล้ายไซรัป ซึ่งช่วยให้มันสามารถกักเก็บความชุ่มชื้นได้อย่างดี กลีเซอรีนใช้กันอย่างแพร่หลายในวงการเภสัชกรรม เครื่องสำอาง การแปรรูปอาหาร และการใช้งานในอุตสาหกรรมต่าง ๆ', '2026-02-11 17:20:00', '2026-02-11 17:20:00'),
(16, 'prod-hydrogenated-castor-oil', 'น้ำมันละหุ่งไฮโดรจิเนต', 'น้ำมันปิโตรเคมีจากถั่วเหลืองเป็นสารสกัดแข็งที่เป็นวากซ์จากน้ำมันถั่วเหลือง ซึ่งใช้ในเครื่องสำอาง ยา และอุตสาหกรรม', 'น้ำมันละหุ่งไฮโดรเจน (Hydrogenated castor oil) ซึ่งรู้จักกันในชื่อ ขี้ผึ้งละหุ่ง หรือเกล็ดขี้ผึ้งละหุ่ง เป็นผลผลิตจากน้ำมันละหุ่งที่ผ่านกระบวนการไฮโดรเจน ซึ่งเป็นการเติมไฮโดรเจนเข้าไปในโมเลกุลของน้ำมันละหุ่ง ทำให้กลายเป็นวัตถุแข็ง เนื้อขี้ผึ้ง ใช้ในผลิตภัณฑ์เครื่องสำอางและดูแลผิวพรรณ เช่น ลิปสติก ครีม และโลชั่น เป็นสารให้ความชุ่มชื้นและความเนียนนุ่มแก่ผิว นอกจากนี้ยังทำหน้าที่เป็นสารเชื่อมในสูตรเครื่องสำอาง ช่วยให้ส่วนผสมติดกันและเกาะติดผิวได้ดีขึ้น', '2026-02-11 17:25:23', '2026-02-11 17:25:23'),
(17, 'prod-microcrystalline-wax', 'เทียนขี้ผึ้งไมโครคริสตัล', 'ขี้ผึ้งไมโครคริสตัลเหลวสำหรับเครื่องสำอางและกาว', 'เทียนไมโครครystallineแบบยืดหยุ่น เหมาะสำหรับเครื่องสำอาง กาวร้อนละลาย และเคลือบเฉพาะทาง คุณสมบัติความยืดหยุ่นและความสามารถในการเกาะติดที่ยอดเยี่ยม', '2026-02-11 17:23:14', '2026-02-11 17:23:14'),
(18, 'prod-olive-oil', 'น้ำมันมะกอก', 'น้ำมันมะกอกบริสุทธิ์คุณภาพพรีเมียม กดเย็นจากมะกอกเมดิเตอร์เรเนียนคัดสรรสำหรับงานทำอาหาร เครื่องสำอาง และอุตสาหกรรม', 'น้ำมันมะกอกบริสุทธิ์พรีเมียมของเราผ่านการสกัดเย็นจากมะกอกเมดิเตอร์เรเนียนที่คัดสรรอย่างพิถีพิถัน มอบคุณภาพที่ยอดเยี่ยมและรสชาติที่เข้มข้น ใช้กันอย่างแพร่หลายในงานปรุงอาหาร เครื่องสำอาง ยา และผลิตภัณฑ์ดูแลส่วนบุคคล น้ำมันมะกอกได้รับความนิยมเพราะประโยชน์ต่อสุขภาพ คุณสมบัติต้านอนุมูลอิสระ และการใช้งานที่หลากหลาย Bio Green Wax คัดสรรน้ำมันมะกอกที่ได้มาตรฐานคุณภาพระดับสากลอย่างเข้มงวด เพื่อความบริสุทธิ์และประสิทธิภาพที่คงเส้นคงวาทุกการใช้งาน', '2026-02-11 17:42:02', '2026-02-11 17:42:02'),
(19, 'prod-palm-kernel-oil', 'น้ำมันปาล์มเคอร์นัล', 'น้ำมันเมล็ดปาล์มสกัดจากเมล็ดของผลปาล์มน้ำมัน ใช้ในผลิตภัณฑ์อาหาร เครื่องสำอาง และอุตสาหกรรมต่าง ๆ', 'น้ำมันกะลามะพร้าวสกัดจากแกนของผลปาล์มน้ำมันและมีลักษณะทางกายภาพที่แตกต่างชัดเจน โดยทั่วไปจะเป็นของแข็งสีเหลืองอ่อนถึงขาวที่อุณหภูมิห้อง แต่เมื่อถูกให้ความร้อนจะละลายกลายเป็นของเหลวใสสีเหลือง เมื่อจุดหลอมละลายอยู่ในช่วง 23 ถึง 28 องศาเซลเซียส (73 ถึง 82 องศาฟาเรนไฮต์) น้ำมันกะลามะพร้าวเป็นแหล่งของกรดลอริกและถูกนำไปใช้ในอุตสาหกรรมอาหาร เครื่องสำอาง และการผลิตสบู่เป็นอย่างแพร่หลาย', '2026-02-11 17:21:53', '2026-02-11 17:21:53'),
(20, 'prod-palm-kernel-olein', 'น้ำมันปาล์มเคอร์นอลีน', 'โอเลอินฟื้นฟูจากเมล็ดปาล์มเกรดพรีเมียม เป็นส่วนของเหลวที่ได้จากการแยกส่วนของน้ำมันเมล็ดปาล์ม ซึ่งขึ้นชื่อในเรื่องความใสที่ยอดเยี่ยม จุดเม็ดเมฆต่ำ และความสามารถในการใช้งานที่หลากหลายในอุตสาหกรรมอาหาร ผลิตภัณฑ์ดูแลส่วนบุคคล และอุตสาหกรรมโอเลโอเคมี', 'Bio Green Wax จัดจำหน่ายน้ำมันปาล์มเคอร์เนลออยล์ (PKOo) คุณภาพสูง ซึ่งเป็นส่วนของเหลวที่ผลิตจากการแยกส่วนควบคุมของน้ำมันปาล์มดิบ เมื่อทำน้ำมันปาล์มเคอร์เนลเย็นภายใต้เงื่อนไขที่แม่นยำ มันจะแยกออกเป็นส่วนแข็ง (palm kernel stearin) และส่วนของเหลว (palm kernel olein) น้ำมันออยย์นี้มีลักษณะใส สีอ่อน มีจุดหลอมเหลวต่ำและสามารถเทเทง่ายอย่างยอดเยี่ยม\n\nน้ำมันปาล์มเคอร์เนลออยล์อุดมไปด้วยกรดลอริก (C12) และกรดไขมันสายกลางคาแคร์ริก/คาเพริก ซึ่งช่วยให้มีความใสเป็นประกาย การดูดซึมได้รวดเร็ว และให้ความรู้สึกเบา ไม่มันเยิ้ม ลักษณะเหล่านี้ทำให้เป็นที่นิยมอย่างมากในอุตสาหกรรมอาหาร เช่น น้ำมันประกอบอาหาร น้ำมันทอด และส่วนผสมในครีมเทียม ไม่มีนมหรือไอศกรีม และในสูตรนมเติมเต็ม\n\nในกลุ่มสินค้าเพื่อดูแลส่วนบุคคลและเครื่องสำอาง น้ำมันปาล์มเคอร์เนลออยล์ใช้กันอย่างแพร่หลายเป็นฐานน้ำมันในโลชั่น ครีม แชมพู และสบู่เหลว เพราะคุณสมบัติที่เป็นมอยเจอร์ไรเซอร์ดีเยี่ยมและเข้ากันได้ดีบนผิว นอกจากนี้ ยังเป็นวัตถุดิบหลักในกระบวนการผลิต oleochemical ให้กรดไขมัน เอสเทอร์มีทิล และสารทำความสะอาดซึ่งใช้ในผลิตภัณฑ์ทำความสะอาดและผลิตภัณฑ์ทำความสะอาดต่าง ๆ\n\nBio Green Wax จัดหาน้ำมันปาล์มเคอร์เนลออยล์จากซัพพลายเชนที่ได้รับการรับรอง RSPO ซึ่งรับประกันความสามารถในการติดตามและสอดคล้องกับความมุ่งมั่นด้านปาล์มออย์ที่ยั่งยืน ผลิตภัณฑ์มีให้ในรูปแบบที่ผ่านการกลั่น ขาวใส และผ่านการดีโอโดไรซ์ (RBD) ซึ่งเป็นไปตามมาตรฐานคุณภาพระดับนานาชาติอย่างเข้มงวด', '2026-02-11 17:46:41', '2026-02-11 17:46:41'),
(21, 'prod-palm-kernel-stearin', 'น้ำมันรำข้าวสกัดจากเมล็ดปาล์ม', 'สเตอรีนจากเมล็ดปาล์มคุณภาพสูง เป็นเฟรคชันแข็งที่ได้จากการแยกสกัดน้ำมันเมล็ดปาล์ม ซึ่งเป็นที่นิยมในด้านโปรไฟล์การละลายที่รวดเร็วและความแข็งแรงที่ยอดเยี่ยมในการผลิตขนมหวาน เครื่องสำอาง และอุตสาหกรรมโอเลโอเคมิคัล', 'Bio Green Wax จัดหาสุกราชะมันสำปะหลังพรีเมียม (PKS) ซึ่งเป็นส่วนแข็งของไขมันที่มีจุดหลอมเหลวสูง ซึ่งผลิตขึ้นโดยการแยกส่วนอย่างมีการควบคุมในกระบวนการ fractionation ของน้ำมันปาล์มขัดสี ให้อยู่ในรูปแบบของไขมันแข็ง ซึ่่งเกิดจากการแยกน้ำมันปาล์มออกเป็นสองส่วน คือไขมันที่เป็นของเหลว (palm kernel olein) และไขมันแข็ง (palm kernel stearin) ซึ่งไขมันแข็งที่ได้มีสีขาวถึงเกือบขาว มีลักษณะจุดหลอมเหลวที่คมชัดและเนื้อสัมผัสแน่นหนา\n\nPalm kernel stearin อุดมไปด้วยกรดลุริก (C12) และกรดมายริสติก (C14) ทำให้มีความแข็งแรงยอดเยี่ยม การเกิดผลึกอย่างรวดเร็ว และคุณสมบัติการละลายที่สะอาด คุณสมบัติเหล่านี้ทำให้มันเป็นวัตถุดิบที่เหมาะสมสำหรับการใช้แทนโกโก้บัตเตอร์ (CBS), ช็อกโกแลตคอมพาวนด์หุ้ม, ไส้ขนมหวาน, และไขมันพิเศษที่ต้องการความแข็งและความเงางามในการตกแต่ง\n\nนอกเหนือจากการใช้งานในอาหารแล้ว Palm kernel stearin ยังเป็น feeds ในอุตสาหกรรม Oleochemical สำหรับการผลิตกรดไขมัน, แอลกอฮอล์ไขมัน, เส้นใยสบู่ และสารลดแรงตึงผิว ในผลิตภัณฑ์ดูแลส่วนบุคคลและเครื่องสำอาง มันช่วยเสริมเนื้อสัมผัสและโครงสร้างให้กับครีม โลชั่น และสูตรแข็งต่าง ๆ\n\nBio Green Wax จัดหาพลอยจากสายโซ่อุปทานที่ได้รับการรับรองจาก RSPO ซึ่งเป็นการรับประกันความสามารถในการติดตามและความสอดคล้องกับความมุ่งมั่นด้านปิโตรเลียมเขียวอย่างยั่งยืน ผลิตภัณฑ์มีให้เลือกในรูปแบบรีไฟน์, ขาวและกลิ่นหอม (RBD) ซึ่งเป็นไปตามมาตรฐานคุณภาพระดับสากลสำหรับใช้ในอาหารและอุตสาหกรรมเทคนิค', '2026-02-11 17:21:03', '2026-02-11 17:21:03'),
(22, 'prod-palm-oil', 'น้ำมันปาล์ม', 'น้ำมันปาล์มและสารสกัดจากปาล์มที่ได้จากการจัดหาอย่างยั่งยืน', 'น้ำมันปาล์มและผลิตภัณฑ์จากปาล์มที่ได้มาทางความยั่งยืนสำหรับการผลิตอาหาร การทำสบู่และผงซักฟอก มีตัวเลือกที่ได้รับการรับรองจาก RSPO พร้อมให้บริการ', '2026-02-09 03:17:24', '2026-02-11 17:28:49'),
(23, 'prod-palm-shortenings', 'ไขมันพัล์มชนิดเนยเทียน (มีจุดหลอมเหลวสูง)', 'น้ำมันปาล์มสำหรับทอดและเบเกอรี่ความละลายสูง (46–52 °C) เป็นไขมันพิเศษสำหรับเบเกอรี่และการทอดทำมาจากน้ำมันปาล์มแยกชั้น ซึ่งออกแบบมาเพื่อให้โครงสร้างแข็งแรง รสชาติบริสุทธิ์ และความทนทานต่อความร้อนที่ยอดเยี่ยมในงานอุตสาหกรรมที่ต้องการความทนทานสูง', 'ฟิล์มพรีสเนียนจากปาล์มที่มีจุดหลอมละลายสูงในช่วง 46–52 °C ถูกสร้างจากปาล์มสไตร์นและเฟร็กชันกลาง เพื่อให้ความเข้มข้นของไขมันแข็งสูง เนื้อสัมผัสที่แน่นหนา และเครือข่ายผลึกที่เสถียรในอุณหภูมิปกติและอุณหภูมิสูง ช่วงการหลอมละลายที่สูงขึ้นนี้ให้ความต้านทานความร้อนที่เหนือกว่า เสถียรภาพในการออกซิเดชัน และลดการออยเอ้าท์ ทำให้เหมาะสมอย่างยิ่งสำหรับสภาพภูมิอากาศแบบเขตร้อนและสายการผลิตที่มีอุณหภูมิสูง\n\nในงานเบเกอรี่ ฟิล์มพรีสเนียนเหล่านี้ให้ความฟู คงรูป และความกรอบที่ดี สนับสนุนการทำเปลือกพายแบบกรอบ การพองตัวของแป้งพัฟ คุกกี้และบิสกิต รวมถึงครีมแคร็กเกอร์ โดยยังคงรูปร่างและความกรอบแม้ในอุณหภูมิอบอุ่น นอกจากนี้ยังใช้เป็นไขมันทอดและแป้งสำหรับทำแป้งโดว์ที่แข็งแรง รวมถึงเป็นทดแทนไขมันจากสัตว์ในผลิตภัณฑ์เนื้อสัตว์ ซึ่งโครงสร้างที่แน่นหนา เสถียรภาพของอิมัลชัน และโปรไฟล์ที่เป็นศูนย์-trans, ไม่ใช้น้ำมันไฮโดรเจน ช่วยให้ได้เนื้อสัมผัสที่คงที่ การปลดปล่อยกลิ่นรสที่สะอาด และสูตรที่เป็นมิตรกับฉลาก', '2026-02-11 17:28:09', '2026-02-11 17:28:09'),
(24, 'prod-palm-stearic-acid', 'กรดสเตียร์ริกปาล์ม', 'กรดสเตียริกปาล์มเป็นกรดไขมันอิ่มตัวที่ได้จากน้ำมันปาล์ม ใช้ในเครื่องสำอาง เทียน และการผลิตยาง', 'กรดสเตียริกจากปาล์มเป็นกรดไขมันชนิดหนึ่งที่ได้จากน้ำมันปาล์ม โดยผ่านกระบวนการแยกและทำให้เกิดผลึกของกรดไขมัน เป็นกรดไขมันอิ่มตัวที่มีความเสถียรและอยู่ในรูปของแข็งที่อุณหภูมิห้อง กรดสเตียริกจากปาล์มมีลักษณะเป็นวาววับ เกิดตั้งแต่สีขาวจนถึงสีเหลืองอ่อน จุดหลอมเหลวโดยทั่วไปอยู่ในช่วงประมาณ 55-70 องศาเซลเซียส (131-158 องศาฟาเรนไฮต์) ซึ่งช่วยให้สามารถนำไปใช้ผสมในสูตรต่าง ๆ สำหรับเครื่องสำอาง เทียน และผลิตภัณฑ์ยางพาราได้อย่างง่ายดาย', '2026-02-11 17:39:49', '2026-02-11 17:39:49'),
(25, 'prod-palm-stearin', 'น้ำมันปาล์มสเตียริน', 'Palm stearin คือส่วนของไขมันปาล์มในรูปแบบของแข็ง ซึ่งมักใช้ในอุตสาหกรรมอาหาร การผลิตเทียน และการทำสบู่', 'Palm stearin เป็นส่วนแข็งของน้ำมันปาล์มที่ได้จากกระบวนการแบ่งเฟส ซึ่งมีชื่อเสียงในด้านปริมาณกรดไขมันอิ่มตัวสูง เป็นไขมันแข็งในอุณหภูมิห้อง มีสีขาวครีมถึงเหลืองอ่อน และเนื้อเนียนนุ่มคล้ายแว็กซ์ Palm stearin มีจุดหลอมเหลวสูงกว่าน้ำมันปาล์ม โดยทั่วไปใช้ในอุตสาหกรรมอาหารเพื่อเสถียรภาพของไขมัน การผลิตมาการีน และในการผลิตเทียนและสบู่', '2026-02-11 17:39:06', '2026-02-11 17:39:06'),
(26, 'prod-paraffin-wax', 'เทียนพาราฟินที่ผ่านการกลั่นอย่างสมบูรณ์ (50-68°C)', 'Bio Green Wax พาราฟินผ่านการกลั่นอย่างเต็มที่ (50-68°C)—เกรดอาหาร/ยา, น้ำมัน <0.5%, แข็งแรงเหนือกว่า. เหมาะสำหรับเทียน, เครื่องสำอาง, บรรจุภัณฑ์, และงานอุตสาหกรรมที่ต้องความแม่นยำ', 'เทียนขี้ผึ้ง Bio Green Wax ที่ผ่านการกลั่นอย่างเต็มที่ (จุดหลอมเหลว 50-68°C) มีปริมาณน้ำมันต่ำมาก (<0.5%) ความแข็งแรงยอดเยี่ยม และกลิ่น/สีที่เป็นกลาง มีให้เลือกในเกรดเทียน (52/54°C, 56/58°C), เกรดบรรจุภัณฑ์ (50/52°C), และเกรดเสาเทียนที่ละลายสูง (64/66°C) เหมาะสำหรับเทียนระดับพรีเมียม เครื่องสำอาง เคลือบบรรจุภัณฑ์อาหาร และแม่พิมพ์ที่ต้องการความบริสุทธิ์สูงสุดและความคงที่ในประสิทธิภาพ', '2026-02-11 17:43:46', '2026-02-11 17:43:46'),
(27, 'prod-pf56-synthetic-wax', 'ขี้ผึ้ง Fischer-Tropsch (FT)', 'เทียน Fischer‑Tropsch (FT) เป็นเทียนพาราฟินสังเคราะห์ความบริสุทธิ์สูงที่ผลิตจาก syngas ซึ่งมีจุดหลอมเหลวสูง ความหนืดต่ำ และความแข็งแรงยอดเยี่ยมสำหรับการใช้งานที่ต้องการความทนทานในพลาสติก เคลือบ เลือดหมึก กาว และการปรับแต่งบิทูเมน', 'FT wax ถูกผลิตขึ้นผ่านกระบวนการสังเคราะห์ Fischer‑Tropsch ให้เป็นเทียนขาวใสสะอาดมาก มีการกระจายพันธะคาร์บอนในช่วงแคบมาก มีปริมาณน้ำมันต่ำมาก และมีความเสถียรทางความร้อนที่ยอดเยี่ยม มีจุดหลอมเหลวสูง ค่าความหนืดของของเหลวต่ำ และความแข็งแรงสูง ซึ่งให้ความทนต่อรอยขีดข่วน การควบคุมความเงา เอฟเฟกต์ด้านด้าน และการหล่อลื่นที่ดีเยี่ยมในสูตรผลิตภัณฑ์หลายชนิด\n\nในงานพลาสติกและการประมวลผล PVC/CPVC FT wax ทำหน้าที่เป็นจาระบีภายในและภายนอกที่มีประสิทธิภาพ รวมทั้งเป็นตัวช่วยในการประมวลผล ช่วยลดความหนืดของการหลอม เพิ่มการไหลของเนื้อพลาสติก และปรับปรุงการหล่อขึ้นรูปและเสถียรภาพของขนาด ชิ้นงานใช้กันอย่างแพร่หลายในกาวร้อนละลายและกาวแบบแรงกด อิงค์เจ็ทพิมพ์ และเคลือบอุตสาหกรรม เพื่อเพิ่มความแข็ง ทนต่อการสึกหรอ รอยขีดข่วน การกันการแตกตัว และลดการตกตะกอน ในขณะเดียวกันก็ช่วยให้วาร์ปทิแคะ ความหนืดคงที่ การประยุกต์ใช้เพิ่มเติม ได้แก่ การปรับปรุงบิทูเมนและค้าสบาป การผสมมาสเทอร์แบตช์และพอลิเมอร์ การประมวลผลยาง การทำความเงา ผลิตภัณฑ์สิ่งทอ และแม้แต่สูตรเครื่องสำอาง ซึ่ง FT wax ช่วยให้ควบคุมคริสตัลไลน์ได้ดีขึ้น ปรับปรุงความทนต่อการสึกหรอและรอยยับ รวมถึงให้ความรู้สึกเรียบเนียนและนุ่มนวล', '2026-02-11 17:44:48', '2026-02-11 17:44:48'),
(28, 'prod-pfad', 'PFAD (Palm Fatty Acid Distillate)', 'PFAD เป็นผลพลอยได้ของการกลั่นน้ำมันปาล์ม ซึ่งใช้ในอุตสาหกรรมการผลิตสบู่ อาหารสัตว์ และการผลิตเชื้อเพลิงชีวภาพ', 'Palm Fatty Acid Distillate (PFAD) คือของเหลือจากกระบวนการกลั่นน้ำมันปาล์ม ซึ่งได้จากการกลั่นน้ำมันปาล์มดิบเพื่อกำจัดสิ่งสกปรกและให้ได้ระดับความบริสุทธิ์ที่สูงขึ้น PFAD เป็นของเหลวสีน้ำตาลเหลืองมีกลิ่นเฉพาะตัว ประกอบด้วยส่วนผสมของกรดไขมันอิ่มตัวและไม่อิ่มตัว โดยกรดไขมันหลัก ได้แก่ กรดลอริก กรดมิตริก และกรดปาล์มิติก PFAD ใช้ในอุตสาหกรรมการผลิตสบู่ อาหารสัตว์ และพลังงานชีวภาพ', '2026-02-11 17:26:51', '2026-02-11 17:26:51'),
(29, 'prod-pkfad', 'น้ำมันกรดไขมันจากเนื้อในของเมล็ดปาล์ม (PKFAD)', 'PKFAD เป็นผลพลอยได้จากการกลั่นน้ำมันเมล็ดปาล์ม ซึ่งอุดมไปด้วยกรดลารูริค ใช้ในอุตสาหกรรมสบู่และอุตสาหกรรมน้ำมันเคมี', 'Palm Kernel Fatty Acid Distillate (PKFAD) คือของเสียที่ได้จากขั้นตอนการกลั่นน้ำมันเมล็ดปาล์ม ซึ่งอุดมไปด้วยกรดไขมัน รวมถึงกรดลอริก จึงมีคุณค่าสำหรับการใช้งานในอุตสาหกรรมบางประเภท PKFAD ถูกนำไปใช้ในงานอุตสาหกรรมต่าง ๆ รวมถึงการผลิตสบู่ การผลิตเชื้อเพลิงชีวภาพ และเป็นวัตถุดิบในอุตสาหกรรมโอเลอเคมี', '2026-02-11 17:40:31', '2026-02-11 17:40:31'),
(30, 'prod-polyethylene-wax', 'ขี้ผึ้งโพลีเอทิลีน (PE wax)', 'เป็นโพลีเอทิลีนที่มีโมเลกุลต่ำ ซึ่งใช้เป็นจาระบีประเภทคุณภาพสูงและช่วยในการประมวลผลในพลาสติก เคลือบผิว สีน้ำหมึก และกาว เพื่อปรับปรุงการไหล ลื่นบนพื้นผิว และความต้านทานรอยขีดข่วน', 'ขี้ผึ้ง polyethylene เป็นขี้ผึ้งสังเคราะห์ชนิดละเอียดที่มีจุดหลอมเหลวสูง มีความหนืดต่ำ ทนความร้อนได้ดีเยี่ยม และสามารถเข้ากันได้อย่างแข็งแรงกับโพลิเมอร์ทั่วไป เช่น PVC, PE, PP และ EVA ซึ่งให้การหล่อลื่นภายในและภายนอก ลดความหนืดของเนื้อพลาสติกและแรงเสียดทาน ช่วยให้การปล่อยแม่พิมพ์เป็นไปอย่างราบรื่นและให้พื้นผิวที่เรียบเนียน เป็นประกายเงา และทนขีดข่วน\n\nแอปพลิเคชันหลักได้แก่การแปรรูปพลาสติกและการทำ masterbatch ซึ่งขี้ผึ้ง PE ช่วยเพิ่มประสิทธิภาพในการฉีดและขึ้นรูปพลาสติก ลดการสะสมของแม่พิมพ์ และปรับปรุงการกระจายสีและสารเติมแต่ง นอกจากนี้ยังใช้ในกาวร้อนและกาวแบบ Pressure-sensitive หมึกพิมพ์ และการเคลือบผง เพื่อควบคุมความหนืดในการละลาย เสริมความเหนียวและความทนทาน และปรับเวลาเปิดและเวลาตั้งตัว งานเพิ่มเติมครอบคลุมไปถึงการใช้งานในยางมะตอย สีทาถนน คอนเสิร์ตไม้พลาสติก คอมโพสิตยาง เคเบิล คอมโพสิต และผลิตภัณฑ์ขี้ผึ้งที่ผสมสำเร็จ เช่น น้ำยาเคลือบเงาและสีเทียน ซึ่งช่วยเพิ่มจุดอ่อนตัว ความแข็งแรง และความต้านน้ำ.', '2026-02-11 17:42:58', '2026-02-11 17:42:58'),
(31, 'prod-rapeseed-oil', 'น้ำมันเรพซีด', 'น้ำมันเรพซีดสกัดเย็นและผ่านการกลั่นจากฟาร์มในสหราชอาณาจักร', 'น้ำมันเรปเซียสบริสุทธิ์และผ่านการกดเย็นจากฟาร์มในสหราชอาณาจักร เหมาะสำหรับการทำอาหาร การอบ และน้ำสลัด ต่ำในไขมันอิ่มตัวและสูงในโอเมก้า-3', '2026-02-11 17:34:31', '2026-02-11 17:34:31'),
(32, 'prod-rapeseed-wax', 'ขี้ผึ้งเรปซีด', 'เทียนเรพซีดเป็นเทียนพืชธรรมชาติที่ใช้เป็นทางเลือกที่เป็นมิตรกับสิ่งแวดล้อมในการทำเทียนและเครื่องสำอาง', 'ขี้ผึ้งคาเปซู (Rapeseed wax) เป็นขี้ผึ้งพืชธรรมชาติที่ได้จากน้ำมันของพืชคาเปซู ซึ่งมักนำมาใช้เป็นทางเลือกที่เป็นมิตรต่อสิ่งแวดล้อมแทนขี้ผึ้งพาราฟินแบบดั้งเดิมในการทำเทียนและการใช้งานอื่น ๆ ให้ความร้อนที่สะอาดและช้า รวมถึงสามารถเก็บกลิ่นได้ดี เป็นที่นิยมในการผลิตเทียนและในการผสมในเครื่องสำอางธรรมชาติ เช่น ลิปบาล์ม โลชั่น และครีม ซึ่งมีคุณสมบัติให้ความชุ่มชื้น', '2026-02-11 17:24:40', '2026-02-11 17:24:40'),
(33, 'prod-soap-noodles', 'เส้นสบู่', 'เส้นบะหมี่สบู่เป็นวัตถุดิบหลักสำหรับการผลิตสบู่ ซึ่งเกิดจากกระบวนการทำให้เป็นสบู่ของน้ำมันและไขมันจากพืช', 'เส้นใยสบู่ หรือที่รู้จักกันในชื่อเกรนูลสบู่ คือหนึ่งในวัตถุดิบหลักที่ใช้ในการผลิตสบู่ พวกมันถูกผลิตขึ้นจากการแปรรูปน้ำมันและไขมันพืชด้วยโซเดียมไฮดรอกไซด์ (โซดาไฟ) ผ่านกระบวนการสบู่ การแปรรูปเส้นใยสบู่โดยทั่วไปเป็นชิ้นหรือเม็ดสีขาวหรือสีเนื้ออ่อน มีกลิ่นหอมอ่อนโยนและเป็นกลาง พวกมันปราศจากสิ่งเจือปนและมีความเข้มข้นของกรดไขมันสูง ซึ่งมีส่วนช่วยในคุณสมบัติทำความสะอาดและทำให้เป็นอิมัลชัน', '2026-02-11 17:41:17', '2026-02-11 17:41:17'),
(34, 'prod-soy-wax', 'เทียนไขถั่วเหลือง', 'เทียนขี้ผึ้งถั่วเหลืองเป็นเทียนจากพืชที่สามารถนำกลับมาใช้ใหม่ได้ ผลิตจากน้ำมันถั่วเหลือง ซึ่งเป็นที่นิยมในการทำเทียนที่เป็นมิตรกับสิ่งแวดล้อม', 'เทียนจากถั่วเหลืองเป็นชนิดของเทียนจากพืชที่ได้มาจากน้ำมันถั่วเหลือง เป็นทางเลือกยอดนิยมแทนเทียนพาราฟินแบบดั้งเดิม ซึ่งได้จากปิโตรเลียม เทียนจากถั่วเหลืองถือว่าเป็นทางเลือกที่สามารถต่อยอดได้เอง จะย่อยสลายได้ตามธรรมชาติ และเป็นมิตรกับสิ่งแวดล้อมในการทำเทียน ผลิตโดยการทำให้ไฮโดรเจนกับน้ำมันถั่วเหลือง เพื่อเปลี่ยนเป็นของแข็งที่เหมาะสมสำหรับเทียน ซึ่งมักมาในรูปแบบเกล็ดซึ่งง่ายต่อการวัดและละลาย', '2026-02-11 17:17:55', '2026-02-11 17:17:55'),
(35, 'prod-soybean-oil', 'น้ำมันถั่วเหลือง', 'น้ำมันถั่วเหลืองคุณภาพสูงสำหรับใช้ในอุตสาหกรรมและครัวเรือน', 'น้ำมันถั่วเหลืองเป็นน้ำมันพืชที่หลากหลาย สกัดจากถั่วเหลือง ซึ่งใช้กันอย่างแพร่หลายในการทอด อบ และปรุงน้ำสลัด เนื่องจากมีรสชาติเบาและจุดไหม้สูง\nเป็นแหล่งของไขมันไม่อิ่มตัวเชิงซ้อน รวมถึงกรดไขมันโอเมก้า-3 และโอเมก้า-6 และให้วิตามินเคและวิตามินอี\nเหมาะสำหรับการทอดลึก การผลิตมาการีน และการใช้งานในอุตสาหกรรมอาหาร ผ่านการกลั่นและขจัดกลิ่นเพื่อมาตรฐานระดับพรีเมียม', '2026-02-11 17:29:29', '2026-02-11 17:29:29'),
(36, 'prod-sunflower-oil', 'น้ำมันดอกทานตะวัน', 'น้ำมันฟักทองกลั่นระดับพรีเมียมสำหรับการปรุงอาหารและการแปรรูปอาหาร', 'น้ำมันดอกทานตะวันบริสุทธิ์เกรดพรีเมียมของเราเหมาะอย่างยิ่งสำหรับการประกอบอาหาร ทอด และการแปรรูปอาหาร สกัดจากเมล็ดทานตะวันที่มีคุณภาพ และผ่านการกลั่นกรองตามมาตรฐานสูงสุด', '2026-02-09 03:22:28', '2026-02-11 17:22:35');
INSERT INTO `products_tr` (`id`, `master_id`, `name`, `description`, `full_description`, `created_at`, `updated_at`) VALUES
(1, 'bdf424df-f9b0-4a79-84d6-f6ed1eb1e84f', 'Palm Olein', 'Palmi yağı oleini, rafine edilmiş palm yağının sıvı fraksiyonudur ve nötr tat, uzun kızartma ömrü ve çıtır çıtır doku sağlayan istikrarlı bir kızartma ve pişirme yağı olarak değer görür; atıştırmalıklar, fast-food ve ev kullanımı için idealdir.', 'Palm olein, rafine edilmiş, beyazlatılmış ve deodorize edilmiş (RBD) palm yağının fraksiyonlanmasıyla üretilir ve oleik ve palmitik asit açısından zengin, şeffaf bir sıvı elde edilir. Bu, doğal olarak iyi oksidatif stabiliteye sahip dengeli bir yağ asidi profili sağlar. Yüksek duman noktası, oksidasyona ve polimer oluşumuna direnç göstermesi ve kötü tatlar oluşturma eğiliminin düşük olması sayesinde, tekrar tekrar kızartma işlemleri gerçekleştirilebilir; bu da yağın bozulmasını azaltır, köpürmeyi engeller ve ürünlerin raf ömrünü uzatır.\n​\nGıda uygulamalarında, palm olein, atıştırmalıklar, patates cipsleri, kızarmış tavuk, hazır erişte ve ön kızartılmış dondurulmuş gıdalar için derin kızartma ortamı olarak yaygın şekilde kullanılır; ayrıca birçok tropikal pazarda genel amaçlı ev tipi pişirme yağı olarak da tercih edilir. Aynı zamanda, soya fasulyesi, ayçiçeği veya diğer bitkisel yağlarla karışımlarında temel yağ olarak hizmet eder ve özelleştirilmiş beslenme ve fonksiyonel profiller elde edilmesine olanak tanır. Margarinse, fırınlama yağlarında ve gıda servis fırın sistemlerinde, stabil performans ve temiz tat kritik öneme sahip olduğu durumlarda kullanılır.', '2026-02-11 17:15:25', '2026-02-11 17:15:25'),
(2, 'prod-beeswax', 'Arı yağı', 'Doğal saf balmumu, kozmetik ve mum yapımı için', 'Etik arıcılar tarafından sağlanan saf ve doğal balmumu. Kozmetik, mum yapımı ve gıda uygulamaları için mükemmel. Farklı kalite seçenekleri mevcuttur.', '2026-02-11 17:29:55', '2026-02-11 17:29:55'),
(3, 'prod-bw101-palm-wax', 'Palmiye Yağı', 'Kremamsı sarı renkte Premium %100 palmiye wax, mum yapımı için idealdir. RSPO SG (Segregated) / MB (Mass balance) sertifikalı.', 'Kadife ve kremsi sarı rengine sahip %100 premium palm wax. Sürdürülebilirlik için RSPO MB sertifikalıdır. Mum yapımı, kalıplama ve kap kısı mumlar için idealdir.', '2026-02-11 17:45:34', '2026-02-11 17:45:34'),
(4, 'prod-bw105-palm-wax', 'Palm Shortenings (Düşük erime noktası)', 'Palm Shortening, fraksiyone palm yağından elde edilen, yarı katı, hidrojene olmayan bir yağıdır ve üstün stabilite ile nötr tat sağlar.', 'Palm Shortening, fraksiyonize palm yağından elde edilen yarı katı, hidrojenlenmemiş bir yağdır ve üstün stabilite ile nötr lezzet sunar.\nFırıncılık uygulamaları için mükemmeldir—kabarık hamur işleri, yumuşak kekler ve yüksek dumana dayanıklı kızartmalar yapar.\nEndüstriyel fırıncılıkta tereyağı veya domuz yağına ekonomik ve oksidasyona dirençli bir alternatif sağlar.', '2026-02-11 17:31:18', '2026-02-11 17:31:18'),
(5, 'prod-bw10510-blended-wax', 'Kavanoz mumları için Palm-Parafin karışımlı balmumu', 'Kullanıma hazır Düşük MP Jel Mum Karışımı: Palm-Parafin-Mikrokristal with Polyboost™, Vybar®, UV stabilize ediciler—sadece renk ve aroma ekleyin, üstün cam yapışması ve maksimum aydınlatma için.', 'Bio Green Wax\'ın Düşük Erime Noktası Cam Kavanoz Mum Karışımı (48-50°C) ve (50-52°C)—Palm-Paraffin-Mikrokristalin formülasyon, cam kaplar için optimize edilmiştir. Kullanıma hazır: sadece renk ve koku ekleyin. Opaklık/adhesiyon için Polyboost/Vybar, raf ömrü için UV stabilizatörleri/antioxidanlar, ayrıca olağanüstü sıcak/soğuk yayılım, kırışıklık yapmayan yanma ve üstün kavanoz tutuşu sağlayan koku tutucu ajanlar içerir; bu, üstün kapsül mumları için ideal bir seçenektir.', '2026-02-11 17:37:24', '2026-02-11 17:37:24'),
(6, 'prod-bw10555-blended-wax', 'Bitkisel Soya Bazlı Vegan Mum Karışımı', 'Bio Green Wax\'tan hazır kullanıma uygun %95 Soja Vegan Karışımı — cam (48-52°C) ve sütun (56-62°C) mumlar için saf bitki bazlı. Sadece renk ve koku ekleyin.', 'Bio Green Wax\'ın %95 Soya Yağı Vegan Karışımı (5% bitki katkısı), cam kavanozlar ve bağımsız sütunlar için temiz yanma ve doğal performans sağlar. Kaplar için düşük erime noktası (48-52°C) ve sütunlar için yüksek erime noktası (56-62°C) olarak mevcuttur. Kullanıma hazırdır: sadece renginizi ve kokunuzu ekleyin, mükemmel yayılım ve düzgün bir yüzey sağlayın.', '2026-02-11 17:32:04', '2026-02-11 17:32:04'),
(7, 'prod-bw10610-blended-wax', 'Göbek Mumları için Palm-Parafin karışımlı mum', 'Kullanıma Hazır Yüksek MP Direk Mum Karışımları (56-58°C & 58-60°C): Palm-Paraffin-Microcrystalline ve Polyboost™, Vybar®, UV stabilizörleri—sadece renk ve koku ekleyin, üstün direk performansı için.', 'Bio Green wax\'s High Melting Point Pillar Candle Blends (56-58°C & 58-60°C)—Palm-Paraffin-Microcrystalline formülasyonları, bağımsız ayakta duran sütun mumları için geliştirilmiştir. Kullanıma hazır: sadece renk ve koku ekleyin. Kalıp çıkarmayı ve opaklığı artırmak için Polyboost/Vybar ile optimize edilmiştir, UV stabilizatörleri/antioksidanlar ile raf ömrünü uzatır, ayrıca koku tutucu ajanlar sayesinde mükemmel sıcak/soğuk itme, mükemmel sütun şekil koruması ve temiz yanma performansı sağlar.', '2026-02-11 17:38:11', '2026-02-11 17:38:11'),
(8, 'prod-bw10655-blended-wax', 'Kuş-Kevküri-Parafinli Mum Karışımı', 'Bio Green Wax\'tan hazır kullanıma hazır Soya-Benzoz-Parafin Karışımı—Jar (48-52°C) ve Pillar (56-62°C) mumlar için en üst düzey koku yayılımı. Sadece koku ve renk ekleyin.', 'Bio Green Wax\'ın Soy-Bal Arısı-Parafin Karışımı, doğal soya pürüzsüzlüğü, balmumu stabilitesi ve parfüm gücü ile eşsiz koku performansı sağlar. Düşük erime noktası (48-52°C) cam kaplarda mükemmel; yüksek erime noktası (56-62°C) ise sütunlar için idealdir. Kullanıma hazır formülasyon—sadece parfüm ve renk ekleyin, üstün sıcak/soğuk yayılım ve kusursuz mum bitişi elde edin.', '2026-02-11 17:32:56', '2026-02-11 17:32:56'),
(9, 'prod-bw8307-blended-wax', 'Hindistan Cevizi- Kanola Mumu Karışımı', 'Bio Green Wax\'tan Hazır Kullanıma Hazır Hindistan Cevizi- Kanola Karışımı—Kavanoz (48-52°C) ve Sütun (56-62°C) mumlar için kremsi doğal performans. Sadece renk ve koku ekleyin.', 'Bio Green Wax\'in Coconut-Rapeseed Karışımı, hindistancevizi mumu\'nun kremamsı dokusu ile kanola yağı mumunun pürüzsüz yanışını bir araya getirerek olağanüstü doğal mum performansı sağlar. Düşük erime noktası (48-52°C) kaplanmış mumlar için optimize edilmiştir; yüksek erime noktası (56-62°C) sütun mumları için uygundur. Tamamen kullanıma hazırdır — sadece istediğiniz renk ve koku ekleyerek profesyonel, temiz yanışlı sonuçlar elde edin.', '2026-02-11 17:33:45', '2026-02-11 17:33:45'),
(10, 'prod-carnauba-wax', 'Carnauba Mumu', 'Parlaklıklar ve kaplamalar için premium Brezilya karnauba cila', '\"Kraliçe mum\" olarak bilinen premium Brezilya carnauba wax. Araba cilası, kozmetik ve gıda kaplamaları için idealdir. En yüksek doğal erime noktası.', '2026-02-11 17:30:32', '2026-02-11 17:30:32'),
(11, 'prod-castor-oil', 'Hint: Castor Oil', 'Ricinius communis tohumlarından elde edilen premium soğuk preslenmiş hint yağı, farmasötik ürünlerde, kozmetikte ve endüstriyel uygulamalarda yaygın olarak kullanılmaktadır.', 'Bio Green Wax, yüksek kaliteli hint yağı tedarik eder; bu çok yönlü bitkisel yağ, Hint yağı bitkisi (Ricinus communis) tohumlarının preslenmesiyle elde edilir. Ricinoleik asit (yaklaşık %85–90) açısından zengin benzersiz kimyasal bileşimiyle tanınan hint yağı, olağanüstü viskozite, kayganlık ve nemlendirme özellikleri sergiler; bu özellikleriyle birçok endüstride vazgeçilmezdir.\n\nHint yağımız özenle temin edilip işlenmiş olup, en yüksek saflık ve tutarlılık standartlarına uygundur. Hem soğuk pres (virgin) hem de rafine gruplarda satışa sunulmakta olup, farmasötik, kozmetik ve endüstriyel uygulamalara uygundur. Yağın dikkate değer stabilitesi ve alkolde çözünürlüğü, onu diğer bitkisel yağlardan ayırır ve üstün performans gerektiren formülasyonlarda tercih edilen bir bileşen haline getirir.\n\nHint yağı doğal olarak biyolojik olarak parçalanabilir olup, yenilenebilir kaynaklardan elde edilir; bu da Bio Green Wax\'in sürdürülebilir ve çevreye duyarlı tedarik taahhüdüyle uyumludur.', '2026-02-11 17:16:23', '2026-02-11 17:16:23'),
(12, 'prod-coconut-oil', 'Hindistan Cevizi Yağı', 'Yemek ve kozmetik uygulamaları için saf ve rafine hindistan cevizi yağı', 'Yüksek kaliteli ham ve rafine vazgeçilmez hindistan cevizi yağı, pişirme, pişirim ve kozmetik uygulamalarına uygun. Özel ihtiyaçlarınıza göre çeşitli derecelerde mevcuttur.', '2026-02-09 02:58:47', '2026-02-11 17:17:06'),
(13, 'prod-coconut-wax', 'Hindistancevizi Mumu', 'Hindistancevizi yağıyla elde edilen doğal bir mum olan hindistancevizi mumları, temiz yanma özelliği ve çevre dostu uygulamalarıyla takdir edilir.', 'Hindistan cevizi yağı, Hindistan cevizi yağından elde edilen doğal bir mumdur ve mum yapımında temiz ve yavaş yanmasıyla bilinir. Genellikle diğer mumlara sürdürülebilir bir alternatif olarak kabul edilir. Hindistan cevizi mumu, çevre dostu özellikleri ve kokuyu iyi tutma yeteneğiyle öne çıkar. Doğal ve yenilenebilir bir kaynaktan elde edilen bu mum, uzun süreli ve daha verimli performans sağlayan temiz ve yavaş yanma özelliğine sahiptir.', '2026-02-11 17:25:56', '2026-02-11 17:25:56'),
(14, 'prod-fr5456-paraffin-wax', 'Yarı Rafine Paraffin Balmumu (50-68°C)', 'Bio Green Wax Yarı Rafine Parafin (50-68°C)—mumlar, kauçuk, tekstil ve yüksek hacimli endüstriyel uygulamalar için uygun, %1-5 oranında ekonomik yağ içeriği.', 'Bio Green Wax\'ın Semi Refined Paraffin Wax\'ları (50-68°C), kontrollü yağ içeriği (1-5%) ile ekonomik performans sağlar ve esnek sertlik sunar. Standart dereceler: 52/54°C (mumlar), 56/58°C (sütunlar), 60/62°C (endüstriyel). Dengeli performans ve fiyatın önemli olduğu, maliyete duyarlı mum üretimi, kauçuk işleme katkıları, tekstil bitirme ve toptan paketleme kaplamalarında mükemmeldir.', '2026-02-11 17:23:49', '2026-02-11 17:23:49'),
(15, 'prod-glycerine', 'Gülsüvat', 'Güçlendirici, renklessiz, kokuşuz ve yapışkan bir sıvıdır; farmasötik, kozmetik ve gıda sektörlerinde yaygın olarak kullanılır.', 'Gliserin, başka bir deyişle gliserol veya gliserin, renkli, kokusuz ve yapışkan bir sıvıdır ve tatlı bir tada sahiptir. Genellikle renksiz olan, ancak hafif sarımsı bir tona sahip olabilen şurup kıvamında, berrak bir sıvıdır. Gliserinin yüksek bir viskozitesi vardır, yani yavaş akar ve nispeten kalın bir yapıya sahiptir. Şurup benzeri bir kıvama sahip olması, nem tutma özelliğine katkıda bulunur. Gliserin, farmasötik, kozmetik, gıda işleme ve çeşitli endüstriyel uygulamalarda yaygın olarak kullanılır.', '2026-02-11 17:19:51', '2026-02-11 17:19:51'),
(16, 'prod-hydrogenated-castor-oil', 'Hidrojenlenmiş Hint Yağı', 'Hidrojenlenmiş hint yağı, hint yağının katı, mumumsu bir türevi olup, kozmetik, ilaç ve endüstriyel uygulamalarda kullanılır.', 'Hidrojene hintyağı, aynı zamanda hintyağı veya hintyağı pulü olarak da bilinir, hintyağı türevidir ve hidrojenleme işlemi görür. Bu işlem, hintyağı moleküllerine hidrojen eklenmesini içerir ve bu da katı, mumsu bir madde ile sonuçlanır. Kozmetik ve kişisel bakım ürünlerinde, rujlar, kremler ve losyonlar gibi, cildi pürüzsüzleştirmek ve nemlendirmek amacıyla emoliyan olarak kullanılır. Ayrıca, kozmetik formüllerde bağlayıcı bir ajan olarak işlev görerek, içeriklerin birbirine yapışmasına ve cilde tutunmasına yardımcı olur.', '2026-02-11 17:25:14', '2026-02-11 17:25:14'),
(17, 'prod-microcrystalline-wax', 'Mikrokristal Mum', 'Kozmetik ve yapıştırıcılar için esnek mikro kristal wax', 'Kıvama uygun mikrokristal wax, kozmetik ürünler, sıcak eritici yapıştırıcılar ve özel kaplamalar için idealdir. Üstün esneklik ve yapışma özellikleri sağlar.', '2026-02-11 17:23:06', '2026-02-11 17:23:06'),
(18, 'prod-olive-oil', 'Zeytinyağı', 'İleri kalite saf zeytinyağı, seçkin Akdeniz zeytinlerinden soğuk presleme yöntemiyle elde edilmiştir ve mutfak, kozmetik ve endüstriyel uygulamalar için uygundur.', 'Premium saf zeytinyağımız, özenle seçilmiş Akdeniz zeytinlerinden soğuk sıkım yöntemiyle elde edilir, üstün kalite ve zengin lezzet sunar. Gıda hazırlığında, kozmetik, ilaç ve kişisel bakım ürünlerinde yaygın olarak kullanılan zeytinyağı, sağlık yararları, antioksidan özellikleri ve çok yönlü kullanımlarıyla değer görmektedir. Bio Green Wax, uluslararası katı kalite standartlarına uygun zeytinyağı tedarik eder, tüm uygulamalarda tutarlı saflık ve performans sağlar.', '2026-02-11 17:41:52', '2026-02-11 17:41:52'),
(19, 'prod-palm-kernel-oil', 'Palmiye Çekirdeği Yağı', 'Palmiye çekirdeği yağı, palm yağı meyvesinin çekirdeğinden elde edilir ve gıda ürünleri, kozmetik ve endüstriyel uygulamalarda kullanılır.', 'Palmiye çekirdeği yağı, palmiye meyvesinin çekirdeğinden elde edilir ve ayırt edici fiziksel özelliklere sahiptir. Genellikle oda sıcaklığında açık sarıdan beyaza kadar katı halde bulunur, ancak ısıtıldığında berrak, sarımsı bir sıvıya dönüşür. Erime noktası 23 ila 28 derece Celsius (73 ila 82 derece Fahrenheit) arasında değişir. Palm kernel yağı, laurik asit açısından zengindir ve gıda üretimi, kozmetik ve sabun yapımında yaygın şekilde kullanılır.', '2026-02-11 17:21:43', '2026-02-11 17:21:43'),
(20, 'prod-palm-kernel-olein', 'Palmiye Çekirdeği Oleini', 'Premium rafine edilmiş palmiye çekirdeği olein, palmiye çekirdeği yağı fraksiyonlaşmasından elde edilen sıvı fraksiyon olup, mükemmel berraklığı, düşük bulanıklık noktası ve gıda, kişisel bakım ve oleokimya endüstrilerinde çok yönlü kullanımıyla değerlidir.', 'Bio Green Wax, rafine edilmiş palm çekirdeği yağının kontrollü fraksiyonizasyonu sonucu üretilen sıvı fraksiyon olan yüksek kaliteli palm çekirdeği olein (PKOo) tedarik etmektedir. Palm çekirdeği yağı doğru koşullar altında soğutulduğunda, katı fraksiyon (palm çekirdeği stearin) ve sıvı fraksiyon (palm çekirdeği olein) olarak ayrılır. Ortaya çıkan olein, düşük erime noktası ve mükemmel dökülebilirliği ile şeffaf, hafif renkli bir yağdır.\n\nPalm çekirdeği olein, laurik asit (C12) ve kaprik/kaprilik orta zincir yağ asitleri bakımından zengindir ve bu da ona üstün parlaklık, hızla emilim ve hafif, yağı hissettirmeyen bir dokunuş sağlar. Bu özellikler, onu yemeklik yağ, kızartma ortamı ve non-dairy kremalar, dondurma ve dolgu sütü formüllerinde bileşen olarak gıda endüstrisinde oldukça aranan hale getirir.\n\nKişisel bakım ve kozmetik sektöründe, palm çekirdeği olein, mükemmel nemlendirici özellikleri ve cilt uyumu sayesinde losyonlar, kremler, şampuanlar ve sıvı sabunlarda yaygın şekilde temel yağ olarak kullanılır. Ayrıca, oleokimya üretiminde ana hammadde olarak hizmet ederek, deterjanlar ve temizlik ürünlerinde kullanılan yağ asitleri, metil esterler ve yüzeyaktif maddelerin üretimini sağlar.\n\nBio Green Wax, palm çekirdeği oleinini RSPO sertifikalı tedarik zincirlerinden temin etmektedir; bu da tam izlenebilirlik ve sürdürülebilir palm yağı taahhütleriyle uyum anlamına gelir. Ürün, rafine, ağartılmış ve deodorize (RBD) formda bulunmakta olup, katı uluslararası kalite standartlarını karşılamaktadır.', '2026-02-11 17:46:28', '2026-02-11 17:46:28'),
(21, 'prod-palm-kernel-stearin', 'Palmiye Çekirdeği Stearin', 'Yüksek kaliteli palm çekirdeği stearin, palm çekirdeği yağı fraksiyonasyonundan elde edilen katı fraksiyon olup, sert erime profili ve mükemmel sertliğiyle şekerleme, kozmetik ve oleokimya uygulamalarında tercih edilir.', 'Bio Green Wax, rafine palm çekirdeği yağı tarafından kontrollü fraksiyonizasyon yoluyla üretilen daha yüksek erime noktasına sahip katı fraksiyon olan premium kalite palm çekirdeği stearin (PKS) tedarik eder. Fraksiyonizasyon sırasında, palm çekirdeği yağı iki bileşene ayrılır: palm çekirdeği oleini (sıvı fraksiyon) ve palm çekirdeği stearini (katı fraksiyon). Elde edilen stearin, karakteristik olarak keskin bir erime noktasına ve sert dokuya sahip, beyazdan kirli beyaza kadar değişen bir yağa dönüşür.\n\nPalm çekirdeği stearini, laurik asit (C12) ve miristik asit (C14) açısından zengindir; bu da ona mükemmel sertlik, hızlı kristalleşme ve temiz bir erime profili sağlar. Bu özellikler, kakao yağı yerine kullanılabilen katkı maddeleri (CBS), bileşik çikolata kaplamaları, şekerleme dolgu maddeleri ve sert ve parlak bir görünüm istenen özel yağlar için ideal bir bileşen olmasını sağlar.\n\nGıda uygulamalarının ötesinde, palm çekirdeği stearini, yağlı asitler, yağlı alkoller, sabun hamurları ve yüzey aktif maddeleri üretimi için oleokimya endüstrisinde değerli bir hammadde olarak hizmet eder. Kişisel bakım ve kozmetikte ise, kremlere, losyonlara ve katı formülasyonlara gövde ve yapı kazandırır.\n\nBio Green Wax, palm çekirdeği stearinini RSPO sertifikalı tedarik zincirlerinden temin eder; böylece tam izlenebilirlik ve sürdürülebilir palm yağı taahhütlerine uyum sağlanır. Ürün, rafine, ağartılmış ve deodorize (RBD) formda mevcuttur ve hem gıda sınıfı hem de teknik sınıf kullanımı için uluslararası kalite standartlarını karşılar.', '2026-02-11 17:20:50', '2026-02-11 17:20:50'),
(22, 'prod-palm-oil', 'Palmiye Yağı', 'Sürdürülebilir şekilde temin edilen palm yağı ve palm türevleri', 'Gıda üretimi, sabun ve deterjan üretimi için sürdürülebilir şekilde temin edilen palmiye yağı ve palm türevleri. RSPO sertifikalı seçenekler mevcuttur.', '2026-02-09 03:02:12', '2026-02-11 17:28:41'),
(23, 'prod-palm-shortenings', 'Palm Kısa Yağları (yüksek erime noktası)', 'Yüksek erime noktası olan palm yağı kuşmanları (46–52 °C), ayrıştırılmış palm yağı kullanılarak yapılan özel fırıncılık ve kızartma yağlarıdır. Güçlü yapı, temiz lezzet ve zorlu endüstriyel uygulamalarda mükemmel ısı stabilitesi sağlamak üzere tasarlanmıştır.', '46–52 °C aralığında yüksek erime noktasına sahip palm kısaltmaları, palm stearin ve orta fraksiyonlardan formüle edilerek yüksek katı yağ içeriği, sert doku ve stabil kristal ağı oluşturmayı sağlar. Bu daha yüksek erime aralığı, üstün ısı direnci, oksidatif stabilite ve azalmış yağ çıkması sağlar; bu özellikler onları tropikal iklimler ve yüksek sıcaklıkta işleme hatları için ideal kılar. \n\nFırıncılık uygulamalarında, bu kısaltmalar iyi havalandırma, lamine ve çıtırlık sağlar; katmanlı tart hamurları, kabarık hamur işleri, krema bisküvileri, kurabiyeler ve bisküvilerin şeklini ve çiğneme keyfini sıcak ortamda bile korumasına destek olur. Ayrıca, dayanıklı kızartma ve hamur yağı olarak kullanılırlar ve et ürünlerinde hayvansal yağ yerine geçici olarak kullanılabilirler. Sert yapıları, emülsiyon stabiliteleri ve sıfır trans, katı olmayan profil özellikleri sayesinde tutarlı doku, temiz tat salınımı ve etiket dostu formülasyonlar elde edilmesine yardımcı olur.', '2026-02-11 17:27:58', '2026-02-11 17:27:58'),
(24, 'prod-palm-stearic-acid', 'Palm Stearik Asit', 'Palm stearik asit, palm yağından elde edilen doygun yağ asididir ve kozmetik, mum ve kauçuk üretiminde kullanılır.', 'Palm stearik asit, palm yağından türetilmiş bir yağ asidi türüdür ve yağ asitlerinin ayrıştırılması ve kristalleştirilmesi yoluyla elde edilir. Oda sıcaklığında stabilitesi ve katı hali ile bilinen doymuş bir yağ asididir. Palm stearik asidin balmumu benzeri bir görünümü olup, beyazdan hafif sarıya kadar değişebilir. Erime noktası genellikle 55-70 derece Celsius (131-158 derece Fahrenheit) arasında olan bu madde, kozmetik ürünler, mumlar ve kauçuk ürünleri gibi çeşitli formülasyonlara kolayca entegre edilmesine olanak tanır.', '2026-02-11 17:39:39', '2026-02-11 17:39:39'),
(25, 'prod-palm-stearin', 'Palm Stearin', 'Palm stearin, palmiye yağının katı fraksiyonudur ve genellikle gıda üretimi, mum yapımı ve sabun üretiminde kullanılır.', 'Palm stearin, fraksiyonlaşma süreciyle elde edilen palm yağının katı fraksiyonudur ve yüksek doymuş yağ asidi içeriğiyle bilinir. Oda sıcaklığında katı bir yağdır ve kremamsı beyazdan soluk sarıya kadar renk tonlarına ve pürüzsüz, mumsu bir dokuya sahiptir. Palm stearin, palm yağına göre daha yüksek erime noktasına sahiptir. Gıda endüstrisinde yağların stabilize edilmesi, margarin üretimi ve mum ve sabun yapımında yaygın olarak kullanılır.', '2026-02-11 17:38:57', '2026-02-11 17:38:57'),
(26, 'prod-paraffin-wax', 'Tamamen Rafine Edilmiş Paraffin Mum (50-68°C)', 'Bio Green Wax Tam Rafine Parafin (50-68°C)—gıda/ilaç kalitesi, <0.5% yağ, üstün sertlik. Mumlar, kozmetik, ambalaj ve hassas endüstriyel uygulamalar için mükemmel.', 'Bio Green Wax\'ın Tamamen Rafine Parafin Mumları (50-68°C eritme noktaları) ultra-düşük yağ içeriği (<%0.5), mükemmel sertlik ve nötr koku/renk özellikleri ile öne çıkar. Mum kalitelerinde (52/54°C, 56/58°C), kaplar kalitelerinde (50/52°C) ve yüksek erime noktalı sütun kalitelerinde (64/66°C) mevcuttur. Üst düzey mumlar, kozmetikler, gıda ambalaj kaplamaları ve maksimum saflık ve tutarlı performans gerektiren hassas kalıplama için idealdir.', '2026-02-11 17:43:34', '2026-02-11 17:43:34'),
(27, 'prod-pf56-synthetic-wax', 'Fischer-Tropsch (FT) mum', 'Fischer‑Tropsch (FT) mumları, сингазdan üretilen yüksek saflıkta sentetik paraffin mumudur ve yüksek erime noktası, düşük viskozite ve mükemmel sertlik sağlar. Bu özellikler, plastikler, kaplamalar, mürekkepler, yapıştırıcılar ve asfalt modifikasyonu gibi zorlu uygulamalarda tercih edilir.', 'FT wax, Fischer‑Tropsch sentezi ile üretilir ve su beyazı, ultra temiz bir wax sağlar. Dar karbon zinciri dağılımı, çok düşük yağ içeriği ve üstün termal stabiliteye sahiptir. Yüksek yumuşama noktasıyla düşük erime viskozitesi ve güçlü sertliği birleştirerek birçok formülde üstün çizik direnci, parlaklık kontrolü, mat etkiler ve yağlama sağlar.  \n\nPlastik ve PVC/CPVC işleme süreçlerinde, FT wax etkin bir iç ve dış lubrican ve işleme yardımcıdır; erime viskozitesini azaltır, akışkanlığı artırır ve kalıp çıkarma ile boyutsal stabiliteyi iyileştirir. Sıcak eritmeli ve basınç duyarlı yapıştırıcılar, baskı mürekkepleri ve endüstriyel kaplamalarda sıkça kullanılır; sertliği, aşınma ve çizilme direncini, yapışma engelleyiciliği ve çökelmeyi önlerken viskoziteyi stabilize eder. Ek temel uygulamalar arasında bitüm ve asfalt modifikasyonu, masterbatch ve polimer karıştırma, kauçuk işleme, cilalar, tekstil ve hatta kozmetik formülasyonları bulunur; buradaki FT wax, kontrollü kristallendirme sağlar, aşınma ve kırışıklık direncini artırır ve pürüzsüz bir dokunuş sunar.', '2026-02-11 17:44:33', '2026-02-11 17:44:33'),
(28, 'prod-pfad', 'PFAD (Palm Yağı Asid Distilası)', 'PFAD, palm yağı rafine edilmesinin bir yan ürünüdür; sabun üretimi, hayvan yemi ve biyoyakıt üretiminde kullanılır.', 'Palm Yağı Yağı Distilatı (PFAD), palm yağı rafineleme sürecinin bir yan ürünü olup, ham palm yağı’nın damıtılmasıyla safsızlıkların giderilmesi ve daha yüksek saflık seviyesine ulaşılmasıyla elde edilir. PFAD, karakteristik bir kokuya sahip kahverengimsi sarı bir sıvıdır. Doymuş ve doymamış yağ asitlerinin karışımını içerir; baskın yağ asitleri laurik asit, miristik asit ve palmitik asittir. PFAD, sabun imalatı, hayvan yemi ve biyodizel üretiminde kullanılmaktadır.', '2026-02-11 17:26:43', '2026-02-11 17:26:43'),
(29, 'prod-pkfad', 'Palm Kernel Yağ Asidi Distilat (PKFAD)', 'PKFAD, palm çekirdeği yağı rafine edilmesi sırasında ortaya çıkan bir yan ürün olup, laurik asit açısından zengindir ve sabun ile oleokimya endüstrilerinde kullanılır.', 'Palmiye Çekirdeği Yağı Asit Distilat (PKFAD), palmiye çekirdeği yağı rafine edilirken elde edilen bir yan ürünüdür. Laurik asit de dahil olmak üzere çeşitli yağ asitleri açısından zengindir ve bu nedenle belirli endüstriyel uygulamalarda değerlidir. PKFAD, sabun üretimi, biyoyakıt üretimi ve oleokimya endüstrisinde ana hammadde olarak kullanılır.', '2026-02-11 17:40:23', '2026-02-11 17:40:23'),
(30, 'prod-polyethylene-wax', 'Polietilen Mum (PE mum)', 'Düşük moleküler ağırlıklı polietilen, plastikler, kaplamalar, mürekkepler ve yapıştırıcılar gibi alanlarda yüksek performanslı bir yağlayıcı ve işleme yardımcı maddesi olarak kullanılır; akışkanlığı, yüzey kayganlığını ve çizilme direncini artırır.', 'Polyethylene wax, ince taneli, yüksek erime noktası olan sentetik bir wax olup, düşük viskozite, mükemmel termal stabilite ve PVC, PE, PP ve EVA gibi yaygın polimerlerle güçlü uyumluluk sağlar. İç ve dış yağlama sağlar, eriyik viskozitesini ve sürtünmeyi azaltır, kalıp çıkarmayı kolaylaştırır ve pürüzsüz, parlak ve çizilmeye dayanıklı yüzeyler oluşturur.\n​\n\nAna uygulamaları arasında plastikler ve masterbatch işlemesi bulunur; burada PE wax ekstrüzyon ve enjeksiyon kalıplama verimliliğini artırır, makara birikimini önler ve pigmentler ile dolgu maddelerinin dağılımını iyileştirir. Ayrıca, sıcak eriyik ve basınç duyarlı yapıştırıcılarda, mürekkep ve toz kaplamalarda eriyik viskozitesini kontrol etmek, kohezyonu ve dayanıklılığı artırmak ve açık ve sertleşme sürelerini optimize etmek amacıyla kullanılır. Ek olarak, asfalt ve yol çizgi boyaları, ahşap-plastik kompozitler, kauçuk katkıları, kablo bileşikleri ve poliş ve pastil gibi formüle edilmiş wax ürünlerinde kullanılır; bu ürünlerde yumuşama noktası, sertlik ve suya dayanıklılığı artırır.', '2026-02-11 17:42:46', '2026-02-11 17:42:46'),
(31, 'prod-rapeseed-oil', 'Kanzola Yağı', 'İngiltere çiftliklerinden soğuk sıkım ve rafine kanola yağı', 'İngiltere çiftliklerinden elde edilen soğuk sıkım ve rafine kanola yağı. Pişirme, fırınlama ve salata sosları için ideal. Doymuş yağ oranı düşük ve omega-3 açısından zengindir.', '2026-02-11 17:34:23', '2026-02-11 17:34:23'),
(32, 'prod-rapeseed-wax', 'Kanola Balmumu', 'Karanfildiği yağı doğal bitkisel bir balmumu olup, mum yapımı ve kozmetikte çevre dostu bir alternatif olarak kullanılır.', 'Kanola yağı madesinden elde edilen doğal bitkisel bir mum olan rapeseed (kanola) mumu, genellikle geleneksel paraffin mumu yerine çevre dostu bir alternatif olarak kullanılır. Temiz ve yavaş yanma sağlar ve iyi koku tutuşu sunar. Rapeseed mumu sıkça mum üretiminde ve lip balm, losyon ve kremler gibi doğal kozmetiklerin formülasyonunda kullanılır ve nemlendirici özellikler sağlar.', '2026-02-11 17:24:30', '2026-02-11 17:24:30'),
(33, 'prod-soap-noodles', 'Sabun Noodles', 'Sabun eriştesi, sabun üretimi için temel hammadde olup, bitkisel yağların ve yağların saponifikasyonu yoluyla üretilir.', 'Sabun eriştesi, diğer adıyla sabun granülleri, sabun üretiminde kullanılan temel ham maddelerden biridir. Bitkisel yağlar ve yağların sodyum hidroksit (kostik soda) ile saponifikasyonu yoluyla üretilirler. Sabun eriştesi genellikle hafif ve nötr bir aromaya sahip, katı beyaz veya krem rengi parçalar veya taneler şeklindedir. Saf ve kirpusuz olup, temizleme ve emülsifleştirme özelliklerine katkıda bulunan yüksek miktarda yağ asidi içerirler.', '2026-02-11 17:41:09', '2026-02-11 17:41:09'),
(34, 'prod-soy-wax', 'Pişmiş Balmumu', 'Soja mumu, soya fasulyesi yağından yapılan yenilenebilir bir bitkisel mumdur ve çevre dostu mum yapımında popülerdir.', 'Soya mumu, soya fasulyesi yağından elde edilen bir bitkisel mum türüdür. Geleneksel petrol bazlı paraffin mumunun popüler bir alternatifi olarak tercih edilir. Soya mumu, yenilenebilir, biyobozunur ve çevre dostu bir seçenek olarak kabul edilir. Soya fasulyesi yağı hidrojenleşerek katı hale getirilir ve bu form, mum yapımına uygun hale gelir. Genellikle ölçülebilir ve kolayca eritilebilen pul şeklinde gelir.', '2026-02-11 17:17:46', '2026-02-11 17:17:46'),
(35, 'prod-soybean-oil', 'Soya Fasulyesi Yağı', 'Endüstriyel ve mutfak amaçlı yüksek kaliteli soya fasulyesi yağı', 'Köri yağı, soya fasulyelerinden elde edilen çok yönlü bir bitkisel yağdır ve nötr aroması ile yüksek duman noktası sayesinde kızartma, fırınlama ve salata sosları için yaygın olarak kullanılır.  \nOmega‑3 ve omega‑6 yağ asitleri de dahil olmak üzere çoklu doymamış yağlar bakımından zengindir ve K vitamini ile E vitamini sağlar.  \nDerin kızartma, margarin üretimi ve endüstriyel gıda uygulamaları için mükemmeldir. Premium standartlara göre rafine edilmiş ve deodorize edilmiştir.', '2026-02-11 17:29:21', '2026-02-11 17:29:21'),
(36, 'prod-sunflower-oil', 'Ayçiçek Yağı', 'Yemek pişirme ve gıda işleme için premium rafine ayçiçek yağı', 'Premium rafine edilmiş ayçiçek yağımız, pişirme, kızartma ve gıda işleme uygulamaları için mükemmeldir. Kaliteli ayçiçeği tohumlarından temin edilmiş ve en yüksek standartlara göre rafine edilmiştir.', '2026-02-09 03:21:58', '2026-02-11 17:22:29');
INSERT INTO `products_vi` (`id`, `master_id`, `name`, `description`, `full_description`, `created_at`, `updated_at`) VALUES
(1, 'bdf424df-f9b0-4a79-84d6-f6ed1eb1e84f', 'Dầu cọ Palm Olein', 'Dầu cọ olein là phần lỏng của dầu cọ tinh chế, được coi là dầu chiên và nấu ăn ổn định, mang lại vị trung tính, tuổi thọ chiên lâu và kết cấu giòn cho các loại snack, đồ ăn nhanh và ứng dụng trong gia đình.', 'Palm olein được sản xuất bằng quá trình phân đoạn dầu cọ đã qua tinh chế, tẩy trắng và deodorized (RBD), để thu được một dạng lỏng trong suốt giàu axit oleic và palmitic, mang lại hồ sơ axit béo cân đối cùng khả năng chống ô-xi hóa tự nhiên tốt. Điểm cháy cao, khả năng chống ô-xi hóa và hình thành phân tử polyme, cũng như xu hướng thấp gây mùi lạ, cho phép lặp lại các chu trình chiên với giảm sự phân hủy dầu, ít bọt hơn và kéo dài hạn sử dụng của thành phẩm.\n​\nTrong ứng dụng thực phẩm, palm olein được sử dụng rộng rãi như một dầu chiên sâu cho các món ăn nhẹ, khoai tây chiên, gà chiên, mì ăn liền, thực phẩm đông lạnh đã qua chiên sơ và dầu nấu ăn gia dụng đa năng trong nhiều thị trường nhiệt đới. Nó cũng là dầu nền trong các hỗn hợp với đậu nành, hướng dương hoặc các loại dầu thực vật khác để đạt được hồ sơ dinh dưỡng và chức năng tùy chỉnh, và được sử dụng trong margarine, chất béo bánh mì, và các hệ thống chiên trong dịch vụ ẩm thực, nơi hiệu suất ổn định và hương vị sạch là điều kiện tiên quyết.', '2026-02-11 17:15:29', '2026-02-11 17:15:29'),
(2, 'prod-beeswax', 'Sáp ong', 'Sáp ong tinh khiết tự nhiên dùng để làm mỹ phẩm và nến', 'Sáp ong tự nhiên thuần khiết được lấy từ những người nuôi ong đạo đức. Hoàn hảo cho mỹ phẩm, làm nến và ứng dụng trong thực phẩm. Có sẵn nhiều loại cấp độ khác nhau.', '2026-02-11 17:29:58', '2026-02-11 17:29:58'),
(3, 'prod-bw101-palm-wax', 'Dầu cọ', 'đáo 100% sáp palm cao cấp có màu vàng kem, lý tưởng cho làm nến. Được chứng nhận RSPO SG (Phân loại riêng) / MB (Cân bằng khối lượng).', 'Sáp đu đủ 100% cao cấp với màu vàng kem đẹp mắt. Được chứng nhận RSPO MB về tính bền vững. Thích hợp để làm nến, đổ khuôn và nến đựng trong hộp.', '2026-02-11 17:45:36', '2026-02-11 17:45:36'),
(4, 'prod-bw105-palm-wax', 'Dầu Shortening lòng bàn tay (Điểm nóng chảy thấp)', 'Dầu cọ rút ngắn là một loại mỡ bán rắn, không hydro hóa, được chiết xuất từ dầu cọ đã phân đoạn, mang lại độ ổn định vượt trội và hương vị trung tính.', 'Dầu mỡ cọ Palm là một loại mỡ bán rắn, không hydrogen hóa, được chiết xuất từ dầu cọ tách thành phần, mang lại độ ổn định vượt trội và vị trung tính.\nHoàn hảo cho các ứng dụng làm bánh — tạo ra bánh pastry xốp layers, bánh mềm mại, và các món chiên giòn với điểm bắt lửa cao.\nLựa chọn kinh tế, chống oxy hóa thay thế bơ hoặc mỡ heo trong ngành làm bánh công nghiệp.', '2026-02-11 17:31:21', '2026-02-11 17:31:21'),
(5, 'prod-bw10510-blended-wax', 'Sáp nến pha trộn giữa dầu cọ và paraffin cho nến lọ', 'Hỗn hợp Nến Jar Low MP đã sẵn sàng sử dụng: Palm-Paraffin-Microcrystalline với Polyboost™, Vybar®, chất ổn định UV—Chỉ cần thêm màu sắc và hương liệu để độ gắn bó và phát tỏa tối ưu trên thủy tinh.', 'Hỗn hợp nến lọ Bio Green Wax có điểm tan thấp (48-50°C) và (50-52°C)—hàm lượng Palm-Paraffin-Microcrystalline tối ưu hóa cho các loại chai lọ thủy tinh. Sẵn sàng sử dụng: chỉ cần thêm màu sắc và hương thơm. Công thức chứa Polyboost/Vybar để tạo độ đục/đăng kết dính, các chất ổn định tia UV/chống oxi hóa để kéo dài tuổi thọ, cùng các chất giữ hương mang lại khả năng phát tỏa tuyệt vời khi nóng/lạnh, cháy không bị nhăn, và giữ tốt trong lọ cho nến container cao cấp.', '2026-02-11 17:37:27', '2026-02-11 17:37:27'),
(6, 'prod-bw10555-blended-wax', 'Hợp chất sáp chay dựa trên đậu nành', 'Hỗn hợp đậu nành thuần chay Ready-to-use 95% từ Bio Green Wax—hoàn toàn từ thực vật cho nến Jar (48-52°C) & Pillar (56-62°C). Chỉ cần thêm màu sắc và hương liệu.', 'Hợp chất sáp đậu nành thuần chay Bio Green Wax 95% (5% phụ gia thực vật) mang lại đốt sạch, hiệu suất tự nhiên cho lọ thủy tinh và cột đứng tự do. Có sẵn với điểm nung chảy thấp (48-52°C) dành cho lọ đựng và điểm nung chảy cao (56-62°C) dành cho cột. Sẵn sàng sử dụng: chỉ cần thêm màu sắc và hương liệu của bạn để đạt hiệu quả lan tỏa tốt và bề mặt mịn màng.', '2026-02-11 17:32:07', '2026-02-11 17:32:07'),
(7, 'prod-bw10610-blended-wax', 'dầu paraffin pha trộn với dầu cọ cho nến cột', 'Hỗn hợp Nến Trụ Cao Cấp Sẵn (56-58°C & 58-60°C): Palm-Paraffin-Microcrystalline với Polyboost™, Vybar®, chất ổn định UV—chỉ cần thêm màu sắc & mùi hương để đạt hiệu suất nến trụ vượt trội.', 'Hợp chất nến cột Bio Green wax có điểm chảy cao (56-58°C & 58-60°C)—các công thức Palm-Paraffin-Microcrystalline được thiết kế dành cho nến cột tự đứng. Sẵn sàng sử dụng: chỉ cần thêm màu sắc và hương thơm. Được tối ưu hóa với Polyboost/Vybar để dễ tháo khuôn và độ đục, chất ổn định tia UV/chống oxy hóa để kéo dài hạn sử dụng, cùng với các chất giữ hương giúp mang lại khả năng phát sáng vượt trội khi nóng/lạnh, giữ hình dạng nến cột lý tưởng và đốt sạch.', '2026-02-11 17:38:15', '2026-02-11 17:38:15'),
(8, 'prod-bw10655-blended-wax', 'Hỗn hợp sáp ong, sáp parafin và sáp paraffin', 'Hỗn hợp Dầu đậu nành - Sáp ong - Paraffin sẵn sàng sử dụng từ Bio Green Wax—hương thơm mạnh mẽ tối đa cho nến Jar (48-52°C) & nến Pillar (56-62°C). Chỉ cần thêm hương và màu.', 'Hỗn hợp sáp đậu nành, sáp ong và paraffin của Bio Green Wax kết hợp sự mịn màng tự nhiên của đậu nành, độ ổn định của sáp ong và khả năng tạo mùi thơm mạnh mẽ của paraffin để mang lại hiệu suất hương thơm vô song. Điểm melting thấp (48-52°C) phù hợp dùng trong các lọ thủy tinh; điểm melting cao (56-62°C) lý tưởng cho cột nến. Công thức đã chuẩn bị sẵn—chỉ cần thêm hương và màu để đạt hiệu quả tỏa hương nóng/lạnh vượt trội và hoàn thiện nến hoàn mỹ.', '2026-02-11 17:33:00', '2026-02-11 17:33:00'),
(9, 'prod-bw8307-blended-wax', 'Hợp chất sáp Dừa-Hạnh nhân', 'Hỗn hợp Dừa-Hạt cải Ready-to-use từ Bio Green Wax—hiệu suất tự nhiên kem mịn cho nến Jar (48-52°C) và nến Pillar (56-62°C). Chỉ cần thêm màu sắc và hương thơm.', 'Hợp chất dầu dừa và hạt cải của Bio Green Wax kết hợp kết cấu mượt mà của sáp dừa và khả năng cháy êm dịu của sáp hạt cải để tạo ra hiệu suất đèn nến tự nhiên xuất sắc. điểm nung chảy thấp (48-52°C) tối ưu cho nến đựng; điểm nung chảy cao (56-62°C) dành cho nến cột. Hoàn toàn sẵn sàng sử dụng — chỉ cần thêm màu sắc và hương thơm yêu thích của bạn để đạt được kết quả chuyên nghiệp, cháy sạch.', '2026-02-11 17:33:49', '2026-02-11 17:33:49'),
(10, 'prod-carnauba-wax', 'Sáp Carnauba', 'Sáp carnauba Brazil cao cấp cho lớp đánh bóng và lớp phủ', 'Sáp carnauba Brazil cao cấp, được gọi là \"Nữ hoàng của các loại sáp\". Lý tưởng cho việc đánh bóng xe hơi, mỹ phẩm và lớp phủ thực phẩm. Nhiệt độ nóng chảy tự nhiên cao nhất.', '2026-02-11 17:30:35', '2026-02-11 17:30:35'),
(11, 'prod-castor-oil', 'Dầu thầu dầu', 'Dầu thầu dầu ép lạnh cao cấp chiết xuất từ hạt Ricinus communis, được sử dụng rộng rãi trong lĩnh vực dược phẩm, mỹ phẩm và các ứng dụng công nghiệp.', 'Bio Green Wax cung cấp dầu thầu dầu chất lượng cao, một loại dầu thực vật đa dụng được chiết xuất bằng cách ép hạt của cây thầu dầu (Ricinus communis). Được biết đến với thành phần hóa học độc đáo giàu axit ricinoleic (khoảng 85–90%), dầu thầu dầu thể hiện khả năng đặc biệt về độ nhớt, độ bôi trơn và khả năng giữ ẩm, khiến nó trở nên vô giá trong nhiều ngành công nghiệp khác nhau.\n\nDầu thầu dầu của chúng tôi được cung cấp và chế biến cẩn thận để đáp ứng tiêu chuẩn cao về độ tinh khiết và tính nhất quán. Nó có sẵn ở dạng ép lạnh (nguyên chất) và tinh chế, phù hợp cho các ứng dụng trong dược phẩm, mỹ phẩm và công nghiệp. Sự ổn định đáng kinh ngạc và khả năng hòa tan trong cồn của dầu làm nó nổi bật so với các loại dầu thực vật khác, biến nó thành thành phần ưa thích trong các công thức yêu cầu hiệu suất vượt trội.\n\nDầu thầu dầu tự nhiên phân hủy sinh học và được chiết xuất từ các nguyên liệu tái tạo, phù hợp với cam kết của Bio Green Wax về nguồn cung bền vững và có trách nhiệm với môi trường.', '2026-02-11 17:16:27', '2026-02-11 17:16:27'),
(12, 'prod-coconut-oil', 'Dầu Dừa', 'Dầu dừa tinh khiết và đã qua tinh chế dùng cho thực phẩm và mỹ phẩm', 'Dầu dừa nguyên chất cao cấp và tinh chế phù hợp cho nấu ăn, làm bánh và các công dụng làm đẹp. Có sẵn nhiều cấp độ khác nhau để đáp ứng yêu cầu cụ thể của bạn.', '2026-02-09 02:59:00', '2026-02-11 17:17:08'),
(13, 'prod-coconut-wax', 'Sáp dừa', 'Nến sáp dừa là loại sáp tự nhiên được chiết xuất từ dầu dừa, nổi bật với khả năng cháy sạch và ứng dụng thân thiện với môi trường.', 'Sáp dừa là một loại sáp tự nhiên được chiết xuất từ dầu dừa, nổi bật với khả năng cháy sạch và cháy chậm trong tạo hình nến. Nó thường được xem là một lựa chọn bền vững thay thế cho các loại sáp khác. Sáp dừa được đánh giá cao nhờ đặc tính thân thiện với môi trường và khả năng giữ hương tốt. Được chiết xuất từ nguồn nguyên liệu tự nhiên và tái tạo được, sáp dừa mang lại hiệu quả cháy sạch, chậm, giúp nến bền lâu và hoạt động hiệu quả hơn.', '2026-02-11 17:25:59', '2026-02-11 17:25:59'),
(14, 'prod-fr5456-paraffin-wax', 'Sáp parafin bán tinh chế (50-68°C)', 'Dầu Paraffin Bio Green Wax Semi Refined (50-68°C)—chi phí hiệu quả với hàm lượng dầu từ 1-5% cho nến, cao su, dệt may và các ứng dụng công nghiệp quy mô lớn.', 'Parafin bán tinh chế của Bio Green Wax (50-68°C) mang lại hiệu suất kinh tế với hàm lượng dầu kiểm soát (1-5%) để điều chỉnh độ cứng linh hoạt. Các loại tiêu chuẩn: 52/54°C (tự nến), 56/58°C (tường), 60/62°C (công nghiệp). Hoàn hảo cho sản xuất nến tiết kiệm chi phí, phụ gia xử lý cao su, hoàn thiện dệt may và lớp phủ đóng gói số lượng lớn, nơi hiệu suất cân bằng và giá cả là yếu tố hàng đầu.', '2026-02-11 17:23:52', '2026-02-11 17:23:52'),
(15, 'prod-glycerine', 'Glycerine', 'Glycerine là một chất lỏng không màu, không mùi, có độ nhớt cao, được sử dụng rộng rãi trong ngành dược phẩm, mỹ phẩm và thực phẩm.', 'Glycerine, còn được gọi là glycerol hoặc glycerin, là một chất lỏng trong suốt, không màu, không mùi và có độ nhớt cao với vị ngọt. Đây là một chất lỏng rõ, giống như si-rúp, thường trong suốt, mặc dù có thể có chút tinge vàng nhạt. Glycerine có độ nhớt cao, nghĩa là nó chảy chậm và khá dày. Nó có kết cấu giống như si-rúp, góp phần vào khả năng giữ ẩm của nó. Glycerine được sử dụng phổ biến trong ngành dược phẩm, mỹ phẩm, chế biến thực phẩm và nhiều ứng dụng công nghiệp khác.', '2026-02-11 17:19:55', '2026-02-11 17:19:55'),
(16, 'prod-hydrogenated-castor-oil', 'Dầu Cọ Hydrogen hóa', 'Dầu thầu dầu hydrogen hóa là một dạng rắn sáp của dầu thầu dầu, được sử dụng trong mỹ phẩm, dược phẩm và các ứng dụng công nghiệp.', 'Dầu thầu dầu hydro hóa, còn gọi là sáp thầu dầu hoặc lát sáp thầu dầu, là một dẫn xuất của dầu thầu dầu trải qua quá trình hydrogen hóa. Quá trình này bao gồm việc thêm hydro vào các phân tử dầu thầu dầu, tạo thành một chất rắn, có dạng sáp. Nó được sử dụng trong các sản phẩm mỹ phẩm và chăm sóc cá nhân như son môi, kem và lotion như một chất làm mềm để cung cấp độ mịn màng và độ ẩm cho da. Nó cũng đóng vai trò như một chất kết dính trong các công thức mỹ phẩm, giúp các thành phần bám dính và dính chặt vào da.', '2026-02-11 17:25:17', '2026-02-11 17:25:17'),
(17, 'prod-microcrystalline-wax', 'Sáp vi tinh thể', 'Sáp vi tinh thể linh hoạt cho mỹ phẩm và chất kết dính', 'Sáp microcrystalline linh hoạt lý tưởng cho mỹ phẩm, keo nóng chảy và lớp phủ đặc biệt. Đặc tính linh hoạt và khả năng kết dính vượt trội.', '2026-02-11 17:23:08', '2026-02-11 17:23:08'),
(18, 'prod-olive-oil', 'Dầu ô liu', 'Dầu ô liu nguyên chất cao cấp, ép lạnh từ những quả ô liu chọn lọc từ Địa Trung Hải, dùng trong ẩm thực, làm đẹp và công nghiệp.', 'Dầu ô liu nguyên chất cao cấp của chúng tôi được ép lạnh từ những quả ô liu Địa Trung Hải được chọn lọc kỹ lưỡng, mang lại chất lượng xuất sắc và hương vị đậm đà. Được sử dụng rộng rãi trong chế biến thực phẩm, mỹ phẩm, dược phẩm và các sản phẩm chăm sóc cá nhân, dầu ô liu được đánh giá cao về lợi ích sức khỏe, đặc tính chống oxy hóa và ứng dụng đa dạng. Bio Green Wax cung cấp dầu ô liu đáp ứng các tiêu chuẩn chất lượng quốc tế nghiêm ngặt, đảm bảo độ tinh khiết và hiệu suất ổn định trong mọi ứng dụng.', '2026-02-11 17:41:55', '2026-02-11 17:41:55'),
(19, 'prod-palm-kernel-oil', 'Dầu Cọ Nhân', 'Dầu cọ thấm xuất từ hạt của quả cây cọ dầu, được sử dụng trong các sản phẩm thực phẩm, mỹ phẩm và ứng dụng công nghiệp.', 'Dầu cọ thô được chiết xuất từ lõi của quả cọ dầu và có đặc tính vật lý riêng biệt. Thường có màu vàng nhạt đến trắng khi ở nhiệt độ phòng, nhưng sẽ chảy thành dạng lỏng trong suốt, có màu vàng nhạt khi được nung nóng. Nhiệt độ melting của nó dao động từ 23 đến 28 độ Celsius (73 đến 82 độ Fahrenheit). Dầu cọ thô giàu axit Lauric và được sử dụng rộng rãi trong sản xuất thực phẩm, mỹ phẩm và sản xuất xà phòng.', '2026-02-11 17:21:46', '2026-02-11 17:21:46'),
(20, 'prod-palm-kernel-olein', 'Dầu cọ dầu hạt', 'Dầu cọ dầu thô tinh luyện cao cấp, phần lỏng thu được từ quá trình phân đoạn dầu cọ, được đánh giá cao về độ trong suốt tuyệt vời, điểm mù thấp và đa dụng trong ngành thực phẩm, chăm sóc cá nhân và ngành công nghiệp oleochemical.', 'Bio Green Wax cung cấp palm kernel olein (PKOo) chất lượng cao, phần lỏng được sản xuất thông qua quá trình phân đoạn kiểm soát của dầu cám lồng đã tinh chế. Khi dầu cám lồng được làm nguội dưới điều kiện chính xác, nó tách thành phần rắn (palm kernel stearin) và phần lỏng (palm kernel olein). Olein thu được là một loại dầu trong suốt, có màu sáng, điểm melting thấp và khả năng chảy tốt.\n\nPalm kernel olein giàu axit lauric (C12) và axit béo trung (capric/caprylic), mang lại độ trong suốt xuất sắc, khả năng hấp thụ nhanh và cảm giác nhẹ, không nhờn rít. Những đặc tính này làm cho nó trở thành một nguyên liệu rất được ưa chuộng trong ngành thực phẩm như dầu nấu ăn, chất trung gian chiên, và thành phần trong kem không sữa, kem (ice cream), và các loại sữa chứa nhân.\n\nTrong lĩnh vực chăm sóc cá nhân và mỹ phẩm, palm kernel olein được sử dụng rộng rãi như một loại dầu nền trong các loại lotion, kem dưỡng, dầu gội và xà phòng lỏng nhờ đặc tính dưỡng ẩm tuyệt vời và khả năng tương thích tốt với da. Nó cũng là nguyên liệu chính trong sản xuất oleochemical, tạo ra axit béo, methyl esters, và surfactant dùng trong chất tẩy rửa và các sản phẩm làm sạch.\n\nBio Green Wax lấy nguồn palm kernel olein từ các chuỗi cung ứng đã được chứng nhận RSPO, đảm bảo đầy đủ khả năng truy xuất nguồn gốc và phù hợp với cam kết phát triển bền vững của ngành dầu cọ. Sản phẩm có dạng tinh chế, tẩy trắng và khử mùi (RBD), đáp ứng tiêu chuẩn chất lượng quốc tế nghiêm ngặt.', '2026-02-11 17:46:32', '2026-02-11 17:46:32'),
(21, 'prod-palm-kernel-stearin', 'Chất béo Stearin hạt thâm nhiên', 'Chất béo palm kernel stearin chất lượng cao, phần rắn thu được từ quá trình phân đoạn của dầu cọ, được ưa chuộng nhờ đặc tính tan chảy nhanh và độ cứng vượt trội trong các ngành công nghiệp kẹo ngọt, mỹ phẩm và oleochemical.', 'Bio Green Wax cung cấp cao cấp palm kernel stearin (PKS), phần rắn có điểm melting cao hơn được sản xuất thông qua quá trình phân đoạn kiểm soát của dầu cọ đã qua tinh chế. Trong quá trình phân đoạn, dầu cọ được tách thành hai thành phần: palm kernel olein (phần lỏng) và palm kernel stearin (phần rắn). Stearin thu được là mỡ màu trắng đến trắng nhạt với điểm melting đặc trưng cao và kết cấu cứng chắc.\n\nPalm kernel stearin chứa nhiều axit lauric (C12) và axit myristic (C14), mang đến độ cứng tuyệt vời, khả năng kết tinh nhanh và hồ sơ tan chảy sạch sẽ. Những đặc tính này khiến nó trở thành thành phần lý tưởng cho các chất thay thế bơ ca cao (CBS), lớp phủ sô cô la hợp chất, nhân kẹo, và các chất béo đặc biệt yêu cầu độ giòn và độ bóng cao.\n\nNgoài ứng dụng trong thực phẩm, palm kernel stearin còn là nguyên liệu quý trong ngành oleochemical để sản xuất axit béo, cồn béo, noodle xà phòng, và surfactant. Trong lĩnh vực chăm sóc cá nhân và mỹ phẩm, nó góp phần cung cấp thể tích và cấu trúc cho kem, lotion và các dạng đặc rắn.\n\nBio Green Wax lấy nguồn palm kernel stearin từ các chuỗi cung ứng đạt chứng nhận RSPO, đảm bảo truy xuất nguồn gốc rõ ràng và tuân thủ cam kết phát triển bền vững của ngành dầu cọ. Sản phẩm có sẵn ở dạng tinh chế, tẩy trắng và khử mùi (RBD), đáp ứng các tiêu chuẩn chất lượng quốc tế cho mục đích thực phẩm và kỹ thuật.', '2026-02-11 17:20:54', '2026-02-11 17:20:54'),
(22, 'prod-palm-oil', 'Dầu cọ', 'Dầu cọ và các dẫn xuất của dầu cọ được lấy nguồn bền vững', 'Dầu cọ và các dẫn xuất từ cọ được khai thác bền vững cho sản xuất thực phẩm, sản xuất xà phòng và chất tẩy rửa. Các tùy chọn đạt chứng nhận RSPO có sẵn.', '2026-02-09 03:17:00', '2026-02-11 17:28:44'),
(23, 'prod-palm-shortenings', 'Dầu cọ chiên rán (điểm nhiệt cao)', 'Chất béo shortening từ mỡ cọ có điểm nóng chảy cao (46–52 °C) là loại mỡ đặc biệt dùng trong làm bánh và chiên, được làm từ dầu cọ tinh chế phân đoạn, nhằm mang lại cấu trúc vững chắc, hương vị tinh khiết và khả năng chịu nhiệt xuất sắc trong các ứng dụng công nghiệp đòi hỏi cao.', 'Các chất béo shortening từ dầu cọ có điểm nóng chảy cao trong khoảng 46–52 °C được pha chế từ phần dầu cọ stearin và các trung phân đoạn để cung cấp hàm lượng chất rắn cao, kết cấu chắc chắn và mạng tinh thể ổn định ở nhiệt độ môi trường và nhiệt độ cao hơn. Khoảng điểm nóng chảy cao hơn này mang lại khả năng chịu nhiệt tốt hơn, độ ổn định oxy hóa cao và giảm hiện tượng chảy dầu, khiến chúng phù hợp cho khí hậu nhiệt đới và các dây chuyền chế biến ở nhiệt độ cao.\n\nTrong các ứng dụng làm bánh, các shortening này tạo độ xốp tốt, khả năng cuốn bánh và độ giòn, hỗ trợ vỏ bánh tart xốp, bánh puff, bánh quy kem, bánh cookies và biscuits giữ hình dáng và độ giòn ngay cả trong điều kiện ấm. Chúng cũng được sử dụng như các chất béo dùng để chiên và làm bánh dẹt mạnh mẽ, cũng như thay thế mỡ động vật trong các sản phẩm thịt, nơi cấu trúc chắc chắn, độ ổn định của emulsions và đặc tính không trans, không hydro hóa giúp đạt được kết cấu đồng nhất, hương vị rõ ràng, và các công thức thân thiện với nhãn mác.', '2026-02-11 17:28:01', '2026-02-11 17:28:01'),
(24, 'prod-palm-stearic-acid', 'Axit stearic cầu chì', 'Axit stearic palm là một axit béo no xuất phát từ dầu cọ, được sử dụng trong mỹ phẩm, nến và sản xuất cao su.', 'Axit stearic palm là một loại axit béo xuất phát từ dầu cọ, được thu được qua quá trình tách biệt và kết tinh các axit béo. Đây là loại axit béo no, nổi bật với độ ổn định và dạng rắn ở nhiệt độ phòng. Axit stearic palm có ngoại hình dạng sáp, từ màu trắng đến hơi vàng. Nhiệt độ melting point của nó thường nằm trong khoảng 55-70 độ Celsius (131-158 độ Fahrenheit), giúp dễ dàng tích hợp vào nhiều công thức khác nhau cho mỹ phẩm, nến và sản phẩm cao su.', '2026-02-11 17:39:42', '2026-02-11 17:39:42'),
(25, 'prod-palm-stearin', 'Dầu béo Palm Stearin', 'Palm stearin là phần rắn của dầu cọ, thường được sử dụng trong sản xuất thực phẩm, sản xuất nến và làm xà phòng.', 'Palm stearin là một phân đoạn rắn của dầu cọ thu được qua quá trình phân đoạn, nổi tiếng với hàm lượng axit béo bão hòa cao. Nó là một chất béo rắn ở nhiệt độ phòng, có màu kem trắng đến vàng nhạt và kết cấu mịn, sáp. Palm stearin có điểm melting cao hơn so với dầu cọ. Nó thường được sử dụng trong ngành công nghiệp thực phẩm để ổn định chất béo, sản xuất margarine, cũng như trong sản xuất nến và xà phòng.', '2026-02-11 17:39:00', '2026-02-11 17:39:00'),
(26, 'prod-paraffin-wax', 'Khuôn Nến Paraffin Tinh Chế Hoàn Toàn (50-68°C)', 'Dầu Paraffin Tinh Khiết Hoàn Toàn Bio Green Wax (50-68°C)—chất lượng thực phẩm/ dược phẩm, dầu <0.5%, độ cứng vượt trội. Hoàn hảo cho nến, mỹ phẩm, đóng gói và các ứng dụng công nghiệp chính xác.', 'Hợp chất sáp paraffin tinh chế hoàn toàn của Bio Green Wax (điểm melt từ 50-68°C) có hàm lượng dầu siêu thấp (<0.5%), độ cứng vượt trội, mùi vị và màu sắc trung tính. Có sẵn các loại phù hợp làm nến (52/54°C, 56/58°C), các loại phù hợp lọ đóng hộp (50/52°C), và các loại sáp tạo hình cột nhiệt độ cao (64/66°C). Lý tưởng cho nến cao cấp, mỹ phẩm, lớp phủ đóng gói thực phẩm và đúc chính xác yêu cầu độ tinh khiết tối đa và độ ổn định hiệu suất.', '2026-02-11 17:43:39', '2026-02-11 17:43:39'),
(27, 'prod-pf56-synthetic-wax', 'Sáp Fischer-Tropsch (FT)', 'Sáp Fischer‑Tropsch (FT) là loại sáp paraffin tổng hợp chất lượng cao, được sản xuất từ syngas, mang đặc điểm nhiệt độ nung chảy cao, độ nhớt thấp và độ cứng tuyệt vời phù hợp cho các ứng dụng đòi hỏi khắt khe trong lĩnh vực nhựa, sơn phủ, mực in, keo và xử lý bitumen', 'FT wax được tạo ra qua quá trình tổng hợp Fischer‑Tropsch, mang lại một loại sáp trong, cực kỳ tinh khiết, có phân bố chuỗi carbon hẹp, hàm lượng dầu rất thấp và độ ổn định nhiệt vượt trội. Nó kết hợp điểm mềm cao với độ nhớt chảy thấp và độ cứng mạnh mẽ, mang lại khả năng chống trầy xước vượt trội, kiểm soát độ bóng, hiệu ứng mờ, đồng thời cung cấp khả năng bôi trơn trong nhiều công thức.\n\nTrong quá trình xử lý nhựa và PVC/CPVC, FT wax hoạt động như một chất bôi trơn nội và ngoại hiệu quả cùng với chất trợ xử lý, giảm độ nhớt chảy của màng chảy, cải thiện lưu thông, nâng cao khả năng tháo khuôn và ổn định kích thước. Nó được sử dụng rộng rãi trong keo nóng chảy và keo nhạy áp lực, mực in, sơn công nghiệp để tăng độ cứng, khả năng chống mài mòn và trầy xước, chống dính, và chống lắng tầng trong khi vẫn duy trì ổn định độ nhớt. Các ứng dụng chính khác gồm có sửa đổi bitumen và nhựa asphalt, masterbatch và phối trộn polymer, xử lý cao su, sơn đánh bóng, dệt may, thậm chí cả các công thức mỹ phẩm, nơi FT wax mang lại khả năng kết tinh kiểm soát, tăng khả năng chống mòn và nhăn, cùng cảm giác mượt mà khi chạm.', '2026-02-11 17:44:38', '2026-02-11 17:44:38'),
(28, 'prod-pfad', 'PFAD (Palm Fatty Acid Distillate)', 'PFAD là phụ phẩm của quá trình tinh chế dầu cọ, được sử dụng trong sản xuất xà phòng, thức ăn gia súc và sản xuất nhiên liệu sinh học.', 'Dịch rỉ dầu mỡ cọ (PFAD) là sản phẩm phụ của quá trình tinh chế dầu cọ. Nó được thu được qua quá trình chưng cất dầu cọ thô để loại bỏ tạp chất và đạt được độ tinh khiết cao hơn. PFAD là một chất lỏng màu nâu vàng có mùi đặc trưng. Nó chứa hỗn hợp các loại axit béo no và không no, với các axit béo chủ đạo là axit lauric, axit myristic và axit palmitic. PFAD được sử dụng trong sản xuất xà phòng, thức ăn chăn nuôi và nhiên liệu sinh học.', '2026-02-11 17:26:46', '2026-02-11 17:26:46'),
(29, 'prod-pkfad', 'Chất tóm tắt Axit béo từ hạt cọ (PKFAD)', 'PKFAD là sản phẩm phụ của quá trình tinh chế dầu cám dừa, giàu axit lauric, được sử dụng trong ngành công nghiệp xà phòng và oleochemical.', 'Tinh dầu axit béo vỏ cọ (PKFAD) là sản phẩm phụ thu được trong quá trình tinh luyện dầu cọ. Nó chứa nhiều axit béo, trong đó có axit lauric, làm cho nó có giá trị trong một số ứng dụng công nghiệp nhất định. PKFAD được sử dụng trong nhiều lĩnh vực công nghiệp, bao gồm sản xuất xà phòng, sản xuất nhiên liệu sinh học và làm nguyên liệu thô trong ngành công nghiệp oleochemical.', '2026-02-11 17:40:26', '2026-02-11 17:40:26'),
(30, 'prod-polyethylene-wax', 'Sáp Polyethylene (sáp PE)', 'là một loại polyethylene có trọng lượng phân tử thấp được sử dụng như một chất bôi trơn hiệu suất cao và phụ gia xử lý trong nhựa, lớp phủ, mực in và keo dán, giúp cải thiện dòng chảy, trượt bề mặt và khả năng chống trầy xước.', 'Sáp polyethylene là một loại sáp tổng hợp mịn, có điểm chảy cao, độ nhớt thấp, ổn định nhiệt tuyệt vời và khả năng tương thích mạnh mẽ với các loại polymer phổ biến như PVC, PE, PP, và EVA. Nó cung cấp khả năng bôi trơn bên trong và bên ngoài, giảm độ nhớt của nhựa nóng chảy và ma sát, tăng khả năng dễ tách khuôn, đồng thời mang lại một bề mặt mịn, bóng và chống trầy xước.\n​\n\nCác ứng dụng chính bao gồm xử lý nhựa và masterbatch, nơi sáp PE cải thiện hiệu quả quá trình đùn và ép phun, ngăn chặn tích tụ trong khuôn và cải thiện phân tán pigment và chất độn. Nó cũng được sử dụng trong keo nóng chảy và keo nhạy cảm với áp lực, mực in và phủ bột để kiểm soát độ nhớt chảy, tăng tính kết dính và độ bền, tối ưu thời gian mở và đóng cứng. Các ứng dụng khác gồm có nhựa bitum và sơn vạch đường, composite gỗ- nhựa, pha trộn cao su, hợp chất cáp, và các sản phẩm sáp dạng pha chế như sơn bóng và sáp chì, trong đó nó nâng cao điểm mềm, độ cứng và khả năng chống nước.', '2026-02-11 17:42:49', '2026-02-11 17:42:49'),
(31, 'prod-rapeseed-oil', 'Dầu cật hạch', 'Dầu hạt cải ép lạnh và dầu cải tinh luyện từ các trang trại Vương quốc Anh', 'Dầu đậu cải ép lạnh và tinh chế từ các trang trại ở Vương quốc Anh. Lý tưởng để nấu ăn, quay và trộn salad. Ít chất béo bão hòa và giàu omega-3.', '2026-02-11 17:34:26', '2026-02-11 17:34:26'),
(32, 'prod-rapeseed-wax', 'Sáp Hạt Cải', 'Sáp hoa cải là loại sáp thực vật tự nhiên được sử dụng như một lựa chọn thân thiện với môi trường trong sản xuất nến và mỹ phẩm.', 'Sáp dầu cải là một loại sáp thực vật tự nhiên chiết xuất từ dầu của cây cải dầu, thường được sử dụng như một giải pháp thân thiện với môi trường thay thế cho sáp paraffin truyền thống trong việc làm nến và các ứng dụng khác. Nó cháy sạch và chậm, đồng thời giữ mùi hương tốt. Sáp dầu cải thường được sử dụng trong sản xuất nến và trong công thức của các loại mỹ phẩm tự nhiên như son dưỡng môi, kem dưỡng, và lotion, mang lại khả năng giữ ẩm.', '2026-02-11 17:24:33', '2026-02-11 17:24:33'),
(33, 'prod-soap-noodles', 'Sữa tắm dạng bánh xà phòng', 'Khuôn xà phòng là nguyên liệu chính để sản xuất xà phòng, được tạo ra bằng quá trình xà phòng hóa các loại dầu và mỡ thực vật.', 'Bột xà phòng, còn gọi là hạt xà phòng, là một trong những nguyên liệu chính used trong sản xuất xà phòng. Chúng được sản xuất bằng cách xử lý dầu và mỡ thực vật với sodium hydroxide (nước lau chùi) qua quá trình xà phòng hóa. Bột xà phòng thường là những khối hoặc hạt màu trắng hoặc ngà, có mùi nhẹ và trung tính. Chúng không chứa tạp chất và có hàm lượng axit béo cao, góp phần vào khả năng làm sạch và nhũ hóa của chúng.', '2026-02-11 17:41:11', '2026-02-11 17:41:11'),
(34, 'prod-soy-wax', 'Sáp đậu nành', 'Dầu đậu nành là một loại sáp thực vật tái tạo được làm từ dầu đậu nành, phổ biến trong việc làm nến thân thiện với môi trường.', 'Sáp đậu nành là một loại sáp thực vật được chiết xuất từ dầu đậu nành. Nó là một sự lựa chọn phổ biến thay thế cho sáp paraffin truyền thống, vốn được chiết từ dầu mỏ. Sáp đậu nành được coi là một lựa chọn có thể tái tạo, phân hủy sinh học và thân thiện với môi trường để làm nến. Nó được tạo ra bằng cách hydrogen hóa dầu đậu nành, biến nó thành dạng rắn phù hợp cho việc làm nến. Thường thì nó có dạng dẻo, dễ đo và melting.', '2026-02-11 17:17:49', '2026-02-11 17:17:49'),
(35, 'prod-soybean-oil', 'Dầu đậu nành', 'Dầu đậu nành chất lượng cao cho mục đích công nghiệp và ẩm thực', 'Dầu đậu nành là một loại dầu thực vật đa dụng được chiết xuất từ đậu nành, được sử dụng rộng rãi để chiên, nướng và làm sốt salad nhờ vào vị trung tính và điểm bốc khói cao.\nNó giàu chất béo không bão hòa đa, bao gồm axit béo omega‑3 và omega‑6, và cung cấp vitamin K cùng vitamin E.\nThích hợp để chiên sâu, sản xuất bơ thực vật, và ứng dụng trong công nghiệp thực phẩm. Được tinh chế và khử mùi theo tiêu chuẩn cao cấp.', '2026-02-11 17:29:24', '2026-02-11 17:29:24'),
(36, 'prod-sunflower-oil', 'Dầu Hướng Dương', 'Dầu hướng dương tinh luyện cao cấp dùng để nấu ăn và chế biến thực phẩm', 'Dầu hướng dương tinh luyện cao cấp của chúng tôi hoàn hảo để nấu nướng, chiên và các ứng dụng chế biến thực phẩm. Được lấy từ hạt hướng dương chất lượng cao và tinh chế theo tiêu chuẩn cao nhất.', '2026-02-09 03:22:05', '2026-02-11 17:22:31');
INSERT INTO `products_zh` (`id`, `master_id`, `name`, `description`, `full_description`, `created_at`, `updated_at`) VALUES
(1, 'bdf424df-f9b0-4a79-84d6-f6ed1eb1e84f', '棕榈油酸 کوچک', '棕榈油月桂酸是精炼棕榈油的液态部分，因其作为一种稳定的炸油和烹饪油而备受青睐，具有中性口感、长时间炸制的耐用性以及酥脆的口感，适用于零食、快餐和家庭使用。', '棕榈油酯通过对精炼、漂白和脱臭（RBD）棕榈油进行分馏制成，获得清澈的液体，富含油酸和棕榈酸，具有平衡的脂肪酸组成，自然具有良好的氧化稳定性。其高烟点、抗氧化和抗聚合能力，以及低的异味形成倾向，使其可以多次重复使用进行油炸，减少油脂分解，减少起泡，提高成品的保质期。\n\n在食品应用方面，棕榈油酯被广泛用作油炸脂，用于零食、薯片、炸鸡、方便面和预炸冷冻食品的油炸，也作为许多热带市场中的通用家用烹饪油。它还可作为基础油，与大豆油、向日葵油或其他植物油混合，用于定制营养和功能特性的油脂配方，并在人造黄油、烘焙脂和餐饮油炸系统中使用，确保稳定的性能和纯净的口感。', '2026-02-11 17:14:50', '2026-02-11 17:14:50'),
(2, 'prod-beeswax', '蜂蜡', '纯天然蜂蜡，用于化妆品和蜡烛制作', '纯天然蜂蜡，来自道德养蜂人的优质蜂蜜。非常适合化妆品、蜡烛制造和食品应用。提供多种等级选择。', '2026-02-05 21:56:28', '2026-02-11 17:29:36'),
(3, 'prod-bw101-palm-wax', '掌蜡', '优质100%棕榈蜡，奶油黄色，适用于制作蜡烛。获得RSPO SG（隔离）/MB（质量平衡）认证。', '优质100%棕榈蜡，呈现美丽的奶油黄色。获得RSPO MB认证，彰显可持续性。非常适合制蜡烛、模具工艺和容器蜡烛。', '2026-02-05 22:03:21', '2026-02-11 17:45:10'),
(4, 'prod-bw105-palm-wax', '棕榈起酯（低熔点）', '棕榈起酥是一种半固态、非氢化脂肪，源自分馏棕榈油，具有优越的稳定性和中性风味。', 'Palm Shortening是一种半固态、非氢化脂肪，来自分馏棕榈油，具有优异的稳定性和中性口感。\n非常适合烘焙应用——能制作层层酥脆的糕点、柔软的蛋糕以及高烟点的酥脆炸物。\n在工业烘焙中，既经济实惠又抗氧化的替代黄油或猪油的理想选择。', '2026-02-05 22:07:41', '2026-02-11 17:30:48'),
(5, 'prod-bw10510-blended-wax', '罐装蜡烛用棕榈-石蜡混合蜡', '即用型低微粒度蜡瓶蜡混合物：棕榈蜡-石蜡-微晶蜡，加入Polyboost™、Vybar®、紫外线稳定剂——只需添加颜色和香气，即可实现优异的玻璃附着力和最大扩散效果。', 'Bio Green Wax的低熔点罐装蜡混合物（48-50°C）及（50-52°C）——棕榈-石蜡-微晶配方，专为玻璃容器优化。免调配：只需添加颜色和香味。具备Polyboost/Vybar，用于不透明度和粘附性，UV稳定剂/抗氧化剂延长保质期，以及香味保持剂，提供卓越的热冷燃烧效果，无裂痕燃烧，以及优异的罐体保持性，适用于高端容器蜡烛。', '2026-02-06 03:34:56', '2026-02-11 17:36:55'),
(6, 'prod-bw10555-blended-wax', '大豆基素食蜡混合物', '来自 Bio Green Wax 的即用型 95% 大豆素食混合料——纯植物基，适用于罐装（48-52°C）和柱状（56-62°C）蜡烛。只需添加颜色和香味即可。', 'Bio Green Wax的95%大豆蜡纯素混合物（含5%植物添加剂）为玻璃罐和独立柱提供干净燃烧的天然性能。适用于低熔点（48-52°C）容器蜡和高熔点（56-62°C）柱蜡。即用型：只需添加你的颜色和香料，即可获得出色的香气扩散和光滑的表面。', '2026-02-06 03:42:23', '2026-02-11 17:31:37'),
(7, 'prod-bw10610-blended-wax', '柱式蜡烛用棕榈-石蜡混合蜡', '即用型高熔点柱状蜡混合料（56-58°C 及 58-60°C）：棕榈-石蜡-微晶蜡结合Polyboost™、Vybar®、UV稳定剂——只需添加颜色和香精，即可实现卓越的柱状蜡性能。', 'Bio Green蜡的高熔点柱状蜡烛混合物（56-58°C & 58-60°C）——棕榈-Paraffin-微晶配方，专为自立式柱状蜡烛设计。免调配：仅需添加色料和香料。采用Polyboost/Vybar优化，便于模具脱模和提升不透明度，加入紫外线稳定剂/抗氧化剂以延长保质期，以及香味保持剂，提供卓越的热冷燃烧效果、完美的柱状形状保持和清洁燃烧性能。', '2026-02-06 03:38:42', '2026-02-11 17:37:44'),
(8, 'prod-bw10655-blended-wax', '大豆蜡-蜂蜡-石蜡混合物', '来自Bio Green Wax的即用型豆油-蜂蜡-石蜡混合料——适用于瓶装（48-52°C）和柱状（56-62°C）蜡烛的终极香气散发。只需添加香精和色素。', 'Bio Green Wax 的大豆-蜂蜡-石蜡混合物结合了天然大豆的顺滑、蜂蜡的稳定性以及石蜡的香气激发力，带来无与伦比的香味表现。低熔点（48-52°C）适用于玻璃容器；高熔点（56-62°C）则非常适合制作蜡柱。现成的配方——只需加入香精和色素，即可实现优异的热/冷释香效果与完美的蜡烛表面。', '2026-02-06 03:46:10', '2026-02-11 17:32:26'),
(9, 'prod-bw8307-blended-wax', '椰子-油菜籽蜡混合物', '来自Bio Green Wax的即用型椰子-油菜籽混合蜡——为罐装（48-52°C）和柱状（56-62°C）蜡烛提供丰富自然的表现。只需添加颜色和香味即可。', 'Bio Green Wax的椰子-菜籽混合蜡结合了椰子蜡的奶油质地和菜籽蜡的平滑燃烧，为您带来卓越的天然蜡烛性能。低熔点（48-52°C）经过优化，适用于容器蜡烛；高熔点（56-62°C）适用于柱状蜡烛。完全即用型，只需添加您选择的颜色和香料，即可获得专业、清洁燃烧的效果。', '2026-02-06 03:49:41', '2026-02-11 17:33:16'),
(10, 'prod-carnauba-wax', '巴西棕榈蜡', '高档巴西巴西坚果蜡，用于抛光和涂层', '优质巴西亚蜡，素有“蜡之女王”之称。非常适合汽车抛光、化妆品和食品涂层。自然融点最高。', '2026-02-05 21:59:17', '2026-02-11 17:30:10'),
(11, 'prod-castor-oil', '蓖麻油', '优质冷压蓖麻油，源自Ricnus communis种子，广泛用于医药、化妆品和工业领域。', 'Bio Green Wax 提供高品质的蓖麻油，这是一种多功能的植物油，通过压榨蓖麻植物（Ricinus communis）的种子获得。蓖麻油以其独特的化学成分——富含蓖麻油酸（约85-90%）而闻名，展现出卓越的粘度、润滑性和保湿性能，使其在各行业中都具有重要价值。\n\n我们的蓖麻油经过精心采购和加工，以符合最高的纯度和一致性标准。它有冷榨（原生）和精炼两种等级，适用于制药、化妆品和工业应用。该油的出色稳定性和在酒精中的溶解性使其区别于其他植物油，成为需要优异性能配方中的理想成分。\n\n蓖麻油具有自然生物降解能力，源自可再生资源，符合Bio Green Wax对可持续发展和环境责任的承诺。', '2026-02-11 17:15:49', '2026-02-11 17:15:49'),
(12, 'prod-coconut-oil', '椰子油', '食品和化妆品用的处女椰子油和精炼椰子油', '优质的处女和精炼椰子油，适用于烹饪、烘焙和美容用途。提供多种等级以满足您的特定需求。', '2026-02-05 21:49:22', '2026-02-11 17:16:44'),
(13, 'prod-coconut-wax', '椰子蜡', '椰子蜡是一种来源于椰子油的天然蜡，以其燃烧清洁的蜡烛和环保应用而闻名。', '椰子蜡是一种天然蜡，来自椰子油，以其在制蜡烛时的清洁和缓慢燃烧而闻名。它常被认为是其他蜡的可持续替代品。椰子蜡因其环保特性和良好的香味 hold 能力而备受青睐。它取自自然且可再生的资源，能在蜡烛中实现清洁、缓慢的燃烧，延长使用寿命并提高效率。', '2026-02-11 17:25:31', '2026-02-11 17:25:31'),
(14, 'prod-fr5456-paraffin-wax', '半精炼石蜡（50-68°C）', 'Bio Green Wax 半精炼石蜡（50-68°C）—具有1-5%的油脂含量，经济实惠，适用于蜡烛、橡胶、纺织品及高产量工业应用。', 'Bio Green Wax的半精炼石蜡蜡（50-68°C）以经济实惠的性能著称，油分控制在1-5%，实现柔韧的硬度。标准等级：52/54°C（蜡烛用）、56/58°C（柱状）、60/62°C（工业用）。非常适合成本敏感的蜡烛生产、橡胶加工助剂、纺织整理以及散装包装涂层，在这些应用中，性能与价格的平衡最为关键。', '2026-02-06 04:03:55', '2026-02-11 17:23:22'),
(15, 'prod-glycerine', '甘油', '甘油是一种无色、无味、粘稠的液体，广泛Used in pharmaceutical、cosmetic和食品工业。', '甘油，也称为丙三醇或甘油，是一种无色、无味、粘稠的液体，具有甜味。它是一种清澈、类似糖浆的液体，通常是无色的，尽管有时会带有轻微的黄色色调。甘油具有高粘度，意味着它流动缓慢且相对厚重。它具有糖浆般的稠度，这有助于其保持水分的能力。甘油在药品、化妆品、食品加工以及各种工业应用中得到了广泛的使用。', '2026-02-11 17:19:23', '2026-02-11 17:19:23'),
(16, 'prod-hydrogenated-castor-oil', '氢化蓖麻油', '氢化蓖麻油是一种由蓖麻油衍生的固态蜡状物，广泛用于化妆品、药品和工业应用领域。', '氢化蓖麻油，又称为蓖麻蜡或蓖麻蜡片，是蓖麻油经过氢化工艺处理而得到的衍生物。这一过程涉及将氢气加入到蓖麻油分子中，形成一种固态、蜡状的物质。它广泛应用于化妆品和个人护理产品中，如口红、面霜和乳液，作为一种润肤剂，为肌肤提供柔滑感和水分。它还在化妆品配方中充当黏合剂，帮助成分粘合在一起，并附着于皮肤。', '2026-02-11 17:24:47', '2026-02-11 17:24:47'),
(17, 'prod-microcrystalline-wax', '微晶蜡', '用于化妆品和粘合剂的柔性微晶蜡', '灵活的微晶蜡，适用于化妆品、热熔胶和特殊涂料。具有优异的柔韧性和粘合性能。', '2026-02-06 03:56:43', '2026-02-11 17:22:44'),
(18, 'prod-olive-oil', '橄榄油', '优质纯橄榄油，冷压自精选地中海橄榄，适用于烹饪、化妆品和工业用途。', '我们的优质纯橄榄油采用冷榨方式，从精心挑选的地中海橄榄中提取，品质卓越，风味浓郁。橄榄油广泛用于食品烹饪、化妆品、医药以及个人护理产品中，因其健康益处、抗氧化特性和多用途应用而备受推崇。Bio Green Wax采购的橄榄油符合严格的国际质量标准，确保在所有应用中始终保持纯净与优异的性能。', '2026-02-11 17:41:26', '2026-02-11 17:41:26'),
(19, 'prod-palm-kernel-oil', '棕榈核油', '棕榈仁油源自油棕果实的种仁，广泛用于食品、化妆品和工业应用。', '棕榈仁油由油棕果实的核仁提取，具有独特的物理特性。它在室温下通常呈浅黄色到白色的固体，但加热后会融化成清澈、偏黄色的液体。其熔点范围为23至28摄氏度（73至82华氏度）。棕榈仁油富含月桂酸，广泛用于食品制造、化妆品和肥皂生产中。', '2026-02-11 17:21:16', '2026-02-11 17:21:16'),
(20, 'prod-palm-kernel-olein', '棕榈仁油', '优质精炼棕榈仁油酯，从棕榈仁油分馏获得的液态部分，以其出色的澄清度、低浑浊点以及在食品、个人护理和油脂化工行业中的广泛应用而闻名。', 'Bio Green Wax供应高品质的棕榈仁油甘油（二甘油酯，PKOo），这是通过对精炼棕榈仁油进行受控分馏而产生的液态成分。当在精确条件下冷却棕榈仁油时，会分离出固体成分（棕榈仁硬脂）和液态成分（棕榈仁油甘油）。最终得到的油甘油是一种清澈、浅色的油，具有较低的熔点和优异的流动性。\n\n棕榈仁油甘油富含月桂酸（C12）以及癸酸/辛酸等中链脂肪酸，因而具有出众的透明度、快速吸收性以及轻盈、不油腻的手感。这些特性使其在食品工业中作为食用油、炸制介质以及非乳制奶精、冰淇淋和充填奶制品的原料而备受青睐。\n\n在个人护理与化妆品领域，棕榈仁油甘油被广泛用作乳液、面霜、洗发水和液体皂中的基础油，因其出色的润肤性能和皮肤兼容性。它还作为油脂化工原料的关键原料，生产脂肪酸、甲酯和用于洗涤剂及清洁产品的表面活性剂。\n\nBio Green Wax的棕榈仁油甘油来源于RSPO认证的供应链，确保全程可追溯性，并符合可持续棕榈油承诺。该产品提供精炼、漂白和除臭（RBD）等不同形式，符合严格的国际质量标准。', '2026-02-11 17:45:50', '2026-02-11 17:45:50'),
(21, 'prod-palm-kernel-stearin', '棕櫚仁硬脂', '高品质的棕榈核脂硬脂酸，源自棕榈核油的分馏固体部分，因其迅速融化的特性和优异的硬度而受到赏识，广泛应用于糖果、化妆品和油脂化工行业。', 'Bio Green Wax提供优质的棕榈仁硬脂（PKS），这是通过受控分馏精炼棕榈仁油而产生的高熔点固体分馏物。在分馏过程中，棕榈仁油被分离成两个组分：棕榈仁油酯（液态组分）和棕榈仁硬脂（固态组分）。最终的硬脂呈白色至微白色油脂，具有明显的锐角熔点和坚硬的质感。\n\n棕榈仁硬脂富含月桂酸（C12）和肉豆蔻酸（C14），赋予其优异的硬度、快速结晶能力以及纯净的融化特性。这些特性使其成为可可脂代用品（CBS）、复合巧克力涂层、糖果填充物以及需要脆性和光泽效果的特种脂肪的理想配料。\n\n除了食品应用外，棕榈仁硬脂在油化工业中也是宝贵的原料，用于生产脂肪酸、脂肪醇、肥皂丝和表面活性剂。在个人护理和化妆品领域，它为面霜、乳液和固体制剂提供体感和结构支持。\n\nBio Green Wax的棕榈仁硬脂来自RSPO（可持续棕榈油圆桌会议）认证的供应链，确保完全可追溯性并符合可持续棕榈油承诺。该产品提供精炼、漂白和脱臭（RBD）形式，符合国际食品级和技术级的质量标准。', '2026-02-11 17:20:11', '2026-02-11 17:20:11'),
(22, 'prod-palm-oil', '棕榈油', '可持续采购的棕榈油及其衍生物', '可持续采购的棕榈油及其衍生品，用于食品制造、肥皂和洗涤剂生产。提供RSPO认证的选择。', '2026-02-05 21:50:40', '2026-02-11 17:28:19'),
(23, 'prod-palm-shortenings', '棕榈起酥（高熔点）', '高熔点棕榈起酥（46–52°C）是一种特殊的烘焙和油炸脂肪，由分级棕榈油制成，旨在提供强烈的结构、纯净的风味以及在苛刻工业应用中的优异热稳定性。', '高熔点棕榈起酥油，熔点在46–52°C范围内，由棕榈油脂和中间馏分调配而成，能够提供高固体脂肪含量、坚实的质地以及在常温和高温下稳定的晶体网络。这一较高的熔点范围具有优异的耐热性、抗氧化稳定性，并减少油析出，非常适合热带气候和高温加工线使用。\n\n在烘焙应用中，这些起酥油能够提供良好的充气性、层次感和酥脆感，支撑酥皮派、泡芙、奶油饼干、曲奇和饼干的酥脆结构，即使在温暖条件下也能保持形状和口感。它们还被用作坚固的炸制和面团脂肪，以及在肉制品中替代动物脂肪，其坚实的结构、乳化稳定性以及零反式、非氢化的特性，有助于实现一致的质地、清爽的风味释放以及标签友好的配方。', '2026-02-11 17:27:25', '2026-02-11 17:27:25'),
(24, 'prod-palm-stearic-acid', '棕榈硬脂酸', '棕榈硬脂酸是一种源自棕榈油的饱和脂肪酸，广泛用于化妆品、蜡烛和橡胶制造。', '棕榈硬脂酸是一种由棕榈油提取的脂肪酸，通过分离和结晶脂肪酸的工艺获得。它是一种饱和脂肪酸，因其稳定性和在室温下呈固态而闻名。棕榈硬脂酸具有蜡状外观，颜色从白色到微黄色不等。它的熔点通常在55至70摄氏度（131至158华氏度）之间，使其能够轻松融入各种化妆品、蜡烛和橡胶制品的配方中。', '2026-02-11 17:39:14', '2026-02-11 17:39:14'),
(25, 'prod-palm-stearin', '棕榈硬脂', '棕榈硬脂是棕榈油的固体部分，常用于食品制造、蜡烛生产和肥皂制作。', '棕榈硬脂是通过分馏工艺从棕榈油中提取的固体部分，以其高饱和脂肪酸含量而著称。在室温下为固体，呈奶油白色至淡黄色，质地光滑、蜡质。棕榈硬脂的熔点高于棕榈油。它在食品工业中广泛用于稳定脂肪、生产人造黄油，以及制造蜡烛和肥皂。', '2026-02-11 17:38:31', '2026-02-11 17:38:31'),
(26, 'prod-paraffin-wax', '完全精制石蜡（50-68°C）', 'Bio Green Wax全精炼石蜡（50-68°C）—食品/药品级，油含量<0.5%，硬度优越。非常适合用于蜡烛、化妆品、包装及精密工业应用。', 'Bio Green Wax的全精炼石蜡蜡（熔点为50-68°C）具有超低油含量（<0.5%）、卓越的硬度以及中性的气味和颜色。提供蜡烛级（52/54°C，56/58°C）、容器级（50/52°C）以及高熔点柱形级（64/66°C）。非常适合高端蜡烛、化妆品、食品包装涂层以及需要最大纯度和性能一致性的精密模具制造。', '2026-02-06 03:53:45', '2026-02-11 17:43:07'),
(27, 'prod-pf56-synthetic-wax', '费舍-特罗普什（FT）蜡', '费舍-特罗普斯（FT）蜡是一种高纯度的合成石蜡蜡，从合成气中生产而成，具有较高的熔点、低粘度和优异的硬度，适用于塑料、涂料、油墨、胶粘剂和沥青改性等高要求应用。', 'FT蜡通过费-托反应合成，生成水白色、超净的蜡，具有狭窄的碳链分布、极低的油分含量以及出色的热稳定性。它结合了高软化点、低熔融粘度和强硬度，为多种配方提供优异的抗划痕性、光泽控制、哑光效果和润滑性能。\n\n在塑料和PVC/CPVC加工中，FT蜡充当高效的内外润滑剂和加工助剂，降低熔融粘度，改善流动性，增强模具释出性和尺寸稳定性。它广泛应用于热熔胶和压敏胶、油墨以及工业涂料中，以提高硬度、耐磨耐刮擦性、阻隔性和抗沉淀能力，同时稳定粘度。其他关键应用还包括沥青和防水沥青改性、母料和聚合物复合、橡胶加工、抛光剂、纺织品，甚至化妆品配方中，FT蜡能实现可控的结晶性、改善耐磨和抗皱性能，以及提供细腻顺滑的感觉。', '2026-02-06 04:15:15', '2026-02-11 17:43:56'),
(28, 'prod-pfad', 'PFAD（棕榈油酸缩馏物）', 'PFAD 是棕榈油精炼的副产品，广泛用于肥皂制造、动物饲料和生物燃料生产。', '棕榈脂肪酸馏分（PFAD）是棕榈油精炼过程中的副产品。通过对原棕榈油进行蒸馏去除杂质，以达到更高的纯度。PFAD呈棕黄色液体，具有特定的气味。它含有饱和脂肪酸和不饱和脂肪酸的混合物，主要的脂肪酸为月桂酸、肉豆蔻酸和棕榈酸。PFAD用于肥皂制造、动物饲料和生物燃料生产。', '2026-02-11 17:26:14', '2026-02-11 17:26:14'),
(29, 'prod-pkfad', '棕榈仁脂肪酸精馏物（PKFAD）', 'PKFAD 是棕榈仁油精炼的副产品，富含月桂酸，广泛应用于皂类和油脂化工行业。', '棕榈核脂肪酸馏分（PKFAD）是榨取棕榈核油过程中获得的副产品。它富含脂肪酸，包括月桂酸，因而在某些工业应用中具有价值。PKFAD被广泛用于各种工业领域，包括肥皂制造、生物燃料生产，以及作为油脂化工行业的原材料。', '2026-02-11 17:39:57', '2026-02-11 17:39:57'),
(30, 'prod-polyethylene-wax', '聚乙烯蜡（PE蜡）', '是一种低分子量聚乙烯，作为塑料、涂料、油墨和胶粘剂中的高性能润滑剂和加工助剂，改善流动性、表面滑移性和抗刮擦性能。', '聚乙烯蜡是一种细微分布、高熔点的合成蜡，具有低粘度、优异的热稳定性和与PVC、PE、PP及EVA等常见聚合物的良好相容性。它提供内部和外部润滑，降低熔体粘度和摩擦，增强模具释放效果，并呈现光滑、光亮且抗划伤的表面。  \n\n主要应用包括塑料和母料加工，其中PE蜡提升挤出和注塑效率，防止模具粘结，并改善颜料和填料的分散性。它还用于热熔胶和压力敏感胶黏剂、油墨及粉末涂层，以控制熔融粘度、增强内聚力和韧性，以及优化开口和固化时间。其他用途涉及沥青和道路标线漆、木塑复合材料、橡胶混合物、电缆料和成品蜡制品，如抛光剂和蜡笔，提升软化点、硬度和防水性能。', '2026-02-06 04:00:25', '2026-02-11 17:42:12'),
(31, 'prod-rapeseed-oil', '菜籽油', '来自英国农场的冷榨和精炼菜籽油', '来自英国农场的冷榨和精炼油菜籽油。非常适合烹饪、烘焙和沙拉调料。饱和脂肪含量低，富含欧米伽-3。', '2026-02-05 21:50:40', '2026-02-11 17:34:02'),
(32, 'prod-rapeseed-wax', '油菜籽蜡', '菜籽蜡是一种天然植物蜡，作为一种环保的替代品，广泛用于蜡烛制作和化妆品。', '菜籽蜡是一种天然植物蜡，来源于油菜植物的油脂，常被用作传统石蜡蜡的环保替代品，广泛应用于蜡烛制作和其他领域。它燃烧干净且缓慢，具有良好的香味保持性。菜籽蜡常用于蜡烛生产，以及天然化妆品的配方中，如润唇膏、乳液和面霜，具有保湿作用。', '2026-02-11 17:24:06', '2026-02-11 17:24:06'),
(33, 'prod-soap-noodles', '皂基面条', '皂条是制造肥皂的主要原料，通过植物油和脂肪的皂化反应生成。', '皂粉，也称为皂粒，是制造肥皂的主要原料之一。它们通过用氢氧化钠（苛性苏打）对植物油脂进行皂化处理生产而成。皂粉通常是固体的白色或象牙色块状或珠状物，具有淡雅中性的香气。它们纯净无杂质，含有高浓度的脂肪酸，有助于其清洁和乳化性能。', '2026-02-11 17:40:40', '2026-02-11 17:40:40'),
(34, 'prod-soy-wax', '大豆蜡', '大豆蜡是一种由大豆油制成的可再生植物蜡，因其环保特性而在蜡烛制作中颇受欢迎。', '大豆蜡是一种由大豆油提取的植物蜡。它是传统石蜡的常用替代品，石蜡来自石油。大豆蜡被认为是一种可再生、可生物降解且环保的蜡烛制作材料。它通过加氢处理大豆油，将其转化为适合制作蜡烛的固体形态。大豆蜡通常呈片状，易于测量和融化。', '2026-02-11 17:17:21', '2026-02-11 17:17:21'),
(35, 'prod-soybean-oil', '大豆油', '高质量工业用和烹饪用大豆油', '大豆油是一种多用途的植物油，取自大豆，由于其中性味道和高烟点，广泛用于煎炸、烘焙和沙拉调料。它富含多不饱和脂肪，包括Omega-3和Omega-6脂肪酸，并提供维生素K和维生素E。它非常适合深炸、马铃薯人造黄油生产以及工业食品应用。经过精炼和除臭，达到优质标准。', '2026-02-05 21:50:40', '2026-02-11 17:28:56'),
(36, 'prod-sunflower-oil', '葵花籽油', '优质精炼向日葵籽油，用于烹饪和食品加工', '我们的优质精炼葵花籽油适用于烹饪、油炸和食品加工。采用优质葵花籽原料，经过最高标准的精炼工艺。', '2026-02-05 21:42:06', '2026-02-11 17:22:03');
INSERT INTO `product_categories` (`id`, `slug`, `name`, `description`, `display_order`, `is_active`, `synchronized_data`, `created_at`) VALUES
('cat-edible-oils', 'edible-oils', 'Edible Oils', 'Premium refined edible oils for cooking and food processing', 1, 1, 1, '2026-02-05 21:03:49'),
('cat-industrial-waxes', 'industrial-waxes', 'Industrial Waxes', 'Industrial-grade paraffin and specialty waxes', 3, 1, 1, '2026-02-05 21:03:49'),
('cat-oleochemicals', 'oleochemicals', 'Oleochemicals', 'Plant based oils and fats/waxes and animal based oils and fats derived products through processes like hydrolysis and transesterification. These versatile chemicals find applications in various industries, including soap and detergent manufacturing, cosmetics, pharmaceuticals, and biofuels.', 5, 1, 1, '2026-02-09 04:38:30'),
('cat-plant-waxes', 'plant-based-waxes', 'Plant-Based Waxes', 'Natural plant-based waxes for candles, cosmetics and more', 2, 1, 1, '2026-02-05 21:03:49'),
('cat-wax-blends', 'wax-blends', 'Wax Blends', 'Custom wax blends for specialized applications', 4, 1, 1, '2026-02-05 21:03:49');
INSERT INTO `product_categories_ar` (`id`, `master_id`, `name`, `description`, `created_at`, `updated_at`) VALUES
(1, 'cat-edible-oils', 'زيوت صالحة للأكل', 'زيوت طهي وتكرير عالية الجودة للاستخدام في الطهي والمعالجة الغذائية', '2026-02-06 04:35:17', '2026-02-09 03:29:53'),
(2, 'cat-industrial-waxes', 'شمعات صناعية', 'شمع البارافين الصناعي الدرجة والتخصص', '2026-02-06 04:38:54', '2026-02-09 03:30:33'),
(3, 'cat-oleochemicals', 'الوليوكيميائيات', 'الزيوت والدهون/الشمع المستندة إلى النبات والمنتجات المستخرجة من الزيوت والدهون المستندة إلى الحيوانات من خلال عمليات مثل التحلل المائي والتحويل الاستيريفي. وتستخدم هذه المواد الكيميائية المتعددة الاستخدامات في صناعات مختلفة، بما في ذلك صناعة الصابون والمنظفات، ومستحضرات التجميل، والأدوية، والوقود الحيوي.', '2026-02-09 17:03:31', '2026-02-09 17:03:31'),
(4, 'cat-plant-waxes', 'شموع نباتية', 'شموع طبيعية نباتية، وشموع ومواد تجميل والمزيد', '2026-02-06 04:37:03', '2026-02-09 03:30:13'),
(5, 'cat-wax-blends', 'خلطات الشمع', 'مزيجات الشموع المخصصة للتطبيقات المتخصصة', '2026-02-06 04:40:45', '2026-02-09 03:30:54');
INSERT INTO `product_categories_de` (`id`, `master_id`, `name`, `description`, `created_at`, `updated_at`) VALUES
(1, 'cat-edible-oils', 'Essigbare Speiseöle', 'Premium raffinierte Speiseöle für Kochen und Lebensmittelverarbeitung', '2026-02-06 04:35:36', '2026-02-09 03:29:57'),
(2, 'cat-industrial-waxes', 'Industrielle Wachse', 'Industrielle Paraffine und Spezialwachse', '2026-02-06 04:39:10', '2026-02-09 03:30:38'),
