(2, 'cat-industrial-waxes', '工业蜡', '工业级石蜡和特殊蜡', '2026-02-06 04:38:32', '2026-02-09 03:30:30'),
(3, 'cat-oleochemicals', '脂肪化学品', '植物性油脂和蜡以及动物性油脂衍生产品通过水解和酯交换等工艺制成。这些多功能化学品在多个行业中广泛应用，包括肥皂和洗涤剂制造、化妆品、制药以及生物燃料。', '2026-02-09 17:03:26', '2026-02-09 17:03:26'),
(4, 'cat-plant-waxes', '植物基蜡', '天然植物蜡，用于蜡烛、化妆品及其他产品', '2026-02-06 04:36:39', '2026-02-09 03:30:09'),
