INSERT INTO `sectors` (`id`, `name`, `slug`, `description`, `icon`, `color`, `image_url`, `display_order`, `is_active`, `synchronized_data`, `created_at`) VALUES
('sec-001', 'Candle Making', 'candle-making', 'Complete Wax Solutions for Candle Manufacturing\nPremium Natural/Plant-Based Waxes (Soy, Palm, Rapeseed, coconut, Beeswax) and Petroleum Waxes (fully/semi-refined paraffin 52-68°C, microcrystalline) for all candle types.\n\nReady-to-Use Wax Blends: Melt directly—no additives needed—for perfect pillar, votive, or container candles with superior scent throw and burn.', 'Flame', NULL, '/uploads/sectors/sec-001.jpg', 0, 1, 1, '2026-02-05 21:03:49'),
('sec-002', 'Cosmetics', 'cosmetics', 'Premium Vegetable Waxes for Cosmetics Manufacturing\n\nHigh-quality natural vegetable waxes including Sunflower wax, Rapeseed wax, Palm wax, Beeswax, Carnauba wax, Candelilla wax, Rice bran wax, Soy wax, Castor wax, Olive wax, Avocado wax, Hemp wax, Berry wax (Rhus verniciflua), and Myrica fruit wax for creams, lipsticks, and skincare.\n\nPerfect emollients, thickeners, and stabilizers delivering smooth texture and superior performance.', 'Sparkles', NULL, '/uploads/sectors/sec-002.jpg', 0, 1, 1, '2026-02-05 21:03:49'),
('sec-003', 'Food & Beverage', 'food', 'Premium Edible Oils & Fats for Food Manufacturing\n\nFully refined edible oils (palm, soy, sunflower, rapeseed, olive, coconut), stearins (palm, soy), and shortenings for bakery, confectionery, and frying applications.\n\nHigh-stability, neutral flavor solutions ensuring consistent texture, extended shelf life, and superior performance across food processing needs.', 'Utensils', NULL, '/uploads/sectors/sec-003.jpg', 0, 1, 1, '2026-02-05 21:03:49'),
('sec-004', 'Pharmaceuticals', 'pharmaceuticals', 'Premium Ingredients for Pharmaceutical Manufacturing\n\nPharma-grade vegetable waxes including Beeswax (BP/Ph.Eur), Carnauba wax, Candelilla wax, Rice bran wax, Sunflower wax, Rapeseed wax, Palm wax, Castor wax, Soy wax, Olive wax, and Hydrogenated vegetable oils for ointments, creams, and suppositories.\n\nHigh-purity, pharmacopoeia-compliant solutions ensuring stability, smooth texture, and consistent drug release in topical and oral formulations.', 'Pill', NULL, '/images/sectors/pharmaceuticals.webp', 0, 1, 1, '2026-02-05 21:03:49'),
('sec-005', 'Textiles & Leather', 'textiles', 'High-performance vegetable waxes including Carnauba wax, Candelilla wax, Rice bran wax, Sunflower wax, Rapeseed wax, Palm wax, Beeswax, Soy wax, plus paraffin waxes and emulsions for fabric finishing, leather treatment, and waterproofing.\n\nSuperior lubrication, water repellency, and abrasion resistance for improved sewability, tear strength, and processing efficiency in textile manufacturing and leather processing.', 'Shirt', NULL, '/images/sectors/textiles-leather.webp', 0, 1, 1, '2026-02-05 21:03:49'),
('sec-006', 'Rubber & Plastics', 'rubber-plastics', 'Fully refined paraffin waxes, microcrystalline waxes, slack wax, and PE waxes optimized for tire production, plastic processing, and rubber compounding.\n\nSuperior lubricants, release agents, and dispersion aids ensuring smooth extrusion, injection molding, calendering, and demolding with excellent surface finish and processing efficiency.', 'Factory', NULL, '/images/sectors/rubber-plastics.webp', 0, 1, 1, '2026-02-05 21:03:49'),
('sec-007', 'Packaging', 'packaging', 'Fully refined paraffin waxes, microcrystalline waxes, slack wax, PE waxes, plus natural carnauba wax and beeswax for paper coating, boxboard lamination, and flexible packaging production.\n\nSuperior waterproofing, grease resistance, and release properties ensuring durable moisture barriers, food-safe coatings, and efficient heat-seal performance across corrugated, folding cartons, and flexible films.', 'Package', NULL, '/images/sectors/packaging.webp', 0, 1, 1, '2026-02-05 21:03:49'),
('sec-008', 'Adhesives', 'adhesives', 'Fully refined paraffin waxes, microcrystalline waxes, slack wax, PE waxes, carnauba wax, and beeswax as high-performance additives for coatings, inks, laminates, and emulsions.\n\nEnhance scratch resistance, moisture barrier, anti-block, COF reduction, and release properties for superior corrugated board, paperboard, and flexible packaging performance.', 'Layers', NULL, '/images/sectors/adhesives.webp', 0, 1, 1, '2026-02-05 21:03:49'),
('sec-009', 'Polishes & Coatings', 'polishes-coatings', 'Fully refined paraffin waxes, microcrystalline waxes, carnauba wax, and beeswax for high-gloss floor polishes, furniture care, automotive coatings, and industrial surface protection.\n\nExceptional abrasion resistance, buffability, and shine delivering long-lasting protection and professional finish across wood, metal, leather, and composite surfaces.', 'Sparkle', NULL, '/images/sectors/polishes-coatings.webp', 0, 1, 1, '2026-02-05 21:03:49'),
('sec-010', 'Paper & Printing', 'paper-printing', 'Fully refined paraffin waxes, microcrystalline waxes, carnauba wax, beeswax, and synthetic waxes for paper coating, ink rubbing resistance, and release applications.\n\nSuperior moisture barrier, anti-stick properties, and print enhancement ensuring high-quality surface protection, excellent ink adhesion, and efficient processing for packaging papers and specialty printing.', 'FileText', NULL, '/images/sectors/paper-printing.webp', 0, 1, 1, '2026-02-05 21:03:49');
INSERT INTO `sectors_ar` (`id`, `master_id`, `name`, `description`, `created_at`, `updated_at`) VALUES
(1, 'sec-001', 'صناعة الشموع', 'حلول الشمع الكاملة لتصنيع الشموع  \nشموع طبيعية/نباتية ممتازة (فsoy، نخيل، دوار الشمس، جوز الهند، شمع العسل) وشموع البترول (بارافين مكرر/نصف مكرر 52-68 درجة مئوية، ميكروكريستالين) لجميع أنواع الشمع.\n\nخليط شمع جاهز للاستخدام: يذوب مباشرة—بدون الحاجة إلى إضافات—لشاوي عمودية، فويفوية، أو حاوية مع انبعاث رائحة ممتاز واحتراق مثالي.', '2026-02-06 04:42:48', '2026-02-11 17:06:06'),
(2, 'sec-002', 'مستحضرات التجميل', 'شموع نباتية فاخرة لصناعة المستحضرات التجميلية\n\nشموع نباتية طبيعية عالية الجودة تشمل شمعة عباد الشمس، شمعة البازلاء، شمعة النخيل، شمع العسل، شمعة الكربونة، شمعة الكندليا، شمعة نخالة الأرز، شمعة فول الصويا، شمعة الخروع، شمعة الزيتون، شمعة الأفوكادو، شمعة القنب، شمعة التوت (Rhus verniciflua)، وشمع فاكهة ميركا لمستحضرات الكريمات وأحمر الشفاه والعناية بالبشرة.\n\nمرطبات، مثخنات، ومثبتات مثالية توفر قوامًا ناعمًا وأداءً فائقًا.', '2026-02-06 04:44:29', '2026-02-11 17:06:36'),
(3, 'sec-003', 'الأطعمة والمشروبات', 'زيوت ودهون صالحة للأكل عالية الجودة لصناعة الأغذية\n\nزيوت صالحة للأكل مكررة بالكامل (النخيل، الصويا، عباد الشمس، اللفت، الزيتون، جوز الهند)، وسيريتينات (النخيل، الصويا)، ودهون مخبوزة للاستخدام في المخبوزات، والحلويات، والقلي.\n\nحلول ذات استقرار عالي ونكهة محايدة تضمن قوامًا متسقًا، عمر افتراضي ممتد، وأداء متفوق في جميع احتياجات معالجة الأغذية.', '2026-02-06 04:46:03', '2026-02-11 17:07:06'),
(4, 'sec-004', 'الأدوية', 'مكونات فاخرة لصناعة الأدوية\n\nشمعات نباتية بدرجة فارما بما في ذلك شمع العسل (BP/Ph.Eur)، شمع الكارنوبا، شمع الكندليلا، شمع نخالة الأرز، شمع عباد الشمس، شمع اللفت، شمع النخيل، شمع الخروع، شمع الصويا، شمع الزيتون والزيوت النباتية المهدرجة للمراهم والكريمات والتحاميل.\n\nحلول ذات نقاء عالٍ ومتوافقة مع الهيئة الدوائية، تضمن الثبات، الملمس الناعم، وإطلاق الدواء بشكل منتظم في التركيبات الموضعية والفموية.', '2026-02-06 04:47:39', '2026-02-11 17:07:37'),
(5, 'sec-005', 'المنسوجات والجلود', 'شمعات الخضروات عالية الأداء بما في ذلك شمع كارnauba، شمع كانديليا، شمع نخالة الأرز، شمع عباد الشمس، شمع بذور اللفت، شمع النخيل، شمع العسل، شمع الصويا، بالإضافة إلى شمعات البارافين والاستحلابات المستخدمة في تشطيب الأقمشة، ومعالجة الجلود، ومانعة التسرب للماء.\n\nتوفير تزييت فائق، ومقاومة للماء، ومقاومة للاهتراء لتحسين قابلية الخياطة، وقوة التمزق، وكفاءة المعالجة في تصنيع المنسوجات ومعالجة الجلود.', '2026-02-06 04:49:17', '2026-02-11 17:08:10'),
(6, 'sec-006', 'مطاط والبلاستيك', 'شمع البارافين المكرر بالكامل، وشموع الميكروكريستالين، وشمع السلاك، وشموع PE المثلى لإنتاج الإطارات، ومعالجة البلاستيك، وخلطات المطاط.\n\nزيوت التزليق الفائقة، والعوامل المفرغة، وأنواع المساعدة في التشتت التي تضمن عملية بكرات سلسة، والحقن بالبلاستيك، والكرناء، وإزالة القوالب مع تشطيب سطحي ممتاز وكفاءة عالية في المعالجة.', '2026-02-06 04:51:11', '2026-02-11 17:08:39'),
(7, 'sec-007', 'التعبئة والتغليف', 'شمع البارافين المكرر بشكل كامل، وشمع الميكروكريستالين، وشمع السلاك، وشموع البوليثيلين (PE)، بالإضافة إلى شمع الكارنيوبا الطبيعي وشمع العسل للتغطية بالورق، وتبطين الصناديق، وإنتاج التغليف المرن.\n\nخصائص ممتازة من حيث مقاومة الماء، ومقاومة الدهون، وسهولة الانزلاق، مما يضمن حواجز فعالة ضد الرطوبة، وتلك المكونة للاستخدام في تغطيات الطعام، وأداء فعال في الختم الحراري عبر الكرافت، والصناديق القابلة للطي، والأغشية المرنة.', '2026-02-06 04:53:08', '2026-02-11 17:09:10'),
(8, 'sec-008', 'لاصقات', 'شمع البرافين المكرر بالكامل، وشموع الميكروكريستالين، وشمع السلاك، وشموع PE، وشمع الكارنوبا، وشمع العسل كمضافات عالية الأداء للطلاءات، والأحبار، واللامينيت، والمستحلبات.\n\nعزز مقاومة الخدش، وحاجز الرطوبة، ومقاومة التآزر، وتقليل معامل الاحتكاك، وخصائص الإطلاق لضمان أداء متفوق لللوح المموج، والورق المقوى، والتغليف المرن.', '2026-02-06 04:54:49', '2026-02-11 17:09:42'),
(9, 'sec-009', 'التلميع والطلاءات', 'شعيرات البرافين المكررة بالكامل، شمع الميكروليني، شمع الكربونوبا، وشمع العسل لطلاءات الأرضيات عالية اللمعان، العناية بالأثاث، الطلاءات السيارات، والحماية الصناعية للأسطح.\n\nمقاومة استثنائية للتآكل، وسهولة التلميع، ولمعان يوفر حماية طويلة الأمد وتشطيب احترافي عبر الأسطح الخشبية والمعادن والجلود والمواد المركبة.', '2026-02-06 04:57:01', '2026-02-11 17:10:12'),
(10, 'sec-010', 'الورق والطباعة', 'شمع البارافين المكرر بالكامل، والشمع البلوري الدقيق، وشمع الكربونة، وشمع العسل، والشمع الصناعي لتغليف الورق، ومقاومة فرك الحبر، وتطبيقات الإفراج.\n\nحاجز رطوبة متفوق، وخصائص مقاومة الالتصاق، وتحسين الطباعة، مما يضمن حماية عالية الجودة للسطح، وارتباط ممتاز للحبر، ومعالجة فعالة لورق التعبئة والطباعة الخاصة.', '2026-02-06 04:59:23', '2026-02-11 17:05:36');
INSERT INTO `sectors_de` (`id`, `master_id`, `name`, `description`, `created_at`, `updated_at`) VALUES
(1, 'sec-001', 'Kerzenherstellung', 'Vollständige Wachslösungen für die Kerzenherstellung\nPremium natürlich/ Pflanzliche Wachse (Soja, Palm, Raps, Kokos, Bienenwachs) und Erdölwachse (vollständig/semi-raffiniertes Paraffin 52-68°C, Mikrokristallin) für alle Kerzenarten.\n\nFertige Wachsformulierungen: Direkt schmelzen—keine Zusätze erforderlich—for perfekte Säulen-, Votiv- oder Glasgefäßenkerzen mit hervorragender Duftverteilung und Brennqualität.', '2026-02-06 04:43:04', '2026-02-11 17:06:11'),
(2, 'sec-002', 'Kosmetik', 'Premium-Gemüsewachse für die Kosmetikherstellung\n\nHochwertige natürliche Gemüsewachse, darunter Sonnenblumenwachs, Rapswachs, Palmenwachs, Bienenwachs, Carnaubawachs, Candelillawachs, Reiskleie-Wachs, Sojawachs, Rizinuswachs, Olivenwachs, Avocado-Wachs, Hanfwachs, Beerwachs (Rhus verniciflua) und Myrtenfruchtwachs für Cremes, Lippenstifte und Hautpflege.\n\nPerfekte Emollients, Verdickungsmittel und Stabilisatoren, die eine geschmeidige Textur und überlegene Leistung gewährleisten.', '2026-02-06 04:44:45', '2026-02-11 17:06:41'),
(3, 'sec-003', 'Nahrung & Getränke', 'Premium Essbare Öle & Fette für die Lebensmittelherstellung\n\nVollständig raffinierte essbare Öle (Palm, Soja, Sonnenblume, Raps, Olivenöl, Kokosnuss), Stearine (Palm, Soja) und Fette für Backwaren, Süßwaren und Frittieren.\n\nHochstabile, neutral schmeckende Lösungen, die eine gleichbleibende Textur, verlängerte Haltbarkeit und überlegene Leistung in der Lebensmittelverarbeitung gewährleisten.', '2026-02-06 04:46:23', '2026-02-11 17:07:12'),
(4, 'sec-004', 'Arzneimittel', 'Premium-Zutaten für die pharmazeutische Herstellung\n\nPharma-Qualitäts-Gemüsewachse, einschließlich Bienenwachs (BP/Ph.Eur), Carnaubawachs, Candelillawachs, Reiskleiewachs, Sonnenblumenwachs, Rapswachs, Palmwachs, Rizinuswachs, Sojawachs, Olivenwachs und hydrierte pflanzliche Öle für Salben, Cremes und Suppositorien.\n\nHochreine, pharmazeutikawissenschaftlich konforme Lösungen, die Stabilität, eine glatte Textur und eine gleichmäßige Wirkstofffreisetzung in topischen und oralen Formulierungen gewährleisten.', '2026-02-06 04:48:01', '2026-02-11 17:07:43'),
(5, 'sec-005', 'Stoffe & Leder', 'Hochleistungs-Gemüsetherwaxen, einschließlich Carnaubawachs, Candelillawachs, Reiskernwachs, Sonnenblumenwachs, Rapswachs, Palmenwachs, Bienenwachs, Sojawachs sowie Paraffinwachs und -emulsionen für Stoffbehandlungen, Lederpflege und Wasserdichtigkeit.\n\nHervorragende Schmierfähigkeit, Wasserabweisung und Abriebfestigkeit für verbesserte Nahtbarkeit, Reißfestigkeit und Verarbeitungseffizienz in der Textilherstellung und Lederverarbeitung.', '2026-02-06 04:49:36', '2026-02-11 17:08:15'),
(6, 'sec-006', 'Gummi & Kunststoffe', 'Vollständig raffinierte Paraffinwachse, Mikrocrystalline-Wachse, Slack-Wachs und PE-Wachse, optimiert für die Reifenherstellung, Kunststoffverarbeitung und Gummi-Compoundierung.\n\nHochwertige Schmierstoffe, Entformmittel und Dispergierhilfsmittel, die eine reibungslose Extrusion, Spritzgießen, Kalanderung und Entformung mit hervorragender Oberflächenqualität und Verarbeitungseffizienz gewährleisten.', '2026-02-06 04:51:33', '2026-02-11 17:08:46'),
(7, 'sec-007', 'Verpackung', 'Vollständig raffinierte Paraffinkwachs, Mikrocrystallines Wachs, Slack Wachs, PE-Wachs sowie natürliches Carnaubawachs und Bienenwachs für die Papierbeschichtung, Wellpapplaminierung und die Produktion flexibler Verpackungen.\n\nHervorragende Wasserdichtigkeit, Fettresistenz und Trenneigenschaften, die langlebige Feuchtigkeitsbarrieren, lebensmittelechte Beschichtungen und eine effiziente Heißversiegelung bei Wellpappe, Faltschachteln und flexiblen Folien gewährleisten.', '2026-02-06 04:53:23', '2026-02-11 17:09:18'),
(8, 'sec-008', 'Klebstoffe', 'Vollständig raffiniertes Paraffinwachs, Mikrokristallwachs, Slack-Wachs, PE-Wachs, Carnaubawachs und Bienenwachs als Hochleistungs-additive für Beschichtungen, Tinten, Laminierungen und Emulsionen.\n\nVerbessern Sie Kratzfestigkeit, Feuchtigkeitsbarriere, Anti-Block, COF-Reduzierung und Freigabeeigenschaften für eine überlegene Leistung bei Wellpappe, Karton und flexiblem Verpackungsmaterial.', '2026-02-06 04:55:09', '2026-02-11 17:09:48'),
(9, 'sec-009', 'Polieren & Beschichtungen', 'Vollständig raffinierte Parafinwachse, Mikrocrystalline Wachse, Carnaubawachs und Bienenwachs für Hochglanz-Fußbodenpolituren, Möbelpflege, Automobillackierungen und industrielle Oberflächenschutzmaßnahmen.\n\nAußergewöhnliche Abriebfestigkeit, Polierbarkeit und Glanz, die langanhaltenden Schutz und professionelles Finish auf Holz-, Metall-, Leder- und Verbundoberflächen bieten.', '2026-02-06 04:57:34', '2026-02-11 17:10:18'),
(10, 'sec-010', 'Papier & Druck', 'Vollständig raffinierte Paraffinwachsarten, Mikrocrystallines Wachs, Carnauba-Wachs, Bienenwachs und synthetische Wachse für Papierbeschichtungen, Tintentransferbeständigkeit und Entlarrvorrichtungen.\n\nHervorragende Feuchtigkeitsbarriere, Antihaft-Eigenschaften und Druckverbesserung, die eine hochwertige Oberflächenschutz, exzellente Tintenhaftung und effiziente Verarbeitung für Verpackungspapiere und Spezialdrucke gewährleisten.', '2026-02-06 04:59:43', '2026-02-11 17:05:42');
INSERT INTO `sectors_es` (`id`, `master_id`, `name`, `description`, `created_at`, `updated_at`) VALUES
(1, 'sec-001', 'Fabricación de velas', 'Soluciones completas de cera para la fabricación de velas\nCeras naturales y vegetales de primera calidad (soja, palma, colza, coco, cera de abeja) y ceras de petróleo (parafinas completamente o semi-refinadas a 52-68°C, microcristalinas) para todo tipo de velas.\n\nMezclas de cera listas para usar: fundir directamente—sin necesidad de aditivos—para velas de pilar, votivas o en contenedores, con una capacidad superior de difusión del aroma y una combustión perfecta.', '2026-02-06 04:42:32', '2026-02-11 17:06:02'),
(2, 'sec-002', 'Cosméticos', 'Ceras vegetales premium para la fabricación de cosméticos\n\nCeras vegetales naturales de alta calidad, incluyendo cera de girasol, cera de colza, cera de palma, cera de abejas, cera de carnauba, cera de candelilla, cera de salvado de arroz, cera de soja, cera de ricino, cera de oliva, cera de aguacate, cera de cáñamo, cera de baya (Rhus verniciflua) y cera de fruta de Myrica para cremas, barras de labios y cuidado de la piel.\n\nEmolientes, espesantes y estabilizadores perfectos que ofrecen una textura suave y un rendimiento superior.', '2026-02-06 04:44:15', '2026-02-11 17:06:32'),
(3, 'sec-003', 'Alimentos y Bebidas', 'Aceites y grasas comestibles premium para la fabricación de alimentos\n\nAceites comestibles totalmente refinados (palma, soja, girasol, colza, oliva, coco), estearinas (palma, soja) y shortenings para aplicaciones en panadería, confitería y frituras.\n\nSoluciones de alta estabilidad y sabor neutral que garantizan una textura consistente, una vida útil prolongada y un rendimiento superior en las necesidades de procesamiento de alimentos.', '2026-02-06 04:45:46', '2026-02-11 17:07:02'),
(4, 'sec-004', 'Farmacéuticos', 'Ingredientes Premium para Fabricación Farmacéutica\n\nCeras vegetales de grado farmacéutico, incluyendo Cera de abejas (BP/Ph.Eur), cera de carnauba, cera de candelilla, cera de salvado de arroz, cera de girasol, cera de colza, cera de palma, cera de ricino, cera de soja, cera de oliva y aceites vegetales hidrogenados para ungüentos, cremas y suppositorios.\n\nSoluciones de alta pureza, en cumplimiento con la farmacopea, que garantizan estabilidad, textura suave y liberación constante del medicamento en formulaciones tópicas y orales.', '2026-02-06 04:47:28', '2026-02-11 17:07:33'),
(5, 'sec-005', 'Textiles y Cuero', 'Ehigh-performance vegetale ceras, incluyendo cera de Carnauba, cera de Candelilla, cera de salvado de arroz, cera de girasol, cera de colza, cera de palma, cera de abejas, cera de soja, además de ceras y emulsiones de parafina para el acabado de tejidos, tratamiento de cuero y impermeabilización.\n\nLubricación superior, repelencia al agua y resistencia a la abrasión para una mejorabilidad, resistencia a roturas y eficiencia en el procesamiento en la fabricación textil y el tratamiento del cuero.', '2026-02-06 04:49:03', '2026-02-11 17:08:06'),
(6, 'sec-006', 'Caucho y Plásticos', 'Ceras de parafina completamente refinadas, ceras microcristalinas, cera de recorte y ceras PE optimizadas para la producción de neumáticos, procesamiento de plásticos y compounding de caucho.\n\nLubricantes superiores, agentes de liberación y auxiliares de dispersión que aseguran una extrusión, moldeo por inyección, calandrado y desmoldeo suaves, con un acabado superficial excelente y eficiencia en el procesamiento.', '2026-02-06 04:50:52', '2026-02-11 17:08:35'),
(7, 'sec-007', 'Embalaje', 'Ceras de parafina totalmente refinadas, ceras microcristalinas, cera de residuo, ceras PE, además de cera de carnauba natural y cera de abeja para recubrimiento de papel, laminación de cartón y producción de envases flexibles.\n\nPropiedades superiores de impermeabilidad, resistencia a grasas y liberación que garantizan barreras contra la humedad duraderas, recubrimientos aptos para alimentos y un rendimiento eficiente en sellado térmico en cartón corrugado, cajas plegables y films flexibles.', '2026-02-06 04:52:57', '2026-02-11 17:09:06'),
(8, 'sec-008', 'Adhesivos', 'Ceras de parafina totalmente refinadas, ceras microcristalinas, cera de desmoldar, ceras PE, cera de carnauba y cera de abejas como aditivos de alto rendimiento para recubrimientos, tintas, laminados y emulsiones.\n\nMejoran la resistencia a los arañazos, la barrera contra la humedad, las propiedades antiadherentes, la reducción del COF y las propiedades de liberación para un rendimiento superior en cartón corrugado, cartón ondulado y envases flexibles.', '2026-02-06 04:54:30', '2026-02-11 17:09:38'),
(9, 'sec-009', 'Pulidos y recubrimientos', 'Ceras de parafina completamente refinadas, ceras microcristalinas, cera de carnauba y cera de abeja para pulimentos de alto brillo, cuidado de muebles, recubrimientos automotrices y protección de superficies industriales.\n\nExcepcional resistencia a la abrasión, capacidad de pulido y brillo que ofrecen protección duradera y acabado profesional en superficies de madera, metal, cuero y compuestos.', '2026-02-06 04:56:41', '2026-02-11 17:10:07'),
(10, 'sec-010', 'Papel y Impresión', 'Parafinas totalmente refinadas, ceras microcristalinas, cera de carnauba, cera de abeja y ceras sintéticas para recubrimiento de papel, resistencia al rozado de tinta y aplicaciones de liberación.\n\nExcelente barrera contra la humedad, propiedades antiadherentes y mejora de impresión que garantizan una protección de superficie de alta calidad, una excelente adhesión de tinta y un procesamiento eficiente para papeles de embalaje e impresión especializada.', '2026-02-06 04:59:08', '2026-02-11 17:05:32');
INSERT INTO `sectors_fr` (`id`, `master_id`, `name`, `description`, `created_at`, `updated_at`) VALUES
(1, 'sec-001', 'Fabrication de bougies', 'Solutions complètes de cires pour la fabrication de bougies\nCires naturelles/à base de plantes de qualité premium (soja, palme, colza, noix de coco, cire d\'abeille) et cires minérales (paraffine entièrement/semi-refinée à 52-68°C, microcristalline) pour tous types de bougies.\n\nMélanges de cires prêts à l\'emploi : fondre directement — aucun additif nécessaire — pour des bougies en pilier, votives ou en contenant avec une diffusion de parfum et une combustion exceptionnelles.', '2026-02-06 04:42:37', '2026-02-11 17:06:04'),
(2, 'sec-002', 'Cosmétiques', 'Cires végétales premium pour la fabrication de cosmétiques\n\nCires végétales naturelles de haute qualité, notamment cire de tournesol, cire de colza, cire de palme, cire d\'abeille, cire de carnauba, cire de candelilla, cire de son de riz, cire de soja, cire de ricin, cire d\'olive, cire d\'avocat, cire de chanvre, cire de baie (Rhus verniciflua) et cire de fruits de Myrica pour crèmes, rouges à lèvres et soins de la peau.\n\nEmollients parfaits, épaississants et stabilisants offrant une texture lisse et des performances supérieures.', '2026-02-06 04:44:18', '2026-02-11 17:06:34'),
(3, 'sec-003', 'Alimentation & Boissons', 'Huiles et graisses comestibles de qualité premium pour la fabrication alimentaire\n\nHuiles comestibles entièrement raffinées (palm, soja, tournesol, rapeseed, olive, noix de coco), stéarines (palm, soja) et shortenings pour la boulangerie, la confiserie et la friture.\n\nSolutions à haute stabilité et saveur neutre garantissant une texture constante, une durée de conservation prolongée et des performances supérieures dans tous les processus de transformation des aliments.', '2026-02-06 04:45:55', '2026-02-11 17:07:04'),
(4, 'sec-004', 'Produits pharmaceutiques', 'Ingrédients de qualité Premium pour la fabrication pharmaceutique\n\nCires végétales de qualité pharmaceutique, notamment la cire d\'abeille (BP/Ph.Eur), la cire de carnauba, la cire de candelilla, la cire de son de riz, la cire de tournesol, la cire de colza, la cire de palme, la cire de ricin, la cire de soja, la cire d\'olive, ainsi que les huiles végétales hydrogénées pour onguents, crèmes et suppositoires.\n\nSolutions de haute pureté, conformes à la pharmacopée, garantissant stabilité, texture lisse et libération constante du médicament dans les formulations topiques et orales.', '2026-02-06 04:47:33', '2026-02-11 17:07:35'),
(5, 'sec-005', 'Textiles & Cuir', 'Cires végétales haute performance, notamment cire de Carnauba, cire de Candelilla, cire de son de riz, cire de tournesol, cire de colza, cire de palme, cire d\'abeille, cire de soja, ainsi que cires et émulsions paraffiniques pour le traitement des tissus, le traitement du cuir et l\'imperméabilisation.\n\nLubrification supérieure, résistance à l\'eau et à l\'abrasion pour une meilleure sewabilité, une résistance à la déchirure et une efficacité accrue en fabrication textile et traitement du cuir.', '2026-02-06 04:49:11', '2026-02-11 17:08:08'),
(6, 'sec-006', 'Caoutchouc & Plastiques', 'Cires paraffiniques entièrement raffinées, cires microcristallines, cires slack et cires PE optimisées pour la fabrication de pneus, la transformation plastique et leCompound du caoutchouc.\n\nLubrifiants, agents de démoulage et dispersants supérieurs garantissant une extrusion, une injection, un calandrage et un démoulage fluides, avec une finition de surface excellente et une efficacité de traitement optimale.', '2026-02-06 04:51:04', '2026-02-11 17:08:37'),
(7, 'sec-007', 'Emballage', 'Cires paraffines entièrement raffinées, cires microcristallines, cire de blanchiment, cires PE, ainsi que cire de carnauba naturelle et cire d\'abeille pour le revêtement du papier, la laminage de carton, et la production d\'emballages flexibles.\n\nExcellentes propriétés d\'étanchéité à l\'eau, de résistance à la graisse et de libération, garantissant des barrières à l\'humidité durables, des revêtements sûrs pour l\'alimentation, et une performance efficace de thermosoudure pour le carton ondulé, les cartons pliants et les films flexibles.', '2026-02-06 04:53:03', '2026-02-11 17:09:08'),
(8, 'sec-008', 'Adhésifs', 'Cires paraffines entièrement raffinées, cires microcristallines, cire brute, cires PE, cire de carnauba et cire d\'abeille en tant qu\'additifs haute performance pour les revêtements, encres, laminés et émulsions.\n\nAméliorez la résistance aux rayures, la barrière contre l\'humidité, l\'anti-blocage, la réduction du COF et les propriétés de libération pour des performances supérieures des cartonnages ondulés, cartons, et emballages flexibles.', '2026-02-06 04:54:35', '2026-02-11 17:09:41'),
(9, 'sec-009', 'Polishings & Revêtements', 'Cires paraffines entièrement raffinées, cires microcristallines, cire de carnauba et cire d\'abeille pour des polish pour sols haute brillance, lustrage de meubles, revêtements automobiles et protection industrielle des surfaces.\n\nRésistance exceptionnelle à l\'abrasion, capacité de polissage et brillance offrant une protection durable et une finition professionnelle sur surfaces en bois, métal, cuir et composites.', '2026-02-06 04:56:50', '2026-02-11 17:10:10'),
(10, 'sec-010', 'Papier et Impression', 'Cires de paraffine entièrement raffinées, cires microcristallines, cire de carnauba, cire d\'abeille et cires synthétiques pour l\'enduction de papier, la résistance au frottement de l\'encre et les applications de décolletage.\n\nBarrière à l\'humidité supérieure, propriétés anti-adhésives, et amélioration de l\'impression garantissant une protection de surface de haute qualité, une excellente adhérence de l\'encre, et un traitement efficace pour les papiers d\'emballage et l\'impression spécialisée.', '2026-02-06 04:59:16', '2026-02-11 17:05:34');
INSERT INTO `sectors_it` (`id`, `master_id`, `name`, `description`, `created_at`, `updated_at`) VALUES
(1, 'sec-001', 'Creazione di candele', 'Soluzioni complete a base di cera per la produzione di candele\nCerate naturali/vegetali di alta qualità (soia, palma, colza, cocco, cera d\'api) e cere petrolifere (paraffina completamente/semi raffinata a 52-68°C, microcristallina) per tutti i tipi di candele.\n\nMiscele di cere pronte all\'uso: Scaldate direttamente—senza bisogno di additivi—per candele a pilastro, votive o in contenitore perfette, con una diffusione di profumo e una combustione superiori.', '2026-02-06 04:43:59', '2026-02-11 17:06:26'),
(2, 'sec-002', 'Cosmetici', 'Cere Waxes Vegetali Premium per la Produzione di Cosmetici\n\nCere vegetali naturali di alta qualità, tra cui cera di Girasole, cera di Colza, cera di Palmo, Cera d\'Api, Cera di Carnauba, Cera di Candelilla, cera di sansa di Riso, cera di Soia, cera di Ricino, cera di Olive, cera di Avocado, cera di Canapa, cera di Bacca (Rhus verniciflua) e cera di frutta di Myrica, ideali per creme, rossetti e cura della pelle.\n\nPerfetti emollienti, addensanti e stabilizzanti che garantiscono una consistenza liscia e prestazioni superiori.', '2026-02-06 04:45:31', '2026-02-11 17:06:56'),
(3, 'sec-003', 'Alimentazione & Bevande', 'Oli e Grassi Edibili di Qualità Premium per la Produzione Alimentare\n\nOli edibili completamente raffinati (palma, soia, girasole, colza, oliva, cocco), stearine (palma, soia) e shortings per applicazioni di panificazione, confetteria e frittura.\n\nSoluzioni ad alta stabilità e sapore neutro che garantiscono una consistenza uniforme, una durata prolungata e prestazioni superiori in tutte le esigenze di lavorazione alimentare.', '2026-02-06 04:47:10', '2026-02-11 17:07:27'),
(4, 'sec-004', 'Farmaceutici', 'Ingredient premium per la produzione farmaceutica\n\nCere vegetali di qualità farmacopea, tra cui Cera d\'api (BP/Ph.Eur), cera di carnauba, cera di candelilla, cera di germe di riso, cera di girasole, cera di colza, cera di palma, cera di ricino, cera di soia, cera d\'oliva e oli vegetali idrogenati per unguenti, creme e supposte.\n\nSoluzioni ad alta purezza conformi alla farmacopea, garantendo stabilità, texture liscia e rilascio costante del farmaco in formulazioni topiche e orali.', '2026-02-06 04:48:42', '2026-02-11 17:08:00'),
(5, 'sec-005', 'Tessuti & Pelle', 'Cere di derivazione vegetale ad alte prestazioni, tra cui cera di Carnauba, cera di Candelilla, cera di crusca di riso, cera di girasole, cera di colza, cera di palma, cera d\'api, cera di soia, oltre a cere e emulsioni di paraffina per il finissaggio tessile, il trattamento della pelle e la impermeabilizzazione.\n\nLubrificazione superiore, repellenza all\'acqua e resistenza all\'abrasione per una migliore lavorabilità, resistenza alla rottura e efficienza nei processi di produzione tessile e lavorazione della pelle.', '2026-02-06 04:50:29', '2026-02-11 17:08:30'),
(6, 'sec-006', 'Gomma & Plastica', 'Cere a paraffina completamente raffinata, cere microcristalline, cere scoperte e cere PE ottimizzati per la produzione di pneumatici, la lavorazione delle materie plastiche e la modifica del caucciù.\n\nLubrificanti superiori, agenti sbloccanti e ausiliari di dispersione che garantiscono un\'estrusione, uno stampaggio a iniezione, un calandamento e uno smontaggio senza problemi, con un\'eccellente finitura superficiale e efficienza di lavorazione.', '2026-02-06 04:52:39', '2026-02-11 17:09:00'),
(7, 'sec-007', 'Confezionamento', 'Cera di paraffina completamente raffinata, cera microcristallina, cera slack, cere PE, oltre a cera naturale di carnauba e cera d\'api per la rivestitura della carta, laminazione di cartoni e produzione di imballaggi flessibili.\n\nProprietà superiori di impermeabilità, resistenza al grasso e rilascio, garantendo barriere durature contro l\'umidità, rivestimenti sicuri per alimenti e prestazioni efficienti di termosigillatura su cartoni ondulati, cartoni pieghevoli e film flessibili.', '2026-02-06 04:54:12', '2026-02-11 17:09:32'),
(8, 'sec-008', 'Adesivi', 'Ceri di paraffina completamente raffinati, cere microcristalline, cere grezze, cere PE, cera di carnauba e cera d\'api come additivi ad alte prestazioni per rivestimenti, inchiostri, laminati ed emulsioni.\n\nMigliora la resistenza ai graffi, la barriera contro l\'umidità, le proprietà anti-adesione, la riduzione del coefficiente di attrito (COF) e le proprietà di rilascio per prestazioni superiori di cartoni ondulati, cartoni pressati e imballaggi flessibili.', '2026-02-06 04:56:08', '2026-02-11 17:10:02'),
(9, 'sec-009', 'Lucidature e Rivestimenti', 'Cere paraffin completamente raffinata, cere microcristalline, cera di carnauba e cera d\'api per cere per pavimenti ad alto gloss, cura dei mobili, rivestimenti automobilistici e protezione delle superfici industriali.\n\nEccezionale resistenza all\'abrasione, lucidabilità e brillantezza, offrendo una protezione duratura e una finitura professionale su superfici di legno, metallo, pelle e composito.', '2026-02-06 04:58:42', '2026-02-11 17:10:33'),
(10, 'sec-010', 'Carta e Stampa', 'Cere di paraffina completamente raffinati, cere microcristalline, cera di carnauba, cera d\'api e cere sintetiche per rivestimenti di carta, resistenza all\'attrito dell\'inchiostro e applicazioni di rilascio.\n\nBarriera superiore contro l\'umidità, proprietà anti-aderenti e miglioramento della stampa che garantiscono una protezione di alta qualità per la superficie, un\'ottima adesione dell\'inchiostro e un\'elaborazione efficiente per carte da imballaggio e stampa specialistica.', '2026-02-06 05:00:37', '2026-02-11 17:05:57');
INSERT INTO `sectors_ja` (`id`, `master_id`, `name`, `description`, `created_at`, `updated_at`) VALUES
(1, 'sec-001', 'キャンドル作り', 'キャンドル製造向け完全ワックスソリューション\n高品質な天然・植物性ワックス（大豆、パーム、菜種、ココナッツ、蜜蝋）および石油系ワックス（完全精製/半精製パラフィン 52-68°C、マイクロクリスタル）をすべてのタイプのキャンドルに対応。\n\nすぐに使用できるワックスブレンド：添加剤不要で直接溶かして使用可能。優れた香りの拡散と燃焼を実現し、ピラーキャンドル、ヴィトー、コンテナキャンドルに最適。', '2026-02-06 04:43:11', '2026-02-11 17:06:13'),
(2, 'sec-002', '化粧品', '化粧品製造用高級野菜ワックス\n\nヒマワリワックス、菜種ワックス、パームワックス、ミツロウ、カルナウバワックス、キャンデリラワックス、米ぬかワックス、大豆ワックス、ホワイトココヤシワックス、オリーブワックス、アボカドワックス、ヘンプワックス、ベリー（RhUs verniciflua）ワックス、ミヤマフルーツワックスなど、高品質な天然野菜ワックスを使用し、クリーム、リップスティック、スキンケア製品に最適です。\n\n完璧なエモリエント、増粘剤、安定剤として、滑らかな質感と優れた性能を実現します。', '2026-02-06 04:44:50', '2026-02-11 17:06:43'),
(3, 'sec-003', '飲食業', '食品製造向け高級食用油および脂肪\n\n完全精製された食用油（パーム、ソイ、ヒマワリ、ナタネ、オリーブ、ココナッツ）、ステアリン（パーム、ソイ）、およびベーカリー、製菓、揚げ物用途のショートニング。\n\n高安定性で中立的な風味のソリューションにより、一貫した食感、長期保存性、そして食品処理のあらゆるニーズにおいて優れたパフォーマンスを保証します。', '2026-02-06 04:46:29', '2026-02-11 17:07:14'),
(4, 'sec-004', '医薬品', '医薬品製造用プレミアム成分\n\nビーズワックス（BP/Ph.Eur）、カルナウバワックス、キャンデリラワックス、米糠ワックス、ヒマワリ油ワックス、菜種油ワックス、パームオイルワックス、カスターオイルワックス、大豆ワックス、オリーブワックス、および軟膏、クリーム、座薬用の水素化植物油を含む医薬品グレードの植物性ワックス。\n\n高純度で薬局方適合のソリューションは、安定性、滑らかなテクスチャー、および局所および経口製剤における一貫した薬物放出を保証します。', '2026-02-06 04:48:06', '2026-02-11 17:07:46'),
(5, 'sec-005', '繊維＆レザー', 'カーノゥバワックス、キャンデリラワックス、米ぬかワックス、ひまわりワックス、菜種ワックス、パームワックス、 beeswax（ミツロウ）、大豆ワックスに、パラフィンワックスやエマルジョンを含む高性能植物性ワックスは、織物仕上げ、革の処理、防水処理に使用されます。\n\n優れた潤滑性、防水性、耐摩耗性により、縫いやすさ、引裂強度、および衣料品製造や革加工における処理効率が向上します。', '2026-02-06 04:49:44', '2026-02-11 17:08:17'),
(6, 'sec-006', 'ゴム＆プラスチック', 'タイヤ製造、プラスチック加工、およびゴム混合に最適化された完全精製パラフィンワックス、マイクロクリスタルワックス、スラックワックス、PEワックス。\n\n優れた潤滑剤、離型剤、および分散促進剤で、スムーズな押出、射出成形、カレンダリング、および離型を実現し、優れた表面仕上げと加工効率を確保します。', '2026-02-06 04:51:42', '2026-02-11 17:08:49'),
(7, 'sec-007', 'パッケージング', '完全精製パラフィンワックス、マイクロクリスタリンワックス、スラックワックス、PEワックスに加え、紙のコーティング、ボードのラミネート、柔軟なパッケージング製品向けの天然カルナウバワックスと蜜蝋を提供します。\n\n優れた防水性、耐油性、離型性を備え、耐久性のある湿気バリア、食品安全コーティング、効率的なホットシール性能を実現し、段ボール箱、折りたたみ箱、柔軟性のあるフィルム全体で活用されています。', '2026-02-06 04:53:30', '2026-02-11 17:09:20'),
(8, 'sec-008', '接着剤', '完全精製パラフィンワックス、ミクロクリスタルワックス、スラックワックス、PEワックス、カルナウバワックス、および蜜蝋をコーティング、インク、ラミネート、エマルションの高性能添加剤として使用。\n\n傷防止性、耐湿バリア性、ブロック防止、COF低減、および離素性を向上させ、優れた段ボール、紙箱、および柔軟包装の性能を実現します。', '2026-02-06 04:55:14', '2026-02-11 17:09:50'),
(9, 'sec-009', 'ポリッシュ＆コーティング', '高光沢の床用ポリッシュ、家具ケア、自動車コーティング、産業用表面保護のための完全精製パラフィンワックス、ミクロクリスタリンワックス、カルナウバワックス、蜜蝋。\n\n優れた耐摩耗性、研磨性、光沢を備え、木材、金属、革、複合素材の表面に長持ちする保護とプロフェッショナルな仕上がりを実現します。', '2026-02-06 04:57:46', '2026-02-11 17:10:20'),
(10, 'sec-010', 'ペーパー＆印刷', '完全精製パラフィンワックス、微結晶ワックス、カラナウアワックス、ミツロウ、および紙コーティング、インク擦過抵抗、リリース用途に適した合成ワックス。\n\n優れた防湿性、非粘着性、および印刷向上性により、高品質な表面保護、優れたインク付着性、効率的な加工を実現し、包装紙や特殊印刷に最適です。', '2026-02-06 04:59:49', '2026-02-11 17:05:44');
INSERT INTO `sectors_ko` (`id`, `master_id`, `name`, `description`, `created_at`, `updated_at`) VALUES
(1, 'sec-001', '양초 제작', '양초 제조를 위한 완전한 왁스 솔루션\n프리미엄 천연/식물성 왁스(소이, 팜, 유채, 코코넛, 밀랍) 및 석유 계 왁스(전면/반정제 파라핀 52-68°C, 미크로크리스탈라인)를 모든 양초 유형에 적합하게 제공합니다.\n\n즉시 사용 가능한 왁스 블렌드: 바로 녹여서 사용하세요—첨가제 필요 없음—우수한 향 전달력과 우수한 연소 특성을 갖춘 피라미드, 보티브, 컨테이너 양초에 이상적입니다.', '2026-02-06 04:43:47', '2026-02-11 17:06:22'),
(2, 'sec-002', '화장품', '화장품 제조용 프리미엄 식물성 왁스\n\n해바라기 왁스, 유채씨 왁스, 야자 왁스, 밀랍, 카르나우바 왁스, 칸델릴라 왁스, 쌀겨 왁스, 대두 왁스, 피마자 왁스, 올리브 왁스, 아보카도 왁스, 햄프 왁스, 베리 왁스 (Rhus verniciflua), 마이르카 과일 왁스 등 고품질 천연 채소성 왁스는 크림, 립스틱, 스킨케어에 적합합니다.\n\n완벽한 피부 연화제, 증점제, 안정제로서 부드러운 질감과 뛰어난 성능을 제공합니다.', '2026-02-06 04:45:22', '2026-02-11 17:06:52'),
(3, 'sec-003', '식품 및 음료', '식품 제조용 프리미엄 식용유 및 유지\n\n정제된 식용유(팜유, 대두유, 해바라기유, 유채유, 올리브유, 코코넛유), 스테아린(팜유, 대두유), 및 제과, 제빵, 튀김용 쇼트닝.\n\n높은 안정성, 중립적인 풍미의 솔루션으로 일관된 식감, 연장된 유통기한, 그리고 식품 가공 전반에 걸친 우수한 성능을 보장합니다.', '2026-02-06 04:46:56', '2026-02-11 17:07:22'),
(4, 'sec-004', '제약 산업', '제약 제조용 프리미엄 원료\n\n제약 등급의 식물성 왁스(벌왁스(BP/Ph.Eur), 카르나우바 왁스, 칸델릴라 왁스, 쌀겨 왁스, 해바라기 왁스, 유채씨 왁스, 야자 왁스, 피마자 왁스, 두유 왁스, 올리브 왁스) 및 연고, 크림, 좌약용 수소화 식물성 오일.\n\n높은 순도와 의약품 규격 적합성을 갖춘 솔루션으로, 안정성, 부드러운 질감, 그리고 일관된 약물 방출을 위한 탑재형 및 경구용 제형을 보장합니다.', '2026-02-06 04:48:30', '2026-02-11 17:07:55'),
(5, 'sec-005', '직물 및 가죽', '카르나우바 왁스, 칸델리라 왁스, 쌀겨 왁스, 해바라기 왁스, 유채 왁스, 야자 왁스, 밀랍, 대두 왁스, 그리고 섬유 마감, 가죽 처리 및 방수용 파라핀 왁스와 유제 등 고성능 채소 왁스.\n\n혁신적인 윤활성, 방수성, 마모 저항으로 직물 제조 및 가죽 가공에서 봉제성 향상, 찢어짐 강도 증가, 처리 효율성 증대.', '2026-02-06 04:50:12', '2026-02-11 17:08:25'),
(6, 'sec-006', '고무 및 플라스틱', '완전 정제된 파라핀 왁스, 마이크로크리스탈라인 왁스, 슬랙 왁스 및 PE 왁스는 타이어 생산, 플라스틱 가공 및 고무 배합에 최적화되어 있습니다.\n\n우수한 윤활제, 이형제 및 분산제는 원활한 압출, 사출 성형, 압연 및 탈형을 보장하며 뛰어난 표면 마감과 가공 효율을 제공합니다.', '2026-02-06 04:52:18', '2026-02-11 17:08:56'),
(7, 'sec-007', '포장', '완전 정제 파라핀 왁스, 미크로크리스탈린 왁스, 슬랙 왁스, PE 왁스, 그리고 종이 코팅, 박스보드 라미네이션, 유연 포장 생산에 사용되는 천연 카르나우바 왁스와 밀랍.\n\n우수한 방수성, 기름 저항성, 방출 특성을 갖추어 내구성 있는 수증기 차단막, 식품 안전 코팅, 그리고 골판지, 접이식 상자, 유연 필름 전반에 걸친 효율적인 열 봉합 성능을 보장합니다.', '2026-02-06 04:53:57', '2026-02-11 17:09:27'),
(8, 'sec-008', '접착제', '고순도 정제 파라핀 왁스, 미크로크리스탈라인 왁스, 슬랙 왁스, PE 왁스, 카르나우바 왁스, 밀랍은 코팅제, 잉크, 라미네이트, 유제의 고성능 첨가제로서 사용됩니다.\n\n긁힘 저항, 수분 차단, 블록 방지, COF 감소, 방출 특성을 향상시켜 우수한 골판지, 종이판, 유연 포장 성능을 제공합니다.', '2026-02-06 04:55:54', '2026-02-11 17:09:58'),
(9, 'sec-009', '폴리시 및 코팅', '완전 정제 파라핀 왁스, 마이크로크리스탈린 왁스, 카나우바 왁스, 밀랍은 고광택 바닥 광택제, 가구 관리, 자동차 코팅, 산업용 표면 보호를 위해 사용됩니다.\n\n탁월한 마모 저항성, 버핑 가능성, 그리고 광택을 제공하여 목재, 금속, 가죽, 복합 재료 표면에 오래 지속되는 보호력과 전문가 수준의 마감 처리를 제공합니다.', '2026-02-06 04:58:23', '2026-02-11 17:10:29'),
(10, 'sec-010', '종이 및 인쇄', '완전히 정제된 파라핀 왁스, 마이크로크리스탈린 왁스, 카나우바 왁스, 밀랍, 그리고 합성 왁스는 종이 코팅, 잉크 마찰 저항, 그리고 방출용으로 사용됩니다.\n\n우수한 수분 차단, 달라붙지 않는 성질, 인쇄 향상 특성으로 고품질 표면 보호와 뛰어난 잉크 접착력, 그리고 포장지 및 특수 인쇄용 효율적인 가공을 보장합니다.', '2026-02-06 05:00:18', '2026-02-11 17:05:52');
INSERT INTO `sectors_pl` (`id`, `master_id`, `name`, `description`, `created_at`, `updated_at`) VALUES
(1, 'sec-001', 'Robienie świec', 'Kompleksowe rozwiązania w zakresie wosku do produkcji świec\nWoski naturalne/roślinne wysokiej jakości (sojowy, palmowy, rzepakowy, kokosowy, pszczeli) oraz woski mineralne (w pełni odpowiednio lub pół-rafinowane parafiny 52-68°C, mikrokrystaliczne) do wszystkich rodzajów świec.\n\nGotowe do użycia mieszanki wosków: topić od razu—nie wymaga dodatków—dla idealnych świec filarowych, votive lub w pojemnikach z doskonałym rozproszeniem zapachu i długim spalaniem.', '2026-02-06 04:44:06', '2026-02-11 17:06:28'),
(2, 'sec-002', 'Kosmetyki', 'Premiumowe woski roślinne do produkcji kosmetyków\n\nWysokiej jakości naturalne woski roślinne, w tym wosk słonecznikowy, wosk rzepakowy, wosk palmowy, wosk pszczeli, wosk carnauba, wosk candelilla, wosk z otrąb ryżowych, wosk sojowy, wosk rycynowy, wosk oliwny, wosk z awokado, wosk konopny, wosk jagodowy (Rhus verniciflua) oraz wosk z owoców myrty dla kremów, pomadek do ust i produktów do pielęgnacji skóry.\n\nIdealne emolienty, zagęstniki oraz stabilizatory zapewniające gładką teksturę i wysoką wydajność.', '2026-02-06 04:45:37', '2026-02-11 17:06:58'),
(3, 'sec-003', 'Jedzenie i napoje', 'Premiumowe oleje i tłuszcze jadalne do produkcji spożywczej\n\nW pełni rafinowane oleje jadalne (palma, soja, słoneczny, rzepak, oliwa, kokos), stearyny (palma, soja) oraz smary do zastosowań piekarniczych, cukierniczych i smażenia.\n\nRozwiązania o wysokiej stabilności i neutralnym smaku, zapewniające jednolitą teksturę, wydłużoną trwałość produktu oraz doskonałe parametry wydajności w różnych procesach przemysłu spożywczego.', '2026-02-06 04:47:17', '2026-02-11 17:07:29'),
(4, 'sec-004', 'Farmaceutyki', 'Premium składniki do produkcji farmaceutycznej\n\nWoski roślinne wysokiej jakości przeznaczone do przemysłu farmaceutycznego, w tym wosk pszczeli (BP/Ph.Eur), wosk karnauba, wosk candelilla, wosk z otrąb ryżu, wosk słonecznikowy, wosk rzepakowy, wosk palmowy, wosk rycynowy, wosk sojowy, wosk z oliwek oraz utwardzone oleje roślinne do maści, kremów i czopków.\n\nRozwiązania o wysokiej czystości, zgodne z pharmacopoeią, zapewniające stabilność, gładką teksturę oraz równomierne uwalnianie leku w formulacjach miejscowych i doustnych.', '2026-02-06 04:48:49', '2026-02-11 17:08:02'),
(5, 'sec-005', 'Tkaniny i skóra', 'Wysokowydajne woski roślinne, w tym wosk Carnauba, wosk Candelilla, wosk z otrąb ryżowych, wosk słonecznikowy, wosk rzepakowy, wosk palmowy, wosk pszczeli, wosk sojowy, a także woski parafinowe i emulsje do wykańczania tkanin, obróbki skór i impregnacji wodoodpornej.\n\nLepsza smarowność, repelencja wodna i odporność na ścieranie dla poprawionego łatwego szycia, wytrzymałości na rozdzieranie i efektywności przetwarzania w przemyśle tekstylnym i obróbce skór.', '2026-02-06 04:50:37', '2026-02-11 17:08:32'),
(6, 'sec-006', 'Guma i tworzywa sztuczne', 'W pełni rafinowane woski parafinowe, woski mikrokrystaliczne, woski surowe oraz woski PE zoptymalizowane do produkcji opon, obróbki plastiku i mieszania gum.  \n\nWyśmienite środki smarne, środki poślizgowe i środki dyspersyjne zapewniające płynne wytłaczanie, wtrysk, walcowanie i demoulding z doskonałym wykończeniem powierzchni i wydajnością obróbki.', '2026-02-06 04:52:47', '2026-02-11 17:09:03'),
(7, 'sec-007', 'Opakowanie', 'W pełni rafinowane woski parafinowe, woski mikrokrystaliczne, woski slack, woski PE oraz naturalny wosk carnauba i wosk pszczeli do powlekania papieru, laminacji tektur meblowych i produkcji elastycznych opakowań.\n\nDoskonałe właściwości wodoodporne, odporność na tłuszcz oraz właściwości antyadhezyjne zapewniają trwałe bariery chroniące przed wilgocią, powłoki bezpieczne dla żywności oraz efektywne właściwości zgrzewania termicznego na tekturze falistej, opakowaniach składanych i filmach elastycznych.', '2026-02-06 04:54:18', '2026-02-11 17:09:34'),
(8, 'sec-008', 'Kleje', 'W pełni rafinowane woski parafinowe, woski mikrokrystaliczne, woski slack, woski PE, wosk karnauba oraz wosk pszczeli jako wysokowydajne dodatki do powłok, tuszy, laminatów i emulsji.\n\nZwiększają odporność na zarysowania, barierę na wilgoć, właściwości anti-block, redukcję współczynnika tarcia (COF) oraz właściwości poślizgowe, zapewniając lepszą jakość tektury falistej, tektury topograficznej i elastycznych opakowań.', '2026-02-06 04:56:15', '2026-02-11 17:10:04'),
(9, 'sec-009', 'Polishowanie i Powłoki', 'W pełni rafinowane woski parafinowe, woski mikrokrystaliczne, wosk carnauba oraz wosk pszczeli do lakierów podłogowych o wysokim połysku, pielęgnacji mebli, powłok samochodowych i przemysłowej ochrony powierzchni.\n\nWyjątkowa odporność na ścieranie, polerowalność i połysk zapewniająca długotrwałą ochronę i profesjonalne wykończenie na powierzchniach z drewna, metalu, skóry i kompozytowych.', '2026-02-06 04:58:54', '2026-02-11 17:10:35'),
(10, 'sec-010', 'Papier i Druk', 'W pełni rafinowane woski parafinowe, woski mikrokrystaliczne, wosk carnauba, wosk pszczeli oraz woski syntetyczne do powlekania papieru, odporności na rozmazanie tuszem oraz zastosowań ślizgowych.\n\nWyjątkowa bariera na wilgoć, właściwości antyadhezyjne oraz poprawa druku zapewniająca ochronę wysokiej jakości powierzchni, doskonałe przenikanie tuszu oraz efektywną obróbkę papierów pakowych i specjalistycznego druku.', '2026-02-06 05:00:45', '2026-02-11 17:05:59');
INSERT INTO `sectors_pt` (`id`, `master_id`, `name`, `description`, `created_at`, `updated_at`) VALUES
(1, 'sec-001', 'Fabricação de velas', 'Soluções completas de cera para fabricação de velas\nCeras premium naturais/de origem vegetal (soja, palma, colza, coco, cera de abelha) e ceras de petróleo (parafina totalmente/semi-refinada a 52-68°C, microcristalina) para todos os tipos de velas.\n\nMisturas de cera prontas para uso: Derreta diretamente—sem necessidade de aditivos—para velas de pilar, votivas ou de recipiente com excelente difusão de aroma e queima superior.', '2026-02-06 04:42:53', '2026-02-11 17:06:08'),
(2, 'sec-002', 'Cosméticos', 'Ceras Vegetais Premium para Fabricação de Cosméticos\n\nCeras vegetais naturais de alta qualidade, incluindo cera de girassol, cera de canola, cera de palma, cera de abelha, cera de carnaúba, cera de candelila, cera de farelo de arroz, cera de soja, cera de castor, cera de azeitona, cera de abacate, cera de cânhamo, cera de baga (Rhus verniciflua) e cera de fruta de Mirica para cremes, batons e cuidados com a pele.\n\nEmolientes, espessantes e estabilizantes perfeitos, oferecendo textura suave e desempenho superior.', '2026-02-06 04:44:35', '2026-02-11 17:06:37'),
(3, 'sec-003', 'Alimentos e Bebidas', 'Óleos e gorduras comestíveis premium para fabricação de alimentos\n\nÓleos comestíveis totalmente refinados (palma, soja, girassol, colza, azeitona, coco), stearins (palma, soja) e shortening para aplicações em padaria, confeitaria e frituras.\n\nSoluções de alta estabilidade e sabor neutro que garantem textura consistente, vida útil prolongada e desempenho superior em diversas necessidades de processamento de alimentos.', '2026-02-06 04:46:11', '2026-02-11 17:07:08'),
(4, 'sec-004', 'Farmacêuticos', 'Ingredientes Premium para Fabricação Farmacêutica\n\nCeras vegetais de grau farmacêutico, incluindo cera de abelha (BP/Ph.Eur), cera de carnaúba, cera de candelila, cera de farelo de arroz, cera de girassol, cera de colza, cera de palma, cera de ricino, cera de soja, cera de oliva e óleos vegetais hidrogenados para pomadas, cremes e supositórios.\n\nSoluções de alta pureza, compatíveis com a farmacopéia, garantindo estabilidade, textura suave e liberação consistente de medicamentos em formulações tópicas e orais.', '2026-02-06 04:47:46', '2026-02-11 17:07:39'),
(5, 'sec-005', 'Tecidos & Couro', 'Ceras vegetais de alto desempenho, incluindo cera de Carnaúba, cera de Candelilla, cera de farelo de arroz, cera de girassol, cera de colza, cera de palma, cera de abelha, cera de soja, além de ceras e emulsões de parafina para acabamento de tecidos, tratamento de couro e impermeabilização.\n\nLubrificação superior, repelência à água e resistência à abrasão para melhor sewability, resistência ao rasgo e eficiência no processamento na fabricação de têxteis e no processamento de couro.', '2026-02-06 04:49:23', '2026-02-11 17:08:12'),
(6, 'sec-006', 'Borracha & Plásticos', 'Cera de parafina totalmente refinada, ceras microcristalinas, cera de graxa e ceras PE otimizadas para a produção de pneus, processamento de plásticos e compounded de borracha.\n\nLubrificantes superiores, agentes antiaderentes e agentes dispersantes que garantem uma extrusão suave, moldagem por injeção, calandragem e desmoldagem com acabamento de superfície excelente e eficiência de processamento.', '2026-02-06 04:51:18', '2026-02-11 17:08:42'),
(7, 'sec-007', 'Embalagem', 'Cerados de parafina totalmente refinada, ceras microcristalinas, cera slack, ceras PE, além de cera natural de carnaúba e cera de abelha para revestimento de papel, laminação de papel-cartão e produção de embalagens flexíveis.\n\nPropriedades superiores de impermeabilidade, resistência a gordura e liberação, garantindo barreiras de umidade duráveis, revestimentos seguros para alimentos e desempenho eficiente em selagem a quente em papelão ondulado, caixas dobráveis e filmes flexíveis.', '2026-02-06 04:53:14', '2026-02-11 17:09:13'),
(8, 'sec-008', 'Adesivos', 'Paraafinas totalmente refinadas, ceras microcristalinas, cera de refugo, ceras PE, cera de carnaúba e cera de abelha como aditivos de alto desempenho para revestimentos, tintas, laminados e emulsões.\n\nMelhore a resistência a riscos, barreira contra umidade, antiaderência, redução do COF e propriedades de liberação para um desempenho superior de papel cartão, papelão e embalagens flexíveis.', '2026-02-06 04:54:54', '2026-02-11 17:09:44'),
(9, 'sec-009', 'Polimentos & Revestimentos', 'Parafina totalmente refinada, cera microcristalina, cera de carnaúba e cera de abelha para polidores de piso de alto brilho, cuidados com móveis, revestimentos automotivos e proteção de superfícies industriais.  \n\nResistência excepcional à abrasão, polimento e brilho, proporcionando proteção duradoura e acabamento profissional em superfícies de madeira, metal, couro e compósitos.', '2026-02-06 04:57:14', '2026-02-11 17:10:14'),
(10, 'sec-010', 'Papel e Impressão', 'Ceras de parafina totalmente refinadas, ceras microcristalinas, cera de carnaúba, cera de abelha e ceras sintéticas para revestimento de papel, resistência ao fricção da tinta e aplicações release.\n\nBarreira superior contra umidade, propriedades antiaderentes e aprimoramento da impressão, garantindo proteção de superfície de alta qualidade, excelente aderência da tinta e processamento eficiente para papéis para embalagem e impressão especial.', '2026-02-06 04:59:31', '2026-02-11 17:05:37');
INSERT INTO `sectors_ru` (`id`, `master_id`, `name`, `description`, `created_at`, `updated_at`) VALUES
(1, 'sec-001', 'Изготовление свечей', 'Полные решения на основе воска для производства свечей\nПремиальные натуральные/растительные воски (соевый, пальмовый, рапсовый, кокосовый, пчелиный) и нефтепродуктовые воски (полностью/частично рафинированный парафин 52-68°C, микрокристаллический) для всех типов свечей.\n\nГотовые к использованию восковые смеси: расплавляйте прямо — добавки не нужны — для идеальных столбчатых, вотовых или контейнерных свечей с превосходным ароматом и качеством горения.', '2026-02-06 04:42:59', '2026-02-11 17:06:09'),
(2, 'sec-002', 'Косметика', 'Премиальные растительные воски для производства косметики\n\nВысококачественные натуральные растительные воски, включая воски подсолнечника, рапса, пальмовые воски, пчелиный воск, карнаубский воск, канделильский воск, рисовые отруби, соевый воск, касторовое воск, оливковый воск, авокадо, конопляный воск, ягодный воск (Rhus verniciflua) и воск из плодов миранги для кремов, помад и ухода за кожей.\n\nОтличные эмоленты, загустители и стабилизаторы, обеспечивающие гладкую текстуру и высокую эффективность.', '2026-02-06 04:44:39', '2026-02-11 17:06:39'),
(3, 'sec-003', 'Еда и напитки', 'Премиальные пищевые масла и жиры для пищевого производства\n\nПолностью рафинированные пищевые масла (пальмовое, соевое, подсолнечное, рапсовое, оливковое, кокосовое), стеарины (пальмовое, соевое) и шортенинги для выпечки, кондитерских изделий и жарки.\n\nВысокостабильные нейтральные по вкусу решения, обеспечивающие однородную текстуру, verlängенный срок хранения и превосходную производительность для различных целей обработки продуктов питания.', '2026-02-06 04:46:16', '2026-02-11 17:07:10'),
(4, 'sec-004', 'Фармацевтика', 'Премиальные ингредиенты для производства фармацевтических препаратов\n\nФармацевтические растительные воски, включая пчелиный воск (BP/Ph.Eur), карнаубский воск, канде́ллиловый воск, воск из рисовых отрубей, подсолнуховый воск, рапсовый воск, пальмовый воск, касторовый воск, соевый воск, оливковый воск, а также гидрогенизированные растительные масла для мазей, кремов и суппозиториев.\n\nВысокочистые, соответствующие фармакопейным требованиям растворы, обеспечивающие стабильность, гладкую текстуру и равномерное высвобождение лекарства в топических и оральных формах.', '2026-02-06 04:47:54', '2026-02-11 17:07:41'),
(5, 'sec-005', 'Ткани и кожа', 'Высокопроизводительные растительные воски, включая карнаубский воск, каннадильский воск, воски из рисовых отрубей, подсолнечное воск, рапсовое воск, пальмовое воск, пчелиный воск, соевый воск, а также парафинистые воски и эмульсии для отделки тканей, обработки кожи и водоотталкивающих покрытий.\n\nОбеспечивают превосходную смазку, водоотталкивающие свойства и устойчивость к истиранию для повышения швейных характеристик, прочности на разрыв и эффективности обработки в текстильной промышленности и при обработке кожи.', '2026-02-06 04:49:30', '2026-02-11 17:08:14'),
(6, 'sec-006', 'Резина и пластики', 'Полностью очищенные парафиновый воск, микрокристаллический воск, слэк-воск и PE-воски, оптимизированные для производства шин, обработки пластмасс и комплектации каучука.\n\nВысококачественные смазочные материалы, разделительные агенты и диспергаторы, обеспечивающие плавное экструзии, литье под давлением, каландрование и высвобождение, с отличной поверхностной отделкой и высокой эффективностью обработки.', '2026-02-06 04:51:27', '2026-02-11 17:08:44'),
(7, 'sec-007', 'Упаковка', 'Полностью рафинированные парафиновые воски, микрокристаллические воски, slack wax, воски PE, а также натуральный карнаубский воск и пчелиный воск для покрытия бумаги, ламинации картонных коробов и производства гибкой упаковки.\n\nВысококачественные водоотталкивающие свойства, сопротивление маслам и антилифтовые характеристики, обеспечивающие надежные барьеры от влаги, безопасные для пищевых продуктов покрытия и эффективное запечатывание при сжатии на гофрированном картоне, складывающихся картонных коробках и гибкой пленке.', '2026-02-06 04:53:19', '2026-02-11 17:09:15'),
(8, 'sec-008', 'Клеящие вещества', 'Полностью рафинированные парафиновые воски, микрокристаллические воски, slack wax, воски PE, карнауба и пчелиный воск в качестве высокоэффективных добавок для покрытий, красок, ламиниров и эмульсий.\n\nУлучшайте устойчивость к царапинам, барьерные свойства против влаги, антиблокирующие свойства, снижение коэффициента трения (COF) и свойства легкого отслаивания для превосходной производительности гофрокартона, картонных и гибких упаковочных материалов.', '2026-02-06 04:55:03', '2026-02-11 17:09:46'),
(9, 'sec-009', 'Полироли и покрытия', 'Полностью рафинированные парафиновые воски, микрокристаллические воски, воск карнауба и пчелиный воск для высокоглянцевых напольных полировок, ухода за мебелью, автомобильных покрытий и промышленной защиты поверхностей.\n\nИсключительная стойкость к истиранию, полируемость и блеск обеспечивают долговременную защиту и профессиональную отделку деревянных, металлических, кожаных и композитных поверхностей.', '2026-02-06 04:57:26', '2026-02-11 17:10:16'),
(10, 'sec-010', 'Бумага и печать', 'Полностью рафинированные парафиновые воски, микрокристаллические воски, воск карнауба, пчелиный воск и синтетические воски для покрытия бумаги, сопротивления трению при нанесении чернил и использования в качестве релиза.\n\nВысокий барьер влагозащиты, антиприлипательные свойства и улучшение печати, обеспечивающие надежную защиту поверхности, отличную адгезию чернил и эффективную обработку для упаковочной бумаги и спецпечати.', '2026-02-06 04:59:38', '2026-02-11 17:05:40');
INSERT INTO `sectors_sw` (`id`, `master_id`, `name`, `description`, `created_at`, `updated_at`) VALUES
(1, 'sec-001', 'Kutengeneza Mishumaa', 'Suluhisho kamili za Wax kwa ajili ya Utengenezaji wa Mishumaa\nWaxes za Asili/Basisi za Mimea za Ubora wa Juu (Soya, Mafuta ya Mihogo, Mimea ya Rapeseed, Nazi, Asali) na Waxes za Petroli (paraffin iliyokamuliwa kamili/kipimo cha nusu 52-68°C, microcrystalline) kwa aina zote za mishumaa.\n\nMchanganyiko wa Wax unaotumika mara moja: Eyedeke moja kwa moja—hakuna viambato vinahitajika—kwa mishumaa ya safi ya nguzo, votive, au ya chupa yenye harufu nzuri na moto wa juu.', '2026-02-06 04:43:24', '2026-02-11 17:06:16'),
(2, 'sec-002', 'Vipodozi', 'Vitunguu vya Mboga vya Premium kwa Utengenezaji wa Vitu vya Kosmetiki\n\nVitunguu vya mboga vya asili vya ubora wa juu ikiwemo vitunguu vya Sunflower, rapeseed, palm, nta wa nyuki, karnauba, candelilla, bran ya mchele, soya, castor, mzeituni, viazivimba, bangi, berry (Rhus verniciflua), na matunda ya Myrica kwa krimu, rangi za matics, na utunzaji wa ngozi.\n\nVitunguu bora vya kunyonya, viunganishi vya unene, na viambata vya utulivu vinavyotoa muundo laini na utendaji wa kipekee.', '2026-02-06 04:45:04', '2026-02-11 17:06:46'),
(3, 'sec-003', 'Vyakula na Vinywaji', 'Mafuta ya Kula ya Premium na Mafuta kwa Utengenezaji wa Chakula\n\nMafuta ya kula yaliyochapishwa kikamilifu (mikoko, soya, alizeti, rape, mzeituni, nazi), stearins (mikoko, soya), na mafuta mafupi kwa matumizi ya kiwanja cha mkate, pipi, na kukaanga.\n\nSuluhisho za hali ya juu zisizo na harufu inayodumu kwa kipindi kirefu, kuhakikisha muundo wa mara kwa mara, maisha marefu ya rafu, na utendaji bora katika mahitaji ya usindikaji wa vyakula.', '2026-02-06 04:46:36', '2026-02-11 17:07:16'),
(4, 'sec-004', 'Dawa za Kulegeza', 'Viungo vya Ubora wa Juu kwa Utengenezaji wa Madawa\n\nWax za mboga za kiwango cha pharma zikiwemo Beeswax (BP/Ph.Eur), wax ya Carnauba, wax ya Candelilla, wax ya Rice bran, wax ya Sunflower, wax ya Rapeseed, wax ya Palm, wax ya Castor, wax ya Soya, wax ya Mzeituni, na mafuta ya mboga yaliyo hydrogenated kwa ajili ya maanjiki, krimu, na suppositories.\n\nSuluhisho za uchafuzi wa hali ya juu, zinazolingana na yeye ya pharmacopoeia zenye kuhakikisha utulivu, muundo laini, na mchakato wa kujitoa kwa dawa bora katika fomula za topical na za kumeza.', '2026-02-06 04:48:13', '2026-02-11 17:07:48'),
(5, 'sec-005', 'Vitega vya nguo na ngozi', 'Vibali vya mboga vya viwandani vinavyofanya kazi kwa kiwango cha juu ikiwa ni pamoja na wax ya Carnauba, wax ya Candelilla, wax ya pamba, wax ya alizeti, wax ya rapeseed, wax ya mparachichi,Ndepeta, wax ya soya, pamoja na wax za paraffini na emulsions kwa ufinyanzi wa kitambaa, matibabu ya ngozi, na kuzuia maji kuingia.\n\nLubrication bora, upinzani wa maji, na upinzani wa abrasion kwa uboreshaji wa ushonaji, nguvu ya kuvunjika na ufanisi wa usindaji katika utengenezaji wa kitambaa na usindikaji wa ngozi.', '2026-02-06 04:49:53', '2026-02-11 17:08:19'),
(6, 'sec-006', 'Mpira na Plastiki', 'Vibaki vya paraffin vilivyosisitizwa kikamilifu, waxes microcrystalline, waxes slack, na waxes PE zilizoboreshwa kwa ajili ya utengenezaji wa matairi, usindikaji wa plastiki, na mchanganyiko wa mpira.\n\nLubricants bora, wakitoa msaada wa kuachilia, na msaada wa kusambaza kuhakikisha extrusion laini, kutengeneza kwa sindano, calendering, na demolding na kumaliza nzuri kwa uso na ufanisi wa usindikaji.', '2026-02-06 04:51:53', '2026-02-11 17:08:51'),
(7, 'sec-007', 'Ufungaji', 'Paraffin waxes zilizotamkwa kikamilifu, waxes za microcrystalline, slack wax, waxes za PE, pamoja na wax ya karneuba asilia na nta wa nyuki kwa kufunika karatasi, uchoraji wa katoni, na utengenezaji wa ufungaji unaobadilika.\n\nUfungaji wa maji wa juu, upinzani dhidi ya mafuta, na mali za kuachilia, kuhakikisha vizuizi vya unyevu vya kudumu, mikaa safi ya chakula, na utendaji wa sealing wa joto wenye ufanisi kwenye katoni zilizo na corrugation, katoni zinazonyanyaswa, na filamu zinazobadilika.', '2026-02-06 04:53:40', '2026-02-11 17:09:22'),
(8, 'sec-008', 'Gummo', 'Paraffin waxes zilizokamilika, waxes microcrystalline, slack wax, PE waxes, wax ya carnauba, na wax ya asali kama viungio vya ubora wa juu kwa matumizi ya coatings, inks, laminates, na emulsions.\n\nBoresha sugu wa mikato, kingo cha unyevunyevu, kuzuia kuunganishwa, kupunguza COF, na mali za kuachilia kwa margazine bora ya corrugated, paperboard, na vifungashio vinavyobadilika.', '2026-02-06 04:55:36', '2026-02-11 17:09:52'),
(9, 'sec-009', 'Polishi na Mipako', 'Paraafini waliochakatwa kikamilifu, waxi za microcrystalline, waxi ya carnauba, na waxi ya nyuki kwa enamel za sakafu za kumwaga shin na hali ya juu, utunzaji wa samani, mafuta ya magari, na ulinzi wa uso wa viwandani.\n\nUhimili wa mikwaruzo, uwezo wa kupiga msasa na kung\'aa vinavyoleta ulinzi wa muda mrefu na kumaliza kitaaluma kwa nyuso za mbao, chuma, ngozi, na mchanganyiko.', '2026-02-06 04:57:58', '2026-02-11 17:10:23'),
(10, 'sec-010', 'Karatasi & Uchapishaji', 'Paraffin waxes zilizotakaswa kikamilifu, waxes za microcrystalline, waxes za carnauba, waxes za nyuki, na waxes za synthetic kwa ajili ya kubaka karatasi, upinzani dhidi ya mmiminiko wa vibonzo, na matumizi ya kutolewa.\n\nKiraka bora cha unyevu, mali dhidi ya kunata, na kuongeza ubora wa chapisho kuhakikisha ulinzi wa uso wa hali ya juu, shikana nzuri kwa vibonzo, na uendeshaji mizuri kwa karatasi za ufungaji na uchapishaji maalum.', '2026-02-06 04:59:59', '2026-02-11 17:05:45');
INSERT INTO `sectors_th` (`id`, `master_id`, `name`, `description`, `created_at`, `updated_at`) VALUES
(1, 'sec-001', 'การทำเทียน', 'โซลูชันวาสต์สำเร็จรูปสำหรับการผลิตเทียน\nวาสต์ธรรมชาติ/จากพืชเกรดพรีเมียม (ถั่วเหลือง ปาล์ม คำแรคซีด น้ำมันมะพร้าว เทียนผึ้ง) และวาสต์ปิโตรเลียม (พาราฟินที่ผ่านการกลั่นเต็มรูปแบบ/กึ่งกลั่น 52-68°C มายครอคริสตัลไลน์) สำหรับเทียนทุกประเภท\n\nวาสต์ผสมสำเร็จรูปพร้อมใช้: ละลายแล้วใช้ได้เลย—ไม่ต้องผสมสารเติมแต่ง—เพื่อเทียนเสา เทียนบูชาหรือเทียนบรรจุภัณฑ์ที่มีกลิ่นหอมและการเผาที่ยอดเยี่ยม', '2026-02-06 04:43:53', '2026-02-11 17:06:24'),
(2, 'sec-002', 'เครื่องสำอาง', 'เทียนพืชชนิดพรีเมี่ยมสำหรับการผลิตเครื่องสำอาง\n\nเทียนพืชธรรมชาติคุณภาพสูง รวมถึงเทียนดอกทานตะวัน เทียนคาโนลา เทียนปาล์ม เทียนผึ้ง เทียนคาร์นูบา เทียนคาเดนิลลา เทียนรำข้าว เทียนถั่วเหลือง เทียนโกฐหวาน เทียนมะกอก เทียนอะโวคาโด เทียนกัญชา เทียนเบอร์รี (Rhus verniciflua) และเทียนผลไม้เมริกา สำหรับครีม ลิปสติก และการดูแลผิว\n\nเป็นมอยเจอร์ไรเซอร์ เทคเจอร์หนาแน่น และสารทำให้คงสภาพที่มอบเนื้อสัมผัสเรียบเนียนและประสิทธิภาพยอดเยี่ยม', '2026-02-06 04:45:27', '2026-02-11 17:06:54'),
(3, 'sec-003', 'อาหารและเครื่องดื่ม', 'น้ำมันและไขมันรับประทานคุณภาพพรีเมี่ยมสำหรับอุตสาหกรรมอาหาร\n\nน้ำมันรับประทานที่ผ่านการกลั่นอย่างสมบูรณ์ (ปาล์ม ถั่วเหลือง ทานตะวัน คาวิซิล แปะก๊วย มะกอก มะพร้าว), สเตอริน (ปาล์ม ถั่วเหลือง), และพรีครีมสำหรับเบเกอรี่ ขนมหวาน และการทอดอาหาร\n\nโซลูชันที่มีความเสถียรสูง รสชาติเป็นกลาง เพื่อความสม่ำเสมอของเนื้อสัมผัส อายุการเก็บรักษาที่ยาวนานขึ้น และประสิทธิภาพยอดเยี่ยมสำหรับความต้องการในกระบวนการผลิตอาหาร', '2026-02-06 04:47:02', '2026-02-11 17:07:24'),
(4, 'sec-004', 'เภสัชภัณฑ์', 'วัตถุดิบพรีเมียมสำหรับการผลิตเภสัชกรรม\n\nขี้ผึ้งพืชเกรดฟาร์ม่า รวมถึงขี้ผึ้งผึ้ง (BP/Ph.Eur), ขี้ผึ้งคาร์นูบา, ขี้ผึ้งแคนเดิลลา, ขี้ผึ้งรำข้าว, ขี้ผึ้งดอกทานตะวัน, ขี้ผึ้งราพิซีด, ขี้ผึ้งปาล์ม, ขี้ผึ้งอาร์โร, ขี้ผึ้งถั่วเหลือง, ขี้ผึ้งมะกอก, และน้ำมันพืชไฮโดรเจนสำหรับ ointments, ครีม และ suppositories\n\nสารละลายคุณภาพสูงที่มีความบริสุทธิ์สูง สอดคล้องกับเภสัชตำรา เพื่อความเสถียรเนื้อสัมผัสที่เนียนนุ่ม และการปล่อยยาอย่างมีเสถียรภาพในสูตรทาภายนอกและรับประทาน', '2026-02-06 04:48:37', '2026-02-11 17:07:58'),
(5, 'sec-005', 'สิ่งทอและเครื่องหนัง', 'วาส์กผักคุณภาพสูง รวมถึง Carnauba wax, Candelilla wax, Rice bran wax, Sunflower wax, Rapeseed wax, Palm wax, Beeswax, Soy wax และวาส์กพาราฟินและอิมัลชันสำหรับการเคลือบผ้า การบำบัดหนัง และการกันน้ำ\n\nคุณสมบัติการหล่อลื่นที่ยอดเยี่ยม การกันน้ำ และความต้านทานการสึกหรอ เพื่อปรับปรุงความสามารถในการเย็บ การต้านทานการฉีกขาด และประสิทธิภาพในการประมวลผลในอุตสาหกรรมสิ่งทอและการแปรรูปหนัง', '2026-02-06 04:50:19', '2026-02-11 17:08:27'),
(6, 'sec-006', 'ยางและพลาสติก', 'ขี้ผึ้งพาราฟินที่ผ่านการกลั่นอย่างสมบูรณ์ ขี้ผึ้งไมโครคริสตัลไลน์ ขี้ผึ้ง Slack และขี้ผึ้ง PE ที่ได้รับการปรับแต่งเพื่อการผลิตยางรถยนต์ กระบวนการแปรรูปพลาสติก และการผสมยางพารา\n\nจาระบีคุณภาพสูง ตัวหล่อลื่น ตัวช่วยในการปล่อย และสารกระจายตัว ช่วยให้การขึ้นรูป การฉีดขึ้นรูป การรีดด้วยลูกกลิ้ง และการถอดแบบเป็นไปอย่างราบรื่น พร้อมพื้นผิวที่เรียบเนียนและประสิทธิภาพในการแปรรูปที่ยอดเยี่ยม', '2026-02-06 04:52:25', '2026-02-11 17:08:58'),
(7, 'sec-007', 'บรรจุภัณฑ์', 'พาราฟินเวกที่ผ่านการกลั่นสมบูรณ์, ขี้ผึ้งไมโครคริสตัลไลน์, ขี้ผึ้งสแลค, ขี้ผึ้ง PE, รวมทั้งขี้ผึ้งคาร์นูบาและขี้ผึ้งผึ้งธรรมชาติ สำหรับการเคลือบกระดาษ การพันกล่อง และการผลิตบรรจุภัณฑ์ยืดหยุ่น\n\nคุณสมบัติการกันน้ำ, ทนต่อไขมัน, และการปล่อยที่เหนือกว่า ช่วยรับประกันเกราะกันชื้นที่ทนทาน, เคลือบที่ปลอดภัยต่ออาหาร, และประสิทธิภาพการซีลด้วยความร้อนที่มีประสิทธิภาพสูง ทั้งในกล่องลูกฟูก, กล่องพับ, และฟิล์มยืดหยุ่น', '2026-02-06 04:54:04', '2026-02-11 17:09:30'),
(8, 'sec-008', 'กาว', 'เทียนแว็กซ์ paraffin ที่ผ่านการกลั่นอย่างสมบูรณ์, เทียนแว็กซ์ไมครคริสตัลไลน์, เทียนแว็กซ์ slack, เทียนแว็กซ์ PE, เทียนแว็กซ์คาร์นาวาบ, และเทียนแว็กซ์จากผึ้ง เป็นสารเติมแต่งประสิทธิภาพสูงสำหรับการเคลือบ, หมึกพิมพ์, ลามิเนต, และอิมัลชัน\n\nช่วยเพิ่มความทนทานต่อรอยขีดข่วน, เกราะกันความชื้น, ป้องกันการติดกัน, ลด COF และคุณสมบัติการปล่อย สำหรับประสิทธิภาพที่เหนือกว่าของกล่องกระดาษลูกฟูก, แผ่นกระดาษ, และบรรจุภัณฑ์แบบยืดหยุ่น', '2026-02-06 04:56:00', '2026-02-11 17:10:00'),
(9, 'sec-009', 'แว็กซ์และเคลือบเงา', 'เทียนพาราฟินที่ผ่านการกลั่นอย่างสมบูรณ์แบบ, ขี้ผึ้งไมโครคริสตัลไลน์, ขี้ผึ้งคาร์นูบา, และขี้ผึ้งผึ้งสำหรับการเคลือบพื้นผิวให้เงาสูง, การดูแลเฟอร์นิเจอร์, เคลือบรถยนต์, และการป้องกันพื้นผิวในอุตสาหกรรม\n\nมีความทนทานต่อการเสียดสีสูง, สามารถขัดเงาและให้เงางามได้, ให้การปกป้องในระยะยาวและเสร็จสิ้นระดับมืออาชีพบนไม้, โลหะ, หนัง, และพื้นผิวผสม.', '2026-02-06 04:58:31', '2026-02-11 17:10:31'),
(10, 'sec-010', 'กระดาษและการพิมพ์', 'ขี้ผึ้งพาราฟินที่ผ่านการกลั่นอย่างสมบูรณ์, ขี้ผึ้งไมโครคริสตัลไลน์, ขี้ผึ้งคาร์นูบา, ขี้ผึ้งผึ้งและขี้ผึ้งสังเคราะห์สำหรับการเคลือบกระดาษ, การทนต่อละอองหมึก, และการใช้งานที่ปล่อย\n\nคุณสมบัติเป็นแนวกันชื้นที่เหนือกว่า, ป้องกันการติด, และเสริมคุณภาพการพิมพ์เพื่อความมั่นใจในความปลอดภัยของพื้นผิว, การยึดเกาะของหมึกที่ยอดเยี่ยม, และการประมวลผลที่มีประสิทธิภาพสำหรับกระดาษบรรจุภัณฑ์และการพิมพ์เฉพาะทาง', '2026-02-06 05:00:29', '2026-02-11 17:05:54');
INSERT INTO `sectors_tr` (`id`, `master_id`, `name`, `description`, `created_at`, `updated_at`) VALUES
(1, 'sec-001', 'Şişe Yapımı', 'Şamdan Üretimi İçin Tamamen Çözüm Wax\'lar  \nPremium Doğal / Bitki Temelli Mumlar (Soya, Palmiye, Kanola, Hindistan Cevizi, Bal Mumu) ve Petrol Mumları (tam/yarı rafine paraffin 52-68°C, mikro kristal) tüm mum türleri için.\n\nKullanıma hazır Mum Karışımları: Doğrudan eritin—hiçbir katkı maddesine ihtiyaç olmadan— üstün koku yayılımı ve yanma özellikleriyle mükemmel pillar, votive veya kap içerisi mumlar için.', '2026-02-06 04:43:36', '2026-02-11 17:06:18'),
(2, 'sec-002', 'Kozmetik', 'Kozmetik Üretimi İçin Premium Sebze Mumları\n\nGüneş Çiçeği yağı, Kanola yağı, Palm yağı, Bal mumu, Carnauba mumu, Candelilla mumu, Pirinç kepeği yağı, Soja yağı, Hint yağı, Zeytin yağı, Avokado yağı, Kenevir yağı, Yaban mersini yağı (Rhus verniciflua) ve Myrica meyvesi yağı gibi yüksek kaliteli doğal sebze mumları, krem, ruj ve cilt bakım ürünleri için.\n\nİnce gözenekli yapı ve üstün performans sağlayan mükemmel yumuşatıcılar, kalınlaştırıcılar ve stabilizatörler.', '2026-02-06 04:45:10', '2026-02-11 17:06:47'),
(3, 'sec-003', 'Yiyecek ve İçecek', 'Gıda Üretimi İçin Premium Yenilebilir Yağlar ve Yağlı Maddeler\n\nTamamen rafine edilmiş yenilebilir yağlar (palmiye, soya, ayçiçek, kanola, zeytin, hindistan cevizi), stearinler (palmiye, soya) ve unlu mamuller, şekerleme ve kızartma uygulamaları için shortningler.\n\nYüksek stabiliteye sahip, nötr lezzetli çözümler, tutarlı doku, uzun raf ömrü ve gıda işleme ihtiyaçları boyunca üstün performans sağlar.', '2026-02-06 04:46:42', '2026-02-11 17:07:18'),
(4, 'sec-004', 'İlaç Sanayii', 'İlaç Üretimi İçin Premium Malzemeler\n\nBP/Ph.Eur standartlarında Mumlar (Arı Mumları), Carnauba Mum, Candelilla Mum, Pirinç Branı Mum, Ayçiçeği Mum, Kanola Mumu, Palm Mumu, Hint Yağı Mumu, Soya Mumu, Zeytin Mumu ve Hidrojene Bitkisel Yağlar, merhemler, kremler ve fitiller için.\n\nYüksek saflıkta, farmakope uyumlu çözümler, topikal ve oral formülasyonlarda stabilite, pürüzsüz doku ve tutarlı ilaç salınımı sağlar.', '2026-02-06 04:48:20', '2026-02-11 17:07:50'),
(5, 'sec-005', 'Tekstiller ve Deri', 'Carnauba vazı, Candelilla vazı, PirENîlzya yağı vazı, Ayçiçeği vazı, Kanola vazı, Palmiye vazı, Mum vazı, Soya vazı ve ek olarak kumaş bitirme, deri işlemi ve su geçirmezlik için paraffin vazları ve emülsiyonları yüksek performanslı sebze mumlarıdır.\n\nGelişmiş yağlama, su iticilik ve aşınma direnci ile tekstil üretimi ve deri işleme süreçlerinde dikiş uyumu, yırtılma kuvveti ve işlem verimliliğini artırır.', '2026-02-06 04:50:00', '2026-02-11 17:08:21'),
(6, 'sec-006', 'Kauçuk ve Plastik', 'Tamamen rafine edilmiş paraffin mumları, mikrokristal mumlar, slack mum ve PE mumlar, lastik üretimi, plastik işlemesi ve kauçuk karışımına optimize edilmiştir.\n\nÜstün yağlayıcılar, serbest bırakıcı ajanlar ve dispersiyon yardımcıları, mükemmel yüzey kalitesi ve işleme verimliliğiyle düzgün ekstrüzyon, enjeksiyon kalıplama, rulo işleme ve kalıptan çıkarmayı sağlar.', '2026-02-06 04:52:02', '2026-02-11 17:08:52'),
(7, 'sec-007', 'Ambalaj', 'Tam rafine edilmiş paraffin mumları, mikro kristallin mumlar, slack wax, PE mumlar ile doğal karnauba ve balmumu, kağıt kaplama, kutu laminasyonu ve esnek ambalaj üretimi için.\n\nÜstün su geçirmezlik, yağ direnci ve serbest bırakma özellikleri sayesinde dayanıklı nem bariyerleri, gıda güvenli kaplamalar ve verimli ısı yapışma performansı sağlar; oluklu mukavva, katlanabilir kartonlar ve esnek filmler üzerinde.', '2026-02-06 04:53:45', '2026-02-11 17:09:24'),
(8, 'sec-008', 'Yapışkanlar', 'Tamamen rafine edilmiş paraffin mumları, mikro kristal yapılı mumlar, slack mum, PE mumlar, karnauba mum ve balmumu, kaplamalar, mürekkepler, laminatlar ve emülsiyonlar için yüksek performanslı katkı maddeleri olarak kullanılır.\n\nÇizilme direncini, nem bariyerini, yapışmazlığı, sürtünme katsayısı (COF) azaltmayı ve çıkarma özelliklerini artırarak üstün oluklu mukavva, karton ve esnek ambalaj performansı sağlar.', '2026-02-06 04:55:42', '2026-02-11 17:09:54'),
(9, 'sec-009', 'Parlatıcılar ve Kaplamalar', 'Tamamen rafine edilmiş paraffin mumları, mikro kristalize mumlar, carnauba mumu ve balmumu, yüksek parlaklık sağlayan yer cilaları, mobilya bakımı, otomotiv kaplamaları ve endüstriyel yüzey koruması için.\n\nOlağanüstü aşınma direnci, parlatılabilirlik ve parlaklık sağlayan, uzun ömürlü koruma ve profesyonel bir görünüm sunar; ahşap, metal, deri ve kompozit yüzeylerde mükemmel sonuçlar verir.', '2026-02-06 04:58:06', '2026-02-11 17:10:25'),
(10, 'sec-010', 'Kağıt ve Baskı', 'Tamamen rafine edilmiş parafin balmumu, mikro kristalize balmumu, carnauba balmumu, balmumu ve kağıt kaplama, mürekkep sürtünme direnci ve bırakma uygulamaları için sentetik balmumları.\n\nÜstün nem bariyeri, yapışmazlık özellikleri ve baskı geliştirme sağlayarak yüksek kaliteli yüzey koruması, mürekkep yapışması ve paketleme kağıtları ile özel baskı işlemlerinde verimli işlem imkanı sunar.', '2026-02-06 05:00:04', '2026-02-11 17:05:47');
INSERT INTO `sectors_vi` (`id`, `master_id`, `name`, `description`, `created_at`, `updated_at`) VALUES
(1, 'sec-001', 'Làm nến', 'Giải pháp wax hoàn chỉnh cho sản xuất nến  \nSáp cao cấp từ thiên nhiên/thực vật (đậu nành, dầu cọ, cải dầu, dừa, sáp ong) và sáp dầu mỏ (paraffin tinh luyện hoàn toàn/bán tinh luyện 52-68°C, vi tinh thể) dành cho tất cả các loại nến.\n\nHỗn hợp sáp ready-to-use: Đun chảy trực tiếp—không cần thêm phụ gia—để tạo ra những cây nến cột, nến votive hoặc nến đựng hoàn hảo với khả năng tỏa hương và cháy vượt trội.', '2026-02-06 04:43:40', '2026-02-11 17:06:20'),
(2, 'sec-002', 'Mỹ phẩm', 'Sáp thực vật cao cấp dùng trong sản xuất mỹ phẩm\n\nCác loại sáp thực vật tự nhiên chất lượng cao bao gồm sáp hướng dương, sáp cải dầu, sáp dầu cọ, sáp ong, sáp carnauba, sáp candelilla, sáp từ cám gạo, sáp đậu nành, sáp castor, sáp ôliu, sáp bơ avokado, sáp hạt mùn rơi, sáp berry (Rhus verniciflua), và sáp trái Myrica dùng cho kem, son môi và chăm sóc da.\n\nNhững chất làm mềm, làm đặc và ổn định hoàn hảo mang lại kết cấu mịn màng và hiệu suất vượt trội.', '2026-02-06 04:45:17', '2026-02-11 17:06:50'),
(3, 'sec-003', 'Thực phẩm & Đồ uống', 'Dầu ăn và chất béo cao cấp dùng trong sản xuất thực phẩm\n\nDầu ăn tinh luyện hoàn toàn (dầu cọ, đậu nành, hướng dương, cải dầu, oliu, dừa), stearins (dầu cọ, đậu nành), và chất làm rắn cho các ứng dụng bánh mì, kẹo và chiên xào.\n\nCác giải pháp ổn định cao, hương vị trung tính, đảm bảo kết cấu đồng nhất, tuổi thọ sản phẩm kéo dài và hiệu suất vượt trội trong các nhu cầu chế biến thực phẩm.', '2026-02-06 04:46:49', '2026-02-11 17:07:20'),
(4, 'sec-004', 'Dược phẩm', 'Nguyên liệu cao cấp dùng trong sản xuất dược phẩm\n\nDầu thực vật đạt tiêu chuẩn dược phẩm gồm sáp ong (BP/Ph.Eur), sáp carnauba, sáp candelilla, sáp vừng, sáp hướng dương, sáp cải dầu, sáp cọ, sáp castor, sáp đậu nành, sáp ô liu và dầu thực vật hydrogen hóa cho thuốc bôi, kem và thuốc đạn.\n\nCác giải pháp tinh khiết, phù hợp với tiêu chuẩn dược điển, đảm bảo độ ổn định, kết cấu mượt mà và phóng thích thuốc đều đặn trong các dạng bào chế dạng bôi ngoài và dạng uống.', '2026-02-06 04:48:25', '2026-02-11 17:07:52'),
(5, 'sec-005', 'Vải và Da', 'Sáp thực vật hiệu suất cao bao gồm sáp Carnauba, sáp Candelilla, sáp cám gạo, sáp hướng dương, sáp cải dầu, sáp cọ, sáp ong, sáp đậu nành cùng với sáp paraffin và nhũ tương để hoàn thiện vải, xử lý da và chống thấm.\n\nĐộ bôi trơn vượt trội, khả năng chống nước và kháng mài mòn giúp cải thiện khả năng may, độ chịu rách và hiệu quả xử lý trong sản xuất dệt may và xử lý da.', '2026-02-06 04:50:06', '2026-02-11 17:08:23'),
(6, 'sec-006', 'Cao su & Nhựa', 'Sáp parafin tinh luyện hoàn toàn, sáp microcrystalline, sáp slack và sáp PE tối ưu hóa cho sản xuất lốp xe, gia công nhựa, và phối trộn cao su.\n\nChất bôi trơn, chất giảm dính, và dung môi phân tán hàng đầu đảm bảo quá trình ép đùn, đúc nhấn, cán màng và tháo khuôn trơn tru, cho bề mặt hoàn thiện xuất sắc và hiệu quả gia công cao.', '2026-02-06 04:52:11', '2026-02-11 17:08:54'),
(7, 'sec-007', 'Bao bì', 'Sáp parafin tinh luyện hoàn toàn, sáp vi tinh thể, sáp slack, sáp PE, cùng với sáp carnauba tự nhiên và sáp ong dùng cho phủ giấy, dán giấy carton, và sản xuất bao bì mềm.\n\nChất lượng chống thấm nước vượt trội, kháng dầu và khả năng chống dính đảm bảo các lớp chống ẩm bền chắc, lớp phủ an toàn thực phẩm, và hiệu suất hàn nhiệt hiệu quả trên các bìa carton, hộp có thể gập, và màng phim mềm.', '2026-02-06 04:53:52', '2026-02-11 17:09:26'),
(8, 'sec-008', 'Chất dính', 'Paraffin wax tinh luyện hoàn toàn, sáp microcrystalline, sáp slack, sáp PE, sáp carnauba và sáp ong như các phụ gia có hiệu suất cao cho lớp phủ, mực in, laminate và nhũ tương.\n\nTăng cường khả năng chống trầy xước, hàng rào chống độ ẩm, chống dính, giảm hệ số ma sát (COF) và tính dễ tách lớp để nâng cao hiệu suất cho bìa các tông, giấy carton và bao bì mềm.', '2026-02-06 04:55:48', '2026-02-11 17:09:56'),
(9, 'sec-009', 'Sơn và Lớp phủ', 'Sáp paraffin tinh chế hoàn toàn, sáp microcrystalline, sáp carnauba và sáp ong cho chất đánh bóng sàn bóng sáng cao, bảo dưỡng nội thất, lớp phủ ô tô và bảo vệ bề mặt công nghiệp.\n\nKhả năng chống mài mòn xuất sắc, dễ đánh bóng và tạo độ sáng, mang lại sự bảo vệ lâu dài và lớp hoàn thiện chuyên nghiệp trên các bề mặt gỗ, kim loại, da và composite.', '2026-02-06 04:58:15', '2026-02-11 17:10:27'),
(10, 'sec-010', 'Giấy & In ấn', 'Sáp paraffin tinh luyện hoàn toàn, sáp vi cấu trúc, sáp carnauba, sáp ong, và các loại sáp tổng hợp dùng để phủ giấy, chống mài mòn mực, và giải pháp tách tĩnh điện.\n\nChịu độ ẩm vượt trội, tính chống dính, và tăng cường khả năng in ấn, đảm bảo lớp bảo vệ bề mặt chất lượng cao, độ bám mực tuyệt vời, và quy trình xử lý hiệu quả cho giấy đóng gói và in đặc biệt.', '2026-02-06 05:00:11', '2026-02-11 17:05:49');
INSERT INTO `sectors_zh` (`id`, `master_id`, `name`, `description`, `created_at`, `updated_at`) VALUES
(1, 'sec-001', '蜡烛制作', '烛制造的完整蜡料解决方案  \n优质天然/植物基蜡（大豆蜡、棕榈蜡、菜籽蜡、椰子蜡、蜂蜡）和石油蜡（全精制/半精制石蜡52-68°C，微晶蜡），适用于所有类型的蜡烛。\n\n即用型蜡混合料：直接融化，无需添加剂，打造出具有优越扩散性和燃烧性能的完美柱蜡、灯芯蜡或容器蜡。', '2026-02-06 04:42:20', '2026-02-11 17:06:01'),
(2, 'sec-002', '化妆品', '用于化妆品制造的优质植物蜡\n\n高品质天然植物蜡，包括向日葵蜡、油菜籽蜡、棕榈蜡、蜂蜡、巴西棕榈蜡、角棕榈蜡、米糠蜡、大豆蜡、蓖麻蜡、橄榄蜡、牛油果蜡、工业大麻蜡、浆果蜡（Rhus verniciflua）以及米格果蜡，用于面霜、口红和护肤产品。\n\n理想的润肤剂、增稠剂和稳定剂，带来顺滑的质地和卓越的性能。', '2026-02-06 04:44:11', '2026-02-11 17:06:30'),
(3, 'sec-003', '食品与饮料', '食品制造的优质食用油与脂肪\n\n全精炼食用油（棕榈油、大豆油、向日葵油、油菜籽油、橄榄油、椰子油）、硬脂（棕榈硬脂、大豆硬脂）及焙烤、糖果和炸制应用的起酥油。\n\n高稳定性、中性风味解决方案，确保口感一致、延长保质期，并在食品加工需求中展现卓越性能。', '2026-02-06 04:45:40', '2026-02-11 17:07:00'),
(4, 'sec-004', '制药行业', '用于药品制造的优质原料\n\n药用级植物蜡，包括蜂蜡（BP/Ph.Eur）、卡纳巴蜡、康德利拉蜡、米糠蜡、葵花蜡、油菜籽蜡、棕榈蜡、蓖麻蜡、大豆蜡、橄榄蜡，以及用于软膏、霜剂和栓剂的氢化植物油。\n\n高纯度、符合药典标准的解决方案，确保稳定性、光滑的质感以及在局部和口服制剂中的药物释放的一致性。', '2026-02-06 04:47:23', '2026-02-11 17:07:31'),
(5, 'sec-005', '纺织品与皮革', '高性能植物蜡，包括巴西棕榈蜡、蜡质果蜡、米糠蜡、向日葵蜡、油菜籽蜡、棕榈蜡、蜂蜡、大豆蜡，以及用于织物整理、皮革处理和防水的石蜡及乳化剂。\n\n卓越的润滑性、防水性和耐磨性，提升纺织品和皮革加工中的缝纫性、抗撕裂强度和生产效率。', '2026-02-06 04:48:55', '2026-02-11 17:08:04'),
(6, 'sec-006', '橡胶与塑料', '全精炼石蜡、微晶蜡、松脂蜡和PE蜡，经过优化，适用于轮胎生产、塑料加工和橡胶配方。\n\n优质润滑剂、脱模剂和分散剂，确保挤出、注塑、压延和脱模过程顺利进行，表面光洁度优秀，加工效率高。', '2026-02-06 04:50:43', '2026-02-11 17:08:33'),
(7, 'sec-007', '包装', '全精炼石蜡、微晶蜡、废蜡、PE蜡，以及用于纸张涂覆、纸板层压和柔性包装生产的天然巴西棕榈蜡和蜂蜡。\n\n优异的防水性、抗油脂性和离型性，确保耐用的阻湿层、食品安全涂层，以及在瓦楞纸箱、折叠纸箱和柔性薄膜中的高效热封性能。', '2026-02-06 04:52:51', '2026-02-11 17:09:04'),
(8, 'sec-008', '粘合剂', '全精炼石蜡、微晶蜡、松香蜡、PE蜡、巴西棕榈蜡和蜂蜡，作为涂料、油墨、层压材料和乳液的高性能添加剂。\n\n提升刮擦抗性、抗湿气屏障、抗粘连、降低COF以及释放性能，确保瓦楞纸板、纸板和柔性包装的卓越性能。', '2026-02-06 04:54:25', '2026-02-11 17:09:36'),
(9, 'sec-009', '抛光与涂层', '完全精炼的石蜡蜡、超细晶体蜡、巴西棕榈蜡和蜂蜡，用于高光地板抛光、家具护理、汽车涂层及工业表面保护。\n\n具有卓越的耐磨性、抛光性和光泽，能提供持久的保护和专业的光洁度，适用于木材、金属、皮革和复合材料表面。', '2026-02-06 04:56:23', '2026-02-11 17:10:06'),
(10, 'sec-010', '纸张与印刷', '完全精制石蜡、云母晶蜡、巴西棕榈蜡、蜂蜡以及合成蜡，用于纸张涂层、抗墨擦拭性以及离型应用。\n\n优异的防潮屏障、抗粘性能和印刷增强，确保高品质的表面保护、出色的墨水附着力以及高效的包装纸和特色印刷加工。', '2026-02-06 04:59:01', '2026-02-11 17:05:30');
