INSERT INTO `seo_page_meta` (`id`, `page_path`, `title`, `description`, `keywords`, `og_title`, `og_description`, `og_image`, `canonical_url`, `no_index`, `is_active`, `created_at`, `updated_at`) VALUES
('spm-001', '/', 'Bio Green Wax Ltd for Edible Oils, fats & Industrial Waxes', 'Suppliers of RSPO MB/SG and EUDR-certified palm oil, olein, stearin, and custom soy, rapeseed, coconut, paraffin, micro & slack wax blends for industries.', 'oils and waxes supplier UK, edible oils wholesale, candle wax supplier, plant-based wax, soy wax, palm wax, paraffin wax, beeswax wholesale, oleochemicals, RSPO certified, bulk wax UK, sunflower oil wholesale', 'Bio Green Wax Ltd - Premium Oils, Waxes & Oleochemicals', 'Your trusted UK supplier for edible oils, candle waxes, industrial waxes, and oleochemicals. 30+ products, RSPO SG certified, EUDR compliant.', NULL, NULL, 0, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('spm-002', '/products', 'Products | Edible Oils, Candle Waxes, Industrial Waxes & Oleochemicals', 'Browse 36+ premium products: sunflower oil, coconut oil, palm oil, soy wax, palm wax, beeswax, paraffin wax, wax blends, glycerine, soap noodles, and more. Wholesale supply from Bio Green Wax Ltd.', 'edible oils wholesale, sunflower oil bulk UK, coconut oil wholesale, palm oil supplier, soy wax bulk, palm wax candle making, beeswax wholesale, paraffin wax UK, wax blends, oleochemicals, glycerine wholesale, soap noodles UK, castor oil bulk', 'Bio Green Wax Products - Oils, Waxes & Oleochemicals', 'Explore our full range of edible oils, plant-based waxes, industrial waxes, wax blends, and oleochemicals. Wholesale supply with RSPO certification.', NULL, NULL, 0, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('spm-003', '/about', 'About Bio Green Wax Ltd | RSPO SG Certified Oils & Waxes Supplier', 'Bio Green Wax Ltd is a UK-based supplier of premium edible oils, waxes, and oleochemicals. RSPO Segregated certified, EUDR compliant, and ISCC EU certified for biofuels feedstock. Committed to sustainability and quality.', 'about bio green wax, UK oils supplier, RSPO segregated certified, EUDR compliant supplier, sustainable oils company, ISCC EU certified, quality oils and waxes', 'About Bio Green Wax Ltd', 'Learn about Bio Green Wax Ltd - your trusted UK partner for sustainable, certified oils and waxes.', NULL, NULL, 0, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('spm-004', '/contact', 'Contact Bio Green Wax Ltd | Request Quotes & Samples', 'Get in touch with Bio Green Wax Ltd for wholesale enquiries, product quotes, and sample requests. Edible oils, candle waxes, industrial waxes, and oleochemicals available for bulk supply.', 'contact bio green wax, request quote oils waxes, wholesale enquiry, oil samples UK, wax supplier contact, bulk order enquiry', 'Contact Bio Green Wax Ltd', 'Request quotes, samples, or make enquiries about our range of oils, waxes, and oleochemicals.', NULL, NULL, 0, 1, '2026-02-05 21:03:49', '2026-02-05 21:03:49'),
('spm-005', '/news', 'News & Industry Updates | Bio Green Wax Ltd', 'Stay informed with the latest news from Bio Green Wax Ltd. Industry insights on edible oils, candle waxes, oleochemicals, sustainability regulations, and market trends.', 'oils and waxes news, candle wax industry updates, edible oil market trends, RSPO news, EUDR updates, UK oils supplier news', 'Bio Green Wax News & Updates', 'Latest industry news, product updates, and sustainability insights from Bio Green Wax Ltd.', NULL, NULL, 0, 1, '2026-02-11 17:26:18', '2026-02-11 17:26:18'),
('spm-006', '/careers', 'Careers at Bio Green Wax Ltd | Join Our Team', 'Explore career opportunities at Bio Green Wax Ltd. Join a growing UK company in the oils, waxes, and oleochemicals industry committed to sustainability and quality.', 'bio green wax careers, oils and waxes industry jobs, UK commodities jobs, sustainability careers', 'Careers at Bio Green Wax', 'Join Bio Green Wax Ltd and build your career in the oils and waxes industry.', NULL, NULL, 0, 1, '2026-02-11 17:26:18', '2026-02-11 17:26:18'),
('spm-007', '/certifications', 'Certifications & Quality Standards | Bio Green Wax Ltd', 'Bio Green Wax Ltd holds ISO 9001, ISO 14001, RSPO Segregated, FSSC 22000, ISCC EU, and ISCC PLUS certifications. Committed to quality, food safety, and sustainability.', 'ISO 9001, ISO 14001, RSPO SG certified, FSSC 22000, ISCC EU, ISCC PLUS, quality certifications, food safety, sustainable supply chain', 'Bio Green Wax Certifications', 'View our quality and sustainability certifications including RSPO, ISCC, and ISO standards.', NULL, NULL, 0, 1, '2026-02-11 17:26:18', '2026-02-11 17:26:18');
