('sc-003', 'about', 'story', 'title', 'Our Story', 'text', 3, 0, '2026-02-05 21:03:49'),
('sc-004', 'about', 'story', 'content', 'Founded in 1985, Bio Green Wax Ltd has grown from a small family business to one of the UK\'s leading suppliers of natural oils and industrial waxes. Our commitment to quality, sustainability, and customer service has been the cornerstone of our success for nearly four decades.', 'text', 4, 0, '2026-02-05 21:03:49'),
('sc-005', 'about', 'mission', 'title', 'Our Mission', 'text', 5, 0, '2026-02-05 21:03:49'),
('sc-006', 'about', 'mission', 'content', 'To provide the highest quality natural oils and waxes while maintaining our commitment to sustainability and ethical sourcing. We believe in building long-term partnerships with our customers and suppliers based on trust and mutual success.', 'text', 6, 0, '2026-02-05 21:03:49'),
('sc-007', 'about', 'values', 'title', 'Our Values', 'text', 7, 0, '2026-02-05 21:03:49'),
('sc-008', 'about', 'values', 'quality', 'Quality Excellence - We never compromise on the quality of our products', 'text', 8, 0, '2026-02-05 21:03:49'),
('sc-009', 'about', 'values', 'sustainability', 'Sustainability - Committed to environmentally responsible practices', 'text', 9, 0, '2026-02-05 21:03:49'),
('sc-010', 'about', 'values', 'integrity', 'Integrity - Honest and transparent in all our business dealings', 'text', 10, 0, '2026-02-05 21:03:49'),
('sc-011', 'about', 'team', 'title', 'Our Team', 'text', 11, 0, '2026-02-05 21:03:49'),
('sc-012', 'about', 'team', 'content', 'Our experienced team brings together expertise in chemistry, logistics, and customer service to deliver exceptional results for our clients.', 'text', 12, 0, '2026-02-05 21:03:49');
